param(
    [switch]$SelfTest,
    [switch]$UiSmokeTest,
    [switch]$ReferenceListTest,
    [switch]$NoUi,
    [string]$LoadAppColumnsPath = "",
    [string]$LoadAppColumnsOutputPath = "",
    [string]$LoadAppColumnsErrorPath = "",
    [string]$MasterDatabase = "",
    [string]$UpgradeTemplateDatabase = "",
    [string]$OutputDatabase = "",
    [string]$AiEndpoint = "",
    [string]$AiModel = "",
    [string]$AiApiKey = "",
    [string]$SplashReadyFile = ""
)

# Project Pickle
# Creates or prepares CFI Access inventory databases from a master template.

$ErrorActionPreference = "Stop"
$script:SplashReadyFilePath = [string]$SplashReadyFile
$script:AppName = "Project Pickle"
$script:AppVersion = "2.1.4"
$script:RunLogTableName = "ProjectPickleRunLog"
$script:UpgradeModeLabel = "Upgrade Project"
$script:AppRoot = if (
    -not [string]::IsNullOrWhiteSpace(
        $PSScriptRoot
    )
) {
    $PSScriptRoot
}
elseif (
    -not [string]::IsNullOrWhiteSpace(
        $PSCommandPath
    )
) {
    Split-Path `
        -Parent $PSCommandPath
}
else {
    (Get-Location).Path
}

$script:AppScriptPath = if (
    -not [string]::IsNullOrWhiteSpace(
        $PSCommandPath
    )
) {
    $PSCommandPath
}
else {
    Join-Path `
        $script:AppRoot `
        "ProjectPickle.ps1"
}
$script:AppIconPath = Join-Path $script:AppRoot "ProjectPickle.ico"
$script:SplashReadyWasSignaled = $false
$script:WOOFIsProcessing = $false
$script:WOOFBackgroundBuildActive = $false
$script:WOOFCancelRequested = $false
$script:WOOFCloseAfterCancel = $false
$script:WOOFAllowCloseAfterCancel = $false
$script:WOOFSuppressCancelException = $false
$script:WOOFLiveRunLogPath = ""
$script:WOOFLiveRunLogConfig = $null
$script:DefaultMasterDatabase = ""
$script:DefaultCfiVersionPlaceholder = "vX.XX.XX"
$script:DefaultProjectNamePlaceholder = "[TRIBE] CFI [DATE 20260624] vX.XX.XX"
$script:AzureOpenAiApiVersion = "2024-12-01-preview"
$script:AiDefaultEndpoint = "https://doi-training-foundry.cognitiveservices.azure.com/"
$script:AiDefaultModel = "gpt-4.1-mini"
$script:AiApprovedHosts = @("doi-training-foundry.cognitiveservices.azure.com")

function Set-ProjectPickleSplashReady {
    if ($script:SplashReadyWasSignaled) {
        return
    }

    $readyPath =
        [string]$script:SplashReadyFilePath

    if (
        [string]::IsNullOrWhiteSpace(
            $readyPath
        )
    ) {
        return
    }

    try {
        if (
            [System.IO.File]::Exists(
                $readyPath
            )
        ) {
            [System.IO.File]::Delete(
                $readyPath
            )
        }

        $script:SplashReadyWasSignaled =
            $true
    }
    catch {
        # Splash cleanup must not stop app startup.
    }
}
function Set-WOOFWindowsAppIdentity {
    try {
        if (-not ([System.Management.Automation.PSTypeName]"WOOF.ShellAppIdentity").Type) {
            Add-Type -TypeDefinition @"
using System;
using System.Runtime.InteropServices;

namespace WOOF {
    public static class ShellAppIdentity {
        [DllImport("shell32.dll", CharSet = CharSet.Unicode)]
        public static extern int SetCurrentProcessExplicitAppUserModelID(string appID);
    }
}
"@
        }
        [void][WOOF.ShellAppIdentity]::SetCurrentProcessExplicitAppUserModelID("USDI.BIA.ProjectPickle")
    }
    catch {
    }
}

function Set-WOOFWindowIcon {
    param(
        [System.Windows.Forms.Form]$Form,
        [System.Drawing.Icon]$Icon
    )

    if ($null -eq $Form -or $null -eq $Icon) { return }
    try {
        if (-not ([System.Management.Automation.PSTypeName]"WOOF.WindowIcon").Type) {
            Add-Type -TypeDefinition @"
using System;
using System.Runtime.InteropServices;

namespace WOOF {
    public static class WindowIcon {
        [DllImport("user32.dll", CharSet = CharSet.Auto)]
        public static extern IntPtr SendMessage(IntPtr hWnd, int msg, IntPtr wParam, IntPtr lParam);
    }
}
"@
        }
        $Form.ShowIcon = $true
        $Form.Icon = $Icon
        if ($Form.IsHandleCreated) {
            [void][WOOF.WindowIcon]::SendMessage($Form.Handle, 0x0080, [intptr]0, $Icon.Handle)
            [void][WOOF.WindowIcon]::SendMessage($Form.Handle, 0x0080, [intptr]1, $Icon.Handle)
        }
    }
    catch {
    }
}

function Set-WOOFComboItems {
    param(
        [System.Windows.Forms.ComboBox]$Combo,
        [string[]]$Items
    )

    if ($null -eq $Combo) { return }
    $current = ConvertTo-BuilderText $Combo.Text
    $Combo.BeginUpdate()
    try {
        $Combo.Items.Clear()
        foreach ($item in @($Items | Where-Object { -not [string]::IsNullOrWhiteSpace($_) } | Sort-Object -Unique)) {
            [void]$Combo.Items.Add($item)
        }
        if (-not [string]::IsNullOrWhiteSpace($current)) { $Combo.Text = $current }
    }
    finally {
        $Combo.EndUpdate()
    }
}

function Get-WOOFComboText {
    param([System.Windows.Forms.ComboBox]$Combo)

    if ($null -eq $Combo) { return "" }
    $text = ConvertTo-BuilderText $Combo.Text
    if (-not [string]::IsNullOrWhiteSpace($text)) { return $text }
    return ConvertTo-BuilderText $Combo.SelectedItem
}

function Test-WOOFTextEquals {
    param(
        [object]$Left,
        [object]$Right
    )

    return [string]::Equals((ConvertTo-BuilderText $Left), (ConvertTo-BuilderText $Right), [System.StringComparison]::OrdinalIgnoreCase)
}

function ConvertTo-RawSingleLineText {
    param([object]$Value)

    if ($null -eq $Value -or $Value -is [System.DBNull]) { return "" }
    $text = [string]$Value
    $text = $text.Replace([string][char]0xFEFF, "")
    $text = $text.Replace([string][char]0x200B, "")
    $text = $text.Replace([string][char]0x200C, "")
    $text = $text.Replace([string][char]0x200D, "")
    return $text.Replace("`r", "").Replace("`n", "")
}

function ConvertTo-BuilderText {
    param([object]$Value)

    if ($null -eq $Value -or $Value -is [System.DBNull]) { return "" }
    $text = [string]$Value
    $text = $text.Replace([string][char]0xFEFF, "")
    $text = $text.Replace([string][char]0x200B, "")
    $text = $text.Replace([string][char]0x200C, "")
    $text = $text.Replace([string][char]0x200D, "")
    $text = $text.Replace([string][char]0x00A0, " ")
    $text = [regex]::Replace($text, "\s+", " ")
    return $text.Trim()
}

function ConvertTo-BuilderDateText {
    param([object]$Value)

    if ($null -eq $Value -or $Value -is [System.DBNull]) { return "" }
    if ($Value -is [datetime]) { return ([datetime]$Value).ToString("yyyy-MM-dd") }
    $text = ConvertTo-BuilderText $Value
    if ([string]::IsNullOrWhiteSpace($text)) { return "" }
    $date = [datetime]::MinValue
    if ([datetime]::TryParse($text, [ref]$date)) { return $date.ToString("yyyy-MM-dd") }
    return $text
}

function ConvertTo-AiText {
    param([object]$Value)

    if ($null -eq $Value -or $Value -is [System.DBNull]) { return "" }
    $text = [string]$Value
    $text = $text.Replace([string][char]0xFEFF, "")
    $text = $text.Replace([string][char]0x200B, "")
    $text = $text.Replace([string][char]0x200C, "")
    $text = $text.Replace([string][char]0x200D, "")
    $text = $text.Replace([string][char]0x00A0, " ")
    $text = [regex]::Replace($text, "[`t ]+", " ")
    $text = [regex]::Replace($text, " ?(`r`n|`n|`r) ?", "`r`n")
    return $text.Trim()
}

function Quote-Name {
    param([string]$Name)
    return "[" + $Name.Replace("]", "]]") + "]"
}

function Sql-Text {
    param([object]$Value)
    if ($null -eq $Value -or $Value -is [System.DBNull]) { return "Null" }
    $text = [string]$Value
    if ([string]::IsNullOrWhiteSpace($text)) { return "Null" }
    return "'" + $text.Replace("'", "''") + "'"
}

function Sql-Guid {
    param([object]$Value)
    if ($null -eq $Value -or $Value -is [System.DBNull]) { return "Null" }
    $text = ConvertTo-BuilderText $Value
    if ([string]::IsNullOrWhiteSpace($text)) { return "Null" }
    $match = [regex]::Match($text, "[0-9A-Fa-f]{8}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{12}")
    if (-not $match.Success) {
        throw "Expected a database ID value in GUID format, but found '$text'."
    }
    return "{guid {" + $match.Value + "}}"
}

function Sql-Date {
    param([object]$Value)
    if ($null -eq $Value -or $Value -is [System.DBNull]) { return "Null" }
    $text = ConvertTo-BuilderText $Value
    if ([string]::IsNullOrWhiteSpace($text)) { return "Null" }
    $date = [datetime]::MinValue
    if (-not [datetime]::TryParse($text, [ref]$date)) { return "Null" }
    return "#" + $date.ToString("yyyy-MM-dd") + "#"
}

function Sql-DateTime {
    param([object]$Value)
    if ($null -eq $Value -or $Value -is [System.DBNull]) { return "Null" }
    $date = [datetime]::MinValue
    if ($Value -is [datetime]) {
        $date = [datetime]$Value
    }
    elseif (-not [datetime]::TryParse((ConvertTo-BuilderText $Value), [ref]$date)) {
        return "Null"
    }
    return "#" + $date.ToString("yyyy-MM-dd HH:mm:ss") + "#"
}

function Sql-Number {
    param([object]$Value)
    if ($null -eq $Value -or $Value -is [System.DBNull]) { return "Null" }
    $text = ConvertTo-BuilderText $Value
    if ([string]::IsNullOrWhiteSpace($text)) { return "Null" }
    $number = 0.0
    if ([double]::TryParse($text, [System.Globalization.NumberStyles]::Any, [System.Globalization.CultureInfo]::InvariantCulture, [ref]$number)) {
        return $number.ToString([System.Globalization.CultureInfo]::InvariantCulture)
    }
    if ([double]::TryParse($text, [ref]$number)) {
        return $number.ToString([System.Globalization.CultureInfo]::InvariantCulture)
    }
    return "Null"
}

function Sql-Bool {
    param([object]$Value)
    if ($null -eq $Value -or $Value -is [System.DBNull]) { return "False" }
    if (ConvertTo-BuilderBool $Value) { return "True" }
    return "False"
}

function ConvertTo-BuilderBool {
    param([object]$Value)

    if ($null -eq $Value -or $Value -is [System.DBNull]) { return $false }
    if ($Value -is [bool]) { return [bool]$Value }
    if ($Value -is [byte] -or $Value -is [int16] -or $Value -is [int32] -or $Value -is [int64] -or $Value -is [double] -or $Value -is [decimal]) {
        return ([double]$Value -ne 0)
    }
    $text = (ConvertTo-BuilderText $Value).ToLowerInvariant()
    return ($text -in @("1", "-1", "true", "yes", "y", "checked"))
}

function Invoke-WOOFUiPulse {
    try {
        if ($script:WOOFBackgroundBuildActive) { return }
        $winFormsApplicationType = ([System.Management.Automation.PSTypeName]"System.Windows.Forms.Application").Type
        if ($null -ne $winFormsApplicationType) {
            [System.Windows.Forms.Application]::DoEvents()
        }
    }
    catch {
    }
    Test-WOOFCancelRequested
}

function Test-WOOFCancelRequested {
    if ($script:WOOFCancelRequested -and -not $script:WOOFSuppressCancelException) {
        throw "Build canceled by user. Project Pickle will close after the current safe checkpoint."
    }
}

function New-GuidText {
    return ([guid]::NewGuid()).ToString()
}

function Get-ProviderCandidates {
    param([string]$Path)

    $extension = [System.IO.Path]::GetExtension($Path).ToLowerInvariant()
    if ($extension -eq ".mdb") {
        return @(
            "Microsoft.Jet.OLEDB.4.0",
            "Microsoft.ACE.OLEDB.16.0",
            "Microsoft.ACE.OLEDB.15.0",
            "Microsoft.ACE.OLEDB.12.0"
        )
    }

    return @(
        "Microsoft.ACE.OLEDB.16.0",
        "Microsoft.ACE.OLEDB.15.0",
        "Microsoft.ACE.OLEDB.12.0",
        "Microsoft.Jet.OLEDB.4.0"
    )
}

function New-AccessConnectionString {
    param([string]$Path)

    if (-not (Test-Path -LiteralPath $Path)) {
        throw "Database not found: $Path"
    }

    $lastError = ""
    foreach ($provider in (Get-ProviderCandidates -Path $Path)) {
        $connectionString = "Provider=$provider;Data Source=$Path;Persist Security Info=False;"
        $connection = New-Object System.Data.OleDb.OleDbConnection($connectionString)
        try {
            $connection.Open()
            $connection.Close()
            return $connectionString
        }
        catch {
            $lastError = $_.Exception.Message
        }
        finally {
            $connection.Dispose()
        }
    }

    $bitness = if ([Environment]::Is64BitProcess) { "64-bit" } else { "32-bit" }
    throw "Could not open the Access database from this $bitness process. Use the 32-bit launcher and make sure the 32-bit Microsoft Access Database Engine is installed. Last driver error: $lastError"
}

function Open-AccessConnection {
    param([string]$ConnectionString)

    $connection = New-Object System.Data.OleDb.OleDbConnection($ConnectionString)
    $connection.Open()
    return $connection
}

function Get-SqlActionSummary {
    param([string]$Sql)

    $clean = [regex]::Replace((ConvertTo-BuilderText $Sql), "\s+", " ").Trim()
    if ($clean -match "(?i)^INSERT\s+INTO\s+(\[[^\]]+\]|[A-Za-z0-9_]+)") {
        return "adding a row to " + $matches[1].Trim("[", "]")
    }
    if ($clean -match "(?i)^UPDATE\s+(\[[^\]]+\]|[A-Za-z0-9_]+)") {
        return "updating " + $matches[1].Trim("[", "]")
    }
    if ($clean -match "(?i)^DELETE\s+FROM\s+(\[[^\]]+\]|[A-Za-z0-9_]+)") {
        return "removing rows from " + $matches[1].Trim("[", "]")
    }
    if ($clean -match "(?i)^ALTER\s+TABLE\s+(\[[^\]]+\]|[A-Za-z0-9_]+)") {
        return "changing the table structure for " + $matches[1].Trim("[", "]")
    }
    if ($clean -match "(?i)^CREATE\s+TABLE\s+(\[[^\]]+\]|[A-Za-z0-9_]+)") {
        return "creating " + $matches[1].Trim("[", "]")
    }
    return "writing to the database"
}

function New-DatabaseWriteFailureMessage {
    param(
        [string]$Sql,
        [string]$AccessMessage
    )

    $action = Get-SqlActionSummary -Sql $Sql
    $sqlStart = [regex]::Replace((ConvertTo-BuilderText $Sql), "\s+", " ").Trim()
    if ($sqlStart.Length -gt 360) { $sqlStart = $sqlStart.Substring(0, 360) + "..." }

    if ($sqlStart -match "(?i)\[?(WOOFRunLog|ProjectPickleRunLog)\]?") {
        return @"
Project Pickle could not save its run log table after the database work.

Access reported:
$AccessMessage

What this means:
- The saved project database was already built or partly built.
- The failed write is Project Pickle's own bookkeeping log, not a plot, tree, regen, period, assignment, or AppColumns setup row.
- This usually happens when an older output copy already has a run log table with short text columns.

What to do:
1. Use the newest Project Pickle build and run again. Project Pickle will try to widen the log table automatically.
2. If the database build finished, review the saved project database and the Build tab log.
3. If this happens again, send the last 5 to 10 Build tab log lines plus the technical detail below.

Technical detail for support:
$sqlStart
"@
    }

    return @"
Project Pickle could not finish a database write while $action.

Access reported:
$AccessMessage

What this usually means:
- A required setup entry is missing or invalid.
- A custom AppColumns row is incomplete, especially a Code field with no Codes values.
- The selected database has a table/field layout different from what Project Pickle expected.

What to check:
1. Project tab: choose the database required by the selected mode and Save Project Location. New Project and Upgrade Project also need a project name and project location choices. Existing Project preserves those values from the selected current-format database.
2. Periods tab: use only for New Project and Upgrade Project. Enter at least one numeric PeriodNumber. Dates may be blank, but typed dates must be valid. Existing Project mode preserves the period rows already in the selected database.
3. AppColumns tab: use one complete row per custom field. For Category=Code, put all allowed codes in the Codes cell.
4. Build tab: read the last successful log line. That tells you which setup step Project Pickle reached.

Technical detail for support:
$sqlStart
"@
}

function Invoke-DbNonQuery {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$Sql,
        [int]$CommandTimeoutSeconds = -1
    )

    $command = $Connection.CreateCommand()
    $command.CommandText = $Sql
    if ($CommandTimeoutSeconds -ge 0) { $command.CommandTimeout = $CommandTimeoutSeconds }
    try {
        return $command.ExecuteNonQuery()
    }
    catch {
        $message = New-DatabaseWriteFailureMessage -Sql $Sql -AccessMessage $_.Exception.Message
        $wrapped = New-Object System.Exception($message, $_.Exception)
        try { $wrapped.Data["WOOF SQL"] = $Sql } catch {}
        throw $wrapped
    }
    finally {
        $command.Dispose()
    }
}

function New-DbParam {
    param(
        [string]$Type,
        [object]$Value
    )

    return [pscustomobject]@{
        Type = $Type
        Value = $Value
    }
}

function DbText {
    param([object]$Value)
    $text = ConvertTo-BuilderText $Value
    if ([string]::IsNullOrWhiteSpace($text)) { return (New-DbParam "Text" ([DBNull]::Value)) }
    return (New-DbParam "Text" $text)
}

function DbLongText {
    param([object]$Value)
    $text = ConvertTo-BuilderText $Value
    if ([string]::IsNullOrWhiteSpace($text)) { return (New-DbParam "LongText" ([DBNull]::Value)) }
    return (New-DbParam "LongText" $text)
}

function DbRawText {
    param([object]$Value)
    if ($null -eq $Value -or $Value -is [System.DBNull]) { return (New-DbParam "Text" ([DBNull]::Value)) }
    $text = ConvertTo-RawSingleLineText $Value
    if ($text.Length -eq 0) { return (New-DbParam "Text" ([DBNull]::Value)) }
    return (New-DbParam "Text" $text)
}

function DbRawLongText {
    param([object]$Value)
    if ($null -eq $Value -or $Value -is [System.DBNull]) { return (New-DbParam "LongText" ([DBNull]::Value)) }
    $text = ConvertTo-RawSingleLineText $Value
    if ($text.Length -eq 0) { return (New-DbParam "LongText" ([DBNull]::Value)) }
    return (New-DbParam "LongText" $text)
}

function DbGuid {
    param([object]$Value)
    if ($null -eq $Value -or $Value -is [System.DBNull]) { return (New-DbParam "Guid" ([DBNull]::Value)) }
    $text = ConvertTo-BuilderText $Value
    if ([string]::IsNullOrWhiteSpace($text)) { return (New-DbParam "Guid" ([DBNull]::Value)) }
    $match = [regex]::Match($text, "[0-9A-Fa-f]{8}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{12}")
    if (-not $match.Success) { throw "Expected a database ID value in GUID format, but found '$text'." }
    return (New-DbParam "Guid" ([guid]$match.Value))
}

function DbInt {
    param([object]$Value)
    if ($null -eq $Value -or $Value -is [System.DBNull]) { return (New-DbParam "Integer" ([DBNull]::Value)) }
    $text = ConvertTo-BuilderText $Value
    if ([string]::IsNullOrWhiteSpace($text)) { return (New-DbParam "Integer" ([DBNull]::Value)) }
    $number = 0
    if (-not [int]::TryParse($text, [ref]$number)) { throw "Expected a whole number, but found '$text'." }
    return (New-DbParam "Integer" $number)
}

function DbDouble {
    param([object]$Value)
    if ($null -eq $Value -or $Value -is [System.DBNull]) { return (New-DbParam "Double" ([DBNull]::Value)) }
    $text = ConvertTo-BuilderText $Value
    if ([string]::IsNullOrWhiteSpace($text)) { return (New-DbParam "Double" ([DBNull]::Value)) }
    $number = 0.0
    if ([double]::TryParse($text, [System.Globalization.NumberStyles]::Any, [System.Globalization.CultureInfo]::InvariantCulture, [ref]$number) -or [double]::TryParse($text, [ref]$number)) {
        return (New-DbParam "Double" $number)
    }
    return (New-DbParam "Double" ([DBNull]::Value))
}

function DbDate {
    param([object]$Value)
    if ($null -eq $Value -or $Value -is [System.DBNull]) { return (New-DbParam "Date" ([DBNull]::Value)) }
    if ($Value -is [datetime]) { return (New-DbParam "Date" ([datetime]$Value)) }
    $text = ConvertTo-BuilderText $Value
    if ([string]::IsNullOrWhiteSpace($text)) { return (New-DbParam "Date" ([DBNull]::Value)) }
    $date = [datetime]::MinValue
    if (-not [datetime]::TryParse($text, [ref]$date)) { return (New-DbParam "Date" ([DBNull]::Value)) }
    return (New-DbParam "Date" $date)
}

function DbBool {
    param([object]$Value)
    return (New-DbParam "Boolean" (ConvertTo-BuilderBool $Value))
}

function Add-OleDbParameter {
    param(
        [System.Data.OleDb.OleDbCommand]$Command,
        [object]$Spec
    )

    $typeName = ConvertTo-BuilderText $Spec.Type
    $value = $Spec.Value
    $oleType = switch ($typeName) {
        "Guid" { [System.Data.OleDb.OleDbType]::Guid; break }
        "Integer" { [System.Data.OleDb.OleDbType]::Integer; break }
        "Double" { [System.Data.OleDb.OleDbType]::Double; break }
        "Date" { [System.Data.OleDb.OleDbType]::Date; break }
        "Boolean" { [System.Data.OleDb.OleDbType]::Boolean; break }
        "LongText" { [System.Data.OleDb.OleDbType]::LongVarWChar; break }
        default { [System.Data.OleDb.OleDbType]::VarWChar }
    }
    $parameter = New-Object System.Data.OleDb.OleDbParameter
    $parameter.OleDbType = $oleType
    if ($typeName -eq "Text") { $parameter.Size = 255 }
    $parameter.Value = if ($null -eq $value -or $value -is [System.DBNull]) { [DBNull]::Value } else { $value }
    [void]$Command.Parameters.Add($parameter)
}

function Set-OleDbParameterValue {
    param(
        [System.Data.OleDb.OleDbParameter]$Parameter,
        [object]$Spec
    )

    $value = if ($Spec.PSObject.Properties["Value"]) { $Spec.Value } else { $Spec }
    $Parameter.Value = if ($null -eq $value -or $value -is [System.DBNull]) { [DBNull]::Value } else { $value }
}

function New-DbParameterizedCommand {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$Sql,
        [object[]]$Parameters
    )

    $command = $Connection.CreateCommand()
    $command.CommandText = $Sql
    foreach ($parameter in @($Parameters)) {
        Add-OleDbParameter -Command $command -Spec $parameter
    }
    try { $command.Prepare() } catch {}
    return $command
}

function Invoke-DbPreparedNonQuery {
    param(
        [System.Data.OleDb.OleDbCommand]$Command,
        [string]$Sql,
        [object[]]$Parameters
    )

    if ($Command.Parameters.Count -ne @($Parameters).Count) {
        throw "Prepared database command expected $($Command.Parameters.Count) parameter(s), but received $(@($Parameters).Count)."
    }
    for ($i = 0; $i -lt $Command.Parameters.Count; $i++) {
        Set-OleDbParameterValue -Parameter $Command.Parameters[$i] -Spec $Parameters[$i]
    }
    try {
        return $Command.ExecuteNonQuery()
    }
    catch {
        $message = New-DatabaseWriteFailureMessage -Sql $Sql -AccessMessage $_.Exception.Message
        $wrapped = New-Object System.Exception($message, $_.Exception)
        try { $wrapped.Data["WOOF SQL"] = $Sql } catch {}
        throw $wrapped
    }
}

function Invoke-DbNonQueryParameterized {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$Sql,
        [object[]]$Parameters
    )

    $command = $Connection.CreateCommand()
    $command.CommandText = $Sql
    foreach ($parameter in @($Parameters)) {
        Add-OleDbParameter -Command $command -Spec $parameter
    }
    try {
        return $command.ExecuteNonQuery()
    }
    catch {
        $message = New-DatabaseWriteFailureMessage -Sql $Sql -AccessMessage $_.Exception.Message
        $wrapped = New-Object System.Exception($message, $_.Exception)
        try { $wrapped.Data["WOOF SQL"] = $Sql } catch {}
        throw $wrapped
    }
    finally {
        $command.Dispose()
    }
}

function Invoke-DbNonQueryParameterizedInTransaction {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [System.Data.OleDb.OleDbTransaction]$Transaction,
        [string]$Sql,
        [object[]]$Parameters
    )

    $command = $Connection.CreateCommand()
    $command.Transaction = $Transaction
    $command.CommandText = $Sql
    foreach ($parameter in @($Parameters)) {
        Add-OleDbParameter -Command $command -Spec $parameter
    }
    try {
        return $command.ExecuteNonQuery()
    }
    catch {
        $message = New-DatabaseWriteFailureMessage -Sql $Sql -AccessMessage $_.Exception.Message
        $wrapped = New-Object System.Exception($message, $_.Exception)
        try { $wrapped.Data["WOOF SQL"] = $Sql } catch {}
        throw $wrapped
    }
    finally {
        $command.Dispose()
    }
}

function Get-DbScalar {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$Sql
    )

    $command = $Connection.CreateCommand()
    $command.CommandText = $Sql
    try {
        return $command.ExecuteScalar()
    }
    finally {
        $command.Dispose()
    }
}

function Get-DbTable {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$Sql
    )

    $command = $Connection.CreateCommand()
    $command.CommandText = $Sql
    $adapter = New-Object System.Data.OleDb.OleDbDataAdapter($command)
    $table = New-Object System.Data.DataTable
    try {
        [void]$adapter.Fill($table)
        return ,$table
    }
    finally {
        $adapter.Dispose()
        $command.Dispose()
    }
}

function Get-UserTables {
    param([System.Data.OleDb.OleDbConnection]$Connection)

    $schema = $Connection.GetOleDbSchemaTable([System.Data.OleDb.OleDbSchemaGuid]::Tables, $null)
    $names = New-Object System.Collections.Generic.List[string]
    foreach ($row in $schema.Rows) {
        $name = [string]$row["TABLE_NAME"]
        $type = [string]$row["TABLE_TYPE"]
        if ($type -eq "TABLE" -and
            -not $name.StartsWith("MSys", [System.StringComparison]::OrdinalIgnoreCase) -and
            -not $name.StartsWith("~", [System.StringComparison]::OrdinalIgnoreCase)) {
            [void]$names.Add($name)
        }
    }
    return @($names.ToArray() | Sort-Object)
}

function Get-TableColumns {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName
    )

    $table = Get-DbTable -Connection $Connection -Sql "SELECT * FROM $(Quote-Name $TableName) WHERE 1=0"
    $columns = New-Object System.Collections.Generic.List[string]
    foreach ($column in $table.Columns) {
        [void]$columns.Add([string]$column.ColumnName)
    }
    return [string[]]$columns.ToArray()
}

function Convert-DataColumnTypeToCfideerDataType {
    param([System.Data.DataColumn]$Column)

    if ($null -eq $Column -or $null -eq $Column.DataType) { return "" }
    switch ($Column.DataType.FullName) {
        "System.Guid" { return "Guid" }
        "System.Byte" { return "Byte" }
        "System.Int16" { return "Short" }
        "System.Int32" { return "Long" }
        "System.Int64" { return "Long" }
        "System.Single" { return "Single" }
        "System.Double" { return "Double" }
        "System.Decimal" { return "Currency" }
        "System.DateTime" { return "DateTime" }
        "System.Boolean" { return "Boolean" }
        "System.String" { return "Text" }
        default { return "" }
    }
}

function Convert-OleDbSchemaColumnTypeToCfideerDataType {
    param([System.Data.DataRow]$ColumnRow)

    if ($null -eq $ColumnRow) { return "" }
    $dataTypeValue = $null
    try { $dataTypeValue = $ColumnRow["DATA_TYPE"] } catch { $dataTypeValue = $null }
    if ($null -eq $dataTypeValue -or $dataTypeValue -is [System.DBNull]) { return "" }

    $dataType = [int]$dataTypeValue
    $maxLength = -1
    try {
        $lengthValue = $ColumnRow["CHARACTER_MAXIMUM_LENGTH"]
        if ($null -ne $lengthValue -and -not ($lengthValue -is [System.DBNull])) {
            $maxLength = [int]$lengthValue
        }
    }
    catch {
        $maxLength = -1
    }

    switch ($dataType) {
        2 { return "Short" }       # SmallInt
        3 { return "Long" }        # Integer / Access Long Integer
        4 { return "Single" }
        5 { return "Double" }
        6 { return "Currency" }
        7 { return "DateTime" }
        11 { return "Boolean" }
        16 { return "Byte" }
        17 { return "Byte" }
        72 { return "Guid" }
        133 { return "DateTime" }
        135 { return "DateTime" }
        201 { return "Memo" }      # LongVarChar
        203 { return "Memo" }      # LongVarWChar / Access Long Text
        129 { if ($maxLength -le 0 -or $maxLength -gt 255) { return "Memo" }; return "Text" }
        130 { if ($maxLength -le 0 -or $maxLength -gt 255) { return "Memo" }; return "Text" }
        200 { if ($maxLength -le 0 -or $maxLength -gt 255) { return "Memo" }; return "Text" }
        202 { if ($maxLength -le 0 -or $maxLength -gt 255) { return "Memo" }; return "Text" }
        default { return "" }
    }
}

function Get-TableColumnInfo {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName
    )

    $table = Get-DbTable -Connection $Connection -Sql "SELECT * FROM $(Quote-Name $TableName) WHERE 1=0"
    $schemaDataTypes = @{}
    try {
        $restrictions = @($null, $null, $TableName, $null)
        $schema = $Connection.GetOleDbSchemaTable([System.Data.OleDb.OleDbSchemaGuid]::Columns, $restrictions)
        if ($null -eq $schema -or $schema.Rows.Count -eq 0) {
            $schema = $Connection.GetOleDbSchemaTable([System.Data.OleDb.OleDbSchemaGuid]::Columns, $null)
        }
        foreach ($row in $schema.Rows) {
            $rowTableName = ConvertTo-BuilderText $row["TABLE_NAME"]
            if (-not [string]::Equals($rowTableName, $TableName, [System.StringComparison]::OrdinalIgnoreCase)) { continue }
            $columnName = ConvertTo-BuilderText $row["COLUMN_NAME"]
            if ([string]::IsNullOrWhiteSpace($columnName)) { continue }
            $schemaType = Convert-OleDbSchemaColumnTypeToCfideerDataType -ColumnRow $row
            if (-not [string]::IsNullOrWhiteSpace($schemaType)) {
                $schemaDataTypes[$columnName.ToLowerInvariant()] = $schemaType
            }
        }
    }
    catch {
        $schemaDataTypes = @{}
    }

    $items = New-Object System.Collections.Generic.List[object]
    foreach ($column in $table.Columns) {
        $columnName = [string]$column.ColumnName
        $key = $columnName.ToLowerInvariant()
        $dataType = if ($schemaDataTypes.ContainsKey($key)) { ConvertTo-BuilderText $schemaDataTypes[$key] } else { Convert-DataColumnTypeToCfideerDataType -Column $column }
        [void]$items.Add([pscustomobject]@{
            ColumnName = $columnName
            DataType = $dataType
        })
    }
    return @($items.ToArray())
}

function Test-TableExists {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName
    )

    foreach ($table in (Get-UserTables -Connection $Connection)) {
        if ($table.Equals($TableName, [System.StringComparison]::OrdinalIgnoreCase)) { return $true }
    }
    return $false
}

function Test-ColumnExists {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName,
        [string]$ColumnName
    )

    foreach ($column in (Get-TableColumns -Connection $Connection -TableName $TableName)) {
        if ($column.Equals($ColumnName, [System.StringComparison]::OrdinalIgnoreCase)) { return $true }
    }
    return $false
}

function Test-AzureAiEndpoint {
    param([string]$Endpoint)

    $uri = $null
    if (-not [System.Uri]::TryCreate(([string]$Endpoint), [System.UriKind]::Absolute, [ref]$uri)) { return $false }
    if ($uri.Host -match "(^|\.)openai\.azure\.com$") { return $true }
    if ($uri.Host -match "(^|\.)cognitiveservices\.azure\.com$") { return $true }
    if ($uri.AbsolutePath -match "/openai/deployments/") { return $true }
    return $false
}

function Get-ApprovedAiHosts {
    $hosts = New-Object System.Collections.Generic.List[string]
    foreach ($hostName in @($script:AiApprovedHosts)) {
        $clean = (ConvertTo-BuilderText $hostName).ToLowerInvariant()
        if (-not [string]::IsNullOrWhiteSpace($clean) -and -not $hosts.Contains($clean)) {
            [void]$hosts.Add($clean)
        }
    }

    $extraHosts = ConvertTo-BuilderText $env:CFI_PROJECT_PICKLE_APPROVED_AI_HOSTS
    if ([string]::IsNullOrWhiteSpace($extraHosts)) {
        $extraHosts = ConvertTo-BuilderText $env:CFI_PROJECTPICKLE_APPROVED_AI_HOSTS
        if ([string]::IsNullOrWhiteSpace($extraHosts)) {
            $extraHosts = ConvertTo-BuilderText $env:CFI_WOOF_APPROVED_AI_HOSTS
        }
    }
    if (-not [string]::IsNullOrWhiteSpace($extraHosts)) {
        foreach ($hostName in @($extraHosts -split "[,; ]+")) {
            $clean = (ConvertTo-BuilderText $hostName).ToLowerInvariant()
            if (-not [string]::IsNullOrWhiteSpace($clean) -and -not $hosts.Contains($clean)) {
                [void]$hosts.Add($clean)
            }
        }
    }

    return [string[]]$hosts.ToArray()
}

function Assert-ApprovedAiEndpoint {
    param([string]$Endpoint)

    $uri = $null
    if (-not [System.Uri]::TryCreate(([string]$Endpoint), [System.UriKind]::Absolute, [ref]$uri)) {
        throw "Enter a valid HTTPS AI endpoint."
    }
    if ($uri.Scheme -ne "https") {
        throw "AI endpoint must use HTTPS."
    }

    $hostName = $uri.Host.ToLowerInvariant()
    $approvedHosts = @(Get-ApprovedAiHosts)
    if (-not ($approvedHosts -contains $hostName)) {
        throw "AI endpoint '$hostName' is not approved for Project Pickle. Approved host(s): $([string]::Join(', ', [string[]]$approvedHosts)). IT can add hosts with CFI_PROJECT_PICKLE_APPROVED_AI_HOSTS."
    }
}

function Get-AiRequestTarget {
    param(
        [string]$Endpoint,
        [string]$Model
    )

    $endpointText = (ConvertTo-BuilderText $Endpoint).TrimEnd("/")
    if ([string]::IsNullOrWhiteSpace($endpointText)) { throw "Enter an AI endpoint." }
    if ([string]::IsNullOrWhiteSpace($Model)) { throw "Enter an AI model or deployment name." }
    if ($Model -notmatch "^[A-Za-z0-9._-]+$") { throw "AI model/deployment name may contain only letters, numbers, dots, underscores, and hyphens." }

    Assert-ApprovedAiEndpoint -Endpoint $endpointText
    if (-not (Test-AzureAiEndpoint -Endpoint $endpointText)) {
        throw "Only approved Azure OpenAI endpoints are allowed."
    }

    if ($endpointText -match "/chat/completions") {
        $uriText = $endpointText
    }
    elseif ($endpointText -match "/openai/deployments/") {
        $uriText = $endpointText.TrimEnd("/") + "/chat/completions"
    }
    else {
        $deploymentName = [System.Uri]::EscapeDataString($Model)
        $uriText = $endpointText + "/openai/deployments/$deploymentName/chat/completions"
    }

    if ($uriText -notmatch "\?") {
        $uriText += "?api-version=$script:AzureOpenAiApiVersion"
    }
    elseif ($uriText -notmatch "api-version=") {
        $uriText += "&api-version=$script:AzureOpenAiApiVersion"
    }

    return [pscustomobject]@{ Uri = $uriText; IsAzure = $true }
}

function Invoke-WOOFAiChat {
    param(
        [string]$Endpoint,
        [string]$Model,
        [string]$ApiKey,
        [string]$SystemMessage,
        [string]$UserMessage,
        [int]$MaxTokens = 1200
    )

    if ([string]::IsNullOrWhiteSpace($ApiKey)) { throw "Enter an AI API key." }
    $target = Get-AiRequestTarget -Endpoint $Endpoint -Model $Model
    $headers = @{ "api-key" = $ApiKey }
    $body = @{
        messages = @(
            @{ role = "system"; content = $SystemMessage },
            @{ role = "user"; content = $UserMessage }
        )
        max_tokens = $MaxTokens
        temperature = 0.1
    }

    $json = $body | ConvertTo-Json -Depth 10
    $bytes = [System.Text.Encoding]::UTF8.GetBytes($json)
    $response = Invoke-RestMethod -Method Post -Uri ([string]$target.Uri) -Headers $headers -ContentType "application/json; charset=utf-8" -Body $bytes -TimeoutSec 90
    if ($response.PSObject.Properties["choices"] -and $response.choices.Count -gt 0) {
        return ConvertTo-AiText $response.choices[0].message.content
    }
    return ConvertTo-AiText ($response | ConvertTo-Json -Depth 8)
}

function Invoke-WOOFAiConnectionTestRequest {
    param(
        [string]$Endpoint,
        [string]$Model,
        [string]$ApiKey
    )

    $text = Invoke-WOOFAiChat -Endpoint $Endpoint -Model $Model -ApiKey $ApiKey -SystemMessage "This is a connection test for Project Pickle. Reply with OK." -UserMessage "Connection test." -MaxTokens 20
    if (-not [string]::IsNullOrWhiteSpace($text)) { return "Connection succeeded. Model response: $text" }
    return "Connection succeeded, but the model returned an empty response."
}

function Get-ZipEntryText {
    param(
        [System.IO.Compression.ZipArchive]$Archive,
        [string]$EntryName
    )

    $entry = $Archive.GetEntry($EntryName)
    if ($null -eq $entry) { return "" }
    $stream = $entry.Open()
    try {
        $reader = New-Object System.IO.StreamReader($stream, [System.Text.Encoding]::UTF8, $true)
        try {
            return $reader.ReadToEnd()
        }
        finally {
            $reader.Dispose()
        }
    }
    finally {
        $stream.Dispose()
    }
}

function Convert-OpenXmlContentToPlainText {
    param([string]$XmlText)

    if ([string]::IsNullOrWhiteSpace($XmlText)) { return "" }
    $text = $XmlText
    $text = $text -replace "<w:tab\s*/>", " "
    $text = $text -replace "</w:p>", "`r`n"
    $text = $text -replace "</w:tr>", "`r`n"
    $text = $text -replace "</w:tc>", " "
    $text = $text -replace "<[^>]+>", ""
    $text = [System.Net.WebUtility]::HtmlDecode($text)
    return ConvertTo-BuilderText $text
}

function Get-DocxTextFromFile {
    param([string]$Path)

    Add-Type -AssemblyName System.IO.Compression
    Add-Type -AssemblyName System.IO.Compression.FileSystem
    $archive = [System.IO.Compression.ZipFile]::OpenRead($Path)
    try {
        $parts = New-Object System.Collections.Generic.List[string]
        foreach ($entryName in @("word/document.xml", "word/footnotes.xml", "word/endnotes.xml")) {
            $xmlText = Get-ZipEntryText -Archive $archive -EntryName $entryName
            $plain = Convert-OpenXmlContentToPlainText -XmlText $xmlText
            if (-not [string]::IsNullOrWhiteSpace($plain)) { [void]$parts.Add($plain) }
        }
        return [string]::Join("`r`n", [string[]]$parts.ToArray())
    }
    finally {
        $archive.Dispose()
    }
}

function Get-WOOFGuideTextFromFile {
    param([string]$Path)

    if ([string]::IsNullOrWhiteSpace($Path)) { return "" }
    if (-not (Test-Path -LiteralPath $Path)) { throw "Guide or reference file not found: $Path" }

    $extension = [System.IO.Path]::GetExtension($Path).ToLowerInvariant()
    switch ($extension) {
        ".txt" { return Get-Content -LiteralPath $Path -Raw }
        ".md" { return Get-Content -LiteralPath $Path -Raw }
        ".csv" { return Get-Content -LiteralPath $Path -Raw }
        ".json" { return Get-Content -LiteralPath $Path -Raw }
        ".ps1" { return Get-Content -LiteralPath $Path -Raw }
        ".docx" { return Get-DocxTextFromFile -Path $Path }
        ".xlsx" {
            $rows = @(Get-OpenXmlRows -Path $Path)
            return [string]::Join("`r`n", [string[]]@($rows | ForEach-Object { [string]::Join(" | ", [string[]]$_.Values) }))
        }
        ".xlsm" {
            $rows = @(Get-OpenXmlRows -Path $Path)
            return [string]::Join("`r`n", [string[]]@($rows | ForEach-Object { [string]::Join(" | ", [string[]]$_.Values) }))
        }
        default { throw "Guide uploads support DOCX, XLSX, XLSM, TXT, MD, CSV, JSON, or PS1 files. PDF and old XLS uploads are disabled because they require Office automation." }
    }
}

function Limit-Text {
    param(
        [string]$Text,
        [int]$MaxLength
    )

    if ([string]::IsNullOrWhiteSpace($Text)) { return "" }
    if ($Text.Length -le $MaxLength) { return $Text }
    return $Text.Substring(0, $MaxLength) + "`r`n...[truncated]..."
}

function Get-RelevantTextSnippets {
    param(
        [string]$Text,
        [string]$Question,
        [string]$SourceName,
        [int]$ChunkSize = 2200,
        [int]$MaxSnippets = 4
    )

    if ([string]::IsNullOrWhiteSpace($Text)) { return "" }
    $terms = @([regex]::Matches((ConvertTo-BuilderText $Question).ToLowerInvariant(), "[a-z0-9_]{4,}") | ForEach-Object { $_.Value } | Select-Object -Unique)
    if ($terms.Count -eq 0) { $terms = @("project", "plot", "period", "appcolumns", "assignment", "query") }

    $chunks = New-Object System.Collections.Generic.List[object]
    for ($i = 0; $i -lt $Text.Length; $i += $ChunkSize) {
        $length = [Math]::Min($ChunkSize, $Text.Length - $i)
        $chunk = $Text.Substring($i, $length)
        $lower = $chunk.ToLowerInvariant()
        $score = 0
        foreach ($term in $terms) {
            $score += ([regex]::Matches($lower, [regex]::Escape($term))).Count
        }
        if ($score -gt 0) {
            [void]$chunks.Add([pscustomobject]@{ Score = $score; Start = $i; Text = $chunk })
        }
    }

    if ($chunks.Count -eq 0) {
        return "[$SourceName]`r`n" + (Limit-Text -Text $Text -MaxLength $ChunkSize)
    }

    $selected = @($chunks | Sort-Object -Property Score -Descending | Select-Object -First $MaxSnippets | Sort-Object -Property Start)
    $parts = New-Object System.Collections.Generic.List[string]
    foreach ($chunk in $selected) {
        [void]$parts.Add("[$SourceName offset $($chunk.Start)]`r`n$($chunk.Text)")
    }
    return [string]::Join("`r`n---`r`n", [string[]]$parts.ToArray())
}

function Get-WOOFAiContext {
    param(
        [string]$Question,
        [string]$GuidePath,
        [bool]$IncludeCode
    )

    $parts = New-Object System.Collections.Generic.List[string]
    $aiContextPath = Join-Path $script:AppRoot "AI-HELP-CONTEXT.md"
    if (Test-Path -LiteralPath $readmePath) {
        [void]$parts.Add("Project Pickle README:`r`n" + (Limit-Text -Text (Get-Content -LiteralPath $readmePath -Raw) -MaxLength 7000))
    }

    if ($IncludeCode) {
        $codePath = Join-Path $script:AppRoot "ProjectPickle.ps1"
        if (Test-Path -LiteralPath $codePath) {
            $codeText = Get-Content -LiteralPath $codePath -Raw
            [void]$parts.Add("Relevant Project Pickle code snippets:`r`n" + (Get-RelevantTextSnippets -Text $codeText -Question $Question -SourceName "ProjectPickle.ps1" -ChunkSize 2600 -MaxSnippets 5))
        }
    }

    if (-not [string]::IsNullOrWhiteSpace($GuidePath)) {
        $guideText = Get-WOOFGuideTextFromFile -Path $GuidePath
        [void]$parts.Add("Relevant guide/reference snippets from ${GuidePath}:`r`n" + (Get-RelevantTextSnippets -Text $guideText -Question $Question -SourceName ([System.IO.Path]::GetFileName($GuidePath)) -ChunkSize 2600 -MaxSnippets 5))
    }

    return [string]::Join("`r`n`r`n====`r`n`r`n", [string[]]$parts.ToArray())
}

function Invoke-WOOFAiHelpRequest {
    param(
        [string]$Endpoint,
        [string]$Model,
        [string]$ApiKey,
        [string]$Question,
        [string]$GuidePath,
        [bool]$IncludeCode
    )

    $cleanQuestion = ConvertTo-BuilderText $Question
    if ([string]::IsNullOrWhiteSpace($cleanQuestion)) { throw "Enter a question for Project Pickle AI Help." }

    $context = Get-WOOFAiContext -Question $cleanQuestion -GuidePath $GuidePath -IncludeCode $IncludeCode
    $systemMessage = "You are Project Pickle AI Help for a CFI Access inventory database setup tool. Answer practical how-to questions using only the provided Project Pickle README, relevant code snippets, and optional CFI guide/reference snippets. Be concise, use step-by-step instructions when useful, and call out uncertainty or guide items the user should verify. Do not claim you changed the database or the app. Do not provide policy/legal/security guarantees."
    $userMessage = @"
User question:
$cleanQuestion

Available context:
$context
"@

    return Invoke-WOOFAiChat -Endpoint $Endpoint -Model $Model -ApiKey $ApiKey -SystemMessage $systemMessage -UserMessage $userMessage -MaxTokens 1400
}

function Ensure-WOOFRunLogTable {
    param([System.Data.OleDb.OleDbConnection]$Connection)

    $tableName = $script:RunLogTableName
    $columns = @(
        [pscustomobject]@{ Name = "RunID"; Type = "TEXT(38)" },
        [pscustomobject]@{ Name = "StepNumber"; Type = "INTEGER" },
        [pscustomobject]@{ Name = "LogTime"; Type = "DATETIME" },
        [pscustomobject]@{ Name = "RunStatus"; Type = "TEXT(64)" },
        [pscustomobject]@{ Name = "StepCategory"; Type = "TEXT(64)" },
        [pscustomobject]@{ Name = "ElapsedSeconds"; Type = "DOUBLE" },
        [pscustomobject]@{ Name = "StepDurationSeconds"; Type = "DOUBLE" },
        [pscustomobject]@{ Name = "ElapsedTime"; Type = "TEXT(32)" },
        [pscustomobject]@{ Name = "StepDuration"; Type = "TEXT(32)" },
        [pscustomobject]@{ Name = "Mode"; Type = "TEXT(64)" },
        [pscustomobject]@{ Name = "ProjectName"; Type = "TEXT(255)" },
        [pscustomobject]@{ Name = "SourceDatabase"; Type = "LONGTEXT" },
        [pscustomobject]@{ Name = "OutputDatabase"; Type = "LONGTEXT" },
        [pscustomobject]@{ Name = "Message"; Type = "LONGTEXT" }
    )

    if (-not (Test-TableExists -Connection $Connection -TableName $tableName)) {
        $definitions = $columns | ForEach-Object { "$(Quote-Name $_.Name) $($_.Type)" }
        [void](Invoke-DbNonQuery -Connection $Connection -Sql "CREATE TABLE $(Quote-Name $tableName) ($([string]::Join(', ', [string[]]$definitions)))")
        return
    }

    foreach ($column in $columns) {
        if (-not (Test-ColumnExists -Connection $Connection -TableName $tableName -ColumnName $column.Name)) {
            [void](Invoke-DbNonQuery -Connection $Connection -Sql "ALTER TABLE $(Quote-Name $tableName) ADD COLUMN $(Quote-Name $column.Name) $($column.Type)")
        }
    }

    foreach ($column in $columns) {
        if (Test-ColumnExists -Connection $Connection -TableName $tableName -ColumnName $column.Name) {
            try {
                [void](Invoke-DbNonQuery -Connection $Connection -Sql "ALTER TABLE $(Quote-Name $tableName) ALTER COLUMN $(Quote-Name $column.Name) $($column.Type)")
            }
            catch {
                if ($column.Name -in @("Mode", "RunStatus", "SourceDatabase", "OutputDatabase", "Message")) {
                    try {
                        [void](Invoke-DbNonQuery -Connection $Connection -Sql "ALTER TABLE $(Quote-Name $tableName) ALTER COLUMN $(Quote-Name $column.Name) LONGTEXT")
                    }
                    catch {
                        # Older output copies may already have data in this table. If Access will not
                        # change a non-critical log column, keep building and let the insert surface it.
                    }
                }
            }
        }
    }
}

function Format-WOOFDuration {
    param([double]$Seconds)

    if ($Seconds -lt 0) { $Seconds = 0 }
    $duration = [System.TimeSpan]::FromSeconds($Seconds)
    if ($duration.TotalHours -ge 1) {
        return ("{0:00}:{1:00}:{2:00}.{3:000}" -f [int]$duration.TotalHours, $duration.Minutes, $duration.Seconds, $duration.Milliseconds)
    }
    return ("{0:00}:{1:00}.{2:000}" -f $duration.Minutes, $duration.Seconds, $duration.Milliseconds)
}

function Get-WOOFRunLogStepCategory {
    param([string]$Message)

    $text = ConvertTo-BuilderText $Message
    if ([string]::IsNullOrWhiteSpace($text)) { return "General" }
    if ($text -match "(?i)run log|WOOFRunLog|ProjectPickleRunLog") { return "Run Log" }
    if ($text -match "(?i)build started|build complete|build failed|total run time") { return "Build" }
    if ($text -match "(?i)CFIDEER|_prjCFIDEER|query") { return "CFIDEER Queries" }
    if ($text -match "(?i)upgrade|old database|moved-field|manual field mapping|unmapped|mapping") { return "Upgrade Import" }
    if ($text -match "(?i)AppColumns|custom field|custom measurement field|placeholder column|AppColumnCodes") { return "AppColumns" }
    if ($text -match "(?i)report|ReportHeaders|ReportColumns") { return "Reports" }
    if ($text -match "(?i)assignment|InventoryAssignment|crew") { return "Assignments" }
    if ($text -match "(?i)plot import|plot row|PlotMeasurements|PlotCustomMeasurements|plots") { return "Plots" }
    if ($text -match "(?i)period|ProjectMeasurementPeriods|ValidationRules|ApplicablePeriods") { return "Periods/Validation" }
    if ($text -match "(?i)project row|ProjectID|reservation|agency|region|reference") { return "Project Setup" }
    if ($text -match "(?i)copying|backup|output copy|source database") { return "Database Copy" }
    if ($text -match "(?i)application title|open output|final") { return "Finalization" }
    return "General"
}

function Get-WOOFConfigPropertyText {
    param(
        [object]$Config,
        [string]$Name
    )

    if ($null -eq $Config) { return "" }
    if ($Config.PSObject.Properties[$Name]) {
        return ConvertTo-BuilderText $Config.PSObject.Properties[$Name].Value
    }
    return ""
}

function ConvertTo-WOOFSafeFileNamePart {
    param(
        [string]$Text,
        [string]$Fallback = "ProjectPickle"
    )

    $clean = ConvertTo-BuilderText $Text
    if ([string]::IsNullOrWhiteSpace($clean)) { $clean = $Fallback }
    foreach ($character in [System.IO.Path]::GetInvalidFileNameChars()) {
        $clean = $clean.Replace([string]$character, "_")
    }
    $clean = [regex]::Replace($clean, "\s+", "_")
    $clean = $clean.Trim("._- ".ToCharArray())
    if ([string]::IsNullOrWhiteSpace($clean)) { $clean = $Fallback }
    return $clean
}

function Get-WOOFRunLogTextPath {
    param(
        [object]$Config,
        [string]$RunStatus = "Success"
    )

    $stamp = Get-Date -Format "yyyyMMdd_HHmmss"
    $statusPart = ConvertTo-WOOFSafeFileNamePart -Text $RunStatus -Fallback "Run"
    $outputDatabase = Get-WOOFConfigPropertyText -Config $Config -Name "OutputDatabase"
    $folder = ""
    $baseName = ""
    if (-not [string]::IsNullOrWhiteSpace($outputDatabase)) {
        try {
            $folder = [System.IO.Path]::GetDirectoryName($outputDatabase)
            $baseName = [System.IO.Path]::GetFileNameWithoutExtension($outputDatabase)
        }
        catch {
            $folder = ""
            $baseName = ""
        }
    }
    if ([string]::Equals($RunStatus, "Live", [System.StringComparison]::OrdinalIgnoreCase)) {
        $folder = Join-Path ([System.IO.Path]::GetTempPath()) "Project Pickle Logs"
    }
    elseif ([string]::IsNullOrWhiteSpace($folder)) {
        $folder = if (-not [string]::IsNullOrWhiteSpace($script:AppRoot)) { $script:AppRoot } else { [System.IO.Path]::GetTempPath() }
    }
    if ([string]::IsNullOrWhiteSpace($baseName)) {
        $baseName = Get-WOOFConfigPropertyText -Config $Config -Name "ProjectName"
    }
    $baseName = ConvertTo-WOOFSafeFileNamePart -Text $baseName -Fallback "ProjectPickle"
    return (Join-Path $folder "$baseName.ProjectPickleRunLog.$statusPart.$stamp.txt")
}

function Format-WOOFRunLogTextLine {
    param(
        [object]$Entry,
        [int]$Step = 1
    )

    $entryProperties = @($Entry.PSObject.Properties.Name)
    $logTime = if ($entryProperties -contains "LogTime") { $Entry.LogTime } else { Get-Date }
    if ($null -eq $logTime -or $logTime -is [System.DBNull]) { $logTime = Get-Date }
    $logTime = [datetime]$logTime
    $message = if ($entryProperties -contains "Message") { [string]$Entry.Message } else { [string]$Entry }
    if ($null -eq $message) { $message = "" }
    $category = if ($entryProperties -contains "StepCategory" -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Entry.StepCategory))) { ConvertTo-BuilderText $Entry.StepCategory } else { Get-WOOFRunLogStepCategory -Message $message }
    $elapsedTime = if ($entryProperties -contains "ElapsedTime" -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Entry.ElapsedTime))) { ConvertTo-BuilderText $Entry.ElapsedTime } else { "00:00.000" }
    $stepDuration = if ($entryProperties -contains "StepDuration" -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Entry.StepDuration))) { ConvertTo-BuilderText $Entry.StepDuration } else { "00:00.000" }
    $cleanMessage = $message.Replace("`r`n", "`n").Replace("`r", "`n").Replace("`n", " / ")
    return ("{0:0000} | {1} | {2} | {3} | {4} | {5}" -f $Step, $logTime.ToString("yyyy-MM-dd HH:mm:ss.fff"), $category, $elapsedTime, $stepDuration, $cleanMessage)
}

function Start-WOOFLiveRunLogTextExport {
    param([object]$Config)

    $path = Get-WOOFRunLogTextPath -Config $Config -RunStatus "Live"
    $folder = [System.IO.Path]::GetDirectoryName($path)
    if (-not [string]::IsNullOrWhiteSpace($folder) -and -not (Test-Path -LiteralPath $folder)) {
        [void](New-Item -ItemType Directory -Path $folder -Force)
    }

    return $path
}

function Add-WOOFLiveRunLogTextEntry {
    param(
        [string]$Path,
        [object]$Entry,
        [int]$Step = 1
    )

    if ([string]::IsNullOrWhiteSpace($Path)) { return }
    try {
        [System.IO.File]::AppendAllLines($Path, [string[]]@((Format-WOOFRunLogTextLine -Entry $Entry -Step $Step)), [System.Text.Encoding]::UTF8)
    }
    catch {
    }
}

function Add-WOOFLiveRunLogMarker {
    param(
        [string]$Path,
        [string]$Text
    )

    if ([string]::IsNullOrWhiteSpace($Path)) { return }
    try {
        $line = "{0} | {1}" -f (Get-Date).ToString("yyyy-MM-dd HH:mm:ss.fff"), (ConvertTo-BuilderText $Text)
        [System.IO.File]::AppendAllLines($Path, [string[]]@("", $line), [System.Text.Encoding]::UTF8)
    }
    catch {
    }
}

function Write-WOOFRunLogTextExport {
    param(
        [object[]]$Entries,
        [object]$Config,
        [string]$RunStatus = "Success",
        [string]$PreferredPath = ""
    )

    if ($null -eq $Entries -or $Entries.Count -eq 0) { return "" }
    $path = ConvertTo-BuilderText $PreferredPath
    if ([string]::IsNullOrWhiteSpace($path)) {
        $path = Get-WOOFRunLogTextPath -Config $Config -RunStatus $RunStatus
    }
    $folder = [System.IO.Path]::GetDirectoryName($path)
    if (-not [string]::IsNullOrWhiteSpace($folder) -and -not (Test-Path -LiteralPath $folder)) {
        [void](New-Item -ItemType Directory -Path $folder -Force)
    }

    $lines = New-Object System.Collections.Generic.List[string]
    [void]$lines.Add("Project Pickle Detailed Run Log")
    [void]$lines.Add(("Exported: {0}" -f (Get-Date).ToString("yyyy-MM-dd HH:mm:ss")))
    [void]$lines.Add(("Run status: {0}" -f (ConvertTo-BuilderText $RunStatus)))
    [void]$lines.Add(("Mode: {0}" -f (Get-WOOFConfigPropertyText -Config $Config -Name "Mode")))
    [void]$lines.Add(("Project: {0}" -f (Get-WOOFConfigPropertyText -Config $Config -Name "ProjectName")))
    [void]$lines.Add(("Existing/old project database: {0}" -f (Get-WOOFConfigPropertyText -Config $Config -Name "SourceDatabase")))
    [void]$lines.Add(("Current master database version: {0}" -f (Get-WOOFConfigPropertyText -Config $Config -Name "UpgradeTemplateDatabase")))
    [void]$lines.Add(("Save Project Location: {0}" -f (Get-WOOFConfigPropertyText -Config $Config -Name "OutputDatabase")))
    [void]$lines.Add("")
    [void]$lines.Add("Step | Log time | Category | Elapsed | Step duration | Message")
    [void]$lines.Add("-----|----------|----------|---------|---------------|--------")

    $step = 1
    $firstLogTime = $null
    $previousLogTime = $null
    foreach ($entry in $Entries) {
        $entryProperties = @($entry.PSObject.Properties.Name)
        $logTime = if ($entryProperties -contains "LogTime") { $entry.LogTime } else { Get-Date }
        if ($null -eq $logTime -or $logTime -is [System.DBNull]) { $logTime = Get-Date }
        $logTime = [datetime]$logTime
        if ($null -eq $firstLogTime) { $firstLogTime = $logTime }
        $message = if ($entryProperties -contains "Message") { [string]$entry.Message } else { [string]$entry }
        if ($null -eq $message) { $message = "" }
        $category = if ($entryProperties -contains "StepCategory" -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $entry.StepCategory))) { ConvertTo-BuilderText $entry.StepCategory } else { Get-WOOFRunLogStepCategory -Message $message }
        $elapsedSeconds = if ($entryProperties -contains "ElapsedSeconds" -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $entry.ElapsedSeconds))) { [double]$entry.ElapsedSeconds } else { [Math]::Round(($logTime - [datetime]$firstLogTime).TotalSeconds, 3) }
        $stepDurationSeconds = if ($entryProperties -contains "StepDurationSeconds" -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $entry.StepDurationSeconds))) { [double]$entry.StepDurationSeconds } elseif ($null -eq $previousLogTime) { 0.0 } else { [Math]::Round(($logTime - [datetime]$previousLogTime).TotalSeconds, 3) }
        $elapsedTime = if ($entryProperties -contains "ElapsedTime" -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $entry.ElapsedTime))) { ConvertTo-BuilderText $entry.ElapsedTime } else { Format-WOOFDuration -Seconds $elapsedSeconds }
        $stepDuration = if ($entryProperties -contains "StepDuration" -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $entry.StepDuration))) { ConvertTo-BuilderText $entry.StepDuration } else { Format-WOOFDuration -Seconds $stepDurationSeconds }
        $cleanMessage = $message.Replace("`r`n", "`n").Replace("`r", "`n").Replace("`n", " / ")
        [void]$lines.Add(("{0:0000} | {1} | {2} | {3} | {4} | {5}" -f $step, $logTime.ToString("yyyy-MM-dd HH:mm:ss.fff"), $category, $elapsedTime, $stepDuration, $cleanMessage))
        $previousLogTime = $logTime
        $step++
    }

    [System.IO.File]::WriteAllLines($path, [string[]]$lines.ToArray(), [System.Text.Encoding]::UTF8)
    return $path
}

function Get-ProjectPickleCrashLogPath {
    $folder = Get-ProjectPickleLogFolder
    return (Join-Path $folder "ProjectPickle.LastError.txt")
}

function Get-ProjectPickleLogFolder {
    $folder = if (-not [string]::IsNullOrWhiteSpace($script:AppRoot)) { $script:AppRoot } else { [System.IO.Path]::GetTempPath() }
    try {
        if (-not [string]::IsNullOrWhiteSpace($folder)) {
            $leafName = [System.IO.Path]::GetFileName($folder)
            if ($leafName -eq "Project Pickle App Files") {
                $parentFolder = Split-Path -Path $folder -Parent
                if (-not [string]::IsNullOrWhiteSpace($parentFolder)) {
                    $folder = $parentFolder
                }
            }
        }
    }
    catch {
    }
    return $folder
}

function Get-ProjectPickleDiagnosticLogPath {
    return (Join-Path (Get-ProjectPickleLogFolder) "ProjectPickle.Diagnostics.txt")
}

function Write-ProjectPickleDiagnosticLog {
    param(
        [string]$Message,
        [string]$Context = ""
    )

    try {
        $path = Get-ProjectPickleDiagnosticLogPath
        $lines = New-Object System.Collections.Generic.List[string]
        [void]$lines.Add(("Time: {0}" -f (Get-Date).ToString("yyyy-MM-dd HH:mm:ss.fff")))
        [void]$lines.Add(("Version: {0}" -f (ConvertTo-BuilderText $script:AppVersion)))
        if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Context))) {
            [void]$lines.Add(("Context: {0}" -f (ConvertTo-BuilderText $Context)))
        }
        [void]$lines.Add(("Message: {0}" -f (ConvertTo-BuilderText $Message)))
        [void]$lines.Add("")
        [System.IO.File]::AppendAllLines($path, [string[]]$lines.ToArray(), [System.Text.Encoding]::UTF8)
        return $path
    }
    catch {
        return ""
    }
}

function Write-ProjectPickleCrashLog {
    param(
        [object]$ExceptionObject,
        [string]$Context = ""
    )

    $path = Get-ProjectPickleCrashLogPath
    $lines = New-Object System.Collections.Generic.List[string]
    [void]$lines.Add("Project Pickle Error Log")
    [void]$lines.Add(("Time: {0}" -f (Get-Date).ToString("yyyy-MM-dd HH:mm:ss")))
    [void]$lines.Add(("Version: {0}" -f (ConvertTo-BuilderText $script:AppVersion)))
    [void]$lines.Add(("Script: {0}" -f (ConvertTo-BuilderText $script:AppScriptPath)))
    if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Context))) {
        [void]$lines.Add(("Context: {0}" -f (ConvertTo-BuilderText $Context)))
    }
    [void]$lines.Add("")
    if ($null -eq $ExceptionObject) {
        [void]$lines.Add("No exception details were available.")
    }
    else {
        [void]$lines.Add([string]$ExceptionObject)
    }
    [System.IO.File]::WriteAllLines($path, [string[]]$lines.ToArray(), [System.Text.Encoding]::UTF8)
    try { [void](Write-ProjectPickleDiagnosticLog -Message ([string]$ExceptionObject) -Context $Context) } catch {}
    return $path
}

function Write-WOOFRunLog {
    param(
        [string]$DatabasePath,
        [object[]]$Entries,
        [object]$Config,
        [string]$RunStatus = "Success"
    )

    if ([string]::IsNullOrWhiteSpace($DatabasePath) -or -not (Test-Path -LiteralPath $DatabasePath)) { return }
    if ($null -eq $Entries -or $Entries.Count -eq 0) { return }

    $connectionString = New-AccessConnectionString -Path $DatabasePath
    $connection = Open-AccessConnection -ConnectionString $connectionString
    try {
        Ensure-WOOFRunLogTable -Connection $connection
        $runId = ([guid]::NewGuid()).ToString()
        $step = 1
        $firstLogTime = $null
        $previousLogTime = $null
        foreach ($entry in $Entries) {
            $entryProperties = @($entry.PSObject.Properties.Name)
            $logTime = if ($entryProperties -contains "LogTime") { $entry.LogTime } else { Get-Date }
            if ($null -eq $logTime -or $logTime -is [System.DBNull]) { $logTime = Get-Date }
            $logTime = [datetime]$logTime
            if ($null -eq $firstLogTime) { $firstLogTime = $logTime }
            $message = if ($entryProperties -contains "Message") { $entry.Message } else { [string]$entry }
            $category = if ($entryProperties -contains "StepCategory" -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $entry.StepCategory))) { ConvertTo-BuilderText $entry.StepCategory } else { Get-WOOFRunLogStepCategory -Message $message }
            $elapsedSeconds = if ($entryProperties -contains "ElapsedSeconds" -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $entry.ElapsedSeconds))) { [double]$entry.ElapsedSeconds } else { [Math]::Round(($logTime - [datetime]$firstLogTime).TotalSeconds, 3) }
            $stepDurationSeconds = if ($entryProperties -contains "StepDurationSeconds" -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $entry.StepDurationSeconds))) { [double]$entry.StepDurationSeconds } elseif ($null -eq $previousLogTime) { 0.0 } else { [Math]::Round(($logTime - [datetime]$previousLogTime).TotalSeconds, 3) }
            $elapsedTime = if ($entryProperties -contains "ElapsedTime" -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $entry.ElapsedTime))) { ConvertTo-BuilderText $entry.ElapsedTime } else { Format-WOOFDuration -Seconds $elapsedSeconds }
            $stepDuration = if ($entryProperties -contains "StepDuration" -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $entry.StepDuration))) { ConvertTo-BuilderText $entry.StepDuration } else { Format-WOOFDuration -Seconds $stepDurationSeconds }
            [void](Invoke-DbNonQueryParameterized -Connection $connection -Sql "INSERT INTO [$script:RunLogTableName] ([RunID], [StepNumber], [LogTime], [RunStatus], [StepCategory], [ElapsedSeconds], [StepDurationSeconds], [ElapsedTime], [StepDuration], [Mode], [ProjectName], [SourceDatabase], [OutputDatabase], [Message]) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)" -Parameters @(
                (DbText $runId),
                (DbInt $step),
                (DbDate $logTime),
                (DbText $RunStatus),
                (DbText $category),
                (DbDouble $elapsedSeconds),
                (DbDouble $stepDurationSeconds),
                (DbText $elapsedTime),
                (DbText $stepDuration),
                (DbText $Config.Mode),
                (DbText $Config.ProjectName),
                (DbLongText $Config.SourceDatabase),
                (DbLongText $Config.OutputDatabase),
                (DbLongText $message)
            ))
            $previousLogTime = $logTime
            $step++
        }
    }
    finally {
        if ($connection.State -eq "Open") { $connection.Close() }
        $connection.Dispose()
    }
}

function Get-RequiredScalarText {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$Sql,
        [string]$Message
    )

    $value = Get-DbScalar -Connection $Connection -Sql $Sql
    $text = ConvertTo-BuilderText $value
    if ([string]::IsNullOrWhiteSpace($text)) { throw $Message }
    return $text
}

function ConvertTo-AccessFieldName {
    param([string]$Name)

    $text = ConvertTo-BuilderText $Name
    if ([string]::IsNullOrWhiteSpace($text)) { return "" }
    $parts = [regex]::Split($text, "[^A-Za-z0-9]+") | Where-Object { -not [string]::IsNullOrWhiteSpace($_) }
    if ($parts.Count -eq 0) { return "" }
    $out = New-Object System.Collections.Generic.List[string]
    foreach ($part in $parts) {
        if ($part.Length -eq 1) {
            [void]$out.Add($part.ToUpperInvariant())
        }
        else {
            [void]$out.Add($part.Substring(0, 1).ToUpperInvariant() + $part.Substring(1))
        }
    }
    return [string]::Join("", [string[]]$out.ToArray())
}

function Get-AccessColumnTypeSql {
    param([string]$DataType)

    switch ((ConvertTo-BuilderText $DataType).ToLowerInvariant()) {
        "guid" { return "GUID" }
        "byte" { return "BYTE" }
        "text" { return "TEXT(255)" }
        "short text" { return "TEXT(255)" }
        "memo" { return "LONGTEXT" }
        "long text" { return "LONGTEXT" }
        "integer" { return "SHORT" }
        "short" { return "SHORT" }
        "long integer" { return "INTEGER" }
        "long" { return "INTEGER" }
        "single" { return "SINGLE" }
        "double" { return "DOUBLE" }
        "date/time" { return "DATETIME" }
        "datetime" { return "DATETIME" }
        "currency" { return "CURRENCY" }
        "boolean" { return "YESNO" }
        "yes/no" { return "YESNO" }
        default { return "TEXT(255)" }
    }
}

function Get-DataTypeId {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$DataType
    )

    $text = ConvertTo-BuilderText $DataType
    if ($text -in @("Short Text", "Long Text")) {
        $text = if ($text -eq "Short Text") { "Text" } else { "Memo" }
    }
    $id = Get-DbScalar -Connection $Connection -Sql "SELECT TOP 1 [ID] FROM [AppColumnDataTypes] WHERE [TypeName] = $(Sql-Text $text)"
    if ($null -ne $id -and -not ($id -is [System.DBNull])) { return [int]$id }
    return 1
}

function Get-CategoryTypeId {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$Category
    )

    $text = ConvertTo-BuilderText $Category
    if ([string]::IsNullOrWhiteSpace($text)) { $text = "Range" }
    $id = Get-DbScalar -Connection $Connection -Sql "SELECT TOP 1 [ID] FROM [AppColumnCategoryTypes] WHERE [CategoryName] = $(Sql-Text $text)"
    if ($null -ne $id -and -not ($id -is [System.DBNull])) { return [int]$id }
    return 4
}

function Get-AppTableId {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName
    )

    $id = Get-DbScalar -Connection $Connection -Sql "SELECT TOP 1 [ID] FROM [AppTables] WHERE [TableName] = $(Sql-Text $TableName)"
    if ($null -eq $id -or $id -is [System.DBNull]) { throw "No AppTables row found for $TableName." }
    return [int]$id
}

function Add-AccessColumnIfMissing {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName,
        [string]$ColumnName,
        [string]$DataType
    )

    if (Test-ColumnExists -Connection $Connection -TableName $TableName -ColumnName $ColumnName) { return $false }
    $typeSql = Get-AccessColumnTypeSql -DataType $DataType
    [void](Invoke-DbNonQuery -Connection $Connection -Sql "ALTER TABLE $(Quote-Name $TableName) ADD COLUMN $(Quote-Name $ColumnName) $typeSql")
    return $true
}

function Get-ActiveCustomMeasurementFieldLookup {
    param([System.Data.OleDb.OleDbConnection]$Connection)

    $lookup = @{}
    foreach ($tableName in @("PlotCustomMeasurements", "TreeCustomMeasurements", "RegenCustomMeasurements")) {
        $lookup[$tableName] = New-Object "System.Collections.Generic.HashSet[string]" ([System.StringComparer]::OrdinalIgnoreCase)
    }
    if (-not (Test-TableExists -Connection $Connection -TableName "AppColumns")) { return $lookup }
    if (-not (Test-TableExists -Connection $Connection -TableName "AppTables")) { return $lookup }

    $appTables = Get-DbTable -Connection $Connection -Sql "SELECT * FROM [AppTables]"
    $tableLookup = @{}
    foreach ($row in $appTables.Rows) {
        $id = Get-DataRowText -Row $row -ColumnNames @("ID", "TableID", "AppTableID")
        $tableName = Get-DataRowText -Row $row -ColumnNames @("TableName", "AppTableName", "Name", "Description")
        if (-not [string]::IsNullOrWhiteSpace($id) -and -not [string]::IsNullOrWhiteSpace($tableName)) {
            $tableLookup[$id] = $tableName
        }
    }

    $appColumns = Get-DbTable -Connection $Connection -Sql "SELECT * FROM [AppColumns]"
    foreach ($row in $appColumns.Rows) {
        $tableName = Get-DataRowText -Row $row -ColumnNames @("TableName", "AppTableName")
        if ([string]::IsNullOrWhiteSpace($tableName)) {
            $tableId = Get-DataRowText -Row $row -ColumnNames @("TableID", "AppTableID")
            if (-not [string]::IsNullOrWhiteSpace($tableId) -and $tableLookup.ContainsKey($tableId)) {
                $tableName = ConvertTo-BuilderText $tableLookup[$tableId]
            }
        }
        if (-not $lookup.ContainsKey($tableName)) { continue }
        if (-not (ConvertTo-BuilderBool (Get-DataRowValue -Row $row -ColumnNames @("Active", "IsActive", "Collected")))) { continue }
        $fieldName = ConvertTo-AccessFieldName (Get-DataRowText -Row $row -ColumnNames @("ColumnName", "FieldName", "Name"))
        if ([string]::IsNullOrWhiteSpace($fieldName)) { continue }
        if (Test-CfideerSampleRemoveField -FieldName $fieldName) { continue }
        [void]$lookup[$tableName].Add($fieldName)
    }

    return $lookup
}

function Set-CustomMeasurementTableColumnOrder {
    param(
        [string]$DatabasePath,
        [hashtable]$ActiveFieldLookup,
        [scriptblock]$Log
    )

    if ([string]::IsNullOrWhiteSpace($DatabasePath) -or -not (Test-Path -LiteralPath $DatabasePath)) { return }
    if ($null -eq $ActiveFieldLookup) { return }

    $tableSpecs = @(
        [pscustomobject]@{ TableName = "PlotCustomMeasurements"; KeyFields = @("MeasurementID", "PlotMeasKey") },
        [pscustomobject]@{ TableName = "TreeCustomMeasurements"; KeyFields = @("MeasurementID", "TreeMeasKey") },
        [pscustomobject]@{ TableName = "RegenCustomMeasurements"; KeyFields = @("MeasurementID", "RegenMeasKey") }
    )

    $engine = $null
    $db = $null
    try {
        foreach ($progId in @("DAO.DBEngine.120", "DAO.DBEngine.36", "DAO.DBEngine")) {
            try {
                $engine = New-Object -ComObject $progId
                $db = $engine.OpenDatabase($DatabasePath)
                break
            }
            catch {
                if ($engine -ne $null) {
                    try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($engine) | Out-Null } catch {}
                    $engine = $null
                }
            }
        }
        if ($null -eq $db) {
            if ($Log) { & $Log "Custom table field order skipped because the Access DAO engine could not open the output database." }
            return
        }

        foreach ($spec in $tableSpecs) {
            $tableDef = $null
            foreach ($candidate in $db.TableDefs) {
                try {
                    if ([string]::Equals([string]$candidate.Name, [string]$spec.TableName, [System.StringComparison]::OrdinalIgnoreCase)) {
                        $tableDef = $candidate
                        break
                    }
                }
                catch {
                }
            }
            if ($null -eq $tableDef) { continue }

            $existingFields = New-Object System.Collections.Generic.List[string]
            foreach ($field in $tableDef.Fields) {
                try {
                    $fieldName = ConvertTo-BuilderText $field.Name
                    if (-not [string]::IsNullOrWhiteSpace($fieldName)) { [void]$existingFields.Add($fieldName) }
                }
                catch {
                }
            }
            if ($existingFields.Count -eq 0) { continue }

            $activeFields = $null
            if ($ActiveFieldLookup.ContainsKey([string]$spec.TableName)) { $activeFields = $ActiveFieldLookup[[string]$spec.TableName] }
            if ($null -eq $activeFields) {
                $activeFields = New-Object "System.Collections.Generic.HashSet[string]" ([System.StringComparer]::OrdinalIgnoreCase)
            }

            $desired = New-Object System.Collections.Generic.List[string]
            foreach ($keyField in @($spec.KeyFields)) {
                foreach ($fieldName in @($existingFields.ToArray())) {
                    if ([string]::Equals($fieldName, $keyField, [System.StringComparison]::OrdinalIgnoreCase) -and -not $desired.Contains($fieldName)) {
                        [void]$desired.Add($fieldName)
                        break
                    }
                }
            }
            foreach ($fieldName in @($existingFields.ToArray())) {
                if (@($spec.KeyFields | Where-Object { [string]::Equals($_, $fieldName, [System.StringComparison]::OrdinalIgnoreCase) }).Count -gt 0) { continue }
                if ($activeFields.Contains($fieldName) -and -not $desired.Contains($fieldName)) { [void]$desired.Add($fieldName) }
            }
            foreach ($fieldName in @($existingFields.ToArray())) {
                if (-not $desired.Contains($fieldName)) { [void]$desired.Add($fieldName) }
            }

            $position = 0
            foreach ($fieldName in @($desired.ToArray())) {
                try {
                    $tableDef.Fields.Item($fieldName).OrdinalPosition = $position
                    $position++
                }
                catch {
                    if ($Log) { & $Log "Custom table field order warning: could not move $($spec.TableName).$($fieldName): $($_.Exception.Message)" }
                }
            }
            try { $tableDef.Fields.Refresh() } catch {}
            if ($Log) { & $Log "Ordered $($spec.TableName) fields with key fields first, active AppColumns next, and inactive history fields last." }
        }
    }
    catch {
        if ($Log) { & $Log "Custom table field order warning: $($_.Exception.Message)" }
    }
    finally {
        if ($db -ne $null) {
            try { $db.Close() } catch {}
            try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($db) | Out-Null } catch {}
        }
        if ($engine -ne $null) {
            try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($engine) | Out-Null } catch {}
        }
        [GC]::Collect()
        [GC]::WaitForPendingFinalizers()
    }
}

function New-AppColumnsArchive {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [scriptblock]$Log
    )

    if (-not (Test-TableExists -Connection $Connection -TableName "AppColumns")) {
        if ($Log) { & $Log "AppColumnsArchive skipped because AppColumns was not found in the output copy." }
        return
    }

    try {
        if (Test-TableExists -Connection $Connection -TableName "AppColumnsArchive") {
            [void](Invoke-DbNonQuery -Connection $Connection -Sql "DROP TABLE [AppColumnsArchive]")
        }
        [void](Invoke-DbNonQuery -Connection $Connection -Sql "SELECT * INTO [AppColumnsArchive] FROM [AppColumns]")
        $archiveCount = [int](Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [AppColumnsArchive]")
        if ($Log) { & $Log "Archived original AppColumns to AppColumnsArchive ($archiveCount row(s))." }
    }
    catch {
        throw "Could not create AppColumnsArchive from the original AppColumns table: $($_.Exception.Message)"
    }
}
function Get-CommonTableColumnsForCopy {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [string]$TableName
    )

    $sourceColumns = @(Get-TableColumns -Connection $SourceConnection -TableName $TableName)
    $targetColumns = @(Get-TableColumns -Connection $TargetConnection -TableName $TableName)

    $sourceLookup = New-Object "System.Collections.Generic.HashSet[string]" ([System.StringComparer]::OrdinalIgnoreCase)
    foreach ($column in $sourceColumns) {
        if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $column))) {
            [void]$sourceLookup.Add((ConvertTo-BuilderText $column))
        }
    }

    $columns = New-Object System.Collections.Generic.List[string]
    foreach ($column in $targetColumns) {
        $clean = ConvertTo-BuilderText $column
        if ([string]::IsNullOrWhiteSpace($clean)) { continue }
        if ($sourceLookup.Contains($clean)) {
            [void]$columns.Add($clean)
        }
    }

    return [string[]]$columns.ToArray()
}

function ConvertTo-AccessExternalDatabaseSqlLiteral {
    param([string]$Path)

    $fullPath = [System.IO.Path]::GetFullPath($Path)
    return "'" + $fullPath.Replace("'", "''") + "'"
}

function Invoke-DbNonQueryInTransaction {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [System.Data.OleDb.OleDbTransaction]$Transaction,
        [string]$Sql
    )

    $command = $Connection.CreateCommand()
    $command.Transaction = $Transaction
    $command.CommandText = $Sql

    try {
        return $command.ExecuteNonQuery()
    }
    catch {
        $message = New-DatabaseWriteFailureMessage -Sql $Sql -AccessMessage $_.Exception.Message
        $wrapped = New-Object System.Exception($message, $_.Exception)
        try { $wrapped.Data["WOOF SQL"] = $Sql } catch {}
        throw $wrapped
    }
    finally {
        $command.Dispose()
    }
}

function Get-AccessTableColumnNamesForExternalCopy {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName,
        [System.Data.OleDb.OleDbTransaction]$Transaction = $null
    )

    if ($null -eq $Connection) {
        throw "Database connection was not supplied while reading columns for table '$TableName'."
    }

    if ([string]::IsNullOrWhiteSpace($TableName)) {
        throw "Table name was blank while reading columns for external table copy."
    }

    $sql = "SELECT * FROM $(Quote-Name $TableName) WHERE 1 = 0"
    $command = $null
    $reader = $null

    try {
        $command = New-Object System.Data.OleDb.OleDbCommand($sql, $Connection)

        if ($null -ne $Transaction) {
            $command.Transaction = $Transaction
        }

        $reader = $command.ExecuteReader([System.Data.CommandBehavior]::SchemaOnly)
        $schema = $reader.GetSchemaTable()

        $columns = New-Object System.Collections.Generic.List[string]

        if ($null -ne $schema) {
            foreach ($row in $schema.Rows) {
                $columnName = [string]$row["ColumnName"]
                if (-not [string]::IsNullOrWhiteSpace($columnName)) {
                    [void]$columns.Add($columnName)
                }
            }
        }

        return [string[]]$columns.ToArray()
    }
    finally {
        if ($null -ne $reader) {
            try { $reader.Close() } catch {}
            try { $reader.Dispose() } catch {}
        }

        if ($null -ne $command) {
            try { $command.Dispose() } catch {}
        }
    }
}

function Copy-AccessTableFromExternalDatabase {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [System.Data.OleDb.OleDbTransaction]$TargetTransaction,
        [string]$SourceDatabaseLiteral,
        [string]$TableName
    )

    if ($null -eq $SourceConnection) {
        throw "Source database connection was not supplied while copying table '$TableName'."
    }

    if ($null -eq $TargetConnection) {
        throw "Target database connection was not supplied while copying table '$TableName'."
    }

    if ([string]::IsNullOrWhiteSpace($TableName)) {
        throw "Table name was blank while copying data from the existing database."
    }

    $sourceColumns = @(Get-AccessTableColumnNamesForExternalCopy -Connection $SourceConnection -TableName $TableName)
    $targetColumns = @(Get-AccessTableColumnNamesForExternalCopy -Connection $TargetConnection -TableName $TableName -Transaction $TargetTransaction)

    if ($sourceColumns.Count -eq 0) {
        throw "Source table '$TableName' does not expose any readable columns."
    }

    if ($targetColumns.Count -eq 0) {
        throw "Target table '$TableName' does not expose any readable columns."
    }

    $sourceLookup = @{}
    foreach ($columnName in $sourceColumns) {
        if (-not $sourceLookup.ContainsKey($columnName)) {
            $sourceLookup[$columnName] = $columnName
        }
    }

    $insertColumns = New-Object System.Collections.Generic.List[string]
    $selectColumns = New-Object System.Collections.Generic.List[string]

    foreach ($targetColumnName in $targetColumns) {
        if ($sourceLookup.ContainsKey($targetColumnName)) {
            $sourceColumnName = [string]$sourceLookup[$targetColumnName]
            [void]$insertColumns.Add((Quote-Name $targetColumnName))
            [void]$selectColumns.Add((Quote-Name $sourceColumnName))
        }
    }

    if ($insertColumns.Count -eq 0) {
        throw "No matching columns were found between source and target table '$TableName'."
    }

    $sourceDatabaseSqlLiteral = [string]$SourceDatabaseLiteral
    if ([string]::IsNullOrWhiteSpace($sourceDatabaseSqlLiteral)) {
        throw "Source database SQL literal was blank while copying table '$TableName'."
    }

    $sourceDatabaseSqlLiteral = $sourceDatabaseSqlLiteral.Trim()

    if (-not $sourceDatabaseSqlLiteral.StartsWith("'")) {
        $sourceDatabaseSqlLiteral = "'" + $sourceDatabaseSqlLiteral.Replace("'", "''") + "'"
    }

    $insertColumnList = [string]::Join(", ", [string[]]$insertColumns.ToArray())
    $selectColumnList = [string]::Join(", ", [string[]]$selectColumns.ToArray())

    $sql = "INSERT INTO $(Quote-Name $TableName) ($insertColumnList) SELECT $selectColumnList FROM $(Quote-Name $TableName) IN $sourceDatabaseSqlLiteral;"

    $command = $null

    try {
        $command = New-Object System.Data.OleDb.OleDbCommand($sql, $TargetConnection)

        if ($null -ne $TargetTransaction) {
            $command.Transaction = $TargetTransaction
        }

        [void]$command.ExecuteNonQuery()
    }
    catch {
        throw "Could not copy table '$TableName' from the existing database: $($_.Exception.Message)"
    }
    finally {
        if ($null -ne $command) {
            try { $command.Dispose() } catch {}
        }
    }
}

function Copy-ReportTablesFromExistingDatabase {
    param(
        [string]$SourceDatabasePath,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [scriptblock]$Log
    )

    if (-not $Log) { $Log = { param($Text) Write-Host $Text } }

    $sourcePath = ConvertTo-BuilderText $SourceDatabasePath
    if ([string]::IsNullOrWhiteSpace($sourcePath)) {
        throw "Copy completed reports was selected, but no Existing/old project database was configured."
    }
    if (-not (Test-Path -LiteralPath $sourcePath)) {
        throw "Copy completed reports was selected, but the Existing/old project database was not found: $sourcePath"
    }

    $sourceConnection = $null
    $transaction = $null
    try {
        $sourceConnection = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $sourcePath)

        foreach ($tableName in @("ReportColumns", "ReportHeaders", "AppColumns", "AppTables")) {
            if (-not (Test-TableExists -Connection $sourceConnection -TableName $tableName)) {
                throw "Existing database does not contain required table '$tableName'."
            }
            if (-not (Test-TableExists -Connection $TargetConnection -TableName $tableName)) {
                throw "Target database does not contain required table '$tableName'."
            }
        }

        $sourceReportColumns = Get-DbTable -Connection $sourceConnection -Sql @"
SELECT [ReportSection], [ReportGroup], [ReportIndex], [ColumnID], [FieldFormat], [TallyFormat]
FROM [ReportColumns]
ORDER BY [ReportSection], [ReportGroup], [ReportIndex];
"@
        $sourceReportHeaders = Get-DbTable -Connection $sourceConnection -Sql @"
SELECT [ReportSection], [ReportGroup], [LineNumber], [Header]
FROM [ReportHeaders]
ORDER BY [ReportSection], [ReportGroup], [LineNumber];
"@

        if ($sourceReportColumns.Rows.Count -eq 0) {
            throw "The existing database ReportColumns table is empty."
        }
        if ($sourceReportHeaders.Rows.Count -eq 0) {
            throw "The existing database ReportHeaders table is empty."
        }

        # Build source and target AppColumns lookups. ReportColumns.ColumnID is
        # preserved when possible and remapped by AppTables.TableName +
        # AppColumns.ColumnName when the current template uses a different GUID.
        $sourceAppColumnRows = Get-DbTable -Connection $sourceConnection -Sql @"
SELECT ac.[ID] AS [ColumnID], appTable.[TableName], ac.[ColumnName]
FROM [AppColumns] AS ac
INNER JOIN [AppTables] AS appTable ON ac.[TableID] = appTable.[ID];
"@
        $targetAppColumnRows = Get-DbTable -Connection $TargetConnection -Sql @"
SELECT ac.[ID] AS [ColumnID], appTable.[TableName], ac.[ColumnName]
FROM [AppColumns] AS ac
INNER JOIN [AppTables] AS appTable ON ac.[TableID] = appTable.[ID];
"@

        $sourceIdentityById = @{}
        foreach ($row in $sourceAppColumnRows.Rows) {
            $columnId = Get-DataRowText -Row $row -ColumnNames @("ColumnID")
            $tableName = Get-DataRowText -Row $row -ColumnNames @("TableName")
            $columnName = Get-DataRowText -Row $row -ColumnNames @("ColumnName")
            if ([string]::IsNullOrWhiteSpace($columnId) -or
                [string]::IsNullOrWhiteSpace($tableName) -or
                [string]::IsNullOrWhiteSpace($columnName)) {
                continue
            }
            $idKey = ([guid]$columnId).ToString("D")
            $sourceIdentityById[$idKey] = "$tableName|$columnName"
        }

        $targetIdById = @{}
        $targetIdByIdentity = @{}
        foreach ($row in $targetAppColumnRows.Rows) {
            $columnId = Get-DataRowText -Row $row -ColumnNames @("ColumnID")
            $tableName = Get-DataRowText -Row $row -ColumnNames @("TableName")
            $columnName = Get-DataRowText -Row $row -ColumnNames @("ColumnName")
            if ([string]::IsNullOrWhiteSpace($columnId)) { continue }

            $idKey = ([guid]$columnId).ToString("D")
            $targetIdById[$idKey] = $columnId

            if (-not [string]::IsNullOrWhiteSpace($tableName) -and
                -not [string]::IsNullOrWhiteSpace($columnName)) {
                $identityKey = "$tableName|$columnName"
                if ($targetIdByIdentity.ContainsKey($identityKey) -and
                    -not [string]::Equals((ConvertTo-BuilderText $targetIdByIdentity[$identityKey]), $columnId, [System.StringComparison]::OrdinalIgnoreCase)) {
                    throw "Target AppColumns contains more than one row for '$tableName.$columnName'."
                }
                $targetIdByIdentity[$identityKey] = $columnId
            }
        }

        $resolvedRows = New-Object System.Collections.Generic.List[object]
        $unresolved = New-Object System.Collections.Generic.List[string]
        foreach ($row in $sourceReportColumns.Rows) {
            $sourceColumnValue = $row["ColumnID"]
            $resolvedColumnId = $null

            if ($null -ne $sourceColumnValue -and -not ($sourceColumnValue -is [System.DBNull])) {
                $sourceColumnId = ConvertTo-BuilderText $sourceColumnValue
                if (-not [string]::IsNullOrWhiteSpace($sourceColumnId)) {
                    $sourceIdKey = ([guid]$sourceColumnId).ToString("D")
                    if ($targetIdById.ContainsKey($sourceIdKey)) {
                        $resolvedColumnId = $targetIdById[$sourceIdKey]
                    }
                    elseif ($sourceIdentityById.ContainsKey($sourceIdKey)) {
                        $identityKey = ConvertTo-BuilderText $sourceIdentityById[$sourceIdKey]
                        if ($targetIdByIdentity.ContainsKey($identityKey)) {
                            $resolvedColumnId = $targetIdByIdentity[$identityKey]
                        }
                        else {
                            [void]$unresolved.Add("$identityKey (source ColumnID $sourceColumnId)")
                        }
                    }
                    else {
                        [void]$unresolved.Add("source ColumnID $sourceColumnId")
                    }
                }
            }

            [void]$resolvedRows.Add([pscustomobject]@{
                SourceRow = $row
                ColumnID = $resolvedColumnId
            })
        }

        if ($unresolved.Count -gt 0) {
            $distinctUnresolved = @($unresolved.ToArray() | Sort-Object -Unique)
            throw "The completed reports reference AppColumns that are not present in the output database:`r`n- " +
                ([string]::Join("`r`n- ", [string[]]$distinctUnresolved)) +
                "`r`n`r`nCopy AppColumns too, or create matching AppColumns before copying reports."
        }

        $transaction = $TargetConnection.BeginTransaction()

        [void](Invoke-DbNonQueryInTransaction -Connection $TargetConnection -Transaction $transaction -Sql "DELETE FROM [ReportHeaders];")
        [void](Invoke-DbNonQueryInTransaction -Connection $TargetConnection -Transaction $transaction -Sql "DELETE FROM [ReportColumns];")

        $insertedColumnCount = 0
        foreach ($resolvedRow in $resolvedRows) {
            $row = $resolvedRow.SourceRow
            $affected = Invoke-DbNonQueryParameterizedInTransaction -Connection $TargetConnection -Transaction $transaction -Sql @"
INSERT INTO [ReportColumns]
    ([ReportSection], [ReportGroup], [ReportIndex], [ColumnID], [FieldFormat], [TallyFormat])
VALUES (?, ?, ?, ?, ?, ?)
"@ -Parameters @(
                (DbRawText $row["ReportSection"]),
                (DbInt $row["ReportGroup"]),
                (DbInt $row["ReportIndex"]),
                (DbGuid $resolvedRow.ColumnID),
                (DbRawText $row["FieldFormat"]),
                (DbRawText $row["TallyFormat"])
            )
            if ([int]$affected -ne 1) { throw "A ReportColumns row was not inserted." }
            $insertedColumnCount++
        }

        $insertedHeaderCount = 0
        foreach ($row in $sourceReportHeaders.Rows) {
            $affected = Invoke-DbNonQueryParameterizedInTransaction -Connection $TargetConnection -Transaction $transaction -Sql @"
INSERT INTO [ReportHeaders]
    ([ReportSection], [ReportGroup], [LineNumber], [Header])
VALUES (?, ?, ?, ?)
"@ -Parameters @(
                (DbRawText $row["ReportSection"]),
                (DbInt $row["ReportGroup"]),
                (DbInt $row["LineNumber"]),
                (DbRawLongText $row["Header"])
            )
            if ([int]$affected -ne 1) { throw "A ReportHeaders row was not inserted." }
            $insertedHeaderCount++
        }

        if ($insertedColumnCount -ne $sourceReportColumns.Rows.Count) {
            throw "ReportColumns verification failed. Expected $($sourceReportColumns.Rows.Count) row(s), inserted $insertedColumnCount."
        }
        if ($insertedHeaderCount -ne $sourceReportHeaders.Rows.Count) {
            throw "ReportHeaders verification failed. Expected $($sourceReportHeaders.Rows.Count) row(s), inserted $insertedHeaderCount."
        }

        $transaction.Commit()
        $transaction.Dispose()
        $transaction = $null

        & $Log "Copied completed reports from existing database. ReportColumns: $insertedColumnCount row(s). ReportHeaders: $insertedHeaderCount row(s). Fixed-width header spacing was preserved."
    }
    catch {
        if ($null -ne $transaction) {
            try { $transaction.Rollback() } catch {}
        }
        throw "Could not copy ReportHeaders and ReportColumns from existing database: $($_.Exception.Message)"
    }
    finally {
        if ($null -ne $transaction) {
            try { $transaction.Dispose() } catch {}
        }
        if ($null -ne $sourceConnection) {
            if ($sourceConnection.State -eq "Open") { $sourceConnection.Close() }
            $sourceConnection.Dispose()
        }
    }
}

function Copy-AppColumnsTablesFromExistingDatabase {
    param(
        [string]$SourceDatabasePath,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [scriptblock]$Log
    )

    if (-not $Log) { $Log = { param($Text) Write-Host $Text } }

    $sourcePath = ConvertTo-BuilderText $SourceDatabasePath
    if ([string]::IsNullOrWhiteSpace($sourcePath)) {
        throw "Copy AppColumns from existing database was selected, but no Existing/old project database was configured."
    }

    if (-not (Test-Path -LiteralPath $sourcePath)) {
        throw "Copy AppColumns from existing database was selected, but the Existing/old project database was not found: $sourcePath"
    }

    $appColumnTables = [string[]]@(
        "AppColumns",
        "AppColumnCodes"
    )

    $sourceConnectionString = New-AccessConnectionString -Path $sourcePath
    $sourceConnection = $null
    $transaction = $null

    try {
        $sourceConnection = Open-AccessConnection -ConnectionString $sourceConnectionString

        foreach ($tableName in $appColumnTables) {
            if (-not (Test-TableExists -Connection $sourceConnection -TableName $tableName)) {
                throw "Existing database does not contain required AppColumns table '$tableName'."
            }

            if (-not (Test-TableExists -Connection $TargetConnection -TableName $tableName)) {
                throw "Target database does not contain required AppColumns table '$tableName'."
            }
        }

        $sourceCounts = @{}
        foreach ($tableName in $appColumnTables) {
            $sourceCounts[$tableName] = [int](Get-DbScalar -Connection $sourceConnection -Sql "SELECT Count(*) FROM $(Quote-Name $tableName)")
        }

        $sourceLiteral = ConvertTo-AccessExternalDatabaseSqlLiteral -Path $sourcePath
        $transaction = $TargetConnection.BeginTransaction()

        [void](Invoke-DbNonQueryInTransaction -Connection $TargetConnection -Transaction $transaction -Sql "DELETE FROM $(Quote-Name "AppColumnCodes");")
        [void](Invoke-DbNonQueryInTransaction -Connection $TargetConnection -Transaction $transaction -Sql "DELETE FROM $(Quote-Name "AppColumns");")

        Copy-AccessTableFromExternalDatabase -SourceConnection $sourceConnection -TargetConnection $TargetConnection -TargetTransaction $transaction -SourceDatabaseLiteral $sourceLiteral -TableName "AppColumns"
        Copy-AccessTableFromExternalDatabase -SourceConnection $sourceConnection -TargetConnection $TargetConnection -TargetTransaction $transaction -SourceDatabaseLiteral $sourceLiteral -TableName "AppColumnCodes"

        $transaction.Commit()
        $transaction = $null

        $summaryParts = New-Object System.Collections.Generic.List[string]
        foreach ($tableName in $appColumnTables) {
            $targetCount = [int](Get-DbScalar -Connection $TargetConnection -Sql "SELECT Count(*) FROM $(Quote-Name $tableName)")
            [void]$summaryParts.Add(("{0}: {1} source row(s), {2} target row(s)" -f $tableName, $sourceCounts[$tableName], $targetCount))
        }

        & $Log ("Copied AppColumns and AppColumnCodes from existing database. " + [string]::Join("; ", [string[]]$summaryParts.ToArray()) + ".")
    }
    catch {
        if ($null -ne $transaction) {
            try { $transaction.Rollback() } catch {}
        }

        throw "Could not copy AppColumns from existing database: $($_.Exception.Message)"
    }
    finally {
        if ($null -ne $transaction) {
            try { $transaction.Dispose() } catch {}
        }

        if ($null -ne $sourceConnection) {
            if ($sourceConnection.State -eq "Open") { $sourceConnection.Close() }
            $sourceConnection.Dispose()
        }
    }
}

function Test-CFIDEERQueryCopyModeAllowed {
    param(
        [AllowNull()]
        [object]$Mode
    )

    return Test-WOOFTextEquals (ConvertTo-BuilderText $Mode) "Upgrade Project"
}

function New-AccessDaoDbEngine {
    $progIds = [string[]]@(
        "DAO.DBEngine.120",
        "DAO.DBEngine.36"
    )

    foreach ($progId in $progIds) {
        try {
            return New-Object -ComObject $progId
        }
        catch {
        }
    }

    throw "Could not create a DAO database engine. Make sure the Microsoft Access Database Engine is installed and that Project Pickle is running in the correct 32-bit/64-bit PowerShell for your Access driver."
}

function Release-BuilderComObject {
    param(
        [object]$ComObject
    )

    if ($null -ne $ComObject) {
        try {
            [void][System.Runtime.InteropServices.Marshal]::ReleaseComObject($ComObject)
        }
        catch {
        }
    }
}

function Get-CFIDEERQueryNamesFromDatabase {
    param(
        [string]$DatabasePath
    )

    $databasePathText = ConvertTo-BuilderText $DatabasePath
    if ([string]::IsNullOrWhiteSpace($databasePathText)) {
        throw "Database path was blank while reading _prjCFIDEER_ query names."
    }

    if (-not (Test-Path -LiteralPath $databasePathText)) {
        throw "Database was not found while reading _prjCFIDEER_ query names: $databasePathText"
    }

    $dao = $null
    $database = $null

    try {
        $dao = New-AccessDaoDbEngine
        $database = $dao.OpenDatabase($databasePathText, $false, $true)

        $queryNames = New-Object System.Collections.Generic.List[string]

        foreach ($queryDef in $database.QueryDefs) {
            $queryName = [string]$queryDef.Name

            if ($queryName.StartsWith("_prjCFIDEER_", [System.StringComparison]::OrdinalIgnoreCase)) {
                [void]$queryNames.Add($queryName)
            }
        }

        return [string[]]$queryNames.ToArray()
    }
    finally {
        if ($null -ne $database) {
            try { $database.Close() } catch {}
            Release-BuilderComObject -ComObject $database
        }

        if ($null -ne $dao) {
            Release-BuilderComObject -ComObject $dao
        }

        [System.GC]::Collect()
        [System.GC]::WaitForPendingFinalizers()
    }
}

# ---------------------------------------------------------------------------
# Processing setup table copy plan
#
# Normal source:
#   Copy all four Processing setup tables.
#
# Older source missing merchantability Yes/No fields:
#   Leave SpeciesMerchantabilityStandards inherited from the current master.
#   Copy only:
#       SpeciesNationalVolumeParms
#       SpeciesRegressionCriteria
#       SpeciesRegressions
# ---------------------------------------------------------------------------

$script:ProjectPickleProcessingTableNamesOverride =
    $null

$script:ProjectPickleSkipSpeciesMerchantabilityStandards =
    $false


function Get-ProcessingTableNames {
    $overrideNames =
        New-Object System.Collections.Generic.List[string]

    if (
        $null -ne
        $script:ProjectPickleProcessingTableNamesOverride
    ) {
        foreach (
            $overrideName in @(
                $script:ProjectPickleProcessingTableNamesOverride
            )
        ) {
            $overrideNameText = (
                ConvertTo-BuilderText `
                    $overrideName
            ).Trim()

            if (
                [string]::IsNullOrWhiteSpace(
                    $overrideNameText
                )
            ) {
                continue
            }

            [void]$overrideNames.Add(
                $overrideNameText
            )
        }
    }

    if ($overrideNames.Count -gt 0) {
        return [string[]]@(
            $overrideNames.ToArray()
        )
    }

    return [string[]]@(
        "SpeciesMerchantabilityStandards"
        "SpeciesNationalVolumeParms"
        "SpeciesRegressionCriteria"
        "SpeciesRegressions"
    )
}


function Get-ProjectPickleProcessingRequiredMerchantabilityFieldNames {
    if (
        $script:ProjectPickleSkipSpeciesMerchantabilityStandards
    ) {
        return [string[]]@()
    }

    return [string[]]@(
        "HasDRC"
        "DMsusceptible"
        "DMcollected"
    )
}


function Get-ProjectPickleProcessingTableColumnNames {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [object]$Connection,

        [Parameter(Mandatory = $true)]
        [string]$TableName
    )

    if ($null -eq $Connection) {
        throw (
            "Cannot read " +
            $TableName +
            " because the database connection is not available."
        )
    }

    if (
        [string]::IsNullOrWhiteSpace(
            $TableName
        )
    ) {
        throw "A Processing table name was not supplied."
    }

    $command =
        $null

    $reader =
        $null

    try {
        $command =
            $Connection.CreateCommand()

        $command.CommandText = (
            "SELECT * FROM " +
            (Quote-Name $TableName) +
            " WHERE 1 = 0"
        )

        $command.CommandTimeout =
            30

        $reader =
            $command.ExecuteReader(
                [System.Data.CommandBehavior]::SchemaOnly
            )

        $schemaTable =
            $reader.GetSchemaTable()

        if (
            $null -eq $schemaTable -or
            $schemaTable.Rows.Count -eq 0
        ) {
            throw (
                "Project Pickle could not read any fields from " +
                $TableName +
                "."
            )
        }

        $columnNames =
            New-Object System.Collections.Generic.List[string]

        foreach (
            $schemaRow in $schemaTable.Rows
        ) {
            if (
                $null -eq $schemaRow -or
                $schemaRow.IsNull(
                    "ColumnName"
                )
            ) {
                continue
            }

            $columnName = (
                ConvertTo-BuilderText `
                    $schemaRow["ColumnName"]
            ).Trim()

            if (
                [string]::IsNullOrWhiteSpace(
                    $columnName
                )
            ) {
                continue
            }

            [void]$columnNames.Add(
                $columnName
            )
        }

        return [string[]]@(
            $columnNames.ToArray()
        )
    }
    finally {
        if ($null -ne $reader) {
            try {
                $reader.Close()
            }
            catch {
            }

            try {
                $reader.Dispose()
            }
            catch {
            }
        }

        if ($null -ne $command) {
            try {
                $command.Dispose()
            }
            catch {
            }
        }
    }
}


function Get-ProjectPickleProcessingCopyCompatibility {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [string]$SourceDatabasePath
    )

    if (
        [string]::IsNullOrWhiteSpace(
            $SourceDatabasePath
        )
    ) {
        throw (
            "Processing tab: choose the Existing/old " +
            "project database first."
        )
    }

    if (
        -not (
            Test-Path `
                -LiteralPath $SourceDatabasePath `
                -PathType Leaf
        )
    ) {
        throw (
            "Processing tab: the Existing/old project " +
            "database was not found:`r`n" +
            $SourceDatabasePath
        )
    }

    $merchantabilityTableName =
        "SpeciesMerchantabilityStandards"

    $compatibleTableNames =
        [string[]]@(
            "SpeciesNationalVolumeParms"
            "SpeciesRegressionCriteria"
            "SpeciesRegressions"
        )

    # This function must always inspect the three fields. Do not replace
    # this list with the fallback-aware helper above.
    $requiredMerchantabilityFields =
        [string[]]@(
            "HasDRC"
            "DMsusceptible"
            "DMcollected"
        )

    $connection =
        $null

    try {
        $connectionString =
            New-AccessConnectionString `
                -Path $SourceDatabasePath

        $connection =
            Open-AccessConnection `
                -ConnectionString $connectionString

        # The other three Processing tables are still mandatory.
        $missingCompatibleTables =
            New-Object System.Collections.Generic.List[string]

        foreach (
            $tableName in $compatibleTableNames
        ) {
            if (
                -not (
                    Test-TableExists `
                        -Connection $connection `
                        -TableName $tableName
                )
            ) {
                [void]$missingCompatibleTables.Add(
                    $tableName
                )
            }
        }

        if (
            $missingCompatibleTables.Count -gt 0
        ) {
            throw (
                "The Existing/old project database is missing " +
                "one or more Processing tables that cannot be " +
                "skipped:`r`n`r`n" +
                [string]::Join(
                    "`r`n",
                    [string[]]$missingCompatibleTables.ToArray()
                ) +
                "`r`n`r`n" +
                "No Processing setup tables were copied."
            )
        }

        $merchantabilityTableExists =
            Test-TableExists `
                -Connection $connection `
                -TableName $merchantabilityTableName

        $missingMerchantabilityFields =
            New-Object System.Collections.Generic.List[string]

        if ($merchantabilityTableExists) {
            $sourceColumnNames =
                [string[]]@(
                    Get-ProjectPickleProcessingTableColumnNames `
                        -Connection $connection `
                        -TableName $merchantabilityTableName
                )

            $sourceColumnLookup =
                @{}

            foreach (
                $sourceColumnName in $sourceColumnNames
            ) {
                if (
                    [string]::IsNullOrWhiteSpace(
                        $sourceColumnName
                    )
                ) {
                    continue
                }

                $lookupKey =
                    $sourceColumnName.Trim().ToUpperInvariant()

                $sourceColumnLookup[
                    $lookupKey
                ] =
                    $true
            }

            foreach (
                $requiredFieldName in
                $requiredMerchantabilityFields
            ) {
                $lookupKey =
                    $requiredFieldName.Trim().ToUpperInvariant()

                if (
                    -not $sourceColumnLookup.ContainsKey(
                        $lookupKey
                    )
                ) {
                    [void]$missingMerchantabilityFields.Add(
                        $requiredFieldName
                    )
                }
            }
        }

        $useThreeTableFallback = (
            -not $merchantabilityTableExists -or
            $missingMerchantabilityFields.Count -gt 0
        )

        $tablesToCopy =
            New-Object System.Collections.Generic.List[string]

        if (-not $useThreeTableFallback) {
            [void]$tablesToCopy.Add(
                $merchantabilityTableName
            )
        }

        foreach (
            $tableName in $compatibleTableNames
        ) {
            [void]$tablesToCopy.Add(
                $tableName
            )
        }

        $warningMessage =
            ""

        if ($useThreeTableFallback) {
            $sourceProblemText =
                ""

            if (-not $merchantabilityTableExists) {
                $sourceProblemText = (
                    "does not contain the " +
                    $merchantabilityTableName +
                    " table"
                )
            }
            else {
                $sourceProblemText = (
                    "contains " +
                    $merchantabilityTableName +
                    ", but that table is missing required " +
                    "Yes/No field(s): " +
                    [string]::Join(
                        ", ",
                        [string[]]$missingMerchantabilityFields.ToArray()
                    )
                )
            }

            $warningMessage = (
                "The Existing/old project database " +
                $sourceProblemText +
                ".`r`n`r`n" +
                "Project Pickle will continue and completely " +
                "replace these three output tables from the " +
                "old database:`r`n`r`n" +
                "  - SpeciesNationalVolumeParms`r`n" +
                "  - SpeciesRegressionCriteria`r`n" +
                "  - SpeciesRegressions`r`n`r`n" +
                "SpeciesMerchantabilityStandards will NOT be " +
                "copied from the old database. The version " +
                "inherited from the current master database " +
                "will remain unchanged in the output.`r`n`r`n" +
                "After Build, manually review and recreate any " +
                "old project-specific merchantability standards " +
                "that still need to be retained."
            )
        }

        return [pscustomobject]@{
            UseThreeTableFallback =
                [bool]$useThreeTableFallback

            MerchantabilityTableExists =
                [bool]$merchantabilityTableExists

            MissingMerchantabilityFields =
                [string[]]@(
                    $missingMerchantabilityFields.ToArray()
                )

            TablesToCopy =
                [string[]]@(
                    $tablesToCopy.ToArray()
                )

            WarningMessage =
                $warningMessage
        }
    }
    finally {
        if ($null -ne $connection) {
            try {
                if (
                    $connection.State -eq
                    [System.Data.ConnectionState]::Open
                ) {
                    $connection.Close()
                }
            }
            catch {
            }

            try {
                $connection.Dispose()
            }
            catch {
            }
        }
    }
}
function Copy-CFIDEERQueriesFromExistingDatabase {
    param(
        [string]$SourceDatabasePath,
        [string]$TargetDatabasePath,
        [scriptblock]$Log
    )

    if (-not $Log) { $Log = { param($Text) Write-Host $Text } }

    $sourcePath = ConvertTo-BuilderText $SourceDatabasePath
    $targetPath = ConvertTo-BuilderText $TargetDatabasePath

    if ([string]::IsNullOrWhiteSpace($sourcePath)) {
        throw "Copy existing _prjCFIDEER_ queries was selected, but no Existing project database was configured."
    }

    if ([string]::IsNullOrWhiteSpace($targetPath)) {
        throw "Copy existing _prjCFIDEER_ queries was selected, but no output database was configured."
    }

    if (-not (Test-Path -LiteralPath $sourcePath)) {
        throw "Copy existing _prjCFIDEER_ queries was selected, but the Existing project database was not found: $sourcePath"
    }

    if (-not (Test-Path -LiteralPath $targetPath)) {
        throw "Copy existing _prjCFIDEER_ queries was selected, but the output database was not found: $targetPath"
    }

    $dao = $null
    $sourceDatabase = $null
    $targetDatabase = $null

    try {
        $dao = New-AccessDaoDbEngine
        $sourceDatabase = $dao.OpenDatabase($sourcePath, $false, $true)
        $targetDatabase = $dao.OpenDatabase($targetPath, $false, $false)

        $sourceQueries = New-Object System.Collections.Generic.List[object]

        foreach ($queryDef in $sourceDatabase.QueryDefs) {
            $queryName = [string]$queryDef.Name

            if ($queryName.StartsWith("_prjCFIDEER_", [System.StringComparison]::OrdinalIgnoreCase)) {
                $querySql = [string]$queryDef.SQL

                if ([string]::IsNullOrWhiteSpace($querySql)) {
                    throw "Existing database query '$queryName' has blank SQL and cannot be copied."
                }

                [void]$sourceQueries.Add([pscustomobject]@{
                    Name = $queryName
                    Sql = $querySql
                })
            }
        }

        if ($sourceQueries.Count -eq 0) {
            throw "The existing database does not contain any saved queries whose names start with '_prjCFIDEER_'."
        }

        $targetQueryNamesToDelete = New-Object System.Collections.Generic.List[string]

        foreach ($queryDef in $targetDatabase.QueryDefs) {
            $queryName = [string]$queryDef.Name

            if ($queryName.StartsWith("_prjCFIDEER_", [System.StringComparison]::OrdinalIgnoreCase)) {
                [void]$targetQueryNamesToDelete.Add($queryName)
            }
        }

        foreach ($queryName in $targetQueryNamesToDelete) {
            $targetDatabase.QueryDefs.Delete($queryName)
        }

        try { $targetDatabase.QueryDefs.Refresh() } catch {}

        foreach ($sourceQuery in $sourceQueries) {
            $createdQuery = $null

            try {
                $createdQuery = $targetDatabase.CreateQueryDef([string]$sourceQuery.Name, [string]$sourceQuery.Sql)
            }
            finally {
                if ($null -ne $createdQuery) {
                    Release-BuilderComObject -ComObject $createdQuery
                }
            }
        }

        try { $targetDatabase.QueryDefs.Refresh() } catch {}

        $copiedNames = New-Object System.Collections.Generic.List[string]
        foreach ($sourceQuery in $sourceQueries) {
            [void]$copiedNames.Add([string]$sourceQuery.Name)
        }

        & $Log ("Copied existing _prjCFIDEER_ queries from existing database. Copied " + $sourceQueries.Count + " query definition(s): " + [string]::Join(", ", [string[]]$copiedNames.ToArray()) + ".")
    }
    catch {
        throw "Could not copy existing _prjCFIDEER_ queries from existing database: $($_.Exception.Message)"
    }
    finally {
        if ($null -ne $targetDatabase) {
            try { $targetDatabase.Close() } catch {}
            Release-BuilderComObject -ComObject $targetDatabase
        }

        if ($null -ne $sourceDatabase) {
            try { $sourceDatabase.Close() } catch {}
            Release-BuilderComObject -ComObject $sourceDatabase
        }

        if ($null -ne $dao) {
            Release-BuilderComObject -ComObject $dao
        }

        [System.GC]::Collect()
        [System.GC]::WaitForPendingFinalizers()
    }
}

# ---------------------------------------------------------------------------
# Processing setup table compatibility
#
# Normal behavior:
#   Copy all four Processing setup tables.
#
# Compatibility fallback:
#   When the old SpeciesMerchanabilityStandards table is missing one or more
#   required Yes/No fields, leave that output table inherited from the current
#   master database and copy only the other three Processing setup tables.
# ---------------------------------------------------------------------------

$script:ProjectPickleProcessingTableNamesOverride =
    $null

$script:ProjectPickleSkipSpeciesMerchantabilityStandards =
    $false

function Get-ProcessingImportCompatibility {
    param(
        [AllowNull()]
        [string]$DatabasePath
    )

    $path = ConvertTo-BuilderText $DatabasePath

    $requiredTables = [string[]]@(
        Get-ProcessingTableNames
    )

    $merchantabilityTableName = "SpeciesMerchantabilityStandards"

    $requiredYesNoFields = [string[]]@(
        "HasDRC",
        "DMsusceptible",
        "DMcollected"
    )

    $missingTables = New-Object System.Collections.Generic.List[string]
    $missingFields = New-Object System.Collections.Generic.List[string]
    $connection = $null

    if ([string]::IsNullOrWhiteSpace($path)) {
        return [pscustomobject]@{
            IsCompatible       = $false
            Message            = "Choose the Existing/old project database before selecting Import Processing tables."
            MissingTables      = [string[]]@()
            MissingYesNoFields = [string[]]@()
        }
    }

    if (-not (Test-Path -LiteralPath $path)) {
        return [pscustomobject]@{
            IsCompatible       = $false
            Message            = "The Existing/old project database was not found: $path"
            MissingTables      = [string[]]@()
            MissingYesNoFields = [string[]]@()
        }
    }

    try {
        $connectionString = New-AccessConnectionString -Path $path
        $connection = Open-AccessConnection -ConnectionString $connectionString

        foreach ($tableName in $requiredTables) {
            if (-not (Test-TableExists -Connection $connection -TableName $tableName)) {
                [void]$missingTables.Add($tableName)
            }
        }

        if (Test-TableExists -Connection $connection -TableName $merchantabilityTableName) {
            foreach ($fieldName in $requiredYesNoFields) {
                if (-not (Test-ColumnExists `
                    -Connection $connection `
                    -TableName $merchantabilityTableName `
                    -ColumnName $fieldName)) {

                    [void]$missingFields.Add($fieldName)
                }
            }
        }

        if ($missingTables.Count -gt 0 -or $missingFields.Count -gt 0) {
            $details = New-Object System.Collections.Generic.List[string]

            if ($missingTables.Count -gt 0) {
                [void]$details.Add(
                    "missing required table(s): " +
                    [string]::Join(
                        ", ",
                        [string[]]$missingTables.ToArray()
                    )
                )
            }

            if ($missingFields.Count -gt 0) {
                [void]$details.Add(
                    "$merchantabilityTableName is missing required Yes/No field(s): " +
                    [string]::Join(
                        ", ",
                        [string[]]$missingFields.ToArray()
                    )
                )
            }

            $detailText = [string]::Join(
                "; ",
                [string[]]$details.ToArray()
            )

            $message = (
                "The selected Existing/old project database cannot be used for Import Processing tables. " +
                $detailText +
                ". Choose a compatible source database that contains HasDRC, DMsusceptible, and DMcollected, " +
                "or leave Import Processing tables unchecked so the Processing tables from the current v3.10 master database remain in the output. " +
                "No Processing tables will be copied."
            )

            return [pscustomobject]@{
                IsCompatible       = $false
                Message            = $message
                MissingTables      = [string[]]($missingTables.ToArray())
                MissingYesNoFields = [string[]]($missingFields.ToArray())
            }
        }

        return [pscustomobject]@{
            IsCompatible       = $true
            Message            = "The selected database contains the required Processing tables and SpeciesMerchantabilityStandards Yes/No fields."
            MissingTables      = [string[]]@()
            MissingYesNoFields = [string[]]@()
        }
    }
    catch {
        return [pscustomobject]@{
            IsCompatible       = $false
            Message            = (
                "Project Pickle could not inspect the Processing tables in the selected Existing/old project database: " +
                $_.Exception.Message
            )
            MissingTables      = [string[]]@()
            MissingYesNoFields = [string[]]@()
        }
    }
    finally {
        if ($null -ne $connection) {
            if ($connection.State -eq "Open") {
                $connection.Close()
            }

            $connection.Dispose()
        }
    }
}
function Copy-ProcessingTablesFromExistingDatabase {
    param(
        [string]$SourceDatabasePath,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [scriptblock]$Log
    )

    if (-not $Log) { $Log = { param($Text) Write-Host $Text } }

    $sourcePath = ConvertTo-BuilderText $SourceDatabasePath
    if ([string]::IsNullOrWhiteSpace($sourcePath)) {
        throw "Import Processing tables from existing database was selected, but no Existing/old project database was configured."
    }

    if (-not (Test-Path -LiteralPath $sourcePath)) {
        throw "Import Processing tables from existing database was selected, but the Existing/old project database was not found: $sourcePath"
    }

    $processingTables = @(Get-ProcessingTableNames)
    $sourceConnectionString = New-AccessConnectionString -Path $sourcePath
    $sourceConnection = $null
    $transaction = $null

    try {
        $sourceConnection = Open-AccessConnection -ConnectionString $sourceConnectionString

        foreach ($tableName in $processingTables) {
            if (-not (Test-TableExists -Connection $sourceConnection -TableName $tableName)) {
                throw "Existing database does not contain required Processing table '$tableName'."
            }
            if (-not (Test-TableExists -Connection $TargetConnection -TableName $tableName)) {
                throw "Target database does not contain required Processing table '$tableName'."
            }
        }

        $merchantabilityTableName = "SpeciesMerchantabilityStandards"

        $requiredFields = @(
            if (
                -not $script:ProjectPickleSkipSpeciesMerchantabilityStandards
            ) {
                "HasDRC"
                "DMsusceptible"
                "DMcollected"
            }
        )

        $missingSourceYesNoFields = New-Object System.Collections.Generic.List[string]

        foreach ($fieldName in $requiredFields) {
            if (-not (Test-ColumnExists `
                -Connection $sourceConnection `
                -TableName $merchantabilityTableName `
                -ColumnName $fieldName)) {

                [void]$missingSourceYesNoFields.Add($fieldName)
            }
        }

        if ($missingSourceYesNoFields.Count -gt 0) {
            throw (
                "The selected Existing/old project database cannot be used for Processing-table import. " +
                "$merchantabilityTableName is missing required Yes/No field(s): " +
                [string]::Join(
                    ", ",
                    [string[]]$missingSourceYesNoFields.ToArray()
                ) +
                ". Choose a compatible source database, or leave Import Processing tables unchecked so the current v3.10 Processing tables remain in the output. " +
                "No Processing tables were copied."
            )
        }

        foreach ($fieldName in $requiredFields) {
            if (-not (Test-ColumnExists `
                -Connection $TargetConnection `
                -TableName $merchantabilityTableName `
                -ColumnName $fieldName)) {

                throw "Target database table '$merchantabilityTableName' does not contain required Yes/No field '$fieldName'."
            }
        }

        $sourceCounts = @{}
        foreach ($tableName in $processingTables) {
            $sourceCounts[$tableName] = [int](Get-DbScalar -Connection $sourceConnection -Sql "SELECT Count(*) FROM $(Quote-Name $tableName)")
        }

        $sourceLiteral = ConvertTo-AccessExternalDatabaseSqlLiteral -Path $sourcePath
        $transaction = $TargetConnection.BeginTransaction()

        for ($i = $processingTables.Count - 1; $i -ge 0; $i--) {
            $tableName = $processingTables[$i]
            [void](Invoke-DbNonQueryInTransaction -Connection $TargetConnection -Transaction $transaction -Sql "DELETE FROM $(Quote-Name $tableName);")
        }

        foreach ($tableName in $processingTables) {
            Copy-AccessTableFromExternalDatabase -SourceConnection $sourceConnection -TargetConnection $TargetConnection -TargetTransaction $transaction -SourceDatabaseLiteral $sourceLiteral -TableName $tableName
        }

        $transaction.Commit()
        $transaction = $null

        $summaryParts = New-Object System.Collections.Generic.List[string]
        foreach ($tableName in $processingTables) {
            $targetCount = [int](Get-DbScalar -Connection $TargetConnection -Sql "SELECT Count(*) FROM $(Quote-Name $tableName)")
            [void]$summaryParts.Add(("{0}: {1} source row(s), {2} target row(s)" -f $tableName, $sourceCounts[$tableName], $targetCount))
        }

        & $Log ("Copied Processing tables from existing database. " + [string]::Join("; ", [string[]]$summaryParts.ToArray()) + ".")
    }
    catch {
        if ($null -ne $transaction) {
            try { $transaction.Rollback() } catch {}
        }
        throw "Could not copy Processing tables from existing database: $($_.Exception.Message)"
    }
    finally {
        if ($null -ne $transaction) {
            try { $transaction.Dispose() } catch {}
        }
        if ($null -ne $sourceConnection) {
            if ($sourceConnection.State -eq "Open") { $sourceConnection.Close() }
            $sourceConnection.Dispose()
        }
    }
}

function Get-ProcessingCalculatedTableNames {
    return [string[]]@(
        "PlotSummaries",
        "TreeCalculations",
        "RegenCalculations"
    )
}

function Copy-ProcessingCalculatedTablesFromExistingDatabase {
    param(
        [string]$SourceDatabasePath,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [scriptblock]$Log
    )

    if (-not $Log) { $Log = { param($Text) Write-Host $Text } }

    $sourcePath = ConvertTo-BuilderText $SourceDatabasePath
    if ([string]::IsNullOrWhiteSpace($sourcePath)) {
        throw "Import Plot Summaries, Tree Calc, and Regen Calc tables was selected, but no Existing/old project database was configured."
    }

    if (-not (Test-Path -LiteralPath $sourcePath)) {
        throw "Import Plot Summaries, Tree Calc, and Regen Calc tables was selected, but the Existing/old project database was not found: $sourcePath"
    }

    $calculatedTables = @(Get-ProcessingCalculatedTableNames)
    $sourceConnectionString = New-AccessConnectionString -Path $sourcePath
    $sourceConnection = $null
    $transaction = $null

    try {
        $sourceConnection = Open-AccessConnection -ConnectionString $sourceConnectionString

        foreach ($tableName in $calculatedTables) {
            if (-not (Test-TableExists -Connection $sourceConnection -TableName $tableName)) {
                throw "Existing database does not contain required Processing calculation/summary table '$tableName'."
            }

            if (-not (Test-TableExists -Connection $TargetConnection -TableName $tableName)) {
                throw "Target database does not contain required Processing calculation/summary table '$tableName'."
            }
        }

        $sourceCounts = @{}
        foreach ($tableName in $calculatedTables) {
            $sourceCounts[$tableName] = [int](Get-DbScalar -Connection $sourceConnection -Sql "SELECT Count(*) FROM $(Quote-Name $tableName)")
        }

        $sourceLiteral = ConvertTo-AccessExternalDatabaseSqlLiteral -Path $sourcePath
        $transaction = $TargetConnection.BeginTransaction()

        for ($i = $calculatedTables.Count - 1; $i -ge 0; $i--) {
            $tableName = $calculatedTables[$i]
            [void](Invoke-DbNonQueryInTransaction -Connection $TargetConnection -Transaction $transaction -Sql "DELETE FROM $(Quote-Name $tableName);")
        }

        foreach ($tableName in $calculatedTables) {
            Copy-AccessTableFromExternalDatabase -SourceConnection $sourceConnection -TargetConnection $TargetConnection -TargetTransaction $transaction -SourceDatabaseLiteral $sourceLiteral -TableName $tableName
        }

        $transaction.Commit()
        $transaction = $null

        $summaryParts = New-Object System.Collections.Generic.List[string]
        foreach ($tableName in $calculatedTables) {
            $targetCount = [int](Get-DbScalar -Connection $TargetConnection -Sql "SELECT Count(*) FROM $(Quote-Name $tableName)")
            [void]$summaryParts.Add(("{0}: {1} source row(s), {2} target row(s)" -f $tableName, $sourceCounts[$tableName], $targetCount))
        }

        & $Log ("Copied Plot Summaries, Tree Calc, and Regen Calc tables from existing database. " + [string]::Join("; ", [string[]]$summaryParts.ToArray()) + ".")
    }
    catch {
        if ($null -ne $transaction) {
            try { $transaction.Rollback() } catch {}
        }

        throw "Could not copy Plot Summaries, Tree Calc, and Regen Calc tables from existing database: $($_.Exception.Message)"
    }
    finally {
        if ($null -ne $transaction) {
            try { $transaction.Dispose() } catch {}
        }

        if ($null -ne $sourceConnection) {
            if ($sourceConnection.State -eq "Open") { $sourceConnection.Close() }
            $sourceConnection.Dispose()
        }
    }
}
function Ensure-CustomMeasurementColumnsForCopiedAppColumns {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [object[]]$CustomFields,
        [scriptblock]$Log
    )

    $customTables = @(
        "PlotCustomMeasurements",
        "TreeCustomMeasurements",
        "RegenCustomMeasurements"
    )

    $addedCount = 0

    foreach ($field in @($CustomFields)) {
        $tableName = ConvertTo-BuilderText $field.TableName
        if ($tableName -notin $customTables) { continue }

        $fieldName = ConvertTo-AccessFieldName $field.FieldName
        if ([string]::IsNullOrWhiteSpace($fieldName)) { continue }
        if (Test-CfideerSampleRemoveField -FieldName $fieldName) { continue }

        if (-not (Test-TableExists -Connection $Connection -TableName $tableName)) {
            throw "Custom table not found while checking copied AppColumns: $tableName"
        }

        $dataType = ConvertTo-BuilderText $field.DataType
        if ([string]::IsNullOrWhiteSpace($dataType)) { $dataType = "Text" }

        $addedColumn = Add-AccessColumnIfMissing -Connection $Connection -TableName $tableName -ColumnName $fieldName -DataType $dataType
        if ($addedColumn) {
            $addedCount++
            if ($Log) { & $Log "Added $tableName.$fieldName for copied AppColumns." }
        }
    }

    if ($Log) {
        & $Log "Checked copied AppColumns against custom measurement tables. Added $addedCount missing custom column(s)."
    }
}
function Ensure-AppColumn {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [object]$Spec
    )

    $appColumnLookup = New-CaseInsensitiveColumnLookup @(Get-TableColumns -Connection $Connection -TableName "AppColumns")
    $resolveAppColumn = {
        param([string[]]$Names)

        foreach ($name in @($Names)) {
            $actualName = Get-ColumnLookupValue -Lookup $appColumnLookup -ColumnName $name
            if (-not [string]::IsNullOrWhiteSpace($actualName)) { return $actualName }
        }
        return ""
    }
    $idColumn = & $resolveAppColumn @("ID", "AppColumnID", "ColumnID")
    $tableIdColumn = & $resolveAppColumn @("TableID", "AppTableID")
    $columnNameColumn = & $resolveAppColumn @("ColumnName", "FieldName", "Name")
    if ([string]::IsNullOrWhiteSpace($idColumn) -or [string]::IsNullOrWhiteSpace($tableIdColumn) -or [string]::IsNullOrWhiteSpace($columnNameColumn)) {
        throw "AppColumns table must include ID, TableID, and ColumnName fields before Project Pickle can update AppColumns settings."
    }

    $specAppColumnId = ""
    if ($Spec.PSObject.Properties["AppColumnID"]) {
        $specAppColumnId = ConvertTo-BuilderText $Spec.AppColumnID
    }
    $columnName = ConvertTo-AccessFieldName $Spec.FieldName
    $dataTypeId = Get-DataTypeId -Connection $Connection -DataType $Spec.DataType
    $categoryTypeId = Get-CategoryTypeId -Connection $Connection -Category $Spec.Category
    $friendly = ConvertTo-BuilderText $Spec.FriendlyName
    if ([string]::IsNullOrWhiteSpace($friendly)) { $friendly = $columnName }
    $short = ConvertTo-BuilderText $Spec.ShortName
    if ([string]::IsNullOrWhiteSpace($short)) { $short = $friendly }
    $description = ConvertTo-BuilderText $Spec.Description
    $validationAbrv = ConvertTo-BuilderText $Spec.ValidationAbrv
    $active = ConvertTo-BuilderBool $Spec.Active
    if ($Spec.PSObject.Properties["StandardCode"]) {
        $standardCode = ConvertTo-BuilderBool $Spec.StandardCode
    }
    else {
        $standardCode = ((ConvertTo-BuilderText $Spec.Category) -eq "Code")
    }
    $displayRule = ConvertTo-BuilderBool $Spec.DisplayRule

    $createUpdateParts = {
        param(
            [System.Collections.Generic.List[string]]$Assignments,
            [System.Collections.Generic.List[object]]$Parameters
        )

        $addUpdatePart = {
            param(
                [string[]]$ColumnAliases,
                [object]$Parameter
            )

            $actualColumn = & $resolveAppColumn $ColumnAliases
            if ([string]::IsNullOrWhiteSpace($actualColumn)) { return }
            [void]$Assignments.Add("$(Quote-Name $actualColumn) = ?")
            [void]$Parameters.Add($Parameter)
        }

        & $addUpdatePart @("DataTypeID", "AppColumnDataTypeID") (DbInt $dataTypeId)
        & $addUpdatePart @("CategoryTypeID", "AppColumnCategoryTypeID") (DbInt $categoryTypeId)
        & $addUpdatePart @("FriendlyName", "Friendly") (DbText $friendly)
        & $addUpdatePart @("ShortName", "Short") (DbText $short)
        & $addUpdatePart @("Description", "ColumnDescription") (DbLongText $description)
        & $addUpdatePart @("Active", "IsActive", "Collected") (DbBool $active)
        & $addUpdatePart @("StandardCode", "IsStandardCode") (DbBool $standardCode)
        & $addUpdatePart @("DisplayRule", "ReportVisible") (DbBool $displayRule)
        & $addUpdatePart @("ValidationAbrv", "ValidationAbbreviation") (DbText $validationAbrv)
    }

    if (-not [string]::IsNullOrWhiteSpace($specAppColumnId)) {
        $existingById = Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [AppColumns] WHERE $(Quote-Name $idColumn) = $(Sql-Guid $specAppColumnId)"
        if ([int]$existingById -le 0) { throw "AppColumns row $specAppColumnId was loaded, but it was not found in the saved project database copy." }
        $assignments = New-Object System.Collections.Generic.List[string]
        $parameters = New-Object System.Collections.Generic.List[object]
        & $createUpdateParts $assignments $parameters
        if ($assignments.Count -gt 0) {
            [void]$parameters.Add((DbGuid $specAppColumnId))
            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "UPDATE [AppColumns] SET $([string]::Join(', ', [string[]]$assignments.ToArray())) WHERE $(Quote-Name $idColumn) = ?" -Parameters @($parameters.ToArray()))
        }
        return $specAppColumnId
    }

    $tableId = Get-AppTableId -Connection $Connection -TableName $Spec.TableName
    $existingId = Get-DbScalar -Connection $Connection -Sql "SELECT TOP 1 $(Quote-Name $idColumn) FROM [AppColumns] WHERE $(Quote-Name $tableIdColumn) = $tableId AND $(Quote-Name $columnNameColumn) = $(Sql-Text $columnName)"
    if ($null -eq $existingId -or $existingId -is [System.DBNull]) {
        $id = New-GuidText
        $insertColumns = New-Object System.Collections.Generic.List[string]
        $insertParameters = New-Object System.Collections.Generic.List[object]
        $addInsertPart = {
            param(
                [string[]]$ColumnAliases,
                [object]$Parameter
            )

            $actualColumn = & $resolveAppColumn $ColumnAliases
            if ([string]::IsNullOrWhiteSpace($actualColumn)) { return }
            [void]$insertColumns.Add((Quote-Name $actualColumn))
            [void]$insertParameters.Add($Parameter)
        }
        & $addInsertPart @("ID", "AppColumnID", "ColumnID") (DbGuid $id)
        & $addInsertPart @("TableID", "AppTableID") (DbInt $tableId)
        & $addInsertPart @("DataTypeID", "AppColumnDataTypeID") (DbInt $dataTypeId)
        & $addInsertPart @("CategoryTypeID", "AppColumnCategoryTypeID") (DbInt $categoryTypeId)
        & $addInsertPart @("ColumnName", "FieldName", "Name") (DbText $columnName)
        & $addInsertPart @("FriendlyName", "Friendly") (DbText $friendly)
        & $addInsertPart @("ShortName", "Short") (DbText $short)
        & $addInsertPart @("Description", "ColumnDescription") (DbLongText $description)
        & $addInsertPart @("Active", "IsActive", "Collected") (DbBool $active)
        & $addInsertPart @("StandardCode", "IsStandardCode") (DbBool $standardCode)
        & $addInsertPart @("DisplayRule", "ReportVisible") (DbBool $displayRule)
        & $addInsertPart @("ValidationAbrv", "ValidationAbbreviation") (DbText $validationAbrv)
        $valuePlaceholders = [string]::Join(", ", [string[]]($insertColumns.ToArray() | ForEach-Object { "?" }))
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [AppColumns] ($([string]::Join(', ', [string[]]$insertColumns.ToArray()))) VALUES ($valuePlaceholders)" -Parameters @($insertParameters.ToArray()))
        return $id
    }

    $idText = ConvertTo-BuilderText $existingId
    $assignments = New-Object System.Collections.Generic.List[string]
    $parameters = New-Object System.Collections.Generic.List[object]
    & $createUpdateParts $assignments $parameters
    if ($assignments.Count -gt 0) {
        [void]$parameters.Add((DbGuid $idText))
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "UPDATE [AppColumns] SET $([string]::Join(', ', [string[]]$assignments.ToArray())) WHERE $(Quote-Name $idColumn) = ?" -Parameters @($parameters.ToArray()))
    }
    return $idText
}

function ConvertTo-AppColumnCodePairs {
    param([string]$CodesText)

    if ($null -eq $CodesText -or $CodesText -is [System.DBNull]) { return @() }
    $clean = [string]$CodesText
    $clean = $clean.Replace([string][char]0xFEFF, "")
    $clean = $clean.Replace([string][char]0x200B, "")
    $clean = $clean.Replace([string][char]0x200C, "")
    $clean = $clean.Replace([string][char]0x200D, "")
    $clean = $clean.Replace([string][char]0x00A0, " ")
    $clean = $clean.Trim()
    if ([string]::IsNullOrWhiteSpace($clean)) { return @() }

    $items = New-Object System.Collections.Generic.List[object]
    $pattern = "(?ms)(?:^|[;\r\n]+|\s+)(?<code>[^\s=;]+)\s*=\s*(?<label>.*?)(?=(?:[;\r\n]+|\s+)[^\s=;]+\s*=|$)"
    $matches = [regex]::Matches($clean, $pattern)
    if ($matches.Count -gt 0) {
        foreach ($match in $matches) {
            $code = ConvertTo-BuilderText $match.Groups["code"].Value
            $label = ConvertTo-BuilderText $match.Groups["label"].Value
            $label = $label.Trim(" ;`r`n`t")
            if ([string]::IsNullOrWhiteSpace($code)) { continue }
            if ([string]::IsNullOrWhiteSpace($label)) { $label = $code }
            [void]$items.Add([pscustomobject]@{
                Code = $code
                CodeLabel = $label
            })
        }
        return @($items.ToArray())
    }

    $parts = [regex]::Split($clean, "[;\r\n]+")
    foreach ($partText in $parts) {
        $part = ConvertTo-BuilderText $partText
        if ([string]::IsNullOrWhiteSpace($part)) { continue }
        [void]$items.Add([pscustomobject]@{
            Code = $part
            CodeLabel = $part
        })
    }
    return @($items.ToArray())
}

function Sort-AppColumnCodeParts {
    param([object[]]$Items)

    $indexed = New-Object System.Collections.Generic.List[object]
    $index = 0
    foreach ($item in $Items) {
        $part = ConvertTo-BuilderText $item
        if ([string]::IsNullOrWhiteSpace($part)) { continue }
        $codeText = $part
        $equalsIndex = $codeText.IndexOf("=")
        if ($equalsIndex -ge 0) {
            $codeText = $codeText.Substring(0, $equalsIndex)
        }
        $codeText = $codeText.Trim()
        [double]$numericCode = 0
        $isNumeric = [double]::TryParse($codeText, [System.Globalization.NumberStyles]::Float, [System.Globalization.CultureInfo]::InvariantCulture, [ref]$numericCode)
        [void]$indexed.Add([pscustomobject]@{
            Part = $part
            NumericGroup = if ($isNumeric) { 0 } else { 1 }
            NumericCode = if ($isNumeric) { $numericCode } else { [double]::PositiveInfinity }
            TextCode = $codeText.ToUpperInvariant()
            OriginalIndex = $index
        })
        $index++
    }

    return @($indexed |
        Sort-Object @{ Expression = { $_.NumericGroup } }, @{ Expression = { $_.NumericCode } }, @{ Expression = { $_.TextCode } }, @{ Expression = { $_.OriginalIndex } } |
        ForEach-Object { $_.Part })
}

function Sync-AppColumnCodes {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$ColumnId,
        [string]$CodesText
    )

    $pairs = @(ConvertTo-AppColumnCodePairs -CodesText $CodesText)
    if ($pairs.Count -eq 0) { return 0 }
    $added = 0
    $desiredCodes = @{}
    foreach ($pair in $pairs) {
        $code = ConvertTo-BuilderText $pair.Code
        $label = ConvertTo-BuilderText $pair.CodeLabel
        if ([string]::IsNullOrWhiteSpace($label)) { $label = $code }
        if ([string]::IsNullOrWhiteSpace($code)) { continue }
        $desiredCodes[$code.ToLowerInvariant()] = $true
        $exists = Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [AppColumnCodes] WHERE [ColumnID] = $(Sql-Guid $ColumnId) AND [Code] = $(Sql-Text $code)"
        if ([int]$exists -gt 0) {
            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "UPDATE [AppColumnCodes] SET [CodeLabel] = ?, [ShowInFDR] = ? WHERE [ColumnID] = ? AND [Code] = ?" -Parameters @(
                (DbText $label),
                (DbBool $true),
                (DbGuid $ColumnId),
                (DbText $code)
            ))
        }
        else {
            $codeId = New-GuidText
            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [AppColumnCodes] ([CodeID], [ColumnID], [MeasurementPeriodNumbers], [Code], [CodeLabel], [ShowInFDR]) VALUES (?, ?, ?, ?, ?, ?)" -Parameters @(
                (DbGuid $codeId),
                (DbGuid $ColumnId),
                (DbText $null),
                (DbText $code),
                (DbText $label),
                (DbBool $true)
            ))
            $added++
        }
    }
    $existingRows = Get-DbTable -Connection $Connection -Sql "SELECT [CodeID], [Code] FROM [AppColumnCodes] WHERE [ColumnID] = $(Sql-Guid $ColumnId)"
    foreach ($existingRow in $existingRows.Rows) {
        $existingCode = Get-DataRowText -Row $existingRow -ColumnNames @("Code")
        if ([string]::IsNullOrWhiteSpace($existingCode)) { continue }
        if ($desiredCodes.ContainsKey($existingCode.ToLowerInvariant())) { continue }
        $codeId = Get-DataRowText -Row $existingRow -ColumnNames @("CodeID")
        if (-not [string]::IsNullOrWhiteSpace($codeId)) {
            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "DELETE FROM [AppColumnCodes] WHERE [CodeID] = ?" -Parameters @((DbGuid $codeId)))
        }
    }
    return $added
}

function Get-AppColumnCodesText {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$ColumnId
    )

    if ([string]::IsNullOrWhiteSpace($ColumnId)) { return "" }
    if (-not (Test-TableExists -Connection $Connection -TableName "AppColumnCodes")) { return "" }
    $rows = Get-DbTable -Connection $Connection -Sql "SELECT [Code], [CodeLabel] FROM [AppColumnCodes] WHERE [ColumnID] = $(Sql-Guid $ColumnId) ORDER BY [Code]"
    $parts = New-Object System.Collections.Generic.List[string]
    foreach ($row in $rows.Rows) {
        $code = Get-DataRowText -Row $row -ColumnNames @("Code")
        if ([string]::IsNullOrWhiteSpace($code)) { continue }
        $label = Get-DataRowText -Row $row -ColumnNames @("CodeLabel")
        if ([string]::IsNullOrWhiteSpace($label) -or $label.Equals($code, [System.StringComparison]::OrdinalIgnoreCase)) {
            [void]$parts.Add($code)
        }
        else {
            [void]$parts.Add("$code=$label")
        }
    }
    $sortedParts = @(Sort-AppColumnCodeParts -Items @($parts.ToArray()))
    return [string]::Join("; ", [string[]]$sortedParts)
}

function ConvertTo-AppColumnCodesCellText {
    param([object]$Value)

    if ($null -eq $Value -or $Value -is [System.DBNull]) { return "" }
    $text = [string]$Value
    $text = $text.Replace([string][char]0xFEFF, "")
    $text = $text.Replace([string][char]0x200B, "")
    $text = $text.Replace([string][char]0x200C, "")
    $text = $text.Replace([string][char]0x200D, "")
    $text = $text.Replace([string][char]0x00A0, " ")
    $text = [regex]::Replace($text, "[`t ]+", " ")
    return $text.Trim()
}

function ConvertTo-AppColumnCodesEditorText {
    param([object]$Value)

    $text = ConvertTo-AppColumnCodesCellText $Value
    if ([string]::IsNullOrWhiteSpace($text)) { return "" }
    $pairs = @(ConvertTo-AppColumnCodePairs -CodesText $text)
    if ($pairs.Count -eq 0) { return $text }
    return [string]::Join("`r`n", [string[]]($pairs | ForEach-Object {
        $code = ConvertTo-BuilderText $_.Code
        $label = ConvertTo-BuilderText $_.CodeLabel
        if ([string]::IsNullOrWhiteSpace($label) -or $label.Equals($code, [System.StringComparison]::OrdinalIgnoreCase)) {
            $code
        }
        else {
            "$code=$label"
        }
    }))
}

function Test-AppColumnsReviewTableExcluded {
    param(
        [string]$TableName,
        [string]$FieldName = ""
    )

    $clean = ConvertTo-BuilderText $TableName
    if ([string]::IsNullOrWhiteSpace($clean)) { return $false }

    $normalized = ($clean -replace "[^A-Za-z0-9]", "").ToLowerInvariant()

    # Trees is normally skipped as a parent/system table, but SpeciesCode
    # lives on Trees and needs to load as a standard AppColumn.
    if ($normalized -eq "trees") {
        $fieldKey = ((ConvertTo-BuilderText $FieldName) -replace "[^A-Za-z0-9]", "").ToLowerInvariant()

        if ($fieldKey -in @(
            "speciescode",
            "treespeciescode"
        )) {
            return $false
        }
    }

    return @(
        "plots",
        "plotsummaries",
        "regencalculations",
        "treecalculations",
        "trees"
    ) -contains $normalized
}

function Test-AppColumnsReviewFieldExcluded {
    param(
        [string]$FieldName,
        [string]$TableName = ""
    )

    $clean = ConvertTo-BuilderText $FieldName
    if ([string]::IsNullOrWhiteSpace($clean)) { return $false }
    $normalized = ($clean -replace "[^A-Za-z0-9]", "").ToLowerInvariant()
    if (@(
        "treeid",
        "treekey",
        "treemeaskey",
        "readdbh",
        "realdbh",
        "treemeasid",
        "regenmeaskey",
        "projectperiodid",
        "projecetperiodid",
        "plotnumber",
        "measurementid",
        "gmp",
        "lastgrowingseason",
        "calcsiteindex",
        "remarksregen",
        "regenremarks",
        "stemcount",
        "fieldnamesampleremove"
    ) -contains $normalized) { return $true }

    $normalizedTable = ((ConvertTo-BuilderText $TableName) -replace "[^A-Za-z0-9]", "").ToLowerInvariant()
    $tableSpecificHiddenFields = @{
        plotmeasurements = @(
            "crew",
            "crewmembers",
            "measurementdate",
            "measuredate",
            "measdate",
            "periodnumber",
            "plotid",
            "plotkey",
            "plotmeaskey",
            "plotstatus",
            "remarksplot",
            "standclass",
            "standage",
            "stockabilityfactor",
            "stockabilitypct"
        )
        regenmeasurements = @(
            "idbh",
            "plotkey",
            "plotID",
            "remarks",
            "remarksregen",
            "regenremarks",
            "stemcount"
        )
        treemeasurements = @(
            "crownclass",
            "crownratio",
            "idbh",
            "periodnumber",
            "remarkstree",
            "totalheight",
            "treehistory"
        )
    }
    if ($tableSpecificHiddenFields.ContainsKey($normalizedTable) -and $tableSpecificHiddenFields[$normalizedTable] -contains $normalized) {
        return $true
    }
    return $false
}

function Get-AppColumnsReviewDataGroup {
    param([string]$TableName)

    $clean = ConvertTo-BuilderText $TableName
    if ([string]::IsNullOrWhiteSpace($clean)) { return "Other" }
    $normalized = ($clean -replace "[^A-Za-z0-9]", "").ToLowerInvariant()
    if ($normalized.StartsWith("plot")) { return "Plot" }
    if ($normalized.StartsWith("tree")) { return "Tree" }
    if ($normalized.StartsWith("regen") -or $normalized.StartsWith("regeneration")) { return "Regen" }
    return "Other"
}

function Get-AppColumnsForBuilder {
    param([System.Data.OleDb.OleDbConnection]$Connection)

    if (-not (Test-TableExists -Connection $Connection -TableName "AppColumns")) {
        throw "The selected database does not contain the AppColumns table, so Project Pickle cannot load standard AppColumns."
    }

    $table = Get-DbTable -Connection $Connection -Sql "SELECT * FROM [AppColumns]"
    $tableLookup = @{}
    if (Test-TableExists -Connection $Connection -TableName "AppTables") {
        $tableRows = Get-DbTable -Connection $Connection -Sql "SELECT * FROM [AppTables]"
        foreach ($tableRow in $tableRows.Rows) {
            $key = Get-DataRowText -Row $tableRow -ColumnNames @("ID", "TableID", "AppTableID", "DataTableID")
            $name = Get-DataRowText -Row $tableRow -ColumnNames @("TableName", "AppTableName", "AppTable", "DataTableName", "Name", "Description", "Table")
            if (-not [string]::IsNullOrWhiteSpace($key) -and -not [string]::IsNullOrWhiteSpace($name) -and -not $tableLookup.ContainsKey($key)) {
                $tableLookup[$key] = $name
            }
        }
    }

    $typeLookup = @{}
    if (Test-TableExists -Connection $Connection -TableName "AppColumnDataTypes") {
        $typeRows = Get-DbTable -Connection $Connection -Sql "SELECT * FROM [AppColumnDataTypes]"
        foreach ($typeRow in $typeRows.Rows) {
            $key = Get-DataRowText -Row $typeRow -ColumnNames @("ID", "DataTypeID", "AppColumnDataTypeID", "TypeID")
            $name = Get-DataRowText -Row $typeRow -ColumnNames @("TypeName", "DataType", "DataTypeName", "AppDataTypeName", "Name", "Description")
            if (-not [string]::IsNullOrWhiteSpace($key) -and -not [string]::IsNullOrWhiteSpace($name) -and -not $typeLookup.ContainsKey($key)) {
                $typeLookup[$key] = $name
            }
        }
    }

    $categoryLookup = @{}
    if (Test-TableExists -Connection $Connection -TableName "AppColumnCategoryTypes") {
        $categoryRows = Get-DbTable -Connection $Connection -Sql "SELECT * FROM [AppColumnCategoryTypes]"
        foreach ($categoryRow in $categoryRows.Rows) {
            $key = Get-DataRowText -Row $categoryRow -ColumnNames @("ID", "CategoryTypeID", "AppColumnCategoryTypeID", "AppCategoryTypeID")
            $name = Get-DataRowText -Row $categoryRow -ColumnNames @("CategoryName", "Category", "CategoryTypeName", "AppCategoryName", "Name", "Description")
            if (-not [string]::IsNullOrWhiteSpace($key) -and -not [string]::IsNullOrWhiteSpace($name) -and -not $categoryLookup.ContainsKey($key)) {
                $categoryLookup[$key] = $name
            }
        }
    }

    $codeLookup = @{}
    if (Test-TableExists -Connection $Connection -TableName "AppColumnCodes") {
        $codeRows = Get-DbTable -Connection $Connection -Sql "SELECT * FROM [AppColumnCodes]"
        foreach ($codeRow in $codeRows.Rows) {
            $columnId = Get-DataRowText -Row $codeRow -ColumnNames @("ColumnID", "AppColumnID", "AppColumnsID", "ParentColumnID")
            $code = Get-DataRowText -Row $codeRow -ColumnNames @("Code", "CodeValue", "Value", "OptionValue")
            if ([string]::IsNullOrWhiteSpace($columnId) -or [string]::IsNullOrWhiteSpace($code)) { continue }
            $label = Get-DataRowText -Row $codeRow -ColumnNames @("CodeLabel", "Label", "DisplayName", "Name", "Description")
            $part = if ([string]::IsNullOrWhiteSpace($label) -or $label.Equals($code, [System.StringComparison]::OrdinalIgnoreCase)) { $code } else { "$code=$label" }
            if (-not $codeLookup.ContainsKey($columnId)) {
                $codeLookup[$columnId] = New-Object System.Collections.Generic.List[string]
            }
            [void]$codeLookup[$columnId].Add($part)
        }
    }
    $items = New-Object System.Collections.Generic.List[object]
    foreach ($row in $table.Rows) {
        $id = Get-DataRowText -Row $row -ColumnNames @("ID", "AppColumnID", "ColumnID", "FieldID")
        $fieldName = Get-DataRowText -Row $row -ColumnNames @("ColumnName", "AppColumnName", "FieldName", "DbFieldName", "Field", "Column", "Name")
        if ([string]::IsNullOrWhiteSpace($id) -or [string]::IsNullOrWhiteSpace($fieldName)) { continue }
        $tableName = Get-DataRowText -Row $row -ColumnNames @("TableName", "AppTableName", "AppTable", "DataTableName", "MeasurementTable", "TargetTable")
        if ([string]::IsNullOrWhiteSpace($tableName)) {
            $tableId = Get-DataRowText -Row $row -ColumnNames @("TableID", "AppTableID", "DataTableID")
            if (-not [string]::IsNullOrWhiteSpace($tableId) -and $tableLookup.ContainsKey($tableId)) {
                $tableName = ConvertTo-BuilderText $tableLookup[$tableId]
            }
        }
        if (Test-AppColumnsReviewTableExcluded -TableName $tableName -FieldName $fieldName) { continue }
        if (Test-AppColumnsReviewFieldExcluded -FieldName $fieldName -TableName $tableName) { continue }
        $typeName = Get-DataRowText -Row $row -ColumnNames @("TypeName", "DataType", "DataTypeName", "AppDataTypeName")
        if ([string]::IsNullOrWhiteSpace($typeName)) {
            $typeId = Get-DataRowText -Row $row -ColumnNames @("DataTypeID", "AppColumnDataTypeID", "TypeID")
            if (-not [string]::IsNullOrWhiteSpace($typeId) -and $typeLookup.ContainsKey($typeId)) {
                $typeName = ConvertTo-BuilderText $typeLookup[$typeId]
            }
        }
        if ([string]::IsNullOrWhiteSpace($typeName)) { $typeName = "Text" }
        $categoryName = Get-DataRowText -Row $row -ColumnNames @("CategoryName", "Category", "CategoryTypeName", "AppCategoryName")
        if ([string]::IsNullOrWhiteSpace($categoryName)) {
            $categoryId = Get-DataRowText -Row $row -ColumnNames @("CategoryTypeID", "AppColumnCategoryTypeID", "AppCategoryTypeID")
            if (-not [string]::IsNullOrWhiteSpace($categoryId) -and $categoryLookup.ContainsKey($categoryId)) {
                $categoryName = ConvertTo-BuilderText $categoryLookup[$categoryId]
            }
        }
        if ([string]::IsNullOrWhiteSpace($categoryName)) { $categoryName = "Range" }
        $speciesCodeColumnIds = @("F73B0BE3-9ECD-459B-ACBE-11284E3D4C76", "C0ABC139-E8F6-42A5-AC34-57811C582511")
        $normalizedRowId = (ConvertTo-BuilderText $id) -replace "[{}]", ""
        if (@($speciesCodeColumnIds | Where-Object { [string]::Equals($_, $normalizedRowId, [System.StringComparison]::OrdinalIgnoreCase) }).Count -gt 0) {
            $categoryName = "Code"
        }
        $standardCode = ConvertTo-BuilderBool (Get-DataRowValue -Row $row -ColumnNames @("StandardCode", "IsStandardCode", "UseStandardCodes"))
        $active = ConvertTo-BuilderBool (Get-DataRowValue -Row $row -ColumnNames @("Active", "IsActive", "Collected", "Enabled"))
        $codesText = ""
        if ($codeLookup.ContainsKey($id)) {
            $sortedCodeParts = @(Sort-AppColumnCodeParts -Items @($codeLookup[$id].ToArray()))
            $codesText = [string]::Join("; ", [string[]]$sortedCodeParts)
        }
        [void]$items.Add([pscustomobject]@{
            AppColumnID = $id
            LoadedFromAppColumns = $true
            StandardCode = $standardCode
            Source = "Loaded"
            TableName = $tableName
            FieldName = $fieldName
            DataType = $typeName
            Category = $categoryName
            FriendlyName = Get-DataRowText -Row $row -ColumnNames @("FriendlyName", "DisplayName", "FieldLabel", "Label", "LongName")
            ShortName = Get-DataRowText -Row $row -ColumnNames @("ShortName", "ShortLabel", "Abbreviation", "Alias")
            Description = Get-DataRowText -Row $row -ColumnNames @("Description", "Comments", "Notes", "HelpText")
            ValidationAbrv = Get-DataRowText -Row $row -ColumnNames @("ValidationAbrv", "ValidationAbbr", "ValidationAbbrev", "ValidationCode", "ValidAbrv")
            Codes = $codesText
            Active = $active
            OriginalActive = $active
            Collected = $active
            ArchiveOnly = $false
            DisplayRule = ConvertTo-BuilderBool (Get-DataRowValue -Row $row -ColumnNames @("DisplayRule", "Display"))
            ReportVisible = $active
            QueryVisible = $active
            OriginalQueryVisible = $active
        })
    }
    return @($items.ToArray())
}

function Copy-AppColumnsBuilderItems {
    param([object[]]$Items)

    $copies = New-Object System.Collections.Generic.List[object]
    foreach ($item in @($Items)) {
        if ($null -eq $item) { continue }
        $copy = $item | Select-Object *
        [void]$copies.Add($copy)
    }
    return @($copies.ToArray())
}

function Load-AppColumnsForBuilderPath {
    param([string]$Path)

    $connectionString = New-AccessConnectionString -Path $Path
    $connection = Open-AccessConnection -ConnectionString $connectionString
    try {
        return @(Get-AppColumnsForBuilder -Connection $connection)
    }
    finally {
        if ($connection) { $connection.Close(); $connection.Dispose() }
    }
}

function Export-AppColumnsLoadResult {
    param(
        [string]$Path,
        [string]$OutputPath,
        [string]$ErrorPath
    )

    try {
        $items = @(Load-AppColumnsForBuilderPath -Path $Path)
        $json = ConvertTo-Json -InputObject @($items) -Depth 6 -Compress
        [System.IO.File]::WriteAllText($OutputPath, $json, [System.Text.Encoding]::UTF8)
        if (-not [string]::IsNullOrWhiteSpace($ErrorPath)) {
            [System.IO.File]::WriteAllText($ErrorPath, "", [System.Text.Encoding]::UTF8)
        }
        return 0
    }
    catch {
        $message = $_.Exception.Message
        if ([string]::IsNullOrWhiteSpace($message)) { $message = "Unknown AppColumns load error." }
        if (-not [string]::IsNullOrWhiteSpace($ErrorPath)) {
            [System.IO.File]::WriteAllText($ErrorPath, $message, [System.Text.Encoding]::UTF8)
        }
        else {
            Write-Error $message
        }
        return 1
    }
}

function Quote-ProcessArgument {
    param([string]$Value)

    if ($null -eq $Value) { return '""' }
    return '"' + ($Value -replace '"', '\"') + '"'
}

function Get-OpenXmlRows {
    param([string]$Path)

    Add-Type -AssemblyName System.IO.Compression
    Add-Type -AssemblyName System.IO.Compression.FileSystem

    $archive = [System.IO.Compression.ZipFile]::OpenRead($Path)
    try {
        $shared = New-Object System.Collections.Generic.List[string]
        $sharedEntry = $archive.GetEntry("xl/sharedStrings.xml")
        if ($sharedEntry) {
            $reader = New-Object System.IO.StreamReader($sharedEntry.Open())
            try {
                [xml]$sharedXml = $reader.ReadToEnd()
                $ns = New-Object System.Xml.XmlNamespaceManager($sharedXml.NameTable)
                $ns.AddNamespace("m", "http://schemas.openxmlformats.org/spreadsheetml/2006/main")
                foreach ($si in $sharedXml.SelectNodes("//m:si", $ns)) {
                    $parts = @()
                    foreach ($t in $si.SelectNodes(".//m:t", $ns)) { $parts += $t.InnerText }
                    [void]$shared.Add([string]::Join("", $parts))
                }
            }
            finally {
                $reader.Dispose()
            }
        }

        $sheetEntry = $archive.GetEntry("xl/worksheets/sheet1.xml")
        if (-not $sheetEntry) { throw "The workbook does not contain sheet1.xml." }
        $reader = New-Object System.IO.StreamReader($sheetEntry.Open())
        try {
            [xml]$sheetXml = $reader.ReadToEnd()
            $ns = New-Object System.Xml.XmlNamespaceManager($sheetXml.NameTable)
            $ns.AddNamespace("m", "http://schemas.openxmlformats.org/spreadsheetml/2006/main")
            $rows = New-Object System.Collections.Generic.List[object]
            foreach ($row in $sheetXml.SelectNodes("//m:sheetData/m:row", $ns)) {
                $values = @{}
                foreach ($cell in $row.SelectNodes("m:c", $ns)) {
                    $ref = [string]$cell.GetAttribute("r")
                    $col = Get-ExcelColumnIndex -CellReference $ref
                    $type = [string]$cell.GetAttribute("t")
                    $valueNode = $cell.SelectSingleNode("m:v", $ns)
                    $value = ""
                    if ($valueNode) {
                        $value = [string]$valueNode.InnerText
                        if ($type -eq "s") {
                            $idx = 0
                            if ([int]::TryParse($value, [ref]$idx) -and $idx -ge 0 -and $idx -lt $shared.Count) {
                                $value = $shared[$idx]
                            }
                        }
                    }
                    $values[$col] = $value
                }
                [void]$rows.Add($values)
            }
            return @($rows.ToArray())
        }
        finally {
            $reader.Dispose()
        }
    }
    finally {
        $archive.Dispose()
    }
}

function Get-ExcelColumnIndex {
    param([string]$CellReference)

    if ([string]::IsNullOrWhiteSpace($CellReference)) { return 0 }
    $match = [regex]::Match($CellReference, "^[A-Za-z]+")
    if (-not $match.Success) { return 0 }
    $index = 0
    foreach ($ch in $match.Value.ToUpperInvariant().ToCharArray()) {
        $index = ($index * 26) + ([int][char]$ch - [int][char]"A" + 1)
    }
    return $index
}

function Import-TabularRows {
    param([string]$Path)

    if ([string]::IsNullOrWhiteSpace($Path)) { return @() }
    if (-not (Test-Path -LiteralPath $Path)) { throw "Import file not found: $Path" }
    $extension = [System.IO.Path]::GetExtension($Path).ToLowerInvariant()
    if ($extension -eq ".csv") {
        return @(Import-Csv -LiteralPath $Path)
    }
    if ($extension -in @(".xlsx", ".xlsm")) {
        $rows = @(Get-OpenXmlRows -Path $Path)
        if ($rows.Count -eq 0) { return @() }
        $headers = @{}
        foreach ($key in $rows[0].Keys) {
            $header = ConvertTo-BuilderText $rows[0][$key]
            if (-not [string]::IsNullOrWhiteSpace($header)) { $headers[$key] = $header }
        }
        $objects = New-Object System.Collections.Generic.List[object]
        for ($i = 1; $i -lt $rows.Count; $i++) {
            $obj = [ordered]@{}
            foreach ($key in $headers.Keys) {
                $obj[$headers[$key]] = if ($rows[$i].ContainsKey($key)) { $rows[$i][$key] } else { "" }
            }
            [void]$objects.Add([pscustomobject]$obj)
        }
        return @($objects.ToArray())
    }
    throw "Unsupported import file type. Use CSV, XLSX, or XLSM."
}

function Get-ObjectPropertyText {
    param(
        [object]$Object,
        [string[]]$Names
    )

    foreach ($name in $Names) {
        if ($Object.PSObject.Properties[$name]) {
            return ConvertTo-BuilderText $Object.PSObject.Properties[$name].Value
        }
    }
    return ""
}

function Get-TabularColumnNames {
    param([string]$Path)

    if ([string]::IsNullOrWhiteSpace($Path) -or -not (Test-Path -LiteralPath $Path)) { return @() }
    $rows = @(Import-TabularRows -Path $Path)
    if ($rows.Count -eq 0) { return @() }
    return @($rows[0].PSObject.Properties.Name | Where-Object { -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $_)) })
}

function Get-DataRowText {
    param(
        [System.Data.DataRow]$Row,
        [string[]]$ColumnNames
    )

    if ($null -eq $Row) { return "" }
    foreach ($name in $ColumnNames) {
        if ($Row.Table.Columns.Contains($name)) {
            return ConvertTo-BuilderText $Row[$name]
        }
    }
    return ""
}

function Get-DataRowValue {
    param(
        [System.Data.DataRow]$Row,
        [string[]]$ColumnNames
    )

    if ($null -eq $Row) { return $null }
    foreach ($name in $ColumnNames) {
        if ($Row.Table.Columns.Contains($name)) {
            return $Row[$name]
        }
    }
    return $null
}

function New-PlotKey {
    param([int]$PlotNumber)
    return "P" + $PlotNumber.ToString("000000")
}

function Get-PeriodApplicableValue {
    param([object]$Period)

    $explicit = ConvertTo-BuilderText $Period.ApplicablePeriod
    if (-not [string]::IsNullOrWhiteSpace($explicit)) { return $explicit }
    foreach ($value in @($Period.ActualStartDate, $Period.PlannedStartDate, $Period.PeriodDescription)) {
        $text = ConvertTo-BuilderText $value
        if ($text -match "(19|20)\d{2}") { return $matches[0] }
    }
    return (Get-Date).Year.ToString()
}

function Test-UpgradeModeText {
    param([object]$Mode)

    $mode = ConvertTo-BuilderText $Mode
    if ([string]::IsNullOrWhiteSpace($mode)) { return $false }
    return [string]::Equals($mode, $script:UpgradeModeLabel, [System.StringComparison]::OrdinalIgnoreCase) -or
        [string]::Equals($mode, "Upgrade Old Project to Selected Template", [System.StringComparison]::OrdinalIgnoreCase) -or
        $mode.StartsWith("Upgrade ", [System.StringComparison]::OrdinalIgnoreCase)
}

function Test-UpgradeMode {
    param([object]$Config)

    if ($null -eq $Config) { return $false }
    if ($Config -is [string]) { return (Test-UpgradeModeText -Mode $Config) }
    $mode = if ($Config.PSObject.Properties["Mode"]) { $Config.Mode } else { $Config }
    return (Test-UpgradeModeText -Mode $mode)
}

function Test-NewProjectModeText {
    param([object]$Mode)

    return [string]::Equals((ConvertTo-BuilderText $Mode), "New Project", [System.StringComparison]::OrdinalIgnoreCase)
}

function Test-ModeUsesCurrentMasterDatabase {
    param([object]$Mode)

    return (Test-NewProjectModeText -Mode $Mode) -or (Test-UpgradeModeText -Mode $Mode)
}

function Test-NewOutputProjectMode {
    param([object]$Config)
    return [string]::Equals((ConvertTo-BuilderText $Config.Mode), "New Project", [System.StringComparison]::OrdinalIgnoreCase) -or (Test-UpgradeMode -Config $Config)
}

function Get-ExistingProjectReferenceSelection {
    param([string]$DatabasePath)

    $path = ConvertTo-BuilderText $DatabasePath
    if ([string]::IsNullOrWhiteSpace($path) -or -not (Test-Path -LiteralPath $path)) {
        throw "Project Pickle could not read Region, Agency, and Reservation from the existing database because the Existing/old project database path was not found."
    }

    $connection = $null
    try {
        $connection = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $path)
        $projectTable = Get-DbTable -Connection $connection -Sql "SELECT TOP 1 * FROM [Projects]"
        if ($projectTable.Rows.Count -eq 0) {
            throw "The existing database has no Projects row to read Region, Agency, and Reservation from."
        }

        $project = $projectTable.Rows[0]
        $projectName = Get-DataRowText -Row $project -ColumnNames @("Description", "ProjectName", "Name", "Project", "Title")
        $cycleLength = Get-DataRowText -Row $project -ColumnNames @("CycleLength", "MeasurementCycleLength", "Cycle", "CycleYears")
        $projectReservationId = Get-DataRowText -Row $project -ColumnNames @("ReservationID")
        $projectReservationCode = Get-DataRowText -Row $project -ColumnNames @("ReservationCode")
        $reservationTable = $null
        if (-not [string]::IsNullOrWhiteSpace($projectReservationId)) {
            try {
                $reservationTable = Get-DbTable -Connection $connection -Sql "SELECT TOP 1 * FROM [Reservations] WHERE [ReservationID] = $(Sql-Guid $projectReservationId)"
            }
            catch {
                $reservationTable = $null
            }
        }
        if (($null -eq $reservationTable -or $reservationTable.Rows.Count -eq 0) -and -not [string]::IsNullOrWhiteSpace($projectReservationCode)) {
            $reservationTable = Get-DbTable -Connection $connection -Sql "SELECT TOP 1 * FROM [Reservations] WHERE [ReservationCode] = $(Sql-Text $projectReservationCode)"
        }
        if ($null -eq $reservationTable -or $reservationTable.Rows.Count -eq 0) {
            throw "Project Pickle could not match the Projects row to a Reservations row in the existing database."
        }

        $reservation = $reservationTable.Rows[0]
        $reservationName = Get-DataRowText -Row $reservation -ColumnNames @("ReservationName", "ForestName", "Name", "Description")
        $reservationCode = Get-DataRowText -Row $reservation -ColumnNames @("ReservationCode")
        if ([string]::IsNullOrWhiteSpace($reservationCode)) { $reservationCode = $projectReservationCode }
        $agencyId = Get-DataRowText -Row $reservation -ColumnNames @("AgencyID")
        $agencyName = ""
        $regionId = ""
        $regionName = ""
        if (-not [string]::IsNullOrWhiteSpace($agencyId)) {
            try {
                $agencyTable = Get-DbTable -Connection $connection -Sql "SELECT TOP 1 * FROM [Agencies] WHERE [AgencyID] = $(Sql-Guid $agencyId)"
                if ($agencyTable.Rows.Count -gt 0) {
                    $agency = $agencyTable.Rows[0]
                    $agencyName = Get-DataRowText -Row $agency -ColumnNames @("AgencyName", "Agency", "Name", "Description")
                    $regionId = Get-DataRowText -Row $agency -ColumnNames @("RegionID")
                }
            }
            catch {
            }
        }
        if (-not [string]::IsNullOrWhiteSpace($regionId)) {
            try {
                $regionTable = Get-DbTable -Connection $connection -Sql "SELECT TOP 1 * FROM [Regions] WHERE [RegionID] = $(Sql-Guid $regionId)"
                if ($regionTable.Rows.Count -gt 0) {
                    $regionName = Get-DataRowText -Row $regionTable.Rows[0] -ColumnNames @("RegionName", "Region", "Name", "Description")
                }
            }
            catch {
            }
        }

        if ([string]::IsNullOrWhiteSpace($reservationName)) {
            throw "Project Pickle found the existing reservation row, but it did not have a ReservationName."
        }

        return [pscustomobject]@{
            ProjectName = $projectName
            CycleLength = $cycleLength
            RegionName = $regionName
            AgencyName = $agencyName
            ReservationName = $reservationName
            ReservationCode = $reservationCode
        }
    }
    finally {
        if ($null -ne $connection) {
            if ($connection.State -eq "Open") { $connection.Close() }
            $connection.Dispose()
        }
    }
}

function Resolve-ReservationSelection {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$ReservationCode,
        [string]$ReservationName,
        [string]$AgencyName = "",
        [string]$RegionName = ""
    )

    $where = ""
    $requestedReservationName = ConvertTo-BuilderText $ReservationName
    if (-not [string]::IsNullOrWhiteSpace($ReservationCode)) {
        $where = "[ReservationCode] = $(Sql-Text $ReservationCode)"
    }
    else {
        $where = "1=1"
    }
    $table = Get-DbTable -Connection $Connection -Sql "SELECT * FROM [Reservations] WHERE $where ORDER BY [ReservationName]"
    if ($table.Rows.Count -eq 0) { throw "Could not find the selected reservation." }
    if (-not $table.Columns.Contains("RegionID")) { $table.Columns.Add("RegionID", [string]) | Out-Null }
    if (-not $table.Columns.Contains("RegionNameResolved")) { $table.Columns.Add("RegionNameResolved", [string]) | Out-Null }
    if (-not $table.Columns.Contains("AgencyNameResolved")) { $table.Columns.Add("AgencyNameResolved", [string]) | Out-Null }

    foreach ($reservation in $table.Rows) {
        $resolvedReservationName = Get-DataRowText -Row $reservation -ColumnNames @("ReservationName", "ForestName", "Name", "Description")
        $agencyId = ConvertTo-BuilderText $reservation["AgencyID"]
        $agency = Get-DbTable -Connection $Connection -Sql "SELECT TOP 1 * FROM [Agencies] WHERE [AgencyID] = $(Sql-Guid $agencyId)"
        $regionId = ""
        $resolvedAgencyName = ""
        $resolvedRegionName = ""
        if ($agency.Rows.Count -gt 0) {
            $resolvedAgencyName = Get-DataRowText -Row $agency.Rows[0] -ColumnNames @("AgencyName", "Agency", "Name", "Description")
            if ([string]::IsNullOrWhiteSpace($resolvedAgencyName)) { $resolvedAgencyName = $agencyId }
            $regionId = Get-DataRowText -Row $agency.Rows[0] -ColumnNames @("RegionID")
            $region = Get-DbTable -Connection $Connection -Sql "SELECT TOP 1 * FROM [Regions] WHERE [RegionID] = $(Sql-Guid $regionId)"
            if ($region.Rows.Count -gt 0) {
                $resolvedRegionName = Get-DataRowText -Row $region.Rows[0] -ColumnNames @("RegionName", "Region", "Name", "Description")
                if ([string]::IsNullOrWhiteSpace($resolvedRegionName)) { $resolvedRegionName = $regionId }
            }
        }
        $reservation["RegionID"] = $regionId
        $reservation["RegionNameResolved"] = $resolvedRegionName
        $reservation["AgencyNameResolved"] = $resolvedAgencyName
        $reservationMatches = [string]::IsNullOrWhiteSpace($requestedReservationName) -or $resolvedReservationName.Equals($requestedReservationName, [System.StringComparison]::OrdinalIgnoreCase)
        $regionMatches = [string]::IsNullOrWhiteSpace($RegionName) -or $resolvedRegionName.Equals($RegionName, [System.StringComparison]::OrdinalIgnoreCase)
        $agencyMatches = [string]::IsNullOrWhiteSpace($AgencyName) -or $resolvedAgencyName.Equals($AgencyName, [System.StringComparison]::OrdinalIgnoreCase)
        if ($reservationMatches -and $regionMatches -and $agencyMatches) {
            return $reservation
        }
    }

    throw "Could not find a reservation matching the selected region, agency, and reservation name."
}

function Set-ProjectSetup {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [object]$Config,
        [System.Data.DataRow]$Reservation,
        [scriptblock]$Log
    )

    $existingProjectId = Get-RequiredScalarText -Connection $Connection -Sql "SELECT TOP 1 [ProjectID] FROM [Projects]" -Message "The database has no Projects row."
    $isNewOutputProject = Test-NewOutputProjectMode -Config $Config
    $isExistingProjectMode = Test-WOOFTextEquals (ConvertTo-BuilderText $Config.Mode) "Existing Project"
    $projectId = if ($isNewOutputProject) { New-GuidText } else { $existingProjectId }
    if ($isExistingProjectMode) {
        & $Log "Existing Project mode: preserving existing Projects row values."
        return $projectId
    }
    $projectName = ConvertTo-BuilderText $Config.ProjectName
    if ([string]::IsNullOrWhiteSpace($projectName)) { $projectName = "CFI Project" }
    $cycleText = ConvertTo-BuilderText $Config.CycleLength
    $cycleLength = $null
    if (-not [string]::IsNullOrWhiteSpace($cycleText)) {
        $parsedCycleLength = 0
        if (-not [int]::TryParse($cycleText, [ref]$parsedCycleLength) -or $parsedCycleLength -le 0) {
            throw "Measurement cycle length must be a whole number of years, such as 10."
        }
        $cycleLength = $parsedCycleLength
    }
    elseif ($isNewOutputProject) {
        $cycleLength = 10
    }
    $reservationId = ConvertTo-BuilderText $Reservation["ReservationID"]
    $reservationCode = ConvertTo-BuilderText $Reservation["ReservationCode"]
    $now = Get-Date

    if ($isNewOutputProject) {
        & $Log "Creating new project row and ProjectID."
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [Projects] ([ProjectID], [ReservationID], [TypeID], [ReservationCode], [Type], [CycleLength], [Description], [IsDeleted], [InitialDate], [Created], [Updated], [UpdUser], [RetrievalID]) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)" -Parameters @(
            (DbGuid $projectId),
            (DbGuid $reservationId),
            (DbInt 1),
            (DbText $reservationCode),
            (DbText "CFI"),
            (DbInt $cycleLength),
            (DbText $projectName),
            (DbBool $false),
            (DbDate $now),
            (DbDate $now),
            (DbDate $now),
            (DbText "builder"),
            (DbInt 0)
        ))
    }
    else {
        & $Log "Using existing project row and normalizing setup values."
        if ($null -ne $cycleLength) {
            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "UPDATE [Projects] SET [ReservationID] = ?, [ReservationCode] = ?, [TypeID] = ?, [Type] = ?, [CycleLength] = ?, [Description] = ?, [Updated] = ?, [UpdUser] = ? WHERE [ProjectID] = ?" -Parameters @(
                (DbGuid $reservationId),
                (DbText $reservationCode),
                (DbInt 1),
                (DbText "CFI"),
                (DbInt $cycleLength),
                (DbText $projectName),
                (DbDate $now),
                (DbText "builder"),
                (DbGuid $projectId)
            ))
        }
        else {
            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "UPDATE [Projects] SET [ReservationID] = ?, [ReservationCode] = ?, [TypeID] = ?, [Type] = ?, [Description] = ?, [Updated] = ?, [UpdUser] = ? WHERE [ProjectID] = ?" -Parameters @(
                (DbGuid $reservationId),
                (DbText $reservationCode),
                (DbInt 1),
                (DbText "CFI"),
                (DbText $projectName),
                (DbDate $now),
                (DbText "builder"),
                (DbGuid $projectId)
            ))
        }
    }

    $tables = @(Get-UserTables -Connection $Connection)
    foreach ($table in $tables) {
        if ($table -eq "Projects") { continue }
        $columns = @(Get-TableColumns -Connection $Connection -TableName $table)
        if ($columns -contains "ProjectID") {
            try {
                [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "UPDATE $(Quote-Name $table) SET [ProjectID] = ?" -Parameters @((DbGuid $projectId)))
            }
            catch {
                & $Log "Could not update ProjectID in ${table}: $($_.Exception.Message)"
            }
        }
    }

    if ($isNewOutputProject) {
        try {
            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "DELETE FROM [Projects] WHERE [ProjectID] <> ?" -Parameters @((DbGuid $projectId)))
        }
        catch {
            & $Log "Could not remove old template project row: $($_.Exception.Message)"
        }
    }

    if (Test-TableExists -Connection $Connection -TableName "AnalysisProjectParameters") {
        $dir = [System.IO.Path]::GetDirectoryName($Config.OutputDatabase)
        $tun = $reservationCode + "_CFI.NTU"
        $ref = $reservationCode + "_CFI.REF"
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "UPDATE [AnalysisProjectParameters] SET [ProjectID] = ?, [TUNFileName] = ?, [REFFileName] = ?, [CFIDataPathName] = ?, [ProjectPathName] = ?, [Updated] = ?, [UpdUser] = ?" -Parameters @(
            (DbGuid $projectId),
            (DbText $tun),
            (DbText $ref),
            (DbLongText $dir),
            (DbLongText $dir),
            (DbDate $now),
            (DbText "builder")
        ))
    }
    if (Test-TableExists -Connection $Connection -TableName "AnalysisRuns") {
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "UPDATE [AnalysisRuns] SET [ProjectID] = ?, [Title] = ?, [Description] = ?, [Updated] = ?, [UpdUser] = ?" -Parameters @(
            (DbGuid $projectId),
            (DbText $projectName),
            (DbLongText $projectName),
            (DbDate $now),
            (DbText "builder")
        ))
    }

    return $projectId
}

function Set-ReferenceScope {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [System.Data.DataRow]$Reservation,
        [scriptblock]$Log
    )

    $reservationId = ConvertTo-BuilderText $Reservation["ReservationID"]
    $agencyId = ConvertTo-BuilderText $Reservation["AgencyID"]
    $regionId = ConvertTo-BuilderText $Reservation["RegionID"]
    & $Log "Pruning Regions, Agencies, and Reservations to the selected project scope."
    [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "DELETE FROM [Reservations] WHERE [ReservationID] <> ?" -Parameters @((DbGuid $reservationId)))
    [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "DELETE FROM [Agencies] WHERE [AgencyID] <> ?" -Parameters @((DbGuid $agencyId)))
    [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "DELETE FROM [Regions] WHERE [RegionID] <> ?" -Parameters @((DbGuid $regionId)))
}

function Set-MeasurementPeriods {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$ProjectId,
        [object[]]$Periods,
        [scriptblock]$Log
    )

    if ($Periods.Count -eq 0) { throw "At least one measurement period is required." }
    & $Log "Writing $($Periods.Count) measurement period row(s)."
    [void](Invoke-DbNonQuery -Connection $Connection -Sql "DELETE FROM [ProjectMeasurementPeriods]")
    $periodOut = New-Object System.Collections.Generic.List[object]
    foreach ($period in $Periods) {
        $periodId = if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $period.ProjectPeriodID))) { New-GuidText } else { ConvertTo-BuilderText $period.ProjectPeriodID }
        $number = [int](ConvertTo-BuilderText $period.PeriodNumber)
        $description = ConvertTo-BuilderText $period.PeriodDescription
        if ([string]::IsNullOrWhiteSpace($description)) { $description = "Measurement $number" }
        $now = Get-Date
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [ProjectMeasurementPeriods] ([ProjectPeriodID], [ProjectID], [PeriodNumber], [PeriodDescription], [PlannedStartDate], [PlannedEndDate], [ActualStartDate], [ActualEndDate], [Created], [Updated], [updUser], [RetrievalID]) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)" -Parameters @(
            (DbGuid $periodId),
            (DbGuid $ProjectId),
            (DbInt $number),
            (DbText $description),
            (DbDate $period.PlannedStartDate),
            (DbDate $period.PlannedEndDate),
            (DbDate $period.ActualStartDate),
            (DbDate $period.ActualEndDate),
            (DbDate $now),
            (DbDate $now),
            (DbText "builder"),
            (DbInt 0)
        ))
        [void]$periodOut.Add([pscustomobject]@{
            ProjectPeriodID = $periodId
            PeriodNumber = $number
            PeriodDescription = $description
            ApplicablePeriod = Get-PeriodApplicableValue -Period $period
            IsCurrent = [bool]$period.IsCurrent
        })
    }

    if (Test-TableExists -Connection $Connection -TableName "InventoryDesign") {
        [void](Invoke-DbNonQuery -Connection $Connection -Sql "DELETE FROM [InventoryDesign]")
        foreach ($period in $periodOut) {
            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [InventoryDesign] ([DesignID], [ProjectPeriodID], [PeriodNumber], [DesignComments], [Questions], [CommentsClarification]) VALUES (?, ?, ?, ?, ?, ?)" -Parameters @(
                (DbGuid (New-GuidText)),
                (DbGuid $period.ProjectPeriodID),
                (DbInt $period.PeriodNumber),
                (DbLongText $null),
                (DbLongText $null),
                (DbLongText $null)
            ))
        }
    }

    return @($periodOut.ToArray())
}

function Set-AnalysisProjectPeriodIds {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [object[]]$Periods,
        [scriptblock]$Log
    )

    $current = @($Periods | Where-Object { ConvertTo-BuilderBool $_.IsCurrent })
    if ($current.Count -gt 0) {
        if ($current.Count -gt 1 -and $Log) {
            & $Log "More than one period was marked current for analysis table setup. Using the highest current period only."
        }
        $current = @($current | Sort-Object PeriodNumber -Descending | Select-Object -First 1)
    }
    else {
        $current = @($Periods | Sort-Object PeriodNumber -Descending | Select-Object -First 1)
        if ($current.Count -gt 0 -and $Log) {
            & $Log "No current period was marked for analysis table setup. Using highest period number $($current[0].PeriodNumber)."
        }
    }

    if ($current.Count -eq 0) { return }
    $periodId = ConvertTo-BuilderText $current[0].ProjectPeriodID
    $periodNumber = ConvertTo-BuilderText $current[0].PeriodNumber
    if ([string]::IsNullOrWhiteSpace($periodId)) { return }

    $updated = New-Object System.Collections.Generic.List[string]
    foreach ($table in @(Get-UserTables -Connection $Connection)) {
        if (-not $table.StartsWith("Analysis", [System.StringComparison]::OrdinalIgnoreCase)) { continue }
        $columns = @(Get-TableColumns -Connection $Connection -TableName $table)
        $lookup = New-CaseInsensitiveColumnLookup $columns
        $periodColumn = Get-ColumnLookupValue -Lookup $lookup -ColumnName "ProjectPeriodID"
        if ([string]::IsNullOrWhiteSpace($periodColumn)) { continue }
        $rowCount = Invoke-DbNonQueryParameterized -Connection $Connection -Sql "UPDATE $(Quote-Name $table) SET $(Quote-Name $periodColumn) = ?" -Parameters @((DbGuid $periodId))
        [void]$updated.Add("$table ($rowCount row(s))")
    }

    if ($Log) {
        if ($updated.Count -gt 0) {
            & $Log "Updated analysis table ProjectPeriodID values to current PeriodNumber $periodNumber ($periodId): $([string]::Join('; ', [string[]]$updated.ToArray()))."
        }
        else {
            & $Log "No analysis tables with ProjectPeriodID were found to update."
        }
    }
}

function Set-ValidationPeriods {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$ProjectId,
        [object[]]$Periods,
        [scriptblock]$Log
    )

    if (-not (Test-TableExists -Connection $Connection -TableName "ValidationRules")) { return }
    $current = @($Periods | Where-Object { $_.IsCurrent })
    if ($current.Count -eq 0) { $current = @($Periods | Sort-Object PeriodNumber -Descending | Select-Object -First 1) }
    $applicable = [string]::Join(",", [string[]]($current | ForEach-Object { $_.ApplicablePeriod } | Where-Object { -not [string]::IsNullOrWhiteSpace($_) }))
    if ([string]::IsNullOrWhiteSpace($applicable)) { $applicable = (Get-Date).Year.ToString() }
    & $Log "Updating ValidationRules ProjectID and ApplicablePeriods to $applicable."
    [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "UPDATE [ValidationRules] SET [ProjectID] = ?, [ApplicablePeriods] = ?" -Parameters @(
        (DbGuid $ProjectId),
        (DbText $applicable)
    ))
}

function Sync-CustomFields {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [object[]]$CustomFields,
        [scriptblock]$Log
    )

    $synced = New-Object System.Collections.Generic.List[object]
    foreach ($field in $CustomFields) {
        $tableName = ConvertTo-BuilderText $field.TableName
        $fieldName = ConvertTo-AccessFieldName $field.FieldName
        if ([string]::IsNullOrWhiteSpace($tableName) -or [string]::IsNullOrWhiteSpace($fieldName)) { continue }
        if (Test-CfideerSampleRemoveField -FieldName $fieldName) { continue }
        $loadedFromAppColumns = $false
        if ($field.PSObject.Properties["LoadedFromAppColumns"]) {
            $loadedFromAppColumns = ConvertTo-BuilderBool $field.LoadedFromAppColumns
        }
        $appColumnIdFromGrid = ""
        if ($field.PSObject.Properties["AppColumnID"]) {
            $appColumnIdFromGrid = ConvertTo-BuilderText $field.AppColumnID
        }
        $isExistingAppColumn = ($loadedFromAppColumns -or -not [string]::IsNullOrWhiteSpace($appColumnIdFromGrid))
        $isCustomMeasurementTable = ($tableName -in @("PlotCustomMeasurements", "TreeCustomMeasurements", "RegenCustomMeasurements"))
        $shouldEnsurePhysicalColumn = (-not $isExistingAppColumn) -or ($isCustomMeasurementTable -and (ConvertTo-BuilderBool $field.Active))
        if ($shouldEnsurePhysicalColumn) {
            if (-not (Test-TableExists -Connection $Connection -TableName $tableName)) { throw "Custom table not found: $tableName" }
            $addedColumn = Add-AccessColumnIfMissing -Connection $Connection -TableName $tableName -ColumnName $fieldName -DataType $field.DataType
            if ($addedColumn) {
                $sourceText = if ($isExistingAppColumn) { "active loaded AppColumns field" } else { "new custom field" }
                & $Log "Added $tableName.$fieldName for $sourceText."
            }
        }
        $field | Add-Member -NotePropertyName TableName -NotePropertyValue $tableName -Force
        $field | Add-Member -NotePropertyName FieldName -NotePropertyValue $fieldName -Force
        $appColumnId = Ensure-AppColumn -Connection $Connection -Spec $field
        $codesText = ConvertTo-AppColumnCodesCellText $field.Codes
        $categoryText = ConvertTo-BuilderText $field.Category
        if (-not $isExistingAppColumn) {
            [void](Sync-AppColumnCodes -Connection $Connection -ColumnId $appColumnId -CodesText $codesText)
        }
        elseif ($categoryText.Equals("Code", [System.StringComparison]::OrdinalIgnoreCase) -and -not [string]::IsNullOrWhiteSpace($codesText)) {
            [void](Sync-AppColumnCodes -Connection $Connection -ColumnId $appColumnId -CodesText $codesText)
        }
        if ($isExistingAppColumn) { & $Log "Updated AppColumns settings and codes for $tableName.$fieldName." }
        $field | Add-Member -NotePropertyName AppColumnID -NotePropertyValue $appColumnId -Force
        [void]$synced.Add($field)
    }
    return @($synced.ToArray())
}

function Remove-FieldNameSampleRemoveFromCustomTables {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [scriptblock]$Log
    )

    $placeholder = "FieldNameSampleRemove"
    foreach ($tableName in @("PlotCustomMeasurements", "TreeCustomMeasurements", "RegenCustomMeasurements")) {
        try {
            if (Test-TableExists -Connection $Connection -TableName "AppColumns") {
                $tableId = $null
                try { $tableId = Get-AppTableId -Connection $Connection -TableName $tableName } catch { $tableId = $null }
                if ($null -ne $tableId) {
                    $appColumnRows = Get-DbTable -Connection $Connection -Sql "SELECT [ID] FROM [AppColumns] WHERE [TableID] = $tableId AND [ColumnName] = $(Sql-Text $placeholder)"
                    foreach ($row in $appColumnRows.Rows) {
                        $columnId = Get-DataRowText -Row $row -ColumnNames @("ID")
                        if ([string]::IsNullOrWhiteSpace($columnId)) { continue }
                        if (Test-TableExists -Connection $Connection -TableName "AppColumnCodes") {
                            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "DELETE FROM [AppColumnCodes] WHERE [ColumnID] = ?" -Parameters @((DbGuid $columnId)))
                        }
                        if (Test-TableExists -Connection $Connection -TableName "ReportColumns") {
                            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "DELETE FROM [ReportColumns] WHERE [ColumnID] = ?" -Parameters @((DbGuid $columnId)))
                        }
                        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "DELETE FROM [AppColumns] WHERE [ID] = ?" -Parameters @((DbGuid $columnId)))
                    }
                }
            }

            if (Test-ColumnExists -Connection $Connection -TableName $tableName -ColumnName $placeholder) {
                [void](Invoke-DbNonQuery -Connection $Connection -Sql "ALTER TABLE $(Quote-Name $tableName) DROP COLUMN $(Quote-Name $placeholder)")
                if ($Log) { & $Log "Removed placeholder column $tableName.$placeholder." }
            }
        }
        catch {
            if ($Log) { & $Log "Warning: could not remove placeholder field ${tableName}.${placeholder}: $($_.Exception.Message)" }
        }
    }
}

function Set-ProjectIdInAllTables {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$ProjectId,
        [scriptblock]$Log
    )

    foreach ($table in @(Get-UserTables -Connection $Connection)) {
        if ([string]::Equals($table, "Projects", [System.StringComparison]::OrdinalIgnoreCase)) { continue }
        $columns = @(Get-TableColumns -Connection $Connection -TableName $table)
        if ($columns -contains "ProjectID") {
            try {
                [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "UPDATE $(Quote-Name $table) SET [ProjectID] = ?" -Parameters @((DbGuid $ProjectId)))
            }
            catch {
                if ($Log) { & $Log "Could not update ProjectID in ${table}: $($_.Exception.Message)" }
            }
        }
    }
}

function New-UpgradePeriodIdMap {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [object[]]$OutputPeriods
    )

    $map = @{}
    $periodTableName = Get-ProjectPeriodTableNameForBuilder -Connection $SourceConnection
    if ([string]::IsNullOrWhiteSpace($periodTableName)) { return $map }
    $sourceColumns = @(Get-TableColumns -Connection $SourceConnection -TableName $periodTableName)
    $sourcePeriodIdColumn = @($sourceColumns | Where-Object { $_ -in @("ProjectPeriodID", "PeriodID", "ID") } | Select-Object -First 1)
    $sourcePeriodNumberColumn = @($sourceColumns | Where-Object { $_ -in @("PeriodNumber", "MeasurementPeriodNumber", "MeasurementPeriod", "Period") } | Select-Object -First 1)
    if ($sourcePeriodIdColumn.Count -eq 0 -or $sourcePeriodNumberColumn.Count -eq 0) { return $map }
    $outputByNumber = @{}
    foreach ($period in @($OutputPeriods)) {
        $number = ConvertTo-BuilderText $period.PeriodNumber
        $periodId = ConvertTo-BuilderText $period.ProjectPeriodID
        if (-not [string]::IsNullOrWhiteSpace($number) -and -not [string]::IsNullOrWhiteSpace($periodId)) {
            $outputByNumber[$number] = $periodId
        }
    }

    $sourcePeriods = Get-DbTable -Connection $SourceConnection -Sql "SELECT * FROM $(Quote-Name $periodTableName)"
    foreach ($row in $sourcePeriods.Rows) {
        $oldId = Get-DataRowText -Row $row -ColumnNames @("ProjectPeriodID", "PeriodID", "ID")
        $number = Get-DataRowText -Row $row -ColumnNames @("PeriodNumber", "MeasurementPeriodNumber", "MeasurementPeriod", "Period")
        if (-not [string]::IsNullOrWhiteSpace($oldId) -and $outputByNumber.ContainsKey($number)) {
            $map[$oldId.ToLowerInvariant()] = $outputByNumber[$number]
        }
    }
    return $map
}

function New-UpgradeOutputPeriodIdByNumber {
    param([object[]]$OutputPeriods)

    $map = @{}
    foreach ($period in @($OutputPeriods)) {
        $number = ConvertTo-BuilderText $period.PeriodNumber
        $periodId = ConvertTo-BuilderText $period.ProjectPeriodID
        if (-not [string]::IsNullOrWhiteSpace($number) -and -not [string]::IsNullOrWhiteSpace($periodId)) {
            $map[$number] = $periodId
        }
    }
    return $map
}

function Resolve-UpgradeProjectPeriodIdValue {
    param(
        [object]$Value,
        [object]$PeriodNumber,
        [hashtable]$PeriodIdMap,
        [hashtable]$OutputPeriodIdByNumber
    )

    $oldPeriodId = ConvertTo-BuilderText $Value
    if (-not [string]::IsNullOrWhiteSpace($oldPeriodId)) {
        $oldKey = $oldPeriodId.ToLowerInvariant()
        if ($PeriodIdMap.ContainsKey($oldKey)) {
            return [guid]([regex]::Match((ConvertTo-BuilderText $PeriodIdMap[$oldKey]), "[0-9A-Fa-f-]{36}").Value)
        }
    }

    $periodNumberText = ConvertTo-BuilderText $PeriodNumber
    if (-not [string]::IsNullOrWhiteSpace($periodNumberText) -and $OutputPeriodIdByNumber.ContainsKey($periodNumberText)) {
        return [guid]([regex]::Match((ConvertTo-BuilderText $OutputPeriodIdByNumber[$periodNumberText]), "[0-9A-Fa-f-]{36}").Value)
    }

    if ($null -eq $Value -or $Value -is [System.DBNull]) { return [DBNull]::Value }
    return $Value
}

function ConvertTo-UpgradeImportValue {
    param(
        [object]$Value,
        [string]$ColumnName,
        [string]$ProjectId,
        [hashtable]$PeriodIdMap
    )

    $column = ConvertTo-BuilderText $ColumnName
    if ([string]::Equals($column, "ProjectID", [System.StringComparison]::OrdinalIgnoreCase)) {
        return [guid]([regex]::Match((ConvertTo-BuilderText $ProjectId), "[0-9A-Fa-f-]{36}").Value)
    }
    if ([string]::Equals($column, "ProjectPeriodID", [System.StringComparison]::OrdinalIgnoreCase)) {
        $oldPeriodId = ConvertTo-BuilderText $Value
        if (-not [string]::IsNullOrWhiteSpace($oldPeriodId)) {
            $key = $oldPeriodId.ToLowerInvariant()
            if ($PeriodIdMap.ContainsKey($key)) {
                return [guid]([regex]::Match((ConvertTo-BuilderText $PeriodIdMap[$key]), "[0-9A-Fa-f-]{36}").Value)
            }
        }
    }
    if ($null -eq $Value -or $Value -is [System.DBNull]) { return [DBNull]::Value }
    return $Value
}

function New-EmptyUpgradeImportDbParam {
    param([string]$DataType)

    $typeName = ConvertTo-BuilderText $DataType
    switch ($typeName) {
        "Guid" { return (New-DbParam "Guid" ([DBNull]::Value)) }
        "Byte" { return (New-DbParam "Integer" ([DBNull]::Value)) }
        "Short" { return (New-DbParam "Integer" ([DBNull]::Value)) }
        "Long" { return (New-DbParam "Integer" ([DBNull]::Value)) }
        "Integer" { return (New-DbParam "Integer" ([DBNull]::Value)) }
        "Single" { return (New-DbParam "Double" ([DBNull]::Value)) }
        "Double" { return (New-DbParam "Double" ([DBNull]::Value)) }
        "Currency" { return (New-DbParam "Double" ([DBNull]::Value)) }
        "DateTime" { return (New-DbParam "Date" ([DBNull]::Value)) }
        "Date" { return (New-DbParam "Date" ([DBNull]::Value)) }
        "Boolean" { return (New-DbParam "Boolean" ([DBNull]::Value)) }
        "Memo" { return (New-DbParam "LongText" ([DBNull]::Value)) }
        "LongText" { return (New-DbParam "LongText" ([DBNull]::Value)) }
        "Long Text" { return (New-DbParam "LongText" ([DBNull]::Value)) }
        default { return (New-DbParam "Text" ([DBNull]::Value)) }
    }
}

function New-UpgradeImportDbParam {
    param(
        [object]$Value,
        [string]$ColumnName,
        [string]$ProjectId,
        [hashtable]$PeriodIdMap,
        [string]$DataType
    )

    $resolvedValue = ConvertTo-UpgradeImportValue -Value $Value -ColumnName $ColumnName -ProjectId $ProjectId -PeriodIdMap $PeriodIdMap
    $typeName = ConvertTo-BuilderText $DataType
    if ($null -eq $resolvedValue -or $resolvedValue -is [System.DBNull]) {
        return (New-EmptyUpgradeImportDbParam -DataType $typeName)
    }

    switch ($typeName) {
        "Guid" { return (DbGuid $resolvedValue) }
        "Byte" { return (DbInt $resolvedValue) }
        "Short" { return (DbInt $resolvedValue) }
        "Long" { return (DbInt $resolvedValue) }
        "Integer" { return (DbInt $resolvedValue) }
        "Single" { return (DbDouble $resolvedValue) }
        "Double" { return (DbDouble $resolvedValue) }
        "Currency" { return (DbDouble $resolvedValue) }
        "DateTime" { return (DbDate $resolvedValue) }
        "Date" { return (DbDate $resolvedValue) }
        "Boolean" { return (DbBool $resolvedValue) }
        "Memo" { return (DbLongText $resolvedValue) }
        "LongText" { return (DbLongText $resolvedValue) }
        "Long Text" { return (DbLongText $resolvedValue) }
        default { return (DbText $resolvedValue) }
    }
}

function Test-UpgradeImportBlankValue {
    param([object]$Value)

    if ($null -eq $Value -or $Value -is [System.DBNull]) { return $true }
    return [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Value))
}

function Get-UpgradeImportRowKeyColumns {
    param(
        [string]$TableName,
        [string[]]$Columns
    )

    $preferred = switch ((ConvertTo-BuilderText $TableName).ToLowerInvariant()) {
        "plots" { @("PlotID"); break }
        "trees" { @("TreeID"); break }
        "plotmeasurements" { @("MeasurementID"); break }
        "plotcustommeasurements" { @("MeasurementID"); break }
        "treemeasurements" { @("MeasurementID"); break }
        "treecustommeasurements" { @("MeasurementID"); break }
        "regenmeasurements" { @("MeasurementID"); break }
        "regencustommeasurements" { @("MeasurementID"); break }
        "inventorycrews" { @("ID"); break }
        "inventoryassignments" { @("ID"); break }
        "inventoryassignmentplots" { @("ID"); break }
        "inventoryassignmenttrees" { @("ID"); break }
        default { @("ID") }
    }

    $available = New-CaseInsensitiveColumnLookup $Columns
    $keys = New-Object System.Collections.Generic.List[string]
    foreach ($columnName in @($preferred)) {
        $actual = Get-ColumnLookupValue -Lookup $available -ColumnName $columnName
        if (-not [string]::IsNullOrWhiteSpace($actual)) { [void]$keys.Add($actual) }
    }
    return [string[]]$keys.ToArray()
}

function Get-UpgradeImportCarryColumns {
    param(
        [string]$TableName,
        [string[]]$Columns
    )

    $preferred = switch ((ConvertTo-BuilderText $TableName).ToLowerInvariant()) {
        "plots" { @("PlotID", "ProjectID", "PlotNumber", "PlotLabel", "PlotTypeID", "PlotKey"); break }
        "trees" { @("TreeID", "ProjectID", "PlotID", "PlotKey", "TreeKey", "TreeNumber"); break }
        "plotmeasurements" { @("MeasurementID", "PlotID", "ProjectID", "ProjectPeriodID", "PeriodNumber", "PlotKey", "PlotMeasKey"); break }
        "plotcustommeasurements" { @("MeasurementID", "PlotMeasKey"); break }
        "treemeasurements" { @("MeasurementID", "TreeID", "ProjectID", "ProjectPeriodID", "PeriodNumber", "TreeKey", "TreeMeasKey"); break }
        "treecustommeasurements" { @("MeasurementID", "TreeMeasKey"); break }
        "regenmeasurements" { @("MeasurementID", "PlotID", "ProjectID", "ProjectPeriodID", "PeriodNumber", "PlotNumber", "RegenMeasKey"); break }
        "regencustommeasurements" { @("MeasurementID", "RegenMeasKey"); break }
        "inventorycrews" { @("ID", "ProjectPeriodID", "ShortName"); break }
        "inventoryassignments" { @("ID", "ProjectPeriodID", "CrewID"); break }
        "inventoryassignmentplots" { @("ID", "AssignmentID", "PlotID"); break }
        "inventoryassignmenttrees" { @("ID", "InventoryAssignmentPlotID", "TreeID"); break }
        default { @("ID") }
    }

    $available = New-CaseInsensitiveColumnLookup $Columns
    $carry = New-Object System.Collections.Generic.List[string]
    foreach ($columnName in @($preferred)) {
        $actual = Get-ColumnLookupValue -Lookup $available -ColumnName $columnName
        if (-not [string]::IsNullOrWhiteSpace($actual) -and -not $carry.Contains($actual)) {
            [void]$carry.Add($actual)
        }
    }
    return [string[]]$carry.ToArray()
}

function ConvertTo-UpgradeSqlLiteral {
    param(
        [object]$Value,
        [string]$DataType
    )

    if ($null -eq $Value -or $Value -is [System.DBNull]) { return "Null" }
    switch ((ConvertTo-BuilderText $DataType)) {
        "Guid" { return (Sql-Guid $Value) }
        "Byte" { return (Sql-Number $Value) }
        "Short" { return (Sql-Number $Value) }
        "Long" { return (Sql-Number $Value) }
        "Integer" { return (Sql-Number $Value) }
        "Single" { return (Sql-Number $Value) }
        "Double" { return (Sql-Number $Value) }
        "Currency" { return (Sql-Number $Value) }
        "DateTime" { return (Sql-DateTime $Value) }
        "Date" { return (Sql-DateTime $Value) }
        "Boolean" { return (Sql-Bool $Value) }
        default { return (Sql-Text $Value) }
    }
}

function Get-UpgradeImportWhereClause {
    param(
        [string[]]$KeyColumns,
        [hashtable]$ValuesByColumn,
        [hashtable]$TargetDataTypes
    )

    $parts = New-Object System.Collections.Generic.List[string]
    foreach ($keyColumn in @($KeyColumns)) {
        if (-not $ValuesByColumn.ContainsKey($keyColumn)) { continue }
        $value = $ValuesByColumn[$keyColumn]
        if (Test-UpgradeImportBlankValue -Value $value) { continue }
        $dataType = Get-UpgradeTargetDataType -DataTypeLookup $TargetDataTypes -ColumnName $keyColumn
        [void]$parts.Add("$(Quote-Name $keyColumn) = $(ConvertTo-UpgradeSqlLiteral -Value $value -DataType $dataType)")
    }
    if ($parts.Count -eq 0) { return "" }
    return "WHERE " + [string]::Join(" AND ", [string[]]$parts.ToArray())
}

function Get-UpgradeImportRowLabel {
    param(
        [string]$TableName,
        [hashtable]$ValuesByColumn
    )

    $parts = New-Object System.Collections.Generic.List[string]
    foreach ($columnName in @("PeriodNumber", "PlotNumber", "PlotMeasKey", "TreeMeasKey", "RegenMeasKey", "MeasurementID", "TreeID", "PlotID", "ID")) {
        if (-not $ValuesByColumn.ContainsKey($columnName)) { continue }
        $value = ConvertTo-BuilderText $ValuesByColumn[$columnName]
        if ([string]::IsNullOrWhiteSpace($value)) { continue }
        [void]$parts.Add("${columnName}=$value")
        if ($parts.Count -ge 4) { break }
    }
    if ($parts.Count -eq 0) { return $TableName }
    return "$TableName ($([string]::Join(', ', [string[]]$parts.ToArray())))"
}

function Invoke-UpgradeRecoverableRowInsert {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName,
        [string[]]$Columns,
        [hashtable]$ValuesByColumn,
        [hashtable]$TargetDataTypes,
        [string]$ProjectId,
        [hashtable]$PeriodIdMap,
        [scriptblock]$Log
    )

    $keyColumns = @(Get-UpgradeImportRowKeyColumns -TableName $TableName -Columns $Columns | Where-Object {
        $ValuesByColumn.ContainsKey($_) -and -not (Test-UpgradeImportBlankValue -Value $ValuesByColumn[$_])
    })
    if ($keyColumns.Count -eq 0) { return $false }

    $whereClause = Get-UpgradeImportWhereClause -KeyColumns ([string[]]$keyColumns) -ValuesByColumn $ValuesByColumn -TargetDataTypes $TargetDataTypes
    if ([string]::IsNullOrWhiteSpace($whereClause)) { return $false }
    $rowLabel = Get-UpgradeImportRowLabel -TableName $TableName -ValuesByColumn $ValuesByColumn

    $rowExists = $false
    try {
        $rowExists = ([int](Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM $(Quote-Name $TableName) $whereClause") -gt 0)
    }
    catch {
        return $false
    }

    if (-not $rowExists) {
        $insertColumns = New-Object System.Collections.Generic.List[string]
        foreach ($columnName in @(Get-UpgradeImportCarryColumns -TableName $TableName -Columns $Columns)) {
            if (-not $ValuesByColumn.ContainsKey($columnName)) { continue }
            if (-not $insertColumns.Contains($columnName)) { [void]$insertColumns.Add($columnName) }
        }
        foreach ($columnName in @($keyColumns)) {
            if (-not $insertColumns.Contains($columnName)) { [void]$insertColumns.Insert(0, $columnName) }
        }

        if ($insertColumns.Count -eq 0) { return $false }
        $usableInsertColumns = New-Object System.Collections.Generic.List[string]
        $insertParameters = New-Object System.Collections.Generic.List[object]
        foreach ($columnName in @($insertColumns)) {
            try {
                $dataType = Get-UpgradeTargetDataType -DataTypeLookup $TargetDataTypes -ColumnName $columnName
                [void]$insertParameters.Add((New-UpgradeImportDbParam -Value $ValuesByColumn[$columnName] -ColumnName $columnName -ProjectId $ProjectId -PeriodIdMap $PeriodIdMap -DataType $dataType))
                [void]$usableInsertColumns.Add($columnName)
            }
            catch {
                if ($keyColumns -contains $columnName) { return $false }
                if ($Log) { & $Log "Upgrade import recovery skipped carry field ${rowLabel}.$columnName because it could not be converted: $($_.Exception.Message)" }
            }
        }
        if ($usableInsertColumns.Count -eq 0) { return $false }

        $columnSql = [string]::Join(", ", [string[]]($usableInsertColumns | ForEach-Object { Quote-Name $_ }))
        $placeholders = [string]::Join(", ", [string[]]($usableInsertColumns | ForEach-Object { "?" }))
        $insertSql = "INSERT INTO $(Quote-Name $TableName) ($columnSql) VALUES ($placeholders)"
        try {
            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql $insertSql -Parameters @($insertParameters.ToArray()))
            $rowExists = $true
        }
        catch {
            return $false
        }
    }

    $updatedFields = 0
    $skippedFields = New-Object System.Collections.Generic.List[string]
    foreach ($columnName in @($Columns)) {
        if ($keyColumns -contains $columnName) { continue }
        if (-not $ValuesByColumn.ContainsKey($columnName)) { continue }
        try {
            $dataType = Get-UpgradeTargetDataType -DataTypeLookup $TargetDataTypes -ColumnName $columnName
            $updateSql = "UPDATE $(Quote-Name $TableName) SET $(Quote-Name $columnName) = ? $whereClause"
            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql $updateSql -Parameters @(
                (New-UpgradeImportDbParam -Value $ValuesByColumn[$columnName] -ColumnName $columnName -ProjectId $ProjectId -PeriodIdMap $PeriodIdMap -DataType $dataType)
            ))
            $updatedFields++
        }
        catch {
            [void]$skippedFields.Add("$columnName ($($_.Exception.Message))")
        }
    }

    if ($Log) {
        if ($skippedFields.Count -gt 0) {
            & $Log "Upgrade import recovered $rowLabel but skipped field(s): $([string]::Join('; ', [string[]]$skippedFields.ToArray()))"
        }
        else {
            & $Log "Upgrade import recovered $rowLabel by copying fields one at a time."
        }
    }
    return $true
}

function Test-BuilderGuidValue {
    param([object]$Value)

    $text = ConvertTo-BuilderText $Value
    if ([string]::IsNullOrWhiteSpace($text)) { return $false }
    return [regex]::IsMatch($text, "[0-9A-Fa-f]{8}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{12}")
}

function Get-UpgradeRepairIntegerFromRow {
    param(
        [System.Data.DataRow]$Row,
        [string[]]$ColumnNames,
        [string[]]$KeyColumnNames = @()
    )

    foreach ($columnName in @($ColumnNames)) {
        $text = Get-DataRowText -Row $Row -ColumnNames @($columnName)
        $number = 0
        if (-not [string]::IsNullOrWhiteSpace($text) -and [int]::TryParse($text, [ref]$number)) {
            return $number
        }
    }

    foreach ($columnName in @($KeyColumnNames)) {
        $text = Get-DataRowText -Row $Row -ColumnNames @($columnName)
        if ([string]::IsNullOrWhiteSpace($text)) { continue }
        $match = [regex]::Match($text, "(?i)P0*(\d+)")
        if (-not $match.Success) { $match = [regex]::Match($text, "^\D*0*(\d+)") }
        if ($match.Success) {
            $number = 0
            if ([int]::TryParse($match.Groups[1].Value, [ref]$number)) { return $number }
        }
    }

    return 0
}

function Test-UpgradeRepairTargetGuidExists {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName,
        [string]$ColumnName,
        [object]$Value
    )

    if (-not (Test-TableExists -Connection $Connection -TableName $TableName)) { return $false }
    if (-not (Test-ColumnExists -Connection $Connection -TableName $TableName -ColumnName $ColumnName)) { return $false }
    if (-not (Test-BuilderGuidValue -Value $Value)) { return $false }
    try {
        return ([int](Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM $(Quote-Name $TableName) WHERE $(Quote-Name $ColumnName) = $(Sql-Guid $Value)") -gt 0)
    }
    catch {
        return $false
    }
}

function Get-UpgradeRepairGuidLookup {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName,
        [string]$ColumnName
    )

    $lookup = @{}
    if (-not (Test-TableExists -Connection $Connection -TableName $TableName)) { return $lookup }
    if (-not (Test-ColumnExists -Connection $Connection -TableName $TableName -ColumnName $ColumnName)) { return $lookup }
    try {
        $rows = Get-DbTable -Connection $Connection -Sql "SELECT $(Quote-Name $ColumnName) FROM $(Quote-Name $TableName) WHERE $(Quote-Name $ColumnName) Is Not Null"
        foreach ($row in $rows.Rows) {
            $value = ConvertTo-BuilderText $row[$ColumnName]
            if ([string]::IsNullOrWhiteSpace($value)) { continue }
            $key = $value.ToLowerInvariant()
            if (-not $lookup.ContainsKey($key)) { $lookup[$key] = $true }
        }
    }
    catch {
    }
    return $lookup
}

function Test-UpgradeRepairGuidLookupContains {
    param(
        [hashtable]$Lookup,
        [object]$Value
    )

    if ($null -eq $Lookup) { return $false }
    $text = ConvertTo-BuilderText $Value
    if ([string]::IsNullOrWhiteSpace($text)) { return $false }
    return $Lookup.ContainsKey($text.ToLowerInvariant())
}

function Add-UpgradeRepairGuidLookupValue {
    param(
        [hashtable]$Lookup,
        [object]$Value
    )

    if ($null -eq $Lookup) { return }
    $text = ConvertTo-BuilderText $Value
    if ([string]::IsNullOrWhiteSpace($text)) { return }
    $key = $text.ToLowerInvariant()
    if (-not $Lookup.ContainsKey($key)) { $Lookup[$key] = $true }
}

function Test-UpgradeRepairSourceMeasurementImported {
    param(
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [string]$TargetMeasurementTableName,
        [System.Data.DataRow]$SourceRow,
        [hashtable]$ImportedMeasurementIds = $null
    )

    if (-not (Test-TableExists -Connection $TargetConnection -TableName $TargetMeasurementTableName)) { return $false }
    if (-not (Test-ColumnExists -Connection $TargetConnection -TableName $TargetMeasurementTableName -ColumnName "MeasurementID")) { return $true }
    $measurementId = Get-DataRowText -Row $SourceRow -ColumnNames @("MeasurementID")
    if (-not (Test-BuilderGuidValue -Value $measurementId)) { return $true }
    if ($null -ne $ImportedMeasurementIds) { return (Test-UpgradeRepairGuidLookupContains -Lookup $ImportedMeasurementIds -Value $measurementId) }
    return (Test-UpgradeRepairTargetGuidExists -Connection $TargetConnection -TableName $TargetMeasurementTableName -ColumnName "MeasurementID" -Value $measurementId)
}

function Add-UpgradeRepairRow {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName,
        [System.Collections.IDictionary]$Values,
        [string]$ProjectId
    )

    if (-not (Test-TableExists -Connection $Connection -TableName $TableName)) { return $false }
    $columnInfo = @(Get-TableColumnInfo -Connection $Connection -TableName $TableName)
    $columnLookup = New-CaseInsensitiveColumnLookup @($columnInfo | ForEach-Object { $_.ColumnName })
    $dataTypes = Get-UpgradeTargetDataTypeLookup -Connection $Connection -TableName $TableName
    $insertColumns = New-Object System.Collections.Generic.List[string]
    $parameters = New-Object System.Collections.Generic.List[object]

    foreach ($key in @($Values.Keys)) {
        $actualColumn = Get-ColumnLookupValue -Lookup $columnLookup -ColumnName (ConvertTo-BuilderText $key)
        if ([string]::IsNullOrWhiteSpace($actualColumn)) { continue }
        if ($insertColumns.Contains($actualColumn)) { continue }
        $value = $Values[$key]
        if (Test-UpgradeImportBlankValue -Value $value) { continue }
        $dataType = Get-UpgradeTargetDataType -DataTypeLookup $dataTypes -ColumnName $actualColumn
        [void]$insertColumns.Add($actualColumn)
        [void]$parameters.Add((New-UpgradeImportDbParam -Value $value -ColumnName $actualColumn -ProjectId $ProjectId -PeriodIdMap @{} -DataType $dataType))
    }

    if ($insertColumns.Count -eq 0) { return $false }
    $columnSql = [string]::Join(", ", [string[]]($insertColumns | ForEach-Object { Quote-Name $_ }))
    $placeholders = [string]::Join(", ", [string[]]($insertColumns | ForEach-Object { "?" }))
    $insertSql = "INSERT INTO $(Quote-Name $TableName) ($columnSql) VALUES ($placeholders)"
    [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql $insertSql -Parameters @($parameters.ToArray()))
    return $true
}

function Add-UpgradeMissingPlotFromRow {
    param(
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [string]$SourceTableName,
        [System.Data.DataRow]$SourceRow,
        [string]$ProjectId,
        [scriptblock]$Log,
        [hashtable]$ExistingPlotIds = $null
    )

    if (-not (Test-TableExists -Connection $TargetConnection -TableName "Plots")) { return $false }
    $plotId = Get-DataRowText -Row $SourceRow -ColumnNames @("PlotID")
    if (-not (Test-BuilderGuidValue -Value $plotId)) { return $false }
    if ($null -ne $ExistingPlotIds) {
        if (Test-UpgradeRepairGuidLookupContains -Lookup $ExistingPlotIds -Value $plotId) { return $false }
    }
    elseif (Test-UpgradeRepairTargetGuidExists -Connection $TargetConnection -TableName "Plots" -ColumnName "PlotID" -Value $plotId) { return $false }

    $plotNumber = Get-UpgradeRepairIntegerFromRow -Row $SourceRow -ColumnNames @("PlotNumber", "Plot", "PlotNo", "PlotIDNumber", "TreePlotNumber", "RegenPlotNumber") -KeyColumnNames @("PlotKey", "PlotMeasKey", "TreeMeasKey", "RegenMeasKey")
    $plotKey = Get-DataRowText -Row $SourceRow -ColumnNames @("PlotKey")
    if ([string]::IsNullOrWhiteSpace($plotKey) -and $plotNumber -gt 0) { $plotKey = New-PlotKey -PlotNumber $plotNumber }
    if ($plotNumber -le 0 -or [string]::IsNullOrWhiteSpace($plotKey)) {
        if ($Log) {
            $measurementId = Get-DataRowText -Row $SourceRow -ColumnNames @("MeasurementID")
            & $Log "Upgrade repair skipped missing Plots row from ${SourceTableName}: PlotID=$plotId, MeasurementID=$measurementId. Project Pickle needs PlotID plus PlotNumber or PlotKey to rebuild the parent plot row."
        }
        return $false
    }

    $now = Get-Date
    $values = [ordered]@{
        PlotID = $plotId
        ProjectID = $ProjectId
        PlotNumber = $plotNumber
        PlotLabel = ConvertTo-BuilderText $plotNumber
        PlotTypeID = 1
        PlotKey = $plotKey
        IsDeleted = $false
        Created = $now
        Updated = $now
        UpdUser = "Pickle"
        RetrievalID = 0
    }
    try {
        [void](Add-UpgradeRepairRow -Connection $TargetConnection -TableName "Plots" -Values $values -ProjectId $ProjectId)
    }
    catch {
        if ($Log) {
            $measurementId = Get-DataRowText -Row $SourceRow -ColumnNames @("MeasurementID")
            & $Log "Upgrade repair could not create missing Plots row from ${SourceTableName}: PlotID=$plotId, MeasurementID=$measurementId. Access reported: $($_.Exception.Message)"
        }
        return $false
    }
    if ($Log) {
        $measurementId = Get-DataRowText -Row $SourceRow -ColumnNames @("MeasurementID")
        & $Log "Upgrade repair created missing Plots row from ${SourceTableName}: PlotID=$plotId, PlotNumber=$plotNumber, PlotKey=$plotKey, MeasurementID=$measurementId, UpdUser=Pickle."
    }
    Add-UpgradeRepairGuidLookupValue -Lookup $ExistingPlotIds -Value $plotId
    return $true
}

function Repair-UpgradeMissingPlotsFromMeasurementTable {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [string]$SourceTableName,
        [string]$ProjectId,
        [scriptblock]$Log,
        [hashtable]$ExistingPlotIds = $null
    )

    if (-not (Test-TableExists -Connection $SourceConnection -TableName $SourceTableName)) { return 0 }
    if (-not (Test-ColumnExists -Connection $SourceConnection -TableName $SourceTableName -ColumnName "PlotID")) { return 0 }
    if ($null -eq $ExistingPlotIds) { $ExistingPlotIds = Get-UpgradeRepairGuidLookup -Connection $TargetConnection -TableName "Plots" -ColumnName "PlotID" }
    $importedMeasurementIds = Get-UpgradeRepairGuidLookup -Connection $TargetConnection -TableName $SourceTableName -ColumnName "MeasurementID"
    $rows = Get-DbTable -Connection $SourceConnection -Sql "SELECT * FROM $(Quote-Name $SourceTableName)"
    $created = 0
    $processed = 0
    if ($Log) { & $Log "Upgrade repair: checking $($rows.Rows.Count) $SourceTableName row(s) for missing parent Plots rows." }
    foreach ($row in $rows.Rows) {
        if (-not (Test-UpgradeRepairSourceMeasurementImported -TargetConnection $TargetConnection -TargetMeasurementTableName $SourceTableName -SourceRow $row -ImportedMeasurementIds $importedMeasurementIds)) {
            $processed++
            continue
        }
        if (Add-UpgradeMissingPlotFromRow -TargetConnection $TargetConnection -SourceTableName $SourceTableName -SourceRow $row -ProjectId $ProjectId -Log $Log -ExistingPlotIds $ExistingPlotIds) {
            $created++
        }
        $processed++
        if (($processed % 500) -eq 0 -and $Log) {
            & $Log "Upgrade repair still checking $SourceTableName for missing Plots rows: $processed of $($rows.Rows.Count) row(s), $created created."
        }
    }
    if ($Log) { & $Log "Upgrade repair checked $SourceTableName for missing Plots rows: $processed row(s), $created created." }
    return $created
}

function Repair-UpgradeMissingTreesFromTreeMeasurements {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [string]$ProjectId,
        [scriptblock]$Log,
        [hashtable]$ExistingPlotIds = $null,
        [hashtable]$ExistingTreeIds = $null
    )

    if (-not (Test-TableExists -Connection $SourceConnection -TableName "TreeMeasurements")) { return 0 }
    if (-not (Test-TableExists -Connection $TargetConnection -TableName "Trees")) { return 0 }
    if (-not (Test-ColumnExists -Connection $SourceConnection -TableName "TreeMeasurements" -ColumnName "TreeID")) { return 0 }

    if ($null -eq $ExistingPlotIds) { $ExistingPlotIds = Get-UpgradeRepairGuidLookup -Connection $TargetConnection -TableName "Plots" -ColumnName "PlotID" }
    if ($null -eq $ExistingTreeIds) { $ExistingTreeIds = Get-UpgradeRepairGuidLookup -Connection $TargetConnection -TableName "Trees" -ColumnName "TreeID" }
    $importedMeasurementIds = Get-UpgradeRepairGuidLookup -Connection $TargetConnection -TableName "TreeMeasurements" -ColumnName "MeasurementID"
    $rows = Get-DbTable -Connection $SourceConnection -Sql "SELECT * FROM [TreeMeasurements]"
    $created = 0
    $processed = 0
    if ($Log) { & $Log "Upgrade repair: checking $($rows.Rows.Count) TreeMeasurements row(s) for missing parent Trees rows." }
    foreach ($row in $rows.Rows) {
        if (-not (Test-UpgradeRepairSourceMeasurementImported -TargetConnection $TargetConnection -TargetMeasurementTableName "TreeMeasurements" -SourceRow $row -ImportedMeasurementIds $importedMeasurementIds)) {
            $processed++
            continue
        }
        $treeId = Get-DataRowText -Row $row -ColumnNames @("TreeID")
        if (-not (Test-BuilderGuidValue -Value $treeId)) {
            $processed++
            continue
        }
        if (Test-UpgradeRepairGuidLookupContains -Lookup $ExistingTreeIds -Value $treeId) {
            $processed++
            continue
        }

        $measurementId = Get-DataRowText -Row $row -ColumnNames @("MeasurementID")
        $plotId = Get-DataRowText -Row $row -ColumnNames @("PlotID")
        $plotKey = Get-DataRowText -Row $row -ColumnNames @("PlotKey")
        $treeKey = Get-DataRowText -Row $row -ColumnNames @("TreeKey")
        $treeNumber = Get-UpgradeRepairIntegerFromRow -Row $row -ColumnNames @("TreeNumber", "Tree", "TreeNo", "TreeNum") -KeyColumnNames @()

        if (-not (Test-BuilderGuidValue -Value $plotId) -or [string]::IsNullOrWhiteSpace($plotKey) -or [string]::IsNullOrWhiteSpace($treeKey) -or $treeNumber -le 0) {
            if ($Log) {
                & $Log "Upgrade repair skipped missing Trees row: TreeID=$treeId, MeasurementID=$measurementId. Project Pickle needs TreeID, TreeKey, PlotID, PlotKey, and TreeNumber to rebuild the parent tree row."
            }
            $processed++
            continue
        }

        if (-not (Test-UpgradeRepairGuidLookupContains -Lookup $ExistingPlotIds -Value $plotId)) {
            [void](Add-UpgradeMissingPlotFromRow -TargetConnection $TargetConnection -SourceTableName "TreeMeasurements" -SourceRow $row -ProjectId $ProjectId -Log $Log -ExistingPlotIds $ExistingPlotIds)
        }
        if (-not (Test-UpgradeRepairGuidLookupContains -Lookup $ExistingPlotIds -Value $plotId)) {
            if ($Log) {
                & $Log "Upgrade repair skipped missing Trees row: TreeID=$treeId, MeasurementID=$measurementId because the parent PlotID=$plotId could not be rebuilt."
            }
            $processed++
            continue
        }

        $now = Get-Date
        $values = [ordered]@{
            TreeID = $treeId
            ProjectID = $ProjectId
            PlotID = $plotId
            PlotKey = $plotKey
            TreeKey = $treeKey
            TreeNumber = $treeNumber
            IsDeleted = $false
            Created = $now
            Updated = $now
            UpdUser = "Pickle"
            RetrievalID = 0
        }
        try {
            [void](Add-UpgradeRepairRow -Connection $TargetConnection -TableName "Trees" -Values $values -ProjectId $ProjectId)
        }
        catch {
            if ($Log) {
                & $Log "Upgrade repair could not create missing Trees row: TreeID=$treeId, MeasurementID=$measurementId. Access reported: $($_.Exception.Message)"
            }
            continue
        }
        $created++
        Add-UpgradeRepairGuidLookupValue -Lookup $ExistingTreeIds -Value $treeId
        if ($Log) {
            & $Log "Upgrade repair created missing Trees row: TreeID=$treeId, TreeKey=$treeKey, TreeNumber=$treeNumber, PlotID=$plotId, MeasurementID=$measurementId, UpdUser=Pickle."
        }
        $processed++
        if (($processed % 500) -eq 0 -and $Log) {
            & $Log "Upgrade repair still checking TreeMeasurements for missing Trees rows: $processed of $($rows.Rows.Count) row(s), $created created."
        }
    }
    if ($Log) { & $Log "Upgrade repair checked TreeMeasurements for missing Trees rows: $processed row(s), $created created." }
    return $created
}

function Repair-UpgradeMissingCustomMeasurementRows {
    param(
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [string]$MeasurementTableName,
        [string]$CustomTableName,
        [string]$MeasurementKeyColumn,
        [string]$ProjectId,
        [scriptblock]$Log
    )

    if (-not (Test-TableExists -Connection $TargetConnection -TableName $MeasurementTableName)) { return 0 }
    if (-not (Test-TableExists -Connection $TargetConnection -TableName $CustomTableName)) { return 0 }
    if (-not (Test-ColumnExists -Connection $TargetConnection -TableName $MeasurementTableName -ColumnName "MeasurementID")) { return 0 }
    if (-not (Test-ColumnExists -Connection $TargetConnection -TableName $CustomTableName -ColumnName "MeasurementID")) { return 0 }

    $existingCustomMeasurementIds = Get-UpgradeRepairGuidLookup -Connection $TargetConnection -TableName $CustomTableName -ColumnName "MeasurementID"
    $rows = Get-DbTable -Connection $TargetConnection -Sql "SELECT * FROM $(Quote-Name $MeasurementTableName)"
    $created = 0
    $processed = 0
    if ($Log) { & $Log "Upgrade repair: checking $($rows.Rows.Count) $MeasurementTableName row(s) for matching $CustomTableName rows." }
    foreach ($row in $rows.Rows) {
        $measurementId = Get-DataRowText -Row $row -ColumnNames @("MeasurementID")
        if (-not (Test-BuilderGuidValue -Value $measurementId)) {
            $processed++
            continue
        }
        if (Test-UpgradeRepairGuidLookupContains -Lookup $existingCustomMeasurementIds -Value $measurementId) {
            $processed++
            continue
        }

        $now = Get-Date
        $values = [ordered]@{
            MeasurementID = $measurementId
            Created = $now
            Updated = $now
            UpdUser = "Pickle"
            RetrievalID = 0
        }
        $measurementKey = Get-DataRowText -Row $row -ColumnNames @($MeasurementKeyColumn)
        if (-not [string]::IsNullOrWhiteSpace($measurementKey)) {
            $values[$MeasurementKeyColumn] = $measurementKey
        }
        try {
            [void](Add-UpgradeRepairRow -Connection $TargetConnection -TableName $CustomTableName -Values $values -ProjectId $ProjectId)
        }
        catch {
            if ($Log) {
                & $Log "Upgrade repair could not create missing ${CustomTableName} row: MeasurementID=$measurementId. Access reported: $($_.Exception.Message)"
            }
            continue
        }
        $created++
        Add-UpgradeRepairGuidLookupValue -Lookup $existingCustomMeasurementIds -Value $measurementId
        if ($Log) {
            & $Log "Upgrade repair created missing ${CustomTableName} row: MeasurementID=$measurementId, $MeasurementKeyColumn=$measurementKey, UpdUser=Pickle."
        }
        $processed++
        if (($processed % 500) -eq 0 -and $Log) {
            & $Log "Upgrade repair still checking $MeasurementTableName -> ${CustomTableName}: $processed of $($rows.Rows.Count) row(s), $created created."
        }
    }
    if ($Log) { & $Log "Upgrade repair checked $MeasurementTableName -> ${CustomTableName}: $processed row(s), $created created." }
    return $created
}

function Invoke-UpgradeRepairMissingInventoryRows {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [string]$ProjectId,
        [scriptblock]$Log
    )

    if ($Log) { & $Log "Upgrade repair: checking for measurement rows whose parent inventory rows are missing." }
    $repairTimer = [System.Diagnostics.Stopwatch]::StartNew()
    $existingPlotIds = Get-UpgradeRepairGuidLookup -Connection $TargetConnection -TableName "Plots" -ColumnName "PlotID"
    $existingTreeIds = Get-UpgradeRepairGuidLookup -Connection $TargetConnection -TableName "Trees" -ColumnName "TreeID"
    $plotRepairCount = 0
    foreach ($sourceTableName in @("PlotMeasurements", "RegenMeasurements", "TreeMeasurements")) {
        $plotRepairCount += Repair-UpgradeMissingPlotsFromMeasurementTable -SourceConnection $SourceConnection -TargetConnection $TargetConnection -SourceTableName $sourceTableName -ProjectId $ProjectId -Log $Log -ExistingPlotIds $existingPlotIds
    }
    $treeRepairCount = Repair-UpgradeMissingTreesFromTreeMeasurements -SourceConnection $SourceConnection -TargetConnection $TargetConnection -ProjectId $ProjectId -Log $Log -ExistingPlotIds $existingPlotIds -ExistingTreeIds $existingTreeIds
    $customRepairCount = 0
    $customRepairCount += Repair-UpgradeMissingCustomMeasurementRows -TargetConnection $TargetConnection -MeasurementTableName "PlotMeasurements" -CustomTableName "PlotCustomMeasurements" -MeasurementKeyColumn "PlotMeasKey" -ProjectId $ProjectId -Log $Log
    $customRepairCount += Repair-UpgradeMissingCustomMeasurementRows -TargetConnection $TargetConnection -MeasurementTableName "TreeMeasurements" -CustomTableName "TreeCustomMeasurements" -MeasurementKeyColumn "TreeMeasKey" -ProjectId $ProjectId -Log $Log
    $customRepairCount += Repair-UpgradeMissingCustomMeasurementRows -TargetConnection $TargetConnection -MeasurementTableName "RegenMeasurements" -CustomTableName "RegenCustomMeasurements" -MeasurementKeyColumn "RegenMeasKey" -ProjectId $ProjectId -Log $Log
    $repairTimer.Stop()
    if ($Log) {
        & $Log "Upgrade repair complete in $(Format-WOOFDuration -Seconds $repairTimer.Elapsed.TotalSeconds): created $plotRepairCount missing Plots row(s), $treeRepairCount missing Trees row(s), and $customRepairCount missing custom measurement row(s)."
    }
}

function New-CaseInsensitiveColumnLookup {
    param([string[]]$ColumnNames)

    $lookup = @{}
    foreach ($columnName in @($ColumnNames)) {
        $clean = ConvertTo-BuilderText $columnName
        if ([string]::IsNullOrWhiteSpace($clean)) { continue }
        $key = $clean.ToLowerInvariant()
        if (-not $lookup.ContainsKey($key)) { $lookup[$key] = $clean }
    }
    return $lookup
}

function Get-ColumnLookupValue {
    param(
        [hashtable]$Lookup,
        [string]$ColumnName
    )

    if ($null -eq $Lookup) { return "" }
    $clean = ConvertTo-BuilderText $ColumnName
    if ([string]::IsNullOrWhiteSpace($clean)) { return "" }
    $key = $clean.ToLowerInvariant()
    if ($Lookup.ContainsKey($key)) { return ConvertTo-BuilderText $Lookup[$key] }
    return ""
}

function Test-UpgradeMovedFieldExcluded {
    param([string]$FieldName)

    $clean = (ConvertTo-BuilderText $FieldName).ToLowerInvariant()
    if ([string]::IsNullOrWhiteSpace($clean)) { return $true }
    $excluded = @(
        "measurementid",
        "plotmeasid",
        "plotmeasurementid",
        "treemeasid",
        "treemeasurementid",
        "regenmeasid",
        "regenmeasurementid",
        "plotid",
        "plotkey",
        "plotmeaskey",
        "treeid",
        "treekey",
        "treemeaskey",
        "regenmeaskey",
        "projectid",
        "projectperiodid",
        "periodid",
        "periodnumber",
        "measurementperiodnumber",
        "created",
        "updated",
        "upduser",
        "retrievalid",
        "isdeleted",
        "fieldnamesampleremove",
        "needsreview"
    )
    return ($clean -in $excluded)
}

function ConvertTo-UpgradeFieldKey {
    param([string]$Text)

    $clean = ConvertTo-BuilderText $Text
    if ([string]::IsNullOrWhiteSpace($clean)) { return "" }
    return (($clean -replace "[^A-Za-z0-9]", "").ToLowerInvariant())
}

function Test-UpgradeMappingReviewFieldExcluded {
    param(
        [string]$TableName,
        [string]$FieldName
    )

    if (Test-UpgradeMovedFieldExcluded -FieldName $FieldName) { return $true }
    $fieldKey = ConvertTo-UpgradeFieldKey $FieldName
    if ([string]::IsNullOrWhiteSpace($fieldKey)) { return $true }
    if ($fieldKey -eq "needsreview") { return $true }

    $tableKey = ConvertTo-UpgradeFieldKey $TableName
    switch ($tableKey) {
        "plots" {
            return ($fieldKey -in @(
                "plotnumber",
                "plotlabel",
                "plottypeid",
                "plotkindid",
                "elevation",
                "compartment",
                "aspect",
                "utmnorthing",
                "utmnorthingcoordinate",
                "utmeasting",
                "utmeastingcoordinate",
                "utmzone",
                "peracreexpansion"
            ))
        }
        "plotmeasurements" {
            return ($fieldKey -in @(
                "plotnumber",
                "plotlabel",
                "plottypeid",
                "plotkindid",
                "elevation",
                "compartment",
                "aspect",
                "utmnorthing",
                "utmnorthingcoordinate",
                "utmeasting",
                "utmeastingcoordinate",
                "utmzone",
                "peracreexpansion",
                "plotstatus",
                "measurementdate",
                "crew"
            ))
        }
        "trees" {
            return ($fieldKey -in @(
                "treeplotnumber",
                "plotnumber",
                "treespeciescode",
                "speciescode",
                "treenumber"
            ))
        }
        "treemeasurements" {
            return ($fieldKey -in @(
                "treeplotnumber",
                "plotnumber",
                "treespeciescode",
                "speciescode",
                "treenumber",
                "minorplot",
                "treehistory",
                "idbh",
                "realdbh",
                "totalheight",
                "problem1",
                "severity1",
                "problem2",
                "severity2"
            ))
        }
        "regenmeasurements" {
            return ($fieldKey -in @(
                "regenplotnumber",
                "plotnumber",
                "regenminorplot",
                "minorplot",
                "regenspeciescode",
                "speciescode",
                "regenidbh",
                "idbh",
                "regenstemcount",
                "stemcount"
            ))
        }
    }
    return $false
}

function Get-UpgradeMeasurementTableSpecs {
    return @(
        [pscustomobject]@{ Domain = "Plot"; TableName = "Plots"; CustomTableName = ""; Key = "PlotID"; Carry = @("PlotID", "PlotKey") },
        [pscustomobject]@{ Domain = "Plot"; TableName = "PlotMeasurements"; CustomTableName = "PlotCustomMeasurements"; Key = "MeasurementID"; Carry = @("MeasurementID", "PlotMeasKey") },
        [pscustomobject]@{ Domain = "Plot"; TableName = "PlotCustomMeasurements"; CustomTableName = "PlotCustomMeasurements"; Key = "MeasurementID"; Carry = @("MeasurementID", "PlotMeasKey") },
        [pscustomobject]@{ Domain = "Tree"; TableName = "Trees"; CustomTableName = ""; Key = "TreeID"; Carry = @("TreeID", "TreeKey", "PlotID", "PlotKey") },
        [pscustomobject]@{ Domain = "Tree"; TableName = "TreeMeasurements"; CustomTableName = "TreeCustomMeasurements"; Key = "MeasurementID"; Carry = @("MeasurementID", "TreeMeasKey") },
        [pscustomobject]@{ Domain = "Tree"; TableName = "TreeCustomMeasurements"; CustomTableName = "TreeCustomMeasurements"; Key = "MeasurementID"; Carry = @("MeasurementID", "TreeMeasKey") },
        [pscustomobject]@{ Domain = "Regen"; TableName = "RegenMeasurements"; CustomTableName = "RegenCustomMeasurements"; Key = "MeasurementID"; Carry = @("MeasurementID", "RegenMeasKey") },
        [pscustomobject]@{ Domain = "Regen"; TableName = "RegenCustomMeasurements"; CustomTableName = "RegenCustomMeasurements"; Key = "MeasurementID"; Carry = @("MeasurementID", "RegenMeasKey") }
    )
}

function Get-UpgradeMeasurementTableSpec {
    param([string]$TableName)

    $clean = ConvertTo-BuilderText $TableName
    foreach ($spec in @(Get-UpgradeMeasurementTableSpecs)) {
        if ([string]::Equals((ConvertTo-BuilderText $spec.TableName), $clean, [System.StringComparison]::OrdinalIgnoreCase)) {
            return $spec
        }
    }
    return $null
}

function Test-UpgradeCustomMeasurementTable {
    param([string]$TableName)

    $clean = ConvertTo-BuilderText $TableName
    return $clean -in @("PlotCustomMeasurements", "TreeCustomMeasurements", "RegenCustomMeasurements")
}

function Test-UpgradeTableOnlyTargetTable {
    param([string]$TableName)

    $clean = ConvertTo-BuilderText $TableName
    if ([string]::IsNullOrWhiteSpace($clean)) { return $false }
    foreach ($spec in @(Get-UpgradeMeasurementTableSpecs)) {
        if ([string]::Equals((ConvertTo-BuilderText $spec.TableName), $clean, [System.StringComparison]::OrdinalIgnoreCase)) {
            return $true
        }
    }
    return $false
}

function Get-UpgradeColumnAliases {
    param(
        [string]$Domain,
        [string]$ColumnName
    )

    $cleanDomain = ConvertTo-BuilderText $Domain
    $cleanColumn = ConvertTo-BuilderText $ColumnName
    $aliases = New-Object System.Collections.Generic.List[string]
    $addAlias = {
        param([string]$Name)
        $text = ConvertTo-BuilderText $Name
        if ([string]::IsNullOrWhiteSpace($text)) { return }
        foreach ($existing in @($aliases.ToArray())) {
            if ([string]::Equals($existing, $text, [System.StringComparison]::OrdinalIgnoreCase)) { return }
        }
        [void]$aliases.Add($text)
    }

    & $addAlias $cleanColumn
    if ([string]::Equals($cleanColumn, "MeasurementID", [System.StringComparison]::OrdinalIgnoreCase)) {
        switch ($cleanDomain) {
            "Plot" {
                & $addAlias "PlotMeasID"
                & $addAlias "PlotMeasurementID"
            }
            "Tree" {
                & $addAlias "TreeMeasID"
                & $addAlias "TreeMeasurementID"
            }
            "Regen" {
                & $addAlias "RegenMeasID"
                & $addAlias "RegenMeasurementID"
            }
        }
    }
    elseif ($cleanColumn -in @("PlotMeasKey", "TreeMeasKey", "RegenMeasKey")) {
        switch ($cleanDomain) {
            "Plot" { & $addAlias "PlotMeasurementKey" }
            "Tree" { & $addAlias "TreeMeasurementKey" }
            "Regen" { & $addAlias "RegenMeasurementKey" }
        }
    }

    return [string[]]$aliases.ToArray()
}

function Get-UpgradeColumnLookupValueWithAliases {
    param(
        [hashtable]$Lookup,
        [string]$Domain,
        [string]$ColumnName
    )

    foreach ($alias in @(Get-UpgradeColumnAliases -Domain $Domain -ColumnName $ColumnName)) {
        $value = Get-ColumnLookupValue -Lookup $Lookup -ColumnName $alias
        if (-not [string]::IsNullOrWhiteSpace($value)) { return $value }
    }
    return ""
}

function Get-UpgradeRenamedFieldTarget {
    param(
        [string]$SourceTable,
        [string]$SourceField
    )

    $sourceTableKey = ConvertTo-UpgradeFieldKey $SourceTable
    $fieldKey = ConvertTo-UpgradeFieldKey $SourceField
    $targetTable = ""
    $targetField = ""

    switch ($sourceTableKey) {
        "plots" {
            if ($fieldKey -eq "habitattype") { $targetTable = "PlotMeasurements"; $targetField = "HabitatType" }
            elseif ($fieldKey -eq "fieldovercover") { $targetTable = "PlotMeasurements"; $targetField = "CoverType" }
            elseif ($fieldKey -eq "fieldoverdensity") { $targetTable = "PlotMeasurements"; $targetField = "DensityClass" }
            elseif ($fieldKey -eq "fieldoversize") { $targetTable = "PlotMeasurements"; $targetField = "SizeClass" }
            elseif ($fieldKey -eq "forestclassification") { $targetTable = "Plots"; $targetField = "FLCCommercial" }
        }
        "plotmeasurements" {
            if ($fieldKey -eq "plotremarks") { $targetTable = "PlotMeasurements"; $targetField = "RemarksPlot" }
            elseif ($fieldKey -eq "fieldovercover") { $targetTable = "PlotMeasurements"; $targetField = "CoverType" }
            elseif ($fieldKey -eq "fieldoverdensity") { $targetTable = "PlotMeasurements"; $targetField = "DensityClass" }
            elseif ($fieldKey -eq "fieldoversize") { $targetTable = "PlotMeasurements"; $targetField = "SizeClass" }
            elseif ($fieldKey -eq "forestclassification") { $targetTable = "Plots"; $targetField = "FLCCommercial" }
        }
        "treemeasurements" {
            if ($fieldKey -eq "treeremarks") { $targetTable = "TreeMeasurements"; $targetField = "RemarksTree" }
        }
        "regenmeasurements" {
            if ($fieldKey -eq "remarks") { $targetTable = "RegenMeasurements"; $targetField = "RemarksRegen" }
        }
    }

    if ([string]::IsNullOrWhiteSpace($targetTable) -or [string]::IsNullOrWhiteSpace($targetField)) { return $null }
    return [pscustomobject]@{
        TableName = $targetTable
        FieldName = $targetField
        TargetText = "$targetTable.$targetField"
    }
}

function Get-UpgradeMappingPreferredTableChoices {
    return @(
        "PlotCustomMeasurements",
        "TreeCustomMeasurements",
        "Plots",
        "Trees",
        "PlotMeasurements",
        "TreeMeasurements",
        "RegenCustomMeasurements",
        "RegenMeasurements"
    )
}

function Split-UpgradeMappingTargetChoice {
    param([string]$TargetChoice)

    $clean = ConvertTo-BuilderText $TargetChoice
    if ([string]::IsNullOrWhiteSpace($clean) -or [string]::Equals($clean, "Skip", [System.StringComparison]::OrdinalIgnoreCase)) {
        return $null
    }
    $dot = $clean.IndexOf(".")
    if ($dot -lt 0) {
        $targetSpec = Get-UpgradeMeasurementTableSpec -TableName $clean
        if ($null -ne $targetSpec -and (Test-UpgradeTableOnlyTargetTable -TableName $targetSpec.TableName)) {
            return [pscustomobject]@{
                TableName = ConvertTo-BuilderText $targetSpec.TableName
                FieldName = ""
                TableOnly = $true
            }
        }
        throw "Upgrade Mapping tab: target '$clean' must be a supported upgrade table, such as PlotCustomMeasurements, TreeCustomMeasurements, Plots, Trees, PlotMeasurements, or TreeMeasurements, or use Table.Field format."
    }
    if ($dot -lt 1 -or $dot -ge ($clean.Length - 1)) {
        throw "Upgrade Mapping tab: target '$clean' must use Table or Table.Field format, such as PlotCustomMeasurements or TreeCustomMeasurements.ExampleField, or choose Skip."
    }
    return [pscustomobject]@{
        TableName = $clean.Substring(0, $dot)
        FieldName = $clean.Substring($dot + 1)
        TableOnly = $false
    }
}

function Get-UpgradeMappingTargetChoices {
    param(
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [object[]]$CustomFields = @()
    )

    $choices = New-Object System.Collections.Generic.List[string]
    $seen = @{}
    $addTableChoice = {
        param([string]$TableName)

        $tableNameText = ConvertTo-BuilderText $TableName
        if ([string]::IsNullOrWhiteSpace($tableNameText)) { return }
        if (-not (Test-UpgradeTableOnlyTargetTable -TableName $tableNameText)) { return }
        $key = $tableNameText.ToLowerInvariant()
        if (-not $seen.ContainsKey($key)) {
            $seen[$key] = $true
            [void]$choices.Add($tableNameText)
        }
    }
    $addChoice = {
        param(
            [string]$TableName,
            [string]$FieldName
        )

        $tableNameText = ConvertTo-BuilderText $TableName
        $fieldNameText = ConvertTo-AccessFieldName $FieldName
        if ([string]::IsNullOrWhiteSpace($tableNameText) -or [string]::IsNullOrWhiteSpace($fieldNameText)) { return }
        if (Test-UpgradeMappingReviewFieldExcluded -TableName $tableNameText -FieldName $fieldNameText) { return }
        $targetSpec = Get-UpgradeMeasurementTableSpec -TableName $tableNameText
        if ($null -eq $targetSpec) { return }
        $choice = "$tableNameText.$fieldNameText"
        $key = $choice.ToLowerInvariant()
        if (-not $seen.ContainsKey($key)) {
            $seen[$key] = $true
            [void]$choices.Add($choice)
        }
    }

    foreach ($tableName in @(Get-UpgradeMappingPreferredTableChoices)) {
        if (Test-TableExists -Connection $TargetConnection -TableName $tableName) {
            & $addTableChoice $tableName
        }
    }
    foreach ($spec in @(Get-UpgradeMeasurementTableSpecs)) {
        if (-not (Test-TableExists -Connection $TargetConnection -TableName $spec.TableName)) { continue }
        & $addTableChoice $spec.TableName
        foreach ($columnName in @(Get-TableColumns -Connection $TargetConnection -TableName $spec.TableName)) {
            & $addChoice $spec.TableName $columnName
        }
    }
    foreach ($field in @($CustomFields)) {
        & $addChoice (ConvertTo-BuilderText $field.TableName) (ConvertTo-BuilderText $field.FieldName)
    }
    return [string[]](@("Skip") + @($choices.ToArray()))
}

function Get-UpgradeDefaultMappingTarget {
    param(
        [object]$SourceSpec,
        [string]$SourceField,
        [System.Data.OleDb.OleDbConnection]$TargetConnection
    )

    if ($null -eq $SourceSpec) { return "Skip" }
    $sourceTable = ConvertTo-BuilderText $SourceSpec.TableName
    if ([string]::IsNullOrWhiteSpace($sourceTable)) { return "Skip" }

    $renamedFieldTarget = Get-UpgradeRenamedFieldTarget -SourceTable $sourceTable -SourceField $SourceField
    $renamedTarget = if ($null -eq $renamedFieldTarget) { "" } else { ConvertTo-BuilderText $renamedFieldTarget.TargetText }
    if (-not [string]::IsNullOrWhiteSpace($renamedTarget)) {
        $target = Split-UpgradeMappingTargetChoice -TargetChoice $renamedTarget
        if ($null -ne $target -and
            (Test-TableExists -Connection $TargetConnection -TableName (ConvertTo-BuilderText $target.TableName)) -and
            (Test-ColumnExists -Connection $TargetConnection -TableName (ConvertTo-BuilderText $target.TableName) -ColumnName (ConvertTo-BuilderText $target.FieldName))) {
            return $renamedTarget
        }
    }

    $tableKey = ConvertTo-UpgradeFieldKey $sourceTable
    if ($tableKey -eq "treemeasurements" -and (Test-TableExists -Connection $TargetConnection -TableName "TreeCustomMeasurements")) {
        return "TreeCustomMeasurements"
    }
    if ($tableKey -in @("plots", "plotmeasurements") -and (Test-TableExists -Connection $TargetConnection -TableName "PlotCustomMeasurements")) {
        return "PlotCustomMeasurements"
    }

    if (-not (Test-UpgradeTableOnlyTargetTable -TableName $sourceTable)) { return "Skip" }
    if (-not (Test-TableExists -Connection $TargetConnection -TableName $sourceTable)) { return "Skip" }
    return $sourceTable
}

function Get-UpgradeFieldMappingSuggestions {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [object[]]$CustomFields = @()
    )

    $customTargetLookup = @{}
    foreach ($field in @($CustomFields)) {
        $tableName = ConvertTo-BuilderText $field.TableName
        $fieldName = ConvertTo-AccessFieldName $field.FieldName
        if ([string]::IsNullOrWhiteSpace($tableName) -or [string]::IsNullOrWhiteSpace($fieldName)) { continue }
        $key = "$($tableName.ToLowerInvariant()).$($fieldName.ToLowerInvariant())"
        $customTargetLookup[$key] = $true
    }

    $items = New-Object System.Collections.Generic.List[object]
    foreach ($sourceSpec in @(Get-UpgradeMeasurementTableSpecs)) {
        if (-not (Test-TableExists -Connection $SourceConnection -TableName $sourceSpec.TableName)) { continue }

        $sourceInfo = @(Get-TableColumnInfo -Connection $SourceConnection -TableName $sourceSpec.TableName)
        $sameTargetLookup = @{}
        if (Test-TableExists -Connection $TargetConnection -TableName $sourceSpec.TableName) {
            $sameTargetLookup = New-CaseInsensitiveColumnLookup @(Get-TableColumns -Connection $TargetConnection -TableName $sourceSpec.TableName)
        }

        $pairedTargetTable = $sourceSpec.CustomTableName
        if ([string]::Equals($sourceSpec.TableName, $sourceSpec.CustomTableName, [System.StringComparison]::OrdinalIgnoreCase)) {
            $pairedTargetTable = switch ($sourceSpec.Domain) {
                "Plot" { "PlotMeasurements" }
                "Tree" { "TreeMeasurements" }
                "Regen" { "RegenMeasurements" }
            }
        }
        $pairedTargetLookup = @{}
        if (-not [string]::IsNullOrWhiteSpace($pairedTargetTable) -and (Test-TableExists -Connection $TargetConnection -TableName $pairedTargetTable)) {
            $pairedTargetLookup = New-CaseInsensitiveColumnLookup @(Get-TableColumns -Connection $TargetConnection -TableName $pairedTargetTable)
        }

        foreach ($columnInfo in $sourceInfo) {
            $sourceField = ConvertTo-BuilderText $columnInfo.ColumnName
            if (Test-UpgradeMappingReviewFieldExcluded -TableName $sourceSpec.TableName -FieldName $sourceField) { continue }
            $defaultTarget = Get-UpgradeDefaultMappingTarget -SourceSpec $sourceSpec -SourceField $sourceField -TargetConnection $TargetConnection
            $isRenamedDefault = ($defaultTarget -match "\.")
            if (-not $isRenamedDefault) {
                if (-not [string]::IsNullOrWhiteSpace((Get-ColumnLookupValue -Lookup $sameTargetLookup -ColumnName $sourceField))) { continue }
                if (-not [string]::IsNullOrWhiteSpace((Get-ColumnLookupValue -Lookup $pairedTargetLookup -ColumnName $sourceField))) { continue }
                $pairedCustomKey = "$($pairedTargetTable.ToLowerInvariant()).$($sourceField.ToLowerInvariant())"
                $sameCustomKey = "$($sourceSpec.TableName.ToLowerInvariant()).$($sourceField.ToLowerInvariant())"
                if ($customTargetLookup.ContainsKey($pairedCustomKey) -or $customTargetLookup.ContainsKey($sameCustomKey)) { continue }
            }
            $notes = if ([string]::Equals($defaultTarget, "Skip", [System.StringComparison]::OrdinalIgnoreCase)) {
                "Choose a target table to add the old field by name, or choose table.field to rename it."
            }
            elseif ($defaultTarget -match "\.") {
                "Suggested: map this renamed old field to $defaultTarget. Review or change to Skip."
            }
            else {
                "Suggested: keep this old field in $defaultTarget using the same field name. Review or change to Skip."
            }
            [void]$items.Add([pscustomobject]@{
                SourceTable = $sourceSpec.TableName
                SourceField = $sourceField
                SourceType = ConvertTo-BuilderText $columnInfo.DataType
                Target = $defaultTarget
                Notes = $notes
            })
        }
    }
    return @($items.ToArray() | Sort-Object SourceTable, SourceField)
}

function ConvertTo-UpgradeDataTypeFamily {
    param([string]$DataType)

    switch ((ConvertTo-BuilderText $DataType).ToLowerInvariant()) {
        "byte" { return "Integer" }
        "short" { return "Integer" }
        "integer" { return "Integer" }
        "long" { return "Integer" }
        "long integer" { return "Integer" }
        "single" { return "Number" }
        "double" { return "Number" }
        "currency" { return "Number" }
        "datetime" { return "Date" }
        "date" { return "Date" }
        "date/time" { return "Date" }
        "boolean" { return "Boolean" }
        "yes/no" { return "Boolean" }
        "guid" { return "Guid" }
        "memo" { return "Text" }
        "longtext" { return "Text" }
        "long text" { return "Text" }
        "text" { return "Text" }
        default { return "Unknown" }
    }
}

function Test-UpgradeDataTypePairNeedsReview {
    param(
        [string]$SourceDataType,
        [string]$TargetDataType
    )

    $sourceFamily = ConvertTo-UpgradeDataTypeFamily -DataType $SourceDataType
    $targetFamily = ConvertTo-UpgradeDataTypeFamily -DataType $TargetDataType
    if ($targetFamily -in @("Text", "Unknown")) { return $false }
    if ($sourceFamily -eq $targetFamily) { return $false }
    if ($targetFamily -eq "Number" -and $sourceFamily -eq "Integer") { return $false }
    return $true
}

function Test-UpgradeValueFitsDataType {
    param(
        [object]$Value,
        [string]$TargetDataType
    )

    if ($null -eq $Value -or $Value -is [System.DBNull]) { return $true }
    $text = ConvertTo-BuilderText $Value
    if ([string]::IsNullOrWhiteSpace($text)) { return $true }

    switch (ConvertTo-UpgradeDataTypeFamily -DataType $TargetDataType) {
        "Integer" {
            $number = 0
            return [int]::TryParse($text, [ref]$number)
        }
        "Number" {
            $number = 0.0
            return ([double]::TryParse($text, [System.Globalization.NumberStyles]::Any, [System.Globalization.CultureInfo]::InvariantCulture, [ref]$number) -or [double]::TryParse($text, [ref]$number))
        }
        "Date" {
            if ($Value -is [datetime]) { return $true }
            $date = [datetime]::MinValue
            return [datetime]::TryParse($text, [ref]$date)
        }
        "Boolean" {
            return ($text.ToLowerInvariant() -in @("0", "1", "-1", "true", "false", "yes", "no", "y", "n", "checked", "unchecked"))
        }
        "Guid" {
            return ([regex]::IsMatch($text, "^[{(]?[0-9A-Fa-f]{8}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{12}[)}]?$"))
        }
        default {
            return $true
        }
    }
}

function ConvertTo-UpgradeReviewSampleText {
    param([object]$Value)

    $text = ConvertTo-BuilderText $Value
    if ($text.Length -gt 40) { return $text.Substring(0, 40) + "..." }
    return $text
}

function Get-UpgradeFieldConversionSummary {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [string]$SourceTable,
        [string]$SourceField,
        [string]$SourceDataType,
        [string]$TargetDataType
    )

    if (-not (Test-UpgradeDataTypePairNeedsReview -SourceDataType $SourceDataType -TargetDataType $TargetDataType)) { return $null }

    $nonBlankCount = 0
    $badCount = 0
    $samples = New-Object System.Collections.Generic.List[string]
    $command = $SourceConnection.CreateCommand()
    $command.CommandText = "SELECT $(Quote-Name $SourceField) FROM $(Quote-Name $SourceTable) WHERE $(Quote-Name $SourceField) Is Not Null"
    $command.CommandTimeout = 0
    $reader = $null
    try {
        $reader = $command.ExecuteReader()
        while ($reader.Read()) {
            $value = $reader[0]
            if ($null -eq $value -or $value -is [System.DBNull]) { continue }
            if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $value))) { continue }
            $nonBlankCount++
            if (-not (Test-UpgradeValueFitsDataType -Value $value -TargetDataType $TargetDataType)) {
                $badCount++
                if ($samples.Count -lt 5) {
                    [void]$samples.Add((ConvertTo-UpgradeReviewSampleText -Value $value))
                }
            }
        }
    }
    finally {
        if ($null -ne $reader) {
            try { $reader.Close() } catch {}
            try { $reader.Dispose() } catch {}
        }
        $command.Dispose()
    }

    return [pscustomobject]@{
        NonBlankCount = $nonBlankCount
        BadCount = $badCount
        Samples = [string[]]$samples.ToArray()
    }
}

function New-UpgradeCustomFieldTypeLookup {
    param([object[]]$CustomFields)

    $lookup = @{}
    foreach ($field in @($CustomFields)) {
        $active = $true
        if ($field.PSObject.Properties["Active"]) { $active = ConvertTo-BuilderBool $field.Active }
        if (-not $active) { continue }
        $tableName = ConvertTo-BuilderText $field.TableName
        $fieldName = ConvertTo-AccessFieldName $field.FieldName
        $dataType = ConvertTo-BuilderText $field.DataType
        if ([string]::IsNullOrWhiteSpace($tableName) -or [string]::IsNullOrWhiteSpace($fieldName) -or [string]::IsNullOrWhiteSpace($dataType)) { continue }
        $lookup["$($tableName.ToLowerInvariant()).$($fieldName.ToLowerInvariant())"] = $dataType
    }
    return $lookup
}

function Get-UpgradeCustomFieldDataType {
    param(
        [hashtable]$CustomFieldTypeLookup,
        [string]$TableName,
        [string]$FieldName
    )

    if ($null -eq $CustomFieldTypeLookup) { return "" }
    $tableNameText = ConvertTo-BuilderText $TableName
    $fieldNameText = ConvertTo-AccessFieldName $FieldName
    if ([string]::IsNullOrWhiteSpace($tableNameText) -or [string]::IsNullOrWhiteSpace($fieldNameText)) { return "" }
    $key = "$($tableNameText.ToLowerInvariant()).$($fieldNameText.ToLowerInvariant())"
    if ($CustomFieldTypeLookup.ContainsKey($key)) { return ConvertTo-BuilderText $CustomFieldTypeLookup[$key] }
    return ""
}

function Get-UpgradeReviewTargetFieldType {
    param(
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [hashtable]$CustomFieldTypeLookup,
        [string]$TargetTable,
        [string]$TargetField
    )

    $customDataType = Get-UpgradeCustomFieldDataType -CustomFieldTypeLookup $CustomFieldTypeLookup -TableName $TargetTable -FieldName $TargetField
    if (-not [string]::IsNullOrWhiteSpace($customDataType)) { return $customDataType }
    if (-not (Test-TableExists -Connection $TargetConnection -TableName $TargetTable)) { return "" }
    foreach ($columnInfo in @(Get-TableColumnInfo -Connection $TargetConnection -TableName $TargetTable)) {
        if ([string]::Equals((ConvertTo-BuilderText $columnInfo.ColumnName), (ConvertTo-BuilderText $TargetField), [System.StringComparison]::OrdinalIgnoreCase)) {
            return ConvertTo-BuilderText $columnInfo.DataType
        }
    }
    return ""
}

function Add-UpgradeDataTypeReviewItem {
    param(
        [System.Collections.Generic.List[object]]$Items,
        [hashtable]$Seen,
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [string]$Context,
        [string]$SourceTable,
        [string]$SourceField,
        [string]$SourceDataType,
        [string]$TargetTable,
        [string]$TargetField,
        [string]$TargetDataType
    )

    if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $SourceDataType)) -or [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $TargetDataType))) { return }
    if (-not (Test-UpgradeDataTypePairNeedsReview -SourceDataType $SourceDataType -TargetDataType $TargetDataType)) { return }
    $key = "$($SourceTable.ToLowerInvariant()).$($SourceField.ToLowerInvariant())|$($TargetTable.ToLowerInvariant()).$($TargetField.ToLowerInvariant())"
    if ($Seen.ContainsKey($key)) { return }
    $Seen[$key] = $true

    $summary = Get-UpgradeFieldConversionSummary -SourceConnection $SourceConnection -SourceTable $SourceTable -SourceField $SourceField -SourceDataType $SourceDataType -TargetDataType $TargetDataType
    if ($null -eq $summary) { return }
    $severity = if ([int]$summary.BadCount -gt 0) { "Error" } else { "Warning" }
    $sampleText = if ($summary.Samples.Count -gt 0) { [string]::Join(", ", [string[]]$summary.Samples) } else { "" }
    [void]$Items.Add([pscustomobject]@{
        Severity = $severity
        Context = $Context
        SourceTable = $SourceTable
        SourceField = $SourceField
        SourceDataType = $SourceDataType
        TargetTable = $TargetTable
        TargetField = $TargetField
        TargetDataType = $TargetDataType
        NonBlankCount = [int]$summary.NonBlankCount
        BadCount = [int]$summary.BadCount
        SampleBadValues = $sampleText
    })
}

function Get-UpgradeSelectedMappingDataTypeReview {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [object[]]$FieldMappings,
        [hashtable]$CustomFieldTypeLookup,
        [System.Collections.Generic.List[object]]$Items,
        [hashtable]$Seen
    )

    foreach ($mapping in @($FieldMappings)) {
        $sourceTable = ConvertTo-BuilderText $mapping.SourceTable
        $sourceField = ConvertTo-BuilderText $mapping.SourceField
        $targetTable = ConvertTo-BuilderText $mapping.TargetTable
        $requestedTargetField = if ($mapping.PSObject.Properties["TargetField"]) { ConvertTo-AccessFieldName $mapping.TargetField } else { "" }
        $isTableOnlyTarget = $false
        if ($mapping.PSObject.Properties["TargetTableOnly"]) { $isTableOnlyTarget = ConvertTo-BuilderBool $mapping.TargetTableOnly }
        if ([string]::IsNullOrWhiteSpace($sourceTable) -or [string]::IsNullOrWhiteSpace($sourceField) -or [string]::IsNullOrWhiteSpace($targetTable)) { continue }
        if (-not (Test-TableExists -Connection $SourceConnection -TableName $sourceTable)) { continue }
        if (-not (Test-TableExists -Connection $TargetConnection -TableName $targetTable)) { continue }
        $renamedFieldTarget = Get-UpgradeRenamedFieldTarget -SourceTable $sourceTable -SourceField $sourceField
        if ($null -ne $renamedFieldTarget -and
            [string]::IsNullOrWhiteSpace($requestedTargetField) -and
            (Test-WOOFTextEquals $targetTable $renamedFieldTarget.TableName)) {
            $requestedTargetField = ConvertTo-AccessFieldName $renamedFieldTarget.FieldName
            $isTableOnlyTarget = $false
        }
        if ([string]::IsNullOrWhiteSpace($requestedTargetField)) { $isTableOnlyTarget = $true }

        $sourceColumnInfo = @(Get-TableColumnInfo -Connection $SourceConnection -TableName $sourceTable)
        $sourceLookup = New-CaseInsensitiveColumnLookup @($sourceColumnInfo | ForEach-Object { $_.ColumnName })
        $sourceColumn = Get-ColumnLookupValue -Lookup $sourceLookup -ColumnName $sourceField
        if ([string]::IsNullOrWhiteSpace($sourceColumn)) { continue }
        $sourceDataType = ""
        foreach ($columnInfo in $sourceColumnInfo) {
            if ([string]::Equals((ConvertTo-BuilderText $columnInfo.ColumnName), $sourceColumn, [System.StringComparison]::OrdinalIgnoreCase)) {
                $sourceDataType = ConvertTo-BuilderText $columnInfo.DataType
                break
            }
        }
        $targetField = if ($isTableOnlyTarget) { ConvertTo-AccessFieldName $sourceColumn } else { $requestedTargetField }
        $targetDataType = Get-UpgradeReviewTargetFieldType -TargetConnection $TargetConnection -CustomFieldTypeLookup $CustomFieldTypeLookup -TargetTable $targetTable -TargetField $targetField
        Add-UpgradeDataTypeReviewItem -Items $Items -Seen $Seen -SourceConnection $SourceConnection -Context "Upgrade Mapping" -SourceTable $sourceTable -SourceField $sourceColumn -SourceDataType $sourceDataType -TargetTable $targetTable -TargetField $targetField -TargetDataType $targetDataType
    }
}

function Get-UpgradeAutomaticDataTypeReview {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [hashtable]$CustomFieldTypeLookup,
        [System.Collections.Generic.List[object]]$Items,
        [hashtable]$Seen
    )

    $tables = @(
        "Plots",
        "PlotMeasurements",
        "PlotCustomMeasurements",
        "Trees",
        "TreeMeasurements",
        "TreeCustomMeasurements",
        "RegenMeasurements",
        "RegenCustomMeasurements",
        "InventoryCrews",
        "InventoryAssignments",
        "InventoryAssignmentPlots",
        "InventoryAssignmentTrees"
    )

    foreach ($tableName in $tables) {
        if (-not (Test-TableExists -Connection $SourceConnection -TableName $tableName)) { continue }
        if (-not (Test-TableExists -Connection $TargetConnection -TableName $tableName)) { continue }
        $sourceInfo = @(Get-TableColumnInfo -Connection $SourceConnection -TableName $tableName)
        $targetInfo = @(Get-TableColumnInfo -Connection $TargetConnection -TableName $tableName)
        $targetLookup = New-CaseInsensitiveColumnLookup @($targetInfo | ForEach-Object { $_.ColumnName })
        foreach ($sourceColumnInfo in $sourceInfo) {
            $sourceField = ConvertTo-BuilderText $sourceColumnInfo.ColumnName
            if (Test-UpgradeMovedFieldExcluded -FieldName $sourceField) { continue }
            $targetField = Get-ColumnLookupValue -Lookup $targetLookup -ColumnName $sourceField
            if ([string]::IsNullOrWhiteSpace($targetField)) { continue }
            $targetDataType = ""
            foreach ($targetColumnInfo in $targetInfo) {
                if ([string]::Equals((ConvertTo-BuilderText $targetColumnInfo.ColumnName), $targetField, [System.StringComparison]::OrdinalIgnoreCase)) {
                    $targetDataType = ConvertTo-BuilderText $targetColumnInfo.DataType
                    break
                }
            }
            Add-UpgradeDataTypeReviewItem -Items $Items -Seen $Seen -SourceConnection $SourceConnection -Context "Same-table import" -SourceTable $tableName -SourceField $sourceField -SourceDataType (ConvertTo-BuilderText $sourceColumnInfo.DataType) -TargetTable $tableName -TargetField $targetField -TargetDataType $targetDataType
        }
    }

    $groups = @(
        @{ Base = "PlotMeasurements"; Custom = "PlotCustomMeasurements" },
        @{ Base = "TreeMeasurements"; Custom = "TreeCustomMeasurements" },
        @{ Base = "RegenMeasurements"; Custom = "RegenCustomMeasurements" }
    )

    foreach ($group in $groups) {
        foreach ($direction in @(
            @{ Source = $group.Base; Same = $group.Base; Moved = $group.Custom },
            @{ Source = $group.Custom; Same = $group.Custom; Moved = $group.Base }
        )) {
            $sourceTable = ConvertTo-BuilderText $direction.Source
            $sameTargetTable = ConvertTo-BuilderText $direction.Same
            $movedTargetTable = ConvertTo-BuilderText $direction.Moved
            if (-not (Test-TableExists -Connection $SourceConnection -TableName $sourceTable)) { continue }
            if (-not (Test-TableExists -Connection $TargetConnection -TableName $sameTargetTable)) { continue }
            if (-not (Test-TableExists -Connection $TargetConnection -TableName $movedTargetTable)) { continue }
            $sourceInfo = @(Get-TableColumnInfo -Connection $SourceConnection -TableName $sourceTable)
            $sameTargetLookup = New-CaseInsensitiveColumnLookup @(Get-TableColumns -Connection $TargetConnection -TableName $sameTargetTable)
            $movedTargetLookup = New-CaseInsensitiveColumnLookup @(Get-TableColumns -Connection $TargetConnection -TableName $movedTargetTable)
            foreach ($sourceColumnInfo in $sourceInfo) {
                $sourceField = ConvertTo-BuilderText $sourceColumnInfo.ColumnName
                if (Test-UpgradeMovedFieldExcluded -FieldName $sourceField) { continue }
                if (-not [string]::IsNullOrWhiteSpace((Get-ColumnLookupValue -Lookup $sameTargetLookup -ColumnName $sourceField))) { continue }
                $targetField = Get-ColumnLookupValue -Lookup $movedTargetLookup -ColumnName $sourceField
                if ([string]::IsNullOrWhiteSpace($targetField)) {
                    $customTargetType = Get-UpgradeCustomFieldDataType -CustomFieldTypeLookup $CustomFieldTypeLookup -TableName $movedTargetTable -FieldName $sourceField
                    if ([string]::IsNullOrWhiteSpace($customTargetType)) { continue }
                    $targetField = $sourceField
                }
                $targetDataType = Get-UpgradeReviewTargetFieldType -TargetConnection $TargetConnection -CustomFieldTypeLookup $CustomFieldTypeLookup -TargetTable $movedTargetTable -TargetField $targetField
                Add-UpgradeDataTypeReviewItem -Items $Items -Seen $Seen -SourceConnection $SourceConnection -Context "Auto moved field" -SourceTable $sourceTable -SourceField $sourceField -SourceDataType (ConvertTo-BuilderText $sourceColumnInfo.DataType) -TargetTable $movedTargetTable -TargetField $targetField -TargetDataType $targetDataType
            }
        }
    }
}

function Get-UpgradeDataTypeReview {
    param(
        [string]$OldDatabasePath,
        [string]$TemplateDatabasePath,
        [object[]]$FieldMappings = @(),
        [object[]]$CustomFields = @()
    )

    if ([string]::IsNullOrWhiteSpace($OldDatabasePath) -or -not (Test-Path -LiteralPath $OldDatabasePath)) { return @() }
    if ([string]::IsNullOrWhiteSpace($TemplateDatabasePath) -or -not (Test-Path -LiteralPath $TemplateDatabasePath)) { return @() }

    $items = New-Object System.Collections.Generic.List[object]
    $seen = @{}
    $customFieldTypeLookup = New-UpgradeCustomFieldTypeLookup -CustomFields $CustomFields
    $sourceConnection = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $OldDatabasePath)
    $targetConnection = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $TemplateDatabasePath)
    try {
        Get-UpgradeAutomaticDataTypeReview -SourceConnection $sourceConnection -TargetConnection $targetConnection -CustomFieldTypeLookup $customFieldTypeLookup -Items $items -Seen $seen
        Get-UpgradeSelectedMappingDataTypeReview -SourceConnection $sourceConnection -TargetConnection $targetConnection -FieldMappings $FieldMappings -CustomFieldTypeLookup $customFieldTypeLookup -Items $items -Seen $seen
    }
    finally {
        if ($sourceConnection.State -eq "Open") { $sourceConnection.Close() }
        if ($targetConnection.State -eq "Open") { $targetConnection.Close() }
        $sourceConnection.Dispose()
        $targetConnection.Dispose()
    }
    return @($items.ToArray() | Sort-Object Severity, Context, SourceTable, SourceField)
}

function Format-UpgradeDataTypeReviewLine {
    param([object]$Item)

    $badText = if ([int]$Item.BadCount -gt 0) { "$($Item.BadCount) value(s) will not fit" } else { "type changed; current values look convertible, but review/crosswalk before upgrade" }
    $sampleText = if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Item.SampleBadValues))) { " Examples: $($Item.SampleBadValues)" } else { "" }
    return "$($Item.Context): $($Item.SourceTable).$($Item.SourceField) ($($Item.SourceDataType)) -> $($Item.TargetTable).$($Item.TargetField) ($($Item.TargetDataType)): $badText out of $($Item.NonBlankCount) nonblank value(s).$sampleText"
}

function Get-UpgradeRelatedMappingInfo {
    param([string]$Domain)

    switch (ConvertTo-BuilderText $Domain) {
        "Plot" {
            return [pscustomobject]@{
                Domain = "Plot"
                ParentTable = "Plots"
                MeasurementTable = "PlotMeasurements"
                CustomTable = "PlotCustomMeasurements"
                ParentIdColumn = "PlotID"
                ParentKeyColumn = "PlotKey"
                MeasurementIdColumn = "MeasurementID"
                MeasurementKeyColumn = "PlotMeasKey"
            }
        }
        "Tree" {
            return [pscustomobject]@{
                Domain = "Tree"
                ParentTable = "Trees"
                MeasurementTable = "TreeMeasurements"
                CustomTable = "TreeCustomMeasurements"
                ParentIdColumn = "TreeID"
                ParentKeyColumn = "TreeKey"
                MeasurementIdColumn = "MeasurementID"
                MeasurementKeyColumn = "TreeMeasKey"
            }
        }
        "Regen" {
            return [pscustomobject]@{
                Domain = "Regen"
                ParentTable = ""
                MeasurementTable = "RegenMeasurements"
                CustomTable = "RegenCustomMeasurements"
                ParentIdColumn = ""
                ParentKeyColumn = ""
                MeasurementIdColumn = "MeasurementID"
                MeasurementKeyColumn = "RegenMeasKey"
            }
        }
    }
    return $null
}

function Get-UpgradeRelatedTableRole {
    param(
        [object]$Info,
        [string]$TableName
    )

    $clean = ConvertTo-BuilderText $TableName
    if ($null -eq $Info -or [string]::IsNullOrWhiteSpace($clean)) { return "" }
    if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Info.ParentTable)) -and [string]::Equals($clean, (ConvertTo-BuilderText $Info.ParentTable), [System.StringComparison]::OrdinalIgnoreCase)) { return "Parent" }
    if ([string]::Equals($clean, (ConvertTo-BuilderText $Info.MeasurementTable), [System.StringComparison]::OrdinalIgnoreCase)) { return "Measurement" }
    if ([string]::Equals($clean, (ConvertTo-BuilderText $Info.CustomTable), [System.StringComparison]::OrdinalIgnoreCase)) { return "Custom" }
    return ""
}

function Get-UpgradeRelatedMeasurementRows {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [object]$Info,
        [string]$MeasurementId = "",
        [string]$MeasurementKey = "",
        [string]$ParentId = "",
        [string]$ParentKey = ""
    )

    $empty = New-Object System.Data.DataTable
    if ($null -eq $Info) { return ,$empty }
    $measurementTable = ConvertTo-BuilderText $Info.MeasurementTable
    if ([string]::IsNullOrWhiteSpace($measurementTable) -or -not (Test-TableExists -Connection $Connection -TableName $measurementTable)) { return ,$empty }

    $whereParts = New-Object System.Collections.Generic.List[string]
    if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $MeasurementId)) -and
        (Test-BuilderGuidValue -Value $MeasurementId)) {
        foreach ($measurementIdColumn in @(Get-UpgradeColumnAliases -Domain $Info.Domain -ColumnName $Info.MeasurementIdColumn)) {
            if (Test-ColumnExists -Connection $Connection -TableName $measurementTable -ColumnName $measurementIdColumn) {
                [void]$whereParts.Add("$(Quote-Name $measurementIdColumn) = $(Sql-Guid $MeasurementId)")
                break
            }
        }
    }
    if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $MeasurementKey))) {
        foreach ($measurementKeyColumn in @(Get-UpgradeColumnAliases -Domain $Info.Domain -ColumnName $Info.MeasurementKeyColumn)) {
            if (Test-ColumnExists -Connection $Connection -TableName $measurementTable -ColumnName $measurementKeyColumn) {
                [void]$whereParts.Add("$(Quote-Name $measurementKeyColumn) = $(Sql-Text $MeasurementKey)")
                break
            }
        }
    }
    if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Info.ParentIdColumn)) -and
        -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $ParentId)) -and
        (Test-ColumnExists -Connection $Connection -TableName $measurementTable -ColumnName $Info.ParentIdColumn) -and
        (Test-BuilderGuidValue -Value $ParentId)) {
        [void]$whereParts.Add("$(Quote-Name $Info.ParentIdColumn) = $(Sql-Guid $ParentId)")
    }
    if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Info.ParentKeyColumn)) -and
        -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $ParentKey)) -and
        (Test-ColumnExists -Connection $Connection -TableName $measurementTable -ColumnName $Info.ParentKeyColumn)) {
        [void]$whereParts.Add("$(Quote-Name $Info.ParentKeyColumn) = $(Sql-Text $ParentKey)")
    }
    if ($whereParts.Count -eq 0) { return ,$empty }

    $where = [string]::Join(" OR ", [string[]]$whereParts.ToArray())
    return Get-DbTable -Connection $Connection -Sql "SELECT * FROM $(Quote-Name $measurementTable) WHERE $where"
}

function Get-UpgradeManualSourceContext {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [System.Data.DataRow]$SourceRow,
        [object]$Info
    )

    $parentId = if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Info.ParentIdColumn))) { Get-DataRowText -Row $SourceRow -ColumnNames @(Get-UpgradeColumnAliases -Domain $Info.Domain -ColumnName $Info.ParentIdColumn) } else { "" }
    $parentKey = if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Info.ParentKeyColumn))) { Get-DataRowText -Row $SourceRow -ColumnNames @(Get-UpgradeColumnAliases -Domain $Info.Domain -ColumnName $Info.ParentKeyColumn) } else { "" }
    $measurementId = Get-DataRowText -Row $SourceRow -ColumnNames @(Get-UpgradeColumnAliases -Domain $Info.Domain -ColumnName $Info.MeasurementIdColumn)
    $measurementKey = Get-DataRowText -Row $SourceRow -ColumnNames @(Get-UpgradeColumnAliases -Domain $Info.Domain -ColumnName $Info.MeasurementKeyColumn)

    if (([string]::IsNullOrWhiteSpace($parentId) -or [string]::IsNullOrWhiteSpace($parentKey)) -and
        (-not [string]::IsNullOrWhiteSpace($measurementId) -or -not [string]::IsNullOrWhiteSpace($measurementKey))) {
        $measurementRows = Get-UpgradeRelatedMeasurementRows -Connection $SourceConnection -Info $Info -MeasurementId $measurementId -MeasurementKey $measurementKey
        if ($measurementRows.Rows.Count -gt 0) {
            if ([string]::IsNullOrWhiteSpace($parentId)) { $parentId = Get-DataRowText -Row $measurementRows.Rows[0] -ColumnNames @(Get-UpgradeColumnAliases -Domain $Info.Domain -ColumnName $Info.ParentIdColumn) }
            if ([string]::IsNullOrWhiteSpace($parentKey)) { $parentKey = Get-DataRowText -Row $measurementRows.Rows[0] -ColumnNames @(Get-UpgradeColumnAliases -Domain $Info.Domain -ColumnName $Info.ParentKeyColumn) }
            if ([string]::IsNullOrWhiteSpace($measurementId)) { $measurementId = Get-DataRowText -Row $measurementRows.Rows[0] -ColumnNames @(Get-UpgradeColumnAliases -Domain $Info.Domain -ColumnName $Info.MeasurementIdColumn) }
            if ([string]::IsNullOrWhiteSpace($measurementKey)) { $measurementKey = Get-DataRowText -Row $measurementRows.Rows[0] -ColumnNames @(Get-UpgradeColumnAliases -Domain $Info.Domain -ColumnName $Info.MeasurementKeyColumn) }
        }
    }

    return [pscustomobject]@{
        ParentId = $parentId
        ParentKey = $parentKey
        MeasurementId = $measurementId
        MeasurementKey = $measurementKey
    }
}

function Add-UpgradeCustomMeasurementRowIfMissing {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$CustomTableName,
        [string]$MeasurementId,
        [string]$MeasurementKeyColumn,
        [string]$MeasurementKey
    )

    if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $CustomTableName))) { return $false }
    if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $MeasurementId)) -or -not (Test-BuilderGuidValue -Value $MeasurementId)) { return $false }
    if (-not (Test-TableExists -Connection $Connection -TableName $CustomTableName)) { return $false }
    if (-not (Test-ColumnExists -Connection $Connection -TableName $CustomTableName -ColumnName "MeasurementID")) { return $false }

    $existing = Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM $(Quote-Name $CustomTableName) WHERE [MeasurementID] = $(Sql-Guid $MeasurementId)"
    if ([int]$existing -gt 0) { return $false }

    if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $MeasurementKeyColumn)) -and
        (Test-ColumnExists -Connection $Connection -TableName $CustomTableName -ColumnName $MeasurementKeyColumn)) {
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO $(Quote-Name $CustomTableName) ([MeasurementID], $(Quote-Name $MeasurementKeyColumn)) VALUES (?, ?)" -Parameters @(
            (DbGuid $MeasurementId),
            (DbText $MeasurementKey)
        ))
    }
    else {
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO $(Quote-Name $CustomTableName) ([MeasurementID]) VALUES (?)" -Parameters @(
            (DbGuid $MeasurementId)
        ))
    }
    return $true
}

function Get-UpgradeRelatedTargetRefs {
    param(
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [object]$Info,
        [string]$TargetTableName,
        [object]$Context
    )

    $refs = New-Object System.Collections.Generic.List[object]
    $seen = @{}
    $targetLookup = New-CaseInsensitiveColumnLookup @(Get-TableColumns -Connection $TargetConnection -TableName $TargetTableName)
    $targetRole = Get-UpgradeRelatedTableRole -Info $Info -TableName $TargetTableName
    $addRef = {
        param(
            [string]$MatchColumn,
            [string]$MatchValue,
            [string]$MeasurementId = "",
            [string]$MeasurementKey = ""
        )

        $actualColumn = Get-UpgradeColumnLookupValueWithAliases -Lookup $targetLookup -Domain $Info.Domain -ColumnName $MatchColumn
        $cleanValue = ConvertTo-BuilderText $MatchValue
        if ([string]::IsNullOrWhiteSpace($actualColumn) -or [string]::IsNullOrWhiteSpace($cleanValue)) { return }
        $key = "$($actualColumn.ToLowerInvariant())|$($cleanValue.ToLowerInvariant())"
        if ($seen.ContainsKey($key)) { return }
        $seen[$key] = $true
        [void]$refs.Add([pscustomobject]@{
            MatchColumn = $actualColumn
            MatchValue = $cleanValue
            MeasurementId = ConvertTo-BuilderText $MeasurementId
            MeasurementKey = ConvertTo-BuilderText $MeasurementKey
        })
    }

    if ($targetRole -eq "Parent") {
        & $addRef $Info.ParentIdColumn $Context.ParentId
        & $addRef $Info.ParentKeyColumn $Context.ParentKey
    }
    elseif ($targetRole -eq "Measurement") {
        & $addRef $Info.MeasurementIdColumn $Context.MeasurementId
        & $addRef $Info.MeasurementKeyColumn $Context.MeasurementKey
        if ($refs.Count -eq 0) {
            $measurementRows = Get-UpgradeRelatedMeasurementRows -Connection $TargetConnection -Info $Info -ParentId $Context.ParentId -ParentKey $Context.ParentKey
            foreach ($measurementRow in $measurementRows.Rows) {
                $measurementId = Get-DataRowText -Row $measurementRow -ColumnNames @(Get-UpgradeColumnAliases -Domain $Info.Domain -ColumnName $Info.MeasurementIdColumn)
                $measurementKey = Get-DataRowText -Row $measurementRow -ColumnNames @(Get-UpgradeColumnAliases -Domain $Info.Domain -ColumnName $Info.MeasurementKeyColumn)
                & $addRef $Info.MeasurementIdColumn $measurementId $measurementId $measurementKey
            }
        }
    }
    elseif ($targetRole -eq "Custom") {
        if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Context.MeasurementId)) -or -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Context.MeasurementKey))) {
            if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Context.MeasurementId))) {
                [void](Add-UpgradeCustomMeasurementRowIfMissing -Connection $TargetConnection -CustomTableName $TargetTableName -MeasurementId $Context.MeasurementId -MeasurementKeyColumn $Info.MeasurementKeyColumn -MeasurementKey $Context.MeasurementKey)
            }
            & $addRef $Info.MeasurementIdColumn $Context.MeasurementId $Context.MeasurementId $Context.MeasurementKey
            & $addRef $Info.MeasurementKeyColumn $Context.MeasurementKey $Context.MeasurementId $Context.MeasurementKey
        }
        if ($refs.Count -eq 0) {
            $measurementRows = Get-UpgradeRelatedMeasurementRows -Connection $TargetConnection -Info $Info -ParentId $Context.ParentId -ParentKey $Context.ParentKey
            foreach ($measurementRow in $measurementRows.Rows) {
                $measurementId = Get-DataRowText -Row $measurementRow -ColumnNames @(Get-UpgradeColumnAliases -Domain $Info.Domain -ColumnName $Info.MeasurementIdColumn)
                $measurementKey = Get-DataRowText -Row $measurementRow -ColumnNames @(Get-UpgradeColumnAliases -Domain $Info.Domain -ColumnName $Info.MeasurementKeyColumn)
                [void](Add-UpgradeCustomMeasurementRowIfMissing -Connection $TargetConnection -CustomTableName $TargetTableName -MeasurementId $measurementId -MeasurementKeyColumn $Info.MeasurementKeyColumn -MeasurementKey $measurementKey)
                & $addRef $Info.MeasurementIdColumn $measurementId $measurementId $measurementKey
            }
        }
    }

    return @($refs.ToArray())
}

function Invoke-UpgradeManualFieldMappings {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [object[]]$FieldMappings,
        [scriptblock]$Log
    )

    $activeMappings = New-Object System.Collections.Generic.List[object]
    $targetSeen = @{}
    foreach ($mapping in @($FieldMappings)) {
        $sourceTable = ConvertTo-BuilderText $mapping.SourceTable
        $sourceField = ConvertTo-BuilderText $mapping.SourceField
        $targetTable = ConvertTo-BuilderText $mapping.TargetTable
        $requestedTargetField = if ($mapping.PSObject.Properties["TargetField"]) { ConvertTo-AccessFieldName $mapping.TargetField } else { "" }
        $isTableOnlyTarget = $false
        if ($mapping.PSObject.Properties["TargetTableOnly"]) { $isTableOnlyTarget = ConvertTo-BuilderBool $mapping.TargetTableOnly }
        $renamedFieldTarget = Get-UpgradeRenamedFieldTarget -SourceTable $sourceTable -SourceField $sourceField
        if ($null -ne $renamedFieldTarget -and
            [string]::IsNullOrWhiteSpace($requestedTargetField) -and
            (Test-WOOFTextEquals $targetTable $renamedFieldTarget.TableName)) {
            $requestedTargetField = ConvertTo-AccessFieldName $renamedFieldTarget.FieldName
            $isTableOnlyTarget = $false
        }
        if ([string]::IsNullOrWhiteSpace($requestedTargetField)) { $isTableOnlyTarget = $true }
        if ([string]::IsNullOrWhiteSpace($sourceTable) -and [string]::IsNullOrWhiteSpace($sourceField) -and [string]::IsNullOrWhiteSpace($targetTable) -and [string]::IsNullOrWhiteSpace($requestedTargetField)) { continue }
        if ([string]::IsNullOrWhiteSpace($sourceTable) -or [string]::IsNullOrWhiteSpace($sourceField) -or [string]::IsNullOrWhiteSpace($targetTable)) {
            throw "Upgrade Mapping tab: each mapping needs Source table, Source field, and a Target table or Target table.field. Clear incomplete rows or choose Skip."
        }
        if (Test-UpgradeMovedFieldExcluded -FieldName $sourceField) {
            throw "Upgrade Mapping tab: $sourceTable.$sourceField is a required ID/system field and cannot be manually mapped."
        }
        $sourceSpec = Get-UpgradeMeasurementTableSpec -TableName $sourceTable
        $targetSpec = Get-UpgradeMeasurementTableSpec -TableName $targetTable
        if ($null -eq $sourceSpec -or $null -eq $targetSpec) {
            throw "Upgrade Mapping tab: manual field mapping only supports Project Pickle upgrade tables such as Plots, Trees, PlotMeasurements, TreeMeasurements, and the custom measurement tables."
        }
        if (-not [string]::Equals($sourceSpec.Domain, $targetSpec.Domain, [System.StringComparison]::OrdinalIgnoreCase)) {
            throw "Upgrade Mapping tab: $sourceTable.$sourceField is $($sourceSpec.Domain) data and cannot map to $targetTable.$targetField, which is $($targetSpec.Domain) data."
        }
        $linkMode = "Direct"
        $relatedInfo = Get-UpgradeRelatedMappingInfo -Domain $sourceSpec.Domain
        $sourceRole = Get-UpgradeRelatedTableRole -Info $relatedInfo -TableName $sourceTable
        $targetRole = Get-UpgradeRelatedTableRole -Info $relatedInfo -TableName $targetTable
        if (-not [string]::Equals((ConvertTo-BuilderText $sourceSpec.Key), (ConvertTo-BuilderText $targetSpec.Key), [System.StringComparison]::OrdinalIgnoreCase)) {
            if ($null -ne $relatedInfo -and
                -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $sourceRole)) -and
                -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $targetRole))) {
                $linkMode = "RelatedTable"
            }
            else {
                throw "Upgrade Mapping tab: $sourceTable.$sourceField cannot map to $targetTable by table name because those tables use different row keys. Choose another $($sourceSpec.Domain) table or choose Skip."
            }
        }
        if (-not (Test-TableExists -Connection $SourceConnection -TableName $sourceTable)) {
            throw "Upgrade Mapping tab: old database table $sourceTable was not found."
        }
        if (-not (Test-TableExists -Connection $TargetConnection -TableName $targetTable)) {
            throw "Upgrade Mapping tab: target table $targetTable was not found in the current master database version or saved project database."
        }
        $sourceColumnInfo = @(Get-TableColumnInfo -Connection $SourceConnection -TableName $sourceTable)
        $sourceLookup = New-CaseInsensitiveColumnLookup @($sourceColumnInfo | ForEach-Object { $_.ColumnName })
        $sourceDataTypes = @{}
        foreach ($columnInfo in $sourceColumnInfo) {
            $sourceDataTypes[(ConvertTo-BuilderText $columnInfo.ColumnName).ToLowerInvariant()] = ConvertTo-BuilderText $columnInfo.DataType
        }
        $targetLookup = New-CaseInsensitiveColumnLookup @(Get-TableColumns -Connection $TargetConnection -TableName $targetTable)
        $sourceColumn = Get-ColumnLookupValue -Lookup $sourceLookup -ColumnName $sourceField
        if ([string]::IsNullOrWhiteSpace($sourceColumn)) {
            throw "Upgrade Mapping tab: old field $sourceTable.$sourceField was not found."
        }
        $sourceDataType = ""
        $sourceDataTypeKey = $sourceColumn.ToLowerInvariant()
        if ($sourceDataTypes.ContainsKey($sourceDataTypeKey)) { $sourceDataType = ConvertTo-BuilderText $sourceDataTypes[$sourceDataTypeKey] }
        $targetField = if ($isTableOnlyTarget) { ConvertTo-AccessFieldName $sourceColumn } else { $requestedTargetField }
        if (Test-UpgradeMovedFieldExcluded -FieldName $targetField) {
            throw "Upgrade Mapping tab: $targetTable.$targetField is a required ID/system field and cannot be manually overwritten."
        }
        $targetColumn = Get-ColumnLookupValue -Lookup $targetLookup -ColumnName $targetField
        if ([string]::IsNullOrWhiteSpace($targetColumn)) {
            if (Test-UpgradeTableOnlyTargetTable -TableName $targetTable) {
                $addedColumn = Add-AccessColumnIfMissing -Connection $TargetConnection -TableName $targetTable -ColumnName $targetField -DataType $sourceDataType
                if ($addedColumn -and $Log) { & $Log "Upgrade manual field mapping: added $targetTable.$targetField using old field type $sourceDataType." }
                $targetLookup = New-CaseInsensitiveColumnLookup @(Get-TableColumns -Connection $TargetConnection -TableName $targetTable)
                $targetColumn = Get-ColumnLookupValue -Lookup $targetLookup -ColumnName $targetField
            }
            else {
                throw "Upgrade Mapping tab: new field $targetTable.$targetField was not found. For new fields, choose a supported target table by name so Project Pickle can add the field, or add the exact field first."
            }
        }
        $targetKey = "$($targetTable.ToLowerInvariant()).$($targetColumn.ToLowerInvariant())"
        if ($targetSeen.ContainsKey($targetKey)) {
            throw "Upgrade Mapping tab: $targetTable.$targetColumn is used more than once. A target field can only receive one old field."
        }
        $targetSeen[$targetKey] = $true
        [void]$activeMappings.Add([pscustomobject]@{
            SourceTable = $sourceTable
            SourceField = $sourceColumn
            TargetTable = $targetTable
            TargetField = $targetColumn
            Domain = $sourceSpec.Domain
            JoinColumn = $sourceSpec.Key
            CarryColumns = $targetSpec.Carry
            CreateMissingTargetRows = Test-UpgradeCustomMeasurementTable -TableName $targetTable
            LinkMode = $linkMode
            SourceRole = $sourceRole
            TargetRole = $targetRole
        })
    }

    if ($activeMappings.Count -eq 0) {
        if ($Log) { & $Log "Upgrade manual field mapping: no selected mappings to apply." }
        return
    }
    if ($Log) { & $Log "Upgrade manual field mapping: applying $($activeMappings.Count) selected mapping(s)." }
    $groups = @($activeMappings.ToArray() | Group-Object SourceTable, TargetTable, JoinColumn, LinkMode)
    foreach ($group in $groups) {
        $first = $group.Group[0]
        $sourceTable = ConvertTo-BuilderText $first.SourceTable
        $targetTable = ConvertTo-BuilderText $first.TargetTable
        $joinColumn = ConvertTo-BuilderText $first.JoinColumn
        $linkMode = ConvertTo-BuilderText $first.LinkMode
        $sourceRows = Get-DbTable -Connection $SourceConnection -Sql "SELECT * FROM $(Quote-Name $sourceTable)"
        if ($sourceRows.Rows.Count -eq 0) { continue }
        $targetLookup = New-CaseInsensitiveColumnLookup @(Get-TableColumns -Connection $TargetConnection -TableName $targetTable)
        $targetDataTypes = Get-UpgradeTargetDataTypeLookup -Connection $TargetConnection -TableName $targetTable
        $warnIfZero = {
            param(
                [int]$UpdatedRows,
                [string]$Source,
                [string]$Target,
                [string]$FieldList
            )

            if ($Log -and $UpdatedRows -eq 0) {
                & $Log "Upgrade manual field mapping warning: copied 0 row(s) for ${Source} -> ${Target}: $FieldList. Check that the old rows have matching IDs/keys in the new output."
            }
        }
        if ([string]::Equals($linkMode, "RelatedTable", [System.StringComparison]::OrdinalIgnoreCase)) {
            $relatedInfo = Get-UpgradeRelatedMappingInfo -Domain $first.Domain
            if ($null -eq $relatedInfo) { continue }
            $sourceRole = Get-UpgradeRelatedTableRole -Info $relatedInfo -TableName $sourceTable
            $targetRole = Get-UpgradeRelatedTableRole -Info $relatedInfo -TableName $targetTable
            $setSql = [string]::Join(", ", [string[]]($group.Group | ForEach-Object { "$(Quote-Name $_.TargetField) = ?" }))
            if ($Log) { & $Log "Upgrade manual field mapping: $sourceTable -> $targetTable through related $($relatedInfo.Domain) keys." }
            Invoke-WOOFUiPulse
            $updatedRows = 0
            $matchedSourceRows = 0
            $unmatchedSourceRows = 0
            $processedRows = 0
            foreach ($row in $sourceRows.Rows) {
                try {
                    $context = Get-UpgradeManualSourceContext -SourceConnection $SourceConnection -SourceRow $row -Info $relatedInfo
                    $targetRefs = @(Get-UpgradeRelatedTargetRefs -TargetConnection $TargetConnection -Info $relatedInfo -TargetTableName $targetTable -Context $context)
                    if ($targetRefs.Count -eq 0) {
                        $unmatchedSourceRows++
                        continue
                    }
                    $matchedSourceRows++
                    foreach ($targetRef in $targetRefs) {
                        $matchColumn = ConvertTo-BuilderText $targetRef.MatchColumn
                        if ([string]::IsNullOrWhiteSpace($matchColumn)) { continue }
                        $parameters = New-Object System.Collections.Generic.List[object]
                        foreach ($fieldMap in $group.Group) {
                            $dataType = Get-UpgradeTargetDataType -DataTypeLookup $targetDataTypes -ColumnName $fieldMap.TargetField
                            [void]$parameters.Add((New-UpgradeImportDbParam -Value $row[$fieldMap.SourceField] -ColumnName $fieldMap.TargetField -ProjectId "" -PeriodIdMap @{} -DataType $dataType))
                        }
                        $matchDataType = Get-UpgradeTargetDataType -DataTypeLookup $targetDataTypes -ColumnName $matchColumn
                        [void]$parameters.Add((New-UpgradeImportDbParam -Value $targetRef.MatchValue -ColumnName $matchColumn -ProjectId "" -PeriodIdMap @{} -DataType $matchDataType))
                        $updateSql = "UPDATE $(Quote-Name $targetTable) SET $setSql WHERE $(Quote-Name $matchColumn) = ?"
                        $affected = Invoke-DbNonQueryParameterized -Connection $TargetConnection -Sql $updateSql -Parameters @($parameters.ToArray())
                        if ([int]$affected -gt 0) { $updatedRows += [int]$affected }
                    }
                }
                catch {
                    if ($Log) { & $Log "Upgrade manual field mapping warning: could not map one $sourceTable row to ${targetTable}: $($_.Exception.Message)" }
                }
                $processedRows++
                if (($processedRows % 25) -eq 0) { Invoke-WOOFUiPulse }
                if (($processedRows % 500) -eq 0 -and $Log) {
                    & $Log "Upgrade manual field mapping still working on ${sourceTable}: $processedRows of $($sourceRows.Rows.Count) row(s) checked."
                }
            }
            if ($Log) {
                $fieldList = [string]::Join(", ", [string[]]@($group.Group | ForEach-Object { "$($_.SourceField)->$($_.TargetField)" }))
                & $Log "Upgrade manual field mapping copied $updatedRows row(s) for ${sourceTable} ($sourceRole) -> ${targetTable} ($targetRole): $fieldList. Matched $matchedSourceRows old row(s); $unmatchedSourceRows old row(s) had no related target row."
                & $warnIfZero $updatedRows $sourceTable $targetTable $fieldList
            }
            continue
        }
        if ([string]::Equals($linkMode, "PlotMeasurementsToPlots", [System.StringComparison]::OrdinalIgnoreCase)) {
            if (-not (Test-ColumnExists -Connection $TargetConnection -TableName "Plots" -ColumnName "PlotID")) { continue }
            $setSql = [string]::Join(", ", [string[]]($group.Group | ForEach-Object { "$(Quote-Name $_.TargetField) = ?" }))
            $updateSql = "UPDATE [Plots] SET $setSql WHERE [PlotID] = ?"
            if ($Log) { & $Log "Upgrade manual field mapping: $sourceTable -> $targetTable through PlotID." }
            Invoke-WOOFUiPulse
            $updatedRows = 0
            $processedRows = 0
            foreach ($row in $sourceRows.Rows) {
                try {
                    $sourcePlotId = Get-DataRowValue -Row $row -ColumnNames @("PlotID")
                    if ($null -eq $sourcePlotId -or $sourcePlotId -is [System.DBNull]) { continue }
                    $parameters = New-Object System.Collections.Generic.List[object]
                    foreach ($fieldMap in $group.Group) {
                        $dataType = Get-UpgradeTargetDataType -DataTypeLookup $targetDataTypes -ColumnName $fieldMap.TargetField
                        [void]$parameters.Add((New-UpgradeImportDbParam -Value $row[$fieldMap.SourceField] -ColumnName $fieldMap.TargetField -ProjectId "" -PeriodIdMap @{} -DataType $dataType))
                    }
                    [void]$parameters.Add((DbGuid $sourcePlotId))
                    $affected = Invoke-DbNonQueryParameterized -Connection $TargetConnection -Sql $updateSql -Parameters @($parameters.ToArray())
                    if ([int]$affected -gt 0) { $updatedRows += [int]$affected }
                }
                catch {
                    if ($Log) { & $Log "Upgrade manual field mapping warning: could not map one $sourceTable row to ${targetTable}: $($_.Exception.Message)" }
                }
                $processedRows++
                if (($processedRows % 25) -eq 0) { Invoke-WOOFUiPulse }
                if (($processedRows % 500) -eq 0 -and $Log) {
                    & $Log "Upgrade manual field mapping still working on ${sourceTable}: $processedRows of $($sourceRows.Rows.Count) row(s) checked."
                }
            }
            if ($Log) {
                $fieldList = [string]::Join(", ", [string[]]@($group.Group | ForEach-Object { "$($_.SourceField)->$($_.TargetField)" }))
                & $Log "Upgrade manual field mapping copied $updatedRows plot row(s) for ${sourceTable} -> ${targetTable}: $fieldList."
                & $warnIfZero $updatedRows $sourceTable $targetTable $fieldList
            }
            continue
        }
        if ([string]::Equals($linkMode, "PlotToPlotMeasurements", [System.StringComparison]::OrdinalIgnoreCase)) {
            if (-not (Test-ColumnExists -Connection $TargetConnection -TableName "PlotMeasurements" -ColumnName "PlotID")) { continue }
            $setSql = [string]::Join(", ", [string[]]($group.Group | ForEach-Object { "$(Quote-Name $_.TargetField) = ?" }))
            $updateSql = "UPDATE [PlotMeasurements] SET $setSql WHERE [PlotID] = ?"
            if ($Log) { & $Log "Upgrade manual field mapping: $sourceTable -> $targetTable through PlotID." }
            Invoke-WOOFUiPulse
            $updatedRows = 0
            $processedRows = 0
            foreach ($row in $sourceRows.Rows) {
                try {
                    $sourcePlotId = Get-DataRowValue -Row $row -ColumnNames @("PlotID")
                    if ($null -eq $sourcePlotId -or $sourcePlotId -is [System.DBNull]) { continue }
                    $parameters = New-Object System.Collections.Generic.List[object]
                    foreach ($fieldMap in $group.Group) {
                        $dataType = Get-UpgradeTargetDataType -DataTypeLookup $targetDataTypes -ColumnName $fieldMap.TargetField
                        [void]$parameters.Add((New-UpgradeImportDbParam -Value $row[$fieldMap.SourceField] -ColumnName $fieldMap.TargetField -ProjectId "" -PeriodIdMap @{} -DataType $dataType))
                    }
                    [void]$parameters.Add((DbGuid $sourcePlotId))
                    $affected = Invoke-DbNonQueryParameterized -Connection $TargetConnection -Sql $updateSql -Parameters @($parameters.ToArray())
                    if ([int]$affected -gt 0) { $updatedRows += [int]$affected }
                }
                catch {
                    if ($Log) { & $Log "Upgrade manual field mapping warning: could not map one $sourceTable row to ${targetTable}: $($_.Exception.Message)" }
                }
                $processedRows++
                if (($processedRows % 25) -eq 0) { Invoke-WOOFUiPulse }
                if (($processedRows % 500) -eq 0 -and $Log) {
                    & $Log "Upgrade manual field mapping still working on ${sourceTable}: $processedRows of $($sourceRows.Rows.Count) row(s) checked."
                }
            }
            if ($Log) {
                $fieldList = [string]::Join(", ", [string[]]@($group.Group | ForEach-Object { "$($_.SourceField)->$($_.TargetField)" }))
                & $Log "Upgrade manual field mapping copied $updatedRows plot measurement row(s) for ${sourceTable} -> ${targetTable}: $fieldList."
                & $warnIfZero $updatedRows $sourceTable $targetTable $fieldList
            }
            continue
        }
        if ([string]::Equals($linkMode, "PlotToPlotCustomMeasurements", [System.StringComparison]::OrdinalIgnoreCase)) {
            if (-not (Test-TableExists -Connection $TargetConnection -TableName "PlotMeasurements")) { continue }
            $plotMeasurementFields = @("MeasurementID", "PlotID")
            if (Test-ColumnExists -Connection $TargetConnection -TableName "PlotMeasurements" -ColumnName "PlotKey") { $plotMeasurementFields += "PlotKey" }
            if (Test-ColumnExists -Connection $TargetConnection -TableName "PlotMeasurements" -ColumnName "PlotMeasKey") { $plotMeasurementFields += "PlotMeasKey" }
            $plotMeasurementSql = "SELECT " + ([string]::Join(", ", [string[]]($plotMeasurementFields | ForEach-Object { Quote-Name $_ }))) + " FROM [PlotMeasurements]"
            $plotMeasurementRows = Get-DbTable -Connection $TargetConnection -Sql $plotMeasurementSql
            $measurementsByPlotKey = @{}
            $addPlotMeasurementLookup = {
                param(
                    [string]$KeyName,
                    [string]$KeyValue,
                    [System.Data.DataRow]$MeasurementRow
                )

                $cleanValue = ConvertTo-BuilderText $KeyValue
                if ([string]::IsNullOrWhiteSpace($cleanValue)) { return }
                $lookupKey = "$($KeyName.ToLowerInvariant())|$($cleanValue.ToLowerInvariant())"
                if (-not $measurementsByPlotKey.ContainsKey($lookupKey)) {
                    $measurementsByPlotKey[$lookupKey] = New-Object System.Collections.Generic.List[object]
                }
                [void]$measurementsByPlotKey[$lookupKey].Add($MeasurementRow)
            }
            foreach ($measurementRow in $plotMeasurementRows.Rows) {
                $measurementPlotId = Get-DataRowText -Row $measurementRow -ColumnNames @("PlotID")
                $measurementPlotKey = Get-DataRowText -Row $measurementRow -ColumnNames @("PlotKey")
                & $addPlotMeasurementLookup "PlotID" $measurementPlotId $measurementRow
                & $addPlotMeasurementLookup "PlotKey" $measurementPlotKey $measurementRow
            }

            $setSql = [string]::Join(", ", [string[]]($group.Group | ForEach-Object { "$(Quote-Name $_.TargetField) = ?" }))
            $updateSql = "UPDATE [PlotCustomMeasurements] SET $setSql WHERE [MeasurementID] = ?"
            if ($Log) { & $Log "Upgrade manual field mapping: $sourceTable -> $targetTable through PlotMeasurements." }
            Invoke-WOOFUiPulse
            $updatedRows = 0
            $processedRows = 0
            $matchedSourceRows = 0
            $unmatchedSourceRows = 0
            foreach ($row in $sourceRows.Rows) {
                try {
                    $sourcePlotIdText = Get-DataRowText -Row $row -ColumnNames @("PlotID")
                    $sourcePlotKeyText = Get-DataRowText -Row $row -ColumnNames @("PlotKey")
                    $matchingMeasurements = New-Object System.Collections.Generic.List[object]
                    $seenMeasurements = @{}
                    foreach ($candidate in @(
                        [pscustomobject]@{ Name = "PlotID"; Value = $sourcePlotIdText },
                        [pscustomobject]@{ Name = "PlotKey"; Value = $sourcePlotKeyText }
                    )) {
                        $candidateValue = ConvertTo-BuilderText $candidate.Value
                        if ([string]::IsNullOrWhiteSpace($candidateValue)) { continue }
                        $lookupKey = "$($candidate.Name.ToLowerInvariant())|$($candidateValue.ToLowerInvariant())"
                        if (-not $measurementsByPlotKey.ContainsKey($lookupKey)) { continue }
                        foreach ($measurementRow in @($measurementsByPlotKey[$lookupKey].ToArray())) {
                            $measurementIdForSeen = Get-DataRowText -Row $measurementRow -ColumnNames @("MeasurementID")
                            if ([string]::IsNullOrWhiteSpace($measurementIdForSeen)) { continue }
                            $seenKey = $measurementIdForSeen.ToLowerInvariant()
                            if ($seenMeasurements.ContainsKey($seenKey)) { continue }
                            $seenMeasurements[$seenKey] = $true
                            [void]$matchingMeasurements.Add($measurementRow)
                        }
                    }
                    if ($matchingMeasurements.Count -eq 0) {
                        $unmatchedSourceRows++
                        continue
                    }
                    $matchedSourceRows++
                    foreach ($measurementRow in @($matchingMeasurements.ToArray())) {
                        $measurementId = Get-DataRowText -Row $measurementRow -ColumnNames @("MeasurementID")
                        if ([string]::IsNullOrWhiteSpace($measurementId)) { continue }
                        $plotMeasKey = Get-DataRowText -Row $measurementRow -ColumnNames @("PlotMeasKey")
                        [void](Add-PlotCustomMeasurementRowIfMissing -Connection $TargetConnection -MeasurementId $measurementId -PlotMeasKey $plotMeasKey)
                        $parameters = New-Object System.Collections.Generic.List[object]
                        foreach ($fieldMap in $group.Group) {
                            $dataType = Get-UpgradeTargetDataType -DataTypeLookup $targetDataTypes -ColumnName $fieldMap.TargetField
                            [void]$parameters.Add((New-UpgradeImportDbParam -Value $row[$fieldMap.SourceField] -ColumnName $fieldMap.TargetField -ProjectId "" -PeriodIdMap @{} -DataType $dataType))
                        }
                        [void]$parameters.Add((DbGuid $measurementId))
                        $affected = Invoke-DbNonQueryParameterized -Connection $TargetConnection -Sql $updateSql -Parameters @($parameters.ToArray())
                        if ([int]$affected -gt 0) { $updatedRows++ }
                    }
                }
                catch {
                    if ($Log) { & $Log "Upgrade manual field mapping warning: could not map one $sourceTable row to ${targetTable}: $($_.Exception.Message)" }
                }
                $processedRows++
                if (($processedRows % 25) -eq 0) { Invoke-WOOFUiPulse }
                if (($processedRows % 500) -eq 0 -and $Log) {
                    & $Log "Upgrade manual field mapping still working on ${sourceTable}: $processedRows of $($sourceRows.Rows.Count) row(s) checked."
                }
            }
            if ($Log) {
                $fieldList = [string]::Join(", ", [string[]]@($group.Group | ForEach-Object { "$($_.SourceField)->$($_.TargetField)" }))
                & $Log "Upgrade manual field mapping copied $updatedRows plot measurement custom row(s) for ${sourceTable} -> ${targetTable}: $fieldList. Matched $matchedSourceRows old plot row(s); $unmatchedSourceRows old plot row(s) had no matching PlotID/PlotKey in PlotMeasurements."
                & $warnIfZero $updatedRows $sourceTable $targetTable $fieldList
            }
            continue
        }
        $targetJoinColumn = Get-ColumnLookupValue -Lookup $targetLookup -ColumnName $joinColumn
        if ([string]::IsNullOrWhiteSpace($targetJoinColumn)) {
            throw "Upgrade Mapping tab: new table $targetTable does not have the required join field $joinColumn."
        }
        $setSql = [string]::Join(", ", [string[]]($group.Group | ForEach-Object { "$(Quote-Name $_.TargetField) = ?" }))
        $updateSql = "UPDATE $(Quote-Name $targetTable) SET $setSql WHERE $(Quote-Name $targetJoinColumn) = ?"
        $alternateJoinColumn = ""
        foreach ($carryColumn in @([string[]]$first.CarryColumns)) {
            if ([string]::Equals((ConvertTo-BuilderText $carryColumn), $joinColumn, [System.StringComparison]::OrdinalIgnoreCase)) { continue }
            $candidate = Get-ColumnLookupValue -Lookup $targetLookup -ColumnName $carryColumn
            if (-not [string]::IsNullOrWhiteSpace($candidate)) {
                $alternateJoinColumn = $candidate
                break
            }
        }
        $alternateUpdateSql = if (-not [string]::IsNullOrWhiteSpace($alternateJoinColumn)) { "UPDATE $(Quote-Name $targetTable) SET $setSql WHERE $(Quote-Name $alternateJoinColumn) = ?" } else { "" }
        if ($Log) { & $Log "Upgrade manual field mapping: $sourceTable -> $targetTable." }
        Invoke-WOOFUiPulse
        $updatedRows = 0
        $processedRows = 0
        $alternateUpdatedRows = 0
        $sourceJoinAliases = @(Get-UpgradeColumnAliases -Domain $first.Domain -ColumnName $joinColumn)
        $alternateSourceJoinAliases = if (-not [string]::IsNullOrWhiteSpace($alternateJoinColumn)) { @(Get-UpgradeColumnAliases -Domain $first.Domain -ColumnName $alternateJoinColumn) } else { @() }
        foreach ($row in $sourceRows.Rows) {
            try {
                if ([bool]$first.CreateMissingTargetRows) {
                    [void](Ensure-UpgradeMeasurementTargetRow -Connection $TargetConnection -SourceRow $row -TargetTableName $targetTable -JoinColumn $joinColumn -CarryColumns ([string[]]$first.CarryColumns) -TargetColumnLookup $targetLookup -TargetDataTypes $targetDataTypes)
                }
                $sourceJoinValue = Get-DataRowValue -Row $row -ColumnNames $sourceJoinAliases
                if ($null -eq $sourceJoinValue -or $sourceJoinValue -is [System.DBNull]) { continue }
                $parameters = New-Object System.Collections.Generic.List[object]
                foreach ($fieldMap in $group.Group) {
                    $dataType = Get-UpgradeTargetDataType -DataTypeLookup $targetDataTypes -ColumnName $fieldMap.TargetField
                    [void]$parameters.Add((New-UpgradeImportDbParam -Value $row[$fieldMap.SourceField] -ColumnName $fieldMap.TargetField -ProjectId "" -PeriodIdMap @{} -DataType $dataType))
                }
                $joinDataType = Get-UpgradeTargetDataType -DataTypeLookup $targetDataTypes -ColumnName $targetJoinColumn
                [void]$parameters.Add((New-UpgradeImportDbParam -Value $sourceJoinValue -ColumnName $targetJoinColumn -ProjectId "" -PeriodIdMap @{} -DataType $joinDataType))
                $affected = Invoke-DbNonQueryParameterized -Connection $TargetConnection -Sql $updateSql -Parameters @($parameters.ToArray())
                if ([int]$affected -gt 0) {
                    $updatedRows += [int]$affected
                }
                elseif (-not [string]::IsNullOrWhiteSpace($alternateUpdateSql)) {
                    $alternateJoinValue = Get-DataRowValue -Row $row -ColumnNames $alternateSourceJoinAliases
                    if ($null -ne $alternateJoinValue -and -not ($alternateJoinValue -is [System.DBNull]) -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $alternateJoinValue))) {
                        $alternateParameters = New-Object System.Collections.Generic.List[object]
                        foreach ($fieldMap in $group.Group) {
                            $dataType = Get-UpgradeTargetDataType -DataTypeLookup $targetDataTypes -ColumnName $fieldMap.TargetField
                            [void]$alternateParameters.Add((New-UpgradeImportDbParam -Value $row[$fieldMap.SourceField] -ColumnName $fieldMap.TargetField -ProjectId "" -PeriodIdMap @{} -DataType $dataType))
                        }
                        $alternateJoinDataType = Get-UpgradeTargetDataType -DataTypeLookup $targetDataTypes -ColumnName $alternateJoinColumn
                        [void]$alternateParameters.Add((New-UpgradeImportDbParam -Value $alternateJoinValue -ColumnName $alternateJoinColumn -ProjectId "" -PeriodIdMap @{} -DataType $alternateJoinDataType))
                        $alternateAffected = Invoke-DbNonQueryParameterized -Connection $TargetConnection -Sql $alternateUpdateSql -Parameters @($alternateParameters.ToArray())
                        if ([int]$alternateAffected -gt 0) {
                            $updatedRows += [int]$alternateAffected
                            $alternateUpdatedRows += [int]$alternateAffected
                        }
                    }
                }
            }
            catch {
                if ($Log) { & $Log "Upgrade manual field mapping warning: could not map one $sourceTable row to ${targetTable}: $($_.Exception.Message)" }
            }
            $processedRows++
            if (($processedRows % 25) -eq 0) { Invoke-WOOFUiPulse }
            if (($processedRows % 500) -eq 0 -and $Log) {
                & $Log "Upgrade manual field mapping still working on ${sourceTable}: $processedRows of $($sourceRows.Rows.Count) row(s) checked."
            }
        }
        if ($Log) {
            $fieldList = [string]::Join(", ", [string[]]@($group.Group | ForEach-Object { "$($_.SourceField)->$($_.TargetField)" }))
            $alternateText = if ($alternateUpdatedRows -gt 0) { " $alternateUpdatedRows row(s) used $alternateJoinColumn fallback." } else { "" }
            & $Log "Upgrade manual field mapping copied $updatedRows row(s) for ${sourceTable} -> ${targetTable}: $fieldList.$alternateText"
            & $warnIfZero $updatedRows $sourceTable $targetTable $fieldList
        }
    }
}

function Get-UpgradeTargetDataTypeLookup {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName
    )

    $lookup = @{}
    foreach ($columnInfo in @(Get-TableColumnInfo -Connection $Connection -TableName $TableName)) {
        $name = ConvertTo-BuilderText $columnInfo.ColumnName
        if ([string]::IsNullOrWhiteSpace($name)) { continue }
        $lookup[$name.ToLowerInvariant()] = ConvertTo-BuilderText $columnInfo.DataType
    }
    return $lookup
}

function Get-UpgradeTargetDataType {
    param(
        [hashtable]$DataTypeLookup,
        [string]$ColumnName
    )

    $clean = ConvertTo-BuilderText $ColumnName
    if ([string]::IsNullOrWhiteSpace($clean)) { return "" }
    $key = $clean.ToLowerInvariant()
    if ($DataTypeLookup.ContainsKey($key)) { return ConvertTo-BuilderText $DataTypeLookup[$key] }
    return ""
}

function Convert-UpgradeDataTypeToAppColumnDataType {
    param([string]$DataType)

    switch ((ConvertTo-BuilderText $DataType).ToLowerInvariant()) {
        "byte" { return "Integer" }
        "short" { return "Integer" }
        "integer" { return "Integer" }
        "long" { return "Long Integer" }
        "single" { return "Single" }
        "double" { return "Double" }
        "currency" { return "Currency" }
        "datetime" { return "Date/Time" }
        "date" { return "Date/Time" }
        "boolean" { return "Boolean" }
        "memo" { return "Memo" }
        "long text" { return "Memo" }
        "text" { return "Text" }
        default { return "Text" }
    }
}

function ConvertTo-AccessExternalDatabasePathLiteral {
    param([string]$Path)

    $clean = ConvertTo-BuilderText $Path
    if ([string]::IsNullOrWhiteSpace($clean)) { return "" }
    return "'" + $clean.Replace("'", "''") + "'"
}

function New-UpgradeMovedFieldTempTableName {
    return "WOOFMoved_" + ([guid]::NewGuid().ToString("N").Substring(0, 16))
}

function Add-UpgradeMovedFieldSnapshotColumn {
    param(
        [System.Collections.Generic.List[string]]$SelectParts,
        [hashtable]$AddedColumns,
        [string]$SourceColumn,
        [string]$TempColumn
    )

    $source = ConvertTo-BuilderText $SourceColumn
    $temp = ConvertTo-BuilderText $TempColumn
    if ([string]::IsNullOrWhiteSpace($source) -or [string]::IsNullOrWhiteSpace($temp)) { return }
    $key = $temp.ToLowerInvariant()
    if ($AddedColumns.ContainsKey($key)) { return }
    [void]$SelectParts.Add("$(Quote-Name $source) AS $(Quote-Name $temp)")
    $AddedColumns[$key] = $temp
}

function New-UpgradeMovedFieldSourceSnapshot {
    param(
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [string]$SourceDatabasePath,
        [string]$SourceTableName,
        [hashtable]$SourceColumnLookup,
        [hashtable]$MovedTargetLookup,
        [string]$JoinColumn,
        [string[]]$CarryColumns,
        [object[]]$FieldMoves,
        [string]$TempTableName
    )

    $sourceSpec = Get-UpgradeMeasurementTableSpec -TableName $SourceTableName
    $sourceDomain = if ($null -ne $sourceSpec) { ConvertTo-BuilderText $sourceSpec.Domain } else { "" }
    $sourceJoinColumn = Get-UpgradeColumnLookupValueWithAliases -Lookup $SourceColumnLookup -Domain $sourceDomain -ColumnName $JoinColumn
    $targetJoinColumn = Get-ColumnLookupValue -Lookup $MovedTargetLookup -ColumnName $JoinColumn
    if ([string]::IsNullOrWhiteSpace($sourceJoinColumn) -or [string]::IsNullOrWhiteSpace($targetJoinColumn)) { return $null }

    $selectParts = New-Object System.Collections.Generic.List[string]
    $addedColumns = @{}
    Add-UpgradeMovedFieldSnapshotColumn -SelectParts $selectParts -AddedColumns $addedColumns -SourceColumn $sourceJoinColumn -TempColumn $targetJoinColumn
    foreach ($columnName in @($CarryColumns)) {
        $sourceColumn = Get-UpgradeColumnLookupValueWithAliases -Lookup $SourceColumnLookup -Domain $sourceDomain -ColumnName $columnName
        $targetColumn = Get-ColumnLookupValue -Lookup $MovedTargetLookup -ColumnName $columnName
        Add-UpgradeMovedFieldSnapshotColumn -SelectParts $selectParts -AddedColumns $addedColumns -SourceColumn $sourceColumn -TempColumn $targetColumn
    }
    foreach ($move in @($FieldMoves)) {
        Add-UpgradeMovedFieldSnapshotColumn -SelectParts $selectParts -AddedColumns $addedColumns -SourceColumn $move.SourceColumn -TempColumn $move.TargetColumn
    }
    if ($selectParts.Count -eq 0) { return $null }

    $externalPath = ConvertTo-AccessExternalDatabasePathLiteral -Path $SourceDatabasePath
    if ([string]::IsNullOrWhiteSpace($externalPath)) { return $null }
    $selectSql = [string]::Join(", ", [string[]]$selectParts.ToArray())
    $sql = "SELECT $selectSql INTO $(Quote-Name $TempTableName) FROM $(Quote-Name $SourceTableName) IN $externalPath WHERE $(Quote-Name $sourceJoinColumn) Is Not Null"
    [void](Invoke-DbNonQuery -Connection $TargetConnection -Sql $sql -CommandTimeoutSeconds 0)

    return [pscustomobject]@{
        SourceJoinColumn = $sourceJoinColumn
        TargetJoinColumn = $targetJoinColumn
        TempJoinColumn = $targetJoinColumn
        TempColumnLookup = New-CaseInsensitiveColumnLookup @(Get-TableColumns -Connection $TargetConnection -TableName $TempTableName)
    }
}

function Invoke-UpgradeMovedFieldBulkInsertMissingRows {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TargetTableName,
        [string]$TempTableName,
        [string]$TargetJoinColumn,
        [string]$TempJoinColumn,
        [string[]]$CarryColumns,
        [hashtable]$TargetColumnLookup,
        [hashtable]$TempColumnLookup
    )

    $pairs = New-Object System.Collections.Generic.List[object]
    foreach ($columnName in @($CarryColumns)) {
        $targetColumn = Get-ColumnLookupValue -Lookup $TargetColumnLookup -ColumnName $columnName
        $tempColumn = Get-ColumnLookupValue -Lookup $TempColumnLookup -ColumnName $targetColumn
        if ([string]::IsNullOrWhiteSpace($targetColumn) -or [string]::IsNullOrWhiteSpace($tempColumn)) { continue }
        if (@($pairs | Where-Object { [string]::Equals($_.TargetColumn, $targetColumn, [System.StringComparison]::OrdinalIgnoreCase) }).Count -gt 0) { continue }
        [void]$pairs.Add([pscustomobject]@{
            TargetColumn = $targetColumn
            TempColumn = $tempColumn
        })
    }
    if ($pairs.Count -eq 0) { return 0 }

    $targetColumnSql = [string]::Join(", ", [string[]]($pairs | ForEach-Object { Quote-Name $_.TargetColumn }))
    $tempColumnSql = [string]::Join(", ", [string[]]($pairs | ForEach-Object { "$(Quote-Name $TempTableName).$(Quote-Name $_.TempColumn)" }))
    $sql = @"
INSERT INTO $(Quote-Name $TargetTableName) ($targetColumnSql)
SELECT $tempColumnSql
FROM $(Quote-Name $TempTableName)
LEFT JOIN $(Quote-Name $TargetTableName)
ON $(Quote-Name $TempTableName).$(Quote-Name $TempJoinColumn) = $(Quote-Name $TargetTableName).$(Quote-Name $TargetJoinColumn)
WHERE $(Quote-Name $TempTableName).$(Quote-Name $TempJoinColumn) Is Not Null
AND $(Quote-Name $TargetTableName).$(Quote-Name $TargetJoinColumn) Is Null
"@
    return Invoke-DbNonQuery -Connection $Connection -Sql $sql -CommandTimeoutSeconds 0
}

function Invoke-UpgradeMovedFieldBulkUpdateRows {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TargetTableName,
        [string]$TempTableName,
        [string]$TargetJoinColumn,
        [string]$TempJoinColumn,
        [object[]]$FieldMoves,
        [hashtable]$TempColumnLookup
    )

    $setParts = New-Object System.Collections.Generic.List[string]
    foreach ($move in @($FieldMoves)) {
        $tempColumn = Get-ColumnLookupValue -Lookup $TempColumnLookup -ColumnName $move.TargetColumn
        if ([string]::IsNullOrWhiteSpace($tempColumn)) { continue }
        [void]$setParts.Add("$(Quote-Name $TargetTableName).$(Quote-Name $move.TargetColumn) = $(Quote-Name $TempTableName).$(Quote-Name $tempColumn)")
    }
    if ($setParts.Count -eq 0) { return 0 }

    $setSql = [string]::Join(", ", [string[]]$setParts.ToArray())
    $sql = @"
UPDATE $(Quote-Name $TargetTableName)
INNER JOIN $(Quote-Name $TempTableName)
ON $(Quote-Name $TargetTableName).$(Quote-Name $TargetJoinColumn) = $(Quote-Name $TempTableName).$(Quote-Name $TempJoinColumn)
SET $setSql
"@
    return Invoke-DbNonQuery -Connection $Connection -Sql $sql -CommandTimeoutSeconds 0
}

function Invoke-UpgradeMovedFieldBulkCopy {
    param(
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [string]$SourceDatabasePath,
        [string]$SourceTableName,
        [string]$MovedTargetTableName,
        [hashtable]$SourceColumnLookup,
        [hashtable]$MovedTargetLookup,
        [string]$JoinColumn,
        [string[]]$CarryColumns,
        [object[]]$FieldMoves,
        [bool]$CreateMissingTargetRows,
        [scriptblock]$Log
    )

    if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $SourceDatabasePath)) -or -not (Test-Path -LiteralPath $SourceDatabasePath)) { return $false }
    $tempTableName = New-UpgradeMovedFieldTempTableName
    $timer = [System.Diagnostics.Stopwatch]::StartNew()
    try {
        $snapshot = New-UpgradeMovedFieldSourceSnapshot -TargetConnection $TargetConnection -SourceDatabasePath $SourceDatabasePath -SourceTableName $SourceTableName -SourceColumnLookup $SourceColumnLookup -MovedTargetLookup $MovedTargetLookup -JoinColumn $JoinColumn -CarryColumns $CarryColumns -FieldMoves $FieldMoves -TempTableName $tempTableName
        if ($null -eq $snapshot) { return $false }

        $insertedRows = 0
        if ($CreateMissingTargetRows) {
            $insertedRows = Invoke-UpgradeMovedFieldBulkInsertMissingRows -Connection $TargetConnection -TargetTableName $MovedTargetTableName -TempTableName $tempTableName -TargetJoinColumn $snapshot.TargetJoinColumn -TempJoinColumn $snapshot.TempJoinColumn -CarryColumns $CarryColumns -TargetColumnLookup $MovedTargetLookup -TempColumnLookup $snapshot.TempColumnLookup
        }
        $updatedRows = Invoke-UpgradeMovedFieldBulkUpdateRows -Connection $TargetConnection -TargetTableName $MovedTargetTableName -TempTableName $tempTableName -TargetJoinColumn $snapshot.TargetJoinColumn -TempJoinColumn $snapshot.TempJoinColumn -FieldMoves $FieldMoves -TempColumnLookup $snapshot.TempColumnLookup
        $timer.Stop()
        if ($Log) {
            $fieldList = [string]::Join(", ", [string[]]@($FieldMoves | ForEach-Object { $_.TargetColumn }))
            $updatedText = if ([int]$updatedRows -ge 0) { "$updatedRows row(s)" } else { "matching row(s)" }
            $insertText = if ($CreateMissingTargetRows) { " Created $insertedRows missing target row(s)." } else { "" }
            & $Log "Upgrade moved-field bulk mapping copied $updatedText from $SourceTableName into $MovedTargetTableName in $(Format-WOOFDuration -Seconds $timer.Elapsed.TotalSeconds).$insertText Field(s): $fieldList."
        }
        return $true
    }
    catch {
        $timer.Stop()
        if ($Log) {
            & $Log "Upgrade moved-field bulk mapping could not be used for $SourceTableName to ${MovedTargetTableName}; Project Pickle will use the slower row-by-row fallback. Access reported: $($_.Exception.Message)"
        }
        return $false
    }
    finally {
        try {
            if (Test-TableExists -Connection $TargetConnection -TableName $tempTableName) {
                [void](Invoke-DbNonQuery -Connection $TargetConnection -Sql "DROP TABLE $(Quote-Name $tempTableName)" -CommandTimeoutSeconds 0)
            }
        }
        catch {
        }
    }
}

function Ensure-UpgradeMeasurementTargetRow {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [System.Data.DataRow]$SourceRow,
        [string]$TargetTableName,
        [string]$JoinColumn,
        [string[]]$CarryColumns,
        [hashtable]$TargetColumnLookup,
        [hashtable]$TargetDataTypes
    )

    $targetSpecForJoin = Get-UpgradeMeasurementTableSpec -TableName $TargetTableName
    $targetDomainForJoin = if ($null -ne $targetSpecForJoin) { ConvertTo-BuilderText $targetSpecForJoin.Domain } else { "" }
    $sourceJoinColumn = Get-UpgradeColumnLookupValueWithAliases -Lookup (New-CaseInsensitiveColumnLookup @($SourceRow.Table.Columns | ForEach-Object { $_.ColumnName })) -Domain $targetDomainForJoin -ColumnName $JoinColumn
    if ([string]::IsNullOrWhiteSpace($sourceJoinColumn)) { return $false }
    $joinValue = $SourceRow[$sourceJoinColumn]
    $targetJoinColumn = Get-ColumnLookupValue -Lookup $TargetColumnLookup -ColumnName $JoinColumn
    if ([string]::IsNullOrWhiteSpace($targetJoinColumn)) { return $false }

    try {
        $existing = Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM $(Quote-Name $TargetTableName) WHERE $(Quote-Name $targetJoinColumn) = $(Sql-Guid $joinValue)"
        if ([int]$existing -gt 0) { return $true }
    }
    catch {
        return $false
    }

    $sourceColumnLookup = New-CaseInsensitiveColumnLookup @($SourceRow.Table.Columns | ForEach-Object { $_.ColumnName })
    $insertColumns = New-Object System.Collections.Generic.List[string]
    $targetSpec = Get-UpgradeMeasurementTableSpec -TableName $TargetTableName
    $targetDomain = if ($null -ne $targetSpec) { ConvertTo-BuilderText $targetSpec.Domain } else { "" }
    foreach ($columnName in @($CarryColumns)) {
        $targetColumn = Get-ColumnLookupValue -Lookup $TargetColumnLookup -ColumnName $columnName
        $sourceColumn = Get-UpgradeColumnLookupValueWithAliases -Lookup $sourceColumnLookup -Domain $targetDomain -ColumnName $columnName
        if ([string]::IsNullOrWhiteSpace($targetColumn) -or [string]::IsNullOrWhiteSpace($sourceColumn)) { continue }
        if (-not $insertColumns.Contains($targetColumn)) { [void]$insertColumns.Add($targetColumn) }
    }
    if ($insertColumns.Count -eq 0) { return $false }

    $columnSql = [string]::Join(", ", [string[]]($insertColumns | ForEach-Object { Quote-Name $_ }))
    $placeholders = [string]::Join(", ", [string[]]($insertColumns | ForEach-Object { "?" }))
    $insertSql = "INSERT INTO $(Quote-Name $TargetTableName) ($columnSql) VALUES ($placeholders)"
    $parameters = New-Object System.Collections.Generic.List[object]
    foreach ($targetColumn in $insertColumns) {
        $sourceColumn = Get-UpgradeColumnLookupValueWithAliases -Lookup $sourceColumnLookup -Domain $targetDomain -ColumnName $targetColumn
        $dataType = Get-UpgradeTargetDataType -DataTypeLookup $TargetDataTypes -ColumnName $targetColumn
        [void]$parameters.Add((New-UpgradeImportDbParam -Value $SourceRow[$sourceColumn] -ColumnName $targetColumn -ProjectId "" -PeriodIdMap @{} -DataType $dataType))
    }
    [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql $insertSql -Parameters @($parameters.ToArray()))
    return $true
}

function Invoke-UpgradeMovedMeasurementFieldImportForDirection {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [string]$SourceDatabasePath,
        [string]$SourceTableName,
        [string]$SameTargetTableName,
        [string]$MovedTargetTableName,
        [string]$JoinColumn,
        [string[]]$CarryColumns,
        [bool]$CreateMissingTargetRows,
        [scriptblock]$Log
    )

    if (-not (Test-TableExists -Connection $SourceConnection -TableName $SourceTableName)) { return }
    if (-not (Test-TableExists -Connection $TargetConnection -TableName $SameTargetTableName)) { return }
    if (-not (Test-TableExists -Connection $TargetConnection -TableName $MovedTargetTableName)) { return }

    $sourceColumns = @(Get-TableColumns -Connection $SourceConnection -TableName $SourceTableName)
    $sameTargetLookup = New-CaseInsensitiveColumnLookup @(Get-TableColumns -Connection $TargetConnection -TableName $SameTargetTableName)
    $movedTargetColumns = @(Get-TableColumns -Connection $TargetConnection -TableName $MovedTargetTableName)
    $movedTargetLookup = New-CaseInsensitiveColumnLookup $movedTargetColumns
    $movedTargetDataTypes = Get-UpgradeTargetDataTypeLookup -Connection $TargetConnection -TableName $MovedTargetTableName

    $fieldMoves = New-Object System.Collections.Generic.List[object]
    foreach ($sourceColumn in $sourceColumns) {
        if (Test-UpgradeMovedFieldExcluded -FieldName $sourceColumn) { continue }
        if (-not [string]::IsNullOrWhiteSpace((Get-ColumnLookupValue -Lookup $sameTargetLookup -ColumnName $sourceColumn))) { continue }
        $targetColumn = Get-ColumnLookupValue -Lookup $movedTargetLookup -ColumnName $sourceColumn
        if ([string]::IsNullOrWhiteSpace($targetColumn)) { continue }
        [void]$fieldMoves.Add([pscustomobject]@{
            SourceColumn = $sourceColumn
            TargetColumn = $targetColumn
        })
    }
    if ($fieldMoves.Count -eq 0) { return }

    if ($Log) { & $Log "Upgrade moved-field mapping: checking $SourceTableName to $MovedTargetTableName." }
    Invoke-WOOFUiPulse
    $sourceLookup = New-CaseInsensitiveColumnLookup $sourceColumns
    if (Invoke-UpgradeMovedFieldBulkCopy -TargetConnection $TargetConnection -SourceDatabasePath $SourceDatabasePath -SourceTableName $SourceTableName -MovedTargetTableName $MovedTargetTableName -SourceColumnLookup $sourceLookup -MovedTargetLookup $movedTargetLookup -JoinColumn $JoinColumn -CarryColumns $CarryColumns -FieldMoves @($fieldMoves.ToArray()) -CreateMissingTargetRows $CreateMissingTargetRows -Log $Log) {
        return
    }

    $sourceRows = Get-DbTable -Connection $SourceConnection -Sql "SELECT * FROM $(Quote-Name $SourceTableName)"
    if ($sourceRows.Rows.Count -eq 0) { return }
    $targetJoinColumn = Get-ColumnLookupValue -Lookup $movedTargetLookup -ColumnName $JoinColumn
    if ([string]::IsNullOrWhiteSpace($targetJoinColumn)) { return }
    $sourceSpec = Get-UpgradeMeasurementTableSpec -TableName $SourceTableName
    $sourceDomain = if ($null -ne $sourceSpec) { ConvertTo-BuilderText $sourceSpec.Domain } else { "" }
    $sourceJoinAliases = @(Get-UpgradeColumnAliases -Domain $sourceDomain -ColumnName $JoinColumn)

    $setSql = [string]::Join(", ", [string[]]($fieldMoves | ForEach-Object { "$(Quote-Name $_.TargetColumn) = ?" }))
    $updateSql = "UPDATE $(Quote-Name $MovedTargetTableName) SET $setSql WHERE $(Quote-Name $targetJoinColumn) = ?"
    $updatedRows = 0
    $processedRows = 0
    foreach ($row in $sourceRows.Rows) {
        try {
            if ($CreateMissingTargetRows) {
                [void](Ensure-UpgradeMeasurementTargetRow -Connection $TargetConnection -SourceRow $row -TargetTableName $MovedTargetTableName -JoinColumn $JoinColumn -CarryColumns $CarryColumns -TargetColumnLookup $movedTargetLookup -TargetDataTypes $movedTargetDataTypes)
            }
            $sourceJoinValue = Get-DataRowValue -Row $row -ColumnNames $sourceJoinAliases
            if ($null -eq $sourceJoinValue -or $sourceJoinValue -is [System.DBNull]) { continue }
            $parameters = New-Object System.Collections.Generic.List[object]
            foreach ($move in $fieldMoves) {
                $dataType = Get-UpgradeTargetDataType -DataTypeLookup $movedTargetDataTypes -ColumnName $move.TargetColumn
                [void]$parameters.Add((New-UpgradeImportDbParam -Value $row[$move.SourceColumn] -ColumnName $move.TargetColumn -ProjectId "" -PeriodIdMap @{} -DataType $dataType))
            }
            $joinDataType = Get-UpgradeTargetDataType -DataTypeLookup $movedTargetDataTypes -ColumnName $targetJoinColumn
            [void]$parameters.Add((New-UpgradeImportDbParam -Value $sourceJoinValue -ColumnName $targetJoinColumn -ProjectId "" -PeriodIdMap @{} -DataType $joinDataType))
            $affected = Invoke-DbNonQueryParameterized -Connection $TargetConnection -Sql $updateSql -Parameters @($parameters.ToArray())
            if ([int]$affected -gt 0) { $updatedRows++ }
        }
        catch {
            if ($Log) { & $Log "Upgrade moved-field warning: could not move one $SourceTableName row into ${MovedTargetTableName}: $($_.Exception.Message)" }
        }
        $processedRows++
        if (($processedRows % 25) -eq 0) { Invoke-WOOFUiPulse }
        if (($processedRows % 500) -eq 0 -and $Log) {
            & $Log "Upgrade moved-field mapping still working on ${SourceTableName}: $processedRows of $($sourceRows.Rows.Count) row(s) checked."
        }
    }

    if ($updatedRows -gt 0 -and $Log) {
        $fieldList = [string]::Join(", ", [string[]]@($fieldMoves | ForEach-Object { $_.TargetColumn }))
        & $Log "Upgrade import moved $updatedRows row(s) from $SourceTableName into $MovedTargetTableName for field(s): $fieldList."
    }
}

function Invoke-UpgradeMovedMeasurementFieldImport {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [string]$SourceDatabasePath,
        [scriptblock]$Log
    )

    $groups = @(
        @{ Base = "PlotMeasurements"; Custom = "PlotCustomMeasurements"; Key = "MeasurementID"; Carry = @("MeasurementID", "PlotMeasKey") },
        @{ Base = "TreeMeasurements"; Custom = "TreeCustomMeasurements"; Key = "MeasurementID"; Carry = @("MeasurementID", "TreeMeasKey") },
        @{ Base = "RegenMeasurements"; Custom = "RegenCustomMeasurements"; Key = "MeasurementID"; Carry = @("MeasurementID", "RegenMeasKey") }
    )

    foreach ($group in $groups) {
        Invoke-UpgradeMovedMeasurementFieldImportForDirection -SourceConnection $SourceConnection -TargetConnection $TargetConnection -SourceDatabasePath $SourceDatabasePath -SourceTableName $group.Base -SameTargetTableName $group.Base -MovedTargetTableName $group.Custom -JoinColumn $group.Key -CarryColumns $group.Carry -CreateMissingTargetRows $true -Log $Log
        Invoke-UpgradeMovedMeasurementFieldImportForDirection -SourceConnection $SourceConnection -TargetConnection $TargetConnection -SourceDatabasePath $SourceDatabasePath -SourceTableName $group.Custom -SameTargetTableName $group.Custom -MovedTargetTableName $group.Base -JoinColumn $group.Key -CarryColumns @($group.Key) -CreateMissingTargetRows $false -Log $Log
    }
}

function Get-UpgradePeriodCountSummaryForTable {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName
    )

    if (-not (Test-TableExists -Connection $Connection -TableName $TableName)) { return "" }
    $columns = @(Get-TableColumns -Connection $Connection -TableName $TableName)
    $periodColumn = @($columns | Where-Object { $_ -in @("PeriodNumber", "MeasurementPeriodNumber", "MeasurementPeriod", "Period") } | Select-Object -First 1)
    if ($periodColumn.Count -eq 0) { return "" }
    $periodColumnName = ConvertTo-BuilderText $periodColumn[0]
    if ([string]::IsNullOrWhiteSpace($periodColumnName)) { return "" }

    $rows = Get-DbTable -Connection $Connection -Sql "SELECT $(Quote-Name $periodColumnName) AS [PeriodNumber], Count(*) AS [RowCount] FROM $(Quote-Name $TableName) GROUP BY $(Quote-Name $periodColumnName) ORDER BY $(Quote-Name $periodColumnName)"
    $parts = New-Object System.Collections.Generic.List[string]
    foreach ($row in $rows.Rows) {
        $periodNumber = Get-DataRowText -Row $row -ColumnNames @("PeriodNumber")
        if ([string]::IsNullOrWhiteSpace($periodNumber)) { $periodNumber = "(blank)" }
        $rowCount = Get-DataRowText -Row $row -ColumnNames @("RowCount")
        [void]$parts.Add("${periodNumber}=$rowCount")
    }
    return [string]::Join(", ", [string[]]$parts.ToArray())
}

function Write-UpgradeMeasurementPeriodImportSummary {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [string]$TableName,
        [scriptblock]$Log
    )

    if ($TableName -notin @("PlotMeasurements", "TreeMeasurements", "RegenMeasurements")) { return }
    if (-not $Log) { return }
    try {
        $sourceSummary = Get-UpgradePeriodCountSummaryForTable -Connection $SourceConnection -TableName $TableName
        $targetSummary = Get-UpgradePeriodCountSummaryForTable -Connection $TargetConnection -TableName $TableName
        if ([string]::IsNullOrWhiteSpace($sourceSummary) -and [string]::IsNullOrWhiteSpace($targetSummary)) { return }
        $message = "Upgrade import period check for ${TableName}: old [$sourceSummary], output [$targetSummary]."
        if (-not [string]::Equals($sourceSummary, $targetSummary, [System.StringComparison]::OrdinalIgnoreCase)) {
            $message = "Upgrade import period warning for ${TableName}: old [$sourceSummary], output [$targetSummary]."
        }
        & $Log $message
    }
    catch {
        & $Log "Upgrade import period check for ${TableName} could not be completed: $($_.Exception.Message)"
    }
}

function Get-UpgradeTableRowCountSafe {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName
    )

    try {
        if (-not (Test-TableExists -Connection $Connection -TableName $TableName)) { return $null }
        $value = Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM $(Quote-Name $TableName)"
        if ($null -eq $value -or $value -is [System.DBNull]) { return 0 }
        return [int64]$value
    }
    catch {
        return $null
    }
}

function Get-UpgradeNonNullColumnCountSafe {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName,
        [string]$ColumnName
    )

    try {
        if (-not (Test-TableExists -Connection $Connection -TableName $TableName)) { return $null }
        if (-not (Test-ColumnExists -Connection $Connection -TableName $TableName -ColumnName $ColumnName)) { return $null }
        $value = Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM $(Quote-Name $TableName) WHERE $(Quote-Name $ColumnName) Is Not Null"
        if ($null -eq $value -or $value -is [System.DBNull]) { return 0 }
        return [int64]$value
    }
    catch {
        return $null
    }
}

function Format-UpgradeDiagnosticCount {
    param([object]$Count)

    if ($null -eq $Count) { return "not available" }
    return ([int64]$Count).ToString("N0")
}

function Get-UpgradeMissingJoinCountSafe {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$LeftTable,
        [string]$RightTable,
        [string]$JoinColumn
    )

    try {
        if (-not (Test-TableExists -Connection $Connection -TableName $LeftTable)) { return $null }
        if (-not (Test-TableExists -Connection $Connection -TableName $RightTable)) { return $null }
        if (-not (Test-ColumnExists -Connection $Connection -TableName $LeftTable -ColumnName $JoinColumn)) { return $null }
        if (-not (Test-ColumnExists -Connection $Connection -TableName $RightTable -ColumnName $JoinColumn)) { return $null }
        $leftJoin = "$(Quote-Name $LeftTable).$(Quote-Name $JoinColumn)"
        $rightJoin = "$(Quote-Name $RightTable).$(Quote-Name $JoinColumn)"
        $sql = "SELECT Count(*) FROM $(Quote-Name $LeftTable) LEFT JOIN $(Quote-Name $RightTable) ON $leftJoin = $rightJoin WHERE $leftJoin Is Not Null AND $rightJoin Is Null"
        $value = Get-DbScalar -Connection $Connection -Sql $sql
        if ($null -eq $value -or $value -is [System.DBNull]) { return 0 }
        return [int64]$value
    }
    catch {
        return $null
    }
}

function Get-UpgradeMissingJoinSampleText {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$LeftTable,
        [string]$RightTable,
        [string]$JoinColumn,
        [string[]]$SampleColumns
    )

    try {
        if (-not (Test-TableExists -Connection $Connection -TableName $LeftTable)) { return "" }
        if (-not (Test-TableExists -Connection $Connection -TableName $RightTable)) { return "" }
        $leftColumns = @(Get-TableColumns -Connection $Connection -TableName $LeftTable)
        $rightColumns = @(Get-TableColumns -Connection $Connection -TableName $RightTable)
        if ($leftColumns -notcontains $JoinColumn -or $rightColumns -notcontains $JoinColumn) { return "" }
        $displayColumns = @($SampleColumns | Where-Object { $leftColumns -contains $_ } | Select-Object -Unique)
        if ($displayColumns.Count -eq 0) { $displayColumns = @($JoinColumn) }
        $selectSql = [string]::Join(", ", [string[]]($displayColumns | ForEach-Object { "$(Quote-Name $LeftTable).$(Quote-Name $_) AS $(Quote-Name $_)" }))
        $leftJoin = "$(Quote-Name $LeftTable).$(Quote-Name $JoinColumn)"
        $rightJoin = "$(Quote-Name $RightTable).$(Quote-Name $JoinColumn)"
        $sql = "SELECT TOP 10 $selectSql FROM $(Quote-Name $LeftTable) LEFT JOIN $(Quote-Name $RightTable) ON $leftJoin = $rightJoin WHERE $leftJoin Is Not Null AND $rightJoin Is Null"
        $rows = Get-DbTable -Connection $Connection -Sql $sql
        if ($rows.Rows.Count -eq 0) { return "" }
        $samples = New-Object System.Collections.Generic.List[string]
        foreach ($row in $rows.Rows) {
            $parts = New-Object System.Collections.Generic.List[string]
            foreach ($columnName in $displayColumns) {
                if ($row.Table.Columns.Contains($columnName)) {
                    $value = ConvertTo-BuilderText $row[$columnName]
                    if ([string]::IsNullOrWhiteSpace($value)) { $value = "(blank)" }
                    [void]$parts.Add("${columnName}=$value")
                }
            }
            if ($parts.Count -gt 0) { [void]$samples.Add([string]::Join("; ", [string[]]$parts.ToArray())) }
        }
        return [string]::Join(" | ", [string[]]$samples.ToArray())
    }
    catch {
        return ""
    }
}

function Write-UpgradePostImportDiagnostics {
    param(
        [System.Data.OleDb.OleDbConnection]$SourceConnection,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [scriptblock]$Log
    )

    if (-not $Log) { return }
    try {
        & $Log "Upgrade diagnostics: checking row counts, period counts, and measurement links after import, moved-field mapping, and repair."
        $tables = @(
            "Plots",
            "PlotMeasurements",
            "PlotCustomMeasurements",
            "Trees",
            "TreeMeasurements",
            "TreeCustomMeasurements",
            "RegenMeasurements",
            "RegenCustomMeasurements",
            "InventoryCrews",
            "InventoryAssignments",
            "InventoryAssignmentPlots",
            "InventoryAssignmentTrees"
        )
        foreach ($tableName in $tables) {
            $oldCount = Get-UpgradeTableRowCountSafe -Connection $SourceConnection -TableName $tableName
            $outputCount = Get-UpgradeTableRowCountSafe -Connection $TargetConnection -TableName $tableName
            $prefix = "Upgrade diagnostics row count"
            if ($null -ne $oldCount -and $null -ne $outputCount -and [int64]$oldCount -ne [int64]$outputCount) {
                $prefix = "Upgrade diagnostics row count warning"
            }
            & $Log ("${prefix}: ${tableName} old={0}, output={1}." -f (Format-UpgradeDiagnosticCount -Count $oldCount), (Format-UpgradeDiagnosticCount -Count $outputCount))
        }

        foreach ($tableName in @("PlotMeasurements", "TreeMeasurements", "RegenMeasurements")) {
            $sourceSummary = Get-UpgradePeriodCountSummaryForTable -Connection $SourceConnection -TableName $tableName
            $targetSummary = Get-UpgradePeriodCountSummaryForTable -Connection $TargetConnection -TableName $tableName
            if ([string]::IsNullOrWhiteSpace($sourceSummary) -and [string]::IsNullOrWhiteSpace($targetSummary)) { continue }
            $prefix = "Upgrade diagnostics period counts"
            if (-not [string]::Equals($sourceSummary, $targetSummary, [System.StringComparison]::OrdinalIgnoreCase)) {
                $prefix = "Upgrade diagnostics period count warning"
            }
            & $Log "${prefix}: ${tableName} old [$sourceSummary], output [$targetSummary]."
        }

        $coverageSpecs = @(
            [pscustomobject]@{ MeasurementTable = "PlotMeasurements"; CustomTable = "PlotCustomMeasurements"; ParentTable = "Plots"; ParentKey = "PlotID"; SampleColumns = @("MeasurementID", "PlotID", "PlotKey", "PlotMeasKey", "PeriodNumber", "PlotNumber") },
            [pscustomobject]@{ MeasurementTable = "TreeMeasurements"; CustomTable = "TreeCustomMeasurements"; ParentTable = "Trees"; ParentKey = "TreeID"; SampleColumns = @("MeasurementID", "TreeID", "TreeKey", "TreeMeasKey", "PlotID", "PlotKey", "PeriodNumber", "TreeNumber") },
            [pscustomobject]@{ MeasurementTable = "RegenMeasurements"; CustomTable = "RegenCustomMeasurements"; ParentTable = "Plots"; ParentKey = "PlotID"; SampleColumns = @("MeasurementID", "PlotID", "PlotKey", "RegenMeasKey", "PeriodNumber", "PlotNumber") }
        )
        foreach ($spec in $coverageSpecs) {
            $measurementRows = Get-UpgradeTableRowCountSafe -Connection $TargetConnection -TableName $spec.MeasurementTable
            $customRows = Get-UpgradeTableRowCountSafe -Connection $TargetConnection -TableName $spec.CustomTable
            $missingCustomRows = Get-UpgradeMissingJoinCountSafe -Connection $TargetConnection -LeftTable $spec.MeasurementTable -RightTable $spec.CustomTable -JoinColumn "MeasurementID"
            $orphanCustomRows = Get-UpgradeMissingJoinCountSafe -Connection $TargetConnection -LeftTable $spec.CustomTable -RightTable $spec.MeasurementTable -JoinColumn "MeasurementID"
            & $Log ("Upgrade diagnostics custom coverage: {0} rows={1}; {2} rows={3}; measurement rows missing custom row={4}; custom rows without measurement row={5}." -f $spec.MeasurementTable, (Format-UpgradeDiagnosticCount -Count $measurementRows), $spec.CustomTable, (Format-UpgradeDiagnosticCount -Count $customRows), (Format-UpgradeDiagnosticCount -Count $missingCustomRows), (Format-UpgradeDiagnosticCount -Count $orphanCustomRows))
            if ($null -ne $missingCustomRows -and [int64]$missingCustomRows -gt 0) {
                $sampleText = Get-UpgradeMissingJoinSampleText -Connection $TargetConnection -LeftTable $spec.MeasurementTable -RightTable $spec.CustomTable -JoinColumn "MeasurementID" -SampleColumns $spec.SampleColumns
                if (-not [string]::IsNullOrWhiteSpace($sampleText)) {
                    & $Log "Upgrade diagnostics sample rows missing $($spec.CustomTable): $sampleText"
                }
            }

            $rowsWithParentKey = Get-UpgradeNonNullColumnCountSafe -Connection $TargetConnection -TableName $spec.MeasurementTable -ColumnName $spec.ParentKey
            $missingParentRows = Get-UpgradeMissingJoinCountSafe -Connection $TargetConnection -LeftTable $spec.MeasurementTable -RightTable $spec.ParentTable -JoinColumn $spec.ParentKey
            & $Log ("Upgrade diagnostics parent coverage: {0} rows with {1}={2}; missing matching {3} rows={4}." -f $spec.MeasurementTable, $spec.ParentKey, (Format-UpgradeDiagnosticCount -Count $rowsWithParentKey), $spec.ParentTable, (Format-UpgradeDiagnosticCount -Count $missingParentRows))
            if ($null -ne $missingParentRows -and [int64]$missingParentRows -gt 0) {
                $sampleText = Get-UpgradeMissingJoinSampleText -Connection $TargetConnection -LeftTable $spec.MeasurementTable -RightTable $spec.ParentTable -JoinColumn $spec.ParentKey -SampleColumns $spec.SampleColumns
                if (-not [string]::IsNullOrWhiteSpace($sampleText)) {
                    & $Log "Upgrade diagnostics sample rows missing $($spec.ParentTable): $sampleText"
                }
            }
        }
    }
    catch {
        & $Log "Upgrade diagnostics could not be completed: $($_.Exception.Message)"
    }
}

function Invoke-UpgradeDataImport {
    param(
        [string]$OldDatabasePath,
        [System.Data.OleDb.OleDbConnection]$TargetConnection,
        [string]$ProjectId,
        [object[]]$Periods,
        [object[]]$FieldMappings = @(),
        [scriptblock]$Log
    )

    if ([string]::IsNullOrWhiteSpace($OldDatabasePath) -or -not (Test-Path -LiteralPath $OldDatabasePath)) {
        throw "Upgrade mode needs the old project database selected in the Existing/old project database box."
    }

    $tables = @(
        "Plots",
        "PlotMeasurements",
        "PlotCustomMeasurements",
        "Trees",
        "TreeMeasurements",
        "TreeCustomMeasurements",
        "RegenMeasurements",
        "RegenCustomMeasurements",
        "InventoryCrews",
        "InventoryAssignments",
        "InventoryAssignmentPlots",
        "InventoryAssignmentTrees"
    )

    & $Log "Upgrade mode: importing compatible project data from the old database."
    $sourceConnection = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $OldDatabasePath)
    try {
        $periodIdMap = New-UpgradePeriodIdMap -SourceConnection $sourceConnection -OutputPeriods $Periods
        $outputPeriodIdByNumber = New-UpgradeOutputPeriodIdByNumber -OutputPeriods $Periods
        foreach ($tableName in @($tables | Select-Object -Last $tables.Count | Sort-Object { [array]::IndexOf($tables, $_) } -Descending)) {
            if (Test-TableExists -Connection $TargetConnection -TableName $tableName) {
                try { [void](Invoke-DbNonQuery -Connection $TargetConnection -Sql "DELETE FROM $(Quote-Name $tableName)") } catch {}
            }
        }

        foreach ($tableName in $tables) {
            if (-not (Test-TableExists -Connection $sourceConnection -TableName $tableName)) {
                & $Log "Upgrade import skipped $tableName because it was not found in the old database."
                continue
            }
            if (-not (Test-TableExists -Connection $TargetConnection -TableName $tableName)) {
                & $Log "Upgrade import skipped $tableName because it is not in the current master database version."
                continue
            }

            $sourceColumns = @(Get-TableColumns -Connection $sourceConnection -TableName $tableName)
            $sourceColumnLookup = New-CaseInsensitiveColumnLookup $sourceColumns
            $tableSpecForImport = Get-UpgradeMeasurementTableSpec -TableName $tableName
            $importDomain = if ($null -ne $tableSpecForImport) { ConvertTo-BuilderText $tableSpecForImport.Domain } else { "" }
            $targetColumnInfo = @(Get-TableColumnInfo -Connection $TargetConnection -TableName $tableName)
            $targetColumns = @($targetColumnInfo | ForEach-Object { $_.ColumnName })
            $targetDataTypes = @{}
            foreach ($columnInfo in $targetColumnInfo) {
                $targetDataTypes[$columnInfo.ColumnName] = ConvertTo-BuilderText $columnInfo.DataType
            }
            $commonColumns = @($targetColumns | Where-Object {
                $targetColumn = ConvertTo-BuilderText $_
                -not [string]::IsNullOrWhiteSpace((Get-UpgradeColumnLookupValueWithAliases -Lookup $sourceColumnLookup -Domain $importDomain -ColumnName $targetColumn))
            })
            if ($commonColumns.Count -eq 0) {
                & $Log "Upgrade import skipped $tableName because no matching fields were found."
                continue
            }

            $missingColumns = @($sourceColumns | Where-Object { ($targetColumns -notcontains $_) -and -not (Test-UpgradeMappingReviewFieldExcluded -TableName $tableName -FieldName $_) })
            if ($missingColumns.Count -gt 0) {
                & $Log "Upgrade import note: $tableName has old field(s) not in the same selected-template table. Project Pickle will try same-named plot/tree/regen moved-field mapping after the main import, then skip anything still unmapped: $([string]::Join(', ', [string[]]$missingColumns))"
            }

            & $Log "Upgrade import reading $tableName rows. Large tables can take a few minutes."
            Invoke-WOOFUiPulse
            $sourceRowCount = [int](Get-DbScalar -Connection $sourceConnection -Sql "SELECT Count(*) FROM $(Quote-Name $tableName)")
            if ($sourceRowCount -eq 0) {
                & $Log "Upgrade import: $tableName had no rows to import."
                continue
            }

            $columnSql = [string]::Join(", ", [string[]]($commonColumns | ForEach-Object { Quote-Name $_ }))
            $placeholders = [string]::Join(", ", [string[]]($commonColumns | ForEach-Object { "?" }))
            $insertSql = "INSERT INTO $(Quote-Name $tableName) ($columnSql) VALUES ($placeholders)"
            $imported = 0
            $processed = 0
            $failed = 0
            $tableTimer = [System.Diagnostics.Stopwatch]::StartNew()
            $readCommand = $sourceConnection.CreateCommand()
            $readCommand.CommandText = "SELECT * FROM $(Quote-Name $tableName)"
            $reader = $null
            $insertCommand = $null
            try {
                $prototypeParameters = New-Object System.Collections.Generic.List[object]
                foreach ($columnName in $commonColumns) {
                    [void]$prototypeParameters.Add((New-EmptyUpgradeImportDbParam -DataType $targetDataTypes[$columnName]))
                }
                $insertCommand = New-DbParameterizedCommand -Connection $TargetConnection -Sql $insertSql -Parameters @($prototypeParameters.ToArray())
                $reader = $readCommand.ExecuteReader()
                while ($reader.Read()) {
                    $valuesByColumn = @{}
                    try {
                        $rowPeriodNumberValue = $null
                        $periodNumberSourceColumn = Get-ColumnLookupValue -Lookup $sourceColumnLookup -ColumnName "PeriodNumber"
                        if (-not [string]::IsNullOrWhiteSpace($periodNumberSourceColumn)) {
                            try { $rowPeriodNumberValue = $reader[$periodNumberSourceColumn] } catch { $rowPeriodNumberValue = $null }
                        }
                        foreach ($columnName in $commonColumns) {
                            $sourceColumnName = Get-UpgradeColumnLookupValueWithAliases -Lookup $sourceColumnLookup -Domain $importDomain -ColumnName $columnName
                            $sourceValue = $reader[$sourceColumnName]
                            if ([string]::Equals((ConvertTo-BuilderText $columnName), "ProjectPeriodID", [System.StringComparison]::OrdinalIgnoreCase)) {
                                $sourceValue = Resolve-UpgradeProjectPeriodIdValue -Value $sourceValue -PeriodNumber $rowPeriodNumberValue -PeriodIdMap $periodIdMap -OutputPeriodIdByNumber $outputPeriodIdByNumber
                            }
                            $valuesByColumn[$columnName] = $sourceValue
                        }

                        $parameters = New-Object System.Collections.Generic.List[object]
                        foreach ($columnName in $commonColumns) {
                            $sourceValue = $valuesByColumn[$columnName]
                            [void]$parameters.Add((New-UpgradeImportDbParam -Value $sourceValue -ColumnName $columnName -ProjectId $ProjectId -PeriodIdMap $periodIdMap -DataType $targetDataTypes[$columnName]))
                        }
                        [void](Invoke-DbPreparedNonQuery -Command $insertCommand -Sql $insertSql -Parameters @($parameters.ToArray()))
                        $imported++
                    }
                    catch {
                        $recovered = $false
                        if ($valuesByColumn.Count -gt 0) {
                            try {
                                $recovered = Invoke-UpgradeRecoverableRowInsert -Connection $TargetConnection -TableName $tableName -Columns ([string[]]$commonColumns) -ValuesByColumn $valuesByColumn -TargetDataTypes $targetDataTypes -ProjectId $ProjectId -PeriodIdMap $periodIdMap -Log $Log
                            }
                            catch {
                                $recovered = $false
                            }
                        }
                        if ($recovered) {
                            $imported++
                        }
                        else {
                            $failed++
                            & $Log "Upgrade import warning: could not import one row into ${tableName}: $($_.Exception.Message)"
                        }
                    }
                    $processed++
                    if (($processed % 100) -eq 0) { Invoke-WOOFUiPulse }
                    if (($processed % 500) -eq 0) {
                        & $Log "Upgrade import still working on ${tableName}: $processed of $sourceRowCount row(s) checked, $imported copied."
                    }
                }
            }
            finally {
                if ($null -ne $reader) {
                    try { $reader.Close() } catch {}
                    try { $reader.Dispose() } catch {}
                }
                $readCommand.Dispose()
                if ($null -ne $insertCommand) { $insertCommand.Dispose() }
            }
            $tableTimer.Stop()
            $failedText = if ($failed -gt 0) { " $failed row(s) failed." } else { "" }
            $rateText = ""
            if ($imported -gt 0 -and $tableTimer.Elapsed.TotalSeconds -gt 0) {
                $rateText = " $([Math]::Round(($imported / $tableTimer.Elapsed.TotalSeconds), 1)) row(s)/sec."
            }
            & $Log "Upgrade import copied $imported row(s) into $tableName in $(Format-WOOFDuration -Seconds $tableTimer.Elapsed.TotalSeconds).$rateText$failedText"
            Write-UpgradeMeasurementPeriodImportSummary -SourceConnection $sourceConnection -TargetConnection $TargetConnection -TableName $tableName -Log $Log
        }

        Invoke-UpgradeMovedMeasurementFieldImport -SourceConnection $sourceConnection -TargetConnection $TargetConnection -SourceDatabasePath $OldDatabasePath -Log $Log
        Invoke-UpgradeRepairMissingInventoryRows -SourceConnection $sourceConnection -TargetConnection $TargetConnection -ProjectId $ProjectId -Log $Log
        Invoke-UpgradeManualFieldMappings -SourceConnection $sourceConnection -TargetConnection $TargetConnection -FieldMappings $FieldMappings -Log $Log
        Invoke-UpgradeRepairMissingInventoryRows -SourceConnection $sourceConnection -TargetConnection $TargetConnection -ProjectId $ProjectId -Log $Log
        Write-UpgradePostImportDiagnostics -SourceConnection $sourceConnection -TargetConnection $TargetConnection -Log $Log
        Set-ProjectIdInAllTables -Connection $TargetConnection -ProjectId $ProjectId -Log $Log
    }
    finally {
        if ($sourceConnection.State -eq "Open") { $sourceConnection.Close() }
        $sourceConnection.Dispose()
    }
}

function Set-OptionalPlotImportField {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$PlotId,
        [string]$TargetColumn,
        [object]$Value,
        [hashtable]$PlotDataTypes
    )

    if (-not (Test-ColumnExists -Connection $Connection -TableName "Plots" -ColumnName $TargetColumn)) { return $false }
    if ([string]::IsNullOrWhiteSpace($value)) { return $false }
    $dataType = Get-UpgradeTargetDataType -DataTypeLookup $PlotDataTypes -ColumnName $TargetColumn
    [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "UPDATE [Plots] SET $(Quote-Name $TargetColumn) = ? WHERE [PlotID] = ?" -Parameters @(
        (New-UpgradeImportDbParam -Value $value -ColumnName $TargetColumn -ProjectId "" -PeriodIdMap @{} -DataType $dataType),
        (DbGuid $PlotId)
    ))
    return $true
}

function Get-PlotImportFieldSpecs {
    return @(
        [pscustomobject]@{ FieldName = "PlotNumber"; Required = $true; Aliases = @("PlotNumber", "Plot Number", "Plot", "PlotNo", "Plot No", "Plot #", "Plot_Num", "PlotIDNumber") },
        [pscustomobject]@{ FieldName = "PlotLabel"; Required = $false; Aliases = @("PlotLabel", "Plot Label", "Label") },
        [pscustomobject]@{ FieldName = "PlotTypeID"; Required = $false; Aliases = @("PlotTypeID", "Plot Type", "PlotType", "Plot Type ID") },
        [pscustomobject]@{ FieldName = "UTMNorthingCoordinate"; Required = $false; Aliases = @("UTMNorthingCoordinate", "UTM Northing", "Northing", "UTMNorthing") },
        [pscustomobject]@{ FieldName = "UTMEastingCoordinate"; Required = $false; Aliases = @("UTMEastingCoordinate", "UTM Easting", "Easting", "UTMEasting") },
        [pscustomobject]@{ FieldName = "UTMZone"; Required = $false; Aliases = @("UTMZone", "UTM Zone", "Zone") },
        [pscustomobject]@{ FieldName = "FLCCommercial"; Required = $false; Aliases = @("FLCCommercial", "FLC Commercial", "FLC Comm", "FLC") }
    )
}

function ConvertTo-ColumnMatchKey {
    param([string]$Text)

    $clean = ConvertTo-BuilderText $Text
    if ([string]::IsNullOrWhiteSpace($clean)) { return "" }
    return ([regex]::Replace($clean.ToLowerInvariant(), "[^a-z0-9]", ""))
}

function Find-BestPlotImportColumn {
    param(
        [string[]]$Columns,
        [string[]]$Aliases
    )

    foreach ($alias in @($Aliases)) {
        foreach ($column in @($Columns)) {
            if ([string]::Equals((ConvertTo-BuilderText $column), (ConvertTo-BuilderText $alias), [System.StringComparison]::OrdinalIgnoreCase)) {
                return ConvertTo-BuilderText $column
            }
        }
    }
    foreach ($alias in @($Aliases)) {
        $aliasKey = ConvertTo-ColumnMatchKey $alias
        if ([string]::IsNullOrWhiteSpace($aliasKey)) { continue }
        foreach ($column in @($Columns)) {
            if ((ConvertTo-ColumnMatchKey $column) -eq $aliasKey) {
                return ConvertTo-BuilderText $column
            }
        }
    }
    return ""
}

function Get-PlotImportMappedSourceColumn {
    param(
        [object[]]$Mappings,
        [string]$FieldName
    )

    $cleanFieldName = ConvertTo-BuilderText $FieldName
    foreach ($mapping in @($Mappings)) {
        if ([string]::Equals((ConvertTo-BuilderText $mapping.FieldName), $cleanFieldName, [System.StringComparison]::OrdinalIgnoreCase)) {
            return ConvertTo-BuilderText $mapping.SourceColumn
        }
    }
    return ""
}

function Get-PlotImportValue {
    param(
        [object]$Row,
        [string]$FieldName,
        [object[]]$Mappings
    )

    $mappingCount = @($Mappings).Count
    if ($mappingCount -gt 0) {
        $sourceColumn = Get-PlotImportMappedSourceColumn -Mappings $Mappings -FieldName $FieldName
        if ([string]::IsNullOrWhiteSpace($sourceColumn)) { return "" }
        return Get-ObjectPropertyText -Object $Row -Names @($sourceColumn)
    }

    $spec = @(Get-PlotImportFieldSpecs | Where-Object { [string]::Equals($_.FieldName, $FieldName, [System.StringComparison]::OrdinalIgnoreCase) } | Select-Object -First 1)
    if ($spec.Count -eq 0) { return "" }
    return Get-ObjectPropertyText -Object $Row -Names ([string[]]$spec[0].Aliases)
}

function Import-Plots {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$Path,
        [string]$ProjectId,
        [object[]]$Periods,
        [object[]]$PlotImportMappings = @(),
        [scriptblock]$Log
    )

    if ([string]::IsNullOrWhiteSpace($Path)) {
        & $Log "No plot import selected. Plot import skipped; assignment setup can use existing plot rows if they are already in the database."
        return 0
    }

    $rows = @(Import-TabularRows -Path $Path)
    if ($rows.Count -eq 0) { throw "The Add New Plots file did not contain any rows." }
    $seen = @{}
    $inserted = 0
    $skippedBlank = 0
    $skippedExisting = 0
    $plotDataTypes = Get-UpgradeTargetDataTypeLookup -Connection $Connection -TableName "Plots"
    $rowNumber = 2
    foreach ($row in $rows) {
        $numberText = Get-PlotImportValue -Row $row -FieldName "PlotNumber" -Mappings $PlotImportMappings
        if ([string]::IsNullOrWhiteSpace($numberText)) {
            $hasAnyRowValue = $false
            foreach ($property in @($row.PSObject.Properties)) {
                if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $property.Value))) {
                    $hasAnyRowValue = $true
                    break
                }
            }
            if (-not $hasAnyRowValue) {
                $skippedBlank++
                $rowNumber++
                continue
            }
            throw "Add New Plots row $rowNumber is missing PlotNumber. On the Plots tab, click Load columns and map Project Pickle field PlotNumber to the spreadsheet column that contains the plot number. For Existing Project mode after an Upgrade, the spreadsheet should contain only new plot numbers; existing plot numbers do not need to be included."
        }
        $plotNumber = 0
        if (-not [int]::TryParse($numberText, [ref]$plotNumber)) { throw "Add New Plots row $rowNumber has PlotNumber '$numberText', which is not numeric." }
        if ($seen.ContainsKey($plotNumber)) { throw "Duplicate PlotNumber '$plotNumber' in Add New Plots file." }
        $seen[$plotNumber] = $true

        $plotId = New-GuidText
        $plotKey = New-PlotKey -PlotNumber $plotNumber
        $plotLabel = Get-PlotImportValue -Row $row -FieldName "PlotLabel" -Mappings $PlotImportMappings
        $plotType = Get-PlotImportValue -Row $row -FieldName "PlotTypeID" -Mappings $PlotImportMappings
        if ([string]::IsNullOrWhiteSpace($plotType)) { $plotType = "1" }
        $existing = Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [Plots] WHERE [PlotNumber] = $plotNumber"
        if ([int]$existing -gt 0) {
            $skippedExisting++
            $rowNumber++
            continue
        }
        $now = Get-Date
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [Plots] ([PlotID], [ProjectID], [PlotNumber], [PlotLabel], [PlotTypeID], [PlotKey], [ManagementUnit], [Compartment], [Elevation], [Aspect], [SlopePercent], [SlopePosition], [UTMNorthingCoordinate], [UTMEastingCoordinate], [UTMZone], [PerAcreExpansion], [IsDeleted], [Created], [Updated], [UpdUser], [RetrievalID]) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)" -Parameters @(
            (DbGuid $plotId),
            (DbGuid $ProjectId),
            (DbInt $plotNumber),
            (DbText $plotLabel),
            (DbDouble $plotType),
            (DbText $plotKey),
            (DbDouble $null),
            (DbDouble $null),
            (DbDouble $null),
            (DbDouble $null),
            (DbDouble $null),
            (DbDouble $null),
            (DbDouble (Get-PlotImportValue -Row $row -FieldName "UTMNorthingCoordinate" -Mappings $PlotImportMappings)),
            (DbDouble (Get-PlotImportValue -Row $row -FieldName "UTMEastingCoordinate" -Mappings $PlotImportMappings)),
            (DbDouble (Get-PlotImportValue -Row $row -FieldName "UTMZone" -Mappings $PlotImportMappings)),
            (DbDouble $null),
            (DbBool $false),
            (DbDate $now),
            (DbDate $now),
            (DbText "Pickle"),
            (DbInt 0)
        ))
        [void](Set-OptionalPlotImportField -Connection $Connection -PlotId $plotId -TargetColumn "FLCCommercial" -Value (Get-PlotImportValue -Row $row -FieldName "FLCCommercial" -Mappings $PlotImportMappings) -PlotDataTypes $plotDataTypes)

        foreach ($period in $Periods) {
            $measurementId = New-GuidText
            $plotMeasKey = $plotKey + "-" + ([int]$period.PeriodNumber).ToString("00")
            $measureNow = Get-Date
            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [PlotMeasurements] ([MeasurementID], [PlotMeasKey], [PlotID], [PlotKey], [ProjectPeriodID], [PeriodNumber], [PlotStatus], [Created], [Updated], [UpdUser], [RetrievalID]) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)" -Parameters @(
                (DbGuid $measurementId),
                (DbText $plotMeasKey),
                (DbGuid $plotId),
                (DbText $plotKey),
                (DbGuid $period.ProjectPeriodID),
                (DbInt $period.PeriodNumber),
                (DbInt $null),
                (DbDate $measureNow),
                (DbDate $measureNow),
                (DbText "Pickle"),
                (DbInt 0)
            ))
            if (Test-TableExists -Connection $Connection -TableName "PlotCustomMeasurements") {
                [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [PlotCustomMeasurements] ([MeasurementID], [PlotMeasKey]) VALUES (?, ?)" -Parameters @(
                    (DbGuid $measurementId),
                    (DbText $plotMeasKey)
                ))
            }
        }
        $inserted++
        $rowNumber++
    }
    & $Log "Imported $inserted new plot row(s). Skipped $skippedExisting existing plot number(s) and $skippedBlank blank spreadsheet row(s)."
    return $inserted
}

function Add-PlotCustomMeasurementRowIfMissing {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$MeasurementId,
        [string]$PlotMeasKey
    )

    if (-not (Test-TableExists -Connection $Connection -TableName "PlotCustomMeasurements")) { return $false }
    if (-not (Test-ColumnExists -Connection $Connection -TableName "PlotCustomMeasurements" -ColumnName "MeasurementID")) { return $false }
    $existing = Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [PlotCustomMeasurements] WHERE [MeasurementID] = $(Sql-Guid $MeasurementId)"
    if ([int]$existing -gt 0) { return $false }

    if (Test-ColumnExists -Connection $Connection -TableName "PlotCustomMeasurements" -ColumnName "PlotMeasKey") {
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [PlotCustomMeasurements] ([MeasurementID], [PlotMeasKey]) VALUES (?, ?)" -Parameters @(
            (DbGuid $MeasurementId),
            (DbText $PlotMeasKey)
        ))
    }
    else {
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [PlotCustomMeasurements] ([MeasurementID]) VALUES (?)" -Parameters @(
            (DbGuid $MeasurementId)
        ))
    }
    return $true
}

function Ensure-BlankPlotMeasurementsForPeriods {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [object[]]$Periods,
        [scriptblock]$Log
    )

    if (-not (Test-TableExists -Connection $Connection -TableName "Plots")) { return 0 }
    if (-not (Test-TableExists -Connection $Connection -TableName "PlotMeasurements")) { return 0 }
    $requiredColumns = @("MeasurementID", "PlotMeasKey", "PlotID", "PlotKey", "ProjectPeriodID", "PeriodNumber", "UpdUser")
    foreach ($columnName in $requiredColumns) {
        if (-not (Test-ColumnExists -Connection $Connection -TableName "PlotMeasurements" -ColumnName $columnName)) {
            if ($Log) { & $Log "Blank plot measurement setup skipped because PlotMeasurements.$columnName was not found." }
            return 0
        }
    }

    $plots = Get-DbTable -Connection $Connection -Sql "SELECT * FROM [Plots]"
    if ($plots.Rows.Count -eq 0) { return 0 }
    $created = 0
    $customCreated = 0
    $checkedPlotPeriods = 0
    foreach ($period in @($Periods)) {
        $periodId = ConvertTo-BuilderText $period.ProjectPeriodID
        $periodNumberText = ConvertTo-BuilderText $period.PeriodNumber
        if ([string]::IsNullOrWhiteSpace($periodId) -or [string]::IsNullOrWhiteSpace($periodNumberText)) { continue }
        $periodNumber = 0
        if (-not [int]::TryParse($periodNumberText, [ref]$periodNumber)) { continue }
        foreach ($plot in $plots.Rows) {
            $checkedPlotPeriods++
            if (($checkedPlotPeriods % 50) -eq 0) { Invoke-WOOFUiPulse }
            if (($checkedPlotPeriods % 500) -eq 0 -and $Log) {
                & $Log "Blank plot measurement setup still working: $checkedPlotPeriods plot/period combination(s) checked."
            }
            $plotId = Get-DataRowText -Row $plot -ColumnNames @("PlotID", "ID")
            if ([string]::IsNullOrWhiteSpace($plotId)) { continue }
            $exists = Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [PlotMeasurements] WHERE [PlotID] = $(Sql-Guid $plotId) AND [ProjectPeriodID] = $(Sql-Guid $periodId)"
            if ([int]$exists -gt 0) {
                $existingMeasurements = Get-DbTable -Connection $Connection -Sql "SELECT [MeasurementID], [PlotMeasKey] FROM [PlotMeasurements] WHERE [PlotID] = $(Sql-Guid $plotId) AND [ProjectPeriodID] = $(Sql-Guid $periodId)"
                foreach ($existingMeasurement in $existingMeasurements.Rows) {
                    $existingMeasurementId = Get-DataRowText -Row $existingMeasurement -ColumnNames @("MeasurementID")
                    if ([string]::IsNullOrWhiteSpace($existingMeasurementId)) { continue }
                    $existingPlotMeasKey = Get-DataRowText -Row $existingMeasurement -ColumnNames @("PlotMeasKey")
                    if (Add-PlotCustomMeasurementRowIfMissing -Connection $Connection -MeasurementId $existingMeasurementId -PlotMeasKey $existingPlotMeasKey) {
                        $customCreated++
                    }
                }
                continue
            }

            $plotKey = Get-DataRowText -Row $plot -ColumnNames @("PlotKey")
            if ([string]::IsNullOrWhiteSpace($plotKey)) {
                $plotNumberText = Get-DataRowText -Row $plot -ColumnNames @("PlotNumber", "Plot")
                $plotNumber = 0
                if ([int]::TryParse($plotNumberText, [ref]$plotNumber)) {
                    $plotKey = New-PlotKey -PlotNumber $plotNumber
                }
            }
            if ([string]::IsNullOrWhiteSpace($plotKey)) {
                if ($Log) { & $Log "Blank plot measurement warning: skipped one plot because PlotKey was blank and PlotNumber could not be used." }
                continue
            }

            $measurementId = New-GuidText
            $plotMeasKey = $plotKey + "-" + $periodNumber.ToString("00")
            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [PlotMeasurements] ([MeasurementID], [PlotMeasKey], [PlotID], [PlotKey], [ProjectPeriodID], [PeriodNumber], [UpdUser]) VALUES (?, ?, ?, ?, ?, ?, ?)" -Parameters @(
                (DbGuid $measurementId),
                (DbText $plotMeasKey),
                (DbGuid $plotId),
                (DbText $plotKey),
                (DbGuid $periodId),
                (DbInt $periodNumber),
                (DbText "Pickle")
            ))
            $created++
            if (Add-PlotCustomMeasurementRowIfMissing -Connection $Connection -MeasurementId $measurementId -PlotMeasKey $plotMeasKey) {
                $customCreated++
            }
        }
    }

    if ($created -gt 0 -and $Log) {
        & $Log "Added $created blank PlotMeasurements row(s) for missing plot/period combinations with UpdUser=Pickle."
    }
    if ($customCreated -gt 0 -and $Log) {
        & $Log "Added $customCreated matching PlotCustomMeasurements row(s) using the same MeasurementID."
    }
    return $created
}

function Clear-InventoryAssignmentTablesForRebuild {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [scriptblock]$Log
    )

    $tables = @(
        "InventoryAssignmentTrees",
        "InventoryAssignmentPlots",
        "InventoryAssignments",
        "InventoryCrews"
    )
    $cleared = New-Object System.Collections.Generic.List[string]
    foreach ($tableName in $tables) {
        if (-not (Test-TableExists -Connection $Connection -TableName $tableName)) { continue }
        $rowCount = 0
        try { $rowCount = [int](Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM $(Quote-Name $tableName)") } catch { $rowCount = 0 }
        if ($rowCount -gt 0) {
            [void](Invoke-DbNonQuery -Connection $Connection -Sql "DELETE FROM $(Quote-Name $tableName)")
        }
        [void]$cleared.Add("$tableName=$rowCount")
    }

    if ($Log) {
        if ($cleared.Count -gt 0) {
            & $Log "Cleared existing inventory assignment rows before rebuild: $([string]::Join('; ', [string[]]$cleared.ToArray()))."
        }
        else {
            & $Log "No inventory assignment tables were found to clear before rebuild."
        }
    }
}

function Get-InventoryAssignmentPeriods {
    param(
        [object[]]$Periods,
        [scriptblock]$Log
    )

    $current = @($Periods | Where-Object { ConvertTo-BuilderBool $_.IsCurrent })
    if ($current.Count -gt 0) {
        if ($current.Count -gt 1 -and $Log) {
            & $Log "More than one period was marked current for assignment setup. Using the highest current period only."
        }
        return @($current | Sort-Object PeriodNumber -Descending | Select-Object -First 1)
    }

    $fallback = @($Periods | Sort-Object PeriodNumber -Descending | Select-Object -First 1)
    if ($fallback.Count -gt 0 -and $Log) {
        & $Log "No current period was marked for assignment setup. Using highest period number $($fallback[0].PeriodNumber)."
    }
    return $fallback
}

function Ensure-InventoryAssignments {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [object[]]$Periods,
        [string[]]$CrewNames,
        [bool]$IncludePlotAssignments,
        [bool]$IncludeTreeAssignments,
        [scriptblock]$Log
    )

    $Periods = @(Get-InventoryAssignmentPeriods -Periods $Periods -Log $Log)
    if ($Periods.Count -eq 0) {
        & $Log "No measurement period found for inventory assignment setup."
        return
    }
    $selectedPeriodNumbers = [string]::Join(", ", [string[]]($Periods | ForEach-Object { (ConvertTo-BuilderText $_.PeriodNumber) }))
    & $Log "Inventory assignments will be built for current period(s): $selectedPeriodNumbers."

    $requiredTables = @("InventoryCrews", "InventoryAssignments")
    if ($IncludePlotAssignments) { $requiredTables += "InventoryAssignmentPlots" }
    if ($IncludeTreeAssignments) { $requiredTables += "InventoryAssignmentTrees" }
    foreach ($requiredTable in $requiredTables) {
        if (-not (Test-TableExists -Connection $Connection -TableName $requiredTable)) {
            throw "Assignment setup requires table $requiredTable, but it was not found in the current master database version."
        }
    }

    $cleanCrewNames = New-Object System.Collections.Generic.List[string]
    $seenCrewNames = New-Object "System.Collections.Generic.HashSet[string]" ([System.StringComparer]::OrdinalIgnoreCase)
    foreach ($crewName in @($CrewNames)) {
        $cleanCrew = ConvertTo-BuilderText $crewName
        if ([string]::IsNullOrWhiteSpace($cleanCrew)) { continue }
        if ($seenCrewNames.Add($cleanCrew)) { [void]$cleanCrewNames.Add($cleanCrew) }
    }
    if ($cleanCrewNames.Count -eq 0) { [void]$cleanCrewNames.Add("Team1") }
    $CrewNames = @($cleanCrewNames.ToArray())

    $assignments = New-Object System.Collections.Generic.List[object]
    $createdCrewRows = 0
    $createdAssignmentRows = 0
    foreach ($period in $Periods) {
        foreach ($crewName in $CrewNames) {
            $cleanCrew = ConvertTo-BuilderText $crewName
            if ([string]::IsNullOrWhiteSpace($cleanCrew)) { continue }
            $crewId = ConvertTo-BuilderText (Get-DbScalar -Connection $Connection -Sql "SELECT TOP 1 [ID] FROM [InventoryCrews] WHERE [ProjectPeriodID] = $(Sql-Guid $period.ProjectPeriodID) AND [ShortName] = $(Sql-Text $cleanCrew)")
            if ([string]::IsNullOrWhiteSpace($crewId)) {
                $crewId = New-GuidText
                $now = Get-Date
                [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [InventoryCrews] ([ID], [ProjectPeriodID], [ShortName], [Description], [Created], [Updated], [UpdUser]) VALUES (?, ?, ?, ?, ?, ?, ?)" -Parameters @(
                    (DbGuid $crewId),
                    (DbGuid $period.ProjectPeriodID),
                    (DbText $cleanCrew),
                    (DbLongText $null),
                    (DbDate $now),
                    (DbDate $now),
                    (DbText "builder")
                ))
                $createdCrewRows++
            }
            $assignmentId = ConvertTo-BuilderText (Get-DbScalar -Connection $Connection -Sql "SELECT TOP 1 [ID] FROM [InventoryAssignments] WHERE [ProjectPeriodID] = $(Sql-Guid $period.ProjectPeriodID) AND [CrewID] = $(Sql-Guid $crewId)")
            if ([string]::IsNullOrWhiteSpace($assignmentId)) {
                $assignmentId = New-GuidText
                $now = Get-Date
                [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [InventoryAssignments] ([ID], [ProjectPeriodID], [CrewID], [StatusID], [Notes], [Created], [Updated], [updUser]) VALUES (?, ?, ?, ?, ?, ?, ?, ?)" -Parameters @(
                    (DbGuid $assignmentId),
                    (DbGuid $period.ProjectPeriodID),
                    (DbGuid $crewId),
                    (DbInt 2),
                    (DbText $cleanCrew),
                    (DbDate $now),
                    (DbDate $now),
                    (DbText "builder")
                ))
                $createdAssignmentRows++
            }
            [void]$assignments.Add([pscustomobject]@{ Period = $period; CrewID = $crewId; AssignmentID = $assignmentId })
        }
    }
    $finalCrewRows = [int](Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [InventoryCrews]")
    $finalAssignmentRows = [int](Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [InventoryAssignments]")
    if ($finalCrewRows -eq 0) { throw "Assignment setup did not create any InventoryCrews rows." }
    if ($finalAssignmentRows -eq 0) { throw "Assignment setup did not create any InventoryAssignments rows." }
    & $Log "Prepared $($assignments.Count) crew assignment row(s). Created $createdCrewRows InventoryCrews row(s) and $createdAssignmentRows InventoryAssignments row(s); final counts are InventoryCrews=$finalCrewRows and InventoryAssignments=$finalAssignmentRows."

    if ($IncludePlotAssignments -and (Test-TableExists -Connection $Connection -TableName "Plots")) {
        $plots = Get-DbTable -Connection $Connection -Sql "SELECT [PlotID] FROM [Plots]"
        if ($plots.Rows.Count -eq 0) {
            & $Log "No plots found. InventoryAssignmentPlots setup skipped."
        }
        else {
            $plotAssignmentChecked = 0
            $createdPlotAssignmentRows = 0
            foreach ($assignment in $assignments) {
                foreach ($plot in $plots.Rows) {
                    $plotAssignmentChecked++
                    if (($plotAssignmentChecked % 50) -eq 0) { Invoke-WOOFUiPulse }
                    if (($plotAssignmentChecked % 500) -eq 0 -and $Log) {
                        & $Log "InventoryAssignmentPlots setup still working: $plotAssignmentChecked assignment/plot combination(s) checked."
                    }
                    $plotId = ConvertTo-BuilderText $plot["PlotID"]
                    $exists = Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [InventoryAssignmentPlots] WHERE [AssignmentID] = $(Sql-Guid $assignment.AssignmentID) AND [PlotID] = $(Sql-Guid $plotId)"
                    if ([int]$exists -eq 0) {
                        $now = Get-Date
                        $affected = Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [InventoryAssignmentPlots] ([ID], [AssignmentID], [PlotID], [StatusID], [TurnedIn], [Imported], [Created], [Updated], [UpdUser]) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)" -Parameters @(
                            (DbGuid (New-GuidText)),
                            (DbGuid $assignment.AssignmentID),
                            (DbGuid $plotId),
                            (DbInt 1),
                            (DbBool $false),
                            (DbBool $false),
                            (DbDate $now),
                            (DbDate $now),
                            (DbText "builder")
                        )
                        if ([int]$affected -gt 0) { $createdPlotAssignmentRows += [int]$affected }
                    }
                }
            }
            $finalPlotAssignmentRows = [int](Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [InventoryAssignmentPlots]")
            if ($finalPlotAssignmentRows -eq 0) {
                throw "Assignment setup did not create any InventoryAssignmentPlots rows, even though $($plots.Rows.Count) plot row(s) and $($assignments.Count) crew assignment row(s) were available."
            }
            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "UPDATE [InventoryAssignmentPlots] SET [StatusID] = ?" -Parameters @((DbInt 1)))
            $nonAwaitingPlotAssignmentRows = [int](Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [InventoryAssignmentPlots] WHERE ([StatusID] Is Null OR [StatusID] <> 1)")
            if ($nonAwaitingPlotAssignmentRows -gt 0) {
                throw "Assignment setup expected all InventoryAssignmentPlots rows to have StatusID=1 for Awaiting Work, but $nonAwaitingPlotAssignmentRows row(s) did not."
            }
            & $Log "InventoryAssignmentPlots setup complete: created $createdPlotAssignmentRows row(s); final count InventoryAssignmentPlots=$finalPlotAssignmentRows for $($plots.Rows.Count) plot row(s). All plot assignment StatusID values were set to 1 (Awaiting Work)."
        }
    }

    if ($IncludeTreeAssignments -and (Test-TableExists -Connection $Connection -TableName "Trees")) {
        $treeCount = [int](Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [Trees]")
        if ($treeCount -eq 0) {
            & $Log "Tree assignment option was selected, but no Trees rows were found."
            return
        }
        $sql = @"
SELECT iap.[ID] AS AssignmentPlotID, t.[TreeID]
FROM ([InventoryAssignmentPlots] AS iap
INNER JOIN [Plots] AS p ON iap.[PlotID] = p.[PlotID])
INNER JOIN [Trees] AS t ON p.[PlotID] = t.[PlotID]
"@
        $rows = Get-DbTable -Connection $Connection -Sql $sql
        if ($rows.Rows.Count -eq 0) {
            throw "Tree assignment setup found $treeCount tree row(s), but none matched InventoryAssignmentPlots by PlotID. Check that plot assignment rows were created before tree assignment setup."
        }
        $treeAssignmentChecked = 0
        $createdTreeAssignmentRows = 0
        foreach ($row in $rows.Rows) {
            $treeAssignmentChecked++
            if (($treeAssignmentChecked % 50) -eq 0) { Invoke-WOOFUiPulse }
            if (($treeAssignmentChecked % 500) -eq 0 -and $Log) {
                & $Log "InventoryAssignmentTrees setup still working: $treeAssignmentChecked assignment/tree combination(s) checked."
            }
            $assignmentPlotId = ConvertTo-BuilderText $row["AssignmentPlotID"]
            $treeId = ConvertTo-BuilderText $row["TreeID"]
            $exists = Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [InventoryAssignmentTrees] WHERE [InventoryAssignmentPlotID] = $(Sql-Guid $assignmentPlotId) AND [TreeID] = $(Sql-Guid $treeId)"
            if ([int]$exists -eq 0) {
                $now = Get-Date
                $affected = Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [InventoryAssignmentTrees] ([ID], [InventoryAssignmentPlotID], [TreeID], [AssignmentStatusID], [Created], [Updated], [UpdUser]) VALUES (?, ?, ?, ?, ?, ?, ?)" -Parameters @(
                    (DbGuid (New-GuidText)),
                    (DbGuid $assignmentPlotId),
                    (DbGuid $treeId),
                    (DbInt 1),
                    (DbDate $now),
                    (DbDate $now),
                    (DbText "builder")
                )
                if ([int]$affected -gt 0) { $createdTreeAssignmentRows += [int]$affected }
            }
        }
        $finalTreeAssignmentRows = [int](Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [InventoryAssignmentTrees]")
        if ($finalTreeAssignmentRows -eq 0) {
            throw "Assignment setup did not create any InventoryAssignmentTrees rows, even though tree assignment setup was selected and $treeCount tree row(s) were available."
        }
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "UPDATE [InventoryAssignmentTrees] SET [AssignmentStatusID] = ?" -Parameters @((DbInt 1)))
        $nonAwaitingTreeAssignmentRows = [int](Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [InventoryAssignmentTrees] WHERE ([AssignmentStatusID] Is Null OR [AssignmentStatusID] <> 1)")
        if ($nonAwaitingTreeAssignmentRows -gt 0) {
            throw "Assignment setup expected all InventoryAssignmentTrees rows to have AssignmentStatusID=1 for Awaiting Work, but $nonAwaitingTreeAssignmentRows row(s) did not."
        }
        & $Log "InventoryAssignmentTrees setup complete: created $createdTreeAssignmentRows row(s); final count InventoryAssignmentTrees=$finalTreeAssignmentRows for $treeCount tree row(s). All tree assignment AssignmentStatusID values were set to 1 (Awaiting Work)."
    }
}

function Set-ProjectPickleReportHeaderFixedWidthView {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [System.Windows.Forms.Control]$ReportHeadersContainer
    )

    # Keep one shared fixed-width font for the Reports tab.
    # Courier New matches the traditional Access fixed-width report display.
    $fontVariable = Get-Variable `
        -Name "ProjectPickleReportHeaderFixedWidthFont" `
        -Scope Script `
        -ErrorAction SilentlyContinue

    if ($null -eq $fontVariable -or $null -eq $fontVariable.Value) {
        $script:ProjectPickleReportHeaderFixedWidthFont =
            [System.Drawing.Font]::new(
                "Courier New",
                [single]10.0,
                [System.Drawing.FontStyle]::Regular,
                [System.Drawing.GraphicsUnit]::Point
            )
    }

    $fixedWidthFont = $script:ProjectPickleReportHeaderFixedWidthFont

    # Recursively find every child control inside the ReportHeaders group.
    # This avoids depending on the exact variable name used for the editor
    # or ruler.
    $getDescendantControls = $null

    $getDescendantControls = {
        param(
            [System.Windows.Forms.Control]$ParentControl
        )

        foreach ($childControl in $ParentControl.Controls) {
            $childControl

            if ($childControl.HasChildren) {
                & $getDescendantControls $childControl
            }
        }
    }

    $allControls = @(
        & $getDescendantControls $ReportHeadersContainer
    )

    # The header editor is the largest multiline TextBox or RichTextBox
    # inside the ReportHeaders group.
    $editorCandidates = @(
        $allControls |
            Where-Object {
                (
                    $_ -is [System.Windows.Forms.RichTextBox] -or
                    $_ -is [System.Windows.Forms.TextBox]
                ) -and
                $_.Multiline
            } |
            Sort-Object -Property @{
                Expression = {
                    [int64]$_.Width * [int64]$_.Height
                }
                Descending = $true
            }
    )

    if ($editorCandidates.Count -eq 0) {
        Write-Warning "Project Pickle could not find the multiline ReportHeaders editor."
        return
    }

    $reportHeaderEditor = $editorCandidates[0]

    # Find the character ruler either by its control name or its text.
    $rulerCandidates = @(
        $allControls |
            Where-Object {
                (
                    $_ -is [System.Windows.Forms.Label] -or
                    $_ -is [System.Windows.Forms.TextBox] -or
                    $_ -is [System.Windows.Forms.RichTextBox]
                ) -and
                (
                    ([string]$_.Name -match "ruler") -or
                    ([string]$_.Text -match "^\s*0.*10.*20")
                )
            }
    )

    $reportHeaderRuler = $null

    if ($rulerCandidates.Count -gt 0) {
        $reportHeaderRuler = $rulerCandidates[0]
    }

    # Apply the same true fixed-width font to the editor.
    $reportHeaderEditor.Font = $fixedWidthFont
    $reportHeaderEditor.WordWrap = $false
    $reportHeaderEditor.AcceptsTab = $false
    $reportHeaderEditor.ShortcutsEnabled = $true

    if ($reportHeaderEditor -is [System.Windows.Forms.RichTextBox]) {
        $reportHeaderEditor.DetectUrls = $false
        $reportHeaderEditor.AutoWordSelection = $false
        $reportHeaderEditor.HideSelection = $false
        $reportHeaderEditor.ZoomFactor = [single]1.0
        $reportHeaderEditor.ScrollBars =
            [System.Windows.Forms.RichTextBoxScrollBars]::Both

        # Apply the font to text that may already have been loaded.
        # Preserve the user's current selection or caret position.
        $originalSelectionStart = [int]$reportHeaderEditor.SelectionStart
        $originalSelectionLength = [int]$reportHeaderEditor.SelectionLength

        if ($reportHeaderEditor.TextLength -gt 0) {
            $reportHeaderEditor.SelectAll()
            $reportHeaderEditor.SelectionFont = $fixedWidthFont

            $safeSelectionStart = [Math]::Min(
                $originalSelectionStart,
                $reportHeaderEditor.TextLength
            )

            $remainingLength = [Math]::Max(
                0,
                $reportHeaderEditor.TextLength - $safeSelectionStart
            )

            $safeSelectionLength = [Math]::Min(
                $originalSelectionLength,
                $remainingLength
            )

            $reportHeaderEditor.Select(
                $safeSelectionStart,
                $safeSelectionLength
            )
        }
    }
    elseif ($reportHeaderEditor -is [System.Windows.Forms.TextBox]) {
        $reportHeaderEditor.ScrollBars =
            [System.Windows.Forms.ScrollBars]::Both
    }

    if ($null -ne $reportHeaderRuler) {
        $reportHeaderRuler.Font = $fixedWidthFont

        if ($reportHeaderRuler -is [System.Windows.Forms.Label]) {
            $reportHeaderRuler.AutoSize = $false
            $reportHeaderRuler.AutoEllipsis = $false
            $reportHeaderRuler.UseCompatibleTextRendering = $false

            # Match the small internal left margin of the text editor.
            $reportHeaderRuler.Padding =
                [System.Windows.Forms.Padding]::new(3, 0, 0, 0)
        }
        elseif ($reportHeaderRuler -is [System.Windows.Forms.RichTextBox]) {
            $reportHeaderRuler.ReadOnly = $true
            $reportHeaderRuler.WordWrap = $false
            $reportHeaderRuler.DetectUrls = $false
            $reportHeaderRuler.ScrollBars =
                [System.Windows.Forms.RichTextBoxScrollBars]::None
        }
        elseif ($reportHeaderRuler -is [System.Windows.Forms.TextBox]) {
            $reportHeaderRuler.ReadOnly = $true
            $reportHeaderRuler.WordWrap = $false
            $reportHeaderRuler.ScrollBars =
                [System.Windows.Forms.ScrollBars]::None
        }

        # Make the ruler and editor start and end at the same position
        # when they share the same parent control.
        if ($reportHeaderRuler.Parent -eq $reportHeaderEditor.Parent) {
            $reportHeaderRuler.Left = $reportHeaderEditor.Left
            $reportHeaderRuler.Width = $reportHeaderEditor.Width
        }
    }

    $ReportHeadersContainer.Invalidate($true)
}
function Get-ManualReportDesignerSpecs {
    return @(
        [pscustomobject]@{
            Key = "Plot|3"
            DisplayName = "Plot - Additional Plot Information"
            Section = "Plot"
            ColumnGroup = 3
            HeaderGroup = 3
            HeaderGroupIsNull = $false
            Title = "Additional Plot Information"
            CustomTableName = "PlotCustomMeasurements"
            AnchorTableName = "PlotMeasurements"
            AnchorColumnName = "RemarksPlot"
        },
        [pscustomobject]@{
            Key = "Tree|1"
            DisplayName = "Tree - Tree Measurements"
            Section = "Tree"
            ColumnGroup = 1
            HeaderGroup = 1
            HeaderGroupIsNull = $false
            Title = "Tree Measurements"
            CustomTableName = "TreeCustomMeasurements"
            AnchorTableName = "TreeMeasurements"
            AnchorColumnName = "RemarksTree"
        },
        [pscustomobject]@{
            Key = "Regen|1"
            DisplayName = "Regen - Regeneration Information"
            Section = "Regen"
            ColumnGroup = 1
            HeaderGroup = $null
            HeaderGroupIsNull = $true
            Title = "Regeneration Information"
            CustomTableName = "RegenCustomMeasurements"
