        }
    )
}

function Get-ManualReportLayoutKey {
    param(
        [string]$Section,
        [int]$ColumnGroup
    )

    return "$(ConvertTo-BuilderText $Section)|$ColumnGroup"
}

function Copy-ManualReportLayout {
    param([object]$Layout)

    if ($null -eq $Layout) { return $null }
    $columns = New-Object System.Collections.Generic.List[object]
    foreach ($column in @($Layout.Columns)) {
        if ($null -eq $column) { continue }
        [void]$columns.Add([pscustomobject]@{
            ColumnID = ConvertTo-BuilderText $column.ColumnID
            TableName = ConvertTo-BuilderText $column.TableName
            ColumnName = ConvertTo-BuilderText $column.ColumnName
            Label = ConvertTo-BuilderText $column.Label
            FieldFormat = ConvertTo-RawSingleLineText $column.FieldFormat
            TallyFormat = ConvertTo-RawSingleLineText $column.TallyFormat
        })
    }

    $headerLines = New-Object System.Collections.Generic.List[string]
    foreach ($line in @($Layout.HeaderLines)) {
        if ($null -eq $line) {
            [void]$headerLines.Add("")
        }
        else {
            [void]$headerLines.Add([string]$line)
        }
    }

    $headerGroup = $null
    if ($Layout.PSObject.Properties["HeaderGroup"] -and $null -ne $Layout.HeaderGroup -and -not ($Layout.HeaderGroup -is [System.DBNull])) {
        $headerGroup = [int]$Layout.HeaderGroup
    }

    return [pscustomobject]@{
        Key = ConvertTo-BuilderText $Layout.Key
        DisplayName = ConvertTo-BuilderText $Layout.DisplayName
        Section = ConvertTo-BuilderText $Layout.Section
        ColumnGroup = [int]$Layout.ColumnGroup
        HeaderGroup = $headerGroup
        HeaderGroupIsNull = ConvertTo-BuilderBool $Layout.HeaderGroupIsNull
        Title = ConvertTo-BuilderText $Layout.Title
        CustomTableName = ConvertTo-BuilderText $Layout.CustomTableName
        AnchorTableName = ConvertTo-BuilderText $Layout.AnchorTableName
        AnchorColumnName = ConvertTo-BuilderText $Layout.AnchorColumnName
        Columns = @($columns.ToArray())
        HeaderLines = [string[]]$headerLines.ToArray()
    }
}

function Get-ManualReportLayoutIssues {
    param([object]$Layout)

    $issues = New-Object System.Collections.Generic.List[string]
    if ($null -eq $Layout) {
        [void]$issues.Add("The report layout is blank.")
        return [string[]]$issues.ToArray()
    }

    $section = ConvertTo-BuilderText $Layout.Section
    $displayName = ConvertTo-BuilderText $Layout.DisplayName
    if ([string]::IsNullOrWhiteSpace($displayName)) { $displayName = "$section report" }
    if ($section -notin @("Plot", "Tree", "Regen")) {
        [void]$issues.Add("$displayName has an unsupported ReportSection '$section'.")
    }

    $columnGroup = 0
    if (-not [int]::TryParse((ConvertTo-BuilderText $Layout.ColumnGroup), [ref]$columnGroup) -or $columnGroup -le 0) {
        [void]$issues.Add("$displayName needs a positive ReportColumns group number.")
    }

    $columns = @($Layout.Columns)
    if ($columns.Count -eq 0) {
        [void]$issues.Add("$displayName has no report columns. Load the database layout or add at least one field.")
    }
    else {
        $seen = New-Object "System.Collections.Generic.HashSet[string]" ([System.StringComparer]::OrdinalIgnoreCase)
        $anchorTableName = ConvertTo-BuilderText $Layout.AnchorTableName
        $anchorColumnName = ConvertTo-BuilderText $Layout.AnchorColumnName
        $customTableName = ConvertTo-BuilderText $Layout.CustomTableName
        $anchorRowNumber = 0
        $customRowNumbers = New-Object System.Collections.Generic.List[int]
        $rowNumber = 1
        foreach ($column in $columns) {
            $columnId = ConvertTo-BuilderText $column.ColumnID
            $tableName = ConvertTo-BuilderText $column.TableName
            $columnName = ConvertTo-BuilderText $column.ColumnName
            $fieldFormat = ConvertTo-RawSingleLineText $column.FieldFormat
            $reference = if (-not [string]::IsNullOrWhiteSpace($tableName) -and -not [string]::IsNullOrWhiteSpace($columnName)) {
                "$tableName.$columnName"
            }
            else {
                $columnId
            }

            if ([string]::IsNullOrWhiteSpace($reference)) {
                [void]$issues.Add("$displayName column row $rowNumber needs Table + Field or a ColumnID.")
            }
            elseif (-not $seen.Add($reference)) {
                [void]$issues.Add("$displayName contains the report column '$reference' more than once.")
            }

            if ([string]::IsNullOrWhiteSpace($fieldFormat)) {
                [void]$issues.Add("$displayName column row $rowNumber needs a FieldFormat.")
            }

            if (-not [string]::IsNullOrWhiteSpace($anchorColumnName) -and
                [string]::Equals($columnName, $anchorColumnName, [System.StringComparison]::OrdinalIgnoreCase) -and
                ([string]::IsNullOrWhiteSpace($tableName) -or [string]::IsNullOrWhiteSpace($anchorTableName) -or [string]::Equals($tableName, $anchorTableName, [System.StringComparison]::OrdinalIgnoreCase))) {
                $anchorRowNumber = $rowNumber
            }
            if (-not [string]::IsNullOrWhiteSpace($customTableName) -and [string]::Equals($tableName, $customTableName, [System.StringComparison]::OrdinalIgnoreCase)) {
                [void]$customRowNumbers.Add($rowNumber)
            }
            $rowNumber++
        }

        if (-not [string]::IsNullOrWhiteSpace($anchorColumnName)) {
            if ($anchorRowNumber -le 0) {
                [void]$issues.Add("$displayName must keep the required remarks field $anchorTableName.$anchorColumnName.")
            }
            else {
                $afterAnchor = @($customRowNumbers.ToArray() | Where-Object { $_ -gt $anchorRowNumber })
                if ($afterAnchor.Count -gt 0) {
                    [void]$issues.Add("$displayName custom measurement fields must be placed before $anchorColumnName. Move custom row(s) $([string]::Join(', ', [string[]]$afterAnchor)) above the remarks row.")
                }
            }
        }
    }

    $headerLines = @($Layout.HeaderLines)
    if ($headerLines.Count -eq 0) {
        [void]$issues.Add("$displayName has no ReportHeaders lines.")
    }
    else {
        $nonEmptyLengths = New-Object System.Collections.Generic.List[int]
        for ($i = 0; $i -lt $headerLines.Count; $i++) {
            $line = if ($null -eq $headerLines[$i]) { "" } else { [string]$headerLines[$i] }
            if ($line.IndexOf("`t", [System.StringComparison]::Ordinal) -ge 0) {
                [void]$issues.Add("$displayName header line $($i + 1) contains a tab. Use spaces so character positions stay fixed.")
            }
            if ($line.IndexOf("`r", [System.StringComparison]::Ordinal) -ge 0 -or $line.IndexOf("`n", [System.StringComparison]::Ordinal) -ge 0) {
                [void]$issues.Add("$displayName header line $($i + 1) contains an embedded line break.")
            }
            if ($line.Length -gt 255) {
                [void]$issues.Add("$displayName header line $($i + 1) is $($line.Length) characters; ReportHeaders.Header supports at most 255.")
            }
            if ($line -match "[^\x20-\x7E]") {
                [void]$issues.Add("$displayName header line $($i + 1) contains a non-ASCII character. Use standard fixed-width characters only.")
            }
            if ($line.Length -gt 0) { [void]$nonEmptyLengths.Add($line.Length) }
        }

        $uniqueLengths = @($nonEmptyLengths.ToArray() | Sort-Object -Unique)
        if ($uniqueLengths.Count -eq 0) {
            [void]$issues.Add("$displayName has no nonblank ReportHeaders text.")
        }
        elseif ($uniqueLengths.Count -gt 1) {
            [void]$issues.Add("$displayName nonblank header lines do not have one fixed width. Lengths found: $([string]::Join(', ', [string[]]$uniqueLengths)).")
        }
    }

    return [string[]]$issues.ToArray()
}

function Get-ManualReportLayoutsIssues {
    param([object[]]$Layouts)

    $issues = New-Object System.Collections.Generic.List[string]
    $seen = New-Object "System.Collections.Generic.HashSet[string]" ([System.StringComparer]::OrdinalIgnoreCase)
    foreach ($layout in @($Layouts)) {
        if ($null -eq $layout) { continue }
        $key = Get-ManualReportLayoutKey -Section (ConvertTo-BuilderText $layout.Section) -ColumnGroup ([int]$layout.ColumnGroup)
        if (-not $seen.Add($key)) {
            [void]$issues.Add("Reports tab contains the layout '$key' more than once.")
        }
        foreach ($issue in @(Get-ManualReportLayoutIssues -Layout $layout)) {
            [void]$issues.Add($issue)
        }
    }
    return [string[]]$issues.ToArray()
}

function New-ReportCharacterRuler {
    param([int]$Width = 120)

    $Width = [Math]::Max(20, [Math]::Min(255, $Width))
    $characters = New-Object char[] $Width
    for ($i = 0; $i -lt $Width; $i++) { $characters[$i] = "." }
    for ($i = 5; $i -lt $Width; $i += 10) { $characters[$i] = "+" }
    for ($i = 0; $i -lt $Width; $i += 10) {
        $label = [string]$i
        for ($j = 0; $j -lt $label.Length -and ($i + $j) -lt $Width; $j++) {
            $characters[$i + $j] = $label[$j]
        }
    }
    return -join $characters
}

function Get-ReportLayoutFromConnection {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [object]$Spec
    )

    if (-not (Test-TableExists -Connection $Connection -TableName "ReportColumns")) {
        throw "The selected database does not contain ReportColumns."
    }
    if (-not (Test-TableExists -Connection $Connection -TableName "ReportHeaders")) {
        throw "The selected database does not contain ReportHeaders."
    }

    $section = ConvertTo-BuilderText $Spec.Section
    $columnGroup = [int]$Spec.ColumnGroup
    $hasAppTables = Test-TableExists -Connection $Connection -TableName "AppTables"
    $columnSql = if ($hasAppTables) {
@"
SELECT rc.[ReportIndex], rc.[ColumnID], rc.[FieldFormat], rc.[TallyFormat],
       ac.[ColumnName], ac.[FriendlyName], ac.[ShortName], appTable.[TableName]
FROM ([ReportColumns] AS rc
LEFT JOIN [AppColumns] AS ac ON rc.[ColumnID] = ac.[ID])
LEFT JOIN [AppTables] AS appTable ON ac.[TableID] = appTable.[ID]
WHERE rc.[ReportSection] = $(Sql-Text $section) AND rc.[ReportGroup] = $columnGroup
ORDER BY rc.[ReportIndex];
"@
    }
    else {
@"
SELECT rc.[ReportIndex], rc.[ColumnID], rc.[FieldFormat], rc.[TallyFormat],
       ac.[ColumnName], ac.[FriendlyName], ac.[ShortName]
FROM [ReportColumns] AS rc
LEFT JOIN [AppColumns] AS ac ON rc.[ColumnID] = ac.[ID]
WHERE rc.[ReportSection] = $(Sql-Text $section) AND rc.[ReportGroup] = $columnGroup
ORDER BY rc.[ReportIndex];
"@
    }

    $columnTable = Get-DbTable -Connection $Connection -Sql $columnSql
    $columns = New-Object System.Collections.Generic.List[object]
    foreach ($row in $columnTable.Rows) {
        $columnName = Get-DataRowText -Row $row -ColumnNames @("ColumnName")
        $friendlyName = Get-DataRowText -Row $row -ColumnNames @("FriendlyName")
        $shortName = Get-DataRowText -Row $row -ColumnNames @("ShortName")
        $label = if (-not [string]::IsNullOrWhiteSpace($shortName)) {
            $shortName
        }
        elseif (-not [string]::IsNullOrWhiteSpace($friendlyName)) {
            $friendlyName
        }
        else {
            $columnName
        }
        [void]$columns.Add([pscustomobject]@{
            ColumnID = Get-DataRowText -Row $row -ColumnNames @("ColumnID")
            TableName = if ($hasAppTables) { Get-DataRowText -Row $row -ColumnNames @("TableName") } else { "" }
            ColumnName = $columnName
            Label = $label
            FieldFormat = ConvertTo-RawSingleLineText $row["FieldFormat"]
            TallyFormat = ConvertTo-RawSingleLineText $row["TallyFormat"]
        })
    }

    $headerWhere = if (ConvertTo-BuilderBool $Spec.HeaderGroupIsNull) {
        "[ReportGroup] Is Null"
    }
    else {
        "[ReportGroup] = $([int]$Spec.HeaderGroup)"
    }
    $headerTable = Get-DbTable -Connection $Connection -Sql "SELECT [LineNumber], [Header] FROM [ReportHeaders] WHERE [ReportSection] = $(Sql-Text $section) AND $headerWhere ORDER BY [LineNumber];"
    $headerLines = New-Object System.Collections.Generic.List[string]
    foreach ($row in $headerTable.Rows) {
        $value = $row["Header"]
        if ($null -eq $value -or $value -is [System.DBNull]) {
            [void]$headerLines.Add("")
        }
        else {
            [void]$headerLines.Add([string]$value)
        }
    }

    return [pscustomobject]@{
        Key = ConvertTo-BuilderText $Spec.Key
        DisplayName = ConvertTo-BuilderText $Spec.DisplayName
        Section = $section
        ColumnGroup = $columnGroup
        HeaderGroup = $Spec.HeaderGroup
        HeaderGroupIsNull = ConvertTo-BuilderBool $Spec.HeaderGroupIsNull
        Title = ConvertTo-BuilderText $Spec.Title
        CustomTableName = ConvertTo-BuilderText $Spec.CustomTableName
        AnchorTableName = ConvertTo-BuilderText $Spec.AnchorTableName
        AnchorColumnName = ConvertTo-BuilderText $Spec.AnchorColumnName
        Columns = @($columns.ToArray())
        HeaderLines = [string[]]$headerLines.ToArray()
    }
}

function Resolve-ManualReportColumnId {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [object]$Column
    )

    $tableName = ConvertTo-BuilderText $Column.TableName
    $columnName = ConvertTo-BuilderText $Column.ColumnName
    if (-not [string]::IsNullOrWhiteSpace($tableName) -and -not [string]::IsNullOrWhiteSpace($columnName)) {
        try {
            $tableId = Get-AppTableId -Connection $Connection -TableName $tableName
            $resolved = Get-DbScalar -Connection $Connection -Sql "SELECT TOP 1 [ID] FROM [AppColumns] WHERE [TableID] = $tableId AND [ColumnName] = $(Sql-Text $columnName)"
            if ($null -ne $resolved -and -not ($resolved -is [System.DBNull])) {
                return ConvertTo-BuilderText $resolved
            }
        }
        catch {
        }
    }

    $columnId = ConvertTo-BuilderText $Column.ColumnID
    if (-not [string]::IsNullOrWhiteSpace($columnId)) {
        $existing = Get-DbScalar -Connection $Connection -Sql "SELECT Count(*) FROM [AppColumns] WHERE [ID] = $(Sql-Guid $columnId)"
        if ([int]$existing -gt 0) { return $columnId }
    }

    $reference = if (-not [string]::IsNullOrWhiteSpace($tableName) -and -not [string]::IsNullOrWhiteSpace($columnName)) {
        "$tableName.$columnName"
    }
    else {
        $columnId
    }
    throw "Reports tab could not resolve report column '$reference' in AppColumns after the custom fields were synchronized."
}

function Apply-ManualReportLayouts {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [object[]]$Layouts,
        [scriptblock]$Log
    )

    if (-not $Log) { $Log = { param($Text) Write-Host $Text } }
    $layoutsToApply = @($Layouts | Where-Object { $null -ne $_ })
    if ($layoutsToApply.Count -eq 0) { return }
    if (-not (Test-TableExists -Connection $Connection -TableName "ReportColumns")) { throw "ReportColumns was not found." }
    if (-not (Test-TableExists -Connection $Connection -TableName "ReportHeaders")) { throw "ReportHeaders was not found." }

    $issues = @(Get-ManualReportLayoutsIssues -Layouts $layoutsToApply)
    if ($issues.Count -gt 0) {
        throw "Reports tab layout needs attention:`r`n`r`n- " + ([string]::Join("`r`n- ", [string[]]$issues))
    }

    $resolvedLayouts = New-Object System.Collections.Generic.List[object]
    foreach ($layout in $layoutsToApply) {
        $resolvedColumns = New-Object System.Collections.Generic.List[object]
        foreach ($column in @($layout.Columns)) {
            [void]$resolvedColumns.Add([pscustomobject]@{
                ColumnID = Resolve-ManualReportColumnId -Connection $Connection -Column $column
                FieldFormat = ConvertTo-RawSingleLineText $column.FieldFormat
                TallyFormat = ConvertTo-RawSingleLineText $column.TallyFormat
            })
        }
        [void]$resolvedLayouts.Add([pscustomobject]@{
            Layout = $layout
            Columns = @($resolvedColumns.ToArray())
        })
    }

    $transaction = $Connection.BeginTransaction()
    try {
        foreach ($resolvedLayout in $resolvedLayouts) {
            $layout = $resolvedLayout.Layout
            $section = ConvertTo-BuilderText $layout.Section
            $columnGroup = [int]$layout.ColumnGroup

            [void](Invoke-DbNonQueryParameterizedInTransaction -Connection $Connection -Transaction $transaction -Sql "DELETE FROM [ReportColumns] WHERE [ReportSection] = ? AND [ReportGroup] = ?" -Parameters @(
                (DbText $section),
                (DbInt $columnGroup)
            ))

            $reportIndex = 1
            foreach ($column in @($resolvedLayout.Columns)) {
                [void](Invoke-DbNonQueryParameterizedInTransaction -Connection $Connection -Transaction $transaction -Sql "INSERT INTO [ReportColumns] ([ReportSection], [ReportGroup], [ReportIndex], [ColumnID], [FieldFormat], [TallyFormat]) VALUES (?, ?, ?, ?, ?, ?)" -Parameters @(
                    (DbText $section),
                    (DbInt $columnGroup),
                    (DbInt $reportIndex),
                    (DbGuid $column.ColumnID),
                    (DbRawText $column.FieldFormat),
                    (DbRawText $column.TallyFormat)
                ))
                $reportIndex++
            }

            $headerGroupIsNull = ConvertTo-BuilderBool $layout.HeaderGroupIsNull
            if ($headerGroupIsNull) {
                if ([string]::Equals($section, "Regen", [System.StringComparison]::OrdinalIgnoreCase)) {
                    [void](Invoke-DbNonQueryParameterizedInTransaction -Connection $Connection -Transaction $transaction -Sql "DELETE FROM [ReportHeaders] WHERE [ReportSection] = ? AND ([ReportGroup] Is Null OR [ReportGroup] = ?)" -Parameters @(
                        (DbText $section),
                        (DbInt $columnGroup)
                    ))
                }
                else {
                    [void](Invoke-DbNonQueryParameterizedInTransaction -Connection $Connection -Transaction $transaction -Sql "DELETE FROM [ReportHeaders] WHERE [ReportSection] = ? AND [ReportGroup] Is Null" -Parameters @((DbText $section)))
                }
            }
            else {
                $headerGroup = if ($layout.PSObject.Properties["HeaderGroup"] -and $null -ne $layout.HeaderGroup) { [int]$layout.HeaderGroup } else { $columnGroup }
                [void](Invoke-DbNonQueryParameterizedInTransaction -Connection $Connection -Transaction $transaction -Sql "DELETE FROM [ReportHeaders] WHERE [ReportSection] = ? AND [ReportGroup] = ?" -Parameters @(
                    (DbText $section),
                    (DbInt $headerGroup)
                ))
            }

            $lineNumber = 1
            foreach ($line in @($layout.HeaderLines)) {
                $headerLine = ConvertTo-RawSingleLineText $line
                $headerGroupValue = if ($headerGroupIsNull) { $null } elseif ($layout.PSObject.Properties["HeaderGroup"] -and $null -ne $layout.HeaderGroup) { [int]$layout.HeaderGroup } else { $columnGroup }
                [void](Invoke-DbNonQueryParameterizedInTransaction -Connection $Connection -Transaction $transaction -Sql "INSERT INTO [ReportHeaders] ([ReportSection], [ReportGroup], [LineNumber], [Header]) VALUES (?, ?, ?, ?)" -Parameters @(
                    (DbText $section),
                    (DbInt $headerGroupValue),
                    (DbInt $lineNumber),
                    (DbRawLongText $headerLine)
                ))
                $lineNumber++
            }

            & $Log "Applied manual $section report layout: $($resolvedLayout.Columns.Count) column(s), $(@($layout.HeaderLines).Count) header line(s)."
        }
        $transaction.Commit()
        $transaction.Dispose()
        $transaction = $null
    }
    catch {
        if ($null -ne $transaction) {
            try { $transaction.Rollback() } catch {}
        }
        throw
    }
    finally {
        if ($null -ne $transaction) {
            try { $transaction.Dispose() } catch {}
        }
    }
}

function ConvertTo-ProjectPickleReportHeaderWords {
    [CmdletBinding()]
    param(
        [AllowNull()]
        [object]$Value
    )

    $text = ConvertTo-BuilderText $Value

    if ([string]::IsNullOrWhiteSpace($text)) {
        return ""
    }

    # Convert underscores and hyphens into spaces.
    $text = $text -replace "[_-]+", " "

    # Split normal PascalCase words.
    # Example: TreeHistory becomes Tree History.
    $text = [regex]::Replace(
        $text,
        "([a-z0-9])([A-Z])",
        '$1 $2'
    )

    # Keep abbreviations together while separating the following word.
    # Example: TotalCUFTDefect becomes Total CUFT Defect.
    $text = [regex]::Replace(
        $text,
        "([A-Z]+)([A-Z][a-z])",
        '$1 $2'
    )

    $text = [regex]::Replace(
        $text,
        "\s+",
        " "
    ).Trim()

    return $text.ToUpperInvariant()
}

function Get-ProjectPickleReportUiValue {
    [CmdletBinding()]
    param(
        [AllowNull()]
        [object]$InputObject,

        [Parameter(Mandatory)]
        [string[]]$PropertyNames
    )

    if ($null -eq $InputObject) {
        return $null
    }

    # Support Hashtable, OrderedDictionary, and other dictionary objects.
    if ($InputObject -is [System.Collections.IDictionary]) {
        foreach ($propertyName in $PropertyNames) {
            foreach ($existingKey in @($InputObject.Keys)) {
                if (
                    [string]::Equals(
                        [string]$existingKey,
                        $propertyName,
                        [System.StringComparison]::OrdinalIgnoreCase
                    )
                ) {
                    return $InputObject[$existingKey]
                }
            }
        }
    }

    # Support normal PowerShell objects and PSCustomObject values.
    foreach ($propertyName in $PropertyNames) {
        foreach ($property in @($InputObject.PSObject.Properties)) {
            if (
                [string]::Equals(
                    [string]$property.Name,
                    $propertyName,
                    [System.StringComparison]::OrdinalIgnoreCase
                )
            ) {
                return $property.Value
            }
        }
    }

    return $null
}

function Set-ProjectPickleReportUiValue {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [object]$InputObject,

        [Parameter(Mandatory)]
        [string[]]$PropertyNames,

        [AllowNull()]
        [object]$Value
    )

    # Support Hashtable, OrderedDictionary, and other dictionary objects.
    if ($InputObject -is [System.Collections.IDictionary]) {
        foreach ($propertyName in $PropertyNames) {
            foreach ($existingKey in @($InputObject.Keys)) {
                if (
                    [string]::Equals(
                        [string]$existingKey,
                        $propertyName,
                        [System.StringComparison]::OrdinalIgnoreCase
                    )
                ) {
                    $InputObject[$existingKey] = $Value
                    return
                }
            }
        }

        $InputObject[$PropertyNames[0]] = $Value
        return
    }

    # Support normal PowerShell objects and PSCustomObject values.
    foreach ($propertyName in $PropertyNames) {
        foreach ($property in @($InputObject.PSObject.Properties)) {
            if (
                [string]::Equals(
                    [string]$property.Name,
                    $propertyName,
                    [System.StringComparison]::OrdinalIgnoreCase
                )
            ) {
                $property.Value = $Value
                return
            }
        }
    }

    # Add HeaderLabel when an older layout object does not already contain it.
    $InputObject | Add-Member `
        -MemberType NoteProperty `
        -Name $PropertyNames[0] `
        -Value $Value
}

function Get-ProjectPickleDefaultReportHeaderLabel {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string]$FieldName,

        [string]$AppTable = "",

        [string]$ReportKey = "",

        [string]$ReportSection = ""
    )

    $fieldText = ConvertTo-BuilderText $FieldName

    if ([string]::IsNullOrWhiteSpace($fieldText)) {
        return ""
    }

    # Build a comparison key without spaces or punctuation.
    $fieldKey = (
        [regex]::Replace(
            $fieldText,
            "[^A-Za-z0-9]",
            ""
        )
    ).ToLowerInvariant()

    # Use the report key, section, and field table together so fields such as
    # SpeciesCode can use SPC in Tree but SPECIES in Regen.
    $context = (
        (
            (ConvertTo-BuilderText $ReportKey) + " " +
            (ConvertTo-BuilderText $ReportSection) + " " +
            (ConvertTo-BuilderText $AppTable)
        ).Trim()
    ).ToLowerInvariant()

    $isRegen = $context -match "regen"

    $isTree = (
        -not $isRegen -and
        $context -match "tree"
    )

    $isPlot = (
        -not $isRegen -and
        -not $isTree -and
        $context -match "plot"
    )

    if ($isTree) {
        $treeLabels = @{
            "treenumber"                 = "TREE"
            "treeno"                     = "TREE"

            "periodnumber"               = "YEAR"
            "measurementyear"            = "YEAR"
            "year"                       = "YEAR"

            "species"                    = "SPC"
            "speciescode"                = "SPC"
            "spc"                        = "SPC"

            "treehistory"                = "TREE HIST"
            "treehistorycode"            = "TREE HIST"
            "history"                    = "TREE HIST"

            "minorplot"                  = "MIN"
            "minorplotnumber"            = "MIN"
            "min"                        = "MIN"

            "idbh"                       = "DBH"
            "dbh"                        = "DBH"

            "totalheight"                = "TOTAL HGT"
            "totalhgt"                   = "TOTAL HGT"
            "heighttotal"                = "TOTAL HGT"

            "crownratio"                 = "CROWN RATIO"
            "cratio"                     = "CROWN RATIO"

            "crownclass"                 = "CROWN CLASS"
            "cclass"                     = "CROWN CLASS"

            "treeage"                    = "AGE"
            "age"                        = "AGE"

            "problem1"                   = "PROB1"
            "prob1"                      = "PROB1"
            "problemcode1"               = "PROB1"
            "problem1code"               = "PROB1"

            "severity1"                  = "SEV1"
            "sev1"                       = "SEV1"
            "severitycode1"              = "SEV1"
            "severity1code"              = "SEV1"

            "problem2"                   = "PROB2"
            "prob2"                      = "PROB2"
            "problemcode2"               = "PROB2"
            "problem2code"               = "PROB2"

            "severity2"                  = "SEV2"
            "sev2"                       = "SEV2"
            "severitycode2"              = "SEV2"
            "severity2code"              = "SEV2"

            "dmr"                        = "DMR"
            "damagemortalityremoval"     = "DMR"
            "damagemortalityremovalcode" = "DMR"

            "bdft"                       = "DEFECT BDFT"
            "bdftdefect"                 = "DEFECT BDFT"
            "defectbdft"                 = "DEFECT BDFT"
            "boardfootdefect"            = "DEFECT BDFT"
            "defectboardfoot"            = "DEFECT BDFT"
            "boardfeetdefect"            = "DEFECT BDFT"
            "defectboardfeet"            = "DEFECT BDFT"
            "totalbdftdefect"            = "DEFECT BDFT"
            "totalboardfootdefect"       = "DEFECT BDFT"

            "cuft"                       = "DEFECT CUFT"
            "cuftdefect"                 = "DEFECT CUFT"
            "defectcuft"                 = "DEFECT CUFT"
            "cubicfootdefect"            = "DEFECT CUFT"
            "defectcubicfoot"            = "DEFECT CUFT"
            "cubicfeetdefect"            = "DEFECT CUFT"
            "defectcubicfeet"            = "DEFECT CUFT"
            "totalcuftdefect"            = "DEFECT CUFT"
            "totalcubicfootdefect"       = "DEFECT CUFT"

            "snagclass"                  = "SNAG CLASS"

            "radialincrement"            = "RAD INC"
            "radialgrowth"               = "RAD INC"
            "radialgrowthincrement"      = "RAD INC"
            "radialinc"                  = "RAD INC"
            "radinc"                     = "RAD INC"

            "remarkstree"                = "REMARKS"
            "treeremarks"                = "REMARKS"
            "remarks"                    = "REMARKS"
        }

        if ($treeLabels.ContainsKey($fieldKey)) {
            return [string]$treeLabels[$fieldKey]
        }

        # Catch alternate board-foot defect field names.
        if (
            $fieldKey -match "defect" -and
            $fieldKey -match "(bdft|boardfoot|boardfeet|boardft)"
        ) {
            return "DEFECT BDFT"
        }

        # Catch alternate cubic-foot defect field names.
        if (
            $fieldKey -match "defect" -and
            $fieldKey -match "(cuft|cubicfoot|cubicfeet|cubicft)"
        ) {
            return "DEFECT CUFT"
        }
    }

    if ($isRegen) {
        $regenLabels = @{
            "periodnumber"      = "YEAR"
            "measurementyear"   = "YEAR"
            "year"              = "YEAR"

            "species"           = "SPECIES"
            "speciescode"       = "SPECIES"

            "minorplot"         = "MINOR PLOT"
            "minorplotnumber"   = "MINOR PLOT"
            "regenplot"         = "MINOR PLOT"
            "regenplotnumber"   = "MINOR PLOT"
            "plot"              = "MINOR PLOT"
            "plotnumber"        = "MINOR PLOT"

            "idbh"              = "DBH"
            "dbh"               = "DBH"

            "stemcount"         = "STEM COUNT"
            "regencount"        = "STEM COUNT"
            "treecount"         = "STEM COUNT"
            "seedlingcount"     = "STEM COUNT"
            "count"             = "STEM COUNT"

            "remarksregen"      = "REMARKS"
            "regenremarks"      = "REMARKS"
            "remarks"           = "REMARKS"
        }

        if ($regenLabels.ContainsKey($fieldKey)) {
            return [string]$regenLabels[$fieldKey]
        }
    }

    if ($isPlot) {
        $plotLabels = @{
            "periodnumber"          = "YEAR"
            "measurementyear"       = "YEAR"
            "year"                  = "YEAR"

            "fieldnamesampleremove" = "ENTER FIELD NAMES FROM PLOT CUSTOM MEAS TABLE HERE"

            "remarksplot"           = "PLOT REMARKS"
            "plotremarks"           = "PLOT REMARKS"
            "remarks"               = "PLOT REMARKS"
        }

        if ($plotLabels.ContainsKey($fieldKey)) {
            return [string]$plotLabels[$fieldKey]
        }
    }

    # These values are safe even when an older layout does not provide
    # enough context to identify Plot, Tree, or Regen.
    $commonLabels = @{
        "periodnumber"          = "YEAR"
        "measurementyear"       = "YEAR"
        "year"                  = "YEAR"
        "treenumber"            = "TREE"
        "remarkstree"           = "REMARKS"
        "remarksregen"          = "REMARKS"
        "remarksplot"           = "PLOT REMARKS"
        "stemcount"             = "STEM COUNT"
        "fieldnamesampleremove" = "ENTER FIELD NAMES FROM PLOT CUSTOM MEAS TABLE HERE"
    }

    if ($commonLabels.ContainsKey($fieldKey)) {
        return [string]$commonLabels[$fieldKey]
    }

    # A custom field without a standard report abbreviation starts with a
    # readable uppercase label made from its database field name.
    return (
        ConvertTo-ProjectPickleReportHeaderWords `
            -Value $fieldText
    )
}

function Set-ProjectPickleDefaultReportLabels {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [object]$Layout,

        [string]$ReportKey = ""
    )

    $resolvedReportKey = ConvertTo-BuilderText $ReportKey

    if ([string]::IsNullOrWhiteSpace($resolvedReportKey)) {
        $resolvedReportKey = ConvertTo-BuilderText (
            Get-ProjectPickleReportUiValue `
                -InputObject $Layout `
                -PropertyNames @(
                    "Key",
                    "ReportKey",
                    "Name",
                    "DisplayName",
                    "ReportName"
                )
        )
    }

    $reportSection = ConvertTo-BuilderText (
        Get-ProjectPickleReportUiValue `
            -InputObject $Layout `
            -PropertyNames @(
                "ReportSection",
                "Section",
                "Report",
                "ReportType"
            )
    )

    $layoutSpec = Get-ProjectPickleReportUiValue `
        -InputObject $Layout `
        -PropertyNames @(
            "Spec",
            "Definition",
            "LayoutSpec"
        )

    if (
        [string]::IsNullOrWhiteSpace($reportSection) -and
        $null -ne $layoutSpec
    ) {
        $reportSection = ConvertTo-BuilderText (
            Get-ProjectPickleReportUiValue `
                -InputObject $layoutSpec `
                -PropertyNames @(
                    "ReportSection",
                    "Section",
                    "Report",
                    "ReportType"
                )
        )
    }

    $columns = @(
        Get-ProjectPickleReportUiValue `
            -InputObject $Layout `
            -PropertyNames @(
                "Columns",
                "ReportColumns",
                "Rows",
                "ColumnRows",
                "ReportColumnRows"
            )
    )

    if ($columns.Count -eq 0) {
        return
    }

    foreach ($column in $columns) {
        if ($null -eq $column) {
            continue
        }

        $columnDefinition = Get-ProjectPickleReportUiValue `
            -InputObject $column `
            -PropertyNames @(
                "AppColumn",
                "ColumnDefinition",
                "Metadata"
            )

        $appTable = ConvertTo-BuilderText (
            Get-ProjectPickleReportUiValue `
                -InputObject $column `
                -PropertyNames @(
                    "AppTable",
                    "AppTableName",
                    "Table",
                    "TableName",
                    "SourceTable"
                )
        )

        $fieldName = ConvertTo-BuilderText (
            Get-ProjectPickleReportUiValue `
                -InputObject $column `
                -PropertyNames @(
                    "Field",
                    "FieldName",
                    "ColumnName",
                    "AppColumnName",
                    "AppColumnFieldName"
                )
        )

        if ($null -ne $columnDefinition) {
            if ([string]::IsNullOrWhiteSpace($appTable)) {
                $appTable = ConvertTo-BuilderText (
                    Get-ProjectPickleReportUiValue `
                        -InputObject $columnDefinition `
                        -PropertyNames @(
                            "AppTable",
                            "AppTableName",
                            "Table",
                            "TableName",
                            "SourceTable"
                        )
                )
            }

            if ([string]::IsNullOrWhiteSpace($fieldName)) {
                $fieldName = ConvertTo-BuilderText (
                    Get-ProjectPickleReportUiValue `
                        -InputObject $columnDefinition `
                        -PropertyNames @(
                            "Field",
                            "FieldName",
                            "ColumnName",
                            "AppColumnName",
                            "AppColumnFieldName"
                        )
                )
            }
        }

        if ([string]::IsNullOrWhiteSpace($fieldName)) {
            continue
        }

        $defaultLabel = Get-ProjectPickleDefaultReportHeaderLabel `
            -FieldName $fieldName `
            -AppTable $appTable `
            -ReportKey $resolvedReportKey `
            -ReportSection $reportSection

        if ([string]::IsNullOrWhiteSpace($defaultLabel)) {
            continue
        }

        Set-ProjectPickleReportUiValue `
            -InputObject $column `
            -PropertyNames @(
                "HeaderLabel",
                "ReportHeaderLabel",
                "ReportLabel",
                "ColumnLabel",
                "Label",
                "DisplayLabel"
            ) `
            -Value $defaultLabel
    }
}

function Set-ProjectPickleDefaultReportLabelsInState {
    [CmdletBinding()]
    param(
        [AllowNull()]
        [object]$State
    )

    # Intentionally disabled.
    #
    # The exact ReportHeaders rows loaded from the selected database are
    # the approved report template. Project Pickle must not generate or
    # replace labels for the existing template fields.
    return
}

# ---------------------------------------------------------------------------
# Report template identity protection
#
# Existing ReportColumns retain the ColumnID loaded from the selected
# database. Newly added fields are resolved from AppColumns during Build.
# ---------------------------------------------------------------------------
# ---------------------------------------------------------------------------
# Report template identity protection
#
# Existing fixed-width ReportHeaders are authoritative.
# Existing ReportColumns must retain the ColumnID that was loaded from the
# selected database. New fields are resolved from AppColumns during Build.
# ---------------------------------------------------------------------------

$script:ProjectPickleOriginalReportColumnIds = @{}

function Get-ProjectPickleGridColumnIndex {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [object]$Grid,

        [Parameter(Mandatory)]
        [string[]]$CandidateNames
    )

    foreach ($candidateName in $CandidateNames) {
        foreach ($column in $Grid.Columns) {
            $valuesToCheck = @(
                [string]$column.Name,
                [string]$column.DataPropertyName,
                [string]$column.HeaderText
            )

            foreach ($valueToCheck in $valuesToCheck) {
                if (
                    [string]::Equals(
                        $valueToCheck,
                        $candidateName,
                        [System.StringComparison]::OrdinalIgnoreCase
                    )
                ) {
                    return [int]$column.Index
                }
            }
        }
    }

    return -1
}

function Get-ProjectPickleReportModelValue {
    [CmdletBinding()]
    param(
        [AllowNull()]
        [object]$InputObject,

        [Parameter(Mandatory)]
        [string[]]$CandidateNames
    )

    if ($null -eq $InputObject) {
        return $null
    }

    if ($InputObject -is [System.Collections.IDictionary]) {
        foreach ($candidateName in $CandidateNames) {
            foreach ($existingKey in @($InputObject.Keys)) {
                if (
                    [string]::Equals(
                        [Convert]::ToString($existingKey),
                        $candidateName,
                        [System.StringComparison]::OrdinalIgnoreCase
                    )
                ) {
                    return $InputObject[$existingKey]
                }
            }
        }
    }

    foreach ($candidateName in $CandidateNames) {
        foreach ($property in @($InputObject.PSObject.Properties)) {
            if (
                [string]::Equals(
                    [Convert]::ToString($property.Name),
                    $candidateName,
                    [System.StringComparison]::OrdinalIgnoreCase
                )
            ) {
                return $property.Value
            }
        }
    }

    return $null
}

function Get-ProjectPickleReportLayoutsFromState {
    [CmdletBinding()]
    param(
        [AllowNull()]
        [object]$State
    )

    if ($null -eq $State) {
        return @()
    }

    $nestedLayouts =
        Get-ProjectPickleReportModelValue `
            -InputObject $State `
            -CandidateNames @(
                "Layouts",
                "ReportLayouts"
            )

    if (
        $null -ne $nestedLayouts -and
        -not [object]::ReferenceEquals(
            $nestedLayouts,
            $State
        )
    ) {
        return @(
            Get-ProjectPickleReportLayoutsFromState `
                -State $nestedLayouts
        )
    }

    if ($State -is [System.Collections.IDictionary]) {
        return @(
            $State.Values |
                Where-Object {
                    $null -ne $_
                }
        )
    }

    if (
        $State -is [System.Collections.IEnumerable] -and
        -not ($State -is [string])
    ) {
        return @(
            $State |
                Where-Object {
                    $null -ne $_
                }
        )
    }

    return @($State)
}

function Get-ProjectPickleReportColumnsFromLayout {
    [CmdletBinding()]
    param(
        [AllowNull()]
        [object]$Layout
    )

    if ($null -eq $Layout) {
        return @()
    }

    $columns =
        Get-ProjectPickleReportModelValue `
            -InputObject $Layout `
            -CandidateNames @(
                "Columns",
                "ReportColumns",
                "ColumnRows",
                "Rows"
            )

    if ($null -eq $columns) {
        return @()
    }

    if ($columns -is [System.Collections.IDictionary]) {
        return @(
            $columns.Values |
                Where-Object {
                    $null -ne $_
                }
        )
    }

    if (
        $columns -is [System.Collections.IEnumerable] -and
        -not ($columns -is [string])
    ) {
        return @(
            $columns |
                Where-Object {
                    $null -ne $_
                }
        )
    }

    return @($columns)
}

function Get-ProjectPickleReportColumnIdentityKey {
    [CmdletBinding()]
    param(
        [AllowNull()]
        [object]$Column
    )

    if ($null -eq $Column) {
        return ""
    }

    $appTableValue =
        Get-ProjectPickleReportModelValue `
            -InputObject $Column `
            -CandidateNames @(
                "AppTable",
                "AppTableName",
                "TableName",
                "Table"
            )

    $appTable =
        [Convert]::ToString($appTableValue).Trim()

    $fieldNameValue =
        Get-ProjectPickleReportModelValue `
            -InputObject $Column `
            -CandidateNames @(
                "Field",
                "FieldName",
                "ColumnName",
                "AppColumnName"
            )

    $fieldName =
        [Convert]::ToString($fieldNameValue).Trim()

    if (
        [string]::IsNullOrWhiteSpace($appTable) -or
        [string]::IsNullOrWhiteSpace($fieldName)
    ) {
        return ""
    }

    return (
        "{0}|{1}" -f
        $appTable,
        $fieldName
    ).ToUpperInvariant()
}

function Get-ProjectPickleReportColumnIdText {
    [CmdletBinding()]
    param(
        [AllowNull()]
        [object]$Column
    )

    if ($null -eq $Column) {
        return ""
    }

    $columnIdValue =
        Get-ProjectPickleReportModelValue `
            -InputObject $Column `
            -CandidateNames @(
                "ColumnID",
                "AppColumnID",
                "AppColumnsID",
                "SourceColumnID",
                "OriginalColumnID",
                "ResolvedColumnID"
            )

    return [Convert]::ToString(
        $columnIdValue
    ).Trim()
}

function Initialize-ProjectPickleReportColumnIdBaseline {
    [CmdletBinding()]
    param(
        [AllowNull()]
        [object]$State
    )

    $script:ProjectPickleOriginalReportColumnIds = @{}

    $layouts = @(
        Get-ProjectPickleReportLayoutsFromState `
            -State $State
    )

    foreach ($layout in $layouts) {
        $columns = @(
            Get-ProjectPickleReportColumnsFromLayout `
                -Layout $layout
        )

        foreach ($column in $columns) {
            $identityKey =
                Get-ProjectPickleReportColumnIdentityKey `
                    -Column $column

            $columnId =
                Get-ProjectPickleReportColumnIdText `
                    -Column $column

            if (
                [string]::IsNullOrWhiteSpace($identityKey) -or
                [string]::IsNullOrWhiteSpace($columnId)
            ) {
                continue
            }

            $appTableValue =
                Get-ProjectPickleReportModelValue `
                    -InputObject $column `
                    -CandidateNames @(
                        "AppTable",
                        "AppTableName",
                        "TableName",
                        "Table"
                    )

            $appTable =
                [Convert]::ToString($appTableValue).Trim()

            $fieldNameValue =
                Get-ProjectPickleReportModelValue `
                    -InputObject $column `
                    -CandidateNames @(
                        "Field",
                        "FieldName",
                        "ColumnName",
                        "AppColumnName"
                    )

            $fieldName =
                [Convert]::ToString($fieldNameValue).Trim()

            if (
                $script:ProjectPickleOriginalReportColumnIds.ContainsKey(
                    $identityKey
                )
            ) {
                $existingRecord =
                    $script:ProjectPickleOriginalReportColumnIds[
                        $identityKey
                    ]

                $existingColumnId =
                    [Convert]::ToString(
                        $existingRecord.ColumnID
                    ).Trim()

                if (
                    -not [string]::Equals(
                        $existingColumnId,
                        $columnId,
                        [System.StringComparison]::OrdinalIgnoreCase
                    )
                ) {
                    throw (
                        "The selected database contains more than one " +
                        "ColumnID for report field '{0}.{1}'." -f
                        $appTable,
                        $fieldName
                    )
                }

                continue
            }

            $script:ProjectPickleOriginalReportColumnIds[
                $identityKey
            ] = [pscustomobject]@{
                ColumnID  = $columnId
                AppTable  = $appTable
                FieldName = $fieldName
            }
        }
    }
}

function Assert-ProjectPickleDefaultReportColumnIdsUnchanged {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [object[]]$Layouts
    )

    if (
        $null -eq $script:ProjectPickleOriginalReportColumnIds -or
        $script:ProjectPickleOriginalReportColumnIds.Count -eq 0
    ) {
        throw (
            "No original ReportColumns ColumnID baseline is loaded. " +
            "Click 'Load all from selected database' on the Reports tab " +
            "before saving or building manual report layouts."
        )
    }

    $resolvedLayouts = @(
        Get-ProjectPickleReportLayoutsFromState `
            -State $Layouts
    )

    foreach ($layout in $resolvedLayouts) {
        $columns = @(
            Get-ProjectPickleReportColumnsFromLayout `
                -Layout $layout
        )

        foreach ($column in $columns) {
            $identityKey =
                Get-ProjectPickleReportColumnIdentityKey `
                    -Column $column

            if (
                [string]::IsNullOrWhiteSpace($identityKey) -or
                -not $script:ProjectPickleOriginalReportColumnIds.ContainsKey(
                    $identityKey
                )
            ) {
                # This row was not in the loaded template.
                # It is treated as a newly added report field.
                continue
            }

            $originalRecord =
                $script:ProjectPickleOriginalReportColumnIds[
                    $identityKey
                ]

            $originalColumnId =
                [Convert]::ToString(
                    $originalRecord.ColumnID
                ).Trim()

            $currentColumnId =
                Get-ProjectPickleReportColumnIdText `
                    -Column $column

            if ([string]::IsNullOrWhiteSpace($currentColumnId)) {
                throw (
                    "Default report field '{0}.{1}' lost its ColumnID. " +
                    "Reload the report layouts from the selected database." -f
                    $originalRecord.AppTable,
                    $originalRecord.FieldName
                )
            }

            if (
                -not [string]::Equals(
                    $originalColumnId,
                    $currentColumnId,
                    [System.StringComparison]::OrdinalIgnoreCase
                )
            ) {
                throw (
                    "Default report field '{0}.{1}' changed ColumnID " +
                    "from '{2}' to '{3}'. Default ColumnIDs are locked. " +
                    "Reload the report layouts from the selected database." -f
                    $originalRecord.AppTable,
                    $originalRecord.FieldName,
                    $originalColumnId,
                    $currentColumnId
                )
            }
        }
    }
}

function Get-ProjectPickleReportGridRowIdentityKey {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [object]$Grid,

        [Parameter(Mandatory)]
        [int]$RowIndex
    )

    if (
        $RowIndex -lt 0 -or
        $RowIndex -ge $Grid.Rows.Count
    ) {
        return ""
    }

    $appTableColumnIndex =
        Get-ProjectPickleGridColumnIndex `
            -Grid $Grid `
            -CandidateNames @(
                "AppTable",
                "AppTableName",
                "TableName",
                "App table"
            )

    $fieldColumnIndex =
        Get-ProjectPickleGridColumnIndex `
            -Grid $Grid `
            -CandidateNames @(
                "Field",
                "FieldName",
                "ColumnName",
                "AppColumnName"
            )

    if (
        $appTableColumnIndex -lt 0 -or
        $fieldColumnIndex -lt 0
    ) {
        return ""
    }

    $appTableCellValue =
        $Grid.Rows[
            $RowIndex
        ].Cells[
            $appTableColumnIndex
        ].Value

    $appTable =
        [Convert]::ToString(
            $appTableCellValue
        ).Trim()

    $fieldCellValue =
        $Grid.Rows[
            $RowIndex
        ].Cells[
            $fieldColumnIndex
        ].Value

    $fieldName =
        [Convert]::ToString(
            $fieldCellValue
        ).Trim()

    if (
        [string]::IsNullOrWhiteSpace($appTable) -or
        [string]::IsNullOrWhiteSpace($fieldName)
    ) {
        return ""
    }

    return (
        "{0}|{1}" -f
        $appTable,
        $fieldName
    ).ToUpperInvariant()
}
function Get-ReportFieldLabel {
    param([object]$Field)

    foreach ($name in @("Label", "ShortName", "FriendlyName", "FieldName", "ColumnName")) {
        if ($Field.PSObject.Properties[$name]) {
            $text = ConvertTo-BuilderText $Field.PSObject.Properties[$name].Value
            if (-not [string]::IsNullOrWhiteSpace($text)) { return $text }
        }
    }
    return "Custom Field"
}

function Get-ReportHeaderWidth {
    param(
        [string]$FieldFormat,
        [string]$Label
    )

    $format = ConvertTo-BuilderText $FieldFormat
    $width = 10
    if ($format -match "(?i)^TEXT,(\d+)") {
        $width = [int]$matches[1]
    }
    elseif ($format -match "\{0,(-?\d+)") {
        $width = [Math]::Abs([int]$matches[1])
    }
    elseif ($format -match "(?i)^DATE") {
        $width = 14
    }
    $labelLength = (ConvertTo-BuilderText $Label).Length
    if ($labelLength -gt 0) {
        $width = [Math]::Max($width, [Math]::Min(18, $labelLength + 2))
    }
    return [Math]::Max(6, [Math]::Min(50, $width))
}

function Format-ReportCellText {
    param(
        [string]$Text,
        [int]$Width
    )

    $value = (ConvertTo-BuilderText $Text).ToUpperInvariant()
    if ($value.Length -gt $Width) { $value = $value.Substring(0, $Width) }
    $left = [Math]::Floor(($Width - $value.Length) / 2)
    $right = $Width - $value.Length - $left
    return (" " * $left) + $value + (" " * $right)
}

function Split-ReportHeaderLabel {
    param(
        [string]$Label,
        [int]$Width
    )

    $clean = [regex]::Replace((ConvertTo-BuilderText $Label), "\s+", " ").Trim()
    if ([string]::IsNullOrWhiteSpace($clean)) { return @("", "") }
    if ($clean.Length -le $Width) { return @($clean, "") }

    $words = @($clean -split " ")
    $line1 = ""
    $line2 = ""
    foreach ($word in $words) {
        if ([string]::IsNullOrWhiteSpace($line1)) {
            $line1 = $word
        }
        elseif (($line1.Length + 1 + $word.Length) -le $Width) {
            $line1 = "$line1 $word"
        }
        elseif ([string]::IsNullOrWhiteSpace($line2)) {
            $line2 = $word
        }
        elseif (($line2.Length + 1 + $word.Length) -le $Width) {
            $line2 = "$line2 $word"
        }
    }
    if ([string]::IsNullOrWhiteSpace($line2) -and $line1.Length -gt $Width) {
        $line2 = $line1.Substring($Width)
        $line1 = $line1.Substring(0, $Width)
    }
    return @($line1, $line2)
}

function New-ReportFieldFormat {
    param([object]$Field)

    $label = Get-ReportFieldLabel -Field $Field
    $width = [Math]::Max(10, [Math]::Min(18, $label.Length + 2))
    $dataType = ConvertTo-BuilderText $Field.DataType
    if ($dataType -match "(?i)text|memo|long") {
        return "TEXT,$width,6"
    }
    if ($dataType -match "(?i)date") {
        return "DATE,01"
    }
    return "{0,$width:g0}"
}

function New-ReportTallyFormat {
    param([string]$FieldFormat)

    $width = Get-ReportHeaderWidth -FieldFormat $FieldFormat -Label ""
    return "_" * [Math]::Max(1, [Math]::Min(22, $width))
}

function New-ReportHeaderLines {
    param(
        [string]$Title,
        [object[]]$Columns
    )

    $cells = New-Object System.Collections.Generic.List[object]
    foreach ($column in @($Columns)) {
        $label = Get-ReportFieldLabel -Field $column
        $width = Get-ReportHeaderWidth -FieldFormat (ConvertTo-BuilderText $column.FieldFormat) -Label $label
        $split = @(Split-ReportHeaderLabel -Label $label -Width $width)
        [void]$cells.Add([pscustomobject]@{
            Width = $width
            Line1 = $split[0]
            Line2 = $split[1]
        })
    }
    if ($cells.Count -eq 0) { return @() }

    $innerWidth = 0
    foreach ($cell in $cells) { $innerWidth += [int]$cell.Width }
    $innerWidth += [Math]::Max(0, $cells.Count - 1)
    $titleText = (ConvertTo-BuilderText $Title).ToUpperInvariant()
    if ($titleText.Length -gt $innerWidth) { $titleText = $titleText.Substring(0, $innerWidth) }
    $dashLeft = [Math]::Max(1, [Math]::Floor(($innerWidth - $titleText.Length - 2) / 2))
    $dashRight = [Math]::Max(1, $innerWidth - $titleText.Length - 2 - $dashLeft)
    $titleLine = ("-" * $dashLeft) + " " + $titleText + " " + ("-" * $dashRight)
    if ($titleLine.Length -lt $innerWidth) { $titleLine += "-" * ($innerWidth - $titleLine.Length) }
    if ($titleLine.Length -gt $innerWidth) { $titleLine = $titleLine.Substring(0, $innerWidth) }

    $line1Cells = @($cells | ForEach-Object { Format-ReportCellText -Text $_.Line1 -Width $_.Width })
    $line2Cells = @($cells | ForEach-Object { Format-ReportCellText -Text $_.Line2 -Width $_.Width })
    $separatorCells = @($cells | ForEach-Object { "-" * $_.Width })
    return @(
        "",
        "     |$titleLine|",
        "     |$([string]::Join('|', [string[]]$line1Cells))|",
        "YEAR |$([string]::Join('|', [string[]]$line2Cells))|",
        "     |$([string]::Join('|', [string[]]$separatorCells))|",
        ""
    )
}

function Get-CustomReportHeaderTemplate {
    param(
        [string]$Section,
        [int]$Group
    )

    $sectionText = ConvertTo-BuilderText $Section
    if ([string]::Equals($sectionText, "Plot", [System.StringComparison]::OrdinalIgnoreCase) -and $Group -eq 3) {
        return @(
            "",
            "     <----------------------------------------------------------------------------------------------------PLOT MEASUREMENTS ---------------------------------------------------------------------------------------------------->",
            "     |                                                                                                                                                                                                                           |",
            "YEAR |                                                                                                                                                                                                                           |",
            "     |     PLOT REMARKS                                                                                                                                                                                                          |",
            "     |===========================================================================================================================================================================================================================|"
        )
    }
    if ([string]::Equals($sectionText, "Tree", [System.StringComparison]::OrdinalIgnoreCase) -and $Group -eq 1) {
        return @(
            "",
            "|----------------------------------------------------------------------------------------------------TREE MEASUREMENTS----------------------------------------------------------------------------------------------------|",
            "|                                                                                                                                                                                                                  |",
            "YEAR |                                                                                                                                                                                                              |",
            "|     TREE REMARKS                                                                                                                                                                                                 |",
            "|==================================================================================================================================================================================================================|"
        )
    }
    if ([string]::Equals($sectionText, "Regen", [System.StringComparison]::OrdinalIgnoreCase) -and $Group -eq 1) {
        return @(
            "",
            "     <----------------------------------------------REGEN INFORMATION---------------------------------------------->",
            "     |                                                                                                             |",
            "YEAR |                                                                                                             |",
            "     |     REGEN REMARKS                                                                                           |",
            "     |=============================================================================================================|"
        )
    }
    return @()
}

function Get-ReportColumnsForHeader {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$Section,
        [int]$Group
    )

    $sql = @"
SELECT rc.[ReportIndex], rc.[FieldFormat], rc.[TallyFormat],
       ac.[ColumnName], ac.[FriendlyName], ac.[ShortName]
FROM [ReportColumns] AS rc
LEFT JOIN [AppColumns] AS ac ON rc.[ColumnID] = ac.[ID]
WHERE rc.[ReportSection] = $(Sql-Text $Section) AND rc.[ReportGroup] = $Group
ORDER BY rc.[ReportIndex]
"@
    $table = Get-DbTable -Connection $Connection -Sql $sql
    $items = New-Object System.Collections.Generic.List[object]
    foreach ($row in $table.Rows) {
        [void]$items.Add([pscustomobject]@{
            FieldFormat = Get-DataRowText -Row $row -ColumnNames @("FieldFormat")
            TallyFormat = Get-DataRowText -Row $row -ColumnNames @("TallyFormat")
            ColumnName = Get-DataRowText -Row $row -ColumnNames @("ColumnName")
            FriendlyName = Get-DataRowText -Row $row -ColumnNames @("FriendlyName")
            ShortName = Get-DataRowText -Row $row -ColumnNames @("ShortName")
        })
    }
    return @($items.ToArray())
}

function Set-ReportHeaderLines {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$Section,
        [object]$Group = $null,
        [string[]]$Lines,
        [switch]$GroupIsNull
    )

    if (-not (Test-TableExists -Connection $Connection -TableName "ReportHeaders")) { return }
    $useNullGroup = $GroupIsNull.IsPresent -or $null -eq $Group -or $Group -is [System.DBNull] -or [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Group))
    if ($useNullGroup) {
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "DELETE FROM [ReportHeaders] WHERE [ReportSection] = ? AND [ReportGroup] Is Null" -Parameters @((DbText $Section)))
    }
    else {
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "DELETE FROM [ReportHeaders] WHERE [ReportSection] = ? AND [ReportGroup] = ?" -Parameters @(
            (DbText $Section),
            (DbInt $Group)
        ))
    }

    $lineNumber = 1
    foreach ($line in @($Lines)) {
        # ReportHeaders is fixed-width data. Never call ConvertTo-BuilderText or
        # DbLongText here because both collapse the spaces that make the report align.
        $headerLine = ConvertTo-RawSingleLineText $line
        if ($headerLine.Length -gt 255) { $headerLine = $headerLine.Substring(0, 255) }
        $groupValue = if ($useNullGroup) { $null } else { $Group }
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [ReportHeaders] ([ReportSection], [ReportGroup], [LineNumber], [Header]) VALUES (?, ?, ?, ?)" -Parameters @(
            (DbText $Section),
            (DbInt $groupValue),
            (DbInt $lineNumber),
            (DbRawLongText $headerLine)
        ))
        $lineNumber++
    }
}

function Update-ReportSetup {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [object[]]$CustomFields,
        [scriptblock]$Log
    )

    if (-not (Test-TableExists -Connection $Connection -TableName "ReportColumns")) { return }
    $reportFields = @($CustomFields | Where-Object { (ConvertTo-BuilderBool $_.Active) -and (ConvertTo-BuilderBool $_.ReportVisible) -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $_.AppColumnID)) })
    $reportSpecs = @(
        @{ TableName = "PlotCustomMeasurements"; Section = "Plot"; Group = 3; HeaderGroup = 3; HeaderGroupIsNull = $false; AnchorTable = "PlotMeasurements"; AnchorColumn = "RemarksPlot"; HeaderTitle = "Additional Plot Information" },
        @{ TableName = "TreeCustomMeasurements"; Section = "Tree"; Group = 1; HeaderGroup = 1; HeaderGroupIsNull = $false; AnchorTable = "TreeMeasurements"; AnchorColumn = "RemarksTree"; HeaderTitle = "Tree Measurements" },
        @{ TableName = "RegenCustomMeasurements"; Section = "Regen"; Group = 1; HeaderGroup = $null; HeaderGroupIsNull = $true; AnchorTable = "RegenMeasurements"; AnchorColumn = "RemarksRegen"; HeaderTitle = "Regeneration Information" }
    )

    foreach ($spec in $reportSpecs) {
        $customTableName = [string]$spec.TableName
        $section = [string]$spec.Section
        $group = [int]$spec.Group
        $anchorTableName = [string]$spec.AnchorTable
        $anchorColumnName = [string]$spec.AnchorColumn
        $sectionFields = @($reportFields | Where-Object { [string]::Equals((ConvertTo-BuilderText $_.TableName), $customTableName, [System.StringComparison]::OrdinalIgnoreCase) })
        $customTableId = $null
        try {
            $customTableId = Get-AppTableId -Connection $Connection -TableName $customTableName
        }
        catch {
            & $Log "Report setup skipped $customTableName because AppTables does not contain it."
            continue
        }

        $existingCustomRows = Get-DbTable -Connection $Connection -Sql "SELECT rc.[ReportSection], rc.[ReportGroup], rc.[ColumnID] FROM [ReportColumns] AS rc INNER JOIN [AppColumns] AS ac ON rc.[ColumnID] = ac.[ID] WHERE ac.[TableID] = $customTableId"
        foreach ($row in $existingCustomRows.Rows) {
            $columnId = Get-DataRowText -Row $row -ColumnNames @("ColumnID")
            if (-not [string]::IsNullOrWhiteSpace($columnId)) {
                [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "DELETE FROM [ReportColumns] WHERE [ReportSection] = ? AND [ReportGroup] = ? AND [ColumnID] = ?" -Parameters @(
                    (DbText (Get-DataRowText -Row $row -ColumnNames @("ReportSection"))),
                    (DbInt (Get-DataRowText -Row $row -ColumnNames @("ReportGroup"))),
                    (DbGuid $columnId)
                ))
            }
        }

        # Older Project Pickle builds wrote Regen headers to numeric group 1 even
        # though the master schema stores Regen ReportHeaders with a Null group.
        # Remove that stale duplicate even when no custom Regen field is selected.
        if ((ConvertTo-BuilderBool $spec.HeaderGroupIsNull) -and [string]::Equals($section, "Regen", [System.StringComparison]::OrdinalIgnoreCase)) {
            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "DELETE FROM [ReportHeaders] WHERE [ReportSection] = ? AND [ReportGroup] = ?" -Parameters @(
                (DbText $section),
                (DbInt $group)
            ))
        }

        if ($sectionFields.Count -eq 0) {
            & $Log "No report-visible custom fields selected for $section."
            continue
        }

        $insertIndex = 1
        $anchorFound = $false
        try {
            $anchorTableId = Get-AppTableId -Connection $Connection -TableName $anchorTableName
            $anchorColumnId = Get-DbScalar -Connection $Connection -Sql "SELECT TOP 1 [ID] FROM [AppColumns] WHERE [TableID] = $anchorTableId AND [ColumnName] = $(Sql-Text $anchorColumnName)"
            if ($null -ne $anchorColumnId -and -not ($anchorColumnId -is [System.DBNull])) {
                $anchorIndex = Get-DbScalar -Connection $Connection -Sql "SELECT TOP 1 [ReportIndex] FROM [ReportColumns] WHERE [ReportSection] = $(Sql-Text $section) AND [ReportGroup] = $group AND [ColumnID] = $(Sql-Guid (ConvertTo-BuilderText $anchorColumnId))"
                if ($null -ne $anchorIndex -and -not ($anchorIndex -is [System.DBNull])) {
                    $insertIndex = [int]$anchorIndex
                    $anchorFound = $true
                }
            }
        }
        catch {
            & $Log "Could not find $section report anchor $anchorTableName.$anchorColumnName; custom fields will be appended."
        }
        if ($insertIndex -le 0) { $insertIndex = 1 }
        if (-not $anchorFound) {
            $maxIndex = Get-DbScalar -Connection $Connection -Sql "SELECT Max([ReportIndex]) FROM [ReportColumns] WHERE [ReportSection] = $(Sql-Text $section) AND [ReportGroup] = $group"
            if ($null -ne $maxIndex -and -not ($maxIndex -is [System.DBNull])) { $insertIndex = [int]$maxIndex + 1 }
        }

        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "UPDATE [ReportColumns] SET [ReportIndex] = [ReportIndex] + ? WHERE [ReportSection] = ? AND [ReportGroup] = ? AND [ReportIndex] >= ?" -Parameters @(
            (DbInt $sectionFields.Count),
            (DbText $section),
            (DbInt $group),
            (DbInt $insertIndex)
        ))

        $index = $insertIndex
        foreach ($field in $sectionFields) {
            $fieldFormat = New-ReportFieldFormat -Field $field
            [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql "INSERT INTO [ReportColumns] ([ReportSection], [ReportGroup], [ReportIndex], [ColumnID], [FieldFormat], [TallyFormat]) VALUES (?, ?, ?, ?, ?, ?)" -Parameters @(
                (DbText $section),
                (DbInt $group),
                (DbInt $index),
                (DbGuid $field.AppColumnID),
                (DbText $fieldFormat),
                (DbText (New-ReportTallyFormat -FieldFormat $fieldFormat))
            ))
            $index++
        }

        $headerColumns = @(Get-ReportColumnsForHeader -Connection $Connection -Section $section -Group $group)
        if ($headerColumns.Count -gt 0) {
            $headerLines = @(New-ReportHeaderLines -Title ([string]$spec.HeaderTitle) -Columns $headerColumns)
            if (ConvertTo-BuilderBool $spec.HeaderGroupIsNull) {
                Set-ReportHeaderLines -Connection $Connection -Section $section -Group $null -GroupIsNull -Lines ([string[]]$headerLines)
            }
            else {
                Set-ReportHeaderLines -Connection $Connection -Section $section -Group ([int]$spec.HeaderGroup) -Lines ([string[]]$headerLines)
            }
        }
        & $Log "Inserted $($sectionFields.Count) $section custom report field(s) before $anchorColumnName."
    }
}

function Get-ActiveFieldsForTable {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$TableName,
        [string[]]$RequiredFirst = @(),
        [string[]]$RequiredLast = @(),
        [string[]]$Exclude = @()
    )

    $columnInfo = @(Get-TableColumnInfo -Connection $Connection -TableName $TableName)
    $columns = @($columnInfo | ForEach-Object { ConvertTo-BuilderText $_.ColumnName })
    $schemaDataTypes = @{}
    foreach ($columnSpec in $columnInfo) {
        $columnName = ConvertTo-BuilderText $columnSpec.ColumnName
        if (-not [string]::IsNullOrWhiteSpace($columnName)) {
            $schemaDataTypes[$columnName] = ConvertTo-BuilderText $columnSpec.DataType
        }
    }
    $tableId = if (Test-TableExists -Connection $Connection -TableName "AppTables") { Get-AppTableId -Connection $Connection -TableName $TableName } else { -1 }
    $metadata = @{}
    if ($tableId -gt 0 -and (Test-TableExists -Connection $Connection -TableName "AppColumns")) {
        $rows = Get-DbTable -Connection $Connection -Sql "SELECT ac.[ColumnName], ac.[Active], appdt.[TypeName] FROM [AppColumns] AS ac LEFT JOIN [AppColumnDataTypes] AS appdt ON ac.[DataTypeID] = appdt.[ID] WHERE ac.[TableID] = $tableId"
        foreach ($row in $rows.Rows) {
            $columnName = ConvertTo-BuilderText $row["ColumnName"]
            if ([string]::IsNullOrWhiteSpace($columnName)) { continue }
            $metadata[$columnName] = [pscustomobject]@{
                Active = ConvertTo-BuilderBool $row["Active"]
                DataType = Get-DataRowText -Row $row -ColumnNames @("TypeName")
            }
        }
    }
    $newFieldSpecForColumn = {
        param([string]$ColumnName)

        $appDataType = if ($metadata.ContainsKey($ColumnName)) { ConvertTo-BuilderText $metadata[$ColumnName].DataType } else { "" }
        $schemaDataType = if ($schemaDataTypes.ContainsKey($ColumnName)) { ConvertTo-BuilderText $schemaDataTypes[$ColumnName] } else { "" }
        $dataType = if ($TableName -like "*CustomMeasurements" -and -not [string]::IsNullOrWhiteSpace($appDataType)) { $appDataType } elseif (-not [string]::IsNullOrWhiteSpace($schemaDataType)) { $schemaDataType } else { $appDataType }
        New-CfideerFieldSpec -FieldName $ColumnName -DataType $dataType
    }
    $fields = New-Object System.Collections.Generic.List[object]
    foreach ($first in $RequiredFirst) {
        if ($columns -contains $first -and @($fields | Where-Object { [string]::Equals((Get-CfideerFieldName $_), $first, [System.StringComparison]::OrdinalIgnoreCase) }).Count -eq 0) {
            [void]$fields.Add((& $newFieldSpecForColumn $first))
        }
    }
    foreach ($column in $columns) {
        if ($Exclude -contains $column) { continue }
        if (Test-CfideerSampleRemoveField -FieldName $column) { continue }
        if ($RequiredFirst -contains $column) { continue }
        if ($RequiredLast -contains $column) { continue }
        if ($metadata.ContainsKey($column) -and -not (ConvertTo-BuilderBool $metadata[$column].Active)) { continue }
        [void]$fields.Add((& $newFieldSpecForColumn $column))
    }
    foreach ($last in $RequiredLast) {
        if ($columns -contains $last -and @($fields | Where-Object { [string]::Equals((Get-CfideerFieldName $_), $last, [System.StringComparison]::OrdinalIgnoreCase) }).Count -eq 0) {
            [void]$fields.Add((& $newFieldSpecForColumn $last))
        }
    }
    return @($fields.ToArray())
}

function New-CfideerQueryVisibleLookup {
    param([object[]]$CustomFields)

    $lookup = @{}
    foreach ($field in @($CustomFields)) {
        if ($null -eq $field) { continue }
        $tableName = ConvertTo-BuilderText $field.TableName
        $fieldName = ConvertTo-AccessFieldName $field.FieldName
        if ([string]::IsNullOrWhiteSpace($tableName) -or [string]::IsNullOrWhiteSpace($fieldName)) { continue }
        $active = if ($field.PSObject.Properties["Active"]) { ConvertTo-BuilderBool $field.Active } else { $true }
        $queryVisible = if ($field.PSObject.Properties["QueryVisible"]) { ConvertTo-BuilderBool $field.QueryVisible } else { $true }
        $key = ("{0}|{1}" -f $tableName, $fieldName).ToLowerInvariant()
        $lookup[$key] = ($active -and $queryVisible)
    }
    return $lookup
}

function Filter-CfideerFieldsByQueryVisible {
    param(
        [object[]]$Fields,
        [string]$TableName,
        [hashtable]$QueryVisibleLookup
    )

    if ($null -eq $QueryVisibleLookup -or $QueryVisibleLookup.Count -eq 0) { return @($Fields) }
    return @($Fields | Where-Object {
        $fieldName = Get-CfideerFieldName $_
        if ([string]::IsNullOrWhiteSpace($fieldName)) { $false }
        else {
            $key = ("{0}|{1}" -f $TableName, $fieldName).ToLowerInvariant()
            if ($QueryVisibleLookup.ContainsKey($key)) {
                ConvertTo-BuilderBool $QueryVisibleLookup[$key]
            }
            else {
                if ($TableName -like "*CustomMeasurements") {
                    return @("MeasurementID", "PlotMeasKey", "TreeMeasKey", "RegenMeasKey") -contains $fieldName
                }
                $true
            }
        }
    })
}

function New-CfideerFieldSpec {
    param(
        [string]$FieldName,
        [string]$DataType = ""
    )

    return [pscustomobject]@{
        FieldName = ConvertTo-BuilderText $FieldName
        DataType = ConvertTo-BuilderText $DataType
    }
}

function Get-CfideerFieldName {
    param([object]$Field)

    if ($null -eq $Field) { return "" }
    if ($Field -is [string]) { return ConvertTo-BuilderText $Field }
    foreach ($name in @("FieldName", "ColumnName", "Name")) {
        if ($Field.PSObject.Properties[$name]) {
            return ConvertTo-BuilderText $Field.PSObject.Properties[$name].Value
        }
    }
    return ConvertTo-BuilderText $Field
}

function Get-CfideerFieldDataType {
    param([object]$Field)

    if ($null -eq $Field -or $Field -is [string]) { return "" }
    if ($Field.PSObject.Properties["DataType"]) {
        return ConvertTo-BuilderText $Field.DataType
    }
    if ($Field.PSObject.Properties["TypeName"]) {
        return ConvertTo-BuilderText $Field.TypeName
    }
    return ""
}

function Test-CfideerSampleRemoveField {
    param([string]$FieldName)

    return [string]::Equals((ConvertTo-BuilderText $FieldName), "FieldNameSampleRemove", [System.StringComparison]::OrdinalIgnoreCase)
}

function Format-CfideerFieldReference {
    param([string]$FieldName)

    $name = ConvertTo-BuilderText $FieldName
    if ($name -match "^[A-Za-z_][A-Za-z0-9_]*$") { return $name }
    return Quote-Name $name
}

function Format-CfideerParameterDeclarationName {
    param([string]$FieldName)

    $name = ConvertTo-BuilderText $FieldName
    if ($name -match "^[A-Za-z_][A-Za-z0-9_]*$") { return $name }
    return Quote-Name $name
}

function Get-CfideerParameterType {
    param(
        [string]$FieldName,
        [string]$DataType,
        [string]$DefaultType = "Text"
    )

    $field = ConvertTo-BuilderText $FieldName
    if ([string]::Equals($field, "IsDeleted", [System.StringComparison]::OrdinalIgnoreCase)) { return "Text" }
    if ($field -match "ID$") { return "Guid" }
    if ($field -match "Date|Created|Updated") { return "DateTime" }

    $type = (ConvertTo-BuilderText $DataType).ToLowerInvariant()
    switch ($type) {
        "guid" { return "Guid" }
        "uniqueidentifier" { return "Guid" }
        "byte" { return "Byte" }
        "integer" { return "Short" }
        "short" { return "Short" }
        "smallint" { return "Short" }
        "long integer" { return "Long" }
        "long" { return "Long" }
        "single" { return "Single" }
        "double" { return "Double" }
        "date/time" { return "DateTime" }
        "datetime" { return "DateTime" }
        "date" { return "DateTime" }
        "currency" { return "Currency" }
        "boolean" { return "Bit" }
        "yes/no" { return "Bit" }
        "bit" { return "Bit" }
        "memo" { return "Text" }
        "long text" { return "Text" }
        "short text" { return "Text" }
        "text" { return "Text" }
    }

    return $DefaultType
}

function New-SelectList {
    param(
        [string]$TableName,
        [object[]]$Fields
    )

    return [string]::Join(", ", [string[]]($Fields | ForEach-Object {
        $fieldName = Get-CfideerFieldName $_
        if ([string]::IsNullOrWhiteSpace($fieldName) -or (Test-CfideerSampleRemoveField -FieldName $fieldName)) { return }
        "$TableName.$(Format-CfideerFieldReference $fieldName)"
    } | Where-Object { -not [string]::IsNullOrWhiteSpace($_) }))
}

function New-SelectListWithCustomAfter {
    param(
        [string]$BaseTableName,
        [object[]]$BaseFields,
        [string]$AfterFieldName,
        [string]$CustomTableName,
        [object[]]$CustomFields,
        [string[]]$TrailingBaseFieldNames = @()
    )

    $parts = New-Object System.Collections.Generic.List[string]
    $insertedCustomFields = $false
    $trailingLookup = New-Object "System.Collections.Generic.HashSet[string]" ([System.StringComparer]::OrdinalIgnoreCase)
    foreach ($fieldName in @($TrailingBaseFieldNames)) {
        $cleanTrailingName = ConvertTo-BuilderText $fieldName
        if (-not [string]::IsNullOrWhiteSpace($cleanTrailingName)) { [void]$trailingLookup.Add($cleanTrailingName) }
    }
    $addFields = {
        param(
            [string]$TableName,
            [object[]]$Fields
        )

        foreach ($field in @($Fields)) {
            $fieldName = Get-CfideerFieldName $field
            if ([string]::IsNullOrWhiteSpace($fieldName) -or (Test-CfideerSampleRemoveField -FieldName $fieldName)) { continue }
            [void]$parts.Add("$TableName.$(Format-CfideerFieldReference $fieldName)")
        }
    }

    foreach ($field in @($BaseFields)) {
        $fieldName = Get-CfideerFieldName $field
        if ([string]::IsNullOrWhiteSpace($fieldName) -or (Test-CfideerSampleRemoveField -FieldName $fieldName)) { continue }
        if ($trailingLookup.Contains($fieldName)) { continue }
        [void]$parts.Add("$BaseTableName.$(Format-CfideerFieldReference $fieldName)")
        if (-not $insertedCustomFields -and [string]::Equals($fieldName, $AfterFieldName, [System.StringComparison]::OrdinalIgnoreCase)) {
            & $addFields $CustomTableName $CustomFields
            $insertedCustomFields = $true
        }
    }

    if (-not $insertedCustomFields) {
        & $addFields $CustomTableName $CustomFields
    }

    foreach ($trailingName in @($TrailingBaseFieldNames)) {
        $matchingBaseField = @($BaseFields | Where-Object {
            [string]::Equals((Get-CfideerFieldName $_), $trailingName, [System.StringComparison]::OrdinalIgnoreCase)
        } | Select-Object -First 1)
        if ($matchingBaseField.Count -gt 0) {
            $fieldName = Get-CfideerFieldName $matchingBaseField[0]
            if (-not [string]::IsNullOrWhiteSpace($fieldName) -and -not (Test-CfideerSampleRemoveField -FieldName $fieldName)) {
                [void]$parts.Add("$BaseTableName.$(Format-CfideerFieldReference $fieldName)")
            }
        }
    }

    return [string]::Join(", ", [string[]]$parts.ToArray())
}

function Get-CfideerGetQueryOrderNames {
    param(
        [object]$OrderConfig,
        [string]$Domain
    )

    if ($null -eq $OrderConfig) { return @() }
    $names = @($Domain, "${Domain}Fields", "${Domain}Order")
    foreach ($name in $names) {
        if ($OrderConfig.PSObject.Properties[$name]) {
            return @($OrderConfig.PSObject.Properties[$name].Value | ForEach-Object { ConvertTo-BuilderText $_ } | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
        }
    }
    return @()
}

function New-CfideerGetSelectList {
    param(
        [string]$BaseTableName,
        [object[]]$BaseFields,
        [string]$CustomTableName,
        [object[]]$CustomFields,
        [string[]]$TrailingBaseFieldNames = @(),
        [string[]]$FieldOrderNames = @()
    )

    $orderNames = @($FieldOrderNames | ForEach-Object { ConvertTo-BuilderText $_ } | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
    if ($orderNames.Count -eq 0) {
        return New-SelectListWithCustomAfter -BaseTableName $BaseTableName -BaseFields $BaseFields -AfterFieldName "__ProjectPickleBeforeTrailingField" -CustomTableName $CustomTableName -CustomFields $CustomFields -TrailingBaseFieldNames $TrailingBaseFieldNames
    }

    $trailingLookup = New-Object "System.Collections.Generic.HashSet[string]" ([System.StringComparer]::OrdinalIgnoreCase)
    foreach ($fieldName in @($TrailingBaseFieldNames)) {
        $cleanTrailing = ConvertTo-BuilderText $fieldName
        if (-not [string]::IsNullOrWhiteSpace($cleanTrailing)) { [void]$trailingLookup.Add($cleanTrailing) }
    }

    $items = New-Object System.Collections.Generic.List[object]
    $counter = [pscustomobject]@{ Value = 0 }
    $addItems = {
        param(
            [string]$TableName,
            [object[]]$Fields,
            [bool]$SkipTrailing
        )

        foreach ($field in @($Fields)) {
            $fieldName = Get-CfideerFieldName $field
            if ([string]::IsNullOrWhiteSpace($fieldName) -or (Test-CfideerSampleRemoveField -FieldName $fieldName)) { continue }
            if ($SkipTrailing -and $trailingLookup.Contains($fieldName)) { continue }
            $fieldKey = ($fieldName -replace "[\[\]]", "").ToLowerInvariant()
            $tableKey = ((ConvertTo-BuilderText $TableName) -replace "[\[\]]", "").ToLowerInvariant()
            [void]$items.Add([pscustomobject]@{
                Id = $counter.Value
                TableName = ConvertTo-BuilderText $TableName
                FieldName = $fieldName
                FieldKey = $fieldKey
                FullKey = "$tableKey.$fieldKey"
                Reference = "$TableName.$(Format-CfideerFieldReference $fieldName)"
            })
            $counter.Value++
        }
    }

    & $addItems $BaseTableName $BaseFields $true
    & $addItems $CustomTableName $CustomFields $true

    $used = New-Object "System.Collections.Generic.HashSet[int]"
    $ordered = New-Object System.Collections.Generic.List[object]
    foreach ($orderName in $orderNames) {
        $cleanOrder = ((ConvertTo-BuilderText $orderName) -replace "[\[\]]", "").Trim()
        if ([string]::IsNullOrWhiteSpace($cleanOrder)) { continue }
        $normalizedOrder = $cleanOrder.ToLowerInvariant()
        $orderTable = ""
        $orderField = $normalizedOrder
        $dotIndex = $normalizedOrder.LastIndexOf(".")
        if ($dotIndex -ge 0) {
            $orderTable = $normalizedOrder.Substring(0, $dotIndex)
            $orderField = $normalizedOrder.Substring($dotIndex + 1)
        }
        if ($trailingLookup.Contains($orderField)) { continue }

        $match = @($items | Where-Object {
            (-not $used.Contains([int]$_.Id)) -and
            (
                (-not [string]::IsNullOrWhiteSpace($orderTable) -and [string]::Equals($_.FullKey, "$orderTable.$orderField", [System.StringComparison]::OrdinalIgnoreCase)) -or
                ([string]::IsNullOrWhiteSpace($orderTable) -and [string]::Equals($_.FieldKey, $orderField, [System.StringComparison]::OrdinalIgnoreCase))
            )
        } | Select-Object -First 1)
        if ($match.Count -gt 0) {
            [void]$ordered.Add($match[0])
            [void]$used.Add([int]$match[0].Id)
        }
    }

    foreach ($item in $items) {
        if (-not $used.Contains([int]$item.Id)) {
            [void]$ordered.Add($item)
            [void]$used.Add([int]$item.Id)
        }
    }

    foreach ($trailingName in @($TrailingBaseFieldNames)) {
        $matchingBaseField = @($BaseFields | Where-Object {
            [string]::Equals((Get-CfideerFieldName $_), $trailingName, [System.StringComparison]::OrdinalIgnoreCase)
        } | Select-Object -First 1)
        if ($matchingBaseField.Count -gt 0) {
            $fieldName = Get-CfideerFieldName $matchingBaseField[0]
            if (-not [string]::IsNullOrWhiteSpace($fieldName) -and -not (Test-CfideerSampleRemoveField -FieldName $fieldName)) {
                [void]$ordered.Add([pscustomobject]@{
                    Reference = "$BaseTableName.$(Format-CfideerFieldReference $fieldName)"
                })
            }
        }
    }

    return [string]::Join(", ", [string[]]($ordered | ForEach-Object { ConvertTo-BuilderText $_.Reference } | Where-Object { -not [string]::IsNullOrWhiteSpace($_) }))
}

function Test-CfideerSqlContainsField {
    param(
        [string]$Sql,
        [string]$TableName,
        [string]$FieldName
    )

    $field = ConvertTo-BuilderText $FieldName
    if ([string]::IsNullOrWhiteSpace($field)) { return $false }
    $normalizedSql = ((ConvertTo-BuilderText $Sql) -replace "[\[\]\s]", "").ToLowerInvariant()
    $normalizedTable = ((ConvertTo-BuilderText $TableName) -replace "[\[\]\s]", "").ToLowerInvariant()
    $normalizedField = ($field -replace "[\[\]\s]", "").ToLowerInvariant()
    if (-not [string]::IsNullOrWhiteSpace($normalizedTable) -and $normalizedSql.Contains("$normalizedTable.$normalizedField")) { return $true }
    return [regex]::IsMatch((ConvertTo-BuilderText $Sql), "(?i)(^|[^A-Za-z0-9_])$([regex]::Escape($field))([^A-Za-z0-9_]|$)")
}

function Remove-CfideerSampleRemoveFieldsFromSelect {
    param([string]$Sql)

    $sourceSql = ConvertTo-BuilderText $Sql
    $match = [regex]::Match($sourceSql, "(?is)\bSELECT\b(?<select>.*?)\bFROM\b")
    if (-not $match.Success) { return $sourceSql }

    $selectText = $match.Groups["select"].Value
    $selectItems = @($selectText -split ",")
    $keptItems = New-Object System.Collections.Generic.List[string]
    $removed = $false
    foreach ($item in $selectItems) {
        $cleanItem = ConvertTo-BuilderText $item
        $normalized = ($cleanItem -replace "[\[\]\s]", "").ToLowerInvariant()
        if ($normalized -match "(^|\.)(fieldnamesampleremove)(asfieldnamesampleremove)?$") {
            $removed = $true
            continue
        }
        if (-not [string]::IsNullOrWhiteSpace($cleanItem)) {
            [void]$keptItems.Add($cleanItem.Trim())
        }
    }

    if (-not $removed) { return $sourceSql }
    $prefix = $sourceSql.Substring(0, $match.Groups["select"].Index).TrimEnd()
    $suffix = $sourceSql.Substring($match.Groups["select"].Index + $match.Groups["select"].Length).TrimStart()
    return $prefix + " " + ([string]::Join(", ", [string[]]$keptItems.ToArray())) + "`r`n" + $suffix
}

function Test-CfideerSelectItemContainsField {
    param(
        [string]$SelectItem,
        [string]$TableName,
        [string]$FieldName
    )

    $item = ConvertTo-BuilderText $SelectItem
    $field = ConvertTo-BuilderText $FieldName
    if ([string]::IsNullOrWhiteSpace($item) -or [string]::IsNullOrWhiteSpace($field)) { return $false }

    $normalizedItem = ($item -replace "[\[\]\s]", "").ToLowerInvariant()
    $normalizedField = ($field -replace "[\[\]\s]", "").ToLowerInvariant()
    $normalizedTable = ((ConvertTo-BuilderText $TableName) -replace "[\[\]\s]", "").ToLowerInvariant()
    if (-not [string]::IsNullOrWhiteSpace($normalizedTable) -and $normalizedItem.Contains("$normalizedTable.$normalizedField")) { return $true }

    return [regex]::IsMatch($item, "(?i)(^|[^A-Za-z0-9_])\[?$([regex]::Escape($field))\]?([^A-Za-z0-9_]|$)")
}

function Test-CfideerSelectItemUsesTable {
    param(
        [string]$SelectItem,
        [string]$TableName
    )

    $item = ConvertTo-BuilderText $SelectItem
    $table = ConvertTo-BuilderText $TableName
    if ([string]::IsNullOrWhiteSpace($item) -or [string]::IsNullOrWhiteSpace($table)) { return $false }

    $normalizedItem = ($item -replace "[\[\]\s]", "").ToLowerInvariant()
    $normalizedTable = ($table -replace "[\[\]\s]", "").ToLowerInvariant()
    return $normalizedItem.StartsWith("$normalizedTable.", [System.StringComparison]::OrdinalIgnoreCase)
}

function Remove-CfideerSelectItemsForTable {
    param(
        [string]$Sql,
        [string]$TableName
    )

    $sourceSql = ConvertTo-BuilderText $Sql
    $match = [regex]::Match($sourceSql, "(?is)\bSELECT\b(?<select>.*?)\bFROM\b")
    if (-not $match.Success) { return $sourceSql }

    $selectText = $match.Groups["select"].Value
    $selectItems = @($selectText -split ",")
    $keptItems = New-Object System.Collections.Generic.List[string]
    $removed = $false
    foreach ($item in $selectItems) {
        $cleanItem = ConvertTo-BuilderText $item
        if ([string]::IsNullOrWhiteSpace($cleanItem)) { continue }
        if (Test-CfideerSelectItemUsesTable -SelectItem $cleanItem -TableName $TableName) {
            $removed = $true
            continue
        }
        [void]$keptItems.Add($cleanItem.Trim())
    }

    if (-not $removed) { return $sourceSql }
    $prefix = $sourceSql.Substring(0, $match.Groups["select"].Index).TrimEnd()
    $suffix = $sourceSql.Substring($match.Groups["select"].Index + $match.Groups["select"].Length).TrimStart()
    return $prefix + " " + ([string]::Join(", ", [string[]]$keptItems.ToArray())) + "`r`n" + $suffix
}

function Add-CfideerProcessCustomFieldsToQuery {
    param(
        [string]$Sql,
        [string]$CustomTableName,
        [object[]]$CustomFields,
        [string[]]$InsertBeforeFieldNames = @()
    )

    $sourceSql = Remove-CfideerSampleRemoveFieldsFromSelect -Sql $Sql
    $sourceSql = Remove-CfideerSelectItemsForTable -Sql $sourceSql -TableName $CustomTableName
    $customEntries = New-Object System.Collections.Generic.List[object]
    $seenCustomFields = New-Object "System.Collections.Generic.HashSet[string]" ([System.StringComparer]::OrdinalIgnoreCase)
    foreach ($field in @($CustomFields)) {
        $fieldName = Get-CfideerFieldName $field
        if ([string]::IsNullOrWhiteSpace($fieldName) -or (Test-CfideerSampleRemoveField -FieldName $fieldName)) { continue }
        if (-not $seenCustomFields.Add($fieldName)) { continue }
        [void]$customEntries.Add([pscustomobject]@{
            FieldName = $fieldName
            Reference = "$CustomTableName.$(Format-CfideerFieldReference $fieldName)"
        })
    }

    if ($customEntries.Count -eq 0) { return $sourceSql }
    $selectRegex = [regex]::new("\bSELECT\b", [System.Text.RegularExpressions.RegexOptions]::IgnoreCase)
    $fromRegex = [regex]::new("\bFROM\b", [System.Text.RegularExpressions.RegexOptions]::IgnoreCase)
    $selectMatch = $selectRegex.Match($sourceSql)
    if (-not $selectMatch.Success) { return $sourceSql }
    $fromMatch = $fromRegex.Match($sourceSql, $selectMatch.Index + $selectMatch.Length)
    if (-not $fromMatch.Success) { return $sourceSql }

    if (@($InsertBeforeFieldNames).Count -gt 0) {
        $selectText = $sourceSql.Substring($selectMatch.Index + $selectMatch.Length, $fromMatch.Index - ($selectMatch.Index + $selectMatch.Length))
        $selectItems = @($selectText -split ",")
        $keptItems = New-Object System.Collections.Generic.List[string]
        foreach ($item in $selectItems) {
            $cleanItem = ConvertTo-BuilderText $item
            if ([string]::IsNullOrWhiteSpace($cleanItem)) { continue }
            $removeCustomItem = $false
            foreach ($entry in $customEntries) {
                if (Test-CfideerSelectItemContainsField -SelectItem $cleanItem -TableName $CustomTableName -FieldName $entry.FieldName) {
                    $removeCustomItem = $true
                    break
                }
            }
            if (-not $removeCustomItem) {
                [void]$keptItems.Add($cleanItem.Trim())
            }
        }

        $insertIndex = $keptItems.Count
        for ($i = 0; $i -lt $keptItems.Count; $i++) {
            foreach ($anchorField in @($InsertBeforeFieldNames)) {
                if (Test-CfideerSelectItemContainsField -SelectItem $keptItems[$i] -FieldName $anchorField) {
                    $insertIndex = $i
                    break
                }
            }
            if ($insertIndex -eq $i) { break }
        }

        $insertItems = New-Object System.Collections.Generic.List[string]
        foreach ($entry in $customEntries) {
            [void]$insertItems.Add((ConvertTo-BuilderText $entry.Reference))
        }
        $finalItems = New-Object System.Collections.Generic.List[string]
        for ($i = 0; $i -lt $keptItems.Count; $i++) {
            if ($i -eq $insertIndex) {
                foreach ($insertItem in $insertItems) { [void]$finalItems.Add($insertItem) }
            }
            [void]$finalItems.Add($keptItems[$i])
        }
        if ($insertIndex -ge $keptItems.Count) {
            foreach ($insertItem in $insertItems) { [void]$finalItems.Add($insertItem) }
        }

        $prefix = $sourceSql.Substring(0, $selectMatch.Index + $selectMatch.Length).TrimEnd()
        $suffix = $sourceSql.Substring($fromMatch.Index).TrimStart()
        return $prefix + " " + ([string]::Join(", ", [string[]]$finalItems.ToArray())) + "`r`n" + $suffix
    }

    $fieldsToAdd = New-Object System.Collections.Generic.List[string]
    foreach ($entry in $customEntries) {
        if (Test-CfideerSqlContainsField -Sql $sourceSql -TableName $CustomTableName -FieldName $entry.FieldName) { continue }
        [void]$fieldsToAdd.Add((ConvertTo-BuilderText $entry.Reference))
    }
    if ($fieldsToAdd.Count -eq 0) { return $sourceSql }

    $beforeFrom = $sourceSql.Substring(0, $fromMatch.Index).TrimEnd()
    $afterFrom = $sourceSql.Substring($fromMatch.Index)
    $separator = if ($beforeFrom.EndsWith(",")) { " " } else { ", " }
    return $beforeFrom + $separator + ([string]::Join(", ", [string[]]$fieldsToAdd.ToArray())) + "`r`n" + $afterFrom
}

function New-UpdateSetList {
    param(
        [string]$TableName,
        [object[]]$Fields,
        [string[]]$Exclude = @(),
        [hashtable]$ParameterNames = @{}
    )

    $parts = New-Object System.Collections.Generic.List[string]
    foreach ($field in $Fields) {
        $fieldName = Get-CfideerFieldName $field
        if ([string]::IsNullOrWhiteSpace($fieldName)) { continue }
        if (Test-CfideerSampleRemoveField -FieldName $fieldName) { continue }
        if ($Exclude -contains $fieldName) { continue }
        $parameterName = $fieldName
        if ($ParameterNames.ContainsKey($fieldName) -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $ParameterNames[$fieldName]))) {
            $parameterName = ConvertTo-BuilderText $ParameterNames[$fieldName]
        }
        [void]$parts.Add("$TableName.$(Format-CfideerFieldReference $fieldName) = $(Quote-Name $parameterName)")
    }
    return [string]::Join(", ", [string[]]$parts.ToArray())
}

function New-ParameterList {
    param(
        [object[]]$Fields,
        [string]$DefaultType = "Text",
        [hashtable]$ParameterNames = @{},
        [hashtable]$ParameterTypes = @{},
        [string]$Separator = ", "
    )

    $items = New-Object System.Collections.Generic.List[string]
    $seenParameters = New-Object "System.Collections.Generic.HashSet[string]" ([System.StringComparer]::OrdinalIgnoreCase)
    foreach ($field in $Fields) {
        $fieldName = Get-CfideerFieldName $field
        if ([string]::IsNullOrWhiteSpace($fieldName)) { continue }
        if (Test-CfideerSampleRemoveField -FieldName $fieldName) { continue }
        $parameterName = $fieldName
        if ($ParameterNames.ContainsKey($fieldName) -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $ParameterNames[$fieldName]))) {
            $parameterName = ConvertTo-BuilderText $ParameterNames[$fieldName]
        }
        if (-not $seenParameters.Add($parameterName)) { continue }
        $dataType = Get-CfideerFieldDataType $field
        $parameterType = Get-CfideerParameterType -FieldName $fieldName -DataType $dataType -DefaultType $DefaultType
        if ($ParameterTypes.ContainsKey($parameterName) -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $ParameterTypes[$parameterName]))) {
            $parameterType = ConvertTo-BuilderText $ParameterTypes[$parameterName]
        }
        elseif ($ParameterTypes.ContainsKey($fieldName) -and -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $ParameterTypes[$fieldName]))) {
            $parameterType = ConvertTo-BuilderText $ParameterTypes[$fieldName]
        }
        [void]$items.Add("$(Format-CfideerParameterDeclarationName $parameterName) $parameterType")
    }
    return "PARAMETERS " + ([string]::Join($Separator, [string[]]$items.ToArray())) + ";"
}

function ConvertTo-OutputFileNamePart {
    param([string]$Text)

    $clean = ConvertTo-BuilderText $Text
    foreach ($invalid in [System.IO.Path]::GetInvalidFileNameChars()) {
        $clean = $clean.Replace([string]$invalid, " ")
    }
    $clean = ($clean -replace "\s+", " ").Trim()
    return $clean
}

function Get-CfiVersionHint {
    param([string]$SourceDatabase)

    $name = ""
    try {
        if (-not [string]::IsNullOrWhiteSpace($SourceDatabase)) {
            $name = [System.IO.Path]::GetFileNameWithoutExtension($SourceDatabase)
        }
    }
    catch {
        $name = ""
    }

    $match = [regex]::Match($name, "(?i)\bv\d+(?:\.\d+)+")
    if ($match.Success) { return $match.Value }
    return $script:DefaultCfiVersionPlaceholder
}

function Get-CfiSourceDateHint {
    param(
        [string]$SourceDatabase,
        [datetime]$DefaultDate = (Get-Date)
    )

    $name = ""
    try {
        if (-not [string]::IsNullOrWhiteSpace($SourceDatabase)) {
            $name = [System.IO.Path]::GetFileNameWithoutExtension($SourceDatabase)
        }
    }
    catch {
        $name = ""
    }

    $match = [regex]::Match($name, "(?i)\[\s*date\s+(\d{8})\s*\]")
    if ($match.Success) { return $match.Groups[1].Value }
    return $DefaultDate.ToString("yyyyMMdd")
}

function New-OutputDatabaseFileNameHint {
    param(
        [string]$ProjectName,
        [string]$SourceDatabase,
        [datetime]$CreatedDate = (Get-Date)
    )

    $projectNameText = ConvertTo-BuilderText $ProjectName
    $projectPart = ConvertTo-OutputFileNamePart $projectNameText
    if ([string]::IsNullOrWhiteSpace($projectPart) -or
        $projectNameText.Equals($script:DefaultProjectNamePlaceholder, [System.StringComparison]::OrdinalIgnoreCase)) {
        $projectPart = "[TribeName]"
        $datePart = "[Date $(Get-CfiSourceDateHint -SourceDatabase $SourceDatabase -DefaultDate $CreatedDate)]"
        $versionPart = $script:DefaultCfiVersionPlaceholder
    }
    else {
        $datePart = $CreatedDate.ToString("yyyyMMdd")
        $versionPart = $script:DefaultCfiVersionPlaceholder
    }

    return "$projectPart CFI $datePart $versionPart.mdb"
}

function Get-OutputDatabaseNameHintSource {
    param(
        [string]$Mode,
        [string]$SourceDatabase,
        [string]$UpgradeTemplateDatabase
    )

    if ((Test-ModeUsesCurrentMasterDatabase -Mode $Mode) -and -not [string]::IsNullOrWhiteSpace($UpgradeTemplateDatabase)) {
        return $UpgradeTemplateDatabase
    }
    return $SourceDatabase
}

function New-AccessApplicationTitle {
    param(
        [string]$TemplateTitle,
        [string]$ProjectName,
        [datetime]$CreatedDate
    )

    $safeProjectName = ConvertTo-BuilderText $ProjectName
    if ([string]::IsNullOrWhiteSpace($safeProjectName)) { $safeProjectName = "CFI Project" }
    $dateText = $CreatedDate.ToString("yyyyMMdd")
    $template = ConvertTo-BuilderText $TemplateTitle
    if ([string]::IsNullOrWhiteSpace($template)) { $template = "[TRIBENAME] CFI [DATE] DB" }

    $projectReplacement = [System.Text.RegularExpressions.MatchEvaluator]{ param($Match) $safeProjectName }
    $dateReplacement = [System.Text.RegularExpressions.MatchEvaluator]{ param($Match) $dateText }
    $title = [regex]::Replace($template, "(?i)\[(TRIBENAME|TRIBE\s*NAME)\]", $projectReplacement)
    $title = [regex]::Replace($title, "(?i)\[DATE(?:\s+\d{4,8})?\]", $dateReplacement)
    if ($title.Equals($template, [System.StringComparison]::Ordinal)) {
        if ($template -match "(?i)^(.+?)\s+CFI\s+\d{8}\s+DB(.*)$") {
            $title = "$safeProjectName CFI $dateText DB$($matches[2])"
        }
        elseif ($template -match "(?i)^(.+?)\s+CFI\s+\d{8}(.*)$") {
            $title = "$safeProjectName CFI $dateText$($matches[2])"
        }
        else {
            $title = "$safeProjectName CFI $dateText DB"
        }
    }

    if ($title.Length -gt 255) { $title = $title.Substring(0, 255).Trim() }
    return $title
}

function Set-AccessApplicationTitle {
    param(
        [string]$DatabasePath,
        [string]$ProjectName,
        [datetime]$CreatedDate,
        [scriptblock]$Log
    )

    $engine = $null
    $db = $null
    $property = $null
    $createdProperty = $null
    try {
        foreach ($progId in @("DAO.DBEngine.120", "DAO.DBEngine.36", "DAO.DBEngine")) {
            try {
                $engine = New-Object -ComObject $progId
                $db = $engine.OpenDatabase($DatabasePath)
                break
            }
            catch {
                if ($engine -ne $null) {
                    try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($engine) | Out-Null } catch {}
                    $engine = $null
                }
            }
        }
        if ($null -eq $db) {
            throw "Could not open the database through the Access DAO engine."
        }

        $currentTitle = ""
        try {
            $property = $db.Properties.Item("AppTitle")
            $currentTitle = ConvertTo-BuilderText $property.Value
        }
        catch {
            $currentTitle = ""
        }
        finally {
            if ($property -ne $null) {
                try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($property) | Out-Null } catch {}
                $property = $null
            }
        }

        $newTitle = New-AccessApplicationTitle -TemplateTitle $currentTitle -ProjectName $ProjectName -CreatedDate $CreatedDate
        if ([string]::IsNullOrWhiteSpace($newTitle)) { return }

        try {
            $property = $db.Properties.Item("AppTitle")
            $property.Value = $newTitle
        }
        catch {
            $createdProperty = $db.CreateProperty("AppTitle", 10, $newTitle)
            $db.Properties.Append($createdProperty)
        }

        if ($Log) { & $Log "Access application title set to: $newTitle" }
    }
    finally {
        if ($property -ne $null) {
            try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($property) | Out-Null } catch {}
        }
        if ($createdProperty -ne $null) {
            try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($createdProperty) | Out-Null } catch {}
        }
        if ($db -ne $null) {
            try { $db.Close() } catch {}
            try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($db) | Out-Null } catch {}
        }
        if ($engine -ne $null) {
            try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($engine) | Out-Null } catch {}
        }
        [GC]::Collect()
        [GC]::WaitForPendingFinalizers()
    }
}

function Set-AccessQueryDefinition {
    param(
        [string]$DatabasePath,
        [string]$QueryName,
        [string]$Sql
    )

    $engine = $null
    $db = $null
    $existing = $null
    $created = $null
    try {
        foreach ($progId in @("DAO.DBEngine.120", "DAO.DBEngine.36", "DAO.DBEngine")) {
            try {
                $engine = New-Object -ComObject $progId
                $db = $engine.OpenDatabase($DatabasePath)
                break
            }
            catch {
                if ($engine -ne $null) {
                    try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($engine) | Out-Null } catch {}
                    $engine = $null
                }
            }
        }
        if ($null -eq $db) {
            throw "Could not open the database through the Access DAO engine."
        }

        $existingSql = $null
        foreach ($queryDef in $db.QueryDefs) {
            try {
                if ([string]$queryDef.Name -eq $QueryName) {
                    $existing = $queryDef
                    $existingSql = [string]$queryDef.SQL
                    break
                }
            }
            catch {
            }
        }

        if (-not [string]::IsNullOrWhiteSpace($existingSql) -and [string]::Equals((ConvertTo-BuilderText $existingSql).Trim(), (ConvertTo-BuilderText $Sql).Trim(), [System.StringComparison]::Ordinal)) {
            return
        }

        if ($existing -ne $null) {
            try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($existing) | Out-Null } catch {}
            $existing = $null
        }
        try { $db.QueryDefs.Delete($QueryName) } catch {}
        $created = $db.CreateQueryDef($QueryName, $Sql)
    }
    finally {
        if ($created -ne $null) {
            try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($created) | Out-Null } catch {}
        }
        if ($existing -ne $null) {
            try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($existing) | Out-Null } catch {}
        }
        if ($db -ne $null) {
            try { $db.Close() } catch {}
            try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($db) | Out-Null } catch {}
        }
        if ($engine -ne $null) {
            try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($engine) | Out-Null } catch {}
        }
        [GC]::Collect()
        [GC]::WaitForPendingFinalizers()
    }
}

function Get-AccessQueryDefinitionSql {
    param(
        [string]$DatabasePath,
        [string]$QueryName
    )

    $engine = $null
    $db = $null
    try {
        foreach ($progId in @("DAO.DBEngine.120", "DAO.DBEngine.36", "DAO.DBEngine")) {
            try {
                $engine = New-Object -ComObject $progId
                $db = $engine.OpenDatabase($DatabasePath)
                break
            }
            catch {
                if ($engine -ne $null) {
                    try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($engine) | Out-Null } catch {}
                    $engine = $null
                }
            }
        }
        if ($null -eq $db) {
            throw "Could not open the database through the Access DAO engine."
        }

        foreach ($queryDef in $db.QueryDefs) {
            try {
                if ([string]$queryDef.Name -eq $QueryName) {
                    return [string]$queryDef.SQL
                }
            }
            catch {
            }
        }
        throw "Saved query not found: $QueryName"
    }
    finally {
        if ($db -ne $null) {
            try { $db.Close() } catch {}
            try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($db) | Out-Null } catch {}
        }
        if ($engine -ne $null) {
            try { [System.Runtime.InteropServices.Marshal]::ReleaseComObject($engine) | Out-Null } catch {}
        }
        [GC]::Collect()
        [GC]::WaitForPendingFinalizers()
    }
}

function Get-AccessQueryDefinitionSqlOrDefault {
    param(
        [string]$DatabasePath,
        [string]$QueryName,
        [string]$DefaultSql
    )

    try {
        return Get-AccessQueryDefinitionSql -DatabasePath $DatabasePath -QueryName $QueryName
    }
    catch {
        return $DefaultSql
    }
}

function Build-CfideerQueries {
    param(
        [System.Data.OleDb.OleDbConnection]$Connection,
        [string]$DatabasePath,
        [scriptblock]$Log,
        [object]$GetQueryFieldOrder = $null,
        [object[]]$CustomFields = @()
    )

    & $Log "Building CFIDEER query definitions."
    foreach ($table in @("PlotCustomMeasurements", "TreeCustomMeasurements", "RegenCustomMeasurements")) {
        $copyExistingCFIDEERQueriesFromExistingDatabase = Test-ConfigFlag -Config $Config -Name "CopyExistingCFIDEERQueriesFromExistingDatabase"
        $cfideerQueryCopyAllowed = Test-CFIDEERQueryCopyModeAllowed -Mode $Config.Mode

        if ($copyExistingCFIDEERQueriesFromExistingDatabase) {
            if (-not $cfideerQueryCopyAllowed) {
                throw "Copy existing _prjCFIDEER_ queries can only run in Upgrade Project mode."
            }

            & $Log "Copying existing _prjCFIDEER_ query definitions from the old database."

            Copy-CFIDEERQueriesFromExistingDatabase `
                -SourceDatabasePath $Config.SourceDatabase `
                -TargetDatabasePath $Config.OutputDatabase `
                -Log $Log

            & $Log "CFIDEER query rebuild skipped because existing _prjCFIDEER_ queries were copied from the old database."
        }

        if ((Test-ColumnExists -Connection $Connection -TableName $table -ColumnName "FieldNameSampleRemove")) {
            & $Log "Skipping placeholder field $table.FieldNameSampleRemove in CFIDEER queries."
        }
    }

    $queryVisibleLookup = New-CfideerQueryVisibleLookup -CustomFields $CustomFields
    $plotFields = @(Filter-CfideerFieldsByQueryVisible -Fields (Get-ActiveFieldsForTable -Connection $Connection -TableName "PlotMeasurements" -RequiredLast @("RemarksPlot", "PlotID", "ProjectPeriodID") -Exclude @("MeasurementID", "PlotMeasKey")) -TableName "PlotMeasurements" -QueryVisibleLookup $queryVisibleLookup)
    $plotCustomFields = @(Filter-CfideerFieldsByQueryVisible -Fields (Get-ActiveFieldsForTable -Connection $Connection -TableName "PlotCustomMeasurements" -Exclude @("MeasurementID", "PlotMeasKey")) -TableName "PlotCustomMeasurements" -QueryVisibleLookup $queryVisibleLookup)
    $treeFields = @(Filter-CfideerFieldsByQueryVisible -Fields (Get-ActiveFieldsForTable -Connection $Connection -TableName "TreeMeasurements" -RequiredLast @("RemarksTree", "TreeKey", "ProjectPeriodID") -Exclude @("MeasurementID", "TreeMeasKey")) -TableName "TreeMeasurements" -QueryVisibleLookup $queryVisibleLookup)
    $treeCustomFields = @(Filter-CfideerFieldsByQueryVisible -Fields (Get-ActiveFieldsForTable -Connection $Connection -TableName "TreeCustomMeasurements" -Exclude @("MeasurementID", "TreeMeasKey")) -TableName "TreeCustomMeasurements" -QueryVisibleLookup $queryVisibleLookup)
    $regenFields = @(Filter-CfideerFieldsByQueryVisible -Fields (Get-ActiveFieldsForTable -Connection $Connection -TableName "RegenMeasurements" -RequiredLast @("RemarksRegen", "MeasurementID") -Exclude @("RegenMeasKey")) -TableName "RegenMeasurements" -QueryVisibleLookup $queryVisibleLookup)
    $excludeGetCriteriaFields = {
        param(
            [object[]]$Fields,
            [string[]]$ExcludedFieldNames
        )

        return @($Fields | Where-Object {
            $fieldName = Get-CfideerFieldName $_
            (-not [string]::IsNullOrWhiteSpace($fieldName)) -and
                (@($ExcludedFieldNames | Where-Object { [string]::Equals($_, $fieldName, [System.StringComparison]::OrdinalIgnoreCase) }).Count -eq 0)
        })
    }
    $plotProcessSourceFields = @(Filter-CfideerFieldsByQueryVisible -Fields (Get-ActiveFieldsForTable -Connection $Connection -TableName "PlotMeasurements" -RequiredFirst @("MeasurementID") -RequiredLast @("RemarksPlot", "PlotID", "ProjectPeriodID") -Exclude @("PlotMeasKey")) -TableName "PlotMeasurements" -QueryVisibleLookup $queryVisibleLookup)
    $plotProcessExcludedFields = @("PlotID", "PlotKey", "PlotMeasKey")
    $plotProcessFields = @(& $excludeGetCriteriaFields -Fields $plotProcessSourceFields -ExcludedFieldNames $plotProcessExcludedFields)
    $plotGetExcludedFields = @("PlotID", "ProjectPeriodID", "CalcSiteIndex", "GMP", "Created", "Updated", "UpdUser", "RetrievalID", "RetrevalID")
    $plotGetFields = @(& $excludeGetCriteriaFields -Fields $plotFields -ExcludedFieldNames $plotGetExcludedFields)
    $treeGetExcludedFields = @("TreeKey", "ProjectPeriodID", "Created", "Updated", "UpdUser", "RetrievalID", "RetrevalID")
    $treeGetFields = @(& $excludeGetCriteriaFields -Fields $treeFields -ExcludedFieldNames $treeGetExcludedFields)
    $regenGetExcludedFields = @("PlotNumber", "PlotID", "ProjectPeriodID", "MeasurementID", "IsDeleted", "Created", "Updated", "UpdUser", "RetrievalID", "RetrevalID")
    $regenGetFields = @(& $excludeGetCriteriaFields -Fields $regenFields -ExcludedFieldNames $regenGetExcludedFields)
    $regenCustomFields = @(Filter-CfideerFieldsByQueryVisible -Fields (Get-ActiveFieldsForTable -Connection $Connection -TableName "RegenCustomMeasurements" -Exclude @("MeasurementID", "RegenMeasKey")) -TableName "RegenCustomMeasurements" -QueryVisibleLookup $queryVisibleLookup)
    $plotGetOrder = @(Get-CfideerGetQueryOrderNames -OrderConfig $GetQueryFieldOrder -Domain "Plot")
    $treeGetOrder = @(Get-CfideerGetQueryOrderNames -OrderConfig $GetQueryFieldOrder -Domain "Tree")
    $regenGetOrder = @(Get-CfideerGetQueryOrderNames -OrderConfig $GetQueryFieldOrder -Domain "Regen")
    if ($plotGetOrder.Count -gt 0) { & $Log "Applying custom field order to _prjCFIDEER_GetPlotMeasurementsForPeriod." }
    if ($treeGetOrder.Count -gt 0) { & $Log "Applying custom field order to _prjCFIDEER_GetTreeMeasurementsForPeriodByKey." }
    if ($regenGetOrder.Count -gt 0) { & $Log "Applying custom field order to _prjCFIDEER_GetRegenMeasurements." }

    $queries = @{}
$queries["_prjCFIDEER_GetPlotMeasurementsForPeriod"] = @"
PARAMETERS PlotID Guid,
ProjectPeriodID Guid;

SELECT $(New-CfideerGetSelectList -BaseTableName "PlotMeasurements" -BaseFields $plotGetFields -CustomTableName "PlotCustomMeasurements" -CustomFields $plotCustomFields -TrailingBaseFieldNames @("RemarksPlot") -FieldOrderNames $plotGetOrder)
FROM
    PlotMeasurements
    LEFT JOIN PlotCustomMeasurements ON PlotMeasurements.[MeasurementID] = PlotCustomMeasurements.[MeasurementID]
WHERE
    (
        ((PlotMeasurements.PlotID) = [PlotID])
        AND (
            (PlotMeasurements.ProjectPeriodID) = [ProjectPeriodID]
        )
    );
"@
    $queries["_prjCFIDEER_GetTreeMeasurementsForPeriodByKey"] = @"
PARAMETERS TreeKey Text (255),
PeriodID Guid;

SELECT $(New-CfideerGetSelectList -BaseTableName "TreeMeasurements" -BaseFields $treeGetFields -CustomTableName "TreeCustomMeasurements" -CustomFields $treeCustomFields -TrailingBaseFieldNames @("RemarksTree") -FieldOrderNames $treeGetOrder)
FROM
