    $queries["_prjCFIDEER_GetRegenMeasurements"] = @"
PARAMETERS RegenID Guid;

SELECT $(New-CfideerGetSelectList -BaseTableName "RegenMeasurements" -BaseFields $regenGetFields -CustomTableName "RegenCustomMeasurements" -CustomFields $regenCustomFields -TrailingBaseFieldNames @("RemarksRegen") -FieldOrderNames $regenGetOrder)
FROM RegenMeasurements LEFT JOIN RegenCustomMeasurements ON RegenMeasurements.[MeasurementID] = RegenCustomMeasurements.[MeasurementID]
WHERE (((RegenMeasurements.MeasurementID)=[RegenID]));
"@
    $plotProcessSelectItems = New-Object System.Collections.Generic.List[string]
[void]$plotProcessSelectItems.Add("Plots.*")

$plotProcessBaseSelect = New-SelectList "PlotMeasurements" $plotProcessFields
if (-not [string]::IsNullOrWhiteSpace($plotProcessBaseSelect)) {
    [void]$plotProcessSelectItems.Add($plotProcessBaseSelect)
}

$plotProcessCustomSelect = New-SelectList "PlotCustomMeasurements" $plotCustomFields
if (-not [string]::IsNullOrWhiteSpace($plotProcessCustomSelect)) {
    [void]$plotProcessSelectItems.Add($plotProcessCustomSelect)
}

if ($Log) {
    & $Log ("_prjCFIDEER_GetProcessPlotList PlotMeasurements SELECT fields: " + ([string]::Join(", ", [string[]]($plotProcessFields | ForEach-Object { Get-CfideerFieldName $_ }))))
    & $Log ("_prjCFIDEER_GetProcessPlotList PlotCustomMeasurements SELECT fields: " + ([string]::Join(", ", [string[]]($plotCustomFields | ForEach-Object { Get-CfideerFieldName $_ }))))
}

$defaultGetProcessPlotSql = @"
