function Test-ConfigFlag {
    param(
        [object]$Config,
        [string]$Name
    )

    if ($null -eq $Config -or -not ($Config.PSObject.Properties.Name -contains $Name)) { return $false }
    return [bool]$Config.$Name
}

# ---------------------------------------------------------------------------
# Upgrade-only archive of the Existing/old database's AppColumns tables.
#
# Source tables:
#     AppColumns
#     AppColumnCodes
#
# Output archive tables:
#     zAppColumns
#     zAppColumnsCodes
#
# This is separate from:
#     AppColumnsArchive
#
# AppColumnsArchive preserves the AppColumns table inherited from the base
# database copied to the output. The z tables below preserve the selected
# Existing/old project database's AppColumns setup.
# ---------------------------------------------------------------------------


function Invoke-ProjectPickleArchiveNonQuery {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [object]$Connection,

        [Parameter(Mandatory = $true)]
        [string]$Sql
    )

    if ($null -eq $Connection) {
        throw (
            "Project Pickle cannot execute the AppColumns archive SQL " +
            "because the output database connection is not available."
        )
    }

    if (
        $Connection.State -ne
        [System.Data.ConnectionState]::Open
    ) {
        throw (
            "Project Pickle cannot execute the AppColumns archive SQL " +
            "because the output database connection is not open."
        )
    }

    if ([string]::IsNullOrWhiteSpace($Sql)) {
        throw (
            "Project Pickle cannot execute a blank AppColumns archive " +
            "SQL statement."
        )
    }

    $command = $null

    try {
        $command =
            $Connection.CreateCommand()

        $command.CommandText =
            $Sql

        $command.CommandTimeout =
            180

        return [int](
            $command.ExecuteNonQuery()
        )
    }
    finally {
        if ($null -ne $command) {
            try {
                $command.Dispose()
            }
            catch {
            }
        }
    }
}


function Get-ProjectPickleOldAppColumnCodesSourceTableName {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [object]$Connection
    )

    # AppColumnCodes is the normal Project Pickle table name.
    # AppColumnsCodes is included only as a fallback for an older or
    # nonstandard source database that used the plural spelling.
    foreach (
        $candidateTableName in [string[]]@(
            "AppColumnCodes"
            "AppColumnsCodes"
        )
    ) {
        if (
            Test-TableExists `
                -Connection $Connection `
                -TableName $candidateTableName
        ) {
            return [string]$candidateTableName
        }
    }

    return ""
}


function Remove-ProjectPickleArchiveTableIfPresent {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [object]$Connection,

        [Parameter(Mandatory = $true)]
        [string]$TableName
    )

    if (
        [string]::IsNullOrWhiteSpace(
            $TableName
        )
    ) {
        throw (
            "Project Pickle cannot remove an archive table because " +
            "the table name is blank."
        )
    }

    if (
        Test-TableExists `
            -Connection $Connection `
            -TableName $TableName
    ) {
        [void](
            Invoke-ProjectPickleArchiveNonQuery `
                -Connection $Connection `
                -Sql (
                    "DROP TABLE " +
                    (Quote-Name $TableName)
                )
        )
    }
}


function Copy-ProjectPickleOldAppColumnsArchives {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory = $true)]
        [object]$OutputConnection,

        [Parameter(Mandatory = $true)]
        [string]$SourceDatabasePath
    )

    $sourceAppColumnsTableName =
        "AppColumns"

    $targetAppColumnsTableName =
        "zAppColumns"

    $targetAppColumnCodesTableName =
        "zAppColumnsCodes"

    if (
        [string]::IsNullOrWhiteSpace(
            $SourceDatabasePath
        )
    ) {
        throw (
            "AppColumns archive: choose the Existing/old project " +
            "database on the Project tab."
        )
    }

    if (
        -not (
            Test-Path `
                -LiteralPath $SourceDatabasePath `
                -PathType Leaf
        )
    ) {
        throw (
            "AppColumns archive: the Existing/old project database " +
            "was not found:`r`n" +
            $SourceDatabasePath
        )
    }

    $sourceDatabaseFullPath =
        [System.IO.Path]::GetFullPath(
            $SourceDatabasePath
        )

    $sourceConnection =
        $null

    $sourceAppColumnsCount =
        0

    $sourceAppColumnCodesCount =
        0

    $sourceAppColumnCodesTableName =
        ""

    $archiveReplacementStarted =
        $false

    try {
        # First validate the source and read its row counts.
        $sourceConnectionString =
            New-AccessConnectionString `
                -Path $sourceDatabaseFullPath

        $sourceConnection =
            Open-AccessConnection `
                -ConnectionString $sourceConnectionString

        if (
            -not (
                Test-TableExists `
                    -Connection $sourceConnection `
                    -TableName $sourceAppColumnsTableName
            )
        ) {
            throw (
                "AppColumns archive: the Existing/old project " +
                "database does not contain the AppColumns table."
            )
        }

        $sourceAppColumnCodesTableName =
            Get-ProjectPickleOldAppColumnCodesSourceTableName `
                -Connection $sourceConnection

        if (
            [string]::IsNullOrWhiteSpace(
                $sourceAppColumnCodesTableName
            )
        ) {
            throw (
                "AppColumns archive: the Existing/old project " +
                "database does not contain the AppColumnCodes table."
            )
        }

        $sourceAppColumnsCount =
            [int](
                Get-DbScalar `
                    -Connection $sourceConnection `
                    -Sql (
                        "SELECT Count(*) FROM " +
                        (Quote-Name $sourceAppColumnsTableName)
                    )
            )

        $sourceAppColumnCodesCount =
            [int](
                Get-DbScalar `
                    -Connection $sourceConnection `
                    -Sql (
                        "SELECT Count(*) FROM " +
                        (
                            Quote-Name `
                                $sourceAppColumnCodesTableName
                        )
                    )
            )

        # Close the separate source connection before the output connection
        # reads the source through an Access external-database IN clause.
        if (
            $sourceConnection.State -eq
            [System.Data.ConnectionState]::Open
        ) {
            $sourceConnection.Close()
        }

        $sourceConnection.Dispose()
        $sourceConnection = $null

        # Escape apostrophes so a source path containing an apostrophe is
        # valid inside an Access SQL string literal.
        $sourcePathForSql =
            $sourceDatabaseFullPath.Replace(
                "'",
                "''"
            )

        $archiveReplacementStarted =
            $true

        # Remove codes first in case an older archive had a relationship
        # from zAppColumnsCodes to zAppColumns.
        Remove-ProjectPickleArchiveTableIfPresent `
            -Connection $OutputConnection `
            -TableName $targetAppColumnCodesTableName

        Remove-ProjectPickleArchiveTableIfPresent `
            -Connection $OutputConnection `
            -TableName $targetAppColumnsTableName

        # Create zAppColumns from the old database.
        $copyAppColumnsSql = (
            "SELECT * INTO " +
            (Quote-Name $targetAppColumnsTableName) +
            " FROM " +
            (Quote-Name $sourceAppColumnsTableName) +
            " IN '" +
            $sourcePathForSql +
            "'"
        )

        [void](
            Invoke-ProjectPickleArchiveNonQuery `
                -Connection $OutputConnection `
                -Sql $copyAppColumnsSql
        )

        # Create zAppColumnsCodes from AppColumnCodes in the old database.
        $copyAppColumnCodesSql = (
            "SELECT * INTO " +
            (Quote-Name $targetAppColumnCodesTableName) +
            " FROM " +
            (
                Quote-Name `
                    $sourceAppColumnCodesTableName
            ) +
            " IN '" +
            $sourcePathForSql +
            "'"
        )

        [void](
            Invoke-ProjectPickleArchiveNonQuery `
                -Connection $OutputConnection `
                -Sql $copyAppColumnCodesSql
        )

        $targetAppColumnsCount =
            [int](
                Get-DbScalar `
                    -Connection $OutputConnection `
                    -Sql (
                        "SELECT Count(*) FROM " +
                        (Quote-Name $targetAppColumnsTableName)
                    )
            )

        $targetAppColumnCodesCount =
            [int](
                Get-DbScalar `
                    -Connection $OutputConnection `
                    -Sql (
                        "SELECT Count(*) FROM " +
                        (
                            Quote-Name `
                                $targetAppColumnCodesTableName
                        )
                    )
            )

        if (
            $targetAppColumnsCount -ne
            $sourceAppColumnsCount
        ) {
            throw (
                "AppColumns archive verification failed. " +
                "The old AppColumns table contains " +
                $sourceAppColumnsCount +
                " row(s), but zAppColumns contains " +
                $targetAppColumnsCount +
                " row(s)."
            )
        }

        if (
            $targetAppColumnCodesCount -ne
            $sourceAppColumnCodesCount
        ) {
            throw (
                "AppColumns archive verification failed. " +
                "The old " +
                $sourceAppColumnCodesTableName +
                " table contains " +
                $sourceAppColumnCodesCount +
                " row(s), but zAppColumnsCodes contains " +
                $targetAppColumnCodesCount +
                " row(s)."
            )
        }

        return [pscustomobject]@{
            SourceDatabase =
                $sourceDatabaseFullPath

            SourceAppColumnsTable =
                $sourceAppColumnsTableName

            SourceAppColumnCodesTable =
                $sourceAppColumnCodesTableName

            TargetAppColumnsTable =
                $targetAppColumnsTableName

            TargetAppColumnCodesTable =
                $targetAppColumnCodesTableName

            AppColumnsRowCount =
                [int]$targetAppColumnsCount

            AppColumnCodesRowCount =
                [int]$targetAppColumnCodesCount
        }
    }
    catch {
        $archiveCopyException =
            $_.Exception

        # A failed two-table archive must not leave only one z table.
        if ($archiveReplacementStarted) {
            try {
                Remove-ProjectPickleArchiveTableIfPresent `
                    -Connection $OutputConnection `
                    -TableName $targetAppColumnCodesTableName
            }
            catch {
            }

            try {
                Remove-ProjectPickleArchiveTableIfPresent `
                    -Connection $OutputConnection `
                    -TableName $targetAppColumnsTableName
            }
            catch {
            }
        }

        throw $archiveCopyException
    }
    finally {
        if ($null -ne $sourceConnection) {
            try {
                if (
                    $sourceConnection.State -eq
                    [System.Data.ConnectionState]::Open
                ) {
                    $sourceConnection.Close()
                }
            }
            catch {
            }

            try {
                $sourceConnection.Dispose()
            }
            catch {
            }
        }
    }
}
function Assert-BuilderConfigReady {
    param([object]$Config)

    $issues = New-Object System.Collections.Generic.List[string]
    $source = ConvertTo-BuilderText $Config.SourceDatabase
    $output = ConvertTo-BuilderText $Config.OutputDatabase
    $projectName = ConvertTo-BuilderText $Config.ProjectName
    $isUpgradeMode = Test-UpgradeMode -Config $Config
    $isNewProjectMode = Test-NewProjectModeText -Mode (ConvertTo-BuilderText $Config.Mode)
    $isExistingMode = Test-WOOFTextEquals (ConvertTo-BuilderText $Config.Mode) "Existing Project"
    $usesCurrentMasterDatabase = Test-ModeUsesCurrentMasterDatabase -Mode (ConvertTo-BuilderText $Config.Mode)
    $copyAppColumnsFromExistingDatabase = Test-ConfigFlag -Config $Config -Name "CopyAppColumnsFromExistingDatabase"
    $archiveOldAppColumnsFromExistingDatabase =
    Test-ConfigFlag `
        -Config $Config `
        -Name "ArchiveOldAppColumnsFromExistingDatabase"

if (
    $archiveOldAppColumnsFromExistingDatabase -and
    -not $isUpgradeMode
) {
    [void]$issues.Add(
        "AppColumns tab: Archive old AppColumns tables as " +
        "zAppColumns and zAppColumnsCodes is available only " +
        "in Upgrade Project mode."
    )
}
    $copyReportsFromExistingDatabase = Test-ConfigFlag -Config $Config -Name "CopyReportsFromExistingDatabase"
    $copyProcessingTablesFromExistingDatabase = Test-ConfigFlag -Config $Config -Name "CopyProcessingTablesFromExistingDatabase"
    $copyProcessingCalculatedTablesFromExistingDatabase = Test-ConfigFlag -Config $Config -Name "CopyProcessingCalculatedTablesFromExistingDatabase"
    $copyExistingCFIDEERQueriesFromExistingDatabase = Test-ConfigFlag -Config $Config -Name "CopyExistingCFIDEERQueriesFromExistingDatabase"
    $isUpgradeModeForCFIDEERQueryCopy = Test-CFIDEERQueryCopyModeAllowed -Mode $Config.Mode

    if ($copyExistingCFIDEERQueriesFromExistingDatabase -and -not $isUpgradeModeForCFIDEERQueryCopy) {
        [void]$issues.Add("Get Field Order tab: Copy existing _prjCFIDEER_ queries from old database is only available in Upgrade Project mode.")
    }

    if ($copyExistingCFIDEERQueriesFromExistingDatabase -and
        (Test-ConfigFlag -Config $Config -Name "BuildCfideerQueries")) {

        [void]$issues.Add("Get Field Order tab: Copy existing _prjCFIDEER_ queries cannot be used while CFIDEER query rebuild is also selected.")
    }

    if ($copyExistingCFIDEERQueriesFromExistingDatabase -and
        $isUpgradeModeForCFIDEERQueryCopy -and
        -not [string]::IsNullOrWhiteSpace($source) -and
        (Test-Path -LiteralPath $source)) {

        try {
            $existingCFIDEERQueryNames = @(
                Get-CFIDEERQueryNamesFromDatabase -DatabasePath $source
            )

            if ($existingCFIDEERQueryNames.Count -eq 0) {
                [void]$issues.Add("Get Field Order tab: the old database does not contain any saved queries whose names start with '_prjCFIDEER_'.")
            }
        }
        catch {
            [void]$issues.Add("Get Field Order tab: could not read _prjCFIDEER_ queries from the old database: $($_.Exception.Message)")
        }
    }

    $periods = @($Config.Periods)
    if (-not $isExistingMode) {
        if ($periods.Count -eq 0) {
            [void]$issues.Add("Periods tab: add at least one measurement period row. New projects normally use PeriodNumber 1.")
        }
        else {
        $seenPeriods = @{}
        foreach ($period in $periods) {
            $periodText = ConvertTo-BuilderText $period.PeriodNumber
            $rowLabel = if ([string]::IsNullOrWhiteSpace($periodText)) { "blank period" } else { "period $periodText" }
            $number = 0
            if (-not [int]::TryParse($periodText, [ref]$number) -or $number -le 0) {
                [void]$issues.Add("Periods tab: PeriodNumber for $rowLabel must be a positive whole number.")
            }
            elseif ($seenPeriods.ContainsKey($number)) {
                [void]$issues.Add("Periods tab: PeriodNumber $number is listed more than once. Each period number must be unique.")
            }
            else {
                $seenPeriods[$number] = $true
            }

            foreach ($dateField in @("PlannedStartDate", "PlannedEndDate", "ActualStartDate", "ActualEndDate")) {
                $dateText = ConvertTo-BuilderText $period.$dateField
                if ([string]::IsNullOrWhiteSpace($dateText)) { continue }
                $parsedDate = [datetime]::MinValue
                if (-not [datetime]::TryParse($dateText, [ref]$parsedDate)) {
                    [void]$issues.Add("Periods tab: $dateField for $rowLabel is not a valid date. Use a normal date, such as 2026-01-01, or leave it blank.")
                }
            }
        }
        }
    }

    $plotImport = ConvertTo-BuilderText $Config.PlotImportPath
    if (-not [string]::IsNullOrWhiteSpace($plotImport) -and -not (Test-Path -LiteralPath $plotImport)) {
        [void]$issues.Add("Plots tab: the selected Add New Plots file was not found. Choose it again or leave it blank.")
    }
    if (-not [string]::IsNullOrWhiteSpace($plotImport) -and $Config.PSObject.Properties["PlotImportMappings"]) {
        $plotNumberMapping = @($Config.PlotImportMappings | Where-Object { [string]::Equals((ConvertTo-BuilderText $_.FieldName), "PlotNumber", [System.StringComparison]::OrdinalIgnoreCase) } | Select-Object -First 1)
        if ($plotNumberMapping.Count -gt 0 -and [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $plotNumberMapping[0].SourceColumn))) {
            [void]$issues.Add("Plots tab: Add New Plots is selected, so PlotNumber must be mapped. Click Load columns, map Project Pickle field PlotNumber to the spreadsheet column containing plot numbers, or leave Add New Plots blank. In Existing Project mode after an Upgrade, the spreadsheet should contain only new plots; existing plot numbers do not need to be included.")
        }
    }
    if ((Test-ConfigFlag -Config $Config -Name "SetupTreeAssignments") -and -not (Test-ConfigFlag -Config $Config -Name "SetupAssignments")) {
        [void]$issues.Add("Tree Assignments tab: tree assignments require plot assignment setup to be checked too.")
    }
    if ((Test-ConfigFlag -Config $Config -Name "SetupTreeAssignments") -and -not $isUpgradeMode) {
        [void]$issues.Add("Tree Assignments tab: tree assignments only run in Upgrade Project mode.")
    }
    $upgradeFieldMappingsForValidation = @()
    if ($Config.PSObject.Properties["UpgradeFieldMappings"]) { $upgradeFieldMappingsForValidation = @($Config.UpgradeFieldMappings) }
    if (-not $isUpgradeMode -and $upgradeFieldMappingsForValidation.Count -gt 0) {
        [void]$issues.Add("Upgrade Mapping tab: selected field mappings only run in Upgrade Project mode. Change Mode to Upgrade Project, choose the old project as Existing/old project database, choose the current master database version, then build again.")
    }
    if ($isUpgradeMode -and $upgradeFieldMappingsForValidation.Count -gt 0 -and -not (Test-ConfigFlag -Config $Config -Name "ImportOldInventoryData")) {
        [void]$issues.Add("Upgrade Mapping tab: selected field mappings require the Plots tab upgrade import checkbox to stay checked.")
    }

    $customFields = @($Config.CustomFields)
        if ($copyAppColumnsFromExistingDatabase -and -not $isNewProjectMode -and -not [string]::IsNullOrWhiteSpace($source) -and (Test-Path -LiteralPath $source)) {
        $sourceConnectionForAppColumns = $null
        try {
            $sourceConnectionStringForAppColumns = New-AccessConnectionString -Path $source
            $sourceConnectionForAppColumns = Open-AccessConnection -ConnectionString $sourceConnectionStringForAppColumns

            if (-not (Test-TableExists -Connection $sourceConnectionForAppColumns -TableName "AppColumns")) {
                [void]$issues.Add("AppColumns tab: the existing database does not contain the AppColumns table.")
            }
            elseif (-not (Test-TableExists -Connection $sourceConnectionForAppColumns -TableName "AppColumnCodes")) {
                [void]$issues.Add("AppColumns tab: the existing database does not contain the AppColumnCodes table.")
            }
            else {
                $customFields = @(Get-AppColumnsForBuilder -Connection $sourceConnectionForAppColumns)
            }
        }
        catch {
            [void]$issues.Add("AppColumns tab: could not read AppColumns from the existing database: $($_.Exception.Message)")
        }
        finally {
            if ($null -ne $sourceConnectionForAppColumns) {
                if ($sourceConnectionForAppColumns.State -eq "Open") { $sourceConnectionForAppColumns.Close() }
                $sourceConnectionForAppColumns.Dispose()
            }
        }
    }
    if ($copyReportsFromExistingDatabase -and $isUpgradeMode -and
        -not [string]::IsNullOrWhiteSpace($source) -and (Test-Path -LiteralPath $source)) {

        $sourceConnectionForReports = $null
        try {
            $sourceConnectionForReports = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $source)
            foreach ($tableName in @("ReportColumns", "ReportHeaders")) {
                if (-not (Test-TableExists -Connection $sourceConnectionForReports -TableName $tableName)) {
                    [void]$issues.Add("Reports tab: the existing database does not contain the $tableName table.")
                }
                else {
                    $rowCount = [int](Get-DbScalar -Connection $sourceConnectionForReports -Sql "SELECT Count(*) FROM $(Quote-Name $tableName)")
                    if ($rowCount -eq 0) {
                        [void]$issues.Add("Reports tab: the existing database $tableName table is empty.")
                    }
                }
            }
        }
        catch {
            [void]$issues.Add("Reports tab: could not read completed reports from the existing database: $($_.Exception.Message)")
        }
        finally {
            if ($null -ne $sourceConnectionForReports) {
                if ($sourceConnectionForReports.State -eq "Open") { $sourceConnectionForReports.Close() }
                $sourceConnectionForReports.Dispose()
            }
        }
    }

      if ($copyProcessingTablesFromExistingDatabase -and
        $isUpgradeMode -and
        -not [string]::IsNullOrWhiteSpace($source) -and
        (Test-Path -LiteralPath $source)) {

        $processingImportCompatibility = Get-ProcessingImportCompatibility `
            -DatabasePath $source

        if (-not [bool]$processingImportCompatibility.IsCompatible) {
            [void]$issues.Add(
                "Processing tab: " +
                [string]$processingImportCompatibility.Message
            )
        }
    }

    if ($copyProcessingTablesFromExistingDatabase -and
        $isUpgradeMode -and
        -not [string]::IsNullOrWhiteSpace($source) -and
        (Test-Path -LiteralPath $source)) {

        $sourceConnectionForProcessing = $null

        try {
            $sourceConnectionStringForProcessing = New-AccessConnectionString -Path $source
            $sourceConnectionForProcessing = Open-AccessConnection -ConnectionString $sourceConnectionStringForProcessing

            $missingProcessingTables = New-Object System.Collections.Generic.List[string]

            foreach ($tableName in @(Get-ProcessingTableNames)) {
                if (-not (Test-TableExists -Connection $sourceConnectionForProcessing -TableName $tableName)) {
                    [void]$missingProcessingTables.Add($tableName)
                }
            }

            if ($missingProcessingTables.Count -gt 0) {
                [void]$issues.Add(
                    "Processing tab: existing database is missing required table(s): " +
                    [string]::Join(
                        ", ",
                        [string[]]$missingProcessingTables.ToArray()
                    )
                )
            }
        }
        catch {
            [void]$issues.Add("Processing tab: could not read Processing tables from the existing database: $($_.Exception.Message)")
        }
        finally {
            if ($null -ne $sourceConnectionForProcessing) {
                if ($sourceConnectionForProcessing.State -eq "Open") {
                    $sourceConnectionForProcessing.Close()
                }

                $sourceConnectionForProcessing.Dispose()
            }
        }
    }

        if ($copyProcessingTablesFromExistingDatabase -and
        $isUpgradeMode -and
        -not [string]::IsNullOrWhiteSpace($source) -and
        (Test-Path -LiteralPath $source)) {

        $sourceConnectionForProcessing = $null

        try {
            $sourceConnectionStringForProcessing = New-AccessConnectionString -Path $source
            $sourceConnectionForProcessing = Open-AccessConnection -ConnectionString $sourceConnectionStringForProcessing

            $missingProcessingTables = New-Object System.Collections.Generic.List[string]

            foreach ($tableName in @(Get-ProcessingTableNames)) {
                if (-not (Test-TableExists -Connection $sourceConnectionForProcessing -TableName $tableName)) {
                    [void]$missingProcessingTables.Add($tableName)
                }
            }

            if ($missingProcessingTables.Count -gt 0) {
                [void]$issues.Add(
                    "Processing tab: existing database is missing required table(s): " +
                    [string]::Join(
                        ", ",
                        [string[]]$missingProcessingTables.ToArray()
                    )
                )
            }
        }
        catch {
            [void]$issues.Add("Processing tab: could not read Processing tables from the existing database: $($_.Exception.Message)")
        }
        finally {
            if ($null -ne $sourceConnectionForProcessing) {
                if ($sourceConnectionForProcessing.State -eq "Open") {
                    $sourceConnectionForProcessing.Close()
                }

                $sourceConnectionForProcessing.Dispose()
            }
        }
    }

    if ($copyProcessingCalculatedTablesFromExistingDatabase -and
        $isUpgradeMode -and
        -not [string]::IsNullOrWhiteSpace($source) -and
        (Test-Path -LiteralPath $source)) {

        $sourceConnectionForProcessingCalculatedTables = $null

        try {
            $sourceConnectionStringForProcessingCalculatedTables = New-AccessConnectionString -Path $source
            $sourceConnectionForProcessingCalculatedTables = Open-AccessConnection -ConnectionString $sourceConnectionStringForProcessingCalculatedTables

            $missingProcessingCalculatedTables = New-Object System.Collections.Generic.List[string]

            foreach ($tableName in @(Get-ProcessingCalculatedTableNames)) {
                if (-not (Test-TableExists -Connection $sourceConnectionForProcessingCalculatedTables -TableName $tableName)) {
                    [void]$missingProcessingCalculatedTables.Add($tableName)
                }
            }

            if ($missingProcessingCalculatedTables.Count -gt 0) {
                [void]$issues.Add(
                    "Processing tab: existing database is missing required Plot Summaries, Tree Calc, and Regen Calc table(s): " +
                    [string]::Join(
                        ", ",
                        [string[]]$missingProcessingCalculatedTables.ToArray()
                    )
                )
            }
        }
        catch {
            [void]$issues.Add("Processing tab: could not read Plot Summaries, Tree Calc, and Regen Calc tables from the existing database: $($_.Exception.Message)")
        }
        finally {
            if ($null -ne $sourceConnectionForProcessingCalculatedTables) {
                if ($sourceConnectionForProcessingCalculatedTables.State -eq "Open") {
                    $sourceConnectionForProcessingCalculatedTables.Close()
                }

                $sourceConnectionForProcessingCalculatedTables.Dispose()
            }
        }
    }

    if ($isUpgradeMode -and (Test-ConfigFlag -Config $Config -Name "ImportOldInventoryData") -and
        -not [string]::IsNullOrWhiteSpace($source) -and (Test-Path -LiteralPath $source) -and
        -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Config.UpgradeTemplateDatabase)) -and (Test-Path -LiteralPath (ConvertTo-BuilderText $Config.UpgradeTemplateDatabase))) {
        try {
            $upgradeMappings = @()
            if ($Config.PSObject.Properties["UpgradeFieldMappings"]) { $upgradeMappings = @($Config.UpgradeFieldMappings) }
            $dataTypeReview = @(Get-UpgradeDataTypeReview -OldDatabasePath $source -TemplateDatabasePath (ConvertTo-BuilderText $Config.UpgradeTemplateDatabase) -FieldMappings $upgradeMappings -CustomFields $customFields)
            $blockingTypeIssues = @($dataTypeReview)
            if ($blockingTypeIssues.Count -gt 0) {
                $shown = 0
                foreach ($item in $blockingTypeIssues) {
                    if ($shown -ge 10) { break }
                    [void]$issues.Add("Upgrade data type check: $(Format-UpgradeDataTypeReviewLine -Item $item)")
                    $shown++
                }
                if ($blockingTypeIssues.Count -gt $shown) {
                    [void]$issues.Add("Upgrade data type check: $($blockingTypeIssues.Count - $shown) more datatype issue(s) were found. Use the Upgrade Mapping tab's Check data types button to review the full list.")
                }
                [void]$issues.Add("Upgrade data type check: Project Pickle stops upgrade builds when an old field type does not match the selected new target type. Crosswalk/convert the old values before building, or map the old field to a Text/Memo custom measurement field so it can be crosswalked later.")
            }
        }
        catch {
            [void]$issues.Add("Upgrade data type check could not finish before build: $($_.Exception.Message)")
        }
    }

    if (
        (Test-ConfigFlag `
            -Config $Config `
            -Name "UpdateReports") -and
        -not $copyReportsFromExistingDatabase
    ) {
        $manualReportLayouts = @()

        if ($Config.PSObject.Properties["ReportLayouts"]) {
            $manualReportLayouts = @(
                $Config.ReportLayouts |
                    Where-Object { $null -ne $_ }
            )
        }

        if ($manualReportLayouts.Count -eq 0) {
            [void]$issues.Add(
                "Reports tab: Update reports is checked, but no manual " +
                "report layouts were saved. Automatic report generation " +
                "is disabled to protect the exact template ReportHeaders. " +
                "Either uncheck Update reports to preserve the reports " +
                "inherited from the selected database, or click Load all " +
                "from selected database, complete and save the report " +
                "layouts, then build again."
            )
        }
        else {
            try {
                Assert-ProjectPickleDefaultReportColumnIdsUnchanged `
                    -Layouts $manualReportLayouts
            }
            catch {
                [void]$issues.Add(
                    "Reports tab: $($_.Exception.Message)"
                )
            }

            foreach (
                $reportIssue in @(
                    Get-ManualReportLayoutsIssues `
                        -Layouts $manualReportLayouts
                )
            ) {
                [void]$issues.Add(
                    "Reports tab: $reportIssue"
                )
            }
        }
    }

    foreach ($field in $customFields) {
        $fieldName = ConvertTo-BuilderText $field.FieldName
        $category = ConvertTo-BuilderText $field.Category
        $loadedFromAppColumns = $false
        if ($field.PSObject.Properties["LoadedFromAppColumns"]) {
            $loadedFromAppColumns = ConvertTo-BuilderBool $field.LoadedFromAppColumns
        }
        if ($category.Equals("Code", [System.StringComparison]::OrdinalIgnoreCase) -and -not $loadedFromAppColumns -and [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $field.Codes))) {
            [void]$issues.Add("AppColumns tab: '$fieldName' is Category=Code but the Codes cell is blank. Enter all allowed codes, such as 1=Yes; 2=No; 9=Unknown or 1=Yes 2=No 9=Unknown, or change Category to Range.")
        }
    }

    if ($issues.Count -gt 0) {
        throw "Please fix these entries before building:`r`n`r`n- " + ([string]::Join("`r`n- ", [string[]]$issues.ToArray()))
    }
}

function Invoke-InventoryBuild {
    param(
        [object]$Config,
        [scriptblock]$Log
    )

    if (-not $Log) { $Log = { param($Text) Write-Host $Text } }
# ---------------------------------------------------------------------------
# Prepare the Processing copy plan before normal build validation.
#
# Compatible old database:
#   Validate and copy all four Processing setup tables.
#
# Missing merchantability fields:
#   Temporarily suppress the old four-table validator.
#   Restore the user's checkbox selection after validation.
#   Copy only the three compatible tables during the actual build.
# ---------------------------------------------------------------------------

$script:ProjectPickleProcessingTableNamesOverride =
    $null

$script:ProjectPickleSkipSpeciesMerchantabilityStandards =
    $false

$projectPickleRestoreProcessingCopyFlag =
    $false


if (
    Test-ConfigFlag `
        -Config $config `
        -Name "CopyProcessingTablesFromExistingDatabase"
) {
    try {
        $processingCompatibility =
            Get-ProjectPickleProcessingCopyCompatibility `
                -SourceDatabasePath (
                    ConvertTo-BuilderText `
                        $config.SourceDatabase
                )

        $script:ProjectPickleProcessingTableNamesOverride =
            [string[]]@(
                $processingCompatibility.TablesToCopy
            )

        $script:ProjectPickleSkipSpeciesMerchantabilityStandards =
            [bool](
                $processingCompatibility.UseThreeTableFallback
            )

        if (
            $processingCompatibility.UseThreeTableFallback
        ) {
            $processingFlagProperty =
                $config.PSObject.Properties[
                    "CopyProcessingTablesFromExistingDatabase"
                ]

            if (
                $null -eq $processingFlagProperty -or
                -not $processingFlagProperty.IsSettable
            ) {
                throw (
                    "Project Pickle could not temporarily prepare " +
                    "the three-table Processing fallback."
                )
            }

            # The old normal validator expects all four tables and all
            # merchantability fields. Temporarily turn off only that old
            # validator. The user's checkbox remains selected in the UI.
            $processingFlagProperty.Value =
                $false

            $projectPickleRestoreProcessingCopyFlag =
                $true

            [void](
                [System.Windows.Forms.MessageBox]::Show(
                    $processingCompatibility.WarningMessage,
                    "Processing import will continue with three tables",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Warning
                )
            )
        }
    }
    catch {
        $script:ProjectPickleProcessingTableNamesOverride =
            $null

        $script:ProjectPickleSkipSpeciesMerchantabilityStandards =
            $false

        [void](
            [System.Windows.Forms.MessageBox]::Show(
                (
                    "Project Pickle could not prepare the " +
                    "Processing table import:`r`n`r`n" +
                    $_.Exception.Message
                ),
                "Processing table check failed",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Error
            )
        )

        return
    }
}


try {
    Assert-BuilderConfigReady `
        -Config $Config
}
finally {
    if (
        $projectPickleRestoreProcessingCopyFlag
    ) {
        # Restore the user's Processing-table selection before the
        # actual database build begins. Get-ProcessingTableNames
        # retains the three-table override for this build.
        $Config.CopyProcessingTablesFromExistingDatabase =
            $true
    }
}
    if ([string]::IsNullOrWhiteSpace($Config.OutputDatabase)) { throw "Choose a Save Project Location path." }
    $isUpgradeMode = Test-UpgradeMode -Config $Config
    $isNewProjectMode = Test-NewProjectModeText -Mode (ConvertTo-BuilderText $Config.Mode)
    $usesCurrentMasterDatabase = Test-ModeUsesCurrentMasterDatabase -Mode (ConvertTo-BuilderText $Config.Mode)
    $copySourceDatabase = if ($usesCurrentMasterDatabase) { ConvertTo-BuilderText $Config.UpgradeTemplateDatabase } else { ConvertTo-BuilderText $Config.SourceDatabase }
    if ($usesCurrentMasterDatabase) {
        if ([string]::IsNullOrWhiteSpace($copySourceDatabase)) { throw "Choose the current master database version." }
        if (-not (Test-Path -LiteralPath $copySourceDatabase)) { throw "Current master database version not found: $copySourceDatabase" }
    }
    else {
        if ([string]::IsNullOrWhiteSpace($copySourceDatabase)) { throw "Choose the Existing/old project database." }
        if (-not (Test-Path -LiteralPath $copySourceDatabase)) { throw "Existing/old project database not found: $copySourceDatabase" }
    }
    if (-not $isNewProjectMode -and -not [string]::IsNullOrWhiteSpace($Config.SourceDatabase) -and [System.IO.Path]::GetFullPath($Config.SourceDatabase).Equals([System.IO.Path]::GetFullPath($Config.OutputDatabase), [System.StringComparison]::OrdinalIgnoreCase)) {
        throw "Save Project Location cannot be the same file as the Existing/old project database."
    }
    if ($usesCurrentMasterDatabase -and [System.IO.Path]::GetFullPath($copySourceDatabase).Equals([System.IO.Path]::GetFullPath($Config.OutputDatabase), [System.StringComparison]::OrdinalIgnoreCase)) {
        throw "Save Project Location cannot be the same file as the current master database version."
    }

    $outDir = [System.IO.Path]::GetDirectoryName($Config.OutputDatabase)
    if (-not (Test-Path -LiteralPath $outDir)) { [void](New-Item -ItemType Directory -Path $outDir -Force) }
    if (Test-Path -LiteralPath $Config.OutputDatabase) {
        $backup = $Config.OutputDatabase + ".backup_" + (Get-Date -Format "yyyyMMdd_HHmmss")
        Move-Item -LiteralPath $Config.OutputDatabase -Destination $backup
        & $Log "Existing output moved to backup: $backup"
    }

    if ($isUpgradeMode) {
        & $Log "Copying current master database version to output."
    }
    elseif ($isNewProjectMode) {
        & $Log "Copying current master database version to output for new project."
    }
    else {
        & $Log "Copying existing project database to output."
    }
    Copy-Item -LiteralPath $copySourceDatabase -Destination $Config.OutputDatabase
    $outputCreatedDate = Get-Date
    try {
        (Get-Item -LiteralPath $Config.OutputDatabase).Attributes = [System.IO.FileAttributes]::Normal
    }
    catch {
    }
    $connectionString = New-AccessConnectionString -Path $Config.OutputDatabase
    $connection = Open-AccessConnection -ConnectionString $connectionString
    try {
        New-AppColumnsArchive -Connection $connection -Log $Log
        # Archive the Existing/old database's AppColumns setup separately from
# AppColumnsArchive and separately from the working AppColumns copy option.
if (
    (Test-UpgradeMode -Config $Config) -and
    (
        Test-ConfigFlag `
            -Config $Config `
            -Name "ArchiveOldAppColumnsFromExistingDatabase"
    )
) {
    $oldAppColumnsArchiveResult =
        Copy-ProjectPickleOldAppColumnsArchives `
            -OutputConnection $connection `
            -SourceDatabasePath (
                ConvertTo-BuilderText `
                    $Config.SourceDatabase
            )

    & $Log (
        "Archived the Existing/old database AppColumns setup. " +
        "zAppColumns: " +
        $oldAppColumnsArchiveResult.AppColumnsRowCount +
        " row(s); zAppColumnsCodes: " +
        $oldAppColumnsArchiveResult.AppColumnCodesRowCount +
        " row(s)."
    )
}
        $keepExistingReferenceScope = $false
        if ($Config.PSObject.Properties["KeepExistingReferenceScope"]) {
            $keepExistingReferenceScope = ConvertTo-BuilderBool $Config.KeepExistingReferenceScope
        }
        if ($keepExistingReferenceScope) {
            $existingReference = Get-ExistingProjectReferenceSelection -DatabasePath $Config.SourceDatabase
            & $Log "Keeping Region, Agency, and Reservation from existing database: $($existingReference.RegionName) / $($existingReference.AgencyName) / $($existingReference.ReservationName)."
            $reservation = Resolve-ReservationSelection -Connection $connection -ReservationCode $existingReference.ReservationCode -ReservationName $existingReference.ReservationName -AgencyName $existingReference.AgencyName -RegionName $existingReference.RegionName
        }
        else {
            $reservation = Resolve-ReservationSelection -Connection $connection -ReservationCode $Config.ReservationCode -ReservationName $Config.ReservationName -AgencyName $Config.AgencyName -RegionName $Config.RegionName
        }
        $projectId = Set-ProjectSetup -Connection $connection -Config $Config -Reservation $reservation -Log $Log
        if (Test-WOOFTextEquals (ConvertTo-BuilderText $Config.Mode) "Existing Project") {
            & $Log "Existing Project mode: preserving measurement periods from the selected database."
            $periods = @(Get-ProjectPeriodsForBuilder -Connection $connection)
            if ($periods.Count -eq 0) {
                throw "Existing Project mode needs measurement periods already in the selected database. The Periods tab is read-only in this mode, so choose a project database with ProjectMeasurementPeriods rows or use Upgrade Project mode if periods must be rebuilt."
            }
            & $Log "Preserved $($periods.Count) existing measurement period row(s)."
        }
        else {
            $periods = @(Set-MeasurementPeriods -Connection $connection -ProjectId $projectId -Periods $Config.Periods -Log $Log)
        }
        Set-AnalysisProjectPeriodIds -Connection $connection -Periods $periods -Log $Log
        if ($Config.PruneReferences) { Set-ReferenceScope -Connection $connection -Reservation $reservation -Log $Log }
            $copyAppColumnsFromExistingDatabase = Test-ConfigFlag -Config $Config -Name "CopyAppColumnsFromExistingDatabase"
        if ($copyAppColumnsFromExistingDatabase) {
            Copy-AppColumnsTablesFromExistingDatabase -SourceDatabasePath $Config.SourceDatabase -TargetConnection $connection -Log $Log
            $customFields = @(Get-AppColumnsForBuilder -Connection $connection)
            Ensure-CustomMeasurementColumnsForCopiedAppColumns -Connection $connection -CustomFields $customFields -Log $Log
        }
        else {
            $customFields = @(Sync-CustomFields -Connection $connection -CustomFields $Config.CustomFields -Log $Log)
        }
        Remove-FieldNameSampleRemoveFromCustomTables -Connection $connection -Log $Log
        $importOldInventoryData = $true
        if ($Config.PSObject.Properties["ImportOldInventoryData"]) {
            $importOldInventoryData = ConvertTo-BuilderBool $Config.ImportOldInventoryData
        }
        if ($isUpgradeMode -and $importOldInventoryData) {
            $upgradeFieldMappings = @()
            if ($Config.PSObject.Properties["UpgradeFieldMappings"]) { $upgradeFieldMappings = @($Config.UpgradeFieldMappings) }
            Invoke-UpgradeDataImport -OldDatabasePath $Config.SourceDatabase -TargetConnection $connection -ProjectId $projectId -Periods $periods -FieldMappings $upgradeFieldMappings -Log $Log
        }
        elseif ($isUpgradeMode) {
            & $Log "Upgrade mode: old plot/tree/regen and assignment data import was turned off."
        }

        $copyProcessingTablesFromExistingDatabase = Test-ConfigFlag -Config $Config -Name "CopyProcessingTablesFromExistingDatabase"
        if ($isUpgradeMode -and $copyProcessingTablesFromExistingDatabase) {
            Copy-ProcessingTablesFromExistingDatabase -SourceDatabasePath $Config.SourceDatabase -TargetConnection $connection -Log $Log
        }
        $copyProcessingCalculatedTablesFromExistingDatabase = Test-ConfigFlag -Config $Config -Name "CopyProcessingCalculatedTablesFromExistingDatabase"
        if ($isUpgradeMode -and $copyProcessingCalculatedTablesFromExistingDatabase) {
        Copy-ProcessingCalculatedTablesFromExistingDatabase -SourceDatabasePath $Config.SourceDatabase -TargetConnection $connection -Log $Log
        }
        
        $activeCustomFieldLookup = Get-ActiveCustomMeasurementFieldLookup -Connection $connection
        $connection.Close()
        $connection.Dispose()
        Set-CustomMeasurementTableColumnOrder -DatabasePath $Config.OutputDatabase -ActiveFieldLookup $activeCustomFieldLookup -Log $Log
        $connection = Open-AccessConnection -ConnectionString $connectionString
        if ($Config.UpdateValidation) { Set-ValidationPeriods -Connection $connection -ProjectId $projectId -Periods $periods -Log $Log }
        $plotImportMappings = @()
        if ($Config.PSObject.Properties["PlotImportMappings"]) { $plotImportMappings = @($Config.PlotImportMappings) }
        $plotCount = Import-Plots -Connection $connection -Path $Config.PlotImportPath -ProjectId $projectId -Periods $periods -PlotImportMappings $plotImportMappings -Log $Log
        [void](Ensure-BlankPlotMeasurementsForPeriods -Connection $connection -Periods $periods -Log $Log)
        if ($Config.SetupAssignments) {
            $existingPlotCount = 0
            if (Test-TableExists -Connection $connection -TableName "Plots") {
                $existingPlotCount = [int](Get-DbScalar -Connection $connection -Sql "SELECT Count(*) FROM [Plots]")
            }
            if ($plotCount -gt 0 -or $existingPlotCount -gt 0) {
                Clear-InventoryAssignmentTablesForRebuild -Connection $connection -Log $Log
                Ensure-InventoryAssignments -Connection $connection -Periods $periods -CrewNames $Config.CrewNames -IncludePlotAssignments $true -IncludeTreeAssignments ([bool]$Config.SetupTreeAssignments) -Log $Log
            }
            else {
                & $Log "Assignment setup selected, but no plots were imported or found. Inventory assignment setup was skipped. Run Project Pickle again after plot data is loaded."
            }
        }
        Set-ProjectIdInAllTables -Connection $connection -ProjectId $projectId -Log $Log
        $copyReportsFromExistingDatabase = Test-ConfigFlag -Config $Config -Name "CopyReportsFromExistingDatabase"
        if ($copyReportsFromExistingDatabase) {
            & $Log "Copy completed reports is selected. Manual report layouts and the automatic report generator will be skipped."
            Copy-ReportTablesFromExistingDatabase -SourceDatabasePath $Config.SourceDatabase -TargetConnection $connection -Log $Log
        }
        elseif ($Config.UpdateReports) {
            $manualReportLayouts = @()
            if ($Config.PSObject.Properties["ReportLayouts"]) { $manualReportLayouts = @($Config.ReportLayouts | Where-Object { $null -ne $_ }) }
            if ($manualReportLayouts.Count -gt 0) {
                & $Log "Applying saved Reports tab layouts as the report source of truth. The automatic report-header generator will not run."
                Apply-ManualReportLayouts -Connection $connection -Layouts $manualReportLayouts -Log $Log
            }
            else {
                & $Log "No Reports tab layouts were saved; using the legacy automatic report updater."
                Update-ReportSetup -Connection $connection -CustomFields $customFields -Log $Log
            }
        }
        if ($Config.BuildCfideerQueries) {
            $connection.Close()
            $queryConnection = Open-AccessConnection -ConnectionString $connectionString
            try {
                $getQueryFieldOrder = $null
                if ($Config.PSObject.Properties["GetQueryFieldOrder"]) { $getQueryFieldOrder = $Config.GetQueryFieldOrder }
                Build-CfideerQueries -Connection $queryConnection -DatabasePath $Config.OutputDatabase -Log $Log -GetQueryFieldOrder $getQueryFieldOrder -CustomFields $customFields
            }
            finally {
                if ($queryConnection.State -eq "Open") { $queryConnection.Close() }
                $queryConnection.Dispose()
            }
        }
        if ($connection.State -eq "Open") { $connection.Close() }
        if (Test-WOOFTextEquals (ConvertTo-BuilderText $Config.Mode) "Existing Project") {
            & $Log "Existing Project mode: preserving existing Access application title."
        }
        else {
            try {
                Set-AccessApplicationTitle -DatabasePath $Config.OutputDatabase -ProjectName $Config.ProjectName -CreatedDate $outputCreatedDate -Log $Log
            }
            catch {
                & $Log "Warning: Access application title could not be updated: $($_.Exception.Message)"
            }
        }
        & $Log "Database build complete: $($Config.OutputDatabase)"
    }
    finally {
        if ($connection.State -eq "Open") { $connection.Close() }
        $connection.Dispose()
    }
}

function New-DefaultPeriod {
    return [pscustomobject]@{
        ProjectPeriodID = ""
        PeriodNumber = 1
        PeriodDescription = "Current Measurement"
        PlannedStartDate = (Get-Date).ToString("yyyy-01-01")
        PlannedEndDate = (Get-Date).ToString("yyyy-12-31")
        ActualStartDate = ""
        ActualEndDate = ""
        ApplicablePeriod = (Get-Date).Year.ToString()
        IsCurrent = $true
    }
}

function Get-ProjectPeriodTableNameForBuilder {
    param([System.Data.OleDb.OleDbConnection]$Connection)

    $periodNumberNames = @("PeriodNumber", "MeasurementPeriodNumber", "MeasurementPeriod", "Period")
    foreach ($candidate in @("ProjectMeasurementPeriods", "ProjectPeriods", "ProjectPeriod", "MeasurementPeriods", "MeasurementPeriod", "InventoryPeriods", "Periods")) {
        if (-not (Test-TableExists -Connection $Connection -TableName $candidate)) { continue }
        try {
            $columns = @(Get-TableColumns -Connection $Connection -TableName $candidate)
            if (@($columns | Where-Object { $_ -in $periodNumberNames }).Count -gt 0) {
                return $candidate
            }
        }
        catch {
        }
    }

    foreach ($tableName in @(Get-UserTables -Connection $Connection)) {
        $normalized = ((ConvertTo-BuilderText $tableName) -replace "[^A-Za-z0-9]", "").ToLowerInvariant()
        if ($normalized -notmatch "period") { continue }
        try {
            $columns = @(Get-TableColumns -Connection $Connection -TableName $tableName)
            if (@($columns | Where-Object { $_ -in $periodNumberNames }).Count -gt 0) {
                return $tableName
            }
        }
        catch {
        }
    }
    return ""
}

function Get-ProjectPeriodsForBuilder {
    param([System.Data.OleDb.OleDbConnection]$Connection)

    $periodTableName = Get-ProjectPeriodTableNameForBuilder -Connection $Connection
    if ([string]::IsNullOrWhiteSpace($periodTableName)) {
        return @()
    }

    $columns = @(Get-TableColumns -Connection $Connection -TableName $periodTableName)
    $periodNumberColumn = @($columns | Where-Object { $_ -in @("PeriodNumber", "MeasurementPeriodNumber", "MeasurementPeriod", "Period") } | Select-Object -First 1)
    if ($periodNumberColumn.Count -eq 0 -or [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $periodNumberColumn[0]))) {
        return @()
    }

    $projectId = ""
    if ((Test-TableExists -Connection $Connection -TableName "Projects") -and (Test-ColumnExists -Connection $Connection -TableName "Projects" -ColumnName "ProjectID")) {
        try { $projectId = ConvertTo-BuilderText (Get-DbScalar -Connection $Connection -Sql "SELECT TOP 1 [ProjectID] FROM [Projects]") } catch { $projectId = "" }
    }
    $where = ""
    if (-not [string]::IsNullOrWhiteSpace($projectId) -and (Test-ColumnExists -Connection $Connection -TableName $periodTableName -ColumnName "ProjectID")) {
        $where = " WHERE [ProjectID] = $(Sql-Guid $projectId)"
    }

    $quotedPeriodTableName = Quote-Name $periodTableName
    $orderBy = Quote-Name (ConvertTo-BuilderText $periodNumberColumn[0])
    $table = $null
    if (-not [string]::IsNullOrWhiteSpace($where)) {
        try { $table = Get-DbTable -Connection $Connection -Sql "SELECT * FROM $quotedPeriodTableName$where ORDER BY $orderBy" } catch { $table = $null }
    }
    if ($null -eq $table -or $table.Rows.Count -eq 0) {
        $table = Get-DbTable -Connection $Connection -Sql "SELECT * FROM $quotedPeriodTableName ORDER BY $orderBy"
    }
    if ($table.Rows.Count -eq 0) { return @() }

    $maxPeriodNumber = 0
    foreach ($row in $table.Rows) {
        $candidate = 0
        if ([int]::TryParse((Get-DataRowText -Row $row -ColumnNames @("PeriodNumber", "MeasurementPeriodNumber", "MeasurementPeriod", "Period")), [ref]$candidate) -and $candidate -gt $maxPeriodNumber) {
            $maxPeriodNumber = $candidate
        }
    }

    $periods = New-Object System.Collections.Generic.List[object]
    foreach ($row in $table.Rows) {
        $periodNumber = 0
        [void][int]::TryParse((Get-DataRowText -Row $row -ColumnNames @("PeriodNumber", "MeasurementPeriodNumber", "MeasurementPeriod", "Period")), [ref]$periodNumber)
        $plannedStartDate = Get-DataRowValue -Row $row -ColumnNames @("PlannedStartDate", "PlannedStart", "PlanStartDate", "PlanStart")
        $plannedEndDate = Get-DataRowValue -Row $row -ColumnNames @("PlannedEndDate", "PlannedEnd", "PlanEndDate", "PlanEnd")
        $actualStartDate = Get-DataRowValue -Row $row -ColumnNames @("ActualStartDate", "ActualStart", "StartDate", "ActualMeasurementStartDate")
        $actualEndDate = Get-DataRowValue -Row $row -ColumnNames @("ActualEndDate", "ActualEnd", "EndDate", "ActualMeasurementEndDate")
        $period = [pscustomobject]@{
            ProjectPeriodID = Get-DataRowText -Row $row -ColumnNames @("ProjectPeriodID", "PeriodID", "ID")
            PeriodNumber = $periodNumber
            PeriodDescription = Get-DataRowText -Row $row -ColumnNames @("PeriodDescription", "MeasurementPeriodDescription", "ProjectPeriodDescription", "Description", "Name")
            PlannedStartDate = ConvertTo-BuilderDateText $plannedStartDate
            PlannedEndDate = ConvertTo-BuilderDateText $plannedEndDate
            ActualStartDate = ConvertTo-BuilderDateText $actualStartDate
            ActualEndDate = ConvertTo-BuilderDateText $actualEndDate
            ApplicablePeriod = ""
            IsCurrent = ($periodNumber -eq $maxPeriodNumber)
        }
        $period.ApplicablePeriod = Get-PeriodApplicableValue -Period $period
        [void]$periods.Add($period)
    }

    return @($periods.ToArray())
}

function Add-BuilderChoiceText {
    param(
        [System.Collections.Generic.List[string]]$List,
        [string]$Value
    )

    $text = ConvertTo-BuilderText $Value
    if (-not [string]::IsNullOrWhiteSpace($text)) {
        [void]$List.Add($text)
    }
}

function Get-BuilderReferenceChoices {
    param([System.Data.OleDb.OleDbConnection]$Connection)

    foreach ($tableName in @("Regions", "Agencies", "Reservations")) {
        if (-not (Test-TableExists -Connection $Connection -TableName $tableName)) {
            throw "The selected database does not contain a [$tableName] table. Choose a CFI current master database version or an existing CFI project database."
        }
    }

    try {
        $regionRows = Get-DbTable -Connection $Connection -Sql "SELECT * FROM [Regions]"
        $agencyRows = Get-DbTable -Connection $Connection -Sql "SELECT * FROM [Agencies]"
        $reservationRows = Get-DbTable -Connection $Connection -Sql "SELECT * FROM [Reservations]"
    }
    catch {
        throw "Could not read Regions, Agencies, and Reservations from the selected database. $($_.Exception.Message)"
    }

    $regionNames = New-Object System.Collections.Generic.List[string]
    $regionChoices = New-Object System.Collections.Generic.List[object]
    $regionById = @{}
    foreach ($row in $regionRows.Rows) {
        $regionId = Get-DataRowText -Row $row -ColumnNames @("RegionID")
        $name = Get-DataRowText -Row $row -ColumnNames @("RegionName", "Region", "Name", "Description")
        if ([string]::IsNullOrWhiteSpace($name)) {
            $name = Get-DataRowText -Row $row -ColumnNames @("RegionCode", "RegionID", "ID")
        }
        Add-BuilderChoiceText -List $regionNames -Value $name
        if (-not [string]::IsNullOrWhiteSpace($name)) {
            [void]$regionChoices.Add([pscustomobject]@{
                RegionID = $regionId
                RegionName = $name
                DisplayName = $name
            })
            if (-not [string]::IsNullOrWhiteSpace($regionId) -and -not $regionById.ContainsKey($regionId)) {
                $regionById[$regionId] = $name
            }
        }
    }

    $agencyNames = New-Object System.Collections.Generic.List[string]
    $agencyChoices = New-Object System.Collections.Generic.List[object]
    $agencyById = @{}
    foreach ($row in $agencyRows.Rows) {
        $agencyId = Get-DataRowText -Row $row -ColumnNames @("AgencyID")
        $regionId = Get-DataRowText -Row $row -ColumnNames @("RegionID")
        $name = Get-DataRowText -Row $row -ColumnNames @("AgencyName", "Agency", "Name", "Description")
        if ([string]::IsNullOrWhiteSpace($name)) {
            $name = Get-DataRowText -Row $row -ColumnNames @("AgencyCode", "AgencyID", "ID")
        }
        Add-BuilderChoiceText -List $agencyNames -Value $name
        if (-not [string]::IsNullOrWhiteSpace($name)) {
            $regionName = ""
            if (-not [string]::IsNullOrWhiteSpace($regionId) -and $regionById.ContainsKey($regionId)) {
                $regionName = ConvertTo-BuilderText $regionById[$regionId]
            }
            $choice = [pscustomobject]@{
                AgencyID = $agencyId
                RegionID = $regionId
                RegionName = $regionName
                AgencyName = $name
                DisplayName = $name
            }
            [void]$agencyChoices.Add($choice)
            if (-not [string]::IsNullOrWhiteSpace($agencyId) -and -not $agencyById.ContainsKey($agencyId)) {
                $agencyById[$agencyId] = $choice
            }
        }
    }

    $reservationNames = New-Object System.Collections.Generic.List[string]
    $reservationChoices = New-Object System.Collections.Generic.List[object]
    $referenceRows = New-Object System.Collections.Generic.List[object]
    foreach ($row in $reservationRows.Rows) {
        $reservationId = Get-DataRowText -Row $row -ColumnNames @("ReservationID")
        $agencyId = Get-DataRowText -Row $row -ColumnNames @("AgencyID")
        $reservationCode = Get-DataRowText -Row $row -ColumnNames @("ReservationCode")
        $name = Get-DataRowText -Row $row -ColumnNames @("ReservationName", "ForestName", "Name", "Description")
        if ([string]::IsNullOrWhiteSpace($name)) {
            $name = Get-DataRowText -Row $row -ColumnNames @("ReservationCode", "ReservationID", "ID")
        }
        $agencyName = ""
        $regionId = ""
        $regionName = ""
        if (-not [string]::IsNullOrWhiteSpace($agencyId) -and $agencyById.ContainsKey($agencyId)) {
            $agencyName = ConvertTo-BuilderText $agencyById[$agencyId].AgencyName
            $regionId = ConvertTo-BuilderText $agencyById[$agencyId].RegionID
            $regionName = ConvertTo-BuilderText $agencyById[$agencyId].RegionName
        }
        Add-BuilderChoiceText -List $reservationNames -Value $name
        if (-not [string]::IsNullOrWhiteSpace($name)) {
            [void]$reservationChoices.Add([pscustomobject]@{
                ReservationID = $reservationId
                ReservationCode = $reservationCode
                AgencyID = $agencyId
                AgencyName = $agencyName
                RegionID = $regionId
                RegionName = $regionName
                ReservationName = $name
                DisplayName = $name
            })
        }
        [void]$referenceRows.Add([pscustomobject]@{
            RegionName = $regionName
            AgencyName = $agencyName
            RegionID = $regionId
            AgencyID = $agencyId
            ReservationName = $name
            ReservationCode = $reservationCode
        })
    }

    return [pscustomobject]@{
        ReferenceRows = @($referenceRows.ToArray())
        RegionChoices = @($regionChoices.ToArray())
        AgencyChoices = @($agencyChoices.ToArray())
        ReservationChoices = @($reservationChoices.ToArray())
        RegionNames = @($regionNames.ToArray() | Sort-Object -Unique)
        AgencyNames = @($agencyNames.ToArray() | Sort-Object -Unique)
        ReservationNames = @($reservationNames.ToArray() | Sort-Object -Unique)
    }
}

function Invoke-ReferenceListTest {
    $source = if ([string]::IsNullOrWhiteSpace($MasterDatabase)) { $script:DefaultMasterDatabase } else { $MasterDatabase }
    if ([string]::IsNullOrWhiteSpace($source) -or -not (Test-Path -LiteralPath $source)) {
        throw "Reference list test needs a valid -MasterDatabase path."
    }

    $connection = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $source)
    try {
        $choices = Get-BuilderReferenceChoices -Connection $connection
        Write-Output "Reference list test passed."
        Write-Output "Regions: $($choices.RegionNames.Count)"
        Write-Output "Agencies: $($choices.AgencyNames.Count)"
        Write-Output "Reservations: $($choices.ReservationNames.Count)"
        if ($choices.RegionNames.Count -gt 0) { Write-Output "First region: $($choices.RegionNames[0])" }
        if ($choices.AgencyNames.Count -gt 0) { Write-Output "First agency: $($choices.AgencyNames[0])" }
        if ($choices.ReservationNames.Count -gt 0) { Write-Output "First reservation: $($choices.ReservationNames[0])" }
        $firstRegionChoice = @($choices.RegionChoices | Where-Object { -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $_.RegionID)) } | Select-Object -First 1)
        if ($firstRegionChoice.Count -gt 0) {
            $regionId = ConvertTo-BuilderText $firstRegionChoice[0].RegionID
            $regionAgencyCount = @($choices.AgencyChoices | Where-Object { [string]::Equals((ConvertTo-BuilderText $_.RegionID), $regionId, [System.StringComparison]::OrdinalIgnoreCase) }).Count
            Write-Output "Agencies linked to first keyed region: $regionAgencyCount"
        }
        $firstAgencyChoice = @($choices.AgencyChoices | Where-Object { -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $_.AgencyID)) } | Select-Object -First 1)
        if ($firstAgencyChoice.Count -gt 0) {
            $agencyId = ConvertTo-BuilderText $firstAgencyChoice[0].AgencyID
            $agencyReservationCount = @($choices.ReservationChoices | Where-Object { [string]::Equals((ConvertTo-BuilderText $_.AgencyID), $agencyId, [System.StringComparison]::OrdinalIgnoreCase) }).Count
            Write-Output "Reservations linked to first keyed agency: $agencyReservationCount"
        }
    }
    finally {
        if ($connection.State -eq "Open") { $connection.Close() }
        $connection.Dispose()
    }
}

function Remove-StaleSelfTestDatabases {
    param([string[]]$Folders)

    foreach ($folder in @($Folders)) {
        if ([string]::IsNullOrWhiteSpace($folder) -or -not (Test-Path -LiteralPath $folder)) { continue }
        $resolvedFolder = [System.IO.Path]::GetFullPath($folder)
        foreach ($file in Get-ChildItem -LiteralPath $resolvedFolder -Filter "_inventory_builder_selftest_*.mdb" -File -ErrorAction SilentlyContinue) {
            $resolvedFile = [System.IO.Path]::GetFullPath($file.FullName)
            if (-not $resolvedFile.StartsWith($resolvedFolder, [System.StringComparison]::OrdinalIgnoreCase)) { continue }
            try {
                [System.Data.OleDb.OleDbConnection]::ReleaseObjectPool()
                [GC]::Collect()
                [GC]::WaitForPendingFinalizers()
                $file.Attributes = [System.IO.FileAttributes]::Normal
                Remove-Item -LiteralPath $resolvedFile -Force
            }
            catch {
                Write-Output "Self-test old temporary database could not be removed: $resolvedFile"
            }
        }
    }
}

function Invoke-SelfTest {
    $source = if ([string]::IsNullOrWhiteSpace($MasterDatabase)) { $script:DefaultMasterDatabase } else { $MasterDatabase }
    if ([string]::IsNullOrWhiteSpace($source)) {
        $bundledSelfTestMaster = Join-Path $script:AppRoot "Testing Artifacts\_reference_list_test_copy.mdb"
        if (Test-Path -LiteralPath $bundledSelfTestMaster) { $source = $bundledSelfTestMaster }
    }
    if ([string]::IsNullOrWhiteSpace($source) -or -not (Test-Path -LiteralPath $source)) { throw "Self-test needs a master database. Put _reference_list_test_copy.mdb in Testing Artifacts or pass -MasterDatabase." }
    Remove-StaleSelfTestDatabases -Folders @($script:AppRoot, [System.IO.Path]::GetTempPath())
    $selfTestSource = Join-Path ([System.IO.Path]::GetTempPath()) ("_inventory_builder_selftest_source_" + ([guid]::NewGuid()).ToString("N") + ".mdb")
    $testOutput = Join-Path ([System.IO.Path]::GetTempPath()) ("_inventory_builder_selftest_" + ([guid]::NewGuid()).ToString("N") + ".mdb")
    $upgradeTestOutput = Join-Path ([System.IO.Path]::GetTempPath()) ("_inventory_builder_upgrade_selftest_" + ([guid]::NewGuid()).ToString("N") + ".mdb")
    $log = { param($Text) Write-Host $Text }
    Copy-Item -LiteralPath $source -Destination $selfTestSource
    $selfTestSourceConn = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $selfTestSource)
    try {
        if (Test-TableExists -Connection $selfTestSourceConn -TableName "AnalysisSelfTest") {
            [void](Invoke-DbNonQuery -Connection $selfTestSourceConn -Sql "DROP TABLE [AnalysisSelfTest]")
        }
        [void](Invoke-DbNonQuery -Connection $selfTestSourceConn -Sql "CREATE TABLE [AnalysisSelfTest] ([ProjectPeriodID] GUID)")
        [void](Invoke-DbNonQueryParameterized -Connection $selfTestSourceConn -Sql "INSERT INTO [AnalysisSelfTest] ([ProjectPeriodID]) VALUES (?)" -Parameters @((DbGuid (New-GuidText))))
    }
    finally {
        if ($selfTestSourceConn.State -eq "Open") { $selfTestSourceConn.Close() }
        $selfTestSourceConn.Dispose()
    }
    $insertSelfTestRow = {
        param(
            [System.Data.OleDb.OleDbConnection]$Connection,
            [string]$TableName,
            [object]$Values
        )

        $columnInfo = @(Get-TableColumnInfo -Connection $Connection -TableName $TableName)
        $columnLookup = New-CaseInsensitiveColumnLookup @($columnInfo | ForEach-Object { $_.ColumnName })
        $dataTypes = @{}
        foreach ($info in $columnInfo) {
            $name = ConvertTo-BuilderText $info.ColumnName
            if (-not [string]::IsNullOrWhiteSpace($name)) { $dataTypes[$name.ToLowerInvariant()] = ConvertTo-BuilderText $info.DataType }
        }
        $insertColumns = New-Object System.Collections.Generic.List[string]
        foreach ($key in $Values.Keys) {
            $targetColumn = Get-ColumnLookupValue -Lookup $columnLookup -ColumnName ([string]$key)
            if ([string]::IsNullOrWhiteSpace($targetColumn)) { continue }
            [void]$insertColumns.Add($targetColumn)
        }
        if ($insertColumns.Count -eq 0) { throw "Self-test could not find any matching columns for $TableName." }
        $columnSql = [string]::Join(", ", [string[]]($insertColumns | ForEach-Object { Quote-Name $_ }))
        $placeholders = [string]::Join(", ", [string[]]($insertColumns | ForEach-Object { "?" }))
        $insertSql = "INSERT INTO $(Quote-Name $TableName) ($columnSql) VALUES ($placeholders)"
        $parameters = New-Object System.Collections.Generic.List[object]
        foreach ($targetColumn in $insertColumns) {
            $dataType = Get-UpgradeTargetDataType -DataTypeLookup $dataTypes -ColumnName $targetColumn
            $paramProjectId = ""
            if ([string]::Equals($targetColumn, "ProjectID", [System.StringComparison]::OrdinalIgnoreCase)) {
                $paramProjectId = ConvertTo-BuilderText $Values[$targetColumn]
            }
            [void]$parameters.Add((New-UpgradeImportDbParam -Value $Values[$targetColumn] -ColumnName $targetColumn -ProjectId $paramProjectId -PeriodIdMap @{} -DataType $dataType))
        }
        [void](Invoke-DbNonQueryParameterized -Connection $Connection -Sql $insertSql -Parameters @($parameters.ToArray()))
    }
    $movedTreeMeasurementId = ""
    $movedTreeScoreValue = 7
    $manualTreeScoreValue = 11
    $loadedStandardScoreValue = 13
    $tableOnlyTreeScoreValue = 17
    $legacyPlotScoreValue = 19
    $soilCodeValue = 41
    $legacyHabitatTypeValue = 21
    $plotMeasurementExtraValue = 23
    $fieldOverCoverValue = 31
    $fieldOverDensityValue = 32
    $fieldOverSizeValue = 33
    $forestClassificationValue = 1
    $treeExtraCustomValue = 29
    $plotCustomToPlotsValue = 43
    $treeCustomToMeasurementsValue = 47
    $treeCustomToTreesValue = 53
    $oldPlotRemarksValue = "Old plot remarks self-test"
    $oldTreeRemarksValue = "Old tree remarks self-test"
    $longTreeNotesValue = "Later-period tree long text self-test " + ("A" * 420)
    $oldRegenRemarksValue = "Old regen remarks self-test"
    $oldRegenMeasurementId = New-GuidText
    $orphanPlotId = New-GuidText
    $orphanPlotMeasurementId = New-GuidText
    $orphanPlotKey = New-PlotKey -PlotNumber 902
    $soilCodePlotId = New-GuidText
    $orphanRegenPlotId = New-GuidText
    $orphanRegenMeasurementId = New-GuidText
    $orphanTreePlotId = New-GuidText
    $orphanTreePlotKey = New-PlotKey -PlotNumber 904
    $orphanTreeId = New-GuidText
    $orphanTreeMeasurementId = New-GuidText
    $orphanTreeKey = "T000904001"
    $orphanTreePeriodId = New-GuidText
    $existingPlotMeasurementId = ""
    $parsedCodePairs = @(ConvertTo-AppColumnCodePairs -CodesText "1=test1 2=test2 3=test3 4=Small Sawtimber")
    if ($parsedCodePairs.Count -ne 4) { throw "Codes parser expected 4 code rows; found $($parsedCodePairs.Count)." }
    if ((ConvertTo-BuilderText $parsedCodePairs[0].Code) -ne "1" -or (ConvertTo-BuilderText $parsedCodePairs[0].CodeLabel) -ne "test1") { throw "Codes parser did not parse the first code correctly." }
    if ((ConvertTo-BuilderText $parsedCodePairs[3].Code) -ne "4" -or (ConvertTo-BuilderText $parsedCodePairs[3].CodeLabel) -ne "Small Sawtimber") { throw "Codes parser did not preserve labels with spaces." }
    $multiLineCodeText = "0=No issue`r`n1=Trace damage`r`n2=Heavy damage"
    if ((ConvertTo-AppColumnCodesCellText $multiLineCodeText) -notmatch "`r`n1=Trace damage") { throw "Codes cell text did not preserve line breaks." }
    $editorCodeText = ConvertTo-AppColumnCodesEditorText "0=None; 1=Trace damage; 2=Heavy damage"
    if ($editorCodeText -notmatch "0=None`r`n1=Trace damage`r`n2=Heavy damage") { throw "Codes editor text did not expand semicolon codes to one code per line." }
    $sortedCodeParts = @(Sort-AppColumnCodeParts -Items @("10=Other", "2=Light", "1=Trace", "0=None", "100=Maximum", "11=Not applicable"))
    if ([string]::Join("; ", [string[]]$sortedCodeParts) -ne "0=None; 1=Trace; 2=Light; 10=Other; 11=Not applicable; 100=Maximum") { throw "Loaded AppColumns code sorting did not sort numeric codes in number order." }
    $mappedPlotRow = [pscustomobject]@{ "Plot #" = "123"; "FLC Comm" = "1" }
    $mappedPlotValues = @(
        [pscustomobject]@{ FieldName = "PlotNumber"; SourceColumn = "Plot #"; Required = $true },
        [pscustomobject]@{ FieldName = "FLCCommercial"; SourceColumn = "FLC Comm"; Required = $false }
    )
    if ((Get-PlotImportValue -Row $mappedPlotRow -FieldName "PlotNumber" -Mappings $mappedPlotValues) -ne "123") { throw "Plot import mapping did not read the mapped PlotNumber column." }
    if ((Get-PlotImportValue -Row $mappedPlotRow -FieldName "FLCCommercial" -Mappings $mappedPlotValues) -ne "1") { throw "Plot import mapping did not read the mapped FLCCommercial column." }
    $plotNumberSpec = @(Get-PlotImportFieldSpecs | Where-Object { $_.FieldName -eq "PlotNumber" } | Select-Object -First 1)
    if ((Find-BestPlotImportColumn -Columns @("Plot #") -Aliases ([string[]]$plotNumberSpec[0].Aliases)) -ne "Plot #") { throw "Plot import mapper did not guess Plot # as PlotNumber." }
    $regenProcessAnchorSql = Add-CfideerProcessCustomFieldsToQuery -Sql "SELECT RegenMeasurements.MinorPlot, RegenMeasurements.RegenRemarks`r`nFROM RegenMeasurements;" -CustomTableName "RegenCustomMeasurements" -CustomFields @((New-CfideerFieldSpec -FieldName "TotalHeight" -DataType "Integer"), (New-CfideerFieldSpec -FieldName "SelfTestRegenField" -DataType "Text")) -InsertBeforeFieldNames @("RegenRemarks", "RemarksRegen")
    if ($regenProcessAnchorSql -notmatch "(?is)RegenMeasurements\.MinorPlot,\s+RegenCustomMeasurements\.TotalHeight,\s+RegenCustomMeasurements\.SelfTestRegenField,\s+RegenMeasurements\.RegenRemarks") { throw "CFIDEER regen process helper did not insert regen custom fields before RegenRemarks." }
    $regenProcessMoveSql = Add-CfideerProcessCustomFieldsToQuery -Sql "SELECT RegenMeasurements.MinorPlot, RegenMeasurements.RegenRemarks, RegenCustomMeasurements.TotalHeight`r`nFROM RegenMeasurements;" -CustomTableName "RegenCustomMeasurements" -CustomFields @((New-CfideerFieldSpec -FieldName "TotalHeight" -DataType "Integer")) -InsertBeforeFieldNames @("RegenRemarks", "RemarksRegen")
    if ($regenProcessMoveSql -notmatch "(?is)RegenMeasurements\.MinorPlot,\s+RegenCustomMeasurements\.TotalHeight,\s+RegenMeasurements\.RegenRemarks\s*\r?\nFROM" -or ([regex]::Matches($regenProcessMoveSql, "TotalHeight", [System.Text.RegularExpressions.RegexOptions]::IgnoreCase)).Count -ne 1) { throw "CFIDEER regen process helper did not move existing regen custom fields before RegenRemarks." }
    foreach ($excludedReviewTable in @("Plots", "Plot Summaries", "PlotSummaries", "RegenCalculations", "TreeCalculations", "Trees")) {
        if (-not (Test-AppColumnsReviewTableExcluded -TableName $excludedReviewTable)) { throw "AppColumns review table filter did not exclude $excludedReviewTable." }
    }
    foreach ($includedReviewTable in @("PlotMeasurements", "PlotCustomMeasurements", "TreeMeasurements", "RegenMeasurements")) {
        if (Test-AppColumnsReviewTableExcluded -TableName $includedReviewTable) { throw "AppColumns review table filter incorrectly excluded $includedReviewTable." }
    }
    foreach ($excludedReviewField in @("TreeID", "TreeKey", "TreeMeasKey", "ReadDBH", "RealDBH", "TreeMeasID", "RegenMeasKey", "ProjectPeriodID", "ProjecetPeriodID", "Plot number", "PlotNumber", "MeasurementID", "GMP", "LastGrowingSeason", "CalcsiteIndex", "CalcSiteIndex", "RemarksRegen", "RegenRemarks", "StemCount", "FieldNameSampleRemove")) {
        if (-not (Test-AppColumnsReviewFieldExcluded -FieldName $excludedReviewField)) { throw "AppColumns review field filter did not exclude $excludedReviewField." }
    }
    foreach ($includedReviewField in @("SpeciesCode", "MinorPlot", "CrownRatio", "RemarksTree")) {
        if (Test-AppColumnsReviewFieldExcluded -FieldName $includedReviewField) { throw "AppColumns review field filter incorrectly excluded $includedReviewField." }
    }
    foreach ($includedReviewField in @("SpeciesCode", "MinorPlot", "CrownRatio", "RemarksTree")) {
    if (Test-AppColumnsReviewFieldExcluded -FieldName $includedReviewField) { throw "AppColumns review field filter incorrectly excluded $includedReviewField." }
}

if (Test-AppColumnsReviewTableExcluded -TableName "Trees" -FieldName "SpeciesCode") {
    throw "AppColumns review table filter incorrectly excluded Trees.SpeciesCode."
}

if (Test-AppColumnsReviewTableExcluded -TableName "Trees" -FieldName "TreeSpeciesCode") {
    throw "AppColumns review table filter incorrectly excluded Trees.TreeSpeciesCode."
}

if (-not (Test-AppColumnsReviewTableExcluded -TableName "Trees" -FieldName "TreeNumber")) {
    throw "AppColumns review table filter should still exclude other Trees fields."
}

foreach ($tableFieldCheck in @(
    @{ TableName = "PlotMeasurements"; FieldNames = @("Crew", "Measurement Date", "PeriodNumber", "PlotID", "PlotKey", "PlotMeasKey", "Plot Status", "RemarksPlot", "StandClass", "StandAge", "StockabilityFactor", "StockabilityPct") },
    @{ TableName = "RegenMeasurements"; FieldNames = @("IDBH", "Remarks", "RemarksRegen", "RegenRemarks", "StemCount") },
    @{ TableName = "TreeMeasurements"; FieldNames = @("CrownClass", "CrownRatio", "IDBH", "PeriodNumber", "RemarksTree", "TotalHeight", "TreeHistory") }
)) {
    foreach ($fieldName in $tableFieldCheck.FieldNames) {
        if (-not (Test-AppColumnsReviewFieldExcluded -FieldName $fieldName -TableName $tableFieldCheck.TableName)) {
            throw "AppColumns review field filter did not exclude $($tableFieldCheck.TableName).$fieldName."
        }
    }
}
    foreach ($groupCheck in @(
        @{ TableName = "PlotMeasurements"; Group = "Plot" },
        @{ TableName = "PlotCustomMeasurements"; Group = "Plot" },
        @{ TableName = "TreeMeasurements"; Group = "Tree" },
        @{ TableName = "TreeCustomMeasurements"; Group = "Tree" },
        @{ TableName = "RegenMeasurements"; Group = "Regen" },
        @{ TableName = "RegenCustomMeasurements"; Group = "Regen" }
    )) {
        $actualGroup = Get-AppColumnsReviewDataGroup -TableName $groupCheck.TableName
        if ($actualGroup -ne $groupCheck.Group) { throw "AppColumns data filter grouped $($groupCheck.TableName) as $actualGroup instead of $($groupCheck.Group)." }
    }
    $outputNameHint = New-OutputDatabaseFileNameHint -ProjectName "Builder Self Test" -SourceDatabase $source -CreatedDate ([datetime]"2026-06-03")
    if ($outputNameHint -ne "Builder Self Test CFI 20260603 vX.XX.XX.mdb") { throw "Save Project Location filename hint should use a fill-in version placeholder, but got: $outputNameHint" }
    $placeholderOutputNameHint = New-OutputDatabaseFileNameHint -ProjectName $script:DefaultProjectNamePlaceholder -SourceDatabase "C:\Temp\[TribeName] CFI [Date 20260520] v3.06.00.mdb" -CreatedDate ([datetime]"2026-06-03")
    if ($placeholderOutputNameHint -ne "[TribeName] CFI [Date 20260520] vX.XX.XX.mdb") { throw "Save Project Location placeholder filename hint should use a fill-in version placeholder, but got: $placeholderOutputNameHint" }
    $futureOutputNameHint = New-OutputDatabaseFileNameHint -ProjectName $script:DefaultProjectNamePlaceholder -SourceDatabase "C:\Temp\[TribeName] CFI [Date 20270115] v3.07.01.mdb" -CreatedDate ([datetime]"2026-06-03")
    if ($futureOutputNameHint -ne "[TribeName] CFI [Date 20270115] vX.XX.XX.mdb") { throw "Save Project Location placeholder filename hint should preserve the source date but use a fill-in version placeholder, got: $futureOutputNameHint" }
    $upgradeOutputHintSource = Get-OutputDatabaseNameHintSource -Mode "Upgrade Project" -SourceDatabase "C:\Temp\Old Project CFI 20240101 v2.98.00.mdb" -UpgradeTemplateDatabase "C:\Temp\[TribeName] CFI [Date 20260520] v3.06.00.mdb"
    $upgradeOutputNameHint = New-OutputDatabaseFileNameHint -ProjectName $script:DefaultProjectNamePlaceholder -SourceDatabase $upgradeOutputHintSource -CreatedDate ([datetime]"2026-06-03")
    if ($upgradeOutputNameHint -ne "[TribeName] CFI [Date 20260520] vX.XX.XX.mdb") { throw "Upgrade Save Project Location filename hint should use the current master database version date and fill-in version placeholder, but got: $upgradeOutputNameHint" }
    $newProjectOutputHintSource = Get-OutputDatabaseNameHintSource -Mode "New Project" -SourceDatabase "C:\Temp\Old Project CFI 20240101 v2.98.00.mdb" -UpgradeTemplateDatabase "C:\Temp\[TribeName] CFI [Date 20260520] v3.06.00.mdb"
    $newProjectOutputNameHint = New-OutputDatabaseFileNameHint -ProjectName $script:DefaultProjectNamePlaceholder -SourceDatabase $newProjectOutputHintSource -CreatedDate ([datetime]"2026-06-03")
    if ($newProjectOutputNameHint -ne "[TribeName] CFI [Date 20260520] vX.XX.XX.mdb") { throw "New Project Save Project Location filename hint should use the current master database version date and fill-in version placeholder, but got: $newProjectOutputNameHint" }
    if (-not (Test-UpgradeModeText -Mode "Upgrade Project")) { throw "Upgrade mode detector did not recognize the current upgrade label." }
    if (-not (Test-UpgradeModeText -Mode "Upgrade Old Project to Selected Template")) { throw "Upgrade mode detector did not recognize the older upgrade label." }
    if (Test-UpgradeModeText -Mode "Existing Project") { throw "Upgrade mode detector incorrectly treated Existing Project as upgrade mode." }
    $processAppendSql = Add-CfideerProcessCustomFieldsToQuery -Sql "SELECT ExistingOne, ExistingTwo`r`nFROM ExistingTable;" -CustomTableName "PlotCustomMeasurements" -CustomFields @((New-CfideerFieldSpec -FieldName "SelfTestField" -DataType "Integer"))
    if ($processAppendSql -notmatch "(?is)SELECT\s+ExistingOne,\s+ExistingTwo,\s+PlotCustomMeasurements\.SelfTestField\s+FROM\s+ExistingTable") { throw "Process query append helper did not preserve the existing SELECT list and append the custom field before FROM." }
    $processAppendAgainSql = Add-CfideerProcessCustomFieldsToQuery -Sql $processAppendSql -CustomTableName "PlotCustomMeasurements" -CustomFields @((New-CfideerFieldSpec -FieldName "SelfTestField" -DataType "Integer"))
    if (([regex]::Matches($processAppendAgainSql, "SelfTestField", [System.Text.RegularExpressions.RegexOptions]::IgnoreCase)).Count -ne 1) { throw "Process query append helper duplicated an existing custom field." }
    $processCleanupSql = Add-CfideerProcessCustomFieldsToQuery -Sql "SELECT ExistingOne, PlotCustomMeasurements.FieldNameSampleRemove, ExistingTwo`r`nFROM ExistingTable;" -CustomTableName "PlotCustomMeasurements" -CustomFields @((New-CfideerFieldSpec -FieldName "SelfTestField" -DataType "Integer"))
    if ($processCleanupSql -match "(?i)FieldNameSampleRemove") { throw "Process query append helper did not remove FieldNameSampleRemove from the preserved SELECT list." }
    if ($processCleanupSql -notmatch "(?is)ExistingOne,\s+ExistingTwo,\s+PlotCustomMeasurements\.SelfTestField") { throw "Process query append helper removed more than the placeholder field." }
    $loadedAppColumnTest = $null
    $sourceConn = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $source)
    try {
        $loadedCandidates = @(Get-AppColumnsForBuilder -Connection $sourceConn | Where-Object {
            $_.Active -and
            -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $_.AppColumnID)) -and
            -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $_.TableName)) -and
            -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $_.FieldName))
        })
        if ($loadedCandidates.Count -gt 0) {
            $loadedAppColumnTest = $loadedCandidates[0]
            $loadedAppColumnTest.Active = $false
            $loadedAppColumnTest.Collected = $false
            $loadedAppColumnTest.ArchiveOnly = $true
            $loadedAppColumnTest.ReportVisible = $false
            $loadedAppColumnTest.QueryVisible = $false
        }
    }
    finally {
        if ($sourceConn.State -eq "Open") { $sourceConn.Close() }
        $sourceConn.Dispose()
    }
    $customFields = New-Object System.Collections.Generic.List[object]
    if ($null -ne $loadedAppColumnTest) { [void]$customFields.Add($loadedAppColumnTest) }
    [void]$customFields.Add([pscustomobject]@{
        TableName = "PlotCustomMeasurements"
        FieldName = "SelfTestField"
        DataType = "Integer"
        Category = "Range"
        FriendlyName = "Self Test Field"
        ShortName = "Self Test"
        Description = "Temporary builder self-test field"
        ValidationAbrv = "SELF"
        Active = $true
        DisplayRule = $false
        Codes = ""
        ReportVisible = $true
    })
    [void]$customFields.Add([pscustomobject]@{
        TableName = "TreeCustomMeasurements"
        FieldName = "SelfTestTreeField"
        DataType = "Integer"
        Category = "Range"
        FriendlyName = "Self Test Tree Field"
        ShortName = "Self Tree"
        Description = "Temporary builder self-test tree field"
        ValidationAbrv = "SELFT"
        Active = $true
        DisplayRule = $false
        Codes = ""
        ReportVisible = $true
    })
    [void]$customFields.Add([pscustomobject]@{
        TableName = "RegenCustomMeasurements"
        FieldName = "SelfTestRegenField"
        DataType = "Integer"
        Category = "Range"
        FriendlyName = "Self Test Regen Field"
        ShortName = "Self Regen"
        Description = "Temporary builder self-test regen field"
        ValidationAbrv = "SELFR"
        Active = $true
        DisplayRule = $false
        Codes = ""
        ReportVisible = $true
    })
    $config = [pscustomobject]@{
        Mode = "New Project"
        SourceDatabase = ""
        UpgradeTemplateDatabase = $selfTestSource
        OutputDatabase = $testOutput
        ProjectName = "Builder Self Test"
        ReservationCode = ""
        ReservationName = ""
        AgencyName = ""
        RegionName = ""
        AllowBlankReferenceSelection = $true
        CycleLength = 10
        Periods = @((New-DefaultPeriod))
        PruneReferences = $false
        CustomFields = @($customFields.ToArray())
        UpdateValidation = $true
        PlotImportPath = ""
        SetupAssignments = $true
        SetupTreeAssignments = $false
        CrewNames = @("Team1")
        UpdateReports = $true
        BuildCfideerQueries = $true
    }
    try {
        Invoke-InventoryBuild -Config $config -Log $log
        $conn = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $testOutput)
        try {
            $projectCount = [int](Get-DbScalar -Connection $conn -Sql "SELECT Count(*) FROM [Projects]")
            $periodCount = [int](Get-DbScalar -Connection $conn -Sql "SELECT Count(*) FROM [ProjectMeasurementPeriods]")
            $fieldExists = Test-ColumnExists -Connection $conn -TableName "PlotCustomMeasurements" -ColumnName "SelfTestField"
            if ($projectCount -ne 1) { throw "Expected 1 project row; found $projectCount." }
            if ($periodCount -ne 1) { throw "Expected 1 period row; found $periodCount." }
            if (-not $fieldExists) { throw "Self-test custom field was not added." }
            foreach ($placeholderTable in @("PlotCustomMeasurements", "TreeCustomMeasurements", "RegenCustomMeasurements")) {
                if (Test-ColumnExists -Connection $conn -TableName $placeholderTable -ColumnName "FieldNameSampleRemove") {
                    throw "Placeholder column FieldNameSampleRemove was not removed from $placeholderTable."
                }
            }
            $placeholderAppColumnCount = [int](Get-DbScalar -Connection $conn -Sql "SELECT Count(*) FROM [AppColumns] WHERE [ColumnName] = 'FieldNameSampleRemove'")
            if ($placeholderAppColumnCount -ne 0) { throw "Placeholder AppColumns row FieldNameSampleRemove was not removed." }
            $selfTestColumnId = Get-RequiredScalarText -Connection $conn -Sql "SELECT TOP 1 [ID] FROM [AppColumns] WHERE [ColumnName] = 'SelfTestField'" -Message "Self-test AppColumns row was not found."
            $selfTestTreeColumnId = Get-RequiredScalarText -Connection $conn -Sql "SELECT TOP 1 [ID] FROM [AppColumns] WHERE [ColumnName] = 'SelfTestTreeField'" -Message "Self-test tree AppColumns row was not found."
            $selfTestRegenColumnId = Get-RequiredScalarText -Connection $conn -Sql "SELECT TOP 1 [ID] FROM [AppColumns] WHERE [ColumnName] = 'SelfTestRegenField'" -Message "Self-test regen AppColumns row was not found."
            $selfTestReportCount = [int](Get-DbScalar -Connection $conn -Sql "SELECT Count(*) FROM [ReportColumns] WHERE [ReportSection] = 'Plot' AND [ReportGroup] = 3 AND [ColumnID] = $(Sql-Guid $selfTestColumnId)")
            if ($selfTestReportCount -ne 1) { throw "Self-test report column was not added to Plot group 3." }
            $treeSelfTestReportCount = [int](Get-DbScalar -Connection $conn -Sql "SELECT Count(*) FROM [ReportColumns] WHERE [ReportSection] = 'Tree' AND [ReportGroup] = 1 AND [ColumnID] = $(Sql-Guid $selfTestTreeColumnId)")
            if ($treeSelfTestReportCount -ne 1) { throw "Self-test tree report column was not added to Tree group 1." }
            $regenSelfTestReportCount = [int](Get-DbScalar -Connection $conn -Sql "SELECT Count(*) FROM [ReportColumns] WHERE [ReportSection] = 'Regen' AND [ReportGroup] = 1 AND [ColumnID] = $(Sql-Guid $selfTestRegenColumnId)")
            if ($regenSelfTestReportCount -ne 1) { throw "Self-test regen report column was not added to Regen group 1." }
            $remarksReportCount = [int](Get-DbScalar -Connection $conn -Sql "SELECT Count(*) FROM [ReportColumns] AS rc INNER JOIN [AppColumns] AS ac ON rc.[ColumnID] = ac.[ID] WHERE rc.[ReportSection] = 'Plot' AND rc.[ReportGroup] = 3 AND ac.[ColumnName] = 'RemarksPlot'")
            if ($remarksReportCount -ne 1) { throw "Plot Remarks report column was not preserved." }
            $getReportIndex = {
                param(
                    [string]$Section,
                    [int]$Group,
                    [string]$ColumnName
                )

                $value = Get-DbScalar -Connection $conn -Sql "SELECT TOP 1 rc.[ReportIndex] FROM [ReportColumns] AS rc INNER JOIN [AppColumns] AS ac ON rc.[ColumnID] = ac.[ID] WHERE rc.[ReportSection] = $(Sql-Text $Section) AND rc.[ReportGroup] = $Group AND ac.[ColumnName] = $(Sql-Text $ColumnName)"
                if ($null -eq $value -or $value -is [System.DBNull]) { throw "Report column not found for $Section group $Group field $ColumnName." }
                return [int]$value
            }
            $plotCustomReportIndex = & $getReportIndex "Plot" 3 "SelfTestField"
            $plotRemarksReportIndex = & $getReportIndex "Plot" 3 "RemarksPlot"
            if (-not ($plotCustomReportIndex -lt $plotRemarksReportIndex)) { throw "Plot custom report field was not placed before Plot Remarks." }
            $treeRadialReportIndex = & $getReportIndex "Tree" 1 "RadialIncrement"
            $treeCustomReportIndex = & $getReportIndex "Tree" 1 "SelfTestTreeField"
            $treeRemarksReportIndex = & $getReportIndex "Tree" 1 "RemarksTree"
            if (-not ($treeRadialReportIndex -lt $treeCustomReportIndex -and $treeCustomReportIndex -lt $treeRemarksReportIndex)) { throw "Tree custom report field was not placed between Radial Increment and Tree Remarks." }
            $regenStemReportIndex = & $getReportIndex "Regen" 1 "StemCount"
            $regenCustomReportIndex = & $getReportIndex "Regen" 1 "SelfTestRegenField"
            $regenRemarksReportIndex = & $getReportIndex "Regen" 1 "RemarksRegen"
            if (-not ($regenStemReportIndex -lt $regenCustomReportIndex -and $regenCustomReportIndex -lt $regenRemarksReportIndex)) { throw "Regen custom report field was not placed between Stem Count and Regen Remarks." }
