            $loadedStandardScore = Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [LoadedStandardScore] FROM [TreeCustomMeasurements] WHERE [MeasurementID] = $(Sql-Guid $movedTreeMeasurementId)"
            if ([int]$loadedStandardScore -ne $loadedStandardScoreValue) { throw "Upgrade self-test did not move active loaded AppColumns field TreeMeasurements.LoadedStandardScore into TreeCustomMeasurements.LoadedStandardScore." }
            if (-not (Test-ColumnExists -Connection $upgradeConn -TableName "TreeCustomMeasurements" -ColumnName "MappedTreeScore")) { throw "Upgrade self-test manual mapping destination column was not added." }
            $mappedTreeScore = Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [MappedTreeScore] FROM [TreeCustomMeasurements] WHERE [MeasurementID] = $(Sql-Guid $movedTreeMeasurementId)"
            if ([int]$mappedTreeScore -ne $manualTreeScoreValue) { throw "Upgrade self-test did not map TreeMeasurements.OldTreeScore into TreeCustomMeasurements.MappedTreeScore." }
            if (-not (Test-ColumnExists -Connection $upgradeConn -TableName "TreeCustomMeasurements" -ColumnName "TableOnlyTreeScore")) { throw "Upgrade self-test table-only manual mapping did not add TreeCustomMeasurements.TableOnlyTreeScore." }
            $tableOnlyTreeScore = Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [TableOnlyTreeScore] FROM [TreeCustomMeasurements] WHERE [MeasurementID] = $(Sql-Guid $movedTreeMeasurementId)"
            if ([int]$tableOnlyTreeScore -ne $tableOnlyTreeScoreValue) { throw "Upgrade self-test did not map TreeMeasurements.TableOnlyTreeScore into TreeCustomMeasurements.TableOnlyTreeScore." }
            $tableOnlyAppColumnCount = [int](Get-DbScalar -Connection $upgradeConn -Sql "SELECT Count(*) FROM [AppColumns] WHERE [ColumnName] = 'TableOnlyTreeScore'")
            if ($tableOnlyAppColumnCount -gt 0) { throw "Upgrade self-test table-only manual mapping should not automatically add an AppColumns row for TableOnlyTreeScore." }
            if (-not (Test-ColumnExists -Connection $upgradeConn -TableName "TreeCustomMeasurements" -ColumnName "TreeExtraCustom")) { throw "Upgrade self-test table-only manual mapping did not add TreeCustomMeasurements.TreeExtraCustom." }
            $treeExtraCustom = Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [TreeExtraCustom] FROM [TreeCustomMeasurements] WHERE [MeasurementID] = $(Sql-Guid $movedTreeMeasurementId)"
            if ([int]$treeExtraCustom -ne $treeExtraCustomValue) { throw "Upgrade self-test did not map TreeMeasurements.TreeExtraCustom into TreeCustomMeasurements.TreeExtraCustom." }
            if (-not (Test-ColumnExists -Connection $upgradeConn -TableName "TreeCustomMeasurements" -ColumnName "LongTreeNotes")) { throw "Upgrade self-test table-only manual mapping did not add TreeCustomMeasurements.LongTreeNotes." }
            $longTreeNotes = ConvertTo-BuilderText (Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [LongTreeNotes] FROM [TreeCustomMeasurements] WHERE [MeasurementID] = $(Sql-Guid $movedTreeMeasurementId)")
            if (-not [string]::Equals($longTreeNotes, $longTreeNotesValue, [System.StringComparison]::Ordinal)) { throw "Upgrade self-test did not preserve a later-period long text tree measurement value." }
            if (-not (Test-ColumnExists -Connection $upgradeConn -TableName "TreeMeasurements" -ColumnName "CustomTreeToMeasurements")) { throw "Upgrade self-test table-only manual mapping did not add TreeMeasurements.CustomTreeToMeasurements." }
            $customTreeToMeasurements = Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [CustomTreeToMeasurements] FROM [TreeMeasurements] WHERE [MeasurementID] = $(Sql-Guid $movedTreeMeasurementId)"
            if ([int]$customTreeToMeasurements -ne $treeCustomToMeasurementsValue) { throw "Upgrade self-test did not map TreeCustomMeasurements.CustomTreeToMeasurements into TreeMeasurements.CustomTreeToMeasurements." }
            if (-not (Test-ColumnExists -Connection $upgradeConn -TableName "Trees" -ColumnName "CustomTreeToTrees")) { throw "Upgrade self-test table-only manual mapping did not add Trees.CustomTreeToTrees." }
            $customTreeToTrees = Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [CustomTreeToTrees] FROM [Trees] WHERE [TreeID] = $(Sql-Guid $movedTreeId)"
            if ([int]$customTreeToTrees -ne $treeCustomToTreesValue) { throw "Upgrade self-test did not map TreeCustomMeasurements.CustomTreeToTrees into Trees.CustomTreeToTrees." }
            $remarksTree = ConvertTo-BuilderText (Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [RemarksTree] FROM [TreeMeasurements] WHERE [MeasurementID] = $(Sql-Guid $movedTreeMeasurementId)")
            if (-not [string]::Equals($remarksTree, $oldTreeRemarksValue, [System.StringComparison]::Ordinal)) { throw "Upgrade self-test did not map TreeRemarks into TreeMeasurements.RemarksTree." }
            $remarksPlot = ConvertTo-BuilderText (Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [RemarksPlot] FROM [PlotMeasurements] WHERE [MeasurementID] = $(Sql-Guid $existingPlotMeasurementId)")
            if (-not [string]::Equals($remarksPlot, $oldPlotRemarksValue, [System.StringComparison]::Ordinal)) { throw "Upgrade self-test did not map PlotRemarks into PlotMeasurements.RemarksPlot." }
            $remarksRegen = ConvertTo-BuilderText (Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [RemarksRegen] FROM [RegenMeasurements] WHERE [MeasurementID] = $(Sql-Guid $oldRegenMeasurementId)")
            if (-not [string]::Equals($remarksRegen, $oldRegenRemarksValue, [System.StringComparison]::Ordinal)) { throw "Upgrade self-test did not map Remarks into RegenMeasurements.RemarksRegen." }
            if (-not (Test-ColumnExists -Connection $upgradeConn -TableName "PlotCustomMeasurements" -ColumnName "LegacyPlotScore")) { throw "Upgrade self-test table-only manual mapping did not add PlotCustomMeasurements.LegacyPlotScore." }
            $legacyPlotScore = Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [LegacyPlotScore] FROM [PlotCustomMeasurements] WHERE [MeasurementID] = $(Sql-Guid $existingPlotMeasurementId)"
            if ([int]$legacyPlotScore -ne $legacyPlotScoreValue) { throw "Upgrade self-test did not map Plots.LegacyPlotScore into PlotCustomMeasurements.LegacyPlotScore." }
            if (-not (Test-ColumnExists -Connection $upgradeConn -TableName "PlotCustomMeasurements" -ColumnName "SoilCode")) { throw "Upgrade self-test table-only manual mapping did not add PlotCustomMeasurements.SoilCode." }
            $soilCode = Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [SoilCode] FROM [PlotCustomMeasurements] WHERE [MeasurementID] = $(Sql-Guid $orphanPlotMeasurementId)"
            if ([int]$soilCode -ne $soilCodeValue) { throw "Upgrade self-test did not map Plots.SoilCode into PlotCustomMeasurements.SoilCode by PlotKey fallback." }
            $habitatTypeValue = Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [HabitatType] FROM [PlotMeasurements] WHERE [MeasurementID] = $(Sql-Guid $existingPlotMeasurementId)"
            if ([int]$habitatTypeValue -ne $legacyHabitatTypeValue) { throw "Upgrade self-test did not map Plots.HabitatType into PlotMeasurements.HabitatType." }
            $coverTypeValue = Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [CoverType] FROM [PlotMeasurements] WHERE [MeasurementID] = $(Sql-Guid $existingPlotMeasurementId)"
            if ([int]$coverTypeValue -ne $fieldOverCoverValue) { throw "Upgrade self-test did not map FieldOverCover into PlotMeasurements.CoverType." }
            $densityClassValue = Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [DensityClass] FROM [PlotMeasurements] WHERE [MeasurementID] = $(Sql-Guid $existingPlotMeasurementId)"
            if ([int]$densityClassValue -ne $fieldOverDensityValue) { throw "Upgrade self-test did not map FieldOverDensity into PlotMeasurements.DensityClass." }
            $sizeClassValue = Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [SizeClass] FROM [PlotMeasurements] WHERE [MeasurementID] = $(Sql-Guid $existingPlotMeasurementId)"
            if ([int]$sizeClassValue -ne $fieldOverSizeValue) { throw "Upgrade self-test did not map FieldOverSize into PlotMeasurements.SizeClass." }
            $flcCommercialValue = Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [FLCCommercial] FROM [Plots] WHERE [PlotID] = $(Sql-Guid $movedPlotId)"
            if ([int]$flcCommercialValue -ne $forestClassificationValue) { throw "Upgrade self-test did not map ForestClassification into Plots.FLCCommercial." }
            if (-not (Test-ColumnExists -Connection $upgradeConn -TableName "PlotCustomMeasurements" -ColumnName "PlotMeasurementExtra")) { throw "Upgrade self-test table-only manual mapping did not add PlotCustomMeasurements.PlotMeasurementExtra." }
            $plotMeasurementExtra = Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [PlotMeasurementExtra] FROM [PlotCustomMeasurements] WHERE [MeasurementID] = $(Sql-Guid $existingPlotMeasurementId)"
            if ([int]$plotMeasurementExtra -ne $plotMeasurementExtraValue) { throw "Upgrade self-test did not map PlotMeasurements.PlotMeasurementExtra into PlotCustomMeasurements.PlotMeasurementExtra." }
            if (-not (Test-ColumnExists -Connection $upgradeConn -TableName "Plots" -ColumnName "CustomPlotToPlots")) { throw "Upgrade self-test table-only manual mapping did not add Plots.CustomPlotToPlots." }
            $customPlotToPlots = Get-DbScalar -Connection $upgradeConn -Sql "SELECT TOP 1 [CustomPlotToPlots] FROM [Plots] WHERE [PlotID] = $(Sql-Guid $movedPlotId)"
            if ([int]$customPlotToPlots -ne $plotCustomToPlotsValue) { throw "Upgrade self-test did not map PlotCustomMeasurements.CustomPlotToPlots into Plots.CustomPlotToPlots." }
            $plotMeasurementCountForMovedPlot = [int](Get-DbScalar -Connection $upgradeConn -Sql "SELECT Count(*) FROM [PlotMeasurements] WHERE [PlotID] = $(Sql-Guid $movedPlotId)")
            if ($plotMeasurementCountForMovedPlot -ne 2) { throw "Upgrade self-test expected one existing and one blank new PlotMeasurements row for the imported plot; found $plotMeasurementCountForMovedPlot." }
            $blankPlotMeasurementRows = Get-DbTable -Connection $upgradeConn -Sql "SELECT [MeasurementID], [UpdUser] FROM [PlotMeasurements] WHERE [PlotID] = $(Sql-Guid $movedPlotId) AND [ProjectPeriodID] = $(Sql-Guid $upgradePeriod2Id)"
            if ($blankPlotMeasurementRows.Rows.Count -ne 1) { throw "Upgrade self-test did not create the blank PlotMeasurements row for the new period." }
            $blankPlotMeasurementId = Get-DataRowText -Row $blankPlotMeasurementRows.Rows[0] -ColumnNames @("MeasurementID")
            $blankPlotMeasurementUpdUser = Get-DataRowText -Row $blankPlotMeasurementRows.Rows[0] -ColumnNames @("UpdUser")
            if (-not [string]::Equals($blankPlotMeasurementUpdUser, "Pickle", [System.StringComparison]::OrdinalIgnoreCase)) { throw "Blank new PlotMeasurements row did not use UpdUser=Pickle." }
            $blankPlotCustomCount = [int](Get-DbScalar -Connection $upgradeConn -Sql "SELECT Count(*) FROM [PlotCustomMeasurements] WHERE [MeasurementID] = $(Sql-Guid $blankPlotMeasurementId)")
            if ($blankPlotCustomCount -ne 1) { throw "Upgrade self-test did not create the matching PlotCustomMeasurements row for the blank new plot measurement." }
            $orphanPlotRepairRows = Get-DbTable -Connection $upgradeConn -Sql "SELECT [PlotNumber], [UpdUser] FROM [Plots] WHERE [PlotID] = $(Sql-Guid $orphanPlotId)"
            if ($orphanPlotRepairRows.Rows.Count -ne 1) { throw "Upgrade self-test did not create a missing Plots row from an orphan PlotMeasurements row." }
            if ([int]$orphanPlotRepairRows.Rows[0]["PlotNumber"] -ne 902) { throw "Upgrade self-test created the orphan plot repair row with the wrong PlotNumber." }
            if (-not [string]::Equals((ConvertTo-BuilderText $orphanPlotRepairRows.Rows[0]["UpdUser"]), "Pickle", [System.StringComparison]::OrdinalIgnoreCase)) { throw "Orphan plot repair row did not use UpdUser=Pickle." }
            $orphanPlotCustomCount = [int](Get-DbScalar -Connection $upgradeConn -Sql "SELECT Count(*) FROM [PlotCustomMeasurements] WHERE [MeasurementID] = $(Sql-Guid $orphanPlotMeasurementId)")
            if ($orphanPlotCustomCount -ne 1) { throw "Upgrade self-test did not create a matching PlotCustomMeasurements row for an orphan plot measurement." }
            $orphanRegenPlotRepairRows = Get-DbTable -Connection $upgradeConn -Sql "SELECT [PlotNumber], [UpdUser] FROM [Plots] WHERE [PlotID] = $(Sql-Guid $orphanRegenPlotId)"
            if ($orphanRegenPlotRepairRows.Rows.Count -ne 1) { throw "Upgrade self-test did not create a missing Plots row from an orphan RegenMeasurements row." }
            if ([int]$orphanRegenPlotRepairRows.Rows[0]["PlotNumber"] -ne 903) { throw "Upgrade self-test created the orphan regen plot repair row with the wrong PlotNumber." }
            if (-not [string]::Equals((ConvertTo-BuilderText $orphanRegenPlotRepairRows.Rows[0]["UpdUser"]), "Pickle", [System.StringComparison]::OrdinalIgnoreCase)) { throw "Orphan regen plot repair row did not use UpdUser=Pickle." }
            $orphanRegenCustomCount = [int](Get-DbScalar -Connection $upgradeConn -Sql "SELECT Count(*) FROM [RegenCustomMeasurements] WHERE [MeasurementID] = $(Sql-Guid $orphanRegenMeasurementId)")
            if ($orphanRegenCustomCount -ne 1) { throw "Upgrade self-test did not create a matching RegenCustomMeasurements row for an orphan regen measurement." }
            $orphanTreePlotRepairRows = Get-DbTable -Connection $upgradeConn -Sql "SELECT [PlotNumber], [UpdUser] FROM [Plots] WHERE [PlotID] = $(Sql-Guid $orphanTreePlotId)"
            if ($orphanTreePlotRepairRows.Rows.Count -ne 1) { throw "Upgrade self-test did not create a missing Plots row from an orphan TreeMeasurements row." }
            if ([int]$orphanTreePlotRepairRows.Rows[0]["PlotNumber"] -ne 904) { throw "Upgrade self-test created the orphan tree plot repair row with the wrong PlotNumber." }
            $orphanTreeRepairRows = Get-DbTable -Connection $upgradeConn -Sql "SELECT [TreeNumber], [UpdUser] FROM [Trees] WHERE [TreeID] = $(Sql-Guid $orphanTreeId)"
            if ($orphanTreeRepairRows.Rows.Count -ne 1) { throw "Upgrade self-test did not create a missing Trees row from an orphan TreeMeasurements row." }
            if ([int]$orphanTreeRepairRows.Rows[0]["TreeNumber"] -ne 12) { throw "Upgrade self-test created the orphan tree repair row with the wrong TreeNumber." }
            if (-not [string]::Equals((ConvertTo-BuilderText $orphanTreeRepairRows.Rows[0]["UpdUser"]), "Pickle", [System.StringComparison]::OrdinalIgnoreCase)) { throw "Orphan tree repair row did not use UpdUser=Pickle." }
            $orphanTreeCustomCount = [int](Get-DbScalar -Connection $upgradeConn -Sql "SELECT Count(*) FROM [TreeCustomMeasurements] WHERE [MeasurementID] = $(Sql-Guid $orphanTreeMeasurementId)")
            if ($orphanTreeCustomCount -ne 1) { throw "Upgrade self-test did not create a matching TreeCustomMeasurements row for an orphan tree measurement." }
            $assignmentPlotCount = [int](Get-DbScalar -Connection $upgradeConn -Sql "SELECT Count(*) FROM [InventoryAssignmentPlots]")
            if ($assignmentPlotCount -lt 1) { throw "Upgrade self-test did not build InventoryAssignmentPlots from imported plot rows." }
            $nonAwaitingAssignmentPlotCount = [int](Get-DbScalar -Connection $upgradeConn -Sql "SELECT Count(*) FROM [InventoryAssignmentPlots] WHERE ([StatusID] Is Null OR [StatusID] <> 1)")
            if ($nonAwaitingAssignmentPlotCount -gt 0) { throw "Upgrade self-test expected all InventoryAssignmentPlots rows to use StatusID=1 for Awaiting Work." }
            $assignmentTreeCount = [int](Get-DbScalar -Connection $upgradeConn -Sql "SELECT Count(*) FROM [InventoryAssignmentTrees]")
            if ($assignmentTreeCount -lt 1) { throw "Upgrade self-test did not build InventoryAssignmentTrees from imported tree rows." }
            $nonAwaitingAssignmentTreeCount = [int](Get-DbScalar -Connection $upgradeConn -Sql "SELECT Count(*) FROM [InventoryAssignmentTrees] WHERE ([AssignmentStatusID] Is Null OR [AssignmentStatusID] <> 1)")
            if ($nonAwaitingAssignmentTreeCount -gt 0) { throw "Upgrade self-test expected all InventoryAssignmentTrees rows to use AssignmentStatusID=1 for Awaiting Work." }
        }
        finally {
            if ($upgradeConn.State -eq "Open") { $upgradeConn.Close() }
            $upgradeConn.Dispose()
        }

        $oldRunLogConn = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $upgradeTestOutput)
        try {
            if (Test-TableExists -Connection $oldRunLogConn -TableName $script:RunLogTableName) {
                [void](Invoke-DbNonQuery -Connection $oldRunLogConn -Sql "DROP TABLE [$script:RunLogTableName]")
            }
            [void](Invoke-DbNonQuery -Connection $oldRunLogConn -Sql "CREATE TABLE [$script:RunLogTableName] ([RunID] TEXT(38), [StepNumber] INTEGER, [LogTime] DATETIME, [RunStatus] TEXT(32), [Mode] TEXT(32), [ProjectName] TEXT(80), [SourceDatabase] TEXT(255), [OutputDatabase] TEXT(255), [Message] TEXT(255))")
        }
        finally {
            if ($oldRunLogConn.State -eq "Open") { $oldRunLogConn.Close() }
            $oldRunLogConn.Dispose()
        }

        $longRunLogMessage = "Upgrade run log self-test " + ("X" * 700)
        Write-WOOFRunLog -DatabasePath $upgradeTestOutput -Entries @([pscustomobject]@{
            LogTime = (Get-Date)
            StepCategory = "Self-Test"
            ElapsedSeconds = 12.345
            StepDurationSeconds = 1.234
            ElapsedTime = "00:12.345"
            StepDuration = "00:01.234"
            Message = $longRunLogMessage
        }) -Config $upgradeConfig -RunStatus "Success"
        $runLogVerifyConn = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $upgradeTestOutput)
        try {
            $savedMode = ConvertTo-BuilderText (Get-DbScalar -Connection $runLogVerifyConn -Sql "SELECT TOP 1 [Mode] FROM [$script:RunLogTableName]")
            if (-not [string]::Equals($savedMode, $script:UpgradeModeLabel, [System.StringComparison]::Ordinal)) { throw "Run log self-test did not preserve the full upgrade mode label." }
            $savedMessageLength = [int](Get-DbScalar -Connection $runLogVerifyConn -Sql "SELECT TOP 1 Len([Message]) FROM [$script:RunLogTableName]")
            if ($savedMessageLength -lt 700) { throw "Run log self-test did not preserve long log messages." }
            $savedCategory = ConvertTo-BuilderText (Get-DbScalar -Connection $runLogVerifyConn -Sql "SELECT TOP 1 [StepCategory] FROM [$script:RunLogTableName]")
            if (-not [string]::Equals($savedCategory, "Self-Test", [System.StringComparison]::Ordinal)) { throw "Run log self-test did not save StepCategory." }
            $savedElapsedSeconds = [double](Get-DbScalar -Connection $runLogVerifyConn -Sql "SELECT TOP 1 [ElapsedSeconds] FROM [$script:RunLogTableName]")
            if ([Math]::Abs($savedElapsedSeconds - 12.345) -gt 0.001) { throw "Run log self-test did not save ElapsedSeconds." }
            $savedStepDurationSeconds = [double](Get-DbScalar -Connection $runLogVerifyConn -Sql "SELECT TOP 1 [StepDurationSeconds] FROM [$script:RunLogTableName]")
            if ([Math]::Abs($savedStepDurationSeconds - 1.234) -gt 0.001) { throw "Run log self-test did not save StepDurationSeconds." }
        }
        finally {
            if ($runLogVerifyConn.State -eq "Open") { $runLogVerifyConn.Close() }
            $runLogVerifyConn.Dispose()
        }
        $runLogTextSelfTestPath = Join-Path ([System.IO.Path]::GetTempPath()) ("_woof_runlog_selftest_" + ([guid]::NewGuid()).ToString("N") + ".txt")
        $savedRunLogTextPath = Write-WOOFRunLogTextExport -Entries @([pscustomobject]@{
            LogTime = (Get-Date)
            StepCategory = "Self-Test"
            ElapsedSeconds = 12.345
            StepDurationSeconds = 1.234
            ElapsedTime = "00:12.345"
            StepDuration = "00:01.234"
            Message = $longRunLogMessage
        }) -Config $upgradeConfig -RunStatus "Failed" -PreferredPath $runLogTextSelfTestPath
        if (-not (Test-Path -LiteralPath $savedRunLogTextPath)) { throw "Run log text self-test did not write the detailed text file." }
        $savedRunLogText = Get-Content -LiteralPath $savedRunLogTextPath -Raw
        if ($savedRunLogText -notmatch "Project Pickle Detailed Run Log") { throw "Run log text self-test did not include the expected heading." }
        if ($savedRunLogText -notmatch "Run status: Failed") { throw "Run log text self-test did not include the failed status." }
        if ($savedRunLogText -notmatch "Upgrade run log self-test") { throw "Run log text self-test did not include the log message." }
        Remove-Item -LiteralPath $savedRunLogTextPath -Force
        Write-Output "Self-test passed."
    }
    finally {
        foreach ($cleanupOutput in @($selfTestSource, $testOutput, $upgradeTestOutput)) {
            if (-not (Test-Path -LiteralPath $cleanupOutput)) { continue }
            $removed = $false
            Start-Sleep -Milliseconds 1000
            for ($attempt = 1; $attempt -le 30 -and -not $removed; $attempt++) {
                [System.Data.OleDb.OleDbConnection]::ReleaseObjectPool()
                [GC]::Collect()
                [GC]::WaitForPendingFinalizers()
                try {
                    (Get-Item -LiteralPath $cleanupOutput).Attributes = [System.IO.FileAttributes]::Normal
                    Remove-Item -LiteralPath $cleanupOutput -Force
                    $removed = $true
                }
                catch {
                    Start-Sleep -Milliseconds 1000
                }
            }
            if (-not $removed) {
                Write-Output "Self-test temporary database could not be removed: $cleanupOutput"
            }
        }
    }
}

function Get-ProjectPickleSyntheticReportFormatInfo {
    [CmdletBinding()]
    param(
        [AllowNull()]
        [object]$FieldFormat,

        [AllowNull()]
        [object]$ColumnName
    )

    $rawFormat =
        [Convert]::ToString($FieldFormat).Trim()

    $name =
        [Convert]::ToString($ColumnName).Trim()

    $width = 0
    $alignment = "Right"
    $kind = "Number"
    $formatCode = ""
    $warning = ""

    # Standard .NET composite formats, such as:
    # {0,6:n0}
    # {0,8:g0}
    # {0,-12}
    $compositeMatch = [regex]::Match(
        $rawFormat,
        '^\s*\{0\s*,\s*(-?\d+)(?:\s*:\s*([^}]+))?\}\s*$'
    )

    if ($compositeMatch.Success) {
        $parsedWidth = 0

        if (
            [int]::TryParse(
                $compositeMatch.Groups[1].Value,
                [ref]$parsedWidth
            )
        ) {
            $width = [Math]::Abs($parsedWidth)

            if ($parsedWidth -lt 0) {
                $alignment = "Left"
            }
        }

        if ($compositeMatch.Groups[2].Success) {
            $formatCode =
                $compositeMatch.Groups[2].Value.Trim()
        }

        $kind = "Composite"
    }
    else {
        # Legacy text formats, such as:
        # TEXT,41,05
        # TEXT,50,6
        #
        # The first number after TEXT is the printable field width.
        $textMatch = [regex]::Match(
            $rawFormat,
            '(?i)^\s*TEXT\s*,\s*(\d+)(?:\s*,.*)?$'
        )

        if ($textMatch.Success) {
            $parsedWidth = 0

            if (
                [int]::TryParse(
                    $textMatch.Groups[1].Value,
                    [ref]$parsedWidth
                )
            ) {
                $width = [Math]::Abs($parsedWidth)
            }

            $alignment = "Left"
            $kind = "Text"
        }
        elseif (
            $rawFormat -match
            '(?i)^\s*DATE(?:\s*,.*)?$'
        ) {
            # Most legacy report dates print as MM/dd/yyyy.
            $width = 10
            $alignment = "Left"
            $kind = "Date"
        }
        elseif (
            $rawFormat -match
            '(?i)^\s*(BOOL|BOOLEAN|LOGICAL)(?:\s*,.*)?$'
        ) {
            $width = 3
            $alignment = "Left"
            $kind = "Boolean"
        }
    }

    if ($width -le 0) {
        $nameWidth = 8

        if (-not [string]::IsNullOrWhiteSpace($name)) {
            $nameWidth = $name.Length
        }

        $width = [Math]::Max(
            6,
            [Math]::Min(
                24,
                $nameWidth
            )
        )

        if ($name -match '(?i)remarks') {
            $kind = "Text"
            $alignment = "Left"
            $width = [Math]::Max(
                20,
                $width
            )
        }

        if ([string]::IsNullOrWhiteSpace($rawFormat)) {
            $warning = (
                "FieldFormat is blank. The synthetic preview used " +
                "a fallback width of $width."
            )
        }
        else {
            $warning = (
                "FieldFormat '$rawFormat' was not recognized. " +
                "The synthetic preview used a fallback width of $width."
            )
        }
    }

    return [pscustomobject]@{
        RawFormat = $rawFormat
        Width = [int]$width
        Alignment = $alignment
        Kind = $kind
        FormatCode = $formatCode
        Warning = $warning
    }
}

function Get-ProjectPickleSyntheticReportValue {
    [CmdletBinding()]
    param(
        [AllowNull()]
        [object]$ColumnName,

        [Parameter(Mandatory)]
        [object]$FormatInfo,

        [Parameter(Mandatory)]
        [int]$RowNumber,

        [Parameter(Mandatory)]
        [int]$ColumnNumber
    )

    $columnNameText =
        [Convert]::ToString($ColumnName)

    $key = (
        [regex]::Replace(
            $columnNameText,
            '[^A-Za-z0-9]',
            ''
        )
    ).ToLowerInvariant()

    if ($FormatInfo.Kind -eq "Date") {
        $baseDate = [datetime]::ParseExact(
            "2026-07-21",
            "yyyy-MM-dd",
            [System.Globalization.CultureInfo]::InvariantCulture
        )

        return $baseDate.AddDays(
            $RowNumber - 1
        )
    }

    if ($FormatInfo.Kind -eq "Boolean") {
        if (($RowNumber % 2) -eq 0) {
            return "N"
        }

        return "Y"
    }

    if ($FormatInfo.Kind -eq "Text") {
        if ($key -match 'remarks') {
            return "SAMPLE REMARK ROW $RowNumber"
        }

        if ($key -match 'species') {
            return "SPC$RowNumber"
        }

        if ($key -match 'status') {
            return "ACTIVE"
        }

        if ($key -match 'crew') {
            return "CREW $RowNumber"
        }

        $readableName = [regex]::Replace(
            $columnNameText,
            '([a-z0-9])([A-Z])',
            '$1 $2'
        )

        if (
            [string]::IsNullOrWhiteSpace(
                $readableName
            )
        ) {
            $readableName =
                "FIELD $ColumnNumber"
        }

        return (
            $readableName.ToUpperInvariant() +
            " $RowNumber"
        )
    }

    if ($key -match 'periodnumber|year') {
        return (
            2025 + $RowNumber
        )
    }

    if ($key -match 'treenumber') {
        return (
            120 + $RowNumber
        )
    }

    if ($key -match 'plotnumber') {
        return (
            7200 + $RowNumber
        )
    }

    if ($key -match 'species|speciescode|spc') {
        return (
            121 + $RowNumber
        )
    }

    if ($key -match 'dbh|idbh') {
        return (
            17 + $RowNumber
        )
    }

    if ($key -match 'height|hgt') {
        return (
            60 + ($RowNumber * 5)
        )
    }

    if ($key -match 'ratio') {
        return (
            40 + ($RowNumber * 5)
        )
    }

    if ($key -match 'age') {
        return (
            30 + ($RowNumber * 2)
        )
    }

    if ($key -match 'northing') {
        return (
            3900000 +
            ($RowNumber * 100)
        )
    }

    if ($key -match 'easting') {
        return (
            450000 +
            ($RowNumber * 100)
        )
    }

    if ($key -match 'zone') {
        return 13
    }

    if ($key -match 'count') {
        return (
            $RowNumber * 10
        )
    }

    if (
        $key -match
        'severity|problem|class|history|minorplot|status'
    ) {
        return $RowNumber
    }

    return (
        ($ColumnNumber * 10) +
        $RowNumber
    )
}

function Format-ProjectPickleSyntheticReportValue {
    [CmdletBinding()]
    param(
        [AllowNull()]
        [object]$Value,

        [Parameter(Mandatory)]
        [object]$FormatInfo
    )

    $width = [int]$FormatInfo.Width

    if ($width -le 0) {
        $width = 1
    }

    $rendered = ""

    if ($FormatInfo.Kind -eq "Composite") {
        try {
            $rendered = [string]::Format(
                [System.Globalization.CultureInfo]::InvariantCulture,
                [string]$FormatInfo.RawFormat,
                $Value
            )
        }
        catch {
            $rendered = [string]::Format(
                [System.Globalization.CultureInfo]::InvariantCulture,
                "{0}",
                $Value
            )
        }
    }
    elseif ($FormatInfo.Kind -eq "Date") {
        if ($Value -is [datetime]) {
            $rendered =
                $Value.ToString(
                    "MM/dd/yyyy",
                    [System.Globalization.CultureInfo]::InvariantCulture
                )
        }
        else {
            $rendered =
                [Convert]::ToString($Value)
        }
    }
    else {
        $rendered =
            [Convert]::ToString($Value)
    }

    # A row of # characters makes an overflow obvious instead of
    # silently allowing one field to shift every field after it.
    if ($rendered.Length -gt $width) {
        return (
            "#" * $width
        )
    }

    if ($rendered.Length -lt $width) {
        if ($FormatInfo.Alignment -eq "Left") {
            $rendered =
                $rendered.PadRight($width)
        }
        else {
            $rendered =
                $rendered.PadLeft($width)
        }
    }

    return $rendered
}

function New-ProjectPickleSyntheticReportPackage {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [object]$Layout,

        [ValidateRange(1, 20)]
        [int]$RowCount = 3
    )

    $columns = @(
        $Layout.Columns |
            Where-Object {
                $null -ne $_
            }
    )

    if ($columns.Count -eq 0) {
        throw (
            "The selected report has no ReportColumns rows."
        )
    }

    $headerLines =
        New-Object System.Collections.Generic.List[string]

    foreach ($headerLine in @($Layout.HeaderLines)) {
        if ($null -eq $headerLine) {
            [void]$headerLines.Add("")
        }
        else {
            [void]$headerLines.Add(
                [string]$headerLine
            )
        }
    }

    if ($headerLines.Count -eq 0) {
        throw (
            "The selected report has no ReportHeaders text."
        )
    }

    $layoutName =
        [Convert]::ToString(
            $Layout.DisplayName
        ).Trim()

    if ([string]::IsNullOrWhiteSpace($layoutName)) {
        $layoutName =
            [Convert]::ToString(
                $Layout.Title
            ).Trim()
    }

    if ([string]::IsNullOrWhiteSpace($layoutName)) {
        $layoutName =
            [Convert]::ToString(
                $Layout.Section
            ).Trim()
    }

    if ([string]::IsNullOrWhiteSpace($layoutName)) {
        $layoutName =
            "Selected report"
    }

    $warnings =
        New-Object System.Collections.Generic.List[string]

    $columnDetails =
        New-Object System.Collections.Generic.List[object]

    for (
        $columnIndex = 0;
        $columnIndex -lt $columns.Count;
        $columnIndex++
    ) {
        $column = $columns[$columnIndex]
        $orderNumber = $columnIndex + 1

        $tableName =
            [Convert]::ToString(
                $column.TableName
            ).Trim()

        $columnName =
            [Convert]::ToString(
                $column.ColumnName
            ).Trim()

        $columnId =
            [Convert]::ToString(
                $column.ColumnID
            ).Trim()

        $fieldFormat =
            [Convert]::ToString(
                $column.FieldFormat
            ).Trim()

        $formatInfo =
            Get-ProjectPickleSyntheticReportFormatInfo `
                -FieldFormat $fieldFormat `
                -ColumnName $columnName

        if (
            -not [string]::IsNullOrWhiteSpace(
                $formatInfo.Warning
            )
        ) {
            [void]$warnings.Add(
                (
                    "Column {0}, {1}.{2}: {3}" -f
                    $orderNumber,
                    $tableName,
                    $columnName,
                    $formatInfo.Warning
                )
            )
        }

        $sampleValues =
            New-Object System.Collections.Generic.List[object]

        for (
            $rowNumber = 1;
            $rowNumber -le $RowCount;
            $rowNumber++
        ) {
            [void]$sampleValues.Add(
                (
                    Get-ProjectPickleSyntheticReportValue `
                        -ColumnName $columnName `
                        -FormatInfo $formatInfo `
                        -RowNumber $rowNumber `
                        -ColumnNumber $orderNumber
                )
            )
        }

        [void]$columnDetails.Add(
            [pscustomobject]@{
                OrderNumber = $orderNumber
                TableName = $tableName
                ColumnName = $columnName
                ColumnID = $columnId
                FieldFormat = $fieldFormat
                FormatInfo = $formatInfo
                SampleValues = @(
                    $sampleValues.ToArray()
                )
            }
        )
    }

    $headerWidth = 0

    foreach ($headerLine in $headerLines) {
        if ($headerLine.Length -gt $headerWidth) {
            $headerWidth =
                $headerLine.Length
        }
    }

    $dataRows =
        New-Object System.Collections.Generic.List[string]

    $dataWidth = 0

    for (
        $rowIndex = 0;
        $rowIndex -lt $RowCount;
        $rowIndex++
    ) {
        $rowBuilder =
            New-Object System.Text.StringBuilder

        foreach ($detail in $columnDetails) {
            $formattedValue =
                Format-ProjectPickleSyntheticReportValue `
                    -Value $detail.SampleValues[$rowIndex] `
                    -FormatInfo $detail.FormatInfo

            if (
                $formattedValue -match '^#+$'
            ) {
                [void]$warnings.Add(
                    (
                        "Column {0}, {1}.{2}: the fake value did not " +
                        "fit its FieldFormat width of {3}." -f
                        $detail.OrderNumber,
                        $detail.TableName,
                        $detail.ColumnName,
                        $detail.FormatInfo.Width
                    )
                )
            }

            [void]$rowBuilder.Append(
                $formattedValue
            )
        }

        $rowText =
            $rowBuilder.ToString()

        if ($rowText.Length -gt $dataWidth) {
            $dataWidth =
                $rowText.Length
        }

        # Pad a short synthetic row to the exact header width so the
        # right edge is easy to compare visually. Do not truncate a row
        # that is wider than the header.
        if (
            $headerWidth -gt 0 -and
            $rowText.Length -lt $headerWidth
        ) {
            $rowText =
                $rowText.PadRight(
                    $headerWidth
                )
        }

        [void]$dataRows.Add(
            $rowText
        )
    }

    if (
        $headerWidth -gt 0 -and
        $dataWidth -ne $headerWidth
    ) {
        [void]$warnings.Add(
            (
                "The exact ReportHeaders width is {0} characters, " +
                "while the combined FieldFormat widths total {1}. " +
                "Review field widths, separators, and the Remarks width." -f
                $headerWidth,
                $dataWidth
            )
        )
    }

    $reportLines =
        New-Object System.Collections.Generic.List[string]

    [void]$reportLines.Add(
        "SYNTHETIC TEST DATA ONLY - NO DATABASE VALUES WERE READ"
    )

    [void]$reportLines.Add(
        "Layout: $layoutName"
    )

    [void]$reportLines.Add("")

    foreach ($headerLine in $headerLines) {
        [void]$reportLines.Add(
            $headerLine
        )
    }

    foreach ($dataRow in $dataRows) {
        [void]$reportLines.Add(
            $dataRow
        )
    }

    $fieldMapLines =
        New-Object System.Collections.Generic.List[string]

    [void]$fieldMapLines.Add(
        "SYNTHETIC FIELD MAP"
    )

    [void]$fieldMapLines.Add(
        "This confirms the report order and the ColumnID used for each data field."
    )

    [void]$fieldMapLines.Add("")

    [void]$fieldMapLines.Add(
        (
            "{0,3}  {1,-42}  {2,-38}  {3,5}  {4,-18}  {5}" -f
            "No.",
            "App table and field",
            "ColumnID",
            "Width",
            "FieldFormat",
            "Fake row 1 value"
        )
    )

    [void]$fieldMapLines.Add(
        (
            "-" * 145
        )
    )

    foreach ($detail in $columnDetails) {
        $displayColumnId =
            [string]$detail.ColumnID

        if (
            [string]::IsNullOrWhiteSpace(
                $displayColumnId
            )
        ) {
            $displayColumnId =
                "(resolved during Build)"
        }

        $sampleDisplay =
            Format-ProjectPickleSyntheticReportValue `
                -Value $detail.SampleValues[0] `
                -FormatInfo $detail.FormatInfo

        $fieldIdentity = (
            "{0}.{1}" -f
            $detail.TableName,
            $detail.ColumnName
        )

        [void]$fieldMapLines.Add(
            (
                "{0,3}  {1,-42}  {2,-38}  {3,5}  {4,-18}  {5}" -f
                $detail.OrderNumber,
                $fieldIdentity,
                $displayColumnId,
                $detail.FormatInfo.Width,
                $detail.FieldFormat,
                $sampleDisplay.Trim()
            )
        )
    }

    $uniqueWarnings = @(
        $warnings.ToArray() |
            Sort-Object -Unique
    )

    if ($uniqueWarnings.Count -gt 0) {
        [void]$fieldMapLines.Add("")
        [void]$fieldMapLines.Add(
            "PREVIEW WARNINGS"
        )

        foreach ($warning in $uniqueWarnings) {
            [void]$fieldMapLines.Add(
                "- $warning"
            )
        }
    }

    $summaryText = (
        "Header width: {0} | Combined FieldFormat width: {1} | " +
        "Fake rows: {2} | Warnings: {3}" -f
        $headerWidth,
        $dataWidth,
        $RowCount,
        $uniqueWarnings.Count
    )

    return [pscustomobject]@{
        LayoutName = $layoutName

        ReportText = [string]::Join(
            "`r`n",
            [string[]]$reportLines.ToArray()
        )

        FieldMapText = [string]::Join(
            "`r`n",
            [string[]]$fieldMapLines.ToArray()
        )

        Warnings = [string[]]$uniqueWarnings
        SummaryText = $summaryText
        HeaderWidth = $headerWidth
        DataWidth = $dataWidth
    }
}

function Show-ProjectPickleSyntheticReportPreview {
    [CmdletBinding()]
    param(
        [System.Windows.Forms.IWin32Window]$Owner,

        [Parameter(Mandatory)]
        [object]$PreviewPackage
    )

    $dialog =
        New-Object System.Windows.Forms.Form

    $dialog.Text = (
        "Synthetic report preview - {0}" -f
        $PreviewPackage.LayoutName
    )

    $dialog.ClientSize =
        New-Object System.Drawing.Size(
            1100,
            690
        )

    $dialog.StartPosition =
        [System.Windows.Forms.FormStartPosition]::CenterParent

    $dialog.MinimizeBox = $false
    $dialog.ShowInTaskbar = $false

    $dialog.FormBorderStyle =
        [System.Windows.Forms.FormBorderStyle]::Sizable

    $tabControl =
        New-Object System.Windows.Forms.TabControl

    $tabControl.SetBounds(
        15,
        15,
        1070,
        555
    )

    $tabControl.Anchor =
        "Top,Bottom,Left,Right"

    $printedLayoutTab =
        New-Object System.Windows.Forms.TabPage

    $printedLayoutTab.Text =
        "Printed layout"

    $fieldMapTab =
        New-Object System.Windows.Forms.TabPage

    $fieldMapTab.Text =
        "Field map and ColumnIDs"

    $previewTextBox =
        New-Object System.Windows.Forms.TextBox

    $previewTextBox.Dock =
        [System.Windows.Forms.DockStyle]::Fill

    $previewTextBox.Multiline = $true
    $previewTextBox.ReadOnly = $true
    $previewTextBox.WordWrap = $false

    $previewTextBox.ScrollBars =
        [System.Windows.Forms.ScrollBars]::Both

    $previewTextBox.BackColor =
        [System.Drawing.SystemColors]::Window

    $previewTextBox.Text =
        [string]$PreviewPackage.ReportText

    $fieldMapTextBox =
        New-Object System.Windows.Forms.TextBox

    $fieldMapTextBox.Dock =
        [System.Windows.Forms.DockStyle]::Fill

    $fieldMapTextBox.Multiline = $true
    $fieldMapTextBox.ReadOnly = $true
    $fieldMapTextBox.WordWrap = $false

    $fieldMapTextBox.ScrollBars =
        [System.Windows.Forms.ScrollBars]::Both

    $fieldMapTextBox.BackColor =
        [System.Drawing.SystemColors]::Window

    $fieldMapTextBox.Text =
        [string]$PreviewPackage.FieldMapText

    $previewFont = $null

    try {
        $previewFont =
            New-Object System.Drawing.Font(
                "Consolas",
                9,
                [System.Drawing.FontStyle]::Regular
            )
    }
    catch {
        $previewFont =
            New-Object System.Drawing.Font(
                "Courier New",
                9,
                [System.Drawing.FontStyle]::Regular
            )
    }

    $previewTextBox.Font =
        $previewFont

    $fieldMapTextBox.Font =
        $previewFont

    [void]$printedLayoutTab.Controls.Add(
        $previewTextBox
    )

    [void]$fieldMapTab.Controls.Add(
        $fieldMapTextBox
    )

    [void]$tabControl.TabPages.Add(
        $printedLayoutTab
    )

    [void]$tabControl.TabPages.Add(
        $fieldMapTab
    )

    $statusLabel =
        New-Object System.Windows.Forms.Label

    $statusLabel.SetBounds(
        15,
        582,
        735,
        72
    )

    $statusLabel.Anchor =
        "Left,Right,Bottom"

    $statusLabel.AutoSize = $false

    $statusLabel.Text = (
        "This uses fake values and the current unsaved Reports-tab " +
        "layout. It does not run Access or change a database.`r`n" +
        $PreviewPackage.SummaryText
    )

    if ($PreviewPackage.Warnings.Count -gt 0) {
        $statusLabel.Text += (
            "`r`nReview the Field map and ColumnIDs tab for preview warnings."
        )

        $statusLabel.ForeColor =
            [System.Drawing.Color]::Firebrick
    }

    $printerPreviewButton =
        New-Object System.Windows.Forms.Button

    $printerPreviewButton.SetBounds(
        765,
        600,
        120,
        34
    )

    $printerPreviewButton.Anchor =
        "Right,Bottom"

    $printerPreviewButton.Text =
        "Print preview"

    $printButton =
        New-Object System.Windows.Forms.Button

    $printButton.SetBounds(
        895,
        600,
        85,
        34
    )

    $printButton.Anchor =
        "Right,Bottom"

    $printButton.Text =
        "Print"

    $closeButton =
        New-Object System.Windows.Forms.Button

    $closeButton.SetBounds(
        990,
        600,
        95,
        34
    )

    $closeButton.Anchor =
        "Right,Bottom"

    $closeButton.Text =
        "Close"

    $closeButton.DialogResult =
        [System.Windows.Forms.DialogResult]::Cancel

    $dialog.CancelButton =
        $closeButton

    $printLines = [string[]][regex]::Split(
        [string]$PreviewPackage.ReportText,
        "`r`n|`n|`r"
    )

    $maximumPrintLength = 0

    foreach ($printLine in $printLines) {
        if ($printLine.Length -gt $maximumPrintLength) {
            $maximumPrintLength =
                $printLine.Length
        }
    }

    $printFontSize = [single]7.0

    if ($maximumPrintLength -gt 200) {
        $printFontSize = [single]5.5
    }
    elseif ($maximumPrintLength -gt 170) {
        $printFontSize = [single]6.0
    }

    $printFont = $null

    try {
        $printFont =
            New-Object System.Drawing.Font(
                "Courier New",
                $printFontSize,
                [System.Drawing.FontStyle]::Regular
            )
    }
    catch {
        $printFont =
            New-Object System.Drawing.Font(
                "Consolas",
                $printFontSize,
                [System.Drawing.FontStyle]::Regular
            )
    }

    $printDocument =
        New-Object System.Drawing.Printing.PrintDocument

    $printDocument.DocumentName = (
        "Project Pickle synthetic report - {0}" -f
        $PreviewPackage.LayoutName
    )

    $printDocument.DefaultPageSettings.Landscape =
        $true

    $printMargins =
        New-Object System.Drawing.Printing.Margins `
            -ArgumentList 25, 25, 25, 25

    $printDocument.DefaultPageSettings.Margins =
        $printMargins

    $printState = [pscustomobject]@{
        LineIndex = 0
    }

    $printDocument.Add_BeginPrint({
        $printState.LineIndex = 0
    }.GetNewClosure())

    $printDocument.Add_PrintPage({
        param(
            $Sender,
            $EventArgs
        )

        $lineHeight = [single][Math]::Ceiling(
            $printFont.GetHeight(
                $EventArgs.Graphics
            )
        )

        $left =
            [single]$EventArgs.MarginBounds.Left

        $top =
            [single]$EventArgs.MarginBounds.Top

        $bottom =
            [single]$EventArgs.MarginBounds.Bottom

        $y = $top

        while (
            $printState.LineIndex -lt
            $printLines.Count
        ) {
            if (
                ($y + $lineHeight) -gt
                $bottom
            ) {
                break
            }

            $lineToPrint =
                [string]$printLines[
                    $printState.LineIndex
                ]

            $EventArgs.Graphics.DrawString(
                $lineToPrint,
                $printFont,
                [System.Drawing.Brushes]::Black,
                $left,
                $y
            )

            $printState.LineIndex++

            $y += $lineHeight
        }

        $EventArgs.HasMorePages = (
            $printState.LineIndex -lt
            $printLines.Count
        )

        if (-not $EventArgs.HasMorePages) {
            $printState.LineIndex = 0
        }
    }.GetNewClosure())

    $printerPreviewButton.Add_Click({
        $printPreviewDialog = $null

        try {
            $printPreviewDialog =
                New-Object System.Windows.Forms.PrintPreviewDialog

            $printPreviewDialog.Document =
                $printDocument

            $printPreviewDialog.WindowState =
                [System.Windows.Forms.FormWindowState]::Maximized

            $printPreviewDialog.UseAntiAlias =
                $true

            [void]$printPreviewDialog.ShowDialog(
                $dialog
            )
        }
        catch {
            [void][System.Windows.Forms.MessageBox]::Show(
                $dialog,
                (
                    "Print preview could not open:`r`n`r`n" +
                    $_.Exception.Message
                ),
                "Synthetic report print preview",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Error
            )
        }
        finally {
            if ($null -ne $printPreviewDialog) {
                $printPreviewDialog.Dispose()
            }
        }
    }.GetNewClosure())

    $printButton.Add_Click({
        $printDialog = $null

        try {
            $printDialog =
                New-Object System.Windows.Forms.PrintDialog

            $printDialog.Document =
                $printDocument

            $printDialog.UseEXDialog =
                $true

            $printDialog.AllowSomePages =
                $false

            $printResult =
                $printDialog.ShowDialog(
                    $dialog
                )

            if (
                $printResult -eq
                [System.Windows.Forms.DialogResult]::OK
            ) {
                $printDocument.Print()
            }
        }
        catch {
            [void][System.Windows.Forms.MessageBox]::Show(
                $dialog,
                (
                    "The synthetic report could not print:`r`n`r`n" +
                    $_.Exception.Message
                ),
                "Synthetic report printing",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Error
            )
        }
        finally {
            if ($null -ne $printDialog) {
                $printDialog.Dispose()
            }
        }
    }.GetNewClosure())

    [void]$dialog.Controls.Add(
        $tabControl
    )

    [void]$dialog.Controls.Add(
        $statusLabel
    )

    [void]$dialog.Controls.Add(
        $printerPreviewButton
    )

    [void]$dialog.Controls.Add(
        $printButton
    )

    [void]$dialog.Controls.Add(
        $closeButton
    )

    $dialog.Add_Shown({
        $previewTextBox.SelectionStart = 0
        $previewTextBox.SelectionLength = 0
        $previewTextBox.ScrollToCaret()
    }.GetNewClosure())

    try {
        if ($null -ne $Owner) {
            [void]$dialog.ShowDialog(
                $Owner
            )
        }
        else {
            [void]$dialog.ShowDialog()
        }
    }
    finally {
        if ($null -ne $printDocument) {
            $printDocument.Dispose()
        }

        if ($null -ne $printFont) {
            $printFont.Dispose()
        }

        if ($null -ne $previewFont) {
            $previewFont.Dispose()
        }

        $dialog.Dispose()
    }
}

function Get-ProjectPickleReportFieldFormatParts {
    [CmdletBinding()]
    param(
        [AllowNull()]
        [object]$FieldFormat
    )

    $formatText =
        [Convert]::ToString($FieldFormat).Trim()

    $result = [pscustomobject]@{
        Original = $formatText
        Kind = "Unknown"
        Width = 0
        CanEditWidth = $false
        Prefix = ""
        Suffix = ""
        IsNegativeWidth = $false
        Alignment = "Unknown"
        FormatCode = ""
        Explanation = ""
    }

    if ([string]::IsNullOrWhiteSpace($formatText)) {
        $result.Kind = "Blank"
        $result.Explanation = (
            "FieldFormat is blank. Code and whole-number fields " +
            "normally start with {0,8:g0}."
        )

        return $result
    }

    # Composite numeric format examples:
    #
    # {0,8:g0}
    # {0,6:n0}
    # {0,-12}
    $compositeMatch = [regex]::Match(
        $formatText,
        "^(?<Prefix>\s*\{0\s*,\s*)(?<Width>-?\d+)(?<Suffix>\s*(?::\s*[^}]+)?\}\s*)$"
    )

    if ($compositeMatch.Success) {
        $signedWidth =
            [int]$compositeMatch.Groups["Width"].Value

        $formatCodeMatch = [regex]::Match(
            $compositeMatch.Groups["Suffix"].Value,
            ":\s*(?<Code>[^}]+)"
        )

        $formatCode = ""

        if ($formatCodeMatch.Success) {
            $formatCode =
                $formatCodeMatch.Groups["Code"].Value.Trim()
        }

        $formatCodeExplanation = ""

        if (
            [string]::Equals(
                $formatCode,
                "g0",
                [System.StringComparison]::OrdinalIgnoreCase
            )
        ) {
            $formatCodeExplanation = (
                "g0 is the legacy general numeric display normally " +
                "used for code and whole-number fields."
            )
        }
        elseif (
            [string]::Equals(
                $formatCode,
                "n0",
                [System.StringComparison]::OrdinalIgnoreCase
            )
        ) {
            $formatCodeExplanation = (
                "n0 displays a number with thousands separators and " +
                "no displayed decimal places."
            )
        }
        elseif (
            [string]::Equals(
                $formatCode,
                "n1",
                [System.StringComparison]::OrdinalIgnoreCase
            )
        ) {
            $formatCodeExplanation = (
                "n1 displays a number with thousands separators and " +
                "one displayed decimal place."
            )
        }
        elseif (
            [string]::Equals(
                $formatCode,
                "n2",
                [System.StringComparison]::OrdinalIgnoreCase
            )
        ) {
            $formatCodeExplanation = (
                "n2 displays a number with thousands separators and " +
                "two displayed decimal places."
            )
        }
        elseif ([string]::IsNullOrWhiteSpace($formatCode)) {
            $formatCodeExplanation = (
                "No separate numeric format code is present."
            )
        }
        else {
            $formatCodeExplanation = (
                "'$formatCode' is preserved exactly by the width editor."
            )
        }

        $result.Kind = "Composite"
        $result.Width = [Math]::Abs($signedWidth)
        $result.CanEditWidth = $true
        $result.Prefix =
            $compositeMatch.Groups["Prefix"].Value
        $result.Suffix =
            $compositeMatch.Groups["Suffix"].Value
        $result.IsNegativeWidth = ($signedWidth -lt 0)
        $result.Alignment = if ($signedWidth -lt 0) {
            "Left"
        }
        else {
            "Right"
        }
        $result.FormatCode = $formatCode
        $result.Explanation = (
            "The width is $($result.Width) characters and the value is " +
            "$($result.Alignment.ToLowerInvariant())-aligned. " +
            "$formatCodeExplanation Only the width number is changed; " +
            "all other characters are preserved."
        )

        return $result
    }

    # Legacy text format examples:
    #
    # TEXT,41,05
    # TEXT,50,6
    #
    # The first number after TEXT is treated as the printable width.
    # Everything after that width remains unchanged.
    $textMatch = [regex]::Match(
        $formatText,
        "^(?<Prefix>\s*TEXT\s*,\s*)(?<Width>\d+)(?<Suffix>\s*(?:,.*)?)$",
        [System.Text.RegularExpressions.RegexOptions]::IgnoreCase
    )

    if ($textMatch.Success) {
        $result.Kind = "Text"
        $result.Width =
            [int]$textMatch.Groups["Width"].Value
        $result.CanEditWidth = $true
        $result.Prefix =
            $textMatch.Groups["Prefix"].Value
        $result.Suffix =
            $textMatch.Groups["Suffix"].Value
        $result.Alignment = "Left"
        $result.Explanation = (
            "This is a legacy text format. The first number after TEXT " +
            "is the printable width. The remaining text-format settings " +
            "are preserved exactly and are not directly editable here."
        )

        return $result
    }

    if (
        $formatText -match
        "^(?i)\s*DATE(?:\s*,.*)?$"
    ) {
        $result.Kind = "Date"
        $result.Explanation = (
            "This is a legacy date format without a separately editable " +
            "width value. It will be preserved exactly."
        )

        return $result
    }

    $result.Explanation = (
        "Project Pickle does not recognize a safely editable width inside " +
        "this format. The value will be preserved exactly. Use the format " +
        "from a similar existing report field rather than typing over it."
    )

    return $result
}

function Test-ProjectPickleReportNumericFormatNeedsRepair {
    [CmdletBinding()]
    param(
        [AllowNull()]
        [object]$FieldFormat
    )

    $formatText =
        [Convert]::ToString(
            $FieldFormat
        ).Trim()

    # A missing format needs the normal Code/Integer default.
    if ([string]::IsNullOrWhiteSpace($formatText)) {
        return $true
    }

    $formatParts =
        Get-ProjectPickleReportFieldFormatParts `
            -FieldFormat $formatText

    # A complete composite format is already safe.
    #
    # Examples:
    #   {0,8:g0}
    #   {0,-8:g0}
    #   {0,6:n0}
    #   {0,10}
    if (
        $formatParts.CanEditWidth -and
        $formatParts.Kind -eq "Composite"
    ) {
        return $false
    }

    # A bare number means that an older direct grid edit replaced the
    # complete format string.
    #
    # Examples:
    #   6
    #   -10
    if ($formatText -match '^\s*-?\d+\s*$') {
        return $true
    }

    # Anything beginning like a composite format but failing the parser
    # is incomplete or malformed.
    #
    # Examples:
    #   {0,}
    #   {0,:g0}
    #   {0,8:g0
    if ($formatText -match '^\s*\{0\s*,') {
        return $true
    }

    # Do not automatically replace an unrelated legacy format that the
    # parser does not recognize.
    return $false
}
function Set-ProjectPickleReportFieldFormatWidth {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string]$FieldFormat,

        [Parameter(Mandatory)]
        [ValidateRange(1, 255)]
        [int]$Width,

        [ValidateSet(
            "Preserve",
            "Right",
            "Left"
        )]
        [string]$Alignment = "Preserve"
    )

    $parts =
        Get-ProjectPickleReportFieldFormatParts `
            -FieldFormat $FieldFormat

    if (-not $parts.CanEditWidth) {
        throw (
            "The width cannot be safely edited in FieldFormat " +
            "'$FieldFormat'."
        )
    }

    $newWidthText =
        [Convert]::ToString($Width)

    if ($parts.Kind -eq "Composite") {
        switch ($Alignment) {
            "Left" {
                $newWidthText =
                    "-" + [Convert]::ToString($Width)
            }

            "Right" {
                $newWidthText =
                    [Convert]::ToString($Width)
            }

            default {
                if ($parts.IsNegativeWidth) {
                    $newWidthText =
                        "-" + [Convert]::ToString($Width)
                }
                else {
                    $newWidthText =
                        [Convert]::ToString($Width)
                }
            }
        }
    }

    # Reconstruct the complete format by concatenating the original
    # prefix, the new signed width, and the original suffix.
    $result =
        [string]$parts.Prefix +
        $newWidthText +
        [string]$parts.Suffix

    # Never return a malformed or incomplete format.
    $verification =
        Get-ProjectPickleReportFieldFormatParts `
            -FieldFormat $result

    if (-not $verification.CanEditWidth) {
        throw (
            "Project Pickle created an invalid FieldFormat '$result'. " +
            "The original value was '$FieldFormat'. No change was saved."
        )
    }

    if ($verification.Width -ne $Width) {
        throw (
            "Project Pickle could not verify the requested width of " +
            "$Width in FieldFormat '$result'. No change was saved."
        )
    }

    return $result
}

function Show-ProjectPickleReportFormatAndTallyDialog {
    [CmdletBinding()]
    param(
        [System.Windows.Forms.IWin32Window]$Owner,

        [string]$FieldName = "",

        [string]$Category = "",

        [string]$DataType = "",

        [AllowNull()]
        [object]$CurrentFieldFormat,

        [AllowNull()]
        [object]$CurrentTallyFormat
    )

    $originalFieldFormat =
        [Convert]::ToString(
            $CurrentFieldFormat
        ).Trim()

    $categoryText =
        [Convert]::ToString($Category).Trim()

    $dataTypeText =
        [Convert]::ToString($DataType).Trim()

    $isCodeField = [string]::Equals(
        $categoryText,
        "Code",
        [System.StringComparison]::OrdinalIgnoreCase
    )

    $isWholeNumberField = (
        $dataTypeText -match
        "^(?i)(byte|short|integer|long|long integer|int16|int32|int64)$"
    )

        $workingFieldFormat =
        $originalFieldFormat

    $formatBeforeAutomaticRepair =
        $workingFieldFormat

    $automaticDefaultApplied =
        $false

    $automaticRepairApplied =
        $false

    $isNumericCodeOrWholeNumber = (
        $isCodeField -or
        $isWholeNumberField
    )

    $formatNeedsAutomaticRepair =
        $false

    if ($isNumericCodeOrWholeNumber) {
        $formatNeedsAutomaticRepair =
            Test-ProjectPickleReportNumericFormatNeedsRepair `
                -FieldFormat $workingFieldFormat
    }

    if ($formatNeedsAutomaticRepair) {
        # Use a literal string. Do not build this as
        # "{0,$width:g0}", because PowerShell can interpret the colon
        # as part of the variable reference.
        $workingFieldFormat =
            "{0,8:g0}"

        if (
            [string]::IsNullOrWhiteSpace(
                $formatBeforeAutomaticRepair
            )
        ) {
            $automaticDefaultApplied =
                $true
        }
        else {
            $automaticRepairApplied =
                $true
        }
    }

    $formatParts =
        Get-ProjectPickleReportFieldFormatParts `
            -FieldFormat $workingFieldFormat

    $currentTallyText =
        [Convert]::ToString(
            $CurrentTallyFormat
        )

    $dialog =
        New-Object System.Windows.Forms.Form

    $dialog.Text =
        "Edit report field width and tally format"

    $dialog.ClientSize =
        New-Object System.Drawing.Size(
            760,
            650
        )

    $dialog.FormBorderStyle =
        [System.Windows.Forms.FormBorderStyle]::FixedDialog

    $dialog.MaximizeBox = $false
    $dialog.MinimizeBox = $false
    $dialog.ShowInTaskbar = $false

    $dialog.StartPosition =
        [System.Windows.Forms.FormStartPosition]::CenterParent

    $instructionsLabel =
        New-Object System.Windows.Forms.Label

    $instructionsLabel.SetBounds(
        15,
        12,
        730,
        38
    )

    $instructionsLabel.Text = (
        "Change only the field width. Project Pickle preserves the rest " +
        "of FieldFormat so a value such as {0,8:g0} cannot accidentally " +
        "be replaced by only the number 6."
    )

    $fieldCaptionLabel =
        New-Object System.Windows.Forms.Label

    $fieldCaptionLabel.SetBounds(
        15,
        55,
        85,
        22
    )

    $fieldCaptionLabel.Text =
        "Field:"

    $fieldValueLabel =
        New-Object System.Windows.Forms.Label

    $fieldValueLabel.SetBounds(
        105,
        55,
        640,
        22
    )

    $fieldValueLabel.AutoEllipsis = $true
    $fieldValueLabel.Text = if (
        [string]::IsNullOrWhiteSpace($FieldName)
    ) {
        "(unknown field)"
    }
    else {
        $FieldName
    }

    $metadataLabel =
        New-Object System.Windows.Forms.Label

    $metadataLabel.SetBounds(
        105,
        78,
        640,
        22
    )

    $metadataLabel.Text = (
        "Category: {0}    Data type: {1}" -f
        $(if (
            [string]::IsNullOrWhiteSpace($categoryText)
        ) {
            "(not detected)"
        }
        else {
            $categoryText
        }),
        $(if (
            [string]::IsNullOrWhiteSpace($dataTypeText)
        ) {
            "(not detected)"
        }
        else {
            $dataTypeText
        })
    )

    $currentFormatLabel =
        New-Object System.Windows.Forms.Label

    $currentFormatLabel.SetBounds(
        15,
        108,
        150,
        22
    )

    $currentFormatLabel.Text =
        "Current FieldFormat:"

    $currentFormatBox =
        New-Object System.Windows.Forms.TextBox

    $currentFormatBox.SetBounds(
        165,
        105,
        580,
        27
    )

    $currentFormatBox.ReadOnly = $true
    $currentFormatBox.Text =
        $workingFieldFormat

    $defaultAppliedLabel =
        New-Object System.Windows.Forms.Label

    $defaultAppliedLabel.SetBounds(
        165,
        135,
        580,
        22
    )

        if ($automaticRepairApplied) {
        $shownOldFormat =
            $formatBeforeAutomaticRepair

        if ([string]::IsNullOrWhiteSpace($shownOldFormat)) {
            $shownOldFormat =
                "(blank)"
        }

        $defaultAppliedLabel.Text = (
            "Recovered malformed FieldFormat '$shownOldFormat' " +
            "as {0,8:g0}. Review the width and alignment, then click OK."
        )

        $defaultAppliedLabel.ForeColor =
            [System.Drawing.Color]::DarkOrange
    }
    elseif ($automaticDefaultApplied) {
        $defaultAppliedLabel.Text = (
            "Automatic default applied: Code and whole-number fields " +
            "start at {0,8:g0}."
        )

        $defaultAppliedLabel.ForeColor =
            [System.Drawing.Color]::DarkGreen
    }
    else {
        $defaultAppliedLabel.Text = ""
    }

    $widthLabel =
        New-Object System.Windows.Forms.Label

    $widthLabel.SetBounds(
        15,
        168,
        145,
        25
    )

    $widthLabel.Text =
        "Width in characters:"

    $widthInput =
        New-Object System.Windows.Forms.NumericUpDown

    $widthInput.SetBounds(
        165,
        164,
        100,
        27
    )

    $widthInput.Minimum = 1
    $widthInput.Maximum = 255

    if (
        $formatParts.CanEditWidth -and
        $formatParts.Width -gt 0
    ) {
        $widthInput.Value =
            [decimal]$formatParts.Width
    }
    else {
        $widthInput.Value = 8
        $widthInput.Enabled = $false
    }

        # ---------------------------------------------------------------
    # Composite-format alignment.
    #
    # Users enter a positive width and choose where unused spaces go.
    # Project Pickle adds or removes the minus sign automatically.
    # ---------------------------------------------------------------

    $alignmentLabel =
        New-Object System.Windows.Forms.Label

    $alignmentLabel.SetBounds(
        290,
        168,
        85,
        25
    )

    $alignmentLabel.Text =
        "Alignment:"

    $alignmentBox =
        New-Object System.Windows.Forms.ComboBox

    $alignmentBox.SetBounds(
        375,
        164,
        370,
        27
    )

    $alignmentBox.DropDownStyle =
        [System.Windows.Forms.ComboBoxStyle]::DropDownList

    [void]$alignmentBox.Items.Add(
        "Right aligned - unused spaces before the value"
    )

    [void]$alignmentBox.Items.Add(
        "Left aligned - unused spaces after the value"
    )

    if ($formatParts.Kind -eq "Composite") {
        $alignmentBox.Enabled = $true

        if ($formatParts.IsNegativeWidth) {
            $alignmentBox.SelectedIndex = 1
        }
        else {
            $alignmentBox.SelectedIndex = 0
        }
    }
    elseif ($formatParts.Kind -eq "Text") {
        # Legacy TEXT formats are already left-aligned.
        $alignmentBox.SelectedIndex = 1
        $alignmentBox.Enabled = $false
    }
    else {
        $alignmentBox.SelectedIndex = 0
        $alignmentBox.Enabled = $false
    }

    $resultFormatLabel =
        New-Object System.Windows.Forms.Label

    $resultFormatLabel.SetBounds(
        15,
        205,
        145,
        22
    )

    $resultFormatLabel.Text =
        "Resulting format:"

    $resultFormatBox =
        New-Object System.Windows.Forms.TextBox

    $resultFormatBox.SetBounds(
        165,
        201,
        580,
        27
    )

    $resultFormatBox.ReadOnly = $true
    $resultFormatBox.Text =
        $workingFieldFormat

    $formatExplanationLabel =
        New-Object System.Windows.Forms.Label

    $formatExplanationLabel.SetBounds(
        15,
        238,
        730,
        58
    )

    $formatExplanationLabel.AutoSize = $false
    $formatExplanationLabel.Text =
        $formatParts.Explanation

    $widthEffectLabel =
        New-Object System.Windows.Forms.Label

    $widthEffectLabel.SetBounds(
        15,
        299,
        730,
        38
    )

    $widthEffectLabel.AutoSize = $false
    $widthEffectLabel.ForeColor =
        [System.Drawing.Color]::DarkSlateBlue

    $tallyGroup =
        New-Object System.Windows.Forms.GroupBox

    $tallyGroup.SetBounds(
        15,
        340,
        730,
        245
    )

    $tallyGroup.Text =
        "TallyFormat - optional legacy tally/write-in mask"

    $tallyModeLabel =
        New-Object System.Windows.Forms.Label

    $tallyModeLabel.SetBounds(
        12,
        28,
        100,
        22
    )

    $tallyModeLabel.Text =
        "Tally choice:"

    $tallyModeBox =
        New-Object System.Windows.Forms.ComboBox

    $tallyModeBox.SetBounds(
        115,
        24,
        595,
        27
    )

    $tallyModeBox.DropDownStyle =
        [System.Windows.Forms.ComboBoxStyle]::DropDownList

    foreach (
        $tallyOption in @(
            "Keep current exactly",
            "No tally guide - blank",
            "One separate slot: _",
            "Two separate slots: _ _",
            "Three separate slots: _ _ _",
            "Continuous underline",
            "Advanced exact mask"
        )
    ) {
        [void]$tallyModeBox.Items.Add(
            $tallyOption
        )
    }

    $tallyPreviewLabel =
        New-Object System.Windows.Forms.Label

    $tallyPreviewLabel.SetBounds(
        12,
        63,
        100,
        22
    )

    $tallyPreviewLabel.Text =
        "Result:"

    $tallyPreviewBox =
        New-Object System.Windows.Forms.TextBox

    $tallyPreviewBox.SetBounds(
        115,
        59,
        595,
        27
    )

    $tallyPreviewBox.ReadOnly = $true

    $continuousWidthLabel =
        New-Object System.Windows.Forms.Label

    $continuousWidthLabel.SetBounds(
        115,
        98,
        205,
        22
    )

    $continuousWidthLabel.Text =
        "Continuous underline length:"

    $continuousWidthInput =
        New-Object System.Windows.Forms.NumericUpDown

    $continuousWidthInput.SetBounds(
        325,
        94,
        90,
        27
    )

    $continuousWidthInput.Minimum = 1
    $continuousWidthInput.Maximum = 100
    $continuousWidthInput.Value = 8
    $continuousWidthInput.Enabled = $false

    $advancedMaskLabel =
        New-Object System.Windows.Forms.Label

    $advancedMaskLabel.SetBounds(
        115,
        132,
        180,
        22
    )

    $advancedMaskLabel.Text =
        "Advanced exact mask:"

    $advancedMaskBox =
        New-Object System.Windows.Forms.TextBox

    $advancedMaskBox.SetBounds(
        295,
        128,
        415,
        27
    )

    $advancedMaskBox.Text =
        $currentTallyText

    $advancedMaskBox.Enabled = $false

    $tallyExplanationLabel =
        New-Object System.Windows.Forms.Label

    $tallyExplanationLabel.SetBounds(
        12,
        166,
        698,
        66
    )

    $tallyExplanationLabel.AutoSize = $false

    $tallyExplanationLabel.Text = (
        "TallyFormat does not position the normal data value. " +
        "It is a separate legacy visual mask: '_' is one tally/write-in " +
        "position, '_ _' is two separate positions, and a continuous " +
        "string of underscores is one continuous line. Leave existing " +
        "template values unchanged unless the tally output must change."
    )

    $okButton =
        New-Object System.Windows.Forms.Button

    $okButton.SetBounds(
        555,
        602,
        90,
        32
    )

    $okButton.Text = "OK"

    $cancelButton =
        New-Object System.Windows.Forms.Button

    $cancelButton.SetBounds(
        655,
        602,
        90,
        32
    )

    $cancelButton.Text = "Cancel"

    $cancelButton.DialogResult =
        [System.Windows.Forms.DialogResult]::Cancel

    $dialog.AcceptButton = $okButton
    $dialog.CancelButton = $cancelButton

        $updateWidthResult = {
        if (-not $formatParts.CanEditWidth) {
            $resultFormatBox.Text =
                $workingFieldFormat

            $widthEffectLabel.Text = (
                "This format does not contain a width that Project " +
                "Pickle can safely change."
            )

            return
        }

        $newWidth =
            [int]$widthInput.Value

        $selectedAlignment =
            "Preserve"

        if ($formatParts.Kind -eq "Composite") {
            if ($alignmentBox.SelectedIndex -eq 1) {
                $selectedAlignment =
                    "Left"
            }
            else {
                $selectedAlignment =
                    "Right"
            }
        }

        try {
            $resultFormatBox.Text =
                Set-ProjectPickleReportFieldFormatWidth `
                    -FieldFormat $workingFieldFormat `
                    -Width $newWidth `
                    -Alignment $selectedAlignment
        }
        catch {
            $resultFormatBox.Text =
                $workingFieldFormat
        }

        $difference =
            $newWidth -
            [int]$formatParts.Width

        $alignmentExplanation = ""

        if ($formatParts.Kind -eq "Composite") {
            if ($selectedAlignment -eq "Left") {
                $alignmentExplanation = (
                    "Left alignment places unused spaces after the " +
                    "value, creating separation before the next field."
                )
            }
            else {
                $alignmentExplanation = (
                    "Right alignment places unused spaces before the " +
                    "value, so the value can touch the next field."
                )
            }
        }
        elseif ($formatParts.Kind -eq "Text") {
            $alignmentExplanation = (
                "Legacy text values are left-aligned."
            )
        }

        $widthExplanation = ""

        if ($difference -eq 0) {
            $widthExplanation = (
                "The field width is unchanged."
            )
        }
        elseif ($difference -lt 0) {
            $charactersRemoved =
                [Math]::Abs($difference)

            $widthExplanation = (
                "The field is $charactersRemoved character(s) narrower; " +
                "later fields begin that many positions earlier."
            )
        }
        else {
            $widthExplanation = (
                "The field is $difference character(s) wider; " +
                "later fields begin that many positions later."
            )
        }

        $widthEffectLabel.Text = (
            $alignmentExplanation +
            " " +
            $widthExplanation
        )
    }.GetNewClosure()

    $getSelectedTallyResult = {
        switch ([int]$tallyModeBox.SelectedIndex) {
            0 {
                return $currentTallyText
            }

            1 {
                return ""
            }

            2 {
                return "_"
            }

            3 {
                return "_ _"
            }

            4 {
                return "_ _ _"
            }

            5 {
                return (
                    "_" *
                    [int]$continuousWidthInput.Value
                )
            }

            6 {
                return [string]$advancedMaskBox.Text
            }

            default {
                return $currentTallyText
            }
        }
    }.GetNewClosure()

    $updateTallyResult = {
        $continuousWidthInput.Enabled = (
            $tallyModeBox.SelectedIndex -eq 5
        )

        $advancedMaskBox.Enabled = (
            $tallyModeBox.SelectedIndex -eq 6
        )

        $tallyResult =
            & $getSelectedTallyResult

        if ([string]::IsNullOrEmpty($tallyResult)) {
            $tallyPreviewBox.Text =
                "(blank)"
        }
        else {
            $tallyPreviewBox.Text =
                $tallyResult
        }
    }.GetNewClosure()

    $showFormatWarning = {
        param(
            [string]$Message
        )

        [void][System.Windows.Forms.MessageBox]::Show(
            $dialog,
            $Message,
            "Edit report field width and tally format",
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Warning
        )
    }.GetNewClosure()

    $widthInput.Add_ValueChanged({
        & $updateWidthResult
    }.GetNewClosure())

    $alignmentBox.Add_SelectedIndexChanged({
        & $updateWidthResult
    }.GetNewClosure())

    $tallyModeBox.Add_SelectedIndexChanged({
        & $updateTallyResult
    }.GetNewClosure())

    $continuousWidthInput.Add_ValueChanged({
        & $updateTallyResult
    }.GetNewClosure())

    $advancedMaskBox.Add_TextChanged({
        & $updateTallyResult
    }.GetNewClosure())

    $tallyModeBox.SelectedIndex = 0

    & $updateWidthResult
    & $updateTallyResult

    $okButton.Add_Click({
        $newFieldFormat =
            [Convert]::ToString(
                $resultFormatBox.Text
            ).Trim()

        if (
            [string]::IsNullOrWhiteSpace(
                $newFieldFormat
            )
        ) {
            & $showFormatWarning (
                "FieldFormat cannot be blank. For a Code field, use " +
                "{0,8:g0}. For another field type, use the format from " +
                "a similar existing report field."
            )

            return
        }

        $newTallyFormat =
            [Convert]::ToString(
                (& $getSelectedTallyResult)
            )

        if (
            $newTallyFormat.Contains("`r") -or
            $newTallyFormat.Contains("`n") -or
            $newTallyFormat.Contains("`t")
        ) {
            & $showFormatWarning (
                "TallyFormat must be one line and cannot contain tabs."
            )

            return
        }

        foreach (
            $character in
            $newTallyFormat.ToCharArray()
        ) {
            $characterCode =
                [int][char]$character

            if (
                $characterCode -lt 32 -or
                $characterCode -gt 126
            ) {
                & $showFormatWarning (
                    "TallyFormat must use printable ASCII characters."
                )

                return
            }
        }

        $dialog.Tag = [pscustomobject]@{
            FieldFormat = $newFieldFormat
            TallyFormat = $newTallyFormat
        }

        $dialog.DialogResult =
            [System.Windows.Forms.DialogResult]::OK

        $dialog.Close()
    }.GetNewClosure())

    [void]$tallyGroup.Controls.Add(
        $tallyModeLabel
    )
    [void]$tallyGroup.Controls.Add(
        $tallyModeBox
    )
    [void]$tallyGroup.Controls.Add(
        $tallyPreviewLabel
    )
    [void]$tallyGroup.Controls.Add(
        $tallyPreviewBox
    )
    [void]$tallyGroup.Controls.Add(
        $continuousWidthLabel
    )
    [void]$tallyGroup.Controls.Add(
        $continuousWidthInput
    )
    [void]$tallyGroup.Controls.Add(
        $advancedMaskLabel
    )
    [void]$tallyGroup.Controls.Add(
        $advancedMaskBox
    )
    [void]$tallyGroup.Controls.Add(
        $tallyExplanationLabel
    )

    foreach (
        $dialogControl in @(
            $instructionsLabel,
            $fieldCaptionLabel,
            $fieldValueLabel,
            $metadataLabel,
            $currentFormatLabel,
            $currentFormatBox,
            $defaultAppliedLabel,
            $widthLabel,
            $widthInput,
            $alignmentLabel,
            $alignmentBox,
            $resultFormatLabel,
            $resultFormatBox,
            $formatExplanationLabel,
            $widthEffectLabel,
            $tallyGroup,
            $okButton,
            $cancelButton
        )
    ) {
        [void]$dialog.Controls.Add(
            $dialogControl
        )
    }

    try {
        if ($null -ne $Owner) {
            $dialogResult =
                $dialog.ShowDialog($Owner)
        }
        else {
            $dialogResult =
                $dialog.ShowDialog()
        }

        if (
            $dialogResult -eq
            [System.Windows.Forms.DialogResult]::OK
        ) {
            return $dialog.Tag
        }

        return $null
    }
    finally {
        $dialog.Dispose()
    }
}
function Show-BuilderApp {
    try { [void](Write-ProjectPickleDiagnosticLog -Message "Project Pickle UI starting." -Context "App startup") } catch {}
    Add-Type -AssemblyName System.Windows.Forms
    Add-Type -AssemblyName System.Drawing
    Set-WOOFWindowsAppIdentity
    [System.Windows.Forms.Application]::EnableVisualStyles()
    [System.Windows.Forms.Application]::SetUnhandledExceptionMode([System.Windows.Forms.UnhandledExceptionMode]::CatchException)

    $threadExceptionHandler = [System.Threading.ThreadExceptionEventHandler]{
        param($sender, $eventArgs)
        try {
            $exceptionText = if ($null -eq $eventArgs -or $null -eq $eventArgs.Exception) { "Unknown UI thread exception." } else { $eventArgs.Exception.ToString() }
            [void](Write-ProjectPickleDiagnosticLog -Message $exceptionText -Context "Windows Forms UI thread exception")
            [void](Write-ProjectPickleCrashLog -ExceptionObject $exceptionText -Context "Windows Forms UI thread exception")
        }
        catch {
        }
    }
    [System.Windows.Forms.Application]::add_ThreadException($threadExceptionHandler)

    $unhandledHandler = [System.UnhandledExceptionEventHandler]{
        param($sender, $eventArgs)
        try {
            $exceptionText = if ($null -eq $eventArgs -or $null -eq $eventArgs.ExceptionObject) { "Unknown unhandled exception." } else { [string]$eventArgs.ExceptionObject }
            [void](Write-ProjectPickleDiagnosticLog -Message $exceptionText -Context "AppDomain unhandled exception")
            [void](Write-ProjectPickleCrashLog -ExceptionObject $exceptionText -Context "AppDomain unhandled exception")
        }
        catch {
        }
    }
    [System.AppDomain]::CurrentDomain.add_UnhandledException($unhandledHandler)

    $uiTheme = [pscustomobject]@{
        AppBack       = [System.Drawing.Color]::FromArgb(246, 248, 245)
        Surface       = [System.Drawing.Color]::FromArgb(255, 255, 255)
        SoftSurface   = [System.Drawing.Color]::FromArgb(241, 245, 239)
        Border        = [System.Drawing.Color]::FromArgb(204, 214, 204)
        Text          = [System.Drawing.Color]::FromArgb(31, 38, 35)
        MutedText     = [System.Drawing.Color]::FromArgb(91, 101, 95)
        Accent        = [System.Drawing.Color]::FromArgb(45, 112, 83)
        AccentSoft    = [System.Drawing.Color]::FromArgb(222, 239, 230)
        AccentDark    = [System.Drawing.Color]::FromArgb(30, 79, 58)
        GridAlt       = [System.Drawing.Color]::FromArgb(250, 252, 249)
        GridSelect    = [System.Drawing.Color]::FromArgb(209, 232, 219)
    }

    function New-PickleUiFont {
        param(
            [float]$Size = 9,
            [System.Drawing.FontStyle]$Style = [System.Drawing.FontStyle]::Regular
        )

        foreach ($family in @("Segoe UI Variable Text", "Segoe UI")) {
            try { return New-Object System.Drawing.Font($family, $Size, $Style) }
            catch {}
        }
        return New-Object System.Drawing.Font([System.Drawing.SystemFonts]::MessageBoxFont.FontFamily, $Size, $Style)
    }

    function Set-PickleButtonStyle {
        param($Button)
        if ($null -eq $Button) { return }

        $isPrimary = (@("Build database", "Ask AI", "Check data types", "Next >") -contains (ConvertTo-BuilderText $Button.Text)) -or [string]::Equals((ConvertTo-BuilderText $Button.Tag), "PrimaryNavigation", [System.StringComparison]::OrdinalIgnoreCase)
        $Button.FlatStyle = [System.Windows.Forms.FlatStyle]::Flat
        $Button.FlatAppearance.BorderSize = 1
        $Button.FlatAppearance.BorderColor = if ($isPrimary) { $uiTheme.AccentDark } else { $uiTheme.Border }
        $Button.FlatAppearance.MouseOverBackColor = if ($isPrimary) { [System.Drawing.Color]::FromArgb(61, 132, 97) } else { $uiTheme.AccentSoft }
        $Button.FlatAppearance.MouseDownBackColor = if ($isPrimary) { $uiTheme.AccentDark } else { [System.Drawing.Color]::FromArgb(212, 232, 219) }
        $Button.BackColor = if ($isPrimary) { $uiTheme.Accent } else { $uiTheme.Surface }
        $Button.ForeColor = if ($isPrimary) { [System.Drawing.Color]::White } else { $uiTheme.Text }
        $Button.Font = if ([string]::Equals((ConvertTo-BuilderText $Button.Tag), "PrimaryNavigation", [System.StringComparison]::OrdinalIgnoreCase)) { New-PickleUiFont 11 ([System.Drawing.FontStyle]::Bold) } else { New-PickleUiFont 9 ([System.Drawing.FontStyle]::Regular) }
        $Button.Cursor = [System.Windows.Forms.Cursors]::Hand
        if ($Button.Height -lt 30) { $Button.Height = 30 }
        if ([string]::Equals((ConvertTo-BuilderText $Button.Tag), "PrimaryNavigation", [System.StringComparison]::OrdinalIgnoreCase) -and $Button.Height -lt 42) { $Button.Height = 42 }
        $Button.UseVisualStyleBackColor = $false
    }

    function Set-PickleGridStyle {
        param($Grid)
        if ($null -eq $Grid) { return }

        $Grid.BackgroundColor = $uiTheme.Surface
        $Grid.BorderStyle = [System.Windows.Forms.BorderStyle]::None
        $Grid.EnableHeadersVisualStyles = $false
        $Grid.GridColor = $uiTheme.Border
        $Grid.ColumnHeadersBorderStyle = [System.Windows.Forms.DataGridViewHeaderBorderStyle]::Single
        $Grid.RowHeadersBorderStyle = [System.Windows.Forms.DataGridViewHeaderBorderStyle]::Single
        $Grid.ColumnHeadersDefaultCellStyle.BackColor = $uiTheme.SoftSurface
        $Grid.ColumnHeadersDefaultCellStyle.ForeColor = $uiTheme.Text
        $Grid.ColumnHeadersDefaultCellStyle.Font = New-PickleUiFont 9 ([System.Drawing.FontStyle]::Bold)
        $Grid.RowHeadersDefaultCellStyle.BackColor = $uiTheme.SoftSurface
        $Grid.RowHeadersDefaultCellStyle.ForeColor = $uiTheme.MutedText
        $Grid.DefaultCellStyle.BackColor = $uiTheme.Surface
        $Grid.DefaultCellStyle.ForeColor = $uiTheme.Text
        $Grid.DefaultCellStyle.SelectionBackColor = $uiTheme.GridSelect
        $Grid.DefaultCellStyle.SelectionForeColor = $uiTheme.Text
        $Grid.DefaultCellStyle.Font = New-PickleUiFont 9 ([System.Drawing.FontStyle]::Regular)
        $Grid.RowsDefaultCellStyle.BackColor = $uiTheme.Surface
        $Grid.RowsDefaultCellStyle.ForeColor = $uiTheme.Text
        $Grid.RowsDefaultCellStyle.SelectionBackColor = $uiTheme.GridSelect
        $Grid.RowsDefaultCellStyle.SelectionForeColor = $uiTheme.Text
        $Grid.AlternatingRowsDefaultCellStyle.BackColor = $uiTheme.GridAlt
        $Grid.AlternatingRowsDefaultCellStyle.ForeColor = $uiTheme.Text
        $Grid.AlternatingRowsDefaultCellStyle.SelectionBackColor = $uiTheme.GridSelect
        $Grid.AlternatingRowsDefaultCellStyle.SelectionForeColor = $uiTheme.Text
        $Grid.CellBorderStyle = [System.Windows.Forms.DataGridViewCellBorderStyle]::SingleHorizontal
        $Grid.RowHeadersWidth = [Math]::Max($Grid.RowHeadersWidth, 28)
    }

    function Set-PickleTabsStyle {
        param($TabControl)
        if ($null -eq $TabControl) { return }

        $TabControl.Font = New-PickleUiFont 9 ([System.Drawing.FontStyle]::Regular)
        $TabControl.DrawMode = [System.Windows.Forms.TabDrawMode]::OwnerDrawFixed
        $TabControl.SizeMode = [System.Windows.Forms.TabSizeMode]::Normal
        $TabControl.Multiline = $true
        $TabControl.Padding = New-Object System.Drawing.Point(10, 4)
        $TabControl.Add_DrawItem({
            param($Sender, $EventArgs)

            $tabPage = $Sender.TabPages[$EventArgs.Index]
            $tabText = ConvertTo-BuilderText $tabPage.Text
            $selected = ($EventArgs.State -band [System.Windows.Forms.DrawItemState]::Selected) -eq [System.Windows.Forms.DrawItemState]::Selected
            $disabled = [string]::Equals((ConvertTo-BuilderText $tabPage.Tag), "Disabled", [System.StringComparison]::OrdinalIgnoreCase)
            $backColor = switch ($tabText) {
                "Project" { [System.Drawing.Color]::FromArgb(220, 240, 226); break }
                "Periods" { [System.Drawing.Color]::FromArgb(220, 234, 250); break }
                "Upgrade Mapping" { [System.Drawing.Color]::FromArgb(250, 235, 207); break }
                "Plots" { [System.Drawing.Color]::FromArgb(215, 240, 239); break }
                "AppColumns" { [System.Drawing.Color]::FromArgb(235, 226, 248); break }
                "Reports" { [System.Drawing.Color]::FromArgb(232, 239, 214); break }
                "Get Field Order" { [System.Drawing.Color]::FromArgb(224, 231, 255); break }
                "CFIDEER Queries" { [System.Drawing.Color]::FromArgb(252, 241, 196); break }
                "Plot Assignments" { [System.Drawing.Color]::FromArgb(246, 226, 211); break }
                "Tree Assignments" { [System.Drawing.Color]::FromArgb(223, 241, 218); break }
                "Processing" { [System.Drawing.Color]::FromArgb(233, 30, 99); break }
                "Build" { [System.Drawing.Color]::FromArgb(244, 67, 54); break }
                "AI Help" { [System.Drawing.Color]::FromArgb(226, 232, 250); break }
                default { $uiTheme.Surface }
            }
            if ($disabled) {
                $backColor = [System.Drawing.Color]::FromArgb(226, 229, 226)
            }
            elseif ($selected) {
                $backColor = [System.Drawing.Color]::FromArgb(255, 255, 255)
            }
            $foreColor = if ($disabled) {
                $uiTheme.MutedText
            }
            elseif ($selected) {
                $uiTheme.AccentDark
            }
            elseif ([string]::Equals($tabText, "Processing", [System.StringComparison]::OrdinalIgnoreCase)) {
                [System.Drawing.Color]::White
            }
            else {
                 $uiTheme.Text
            }

            $bounds = $EventArgs.Bounds
            $backBrush = $null
            $borderPen = $null
            try {
                $backBrush = [System.Drawing.SolidBrush]::new($backColor)
                $borderPen = [System.Drawing.Pen]::new($uiTheme.Border)
                $EventArgs.Graphics.FillRectangle($backBrush, $bounds)
                $EventArgs.Graphics.DrawRectangle($borderPen, $bounds.X, $bounds.Y, [Math]::Max(0, $bounds.Width - 1), [Math]::Max(0, $bounds.Height - 1))
                $textFlags = [System.Windows.Forms.TextFormatFlags]::HorizontalCenter -bor [System.Windows.Forms.TextFormatFlags]::VerticalCenter -bor [System.Windows.Forms.TextFormatFlags]::EndEllipsis
                [System.Windows.Forms.TextRenderer]::DrawText($EventArgs.Graphics, $tabText, $Sender.Font, $bounds, $foreColor, $textFlags)
            }
            finally {
                if ($null -ne $backBrush) { $backBrush.Dispose() }
                if ($null -ne $borderPen) { $borderPen.Dispose() }
            }
        })
    }

    function Set-PickleControlTreeStyle {
        param($Root)
        if ($null -eq $Root) { return }

        foreach ($control in $Root.Controls) {
            if ($control -is [System.Windows.Forms.TabPage]) {
                $control.BackColor = $uiTheme.AppBack
                $control.ForeColor = $uiTheme.Text
                $control.Font = New-PickleUiFont $control.Font.Size $control.Font.Style
            }
            elseif ($control -is [System.Windows.Forms.Label]) {
                $control.BackColor = [System.Drawing.Color]::Transparent
                try {
                    $controlTextArgb = [System.Drawing.Color]::FromKnownColor([System.Drawing.KnownColor]::ControlText).ToArgb()
                    if ($control.ForeColor.IsEmpty -or $control.ForeColor.ToArgb() -eq $controlTextArgb) { $control.ForeColor = $uiTheme.Text }
                }
                catch {
                    $control.ForeColor = $uiTheme.Text
                }
                $control.Font = New-PickleUiFont $control.Font.Size $control.Font.Style
            }
            elseif ($control -is [System.Windows.Forms.Button]) {
                Set-PickleButtonStyle $control
            }
            elseif ($control -is [System.Windows.Forms.TextBox]) {
                $control.BorderStyle = [System.Windows.Forms.BorderStyle]::FixedSingle
                $control.BackColor = if ($control.ReadOnly) { $uiTheme.SoftSurface } else { $uiTheme.Surface }
                $control.ForeColor = $uiTheme.Text
                $control.Font = New-PickleUiFont $control.Font.Size $control.Font.Style
            }
            elseif ($control -is [System.Windows.Forms.RichTextBox]) {
                $control.BorderStyle = [System.Windows.Forms.BorderStyle]::FixedSingle
                $control.BackColor = $uiTheme.SoftSurface
                $control.ForeColor = $uiTheme.Text
                $control.Font = New-PickleUiFont $control.Font.Size $control.Font.Style
            }
            elseif ($control -is [System.Windows.Forms.ComboBox]) {
                $control.FlatStyle = [System.Windows.Forms.FlatStyle]::Flat
                $control.BackColor = $uiTheme.Surface
                $control.ForeColor = $uiTheme.Text
                $control.Font = New-PickleUiFont $control.Font.Size $control.Font.Style
            }
            elseif ($control -is [System.Windows.Forms.CheckBox]) {
                $control.BackColor = [System.Drawing.Color]::Transparent
                $control.ForeColor = $uiTheme.Text
                $control.Font = New-PickleUiFont $control.Font.Size $control.Font.Style
            }
            elseif ($control -is [System.Windows.Forms.GroupBox]) {
                $control.BackColor = [System.Drawing.Color]::Transparent
                $control.ForeColor = $uiTheme.Text
                $control.Font = New-PickleUiFont $control.Font.Size ([System.Drawing.FontStyle]::Bold)
            }
            elseif ($control -is [System.Windows.Forms.DataGridView]) {
                Set-PickleGridStyle $control
            }
            elseif ($control -is [System.Windows.Forms.StatusStrip]) {
                $control.BackColor = $uiTheme.Surface
                $control.ForeColor = $uiTheme.MutedText
                $control.RenderMode = [System.Windows.Forms.ToolStripRenderMode]::System
            }

            Set-PickleControlTreeStyle $control
        }
    }

    $form = New-Object System.Windows.Forms.Form
