    $form.StartPosition = "CenterScreen"
    $form.Size = New-Object System.Drawing.Size(1280, 840)
    $form.MinimumSize = New-Object System.Drawing.Size(1080, 720)
    $form.Font = New-PickleUiFont 9
    $form.BackColor = $uiTheme.AppBack
    $form.AutoScaleMode = [System.Windows.Forms.AutoScaleMode]::Dpi
    $form.ShowIcon = $true
    $form.ShowInTaskbar = $true
    if (Test-Path -LiteralPath $script:AppIconPath) {
        $appIcon = New-Object System.Drawing.Icon($script:AppIconPath)
        $setWindowIcon = ${function:Set-WOOFWindowIcon}
        & $setWindowIcon -Form $form -Icon $appIcon
        $form.Add_HandleCreated({ & $setWindowIcon -Form $form -Icon $appIcon }.GetNewClosure())
        $form.Add_FormClosed({ if ($appIcon) { $appIcon.Dispose() } })
    }
    $form.Add_FormClosing({
        param($Sender, $EventArgs)
        if ($script:WOOFIsProcessing -and -not $script:WOOFAllowCloseAfterCancel) {
            if ($script:WOOFCancelRequested) {
                $EventArgs.Cancel = $true
                return
            }
            $liveLogText = if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $script:WOOFLiveRunLogPath))) { "" } else { "`r`n`r`nLive log:`r`n$script:WOOFLiveRunLogPath" }
            $answer = [System.Windows.Forms.MessageBox]::Show(
                "Project Pickle is still processing. Closing during a database write can leave the saved project database incomplete.`r`n`r`nChoose No to keep waiting. Choose Yes to request cancel; Project Pickle will close after the current safe checkpoint.$liveLogText",
                "Project Pickle is still working",
                [System.Windows.Forms.MessageBoxButtons]::YesNo,
                [System.Windows.Forms.MessageBoxIcon]::Warning,
                [System.Windows.Forms.MessageBoxDefaultButton]::Button2
            )
            if ($answer -ne [System.Windows.Forms.DialogResult]::Yes) {
                Add-WOOFLiveRunLogMarker -Path $script:WOOFLiveRunLogPath -Text "Close requested while Project Pickle was processing. Close was canceled by the user; Project Pickle continued running."
                $EventArgs.Cancel = $true
                return
            }
            $script:WOOFCancelRequested = $true
            $script:WOOFCloseAfterCancel = $true
            Add-WOOFLiveRunLogMarker -Path $script:WOOFLiveRunLogPath -Text "Close requested by the user while Project Pickle was processing. Project Pickle will stop after the current safe checkpoint."
            try { $statusLabel.Text = "Close requested. Project Pickle will stop after the current safe checkpoint." } catch {}
            $EventArgs.Cancel = $true
            return
        }
    })

