    function Add-BrowseButton {
        param($Parent, $TextBox, [int]$X, [int]$Y, [string]$Filter, [bool]$Save)
        $button = New-Object System.Windows.Forms.Button
        $button.Text = "Browse"
        $button.Location = New-Object System.Drawing.Point($X, $Y)
        $button.Size = New-Object System.Drawing.Size(82, 28)
        Set-PickleButtonStyle $button
        $Parent.Controls.Add($button)
        $button.Add_Click({
            if ($Save -and $button.Tag -is [scriptblock]) {
                & ([scriptblock]$button.Tag)
            }
            if ($Save) {
                $dialog = New-Object System.Windows.Forms.SaveFileDialog
                $dialog.Filter = $Filter
                $dialog.DefaultExt = "mdb"
                $dialog.AddExtension = $true
                $dialog.OverwritePrompt = $true
            }
            else {
                $dialog = New-Object System.Windows.Forms.OpenFileDialog
                $dialog.Filter = $Filter
            }
            try {
                $fileName = ""
                if (-not [string]::IsNullOrWhiteSpace($TextBox.Text)) {
                    $dir = if ($Save) { [System.IO.Path]::GetDirectoryName($TextBox.Text) } else { [System.IO.Path]::GetDirectoryName($TextBox.Text) }
                    if (-not [string]::IsNullOrWhiteSpace($dir) -and (Test-Path -LiteralPath $dir)) { $dialog.InitialDirectory = $dir }
                    $fileName = [System.IO.Path]::GetFileName($TextBox.Text)
                    if (-not $Save -and -not [string]::IsNullOrWhiteSpace($fileName)) { $dialog.FileName = $fileName }
                }
                if ($Save) {
                    $hint = ConvertTo-BuilderText $TextBox.Tag
                    if (-not [string]::IsNullOrWhiteSpace($hint)) {
                        $dialog.FileName = $hint
                    }
                    elseif (-not [string]::IsNullOrWhiteSpace($fileName)) {
                        $dialog.FileName = $fileName
                    }
                }
                if ($dialog.ShowDialog($form) -eq [System.Windows.Forms.DialogResult]::OK) { $TextBox.Text = $dialog.FileName }
            }
            finally {
                $dialog.Dispose()
            }
        }.GetNewClosure())
        return $button
    }

