    $keepExistingReferenceCheck = New-Object System.Windows.Forms.CheckBox
    $keepExistingReferenceCheck.Text = "Keep Region, Agency, and Reservation from Existing Database"
    $keepExistingReferenceCheck.Location = New-Object System.Drawing.Point(180, 489)
    $keepExistingReferenceCheck.Size = New-Object System.Drawing.Size(560, 24)
    $setupPage.Controls.Add($keepExistingReferenceCheck)
    $keepExistingReferenceTip = "Upgrade Project and Existing Project can keep the Region, Agency, and Reservation already stored in the selected existing database. New Project requires you to load the lists and select these values manually."
    $toolTip.SetToolTip($keepExistingReferenceCheck, $keepExistingReferenceTip)
    $refreshKeepExistingReferenceState = {
        $modeText = Get-WOOFComboText -Combo $modeBox
        $isSelectedUpgradeMode = Test-UpgradeModeText -Mode $modeText
        $isExistingProjectMode = Test-WOOFTextEquals $modeText "Existing Project"
        $keepExistingReferenceCheck.Enabled = $isSelectedUpgradeMode
        $keepExistingReferenceCheck.ForeColor = if ($keepExistingReferenceCheck.Enabled) { $uiTheme.Text } else { $uiTheme.MutedText }
        $manualReferenceEnabled = -not [bool]$keepExistingReferenceCheck.Checked
        foreach ($control in @($regionLabel, $agencyLabel, $reservationNameLabel)) {
            $control.Enabled = $manualReferenceEnabled
        }
        foreach ($combo in @($regionBox, $agencyBox, $reservationNameBox)) {
            if ($manualReferenceEnabled) {
                $combo.Enabled = $true
                $combo.DropDownStyle = "DropDown"
                $combo.BackColor = $uiTheme.Surface
                $combo.ForeColor = $uiTheme.Text
            }
            else {
                # Locked but readable: keep it enabled so text stays crisp,
                # but block typing and the dropdown so it's effectively read-only.
                $combo.Enabled = $true
                $combo.DropDownStyle = "DropDownList"
                $combo.BackColor = $uiTheme.SoftSurface
                $combo.ForeColor = $uiTheme.Text
            }
        }
        if ($isExistingProjectMode) {
            $keepExistingReferenceCheck.ForeColor = $uiTheme.MutedText
        }
    }.GetNewClosure()
    $setKeepExistingReferenceModeDefault = {
        $modeText = Get-WOOFComboText -Combo $modeBox
