    $script:BuilderReferenceRows = @()
    $script:BuilderReferenceSource = ""
    $script:BuilderRegionChoices = @()
    $script:BuilderAgencyChoices = @()
    $script:BuilderReservationChoices = @()
    $script:BuilderAllRegionNames = @()
    $script:BuilderAllAgencyNames = @()
    $script:BuilderAllReservationNames = @()
    $script:BuilderIsRefreshingReferenceLists = $false
    $getSelectedRegionIds = {
        $selectedRegion = Get-WOOFComboText $regionBox
        if ([string]::IsNullOrWhiteSpace($selectedRegion)) { return @() }
        return @($script:BuilderRegionChoices | Where-Object {
            [string]::Equals((ConvertTo-BuilderText $_.DisplayName), $selectedRegion, [System.StringComparison]::OrdinalIgnoreCase)
        } | ForEach-Object { ConvertTo-BuilderText $_.RegionID } | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
    }.GetNewClosure()
    $getSelectedAgencyIds = {
        param([string[]]$RegionIds)

        $selectedAgency = Get-WOOFComboText $agencyBox
        if ([string]::IsNullOrWhiteSpace($selectedAgency)) { return @() }
        $matches = @($script:BuilderAgencyChoices | Where-Object {
            [string]::Equals((ConvertTo-BuilderText $_.DisplayName), $selectedAgency, [System.StringComparison]::OrdinalIgnoreCase)
        })
        if (@($RegionIds).Count -gt 0) {
            $regionScopedMatches = @($matches | Where-Object { @($RegionIds) -contains (ConvertTo-BuilderText $_.RegionID) })
            if ($regionScopedMatches.Count -gt 0) { $matches = $regionScopedMatches }
        }
        return @($matches | ForEach-Object { ConvertTo-BuilderText $_.AgencyID } | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
    }.GetNewClosure()
    $refreshReservationList = {
        if ($script:BuilderIsRefreshingReferenceLists) { return }
        $regionIds = @(& $getSelectedRegionIds)
        $agencyIds = @(& $getSelectedAgencyIds -RegionIds ([string[]]$regionIds))
        $selectedRegion = Get-WOOFComboText $regionBox
        $selectedAgency = Get-WOOFComboText $agencyBox
        $reservationRows = @($script:BuilderReservationChoices)
        if ($agencyIds.Count -gt 0) {
            $reservationRows = @($reservationRows | Where-Object { $agencyIds -contains (ConvertTo-BuilderText $_.AgencyID) })
        }
        elseif ($regionIds.Count -gt 0) {
            $reservationRows = @($reservationRows | Where-Object { $regionIds -contains (ConvertTo-BuilderText $_.RegionID) })
        }
        elseif ([string]::IsNullOrWhiteSpace($selectedRegion) -and [string]::IsNullOrWhiteSpace($selectedAgency)) {
            $reservationRows = @($script:BuilderReservationChoices)
        }
        $reservations = @($reservationRows | ForEach-Object { ConvertTo-BuilderText $_.DisplayName } | Where-Object { -not [string]::IsNullOrWhiteSpace($_) } | Sort-Object -Unique)
        if ($reservations.Count -eq 0 -and [string]::IsNullOrWhiteSpace($selectedRegion) -and [string]::IsNullOrWhiteSpace($selectedAgency)) {
            $reservations = @($script:BuilderAllReservationNames)
        }
        $currentReservation = ConvertTo-BuilderText $reservationNameBox.Text
        $script:BuilderIsRefreshingReferenceLists = $true
        try {
            Set-WOOFComboItems -Combo $reservationNameBox -Items ([string[]]$reservations)
        }
        finally {
            $script:BuilderIsRefreshingReferenceLists = $false
        }
        $reservationStillValid = @($reservations | Where-Object { [string]::Equals((ConvertTo-BuilderText $_), $currentReservation, [System.StringComparison]::OrdinalIgnoreCase) }).Count -gt 0
        if (-not [string]::IsNullOrWhiteSpace($currentReservation) -and -not $reservationStillValid) {
            $reservationNameBox.Text = ""
        }
    }.GetNewClosure()
    $refreshAgencyList = {
        if ($script:BuilderIsRefreshingReferenceLists) { return }
        $regionIds = @(& $getSelectedRegionIds)
        $selectedRegion = Get-WOOFComboText $regionBox
        $agencyRows = @($script:BuilderAgencyChoices)
        if ($regionIds.Count -gt 0) {
            $agencyRows = @($agencyRows | Where-Object { $regionIds -contains (ConvertTo-BuilderText $_.RegionID) })
        }
        $agencies = @($agencyRows | ForEach-Object { ConvertTo-BuilderText $_.DisplayName } | Where-Object { -not [string]::IsNullOrWhiteSpace($_) } | Sort-Object -Unique)
        if ($agencies.Count -eq 0 -and [string]::IsNullOrWhiteSpace($selectedRegion)) {
            $agencies = @($script:BuilderAllAgencyNames)
        }
        $currentAgency = ConvertTo-BuilderText $agencyBox.Text
        $script:BuilderIsRefreshingReferenceLists = $true
        try {
            Set-WOOFComboItems -Combo $agencyBox -Items ([string[]]$agencies)
        }
        finally {
            $script:BuilderIsRefreshingReferenceLists = $false
        }
        $agencyStillValid = @($agencies | Where-Object { [string]::Equals((ConvertTo-BuilderText $_), $currentAgency, [System.StringComparison]::OrdinalIgnoreCase) }).Count -gt 0
        if (-not [string]::IsNullOrWhiteSpace($currentAgency) -and -not $agencyStillValid) {
            $agencyBox.Text = ""
        }
        & $refreshReservationList
    }.GetNewClosure()

    $optionsPage = New-TabPage "Periods"
    $optionsPage.AutoScroll = $true
    $optionsPage.AutoScrollMinSize = New-Object System.Drawing.Size(0, 700)
    $periodIntroLabel = New-Object System.Windows.Forms.Label
$periodIntroLabel.Text = @"
What needs to be done:
1. Use this tab only in New Project or Upgrade Project mode.
2. Select "Load periods from database" when working in Upgrade Project mode.
3. Add the new project period and confirm the existing period data.

New Project: enter the project information in row 1 with PeriodNumber 1 and check IsCurrent.
Upgrade Project: verify the information and number of periods, then add the new period for the remeasurement and check IsCurrent.
Existing Project: this tab is read-only/greyed out. Use Existing Project mode only for adding field data items or additional plots, then continue through Get Field Order, CFIDEER Queries, Assignments, and Build.
"@
    $periodIntroLabel.Location = New-Object System.Drawing.Point(18, 18)
    $periodIntroLabel.Size = New-Object System.Drawing.Size(1030, 146)
    $periodIntroLabel.Anchor = "Top,Left"
    $optionsPage.Controls.Add($periodIntroLabel)
    $toolTip.SetToolTip($periodIntroLabel, "Periods are separate from measurement cycle length. Add or edit period rows only in New Project or Upgrade Project mode. Existing Project mode preserves the period rows already in the selected database.")
    $loadPeriodsButton = New-Object System.Windows.Forms.Button
    $loadPeriodsButton.Text = "Load periods from database"
    $loadPeriodsButton.Location = New-Object System.Drawing.Point(18, 176)
    $loadPeriodsButton.Size = New-Object System.Drawing.Size(205, 26)
    $optionsPage.Controls.Add($loadPeriodsButton)
    $toolTip.SetToolTip($loadPeriodsButton, "Upgrade Project mode only. Loads measurement periods from the old database selected in Existing/old project database so you can add the new remeasurement period. New Project mode starts with the default period row. Existing Project mode preserves existing period rows and keeps this tab read-only.")
    $periodGrid = New-Object System.Windows.Forms.DataGridView
    $script:ProjectPicklePeriodGrid = $periodGrid
    $periodGrid.Location = New-Object System.Drawing.Point(18, 214)
    $periodGrid.Size = New-Object System.Drawing.Size(1030, 342)
    $periodGrid.Anchor = "Top,Left,Right,Bottom"
    $periodGrid.AllowUserToAddRows = $true
    $periodGrid.AllowUserToDeleteRows = $true
    $periodGrid.AutoSizeColumnsMode = "None"
    $periodGrid.ScrollBars = "Both"
    $periodGrid.ShowCellToolTips = $true
    $optionsPage.Controls.Add($periodGrid)
    $toolTip.SetToolTip($periodGrid, "Add one row per measurement period. Use the bottom scrollbar when the app is not maximized.")
    $periodIdColumnIndex = $periodGrid.Columns.Add("ProjectPeriodID", "ProjectPeriodID")
    $periodGrid.Columns[$periodIdColumnIndex].Visible = $false
    foreach ($name in @("PeriodNumber", "PeriodDescription", "PlannedStartDate", "PlannedEndDate", "ActualStartDate", "ActualEndDate", "ApplicablePeriod")) {
        $idx = $periodGrid.Columns.Add($name, $name)
        $periodGrid.Columns[$idx].Width = if ($name -eq "PeriodDescription") { 240 } else { 150 }
    }
    Set-GridColumnToolTip $periodGrid.Columns["PeriodNumber"] "Numeric period number. New projects normally use 1. Existing projects may have multiple rows, such as 1, 2, 3, or more."
    Set-GridColumnToolTip $periodGrid.Columns["PeriodDescription"] "Plain-language period label, such as Current Measurement, 2015 Remeasurement, or 2026 Measurement."
    Set-GridColumnToolTip $periodGrid.Columns["PlannedStartDate"] "Optional planned start date for this period. Use a normal date format, such as 2026-01-01."
    Set-GridColumnToolTip $periodGrid.Columns["PlannedEndDate"] "Optional planned end date for this period. Use a normal date format, such as 2026-12-31."
    Set-GridColumnToolTip $periodGrid.Columns["ActualStartDate"] "Optional actual start date if known. Leave blank when it is not known yet."
    Set-GridColumnToolTip $periodGrid.Columns["ActualEndDate"] "Optional actual end date if known. Leave blank when it is not known yet."
    Set-GridColumnToolTip $periodGrid.Columns["ApplicablePeriod"] "Value written to ValidationRules.ApplicablePeriods when validation setup is selected. Usually the measurement year or period identifier used by the project."
    $currentCol = New-Object System.Windows.Forms.DataGridViewCheckBoxColumn
    $currentCol.Name = "IsCurrent"
    $currentCol.HeaderText = "IsCurrent"
    [void]$periodGrid.Columns.Add($currentCol)
    Set-GridColumnToolTip $currentCol "Check the row that represents the current active measurement period. Only one row can be checked. When adding a new period to a multiperiod project, make the new period current."
    $script:BuilderIsSyncingPeriodCurrent = $false
    $setSingleCurrentPeriodRow = {
        param([System.Windows.Forms.DataGridViewRow]$CurrentRow)

        if ($null -eq $CurrentRow) { return }
        if (-not $periodGrid.Columns.Contains("IsCurrent")) { return }
        if ($script:BuilderIsSyncingPeriodCurrent) { return }
        try {
            $script:BuilderIsSyncingPeriodCurrent = $true
            foreach ($row in $periodGrid.Rows) {
                if ($row.IsNewRow) { continue }
                $row.Cells["IsCurrent"].Value = [object]($row.Index -eq $CurrentRow.Index)
            }
        }
        finally {
            $script:BuilderIsSyncingPeriodCurrent = $false
        }
    }.GetNewClosure()
    $periodGrid.Add_CurrentCellDirtyStateChanged({
        if ($periodGrid.IsCurrentCellDirty) {
            [void]$periodGrid.CommitEdit([System.Windows.Forms.DataGridViewDataErrorContexts]::Commit)
        }
    })
    $periodGrid.Add_CellValueChanged({
        param($Sender, $EventArgs)
        if ($script:BuilderIsSyncingPeriodCurrent) { return }
        if ($EventArgs.RowIndex -lt 0 -or $EventArgs.ColumnIndex -lt 0) { return }
        if ($Sender.Columns[$EventArgs.ColumnIndex].Name -ne "IsCurrent") { return }
        $row = $Sender.Rows[$EventArgs.RowIndex]
        if (ConvertTo-BuilderBool $row.Cells["IsCurrent"].Value) {
            & $setSingleCurrentPeriodRow -CurrentRow $row
        }
    })
    $periodGrid.Add_DefaultValuesNeeded({
        param($Sender, $EventArgs)
        $EventArgs.Row.Cells["IsCurrent"].Value = $true
        & $setSingleCurrentPeriodRow -CurrentRow $EventArgs.Row
    })
    $addPeriodRowToGrid = {
        param([object]$Period)

        [void]$periodGrid.Rows.Add(
            (ConvertTo-BuilderText $Period.ProjectPeriodID),
            (ConvertTo-BuilderText $Period.PeriodNumber),
            (ConvertTo-BuilderText $Period.PeriodDescription),
            (ConvertTo-BuilderDateText $Period.PlannedStartDate),
            (ConvertTo-BuilderDateText $Period.PlannedEndDate),
            (ConvertTo-BuilderDateText $Period.ActualStartDate),
            (ConvertTo-BuilderDateText $Period.ActualEndDate),
            (ConvertTo-BuilderText $Period.ApplicablePeriod),
            (ConvertTo-BuilderBool $Period.IsCurrent)
        )
    }.GetNewClosure()

    $newDefaultPeriodFactory = ${function:New-DefaultPeriod}
    $resetPeriodGridToDefault = {
        $periodGrid.Rows.Clear()
        & $addPeriodRowToGrid -Period (& $newDefaultPeriodFactory)
    }.GetNewClosure()

    $loadExistingPeriodsToGrid = {
        param([System.Data.OleDb.OleDbConnection]$Connection)

        $periods = @(Get-ProjectPeriodsForBuilder -Connection $Connection)
        if ($periods.Count -eq 0) {
            return 0
        }

        $periodGrid.Rows.Clear()
        foreach ($period in $periods) {
            & $addPeriodRowToGrid -Period $period
        }
        return $periods.Count
    }.GetNewClosure()

    $refreshReadOnlyExistingPeriods = {
        $selectedMode = Get-WOOFComboText -Combo $modeBox
        if (-not (Test-WOOFTextEquals $selectedMode "Existing Project")) { return }

        $path = ConvertTo-BuilderText $sourceBox.Text
        if ([string]::IsNullOrWhiteSpace($path) -or -not (Test-Path -LiteralPath $path -ErrorAction SilentlyContinue)) {
            $periodGrid.Rows.Clear()
            return
        }

        $connection = $null
        try {
            $connection = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $path)
            [void](& $loadExistingPeriodsToGrid -Connection $connection)
        }
        catch {
            $periodGrid.Rows.Clear()
        }
        finally {
            if ($null -ne $connection) {
                if ($connection.State -eq "Open") { $connection.Close() }
                $connection.Dispose()
            }
        }
    }.GetNewClosure()

    & $resetPeriodGridToDefault
    $updateLoadPeriodsButtonAvailability = {
        $enabled = Test-UpgradeModeText -Mode (Get-WOOFComboText -Combo $modeBox)
        $loadPeriodsButton.Enabled = $enabled
        $loadPeriodsButton.Text = "Load periods from database"
        $loadPeriodsButton.BackColor = if ($enabled) { $uiTheme.Surface } else { $uiTheme.SoftSurface }
        $loadPeriodsButton.ForeColor = if ($enabled) { $uiTheme.Text } else { $uiTheme.MutedText }
    }.GetNewClosure()
    $modeBox.Add_SelectedIndexChanged({ & $updateLoadPeriodsButtonAvailability }.GetNewClosure())
    & $updateLoadPeriodsButtonAvailability

    $loadPeriodsButton.Add_Click({
        try {
            if (-not (Test-UpgradeModeText -Mode (Get-WOOFComboText -Combo $modeBox))) {
                [System.Windows.Forms.MessageBox]::Show("This button is only for Upgrade Project mode. New Project mode uses the default period row. Existing Project mode keeps the Periods tab read-only because the selected database should already contain the correct period structure.", "Load periods", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
                return
            }
            $path = ConvertTo-BuilderText $sourceBox.Text
            if ([string]::IsNullOrWhiteSpace($path) -or -not (Test-Path -LiteralPath $path)) {
                [System.Windows.Forms.MessageBox]::Show("Choose the old project database in Existing/old project database on the Project tab first, then click Load periods from database again.", "Load periods", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
                return
            }

            $statusLabel.Text = "Loading measurement periods from old database..."
            [System.Windows.Forms.Application]::DoEvents()
            $connection = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $path)
            try {
                $periodTableName = Get-ProjectPeriodTableNameForBuilder -Connection $connection
                $count = & $loadExistingPeriodsToGrid -Connection $connection
                if ($count -gt 0) {
                    $sourceTableText = if ([string]::IsNullOrWhiteSpace($periodTableName)) { "" } else { " from $periodTableName" }
                    $statusLabel.Text = "Loaded $count measurement period(s)$sourceTableText."
                    [System.Windows.Forms.MessageBox]::Show("Loaded $count measurement period(s)$sourceTableText.", "Load periods", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
                }
                else {
                    $statusLabel.Text = "No measurement periods were found."
                    [System.Windows.Forms.MessageBox]::Show("No measurement periods were found in the selected database. Project Pickle looked for common period tables such as ProjectMeasurementPeriods, ProjectPeriods, MeasurementPeriods, InventoryPeriods, and Periods.", "Load periods", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
                }
            }
            finally {
                if ($connection.State -eq "Open") { $connection.Close() }
                $connection.Dispose()
            }
        }
        catch {
            $statusLabel.Text = "Could not load measurement periods."
            [System.Windows.Forms.MessageBox]::Show($_.Exception.Message, "Load periods failed", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
        }
    })
    $loadReferenceChoices = {
        try {
            $selectedMode = Get-WOOFComboText -Combo $modeBox
            $isSelectedUpgradeMode = Test-UpgradeModeText -Mode $selectedMode
            $isNewProjectMode = Test-NewProjectModeText -Mode $selectedMode
            $referencePathText = if ($isNewProjectMode) { ConvertTo-BuilderText $upgradeTemplateBox.Text } else { ConvertTo-BuilderText $sourceBox.Text }
            if ([string]::IsNullOrWhiteSpace($referencePathText) -or -not (Test-Path -LiteralPath $referencePathText)) {
                if ($isNewProjectMode) {
                    throw "Choose the current master database version before loading Region, Agency, and Reservation lists."
                }
                throw "Choose the Existing/old project database before loading Region, Agency, and Reservation lists."
            }

            $sourcePath = if ($isNewProjectMode) { "" } else { [System.IO.Path]::GetFullPath((ConvertTo-BuilderText $sourceBox.Text)) }
            $referencePath = [System.IO.Path]::GetFullPath($referencePathText)
            $loadedSource = ConvertTo-BuilderText $script:BuilderReferenceSource
            $loadedRegionCount = @($script:BuilderAllRegionNames).Count
            $loadedAgencyCount = @($script:BuilderAllAgencyNames).Count
            $loadedReservationCount = @($script:BuilderAllReservationNames).Count
            if ([string]::Equals($loadedSource, $referencePath, [System.StringComparison]::OrdinalIgnoreCase) -and
                $loadedRegionCount -gt 0 -and
                $loadedAgencyCount -gt 0 -and
                $loadedReservationCount -gt 0 -and
                -not (Test-WOOFTextEquals $selectedMode "Existing Project") -and
                -not $isSelectedUpgradeMode) {
                $statusLabel.Text = "Lists already loaded: $loadedRegionCount region(s), $loadedAgencyCount agency/agencies, $loadedReservationCount reservation(s)"
                return
            }
            $statusLabel.Text = if ($isSelectedUpgradeMode) { "Loading reference lists and periods from old project..." } elseif ($isNewProjectMode) { "Loading region, agency, and reservation lists from current master..." } else { "Loading region, agency, reservation, and read-only periods from existing project..." }
            [System.Windows.Forms.Application]::DoEvents()
            $connection = $null
            $connection = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $referencePath)
            try {
                $choices = Get-BuilderReferenceChoices -Connection $connection
                $script:BuilderReferenceRows = @($choices.ReferenceRows)
                $script:BuilderReferenceSource = $referencePath
                $script:BuilderRegionChoices = @($choices.RegionChoices)
                $script:BuilderAgencyChoices = @($choices.AgencyChoices)
                $script:BuilderReservationChoices = @($choices.ReservationChoices)
                $script:BuilderAllRegionNames = @($choices.RegionNames)
                $script:BuilderAllAgencyNames = @($choices.AgencyNames)
                $script:BuilderAllReservationNames = @($choices.ReservationNames)
                $script:BuilderIsRefreshingReferenceLists = $true
                try {
                    Set-WOOFComboItems -Combo $regionBox -Items ([string[]]$script:BuilderAllRegionNames)
                    Set-WOOFComboItems -Combo $agencyBox -Items ([string[]]$script:BuilderAllAgencyNames)
                    Set-WOOFComboItems -Combo $reservationNameBox -Items ([string[]]$script:BuilderAllReservationNames)
                }
                finally {
                    $script:BuilderIsRefreshingReferenceLists = $false
                }
                $statusText = "Loaded $($script:BuilderAllRegionNames.Count) region(s), $($script:BuilderAllAgencyNames.Count) agency/agencies, and $($script:BuilderAllReservationNames.Count) reservation(s)"
                if ((Test-WOOFTextEquals $selectedMode "Existing Project") -or $isSelectedUpgradeMode) {
                    $periodConnection = $null
                    try {
                        $periodPath = $sourcePath
                        $periodConnection = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $periodPath)
                        $loadedPeriodCount = & $loadExistingPeriodsToGrid -Connection $periodConnection
                    }
                    finally {
                        if ($null -ne $periodConnection) {
                            if ($periodConnection.State -eq "Open") { $periodConnection.Close() }
                            $periodConnection.Dispose()
                        }
                    }
                    if ($loadedPeriodCount -gt 0) {
                        $statusText = "$statusText and $loadedPeriodCount existing measurement period(s)"
                    }
                    elseif ($isSelectedUpgradeMode) {
                        $statusText = "$statusText; no measurement periods were found in the old project database"
                    }
                }
                if (Test-WOOFTextEquals $selectedMode "Existing Project") {
                    $existingProjectInfo = Get-ExistingProjectReferenceSelection -DatabasePath $sourcePath
                    $existingProjectName = ConvertTo-BuilderText $existingProjectInfo.ProjectName
                    $existingCycleLength = ConvertTo-BuilderText $existingProjectInfo.CycleLength
                    if (-not [string]::IsNullOrWhiteSpace($existingProjectName)) { $projectBox.Text = $existingProjectName }
                    if (-not [string]::IsNullOrWhiteSpace($existingCycleLength)) { $cycleBox.Text = $existingCycleLength }
                    $regionBox.SelectedItem = ConvertTo-BuilderText $existingProjectInfo.RegionName
                    $regionBox.Text = ConvertTo-BuilderText $existingProjectInfo.RegionName
                    $agencyBox.SelectedItem = ConvertTo-BuilderText $existingProjectInfo.AgencyName
                    $agencyBox.Text = ConvertTo-BuilderText $existingProjectInfo.AgencyName
                    $reservationNameBox.SelectedItem = ConvertTo-BuilderText $existingProjectInfo.ReservationName
                    $reservationNameBox.Text = ConvertTo-BuilderText $existingProjectInfo.ReservationName
                    & $refreshProjectIdentityModeState
                    & $refreshKeepExistingReferenceState
                    $statusText = "$statusText. Existing project identity loaded read-only."
                }
                $statusLabel.Text = $statusText
            }
            finally {
                if ($null -ne $connection) {
                    if ($connection.State -eq "Open") { $connection.Close() }
                    $connection.Dispose()
                }
            }
        }
        catch {
            $statusLabel.Text = "Could not load lists from the selected database."
            [System.Windows.Forms.MessageBox]::Show($_.Exception.Message, "Could not load lists", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
        }
    }.GetNewClosure()
