function script:Get-PlotImportMappingsFromGrid {
        $items = New-Object System.Collections.Generic.List[object]
        foreach ($row in $plotMappingGrid.Rows) {
            if ($row.IsNewRow) { continue }
            $fieldName = ConvertTo-BuilderText $row.Cells["FieldName"].Value
            if ([string]::IsNullOrWhiteSpace($fieldName)) { continue }
            [void]$items.Add([pscustomobject]@{
                FieldName = $fieldName
                SourceColumn = ConvertTo-BuilderText $row.Cells["SourceColumn"].Value
                Required = [string]::Equals((ConvertTo-BuilderText $row.Cells["Required"].Value), "Yes", [System.StringComparison]::OrdinalIgnoreCase)
            })
        }
        return @($items.ToArray())
    }

    function Set-PlotMappingSourceColumnChoices {
        param([string[]]$Columns)

        $sourceColumn = [System.Windows.Forms.DataGridViewComboBoxColumn]$plotMappingGrid.Columns["SourceColumn"]
        $sourceColumn.Items.Clear()
        [void]$sourceColumn.Items.Add("")
        foreach ($columnName in @($Columns | Where-Object { -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $_)) } | Sort-Object -Unique)) {
            [void]$sourceColumn.Items.Add((ConvertTo-BuilderText $columnName))
        }
    }

    function Populate-PlotImportMappingGrid {
        param([string]$Path)

        if ([string]::IsNullOrWhiteSpace($Path) -or -not (Test-Path -LiteralPath $Path)) {
            [System.Windows.Forms.MessageBox]::Show("Choose a plot import spreadsheet first.", "Load plot columns", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
            return $false
        }
        $currentMappings = @{}
        foreach ($mapping in @(Get-PlotImportMappingsFromGrid)) {
            $fieldName = ConvertTo-BuilderText $mapping.FieldName
            if (-not [string]::IsNullOrWhiteSpace($fieldName)) { $currentMappings[$fieldName] = ConvertTo-BuilderText $mapping.SourceColumn }
        }
        $columns = @(Get-TabularColumnNames -Path $Path)
        if ($columns.Count -eq 0) { throw "No column headers were found in the selected Add New Plots file." }
        Set-PlotMappingSourceColumnChoices -Columns $columns
        $plotMappingGrid.Rows.Clear()
        foreach ($spec in Get-PlotImportFieldSpecs) {
            $sourceColumn = ""
            if ($currentMappings.ContainsKey($spec.FieldName) -and $columns -contains $currentMappings[$spec.FieldName]) {
                $sourceColumn = $currentMappings[$spec.FieldName]
            }
            else {
                $sourceColumn = Find-BestPlotImportColumn -Columns $columns -Aliases ([string[]]$spec.Aliases)
            }
            $idx = $plotMappingGrid.Rows.Add()
            $row = $plotMappingGrid.Rows[$idx]
            $row.Cells["FieldName"].Value = $spec.FieldName
            $row.Cells["Required"].Value = if ($spec.Required) { "Yes" } else { "" }
            $row.Cells["SourceColumn"].Value = $sourceColumn
            $row.Cells["Aliases"].Value = [string]::Join(", ", [string[]]$spec.Aliases)
        }
        $plotNumberMapping = @(Get-PlotImportMappingsFromGrid | Where-Object { [string]::Equals((ConvertTo-BuilderText $_.FieldName), "PlotNumber", [System.StringComparison]::OrdinalIgnoreCase) } | Select-Object -First 1)
        $plotNumberSource = if ($plotNumberMapping.Count -gt 0) { ConvertTo-BuilderText $plotNumberMapping[0].SourceColumn } else { "" }
        if ([string]::IsNullOrWhiteSpace($plotNumberSource)) {
            $plotMappingStatusLabel.Text = "Loaded $($columns.Count) spreadsheet column(s). Map PlotNumber before using Next or building."
        }
        else {
            $plotMappingStatusLabel.Text = "Loaded $($columns.Count) spreadsheet column(s). PlotNumber is mapped to '$plotNumberSource'."
        }
        return $true
    }

