    function Add-UpgradeMappingTargetChoiceIfMissing {
        param([string]$Value)

        $clean = ConvertTo-BuilderText $Value
        if ([string]::IsNullOrWhiteSpace($clean)) { return }
        $targetColumn = [System.Windows.Forms.DataGridViewComboBoxColumn]$upgradeMappingGrid.Columns["Target"]
        if (-not $targetColumn.Items.Contains($clean)) {
            [void]$targetColumn.Items.Add($clean)
        }
    }

    function Set-UpgradeMappingTargetChoices {
        param([string[]]$Choices)

        $currentTargets = @()
        foreach ($row in $upgradeMappingGrid.Rows) {
            if ($row.IsNewRow) { continue }
            $target = ConvertTo-BuilderText $row.Cells["Target"].Value
            if (-not [string]::IsNullOrWhiteSpace($target)) { $currentTargets += $target }
        }
        $targetColumn = [System.Windows.Forms.DataGridViewComboBoxColumn]$upgradeMappingGrid.Columns["Target"]
        $targetColumn.Items.Clear()
        [void]$targetColumn.Items.Add("Skip")
        $seenChoices = @{ "skip" = $true }
        foreach ($choice in @($Choices | Where-Object { -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $_)) })) {
            $cleanChoice = ConvertTo-BuilderText $choice
            $choiceKey = $cleanChoice.ToLowerInvariant()
            if ($seenChoices.ContainsKey($choiceKey)) { continue }
            $seenChoices[$choiceKey] = $true
            Add-UpgradeMappingTargetChoiceIfMissing -Value $cleanChoice
        }
        foreach ($target in $currentTargets) {
            Add-UpgradeMappingTargetChoiceIfMissing -Value $target
        }
        foreach ($row in $upgradeMappingGrid.Rows) {
            if ($row.IsNewRow) { continue }
            if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $row.Cells["Target"].Value))) {
                $row.Cells["Target"].Value = "Skip"
            }
        }
    }

    function Get-UpgradeMappingCustomTargetFields {
        $items = New-Object System.Collections.Generic.List[object]
        $seen = @{}
        $addTarget = {
            param(
                [string]$TableName,
                [string]$FieldName,
                [bool]$Active = $true
            )

            if (-not $Active) { return }
            $tableNameText = ConvertTo-BuilderText $TableName
            $fieldNameText = ConvertTo-AccessFieldName $FieldName
            if ([string]::IsNullOrWhiteSpace($tableNameText) -or [string]::IsNullOrWhiteSpace($fieldNameText)) { return }
            if ($tableNameText -notin @("PlotCustomMeasurements", "TreeCustomMeasurements", "RegenCustomMeasurements")) { return }
            $key = "$($tableNameText.ToLowerInvariant()).$($fieldNameText.ToLowerInvariant())"
            if ($seen.ContainsKey($key)) { return }
            $seen[$key] = $true
            [void]$items.Add([pscustomobject]@{
                TableName = $tableNameText
                FieldName = $fieldNameText
            })
        }

        try { Save-LoadedAppColumnGridState } catch {}
        foreach ($item in @($script:BuilderLoadedAppColumnItems)) {
            & $addTarget (ConvertTo-BuilderText $item.TableName) (ConvertTo-BuilderText $item.FieldName) (ConvertTo-BuilderBool $item.Active)
        }
        if ($null -ne $customFieldGrid) {
            foreach ($row in $customFieldGrid.Rows) {
                if ($row.IsNewRow) { continue }
                & $addTarget (ConvertTo-BuilderText $row.Cells["TableName"].Value) (ConvertTo-BuilderText $row.Cells["FieldName"].Value) (ConvertTo-BuilderBool $row.Cells["Active"].Value)
            }
        }
        return @($items.ToArray())
    }

    function Add-UpgradeMappingRowToGrid {
        param([object]$Item)

        $targetText = ConvertTo-BuilderText $Item.Target
        if ([string]::IsNullOrWhiteSpace($targetText)) {
            $itemTargetTable = if ($Item.PSObject.Properties["TargetTable"]) { ConvertTo-BuilderText $Item.TargetTable } else { "" }
            $itemTargetField = if ($Item.PSObject.Properties["TargetField"]) { ConvertTo-BuilderText $Item.TargetField } else { "" }
            if (-not [string]::IsNullOrWhiteSpace($itemTargetTable) -and -not [string]::IsNullOrWhiteSpace($itemTargetField)) {
                $targetText = "$itemTargetTable.$itemTargetField"
            }
            elseif (-not [string]::IsNullOrWhiteSpace($itemTargetTable)) {
                $targetText = $itemTargetTable
            }
            else {
                $targetText = "Skip"
            }
        }
        Add-UpgradeMappingTargetChoiceIfMissing -Value $targetText
        $idx = $upgradeMappingGrid.Rows.Add()
        $row = $upgradeMappingGrid.Rows[$idx]
        $row.Cells["SourceTable"].Value = ConvertTo-BuilderText $Item.SourceTable
        $row.Cells["SourceField"].Value = ConvertTo-BuilderText $Item.SourceField
        $row.Cells["SourceType"].Value = ConvertTo-BuilderText $Item.SourceType
        $row.Cells["Target"].Value = $targetText
        $row.Cells["Notes"].Value = ConvertTo-BuilderText $Item.Notes
        if ([string]::Equals($targetText, "Skip", [System.StringComparison]::OrdinalIgnoreCase) -and [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $row.Cells["Notes"].Value))) {
            $row.Cells["Notes"].Value = "Skipped: this old field will not be added or copied."
        }
    }

    function Get-UpgradeFieldMappingsFromGrid {
        $items = New-Object System.Collections.Generic.List[object]
        $rowNumber = 1
        foreach ($row in $upgradeMappingGrid.Rows) {
            if ($row.IsNewRow) {
                $rowNumber++
                continue
            }
            $sourceTable = ConvertTo-BuilderText $row.Cells["SourceTable"].Value
            $sourceField = ConvertTo-BuilderText $row.Cells["SourceField"].Value
            $targetText = ConvertTo-BuilderText $row.Cells["Target"].Value
            if ([string]::IsNullOrWhiteSpace($targetText) -or [string]::Equals($targetText, "Skip", [System.StringComparison]::OrdinalIgnoreCase)) {
                $rowNumber++
                continue
            }
            if ([string]::IsNullOrWhiteSpace($sourceTable) -or [string]::IsNullOrWhiteSpace($sourceField)) {
                throw "Upgrade Mapping tab: row $rowNumber has a target but no old table/field. Load unmapped fields again or clear the row."
            }
            $target = Split-UpgradeMappingTargetChoice -TargetChoice $targetText
            [void]$items.Add([pscustomobject]@{
                SourceTable = $sourceTable
                SourceField = $sourceField
                TargetTable = ConvertTo-BuilderText $target.TableName
                TargetField = ConvertTo-BuilderText $target.FieldName
                TargetTableOnly = ConvertTo-BuilderBool $target.TableOnly
            })
            $rowNumber++
        }
        return @($items.ToArray())
    }

    function Get-UpgradeMappingRowsForFile {
        $items = New-Object System.Collections.Generic.List[object]
        foreach ($row in $upgradeMappingGrid.Rows) {
            if ($row.IsNewRow) { continue }
            $sourceTable = ConvertTo-BuilderText $row.Cells["SourceTable"].Value
            $sourceField = ConvertTo-BuilderText $row.Cells["SourceField"].Value
            if ([string]::IsNullOrWhiteSpace($sourceTable) -or [string]::IsNullOrWhiteSpace($sourceField)) { continue }
            [void]$items.Add([pscustomobject]@{
                SourceTable = $sourceTable
                SourceField = $sourceField
                SourceType = ConvertTo-BuilderText $row.Cells["SourceType"].Value
                Target = if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $row.Cells["Target"].Value))) { "Skip" } else { ConvertTo-BuilderText $row.Cells["Target"].Value }
                Notes = ConvertTo-BuilderText $row.Cells["Notes"].Value
            })
        }
        return @($items.ToArray())
    }

    function Test-UpgradeMappingModeReady {
        param([string]$ActionTitle = "Upgrade Mapping")

        $selectedMode = Get-WOOFComboText -Combo $modeBox
        if (Test-UpgradeModeText -Mode $selectedMode) { return $true }

        $message = "Upgrade Mapping only runs in Upgrade Project mode.`r`n`r`nSet Project tab > Mode to Upgrade Project, choose the old project database in Existing/old project database, choose the current master database version, then return to this tab."
        $upgradeMappingStatusLabel.Text = "Mode must be Upgrade Project."
        $statusLabel.Text = "Upgrade Mapping needs Upgrade Project mode."
        [System.Windows.Forms.MessageBox]::Show($message, $ActionTitle, [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
        return $false
    }

    $loadUpgradeMappingButton.Add_Click({
        try {
            if (-not (Test-UpgradeMappingModeReady -ActionTitle "Load upgrade mapping")) { return }
            $oldPath = ConvertTo-BuilderText $sourceBox.Text
            $templatePath = ConvertTo-BuilderText $upgradeTemplateBox.Text
            if ([string]::IsNullOrWhiteSpace($oldPath) -or -not (Test-Path -LiteralPath $oldPath)) {
                [System.Windows.Forms.MessageBox]::Show("Choose the old project database in Existing/old project database first.", "Load upgrade mapping", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
                return
            }
            if ([string]::IsNullOrWhiteSpace($templatePath) -or -not (Test-Path -LiteralPath $templatePath)) {
                [System.Windows.Forms.MessageBox]::Show("Choose the current master database version first.", "Load upgrade mapping", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
                return
            }
            $customTargets = @(Get-UpgradeMappingCustomTargetFields)
            $statusLabel.Text = "Loading upgrade field mapping choices..."
            [System.Windows.Forms.Application]::DoEvents()
            $oldConnection = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $oldPath)
            $templateConnection = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $templatePath)
            try {
                $choices = @(Get-UpgradeMappingTargetChoices -TargetConnection $templateConnection -CustomFields $customTargets)
                Set-UpgradeMappingTargetChoices -Choices ([string[]]$choices)
                $items = @(Get-UpgradeFieldMappingSuggestions -SourceConnection $oldConnection -TargetConnection $templateConnection -CustomFields $customTargets)
                $upgradeMappingGrid.Rows.Clear()
                foreach ($item in $items) {
                    Add-UpgradeMappingRowToGrid -Item $item
                }
                $upgradeMappingStatusLabel.Text = "Loaded $($items.Count) old field(s) needing review."
                $statusLabel.Text = "Upgrade mapping loaded."
                [System.Windows.Forms.MessageBox]::Show("Loaded $($items.Count) old field(s) needing review. Project Pickle preselects likely targets when it can: old Plots.HabitatType goes to PlotMeasurements.HabitatType; old FieldOverCover, FieldOverDensity, and FieldOverSize go to PlotMeasurements.CoverType, DensityClass, and SizeClass; old ForestClassification goes to Plots.FLCCommercial; old tree measurement extras go to TreeCustomMeasurements; old plot/plot measurement extras go to PlotCustomMeasurements; and old remark fields are mapped to the new remarks fields. Fields named NeedsReview and common standard fields are skipped. Choose table.field only when the old field should be renamed. Leave fields as Skip when they should not carry forward. Mapping only makes sure fields and data carry into the new database; it does not set up or activate AppColumns. Save mapping is optional; Build uses the grid whether or not you save it. Click Check data types before building to catch old Text fields mapped to new Integer, Date, Boolean, or ID fields. Example: if old HabitatType is Text and the current master database version HabitatType is Long Integer, crosswalk/convert HabitatType before building, or change the target to a Text custom measurement field so the old text can be crosswalked later.", "Load upgrade mapping", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
            }
            finally {
                if ($oldConnection.State -eq "Open") { $oldConnection.Close() }
                if ($templateConnection.State -eq "Open") { $templateConnection.Close() }
                $oldConnection.Dispose()
                $templateConnection.Dispose()
            }
        }
        catch {
            $statusLabel.Text = "Could not load upgrade mapping."
            [System.Windows.Forms.MessageBox]::Show($_.Exception.Message, "Load upgrade mapping failed", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
        }
    })

    $checkUpgradeMappingTypesButton.Add_Click({
        try {
            if (-not (Test-UpgradeMappingModeReady -ActionTitle "Check data types")) { return }
            $oldPath = ConvertTo-BuilderText $sourceBox.Text
            $templatePath = ConvertTo-BuilderText $upgradeTemplateBox.Text
            if ([string]::IsNullOrWhiteSpace($oldPath) -or -not (Test-Path -LiteralPath $oldPath)) {
                [System.Windows.Forms.MessageBox]::Show("Choose the old project database in Existing/old project database first.", "Check data types", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
                return
            }
            if ([string]::IsNullOrWhiteSpace($templatePath) -or -not (Test-Path -LiteralPath $templatePath)) {
                [System.Windows.Forms.MessageBox]::Show("Choose the current master database version first.", "Check data types", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
                return
            }
            $statusLabel.Text = "Checking upgrade data types..."
            [System.Windows.Forms.Application]::DoEvents()
            $mappings = @(Get-UpgradeFieldMappingsFromGrid)
            $customRows = @(Get-CustomRowsFromGrid)
            $reviewItems = @(Get-UpgradeDataTypeReview -OldDatabasePath $oldPath -TemplateDatabasePath $templatePath -FieldMappings $mappings -CustomFields $customRows)
            if ($reviewItems.Count -eq 0) {
                $upgradeMappingStatusLabel.Text = "No datatype issues found."
                $statusLabel.Text = "Upgrade data type check passed."
                [System.Windows.Forms.MessageBox]::Show("No risky datatype changes were found. Project Pickle did not find old fields being sent into incompatible current master database version or mapping targets.", "Check data types", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
                return
            }

            $errors = @($reviewItems | Where-Object { [int]$_.BadCount -gt 0 })
            $warnings = @($reviewItems | Where-Object { [int]$_.BadCount -eq 0 })
            $lines = New-Object System.Collections.Generic.List[string]
            [void]$lines.Add("Found $($errors.Count) datatype issue(s) and $($warnings.Count) type-change warning(s).")
            [void]$lines.Add("Project Pickle will stop the build until these are resolved.")
            [void]$lines.Add("")
            if ($errors.Count -gt 0) {
                [void]$lines.Add("Values that will not fit the selected target:")
                foreach ($item in @($errors | Select-Object -First 18)) {
                    [void]$lines.Add("- " + (Format-UpgradeDataTypeReviewLine -Item $item))
                }
                if ($errors.Count -gt 18) { [void]$lines.Add("- ...and $($errors.Count - 18) more issue(s).") }
                [void]$lines.Add("")
            }
            if ($warnings.Count -gt 0) {
                [void]$lines.Add("Type changes that need review/crosswalk even if current values look convertible:")
                foreach ($item in @($warnings | Select-Object -First 12)) {
                    [void]$lines.Add("- " + (Format-UpgradeDataTypeReviewLine -Item $item))
                }
                if ($warnings.Count -gt 12) { [void]$lines.Add("- ...and $($warnings.Count - 12) more warning(s).") }
                [void]$lines.Add("")
            }
            [void]$lines.Add("Best fixes: crosswalk/convert the old field before building, choose a Text/Memo target, or map to a new custom field that uses the old field's data type.")
            [void]$lines.Add("Example: old HabitatType Text should be converted to the new HabitatType integer code before upgrade. If the crosswalk is not ready, map the old HabitatType to PlotCustomMeasurements by table name or to another Text custom field so the old text is preserved for later.")
            $message = [string]::Join("`r`n", [string[]]$lines.ToArray())
            $upgradeMappingStatusLabel.Text = "Datatype check: $($errors.Count) issue(s), $($warnings.Count) warning(s)."
            $statusLabel.Text = "Upgrade data type check complete."
            $icon = [System.Windows.Forms.MessageBoxIcon]::Warning
            [System.Windows.Forms.MessageBox]::Show($message, "Check data types", [System.Windows.Forms.MessageBoxButtons]::OK, $icon) | Out-Null
        }
        catch {
            $statusLabel.Text = "Upgrade data type check failed."
            [System.Windows.Forms.MessageBox]::Show($_.Exception.Message, "Check data types failed", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
        }
    })

    $clearUpgradeMappingButton.Add_Click({
        $upgradeMappingGrid.Rows.Clear()
        $upgradeMappingStatusLabel.Text = "No upgrade field mappings loaded."
        $statusLabel.Text = "Upgrade mapping cleared."
    })

    $saveUpgradeMappingButton.Add_Click({
        $dialog = New-Object System.Windows.Forms.SaveFileDialog
        $dialog.Filter = "Project Pickle upgrade mapping (*.json)|*.json|All files (*.*)|*.*"
        $dialog.DefaultExt = "json"
        $dialog.AddExtension = $true
        $dialog.FileName = "ProjectPickle-upgrade-field-mapping.json"
        try {
            if ($dialog.ShowDialog($form) -ne [System.Windows.Forms.DialogResult]::OK) { return }
            $rows = @(Get-UpgradeMappingRowsForFile)
            $rows | ConvertTo-Json -Depth 6 | Set-Content -LiteralPath $dialog.FileName -Encoding UTF8
            $statusLabel.Text = "Upgrade mapping saved."
        }
        catch {
            [System.Windows.Forms.MessageBox]::Show($_.Exception.Message, "Save upgrade mapping failed", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
        }
        finally {
            $dialog.Dispose()
        }
    })

    $loadUpgradeMappingFileButton.Add_Click({
        if (-not (Test-UpgradeMappingModeReady -ActionTitle "Load saved mapping file")) { return }
        $dialog = New-Object System.Windows.Forms.OpenFileDialog
        $dialog.Filter = "Project Pickle upgrade mapping (*.json)|*.json|All files (*.*)|*.*"
        try {
            if ($dialog.ShowDialog($form) -ne [System.Windows.Forms.DialogResult]::OK) { return }
            $loaded = @(Get-Content -LiteralPath $dialog.FileName -Raw | ConvertFrom-Json)
            foreach ($item in $loaded) {
                $targetText = ConvertTo-BuilderText $item.Target
                if (-not [string]::IsNullOrWhiteSpace($targetText)) { Add-UpgradeMappingTargetChoiceIfMissing -Value $targetText }
            }
            $upgradeMappingGrid.Rows.Clear()
            foreach ($item in $loaded) {
                Add-UpgradeMappingRowToGrid -Item $item
            }
            $upgradeMappingStatusLabel.Text = "Loaded $($loaded.Count) saved mapping row(s)."
            $statusLabel.Text = "Saved upgrade mapping file loaded."
        }
        catch {
            [System.Windows.Forms.MessageBox]::Show($_.Exception.Message, "Load saved mapping file failed", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
        }
        finally {
            $dialog.Dispose()
        }
    })

    $updateUpgradeMappingModeCue = {
        $enabled = Test-UpgradeModeText -Mode (Get-WOOFComboText -Combo $modeBox)
        $upgradeMappingPage.Tag = if ($enabled) { "" } else { "Disabled" }
        $upgradeMappingPage.BackColor = if ($enabled) { $uiTheme.AppBack } else { $uiTheme.SoftSurface }
        foreach ($control in $upgradeMappingPage.Controls) {
            $control.Enabled = $enabled
        }
        if ($enabled) {
            if ([string]::Equals((ConvertTo-BuilderText $upgradeMappingStatusLabel.Text), "Mode must be Upgrade Project.", [System.StringComparison]::OrdinalIgnoreCase)) {
                $upgradeMappingStatusLabel.Text = "Upgrade mode selected. Load unmapped fields when ready."
            }
        }
        else {
            $upgradeMappingStatusLabel.Text = "Mode must be Upgrade Project."
            if ($tabs.SelectedTab -eq $upgradeMappingPage) {
                $tabs.SelectedTab = $plotPage
                $statusLabel.Text = "Upgrade Mapping is only available in Upgrade Project mode."
            }
        }
        try { $tabs.Invalidate() } catch {}
    }.GetNewClosure()
    $modeBox.Add_SelectedIndexChanged({ & $updateUpgradeMappingModeCue }.GetNewClosure())
    & $updateUpgradeMappingModeCue

    $tabs.TabPages.Remove($upgradeMappingPage)
    $periodTabIndex = $tabs.TabPages.IndexOf($optionsPage)
    if ($periodTabIndex -ge 0) {
        $tabs.TabPages.Insert($periodTabIndex + 1, $upgradeMappingPage)
    }
    else {
        [void]$tabs.TabPages.Add($upgradeMappingPage)
    }
    $tabs.Add_Selecting({
        param($Sender, $EventArgs)
        if ($EventArgs.TabPage -eq $upgradeMappingPage -and -not (Test-UpgradeModeText -Mode (Get-WOOFComboText -Combo $modeBox))) {
            $EventArgs.Cancel = $true
            $statusLabel.Text = "Upgrade Mapping is only available in Upgrade Project mode."
        }
    }.GetNewClosure())

