                $columnName = ConvertTo-BuilderText $Sender.Columns[$EventArgs.ColumnIndex].Name
            }
            $rowText = if ($EventArgs.RowIndex -ge 0) { [string]$EventArgs.RowIndex } else { "unknown" }
            $message = if ($null -eq $EventArgs.Exception) { "Unknown AppColumns grid data error." } else { $EventArgs.Exception.ToString() }
            [void](Write-ProjectPickleDiagnosticLog -Message $message -Context "Loaded AppColumns grid data error (row $rowText, column $columnName)")
            $EventArgs.ThrowException = $false
            $statusLabel.Text = "Project Pickle skipped one AppColumns display issue. See ProjectPickle.Diagnostics.txt for details."
