        if ($fieldGrid.IsCurrentCellDirty) {
            [void]$fieldGrid.CommitEdit([System.Windows.Forms.DataGridViewDataErrorContexts]::Commit)
        }
    })
    $customFieldGrid.Add_CurrentCellDirtyStateChanged({
        if ($customFieldGrid.IsCurrentCellDirty) {
            [void]$customFieldGrid.CommitEdit([System.Windows.Forms.DataGridViewDataErrorContexts]::Commit)
        }
    })
    $script:ProjectPickleCustomAppColumnDeleteApproved = $false
    $customFieldGrid.Add_UserDeletingRow({
        param($Sender, $EventArgs)

        if ($script:ProjectPickleCustomAppColumnDeleteApproved) { return }
        $rowCount = 1
        try {
            $selectedRows = @($Sender.SelectedRows | Where-Object { -not $_.IsNewRow })
            if ($selectedRows.Count -gt 0) { $rowCount = $selectedRows.Count }
        }
        catch {
            $rowCount = 1
        }

        $fieldName = ""
        try {
            if ($null -ne $EventArgs.Row -and $Sender.Columns.Contains("FieldName")) {
                $fieldName = ConvertTo-BuilderText $EventArgs.Row.Cells["FieldName"].Value
            }
        }
        catch {
            $fieldName = ""
        }

        $targetText = if ($rowCount -gt 1) {
            "$rowCount selected new custom AppColumns rows"
        }
        elseif ([string]::IsNullOrWhiteSpace($fieldName)) {
            "this selected new custom AppColumns row"
        }
        else {
            "the new custom AppColumns row '$fieldName'"
        }

        $message = "Delete $targetText from the setup list?`r`n`r`nThis only removes the row from this Project Pickle run. It does not remove a field from any database that has already been built."
        $answer = [System.Windows.Forms.MessageBox]::Show($message, "Delete custom AppColumns row?", [System.Windows.Forms.MessageBoxButtons]::YesNo, [System.Windows.Forms.MessageBoxIcon]::Warning)
        if ($answer -ne [System.Windows.Forms.DialogResult]::Yes) {
            $EventArgs.Cancel = $true
            return
        }

        $script:ProjectPickleCustomAppColumnDeleteApproved = $true
        try {
            [void]$Sender.BeginInvoke([System.Action]{ $script:ProjectPickleCustomAppColumnDeleteApproved = $false })
        }
        catch {
            $script:ProjectPickleCustomAppColumnDeleteApproved = $false
        }
    })
    function Show-AppColumnCodesEditor {
        param(
            [System.Windows.Forms.DataGridView]$Grid,
            [string]$BoxName
        )

        if ([bool]$copyAppColumnsCheck.Checked) {
            [System.Windows.Forms.MessageBox]::Show(
                "Copy AppColumns from existing database is checked, so AppColumns code editing is disabled for this build. Uncheck it to manually edit AppColumns.",
                "AppColumns copy mode",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information
            ) | Out-Null
            return
        }
        if ($null -eq $Grid -or $null -eq $Grid.CurrentRow -or $Grid.CurrentRow.IsNewRow) {
            [System.Windows.Forms.MessageBox]::Show("Select one AppColumns row first, then click Edit selected codes.", "Edit codes", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
            return
        }
        if (-not $Grid.Columns.Contains("Codes")) { return }
        try { $Grid.EndEdit() } catch {}
        $row = $Grid.CurrentRow
        $fieldName = ConvertTo-BuilderText $row.Cells["FieldName"].Value
        $titleField = if ([string]::IsNullOrWhiteSpace($fieldName)) { "selected field" } else { $fieldName }

        $dialog = New-Object System.Windows.Forms.Form
        $dialog.Text = "Edit codes - $titleField"
        $dialog.StartPosition = "CenterParent"
        $dialog.Size = New-Object System.Drawing.Size(760, 560)
        $dialog.MinimizeBox = $false
        $dialog.MaximizeBox = $false
        $dialog.ShowIcon = $true
        try { $dialog.Icon = $form.Icon } catch {}

        $help = New-Object System.Windows.Forms.Label
        $help.Text = "Use one code per line or semicolon-separated pairs. Examples: 1=Live, 2=Dead, 9=Unknown. Labels may contain spaces."
        $help.Location = New-Object System.Drawing.Point(12, 12)
        $help.Size = New-Object System.Drawing.Size(720, 36)
        $dialog.Controls.Add($help)

        $textBox = New-Object System.Windows.Forms.TextBox
        $textBox.Location = New-Object System.Drawing.Point(12, 54)
        $textBox.Size = New-Object System.Drawing.Size(720, 410)
        $textBox.Anchor = "Top,Left,Right,Bottom"
        $textBox.Multiline = $true
        $textBox.ScrollBars = "Both"
        $textBox.AcceptsReturn = $true
        $textBox.AcceptsTab = $true
        $textBox.WordWrap = $false
        $textBox.Font = New-Object System.Drawing.Font("Consolas", 10)
        $textBox.Text = ConvertTo-AppColumnCodesEditorText $row.Cells["Codes"].Value
        $dialog.Controls.Add($textBox)

        $okButton = New-Object System.Windows.Forms.Button
        $okButton.Text = "OK"
        $okButton.Location = New-Object System.Drawing.Point(560, 478)
        $okButton.Size = New-Object System.Drawing.Size(80, 28)
        $okButton.Anchor = "Right,Bottom"
        $okButton.DialogResult = [System.Windows.Forms.DialogResult]::OK
        $dialog.AcceptButton = $okButton
        $dialog.Controls.Add($okButton)

        $cancelButton = New-Object System.Windows.Forms.Button
        $cancelButton.Text = "Cancel"
        $cancelButton.Location = New-Object System.Drawing.Point(650, 478)
        $cancelButton.Size = New-Object System.Drawing.Size(80, 28)
        $cancelButton.Anchor = "Right,Bottom"
        $cancelButton.DialogResult = [System.Windows.Forms.DialogResult]::Cancel
        $dialog.CancelButton = $cancelButton
        $dialog.Controls.Add($cancelButton)

        try {
            if ($dialog.ShowDialog($form) -eq [System.Windows.Forms.DialogResult]::OK) {
                $row.Cells["Codes"].Value = ConvertTo-AppColumnCodesCellText $textBox.Text
                $statusLabel.Text = "Updated Codes text for $BoxName row: $titleField"
            }
        }
        finally {
            $dialog.Dispose()
        }
    }
    $editLoadedCodesButton.Add_Click({ Show-AppColumnCodesEditor -Grid $fieldGrid -BoxName "loaded AppColumns" })
    $editCustomCodesButton.Add_Click({ Show-AppColumnCodesEditor -Grid $customFieldGrid -BoxName "new custom AppColumns" })
    $fieldGrid.Add_CellDoubleClick({
