    function Sync-AppColumnActiveOutputs {
        param(
            [System.Windows.Forms.DataGridView]$Grid,
            [System.Windows.Forms.DataGridViewRow]$Row
        )

        if ($null -eq $Grid -or $null -eq $Row -or $Row.IsNewRow) { return }
        if (-not $Grid.Columns.Contains("Active")) { return }
        $isActive = ConvertTo-BuilderBool $Row.Cells["Active"].Value
        if ($Grid.Columns.Contains("Collected")) { $Row.Cells["Collected"].Value = $isActive }
        if ($Grid.Columns.Contains("ReportVisible")) { $Row.Cells["ReportVisible"].Value = $isActive }
        if ($Grid.Columns.Contains("QueryVisible")) { $Row.Cells["QueryVisible"].Value = $isActive }
    }
    foreach ($grid in @($fieldGrid, $customFieldGrid)) {
        $grid.Add_CellValueChanged({
            param($Sender, $EventArgs)
            if ($script:ProjectPickleIsRefreshingLoadedAppColumns -and $Sender -eq $fieldGrid) { return }
            if ($EventArgs.RowIndex -lt 0 -or $EventArgs.ColumnIndex -lt 0) { return }
            if (-not $Sender.Columns.Contains("Active")) { return }
            if ($Sender.Columns[$EventArgs.ColumnIndex].Name -ne "Active") { return }
            Sync-AppColumnActiveOutputs -Grid $Sender -Row $Sender.Rows[$EventArgs.RowIndex]
        })
    }
    $customFieldGrid.Add_DefaultValuesNeeded({
        param($Sender, $EventArgs)
        $EventArgs.Row.Cells["Active"].Value = $true
        $EventArgs.Row.Cells["Collected"].Value = $true
        $EventArgs.Row.Cells["ArchiveOnly"].Value = $false
        $EventArgs.Row.Cells["ReportVisible"].Value = $true
        $EventArgs.Row.Cells["QueryVisible"].Value = $true
    })
        $setAppColumnsCopyModeUiState = {
        $copyMode = [bool]$copyAppColumnsCheck.Checked
        $manualAppColumnsEnabled = -not $copyMode

        foreach ($button in @(
            $loadAppColumnsButton,
            $editLoadedCodesButton,
            $copyLoadedToCustomButton,
            $editCustomCodesButton
        )) {
            if ($null -ne $button) {
                $button.Enabled = $manualAppColumnsEnabled
                $button.BackColor = if ($manualAppColumnsEnabled) { $uiTheme.Surface } else { $uiTheme.SoftSurface }
                $button.ForeColor = if ($manualAppColumnsEnabled) { $uiTheme.Text } else { $uiTheme.MutedText }
            }
        }

        if ($null -ne $fieldGrid) {
            $fieldGrid.ReadOnly = $copyMode
            $fieldGrid.BackgroundColor = if ($copyMode) { $uiTheme.SoftSurface } else { $uiTheme.Surface }
            $fieldGrid.DefaultCellStyle.BackColor = if ($copyMode) { $uiTheme.SoftSurface } else { $uiTheme.Surface }
            $fieldGrid.DefaultCellStyle.ForeColor = if ($copyMode) { $uiTheme.MutedText } else { $uiTheme.Text }

            foreach ($columnName in @("Source", "AppColumnID", "LoadedFromAppColumns", "StandardCode", "TableName")) {
                if ($fieldGrid.Columns.Contains($columnName)) {
                    $fieldGrid.Columns[$columnName].ReadOnly = $true
                }
            }
        }

        if ($null -ne $customFieldGrid) {
            $customFieldGrid.ReadOnly = $copyMode
            $customFieldGrid.AllowUserToAddRows = $manualAppColumnsEnabled
            $customFieldGrid.AllowUserToDeleteRows = $manualAppColumnsEnabled
            $customFieldGrid.BackgroundColor = if ($copyMode) { $uiTheme.SoftSurface } else { $uiTheme.Surface }
            $customFieldGrid.DefaultCellStyle.BackColor = if ($copyMode) { $uiTheme.SoftSurface } else { $uiTheme.Surface }
            $customFieldGrid.DefaultCellStyle.ForeColor = if ($copyMode) { $uiTheme.MutedText } else { $uiTheme.Text }

            foreach ($columnName in @("Source", "AppColumnID", "LoadedFromAppColumns")) {
                if ($customFieldGrid.Columns.Contains($columnName)) {
                    $customFieldGrid.Columns[$columnName].ReadOnly = $true
                }
            }
        }

        if ($copyMode) {
            $statusLabel.Text = "Copy AppColumns from existing database is on. Manual AppColumns loading and editing are locked for this build."
        }
    }.GetNewClosure()

    $copyAppColumnsCheck.Add_CheckedChanged({
        & $setAppColumnsCopyModeUiState
    }.GetNewClosure())

    & $setAppColumnsCopyModeUiState
    function Add-ComboItemIfMissing {
        param(
            [System.Windows.Forms.DataGridViewComboBoxColumn]$Column,
            [string]$Value
        )

        $clean = ConvertTo-BuilderText $Value
        if ([string]::IsNullOrWhiteSpace($clean)) { return }
        if (-not $Column.Items.Contains($clean)) {
            [void]$Column.Items.Add($clean)
        }
    }

    function Add-AppColumnRowToGrid {
        param([object]$Item)

        Add-ComboItemIfMissing -Column $dataTypeColumn -Value $Item.DataType
        Add-ComboItemIfMissing -Column $categoryColumn -Value $Item.Category

        $idx = $fieldGrid.Rows.Add(@(
            (ConvertTo-BuilderText $Item.Source),
            (ConvertTo-BuilderText $Item.AppColumnID),
            (ConvertTo-BuilderBool $Item.LoadedFromAppColumns),
            (ConvertTo-BuilderBool $Item.StandardCode),
            (ConvertTo-BuilderText $Item.TableName),
            (ConvertTo-BuilderText $Item.FieldName),
            $(if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Item.DataType))) { "Text" } else { ConvertTo-BuilderText $Item.DataType }),
            $(if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Item.Category))) { "Range" } else { ConvertTo-BuilderText $Item.Category }),
            (ConvertTo-BuilderText $Item.FriendlyName),
            (ConvertTo-BuilderText $Item.ShortName),
            (ConvertTo-BuilderText $Item.Description),
            (ConvertTo-BuilderText $Item.ValidationAbrv),
            (ConvertTo-AppColumnCodesCellText $Item.Codes),
            (ConvertTo-BuilderBool $Item.Active),
            (ConvertTo-BuilderBool $Item.DisplayRule),
            (ConvertTo-BuilderBool $Item.ReportVisible),
            (ConvertTo-BuilderBool $Item.QueryVisible),
            (ConvertTo-BuilderBool $Item.Active),
            $false
        ))
        $row = $fieldGrid.Rows[$idx]
        $row.DefaultCellStyle.BackColor = [System.Drawing.Color]::FromArgb(248, 250, 252)
        $row.DefaultCellStyle.ForeColor = $uiTheme.Text
        $row.DefaultCellStyle.SelectionForeColor = $uiTheme.Text
        if ($idx -eq 0) {
            try {
                [void](Write-ProjectPickleDiagnosticLog -Message ("First row immediately after Add-AppColumnRowToGrid -> Source='{0}', TableName='{1}', FieldName='{2}', DataType='{3}', Category='{4}', FriendlyName='{5}'" -f `
                    (ConvertTo-BuilderText $row.Cells["Source"].Value), `
                    (ConvertTo-BuilderText $row.Cells["TableName"].Value), `
                    (ConvertTo-BuilderText $row.Cells["FieldName"].Value), `
                    (ConvertTo-BuilderText $row.Cells["DataType"].Value), `
                    (ConvertTo-BuilderText $row.Cells["Category"].Value), `
                    (ConvertTo-BuilderText $row.Cells["FriendlyName"].Value)) -Context "Add AppColumns row")
            }
            catch {
            }
        }
    }

    function Get-CustomAppTableForLoadedTable {
        param([string]$TableName)

        $clean = ConvertTo-BuilderText $TableName
        switch ($clean) {
            "PlotMeasurements" { return "PlotCustomMeasurements" }
            "TreeMeasurements" { return "TreeCustomMeasurements" }
            "RegenMeasurements" { return "RegenCustomMeasurements" }
            "PlotCustomMeasurements" { return "PlotCustomMeasurements" }
            "TreeCustomMeasurements" { return "TreeCustomMeasurements" }
            "RegenCustomMeasurements" { return "RegenCustomMeasurements" }
            default { return "PlotCustomMeasurements" }
        }
    }

    function Get-AppColumnItemFromGridRow {
        param([System.Windows.Forms.DataGridViewRow]$Row)

        if ($null -eq $Row -or $Row.IsNewRow) { return $null }
        return [pscustomobject]@{
            Source = ConvertTo-BuilderText $Row.Cells["Source"].Value
            AppColumnID = ConvertTo-BuilderText $Row.Cells["AppColumnID"].Value
            LoadedFromAppColumns = ConvertTo-BuilderBool $Row.Cells["LoadedFromAppColumns"].Value
            StandardCode = ConvertTo-BuilderBool $Row.Cells["StandardCode"].Value
            TableName = ConvertTo-BuilderText $Row.Cells["TableName"].Value
            FieldName = ConvertTo-BuilderText $Row.Cells["FieldName"].Value
            DataType = ConvertTo-BuilderText $Row.Cells["DataType"].Value
            Category = ConvertTo-BuilderText $Row.Cells["Category"].Value
            FriendlyName = ConvertTo-BuilderText $Row.Cells["FriendlyName"].Value
            ShortName = ConvertTo-BuilderText $Row.Cells["ShortName"].Value
            Description = ConvertTo-BuilderText $Row.Cells["Description"].Value
            ValidationAbrv = ConvertTo-BuilderText $Row.Cells["ValidationAbrv"].Value
            Codes = ConvertTo-AppColumnCodesCellText $Row.Cells["Codes"].Value
            Active = ConvertTo-BuilderBool $Row.Cells["Active"].Value
            Collected = ConvertTo-BuilderBool $Row.Cells["Active"].Value
            ArchiveOnly = $false
            DisplayRule = ConvertTo-BuilderBool $Row.Cells["DisplayRule"].Value
            ReportVisible = ConvertTo-BuilderBool $Row.Cells["ReportVisible"].Value
            QueryVisible = ConvertTo-BuilderBool $Row.Cells["QueryVisible"].Value
        }
    }

    function Save-LoadedAppColumnGridState {
        if ($null -eq $script:BuilderLoadedAppColumnItems -or @($script:BuilderLoadedAppColumnItems).Count -eq 0) { return }
        try { $fieldGrid.EndEdit() } catch {}
        $byId = @{}
        foreach ($item in @($script:BuilderLoadedAppColumnItems)) {
            $id = ConvertTo-BuilderText $item.AppColumnID
            if (-not [string]::IsNullOrWhiteSpace($id)) { $byId[$id] = $item }
        }
        foreach ($row in $fieldGrid.Rows) {
            if ($row.IsNewRow) { continue }
            $gridItem = Get-AppColumnItemFromGridRow -Row $row
            if ($null -eq $gridItem) { continue }
            $id = ConvertTo-BuilderText $gridItem.AppColumnID
            if (-not $byId.ContainsKey($id)) { continue }
            $item = $byId[$id]
            foreach ($propName in @("Source", "LoadedFromAppColumns", "StandardCode", "TableName", "FieldName", "DataType", "Category", "FriendlyName", "ShortName", "Description", "ValidationAbrv", "Codes", "Active", "DisplayRule", "ReportVisible", "QueryVisible")) {
                $item.$propName = $gridItem.$propName
            }
            $item.Collected = ConvertTo-BuilderBool $gridItem.Active
            $item.ArchiveOnly = $false
        }
    }

    function Refresh-LoadedAppColumnGrid {
        param([switch]$SkipSave)

        if (-not $SkipSave) { Save-LoadedAppColumnGridState }
        $filter = ConvertTo-BuilderText $loadedFilterBox.SelectedItem
        $dataFilter = ConvertTo-BuilderText $loadedDataFilterBox.SelectedItem
        $fieldSearch = ConvertTo-BuilderText $loadedFieldSearchBox.Text
        $script:ProjectPickleIsRefreshingLoadedAppColumns = $true
        $fieldGrid.SuspendLayout()
        try {
            $fieldGrid.Rows.Clear()
            foreach ($item in @($script:BuilderLoadedAppColumnItems)) {
                $isActive = ConvertTo-BuilderBool $item.Active
                if ($filter -eq "Active only" -and -not $isActive) { continue }
                if ($filter -eq "Inactive only" -and $isActive) { continue }
                $dataGroup = Get-AppColumnsReviewDataGroup -TableName $item.TableName
                if ($dataFilter -eq "Plot data" -and $dataGroup -ne "Plot") { continue }
                if ($dataFilter -eq "Tree data" -and $dataGroup -ne "Tree") { continue }
                if ($dataFilter -eq "Regen data" -and $dataGroup -ne "Regen") { continue }
                if (-not [string]::IsNullOrWhiteSpace($fieldSearch)) {
                    $fieldName = ConvertTo-BuilderText $item.FieldName
                    if ($fieldName.IndexOf($fieldSearch, [System.StringComparison]::OrdinalIgnoreCase) -lt 0) { continue }
                }
                Add-AppColumnRowToGrid -Item $item
            }
            if ($fieldGrid.Rows.Count -gt 0) {
                $firstRow = $fieldGrid.Rows[0]
                try {
                    [void](Write-ProjectPickleDiagnosticLog -Message ("First loaded grid row -> Source='{0}', TableName='{1}', FieldName='{2}', DataType='{3}', Category='{4}', FriendlyName='{5}'" -f `
                        (ConvertTo-BuilderText $firstRow.Cells["Source"].Value), `
                        (ConvertTo-BuilderText $firstRow.Cells["TableName"].Value), `
                        (ConvertTo-BuilderText $firstRow.Cells["FieldName"].Value), `
                        (ConvertTo-BuilderText $firstRow.Cells["DataType"].Value), `
                        (ConvertTo-BuilderText $firstRow.Cells["Category"].Value), `
                        (ConvertTo-BuilderText $firstRow.Cells["FriendlyName"].Value)) -Context "Refresh loaded AppColumns grid")
                }
                catch {
                }
            }
        }
        finally {
            $script:ProjectPickleIsRefreshingLoadedAppColumns = $false
            $fieldGrid.ResumeLayout()
        }
    }

    function Add-CustomAppColumnRowToGrid {
        param([object]$Item)

        Add-ComboItemIfMissing -Column $customTableColumn -Value $Item.TableName
        Add-ComboItemIfMissing -Column $customDataTypeColumn -Value $Item.DataType
        Add-ComboItemIfMissing -Column $customCategoryColumn -Value $Item.Category

        $idx = $customFieldGrid.Rows.Add()
        $row = $customFieldGrid.Rows[$idx]
        $row.Cells["Source"].Value = "New"
        $row.Cells["AppColumnID"].Value = ""
        $row.Cells["LoadedFromAppColumns"].Value = $false
        $row.Cells["TableName"].Value = ConvertTo-BuilderText $Item.TableName
        $row.Cells["FieldName"].Value = ConvertTo-BuilderText $Item.FieldName
        $row.Cells["DataType"].Value = if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Item.DataType))) { "Text" } else { ConvertTo-BuilderText $Item.DataType }
        $row.Cells["Category"].Value = if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $Item.Category))) { "Range" } else { ConvertTo-BuilderText $Item.Category }
        $row.Cells["FriendlyName"].Value = ConvertTo-BuilderText $Item.FriendlyName
        $row.Cells["ShortName"].Value = ConvertTo-BuilderText $Item.ShortName
        $row.Cells["Description"].Value = ConvertTo-BuilderText $Item.Description
        $row.Cells["ValidationAbrv"].Value = ConvertTo-BuilderText $Item.ValidationAbrv
        $row.Cells["Codes"].Value = ConvertTo-AppColumnCodesCellText $Item.Codes
        $row.Cells["Active"].Value = if ($Item.PSObject.Properties["Active"]) { ConvertTo-BuilderBool $Item.Active } else { $true }
        $row.Cells["Collected"].Value = ConvertTo-BuilderBool $row.Cells["Active"].Value
        $row.Cells["ArchiveOnly"].Value = $false
        $row.Cells["DisplayRule"].Value = ConvertTo-BuilderBool $Item.DisplayRule
        $row.Cells["ReportVisible"].Value = if ($Item.PSObject.Properties["ReportVisible"]) { ConvertTo-BuilderBool $Item.ReportVisible } else { $true }
        $row.Cells["QueryVisible"].Value = if ($Item.PSObject.Properties["QueryVisible"]) { ConvertTo-BuilderBool $Item.QueryVisible } else { $true }
    }

