    if ($null -eq $script:ProjectPickleAppColumnsLoadCache) {
        $script:ProjectPickleAppColumnsLoadCache = @{}
    }
    $script:ProjectPickleAppColumnsLoadState = $null
    $script:ProjectPickleIsRefreshingLoadedAppColumns = $false

    $loadAppColumnsButton.Add_Click({
        try {
                if ([bool]$copyAppColumnsCheck.Checked) {
                [System.Windows.Forms.MessageBox]::Show(
                    "Copy AppColumns from existing database is checked, so Load Standard AppColumn is disabled for this build. Uncheck it to manually load or edit AppColumns.",
                    "AppColumns copy mode",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Information
                ) | Out-Null
                & $setAppColumnsCopyModeUiState
                return

            }
            if ($script:ProjectPickleAppColumnsLoadState -and -not $script:ProjectPickleAppColumnsLoadState.Completed) {
                $statusLabel.Text = "Standard AppColumns are still loading..."
                return
            }
            $selectedMode = Get-WOOFComboText -Combo $modeBox
            $isSelectedUpgradeMode = Test-UpgradeModeText -Mode $selectedMode
            $usesCurrentMasterDatabase = Test-ModeUsesCurrentMasterDatabase -Mode $selectedMode
            $path = if ($usesCurrentMasterDatabase) { ConvertTo-BuilderText $upgradeTemplateBox.Text } else { ConvertTo-BuilderText $sourceBox.Text }
            if ([string]::IsNullOrWhiteSpace($path) -or -not (Test-Path -LiteralPath $path)) {
                $missingMessage = if ($usesCurrentMasterDatabase) { "Choose the current master database version on the Project tab first, then click Load Standard AppColumn again." } else { "Choose the Existing/old project database on the Project tab first, then click Load Standard AppColumn again." }
                [System.Windows.Forms.MessageBox]::Show($missingMessage, "Load Standard AppColumn", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
                return
            }

            $hasRows = $false
            foreach ($row in $fieldGrid.Rows) {
                if (-not $row.IsNewRow) {
                    $hasRows = $true
                    break
                }
            }
            if ($hasRows) {
                $answer = [System.Windows.Forms.MessageBox]::Show("Loading Standard AppColumn will clear only the loaded review box. New custom rows in the lower box will stay. Continue?", "Load Standard AppColumn", [System.Windows.Forms.MessageBoxButtons]::YesNo, [System.Windows.Forms.MessageBoxIcon]::Question)
                if ($answer -ne [System.Windows.Forms.DialogResult]::Yes) { return }
            }

            $statusLabel.Text = "Loading standard AppColumns..."
            $loadAppColumnsButton.Enabled = $false
            $loadAppColumnsButton.Text = "Loading..."
            $progress.Style = [System.Windows.Forms.ProgressBarStyle]::Marquee
            $form.UseWaitCursor = $true
            try { [void](Write-ProjectPickleDiagnosticLog -Message "Started loading standard AppColumns from: $path" -Context "Load Standard AppColumn click") } catch {}
            [System.Windows.Forms.Application]::DoEvents()
            $loadedFromText = if ($usesCurrentMasterDatabase) { "from the current master database version" } else { "from the selected current-format project database" }
            $fileInfo = Get-Item -LiteralPath $path
            $cacheKey = "{0}|{1}|{2}" -f $fileInfo.FullName.ToLowerInvariant(), $fileInfo.Length, $fileInfo.LastWriteTimeUtc.Ticks
            if (-not [string]::IsNullOrWhiteSpace($cacheKey) -and $script:ProjectPickleAppColumnsLoadCache.ContainsKey($cacheKey)) {
                $cachedItems = @($script:ProjectPickleAppColumnsLoadCache[$cacheKey])
                $items = @(Copy-AppColumnsBuilderItems -Items $cachedItems)
                $script:BuilderLoadedAppColumnItems = @($items)
                if ($script:BuilderLoadedAppColumnItems.Count -gt 0) {
                    $firstLoadedItem = $script:BuilderLoadedAppColumnItems[0]
                    try {
                        [void](Write-ProjectPickleDiagnosticLog -Message ("First cached item before grid refresh -> Source='{0}', TableName='{1}', FieldName='{2}', DataType='{3}', Category='{4}', FriendlyName='{5}'" -f `
                            (ConvertTo-BuilderText $firstLoadedItem.Source), `
                            (ConvertTo-BuilderText $firstLoadedItem.TableName), `
                            (ConvertTo-BuilderText $firstLoadedItem.FieldName), `
                            (ConvertTo-BuilderText $firstLoadedItem.DataType), `
                            (ConvertTo-BuilderText $firstLoadedItem.Category), `
                            (ConvertTo-BuilderText $firstLoadedItem.FriendlyName)) -Context "Load Standard AppColumn click")
                    }
                    catch {
                    }
                }
                Refresh-LoadedAppColumnGrid -SkipSave
                try { [void](Write-ProjectPickleDiagnosticLog -Message "Loaded $($items.Count) AppColumns rows from cache." -Context "Load Standard AppColumn click") } catch {}
                $statusLabel.Text = "Loaded $($items.Count) AppColumns rows $loadedFromText (loaded from cache). Review Active checkboxes before building."
                $loadAppColumnsButton.Text = "Load Standard AppColumn"
                & $setAppColumnsCopyModeUiState
                $progress.Style = [System.Windows.Forms.ProgressBarStyle]::Blocks
                try { $progress.Value = 0 } catch {}
                $form.UseWaitCursor = $false
                [System.Windows.Forms.MessageBox]::Show("Loaded $($items.Count) AppColumns rows $loadedFromText (loaded from cache). Uncheck Active for standard fields that do not apply to this project, then build when ready.", "Load Standard AppColumn", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
                return
            }

            $items = @(Load-AppColumnsForBuilderPath -Path $path)
            try { [void](Write-ProjectPickleDiagnosticLog -Message "Loaded $($items.Count) AppColumns rows from database before grid refresh." -Context "Load Standard AppColumn click") } catch {}
            if (-not [string]::IsNullOrWhiteSpace($cacheKey)) {
                $script:ProjectPickleAppColumnsLoadCache[$cacheKey] = @(Copy-AppColumnsBuilderItems -Items $items)
            }
            $script:BuilderLoadedAppColumnItems = @(Copy-AppColumnsBuilderItems -Items $items)
            if ($script:BuilderLoadedAppColumnItems.Count -gt 0) {
                $firstLoadedItem = $script:BuilderLoadedAppColumnItems[0]
                try {
                    [void](Write-ProjectPickleDiagnosticLog -Message ("First loaded item before grid refresh -> Source='{0}', TableName='{1}', FieldName='{2}', DataType='{3}', Category='{4}', FriendlyName='{5}'" -f `
                        (ConvertTo-BuilderText $firstLoadedItem.Source), `
                        (ConvertTo-BuilderText $firstLoadedItem.TableName), `
                        (ConvertTo-BuilderText $firstLoadedItem.FieldName), `
                        (ConvertTo-BuilderText $firstLoadedItem.DataType), `
                        (ConvertTo-BuilderText $firstLoadedItem.Category), `
                        (ConvertTo-BuilderText $firstLoadedItem.FriendlyName)) -Context "Load Standard AppColumn click")
                }
                catch {
                }
            }
            Refresh-LoadedAppColumnGrid -SkipSave
            try { [void](Write-ProjectPickleDiagnosticLog -Message "Finished refreshing loaded AppColumns grid with $($items.Count) rows." -Context "Load Standard AppColumn click") } catch {}
            $statusLabel.Text = "Loaded $($items.Count) AppColumns rows $loadedFromText. Review Active checkboxes before building."
            $loadAppColumnsButton.Text = "Load Standard AppColumn"
            & $setAppColumnsCopyModeUiState
            $progress.Style = [System.Windows.Forms.ProgressBarStyle]::Blocks
            try { $progress.Value = 0 } catch {}
            $form.UseWaitCursor = $false
            [System.Windows.Forms.MessageBox]::Show("Loaded $($items.Count) AppColumns rows $loadedFromText. Uncheck Active for standard fields that do not apply to this project, then build when ready.", "Load Standard AppColumn", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
        }
        catch {
            $statusLabel.Text = "Could not load standard AppColumns."
            $loadAppColumnsButton.Text = "Load Standard AppColumn"
            & $setAppColumnsCopyModeUiState
            $progress.Style = [System.Windows.Forms.ProgressBarStyle]::Blocks
            try { $progress.Value = 0 } catch {}
            $form.UseWaitCursor = $false
            try { [void](Write-ProjectPickleCrashLog -ExceptionObject $_.Exception -Context "Load Standard AppColumn click failed") } catch {}
            [System.Windows.Forms.MessageBox]::Show($_.Exception.Message, "Load Standard AppColumn failed", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
        }
    })

    $copyLoadedToCustomButton.Add_Click({
        try {
                if ([bool]$copyAppColumnsCheck.Checked) {
                [System.Windows.Forms.MessageBox]::Show(
                    "Copy AppColumns from existing database is checked, so Copy selected format is disabled for this build. Uncheck it to manually create custom AppColumns.",
                    "AppColumns copy mode",
