    $reportColumnsGrid.DefaultCellStyle.WrapMode =
        [System.Windows.Forms.DataGridViewTriState]::False

    # Report order is controlled by Move up and Move down.
    foreach ($gridColumn in $reportColumnsGrid.Columns) {
        if (
            $gridColumn -is
            [System.Windows.Forms.DataGridViewColumn]
        ) {
            $gridColumn.SortMode =
                [System.Windows.Forms.DataGridViewColumnSortMode]::NotSortable
        }
    }

    # Return one real DataGridViewColumn by its internal Name.
    $getNamedReportGridColumn = {
        param(
            [Parameter(Mandatory)]
            [string]$ColumnName
        )

        foreach ($candidateColumn in $reportColumnsGrid.Columns) {
            if (
                $candidateColumn -is
                [System.Windows.Forms.DataGridViewColumn] -and
                [string]::Equals(
                    [string]$candidateColumn.Name,
                    $ColumnName,
                    [System.StringComparison]::OrdinalIgnoreCase
                )
            ) {
                return $candidateColumn
            }
        }

        return $null
    }.GetNewClosure()

    # Lock every value that should be changed only through Project Pickle
    # controls rather than by typing into the grid.
    foreach (
        $lockedColumnName in @(
            "OrderNumber",
            "TableName",
            "ColumnName",
            "Label",
            "FieldFormat",
            "TallyFormat",
            "ColumnID"
        )
    ) {
        $lockedGridColumn =
            & $getNamedReportGridColumn `
                -ColumnName $lockedColumnName

        if (
            $lockedGridColumn -is
            [System.Windows.Forms.DataGridViewColumn]
        ) {
            $lockedGridColumn.ReadOnly = $true
        }
    }

    # FieldFormat can be changed only through Edit width / tally.
    $fieldFormatGridColumn =
        & $getNamedReportGridColumn `
            -ColumnName "FieldFormat"

    if (
        $fieldFormatGridColumn -is
        [System.Windows.Forms.DataGridViewColumn]
    ) {
        $fieldFormatGridColumn.HeaderText =
            "FieldFormat (use button)"

        $fieldFormatGridColumn.ToolTipText = (
            "Select this report row and click Edit width / tally. " +
            "Direct typing is disabled so a complete format such as " +
            "{0,8:g0} cannot be replaced by one character."
        )
    }

    # TallyFormat can be changed only through Edit width / tally.
    $tallyFormatGridColumn =
        & $getNamedReportGridColumn `
            -ColumnName "TallyFormat"

    if (
        $tallyFormatGridColumn -is
        [System.Windows.Forms.DataGridViewColumn]
    ) {
        $tallyFormatGridColumn.HeaderText =
            "TallyFormat (use button)"

        $tallyFormatGridColumn.ToolTipText = (
            "Select this report row and click Edit width / tally. " +
            "Direct typing is disabled so the complete legacy tally " +
            "mask cannot be replaced accidentally."
        )
    }

    # ColumnID is the link from ReportColumns to AppColumns.ID.
    # It stays in the row model but is hidden from manual editing.
    $columnIdGridColumn =
        & $getNamedReportGridColumn `
            -ColumnName "ColumnID"

    if (
        $columnIdGridColumn -is
        [System.Windows.Forms.DataGridViewColumn]
    ) {
        $columnIdGridColumn.ReadOnly = $true

        $columnIdGridColumn.HeaderText =
            "AppColumns ID (locked)"

        $columnIdGridColumn.Visible = $false
    }

    # The separate label-planning column is no longer part of the workflow.
    # Users type and stack printed words directly in ReportHeaders below.
    # The underlying Label value remains available to existing save/build
    # code even though the column is not displayed.
    $labelGridColumn =
        & $getNamedReportGridColumn `
            -ColumnName "Label"

    if (
        $labelGridColumn -is
        [System.Windows.Forms.DataGridViewColumn]
    ) {
        $labelGridColumn.ReadOnly = $true
        $labelGridColumn.Visible = $false
    }

    $addReportFieldsButton = New-Object System.Windows.Forms.Button
    $addReportFieldsButton.Text = "Add ReportVisible fields"
    $addReportFieldsButton.Location = New-Object System.Drawing.Point(846, 30)
    $addReportFieldsButton.Size = New-Object System.Drawing.Size(166, 30)
    $addReportFieldsButton.Anchor = "Top,Right"
    $reportColumnsGroup.Controls.Add($addReportFieldsButton)

    $reportMoveUpButton = New-Object System.Windows.Forms.Button
    $reportMoveUpButton.Text = "Move up"
    $reportMoveUpButton.Location = New-Object System.Drawing.Point(846, 72)
    $reportMoveUpButton.Size = New-Object System.Drawing.Size(166, 30)
    $reportMoveUpButton.Anchor = "Top,Right"
    $reportColumnsGroup.Controls.Add($reportMoveUpButton)

    $reportMoveDownButton = New-Object System.Windows.Forms.Button
    $reportMoveDownButton.Text = "Move down"
    $reportMoveDownButton.Location = New-Object System.Drawing.Point(846, 110)
    $reportMoveDownButton.Size = New-Object System.Drawing.Size(166, 30)
    $reportMoveDownButton.Anchor = "Top,Right"
    $reportColumnsGroup.Controls.Add($reportMoveDownButton)

    $reportRemoveButton = New-Object System.Windows.Forms.Button
    $reportRemoveButton.Text = "Remove selected"
    $reportRemoveButton.Location = New-Object System.Drawing.Point(846, 148)
    $reportRemoveButton.Size = New-Object System.Drawing.Size(166, 30)
    $reportRemoveButton.Anchor = "Top,Right"
    $reportColumnsGroup.Controls.Add($reportRemoveButton)

    $generateReportHeaderButton = New-Object System.Windows.Forms.Button
    $generateReportHeaderButton.Text = "Generate replacement header"
    $generateReportHeaderButton.Visible = $false
    $generateReportHeaderButton.Enabled = $false
    $generateReportHeaderButton.TabStop = $false
    $generateReportHeaderButton.Location = New-Object System.Drawing.Point(846, 198)
    $generateReportHeaderButton.Size = New-Object System.Drawing.Size(166, 30)
    $generateReportHeaderButton.Anchor = "Top,Right"
    $reportColumnsGroup.Controls.Add($generateReportHeaderButton)
    $toolTip.SetToolTip($generateReportHeaderButton, "Creates an editable starter header from the current labels and formats. It does not replace the need to align the final fixed-width header manually.")

    # The separate 1-3 label-line planner is no longer part of the
    # Reports workflow. Keep a real hidden Button object only so any
    # older attached click handler remains harmless and does not cause
    # a null-object startup failure.
    $editReportLabelLinesButton =
        New-Object System.Windows.Forms.Button

    $editReportLabelLinesButton.Name =
        "editReportLabelLinesButtonDormant"

    $editReportLabelLinesButton.Text =
        "Edit 1-3 label lines"

        if (
        $editReportLabelLinesButton -is
        [System.Windows.Forms.Button]
    ) {
        $editReportLabelLinesButton.Visible = $false
        $editReportLabelLinesButton.Enabled = $false
        $editReportLabelLinesButton.TabStop = $false
    }

    $showNewReportFieldLabelDialog = {
        param(
            [System.Windows.Forms.IWin32Window]$Owner,

            [string]$FieldName,

            [AllowNull()]
            [object]$CurrentValue,

            [AllowNull()]
            [object]$FieldFormat
        )

        # ---------------------------------------------------------------
        # Determine the printable field width when the legacy format uses
        # a recognized width pattern.
        #
        # Examples:
        #   {0,6:n0}   -> 6
        #   {0,-12}    -> 12
        #   TEXT,50,6  -> 6
        # ---------------------------------------------------------------

        $fieldWidth = 0
        $formatText = [Convert]::ToString(
            $FieldFormat
        ).Trim()

        $compositeWidthMatch = [regex]::Match(
            $formatText,
            "\{0\s*,\s*(-?\d+)"
        )

        if ($compositeWidthMatch.Success) {
            $parsedWidth = 0

            if (
                [int]::TryParse(
                    $compositeWidthMatch.Groups[1].Value,
                    [ref]$parsedWidth
                )
            ) {
                $fieldWidth = [Math]::Abs(
                    $parsedWidth
                )
            }
        }
        else {
            $textWidthMatch = [regex]::Match(
                $formatText,
                "(?i)^\s*TEXT\s*,\s*\d+\s*,\s*(\d+)\s*$"
            )

            if ($textWidthMatch.Success) {
                $parsedWidth = 0

                if (
                    [int]::TryParse(
                        $textWidthMatch.Groups[1].Value,
                        [ref]$parsedWidth
                    )
                ) {
                    $fieldWidth = [Math]::Abs(
                        $parsedWidth
                    )
                }
            }
        }

        # ---------------------------------------------------------------
        # Read an existing slash-separated label plan.
        # ---------------------------------------------------------------

        $currentText = [Convert]::ToString(
            $CurrentValue
        )

        $currentText = $currentText.Replace(
            "`r`n",
            " / "
        )

        $currentText = $currentText.Replace(
            "`r",
            " / "
        )

        $currentText = $currentText.Replace(
            "`n",
            " / "
        )

        $currentParts = @()

        if (-not [string]::IsNullOrWhiteSpace($currentText)) {
            $currentParts = @(
                [regex]::Split(
                    $currentText,
                    "\s*/\s*"
                ) |
                    ForEach-Object {
                        ([string]$_).Trim()
                    } |
                    Where-Object {
                        -not [string]::IsNullOrWhiteSpace($_)
                    } |
                    Select-Object -First 3
            )
        }

        # Start a blank new label with a readable version of the field
        # name when no label plan exists yet.
        if (
            $currentParts.Count -eq 0 -and
            -not [string]::IsNullOrWhiteSpace($FieldName)
        ) {
            $starterLabel = [regex]::Replace(
                $FieldName,
                "([a-z0-9])([A-Z])",
                '$1 $2'
            )

            $currentParts = @(
                $starterLabel.ToUpperInvariant()
            )
        }

        # ---------------------------------------------------------------
        # Create the dialog.
        # ---------------------------------------------------------------

        $dialog = New-Object System.Windows.Forms.Form

        $dialog.Text =
            "Edit report label lines"

        $dialog.ClientSize =
            New-Object System.Drawing.Size(610, 445)

        $dialog.FormBorderStyle =
            [System.Windows.Forms.FormBorderStyle]::FixedDialog

        $dialog.MaximizeBox = $false
        $dialog.MinimizeBox = $false
        $dialog.ShowInTaskbar = $false

        $dialog.StartPosition =
            [System.Windows.Forms.FormStartPosition]::CenterParent

        $instructionsLabel =
            New-Object System.Windows.Forms.Label

        $instructionsLabel.SetBounds(
            15,
            12,
            580,
            42
        )

        $instructionsLabel.Text = (
            "Enter the printed report label on one, two, or three lines. " +
            "Each filled box represents one line in the fixed-width " +
            "ReportHeaders visual."
        )

        $fieldCaptionLabel =
            New-Object System.Windows.Forms.Label

        $fieldCaptionLabel.SetBounds(
            15,
            59,
            70,
            22
        )

        $fieldCaptionLabel.Text = "Field:"

        $fieldValueLabel =
            New-Object System.Windows.Forms.Label

        $fieldValueLabel.SetBounds(
            90,
            59,
            505,
            22
        )

        $fieldValueLabel.AutoEllipsis = $true

        if ([string]::IsNullOrWhiteSpace($FieldName)) {
            $fieldValueLabel.Text =
                "(field name unavailable)"
        }
        else {
            $fieldValueLabel.Text =
                $FieldName
        }

        $widthInformationLabel =
            New-Object System.Windows.Forms.Label

        $widthInformationLabel.SetBounds(
            90,
            82,
            505,
            24
        )

        if ($fieldWidth -gt 0) {
            $widthInformationLabel.Text = (
                "FieldFormat allows up to {0} character(s) on each label line." -f
                $fieldWidth
            )
        }
        else {
            $widthInformationLabel.Text = (
                "The printable width could not be read from FieldFormat. " +
                "Review the fixed-width header carefully."
            )
        }

        $line1Label =
            New-Object System.Windows.Forms.Label

        $line1Label.SetBounds(
            15,
            119,
            70,
            25
        )

        $line1Label.Text = "Line 1:"

        $line1TextBox =
            New-Object System.Windows.Forms.TextBox

        $line1TextBox.SetBounds(
            90,
            115,
            505,
            27
        )

        $line1TextBox.CharacterCasing =
            [System.Windows.Forms.CharacterCasing]::Upper

        $line2Label =
            New-Object System.Windows.Forms.Label

        $line2Label.SetBounds(
            15,
            157,
            70,
            25
        )

        $line2Label.Text = "Line 2:"

        $line2TextBox =
            New-Object System.Windows.Forms.TextBox

        $line2TextBox.SetBounds(
            90,
            153,
            505,
            27
        )

        $line2TextBox.CharacterCasing =
            [System.Windows.Forms.CharacterCasing]::Upper

        $line3Label =
            New-Object System.Windows.Forms.Label

        $line3Label.SetBounds(
            15,
            195,
            70,
            25
        )

        $line3Label.Text = "Line 3:"

        $line3TextBox =
            New-Object System.Windows.Forms.TextBox

        $line3TextBox.SetBounds(
            90,
            191,
            505,
            27
        )

        $line3TextBox.CharacterCasing =
            [System.Windows.Forms.CharacterCasing]::Upper

        $entryHelpLabel =
            New-Object System.Windows.Forms.Label

        $entryHelpLabel.SetBounds(
            90,
            225,
            505,
            36
        )

        $entryHelpLabel.Text = (
            "Leave Line 2 and Line 3 blank for a one-line label. " +
            "Do not leave a blank line between two filled lines."
        )

        $previewGroup =
            New-Object System.Windows.Forms.GroupBox

        $previewGroup.SetBounds(
            15,
            269,
            580,
            112
        )

        $previewGroup.Text =
            "Stacked preview"

        $previewTextBox =
            New-Object System.Windows.Forms.TextBox

        $previewTextBox.SetBounds(
            12,
            24,
            556,
            75
        )

        $previewTextBox.Multiline = $true
        $previewTextBox.ReadOnly = $true
        $previewTextBox.WordWrap = $false

        $previewTextBox.ScrollBars =
            [System.Windows.Forms.ScrollBars]::None

        $previewTextBox.TextAlign =
            [System.Windows.Forms.HorizontalAlignment]::Center

        $previewTextBox.BackColor =
            [System.Drawing.SystemColors]::Window

        try {
            $previewTextBox.Font =
                New-Object System.Drawing.Font(
                    "Consolas",
                    10,
                    [System.Drawing.FontStyle]::Regular
                )
        }
        catch {
        }

        $previewGroup.Controls.Add(
            $previewTextBox
        )

        $okButton =
            New-Object System.Windows.Forms.Button

        $okButton.SetBounds(
            405,
            397,
            90,
            32
        )

        $okButton.Text = "OK"

        $cancelButton =
            New-Object System.Windows.Forms.Button

        $cancelButton.SetBounds(
            505,
            397,
            90,
            32
        )

        $cancelButton.Text = "Cancel"

        $cancelButton.DialogResult =
            [System.Windows.Forms.DialogResult]::Cancel

        $dialog.AcceptButton = $okButton
        $dialog.CancelButton = $cancelButton

        # ---------------------------------------------------------------
        # Fill the three entry boxes from the current slash-separated
        # label plan.
        # ---------------------------------------------------------------

        if ($currentParts.Count -ge 1) {
            $line1TextBox.Text =
                ([string]$currentParts[0]).ToUpperInvariant()
        }

        if ($currentParts.Count -ge 2) {
            $line2TextBox.Text =
                ([string]$currentParts[1]).ToUpperInvariant()
        }

        if ($currentParts.Count -ge 3) {
            $line3TextBox.Text =
                ([string]$currentParts[2]).ToUpperInvariant()
        }

        # ---------------------------------------------------------------
        # Live stacked preview.
        # ---------------------------------------------------------------

        $updateLabelPreview = {
            $previewLines =
                New-Object System.Collections.Generic.List[string]

            foreach (
                $textBox in @(
                    $line1TextBox,
                    $line2TextBox,
                    $line3TextBox
                )
            ) {
                $previewLine = [regex]::Replace(
                    ([string]$textBox.Text).Trim(),
                    " {2,}",
                    " "
                )

                if (
                    -not [string]::IsNullOrWhiteSpace(
                        $previewLine
                    )
                ) {
                    [void]$previewLines.Add(
                        $previewLine.ToUpperInvariant()
                    )
                }
            }

            if ($previewLines.Count -eq 0) {
                $previewTextBox.Text =
                    "(blank)"
            }
            else {
                $previewTextBox.Text =
                    [string]::Join(
                        [Environment]::NewLine,
                        [string[]]$previewLines.ToArray()
                    )
            }
        }.GetNewClosure()

        $line1TextBox.Add_TextChanged({
            & $updateLabelPreview
        }.GetNewClosure())

        $line2TextBox.Add_TextChanged({
            & $updateLabelPreview
        }.GetNewClosure())

        $line3TextBox.Add_TextChanged({
            & $updateLabelPreview
        }.GetNewClosure())

        & $updateLabelPreview

        $showLabelWarning = {
            param(
                [string]$Message
            )

            [void][System.Windows.Forms.MessageBox]::Show(
                $dialog,
                $Message,
                "Edit report label lines",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Warning
            )
        }.GetNewClosure()

        # ---------------------------------------------------------------
        # Validate and save the three-line plan.
        # ---------------------------------------------------------------

        $okButton.Add_Click({
            $rawLines = [string[]]@(
                [string]$line1TextBox.Text,
                [string]$line2TextBox.Text,
                [string]$line3TextBox.Text
            )

            if (
                [string]::IsNullOrWhiteSpace(
                    $rawLines[0]
                )
            ) {
                & $showLabelWarning (
                    "Line 1 is required."
                )

                [void]$line1TextBox.Focus()
                return
            }

            if (
                [string]::IsNullOrWhiteSpace(
                    $rawLines[1]
                ) -and
                -not [string]::IsNullOrWhiteSpace(
                    $rawLines[2]
                )
            ) {
                & $showLabelWarning (
                    "Line 2 cannot be blank when Line 3 contains text."
                )

                [void]$line2TextBox.Focus()
                return
            }

            $normalizedLines =
                New-Object System.Collections.Generic.List[string]

            for (
                $lineIndex = 0;
                $lineIndex -lt $rawLines.Count;
                $lineIndex++
            ) {
                $rawLine = $rawLines[$lineIndex]

                if ([string]::IsNullOrWhiteSpace($rawLine)) {
                    continue
                }

                $displayLineNumber =
                    $lineIndex + 1

                if ($rawLine.Contains("`t")) {
                    & $showLabelWarning (
                        "Line $displayLineNumber contains a tab. " +
                        "Use spaces instead."
                    )

                    return
                }

                if ($rawLine.Contains("/")) {
                    & $showLabelWarning (
                        "Line $displayLineNumber contains a slash. " +
                        "Slashes are reserved for separating the three " +
                        "stored label lines."
                    )

                    return
                }

                if ($rawLine.Contains("|")) {
                    & $showLabelWarning (
                        "Line $displayLineNumber contains a vertical bar. " +
                        "Vertical bars are reserved for report boundaries."
                    )

                    return
                }

                $normalizedLine = [regex]::Replace(
                    $rawLine.Trim(),
                    " {2,}",
                    " "
                ).ToUpperInvariant()

                foreach (
                    $character in
                    $normalizedLine.ToCharArray()
                ) {
                    $characterCode =
                        [int][char]$character

                    if (
                        $characterCode -lt 32 -or
                        $characterCode -gt 126
                    ) {
                        & $showLabelWarning (
                            "Line $displayLineNumber contains a character " +
                            "that is not printable ASCII."
                        )

                        return
                    }
                }

                if (
                    $fieldWidth -gt 0 -and
                    $normalizedLine.Length -gt $fieldWidth
                ) {
                    & $showLabelWarning (
                        (
                            "Line {0}, '{1}', contains {2} characters, " +
                            "but FieldFormat allows only {3}. Shorten the " +
                            "line or increase FieldFormat."
                        ) -f
                        $displayLineNumber,
                        $normalizedLine,
                        $normalizedLine.Length,
                        $fieldWidth
                    )

                    return
                }

                [void]$normalizedLines.Add(
                    $normalizedLine
                )
            }

            $dialog.Tag =
                [string]::Join(
                    " / ",
                    [string[]]$normalizedLines.ToArray()
                )

            $dialog.DialogResult =
                [System.Windows.Forms.DialogResult]::OK

            $dialog.Close()
        }.GetNewClosure())

        foreach (
            $dialogControl in @(
                $instructionsLabel,
                $fieldCaptionLabel,
                $fieldValueLabel,
                $widthInformationLabel,
                $line1Label,
                $line1TextBox,
                $line2Label,
                $line2TextBox,
                $line3Label,
                $line3TextBox,
                $entryHelpLabel,
                $previewGroup,
                $okButton,
                $cancelButton
            )
        ) {
            [void]$dialog.Controls.Add(
                $dialogControl
            )
        }

        $dialog.Add_Shown({
            [void]$line1TextBox.Focus()
            $line1TextBox.SelectAll()
        }.GetNewClosure())

        try {
            if ($null -ne $Owner) {
                $dialogResult =
                    $dialog.ShowDialog($Owner)
            }
            else {
                $dialogResult =
                    $dialog.ShowDialog()
            }

            if (
                $dialogResult -eq
                [System.Windows.Forms.DialogResult]::OK
            ) {
                return [string]$dialog.Tag
            }

            return $null
        }
        finally {
            $dialog.Dispose()
        }
    }.GetNewClosure()

    # -----------------------------------------------------------------------
    # Open the three-line editor for the selected newly added field.
    # -----------------------------------------------------------------------

    $editReportLabelLinesButton.Add_Click({
        $selectedRow =
            $reportColumnsGrid.CurrentRow

        if (
            $null -eq $selectedRow -or
            $selectedRow.IsNewRow
        ) {
            [void][System.Windows.Forms.MessageBox]::Show(
                $form,
                (
                    "Select a newly added report field first."
                ),
                "Edit report label lines",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information
            )

            return
        }

        $labelCell =
            $selectedRow.Cells["Label"]

        $identityKey =
            Get-ProjectPickleReportGridRowIdentityKey `
                -Grid $reportColumnsGrid `
                -RowIndex $selectedRow.Index

        $isTemplateRow =
            [bool]$labelCell.ReadOnly

        if (
            -not $isTemplateRow -and
            -not [string]::IsNullOrWhiteSpace(
                $identityKey
            ) -and
            $null -ne $script:ProjectPickleOriginalReportColumnIds -and
            $script:ProjectPickleOriginalReportColumnIds.ContainsKey(
                $identityKey
            )
        ) {
            $isTemplateRow = $true
        }

        if ($isTemplateRow) {
            [void][System.Windows.Forms.MessageBox]::Show(
                $form,
                (
                    "The selected row came from the loaded report " +
                    "template. Its exact printed label is already " +
                    "preserved in ReportHeaders below.`r`n`r`n" +
                    "Select a field that was added with " +
                    "'Add ReportVisible fields'."
                ),
                "Template label is locked",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information
            )

            return
        }

        $fieldName =
            ConvertTo-BuilderText (
                $selectedRow.Cells[
                    "ColumnName"
                ].Value
            )

        $currentLabel =
            $labelCell.Value

        $fieldFormat =
            $selectedRow.Cells[
                "FieldFormat"
            ].Value

        $newLabelPlan =
            & $showNewReportFieldLabelDialog `
                -Owner $form `
                -FieldName $fieldName `
                -CurrentValue $currentLabel `
                -FieldFormat $fieldFormat

        if ($null -eq $newLabelPlan) {
            return
        }

        $labelCell.Value =
            $newLabelPlan

        $labelCell.ToolTipText =
            $newLabelPlan.Replace(
                " / ",
                [Environment]::NewLine
            )

        $reportUiState.IsDirty = $true

        $reportLoadStatusLabel.Text = (
            "Saved a 1-3 line label plan for '{0}'. " +
            "Place the same words in the exact ReportHeaders text below." -f
            $fieldName
        )
    }.GetNewClosure())

        # -----------------------------------------------------------------------
    # Find Category and DataType from the AppColumns grids so newly added
    # Code fields can receive the correct default FieldFormat.
    # -----------------------------------------------------------------------

    $getReportAppColumnMetadata = {
        param(
            [string]$TableName,
            [string]$ColumnName
        )

        $result = [pscustomobject]@{
            Category = ""
            DataType = ""
        }

        foreach (
            $appColumnGrid in @(
                $customFieldGrid,
                $fieldGrid
            )
        ) {
            if ($null -eq $appColumnGrid) {
                continue
            }

            $tableColumnIndex =
                Get-ProjectPickleGridColumnIndex `
                    -Grid $appColumnGrid `
                    -CandidateNames @(
                        "AppTable",
                        "App table",
                        "TableName",
                        "Table"
                    )

            $fieldColumnIndex =
                Get-ProjectPickleGridColumnIndex `
                    -Grid $appColumnGrid `
                    -CandidateNames @(
                        "FieldName",
                        "Field name",
                        "ColumnName",
                        "Field"
                    )

            $categoryColumnIndex =
                Get-ProjectPickleGridColumnIndex `
                    -Grid $appColumnGrid `
                    -CandidateNames @(
                        "Category"
                    )

            $dataTypeColumnIndex =
                Get-ProjectPickleGridColumnIndex `
                    -Grid $appColumnGrid `
                    -CandidateNames @(
                        "DataType",
                        "Data type",
                        "ColumnType",
                        "Type"
                    )

            $codesColumnIndex =
                Get-ProjectPickleGridColumnIndex `
                    -Grid $appColumnGrid `
                    -CandidateNames @(
                        "Codes",
                        "Code list"
                    )

            $standardCodeColumnIndex =
                Get-ProjectPickleGridColumnIndex `
                    -Grid $appColumnGrid `
                    -CandidateNames @(
                        "StandardCode",
                        "Standard code"
                    )

            if (
                $tableColumnIndex -lt 0 -or
                $fieldColumnIndex -lt 0
            ) {
                continue
            }

            foreach ($appColumnRow in $appColumnGrid.Rows) {
                if ($appColumnRow.IsNewRow) {
                    continue
                }

                $candidateTable =
                    ConvertTo-BuilderText (
                        $appColumnRow.Cells[
                            $tableColumnIndex
                        ].Value
                    )

                $candidateField =
                    ConvertTo-BuilderText (
                        $appColumnRow.Cells[
                            $fieldColumnIndex
                        ].Value
                    )

                if (
                    -not [string]::Equals(
                        $candidateTable,
                        $TableName,
                        [System.StringComparison]::OrdinalIgnoreCase
                    ) -or
                    -not [string]::Equals(
                        $candidateField,
                        $ColumnName,
                        [System.StringComparison]::OrdinalIgnoreCase
                    )
                ) {
                    continue
                }

                if ($categoryColumnIndex -ge 0) {
                    $result.Category =
                        ConvertTo-BuilderText (
                            $appColumnRow.Cells[
                                $categoryColumnIndex
                            ].Value
                        )
                }

                if ($dataTypeColumnIndex -ge 0) {
                    $result.DataType =
                        ConvertTo-BuilderText (
                            $appColumnRow.Cells[
                                $dataTypeColumnIndex
                            ].Value
                        )
                }

                if (
                    [string]::IsNullOrWhiteSpace(
                        $result.Category
                    ) -and
                    $codesColumnIndex -ge 0
                ) {
                    $codesText =
                        ConvertTo-BuilderText (
                            $appColumnRow.Cells[
                                $codesColumnIndex
                            ].Value
                        )

                    if (
                        -not [string]::IsNullOrWhiteSpace(
                            $codesText
                        )
                    ) {
                        $result.Category = "Code"
                    }
                }

                if (
                    [string]::IsNullOrWhiteSpace(
                        $result.Category
                    ) -and
                    $standardCodeColumnIndex -ge 0
                ) {
                    try {
                        $usesStandardCode =
                            ConvertTo-BuilderBool (
                                $appColumnRow.Cells[
                                    $standardCodeColumnIndex
                                ].Value
                            )

                        if ($usesStandardCode) {
                            $result.Category = "Code"
                        }
                    }
                    catch {
                    }
                }

                return $result
            }
        }

        return $result
    }.GetNewClosure()

    # -----------------------------------------------------------------------
    # Apply {0,8:g0} to newly added Code fields whose FieldFormat is blank.
    # Existing loaded template rows are never changed by this routine.
    # -----------------------------------------------------------------------

    $applyCodeDefaultsToNewReportRows = {
        $changedCount = 0

        foreach ($reportRow in $reportColumnsGrid.Rows) {
            if ($reportRow.IsNewRow) {
                continue
            }

            $identityKey =
                Get-ProjectPickleReportGridRowIdentityKey `
                    -Grid $reportColumnsGrid `
                    -RowIndex $reportRow.Index

            $isLoadedTemplateRow = (
                -not [string]::IsNullOrWhiteSpace(
                    $identityKey
                ) -and
                $null -ne $script:ProjectPickleOriginalReportColumnIds -and
                $script:ProjectPickleOriginalReportColumnIds.ContainsKey(
                    $identityKey
                )
            )

            if ($isLoadedTemplateRow) {
                continue
            }

            $currentFormat =
                ConvertTo-RawSingleLineText (
                    $reportRow.Cells[
                        "FieldFormat"
                    ].Value
                )

            # Repair a blank, bare-number, or incomplete composite format.
            # A complete existing format is preserved.
            $formatNeedsRepair =
                Test-ProjectPickleReportNumericFormatNeedsRepair `
                    -FieldFormat $currentFormat

            if (-not $formatNeedsRepair) {
                continue
            }

            $tableName =
                ConvertTo-BuilderText (
                    $reportRow.Cells[
                        "TableName"
                    ].Value
                )

            $columnName =
                ConvertTo-BuilderText (
                    $reportRow.Cells[
                        "ColumnName"
                    ].Value
                )

            $metadata =
                & $getReportAppColumnMetadata `
                    -TableName $tableName `
                    -ColumnName $columnName

            if (
                [string]::Equals(
                    (ConvertTo-BuilderText $metadata.Category),
                    "Code",
                    [System.StringComparison]::OrdinalIgnoreCase
                )
            ) {
                $reportRow.Cells[
                    "FieldFormat"
                ].Value = "{0,8:g0}"

                $changedCount++
            }
        }

        if ($changedCount -gt 0) {
            $reportUiState.IsDirty = $true

            $reportLoadStatusLabel.Text = (
                "Applied the default {0,8:g0} FieldFormat to " +
                "$changedCount newly added Code field(s)."
            )
        }

        return $changedCount
    }.GetNewClosure()

