                ].Value
            )

        # A FieldFormat consisting only of a number means direct cell
        # editing already damaged the format string. Do not let that
        # damaged value become the starting point for another edit.
        if (
            $originalFieldFormat -match
            "^\s*-?\d+\s*$"
        ) {
            [void][System.Windows.Forms.MessageBox]::Show(
                $form,
                (
                    "This field's FieldFormat currently contains only " +
                    "'$originalFieldFormat'. The complete legacy format " +
                    "was replaced by direct grid editing.`r`n`r`n" +
