                    "Expected examples include:`r`n" +
                    "{0,8:g0}`r`n" +
                    "{0,6:n0}`r`n" +
                    "TEXT,40,05"
                ),
                "Invalid FieldFormat",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Warning
            )

            return
        }

        $selectedRow.Cells[
            "FieldFormat"
        ].Value =
            $newFieldFormat

