# ---------------------------------------------------------------------------
# Automatic separator before the Remarks field
#
# The Reports grid continues to use normal editable formats such as:
#
#     {0,1}
#     {0,4:g0}
#
# When Project Pickle previews, validates, saves, or builds the layout, the
# final custom field immediately before Remarks receives a forced trailing
# blank. Examples:
#
#     Plot: {0,1}    becomes {0,2:0\ }
#     Tree: {0,4:g0} becomes {0,5:0\ }
#
# The special stored format is converted back to a normal editable format
# when the layout is displayed in the Reports grid.
#
# This applies to:
#
#     PlotCustomMeasurements  before RemarksPlot
#     TreeCustomMeasurements  before RemarksTree
#     RegenCustomMeasurements before RemarksRegen
# ---------------------------------------------------------------------------

$getProjectPickleFinalCustomColumnBeforeRemarksIndex = {
    param(
        [object[]]$Columns,
        [object]$Spec
    )

    if (
        $null -eq $Columns -or
        $Columns.Count -eq 0
    ) {
        return -1
    }

    # Identify the report from the actual required Remarks field instead of
    # depending only on report-spec metadata. This makes the same rule work
    # reliably for Plot, Tree, and Regen layouts.
    $remarksToCustomTable = @{
        "REMARKSPLOT" =
            "PlotCustomMeasurements"

        "REMARKSTREE" =
            "TreeCustomMeasurements"

        "REMARKSREGEN" =
            "RegenCustomMeasurements"
    }

    $remarksIndex =
        -1

    $expectedCustomTableName =
        ""

    for (
        $columnIndex = 0;
        $columnIndex -lt $Columns.Count;
        $columnIndex++
    ) {
        $column =
            $Columns[$columnIndex]

        if ($null -eq $column) {
            continue
        }

        $columnName = (
            ConvertTo-BuilderText `
                $column.ColumnName
        ).Trim()

        if (
            [string]::IsNullOrWhiteSpace(
                $columnName
            )
        ) {
            continue
        }

        $columnNameKey =
            $columnName.ToUpperInvariant()

        if (
            $remarksToCustomTable.ContainsKey(
                $columnNameKey
            )
        ) {
            $remarksIndex =
                $columnIndex

            $expectedCustomTableName =
                [string]$remarksToCustomTable[
                    $columnNameKey
                ]

            break
        }
    }

    if ($remarksIndex -le 0) {
        return -1
    }

    $candidateIndex =
        $remarksIndex - 1

    $candidateColumn =
        $Columns[$candidateIndex]

    if ($null -eq $candidateColumn) {
        return -1
    }

    $candidateTableName = (
        ConvertTo-BuilderText `
            $candidateColumn.TableName
    ).Trim()

    if (
        -not [string]::Equals(
            $candidateTableName,
            $expectedCustomTableName,
            [System.StringComparison]::OrdinalIgnoreCase
        )
    ) {
        # The field immediately before Remarks is an original standard
        # field rather than a custom-measurement field. Leave it unchanged.
        return -1
    }

    return [int]$candidateIndex
}.GetNewClosure()


$convertProjectPickleFinalCustomFormatForStorage = {
    param(
        [object]$FieldFormat
    )

    $formatText =
        [string](
            ConvertTo-RawSingleLineText `
                $FieldFormat
        )

    $formatText =
        $formatText.Trim()

    if (
        [string]::IsNullOrWhiteSpace(
            $formatText
        )
    ) {
        return $formatText
    }

    # Recognize a format that Project Pickle already converted:
    #
    #     {0,2:0\ }
    #     {0,5:0\ }
    #
    # Normalize it without increasing its width a second time.
    $storedFormatMatch =
        [regex]::Match(
            $formatText,
            '^\{0,\s*(?<width>-?\d+)\s*:0\\ \}$',
            [System.Text.RegularExpressions.RegexOptions]::IgnoreCase
        )

    if ($storedFormatMatch.Success) {
        $storedWidth =
            0

        if (
            -not [int]::TryParse(
                $storedFormatMatch.Groups[
                    "width"
                ].Value,
                [ref]$storedWidth
            )
        ) {
            return $formatText
        }

        $storedWidth =
            [Math]::Max(
                1,
                [Math]::Abs(
                    $storedWidth
                )
            )

        return (
            "{0," +
            $storedWidth +
            ":0\ }"
        )
    }

    # Recognize all ordinary whole-number forms used by the report designer:
    #
    #     {0,1}
    #     {0,}
    #     {0}
    #     {0,-4:g0}
    #     {0,4:g0}
    #     {0,4:0}
    #
    # Plot fields commonly use the short {0,1} form. The prior version did
    # not recognize that form because it required :g0 or :0.
    $editableFormatMatch =
        [regex]::Match(
            $formatText,
            '^\{0(?:,\s*(?<width>-?\d+)?\s*)?(?::\s*(?<numberFormat>g0|0)\s*)?\}$',
            [System.Text.RegularExpressions.RegexOptions]::IgnoreCase
        )

    if (-not $editableFormatMatch.Success) {
        # Do not force a numeric format onto TEXT formats, dates, or other
        # specialized legacy formats.
        return $formatText
    }

    # Use one position when an older/default format contains no width,
    # including the malformed-but-seen form {0,}.
    $editableWidth =
        1

    $widthText =
        $editableFormatMatch.Groups[
            "width"
        ].Value

    if (
        -not [string]::IsNullOrWhiteSpace(
            $widthText
        )
    ) {
        $parsedWidth =
            0

        if (
            -not [int]::TryParse(
                $widthText,
                [ref]$parsedWidth
            )
        ) {
            return $formatText
        }

        $editableWidth =
            [Math]::Max(
                1,
                [Math]::Abs(
                    $parsedWidth
                )
            )
    }

    # The escaped blank inside the numeric pattern guarantees one blank
    # after the value. Increasing the total width by one preserves the
    # ordinary right-alignment space before the value when one exists.
    $storedWidth =
        $editableWidth + 1

    return (
        "{0," +
        $storedWidth +
        ":0\ }"
    )
}.GetNewClosure()


$convertProjectPickleFinalCustomFormatForEditing = {
    param(
        [object]$FieldFormat
    )

    $formatText =
        [string](
            ConvertTo-RawSingleLineText `
                $FieldFormat
        )

    $formatText =
        $formatText.Trim()

    if (
        [string]::IsNullOrWhiteSpace(
            $formatText
        )
    ) {
        return $formatText
    }

    $storedFormatMatch =
        [regex]::Match(
            $formatText,
            '^\{0,\s*(?<width>-?\d+)\s*:0\\ \}$',
            [System.Text.RegularExpressions.RegexOptions]::IgnoreCase
        )

    if (-not $storedFormatMatch.Success) {
        return $formatText
    }

    $storedWidth =
        0

    if (
        -not [int]::TryParse(
            $storedFormatMatch.Groups[
                "width"
            ].Value,
            [ref]$storedWidth
        )
    ) {
        return $formatText
    }

    $storedWidth =
        [Math]::Abs(
            $storedWidth
        )

    # Remove the extra trailing-separator position before showing the
    # format in the editable Reports grid.
    $editableWidth =
        [Math]::Max(
            1,
            $storedWidth - 1
        )

    return (
        "{0," +
        $editableWidth +
        ":g0}"
    )
}.GetNewClosure()



    $getReportHeaderLinesFromEditor = {
        $text = if ($null -eq $reportHeaderEditor.Text) { "" } else { [string]$reportHeaderEditor.Text }
        return [string[]][regex]::Split($text, "`r`n|`n|`r")
    }.GetNewClosure()

    $updateReportOrderNumbers = {
        $order = 1
        foreach ($row in $reportColumnsGrid.Rows) {
            if ($row.IsNewRow) { continue }
            $row.Cells["OrderNumber"].Value = $order
            $order++
        }
    }.GetNewClosure()

    $updateReportHeaderStatus = {
        $lines = @(& $getReportHeaderLinesFromEditor)
        $lengths = New-Object System.Collections.Generic.List[int]
        $parts = New-Object System.Collections.Generic.List[string]
        $maximum = 0
        for ($i = 0; $i -lt $lines.Count; $i++) {
            $line = if ($null -eq $lines[$i]) { "" } else { [string]$lines[$i] }
            $length = $line.Length
            [void]$parts.Add("$($i + 1)=$length")
            if ($length -gt 0) { [void]$lengths.Add($length) }
            if ($length -gt $maximum) { $maximum = $length }
        }
        $unique = @($lengths.ToArray() | Sort-Object -Unique)
        if ($unique.Count -le 1) {
            $widthText = if ($unique.Count -eq 1) { "$($unique[0]) characters" } else { "no nonblank lines" }
            $reportHeaderStatusLabel.Text = "Fixed width OK: $widthText. Line lengths: $([string]::Join(', ', [string[]]$parts.ToArray()))"
            $reportHeaderStatusLabel.ForeColor = $uiTheme.AccentDark
        }
        else {
            $reportHeaderStatusLabel.Text = "Fix before saving: nonblank lines have different widths ($([string]::Join(', ', [string[]]$unique))). Line lengths: $([string]::Join(', ', [string[]]$parts.ToArray()))"
            $reportHeaderStatusLabel.ForeColor = [System.Drawing.Color]::Firebrick
        }
        $reportRulerBox.Text = New-ReportCharacterRuler -Width ([Math]::Max(120, $maximum))
    }.GetNewClosure()

    $getReportLayoutFromUi = {
        param([object]$SpecOverride = $null)

        try { [void]$reportColumnsGrid.EndEdit() } catch {}
        $spec = if ($null -ne $SpecOverride) { $SpecOverride } else { & $getCurrentReportSpec }
        if ($null -eq $spec) { return $null }
        $columns = New-Object System.Collections.Generic.List[object]
        foreach ($row in $reportColumnsGrid.Rows) {
            if ($row.IsNewRow) { continue }
            $columnId =
    ConvertTo-BuilderText `
        $row.Cells["ColumnID"].Value

$tableName =
    ConvertTo-BuilderText `
        $row.Cells["TableName"].Value

$columnName =
    ConvertTo-BuilderText `
        $row.Cells["ColumnName"].Value

$label =
    ConvertTo-BuilderText `
        $row.Cells["Label"].Value

$currentGridFieldFormat =
    ConvertTo-RawSingleLineText `
        $row.Cells["FieldFormat"].Value

$fieldFormat =
    $currentGridFieldFormat

$tallyFormat =
    ConvertTo-RawSingleLineText `
        $row.Cells["TallyFormat"].Value

# RemarksTree is a multiline text report field. The Add ReportVisible
# fields operation must never replace its loaded TEXT format with a
# numeric .NET format such as {0,8:g}.
if (
    [string]::Equals(
        ([string]$columnName).Trim(),
        "RemarksTree",
        [System.StringComparison]::OrdinalIgnoreCase
    )
) {
    $fieldFormat =
        "TEXT,40,5"

    if (
        -not [string]::Equals(
            $currentGridFieldFormat,
            $fieldFormat,
            [System.StringComparison]::Ordinal
        )
    ) {
        $row.Cells["FieldFormat"].Value =
            $fieldFormat
    }
}
            if ([string]::IsNullOrWhiteSpace($columnId) -and [string]::IsNullOrWhiteSpace($tableName) -and [string]::IsNullOrWhiteSpace($columnName) -and [string]::IsNullOrWhiteSpace($fieldFormat) -and [string]::IsNullOrWhiteSpace($tallyFormat)) {
                continue
            }
            [void]$columns.Add([pscustomobject]@{
                ColumnID = $columnId
                TableName = $tableName
                ColumnName = $columnName
                Label = $label
                FieldFormat = $fieldFormat
                TallyFormat = $tallyFormat
            })
        }

                # Work with a normal array so the position immediately before
        # Remarks can be examined reliably.
        $projectPickleColumnArray =
            @(
                $columns.ToArray()
            )

        $projectPickleFinalCustomIndex =
            & $getProjectPickleFinalCustomColumnBeforeRemarksIndex `
                -Columns $projectPickleColumnArray `
                -Spec $spec

        if ($projectPickleFinalCustomIndex -ge 0) {
            $projectPickleFinalCustomColumn =
                $projectPickleColumnArray[
                    $projectPickleFinalCustomIndex
                ]

            $projectPickleFinalCustomColumn.FieldFormat =
                & $convertProjectPickleFinalCustomFormatForStorage `
                    -FieldFormat (
                        $projectPickleFinalCustomColumn.FieldFormat
                    )
        }

        return [pscustomobject]@{
            Key = ConvertTo-BuilderText $spec.Key
            DisplayName = ConvertTo-BuilderText $spec.DisplayName
            Section = ConvertTo-BuilderText $spec.Section
            ColumnGroup = [int]$spec.ColumnGroup
            HeaderGroup = $spec.HeaderGroup
            HeaderGroupIsNull = ConvertTo-BuilderBool $spec.HeaderGroupIsNull
            Title = ConvertTo-BuilderText $spec.Title
            CustomTableName = ConvertTo-BuilderText $spec.CustomTableName
            AnchorTableName = ConvertTo-BuilderText $spec.AnchorTableName
            AnchorColumnName = ConvertTo-BuilderText $spec.AnchorColumnName
            Columns = @($projectPickleColumnArray)
            HeaderLines = [string[]]@(& $getReportHeaderLinesFromEditor)
        }
    }.GetNewClosure()

        $previewTestReportButton.Add_Click({
        try {
            # Read the current grid and current exact header text.
            # This includes unsaved edits currently visible on screen.
            $currentLayout =
                & $getReportLayoutFromUi

            if ($null -eq $currentLayout) {
                throw (
                    "Select and load a report layout first."
                )
            }

            if (
                @($currentLayout.Columns).Count -eq 0
            ) {
                throw (
                    "The selected layout has no ReportColumns rows."
                )
            }

            $hasHeaderText = (
                @(
                    $currentLayout.HeaderLines |
                        Where-Object {
                            $null -ne $_ -and
                            ([string]$_).Length -gt 0
                        }
                ).Count -gt 0
            )

            if (-not $hasHeaderText) {
                throw (
                    "The selected layout has no ReportHeaders text."
                )
            }

            $previewPackage =
                New-ProjectPickleSyntheticReportPackage `
                    -Layout $currentLayout `
                    -RowCount 3

            Show-ProjectPickleSyntheticReportPreview `
                -Owner $form `
                -PreviewPackage $previewPackage

            $reportLoadStatusLabel.Text = (
                "Opened a synthetic preview for '{0}'. " +
                "The preview did not save or change the database." -f
                $previewPackage.LayoutName
            )
        }
        catch {
            [void][System.Windows.Forms.MessageBox]::Show(
                $form,
                (
                    "The synthetic report preview could not be created." +
                    "`r`n`r`n" +
                    $_.Exception.Message
                ),
                "Preview / print fake data",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Error
            )
        }
    }.GetNewClosure())

    $saveCurrentReportLayout = {
        param(
            [bool]$Validate = $false,
            [object]$SpecOverride = $null
        )

        $layout = & $getReportLayoutFromUi -SpecOverride $SpecOverride
        if ($null -eq $layout) { return $null }
        $hasHeaderText = @($layout.HeaderLines | Where-Object { $null -ne $_ -and ([string]$_).Length -gt 0 }).Count -gt 0
        if (@($layout.Columns).Count -eq 0 -and -not $hasHeaderText) {
            if ($reportUiState.Layouts.ContainsKey($layout.Key)) { $reportUiState.Layouts.Remove($layout.Key) }
            $reportUiState.IsDirty = $false
            return $null
        }
        if ($Validate) {
            $issues = @(Get-ManualReportLayoutIssues -Layout $layout)
            if ($issues.Count -gt 0) {
                throw "Reports tab layout needs attention:`r`n`r`n- " + ([string]::Join("`r`n- ", [string[]]$issues))
            }
        }
        $reportUiState.Layouts[$layout.Key] = Copy-ManualReportLayout -Layout $layout
        $reportUiState.IsDirty = $false
        return $reportUiState.Layouts[$layout.Key]
    }.GetNewClosure()

    $populateReportLayoutUi = {
    param(
        [object]$Layout
    )

    $reportUiState.IsLoading =
        $true

    try {
        $layoutColumns =
            @(
                $Layout.Columns
            )

        $finalCustomColumnIndex =
            & $getProjectPickleFinalCustomColumnBeforeRemarksIndex `
                -Columns $layoutColumns `
                -Spec $Layout

        $reportColumnsGrid.Rows.Clear()

        $order =
            1

        for (
            $columnIndex = 0;
            $columnIndex -lt $layoutColumns.Count;
            $columnIndex++
        ) {
            $column =
                $layoutColumns[$columnIndex]

            if ($null -eq $column) {
                continue
            }

            $columnNameForGrid =
                ConvertTo-BuilderText `
                    $column.ColumnName

            $fieldFormatForGrid =
                ConvertTo-RawSingleLineText `
                    $column.FieldFormat

            if (
                $columnIndex -eq
                $finalCustomColumnIndex
            ) {
                # Convert the special stored format back into an ordinary
                # format that Edit width / tally understands.
                $fieldFormatForGrid =
                    & $convertProjectPickleFinalCustomFormatForEditing `
                        -FieldFormat $fieldFormatForGrid
            }

            # Preserve the required Tree remarks format even if a bad
            # in-memory value was encountered.
            if (
                [string]::Equals(
                    $columnNameForGrid.Trim(),
                    "RemarksTree",
                    [System.StringComparison]::OrdinalIgnoreCase
                )
            ) {
                $fieldFormatForGrid =
                    "TEXT,40,5"
            }

            $rowIndex =
                $reportColumnsGrid.Rows.Add()

            $row =
                $reportColumnsGrid.Rows[
                    $rowIndex
                ]

            $row.Cells[
                "OrderNumber"
            ].Value =
                $order

            $row.Cells[
                "TableName"
            ].Value =
                ConvertTo-BuilderText `
                    $column.TableName

            $row.Cells[
                "ColumnName"
            ].Value =
                $columnNameForGrid

            $row.Cells[
                "Label"
            ].Value =
                ConvertTo-BuilderText `
                    $column.Label

            $row.Cells[
                "FieldFormat"
            ].Value =
                $fieldFormatForGrid

            $row.Cells[
                "TallyFormat"
            ].Value =
                ConvertTo-RawSingleLineText `
                    $column.TallyFormat

            $row.Cells[
                "ColumnID"
            ].Value =
                ConvertTo-BuilderText `
                    $column.ColumnID

            $order++
        }

        $reportHeaderEditor.Text =
            [string]::Join(
                "`r`n",
                [string[]]@(
                    $Layout.HeaderLines
                )
            )

        & $updateReportOrderNumbers
        & $updateReportHeaderStatus

        $reportUiState.IsDirty =
            $false
    }
    finally {
        $reportUiState.IsLoading =
            $false
    }
}.GetNewClosure()

    $showSelectedReportLayout = {
        $spec = & $getCurrentReportSpec
        if ($null -eq $spec) { return }
        $reportUiState.CurrentKey = ConvertTo-BuilderText $spec.Key
        if ($reportUiState.Layouts.ContainsKey($reportUiState.CurrentKey)) {
            & $populateReportLayoutUi -Layout (Copy-ManualReportLayout -Layout $reportUiState.Layouts[$reportUiState.CurrentKey])
            $reportLoadStatusLabel.Text = "Editing saved in-memory layout: $($spec.DisplayName). Build will apply it when Update reports is checked."
        }
        else {
            & $populateReportLayoutUi -Layout ([pscustomobject]@{ Columns = @(); HeaderLines = @() })
            $reportLoadStatusLabel.Text = "No manual layout loaded for $($spec.DisplayName). Click Load all from selected database."
        }
    }.GetNewClosure()

    $getReportDatabasePath = {
        $modeText = Get-WOOFComboText -Combo $modeBox
        if (Test-ModeUsesCurrentMasterDatabase -Mode $modeText) {
            return ConvertTo-BuilderText $upgradeTemplateBox.Text
        }
        return ConvertTo-BuilderText $sourceBox.Text
    }.GetNewClosure()

    $swapReportRows = {
        param([int]$Direction)

        if ($null -eq $reportColumnsGrid.CurrentRow -or $reportColumnsGrid.CurrentRow.IsNewRow) { return }
        $sourceIndex = $reportColumnsGrid.CurrentRow.Index
        $targetIndex = $sourceIndex + $Direction
        $lastDataIndex = $reportColumnsGrid.Rows.Count - 1
        if ($reportColumnsGrid.AllowUserToAddRows) { $lastDataIndex-- }
        if ($targetIndex -lt 0 -or $targetIndex -gt $lastDataIndex) { return }
        foreach ($column in $reportColumnsGrid.Columns) {
            $sourceValue = $reportColumnsGrid.Rows[$sourceIndex].Cells[$column.Index].Value
            $targetValue = $reportColumnsGrid.Rows[$targetIndex].Cells[$column.Index].Value
            $reportColumnsGrid.Rows[$sourceIndex].Cells[$column.Index].Value = $targetValue
            $reportColumnsGrid.Rows[$targetIndex].Cells[$column.Index].Value = $sourceValue
        }
        & $updateReportOrderNumbers
        $reportColumnsGrid.ClearSelection()
        $reportColumnsGrid.Rows[$targetIndex].Selected = $true
        $reportColumnsGrid.CurrentCell = $reportColumnsGrid.Rows[$targetIndex].Cells["ColumnName"]
        $reportUiState.IsDirty = $true
    }.GetNewClosure()

    $reportLayoutSelector.Add_SelectedIndexChanged({
        if ($reportUiState.IsLoading) { return }
        if (-not [string]::IsNullOrWhiteSpace($reportUiState.CurrentKey) -and $reportSpecByKey.ContainsKey($reportUiState.CurrentKey)) {
            try { [void](& $saveCurrentReportLayout -Validate $false -SpecOverride $reportSpecByKey[$reportUiState.CurrentKey]) } catch {}
        }
        & $showSelectedReportLayout
    }.GetNewClosure())

    $loadReportLayoutsButton.Add_Click({
        $connection = $null
        try {
            $databasePath = & $getReportDatabasePath
            if ([string]::IsNullOrWhiteSpace($databasePath)) {
                throw "Choose the current master database version or Existing/old project database on the Project tab first."
            }
            if (-not (Test-Path -LiteralPath $databasePath)) { throw "Database not found: $databasePath" }
            if ($reportUiState.Layouts.Count -gt 0) {
                $answer = [System.Windows.Forms.MessageBox]::Show("Reloading replaces all unsaved manual report layouts with the current database values. Continue?", "Reload report layouts", [System.Windows.Forms.MessageBoxButtons]::YesNo, [System.Windows.Forms.MessageBoxIcon]::Question)
                if ($answer -ne [System.Windows.Forms.DialogResult]::Yes) { return }
            }
            $connection = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $databasePath)
            $newState = @{}
            foreach ($spec in $reportSpecs) {
                $layout = Get-ReportLayoutFromConnection -Connection $connection -Spec $spec
                $newState[(ConvertTo-BuilderText $spec.Key)] = Copy-ManualReportLayout -Layout $layout
            }
            Initialize-ProjectPickleReportColumnIdBaseline -State $newState
            $reportUiState.Layouts = $newState
            & $showSelectedReportLayout
                        $reportLoadStatusLabel.Text = (
                "Loaded Plot, Tree, and Regen layouts " +
                "from the selected database."
            )
            $statusLabel.Text = "Loaded all manual report layouts. Add ReportVisible custom fields, edit formats, and align headers."
        }
        catch {
            [System.Windows.Forms.MessageBox]::Show($_.Exception.Message, "Load report layouts failed", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
        }
        finally {
            if ($null -ne $connection) {
                if ($connection.State -eq "Open") { $connection.Close() }
                $connection.Dispose()
            }
        }
    }.GetNewClosure())

    $saveReportLayoutButton.Add_Click({
        try {
            $saved = & $saveCurrentReportLayout -Validate $true
            if ($null -eq $saved) { throw "There is no current report layout to save. Load the database layout first." }
            $reportLoadStatusLabel.Text = "Saved manual layout in memory: $($saved.DisplayName). It will be written during Build."
            $statusLabel.Text = "Saved $($saved.DisplayName) report layout."
        }
        catch {
            [System.Windows.Forms.MessageBox]::Show($_.Exception.Message, "Report layout needs attention", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
        }
    }.GetNewClosure())

    $validateReportLayoutsButton.Add_Click({
        try {
            [void](& $saveCurrentReportLayout -Validate $false)
            $layouts = New-Object System.Collections.Generic.List[object]
            foreach ($spec in $reportSpecs) {
                $key = ConvertTo-BuilderText $spec.Key
                if ($reportUiState.Layouts.ContainsKey($key)) { [void]$layouts.Add((Copy-ManualReportLayout -Layout $reportUiState.Layouts[$key])) }
            }
            if ($layouts.Count -eq 0) { throw "No manual report layouts are loaded. Click Load all from selected database first." }
            $issues = @(Get-ManualReportLayoutsIssues -Layouts @($layouts.ToArray()))
            if ($issues.Count -gt 0) { throw "Reports tab layout needs attention:`r`n`r`n- " + ([string]::Join("`r`n- ", [string[]]$issues)) }
            [System.Windows.Forms.MessageBox]::Show("All loaded report layouts passed validation. Build will write the exact column order, formats, and header spacing shown here.", "Report layouts valid", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
        }
        catch {
            [System.Windows.Forms.MessageBox]::Show($_.Exception.Message, "Report layout validation", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
        }
    }.GetNewClosure())

    # ---------------------------------------------------------------------------
# RemarksTree FieldFormat protection
#
# IMPORTANT:
# This code must remain AFTER Project Pickle's original
# $addReportFieldsButton.Add_Click({ ... }) handler.
#
# The additional click handler therefore runs after the normal handler.
# CellValueChanged also catches any later grid assignment and immediately
# restores the required RemarksTree text format.
# ---------------------------------------------------------------------------

$script:ProjectPickleRepairingRemarksTreeFormat =
    $false


$repairProjectPickleRemarksTreeFormat = {
    if (
        $script:ProjectPickleRepairingRemarksTreeFormat
    ) {
        return
    }

    $script:ProjectPickleRepairingRemarksTreeFormat =
        $true

    $loadingBeforeRepair =
        [bool]$reportUiState.IsLoading

    $dirtyBeforeRepair =
        [bool]$reportUiState.IsDirty

    try {
        # Prevent the repair itself from being interpreted as a manual edit.
        $reportUiState.IsLoading =
            $true

        # Repair the visible grid.
        foreach (
            $row in $reportColumnsGrid.Rows
        ) {
            if (
                $null -eq $row -or
                $row.IsNewRow
            ) {
                continue
            }

            $columnName = (
                ConvertTo-BuilderText `
                    $row.Cells["ColumnName"].Value
            ).Trim()

            if (
                -not [string]::Equals(
                    $columnName,
                    "RemarksTree",
                    [System.StringComparison]::OrdinalIgnoreCase
                )
            ) {
                continue
            }

            $currentFieldFormat =
                ConvertTo-RawSingleLineText `
                    $row.Cells["FieldFormat"].Value

            if (
                -not [string]::Equals(
                    $currentFieldFormat,
                    "TEXT,40,5",
                    [System.StringComparison]::Ordinal
                )
            ) {
                $row.Cells["FieldFormat"].Value =
                    "TEXT,40,5"
            }
        }

        # Repair the current in-memory layout too. This is important when
        # the normal Add ReportVisible fields handler already rebuilt or
        # stored the layout before this repair handler runs.
        $currentSpec =
            & $getCurrentReportSpec

        if ($null -ne $currentSpec) {
            $layoutKey = (
                ConvertTo-BuilderText `
                    $currentSpec.Key
            ).Trim()

            if (
                -not [string]::IsNullOrWhiteSpace(
                    $layoutKey
                ) -and
                $null -ne $reportUiState.Layouts -and
                $reportUiState.Layouts.ContainsKey(
                    $layoutKey
                )
            ) {
                $currentLayout =
                    $reportUiState.Layouts[
                        $layoutKey
                    ]

                if ($null -ne $currentLayout) {
                    foreach (
                        $column in @(
                            $currentLayout.Columns
                        )
                    ) {
                        if ($null -eq $column) {
                            continue
                        }

                        $columnName = (
                            ConvertTo-BuilderText `
                                $column.ColumnName
                        ).Trim()

                        if (
                            -not [string]::Equals(
                                $columnName,
                                "RemarksTree",
                                [System.StringComparison]::OrdinalIgnoreCase
                            )
                        ) {
                            continue
                        }

                        $fieldFormatProperty =
                            $column.PSObject.Properties[
                                "FieldFormat"
                            ]

                        if (
                            $null -ne $fieldFormatProperty -and
                            $fieldFormatProperty.IsSettable
                        ) {
                            $fieldFormatProperty.Value =
                                "TEXT,40,5"
                        }
                    }
                }
            }
        }
    }
    finally {
        # Keep the loading and dirty states established by the normal
        # Project Pickle workflow.
        $reportUiState.IsLoading =
            $loadingBeforeRepair

        $reportUiState.IsDirty =
            $dirtyBeforeRepair

        $script:ProjectPickleRepairingRemarksTreeFormat =
            $false
    }

    try {
        $reportColumnsGrid.Refresh()
    }
    catch {
    }
}.GetNewClosure()


# Catch any attempt to assign a different format while the grid is being
# rebuilt, loaded, edited, or refreshed.
$reportColumnsGrid.Add_CellValueChanged({
    param(
        $Sender,
        $EventArgs
    )

    if (
        $script:ProjectPickleRepairingRemarksTreeFormat
    ) {
        return
    }

    if (
        $null -eq $EventArgs -or
        $EventArgs.RowIndex -lt 0 -or
        $EventArgs.ColumnIndex -lt 0
    ) {
        return
    }

    $changedColumn =
        $Sender.Columns[
            $EventArgs.ColumnIndex
        ]

    if ($null -eq $changedColumn) {
        return
    }

    $changedColumnName =
        ConvertTo-BuilderText `
            $changedColumn.Name

    $relevantColumnChanged = (
        [string]::Equals(
            $changedColumnName,
            "ColumnName",
            [System.StringComparison]::OrdinalIgnoreCase
        ) -or
        [string]::Equals(
            $changedColumnName,
            "FieldFormat",
            [System.StringComparison]::OrdinalIgnoreCase
        )
    )

    if (-not $relevantColumnChanged) {
        return
    }

    & $repairProjectPickleRemarksTreeFormat
}.GetNewClosure())


# This handler is deliberately registered after Project Pickle's original
# Add ReportVisible fields handler. .NET invokes the handlers in registration
# order, so this repair runs synchronously after the normal add operation.
$addReportFieldsButton.Add_Click({
    & $repairProjectPickleRemarksTreeFormat
}.GetNewClosure())

    $addReportFieldsButton.Add_Click({
        try {
            $spec = & $getCurrentReportSpec
            if ($null -eq $spec) { return }
            $layout = & $getReportLayoutFromUi
            if (@($layout.Columns).Count -eq 0) { throw "Load the database report layouts first so required standard fields and the remarks field are preserved." }
            $appColumnRows = @(Get-CustomRowsFromGrid)
            $available = @($appColumnRows | Where-Object {
                [string]::Equals((ConvertTo-BuilderText $_.TableName), (ConvertTo-BuilderText $spec.CustomTableName), [System.StringComparison]::OrdinalIgnoreCase) -and
                (ConvertTo-BuilderBool $_.Active) -and
                (ConvertTo-BuilderBool $_.ReportVisible) -and
                -not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $_.FieldName))
            })
            $existing = New-Object "System.Collections.Generic.HashSet[string]" ([System.StringComparer]::OrdinalIgnoreCase)
            foreach ($column in @($layout.Columns)) {
                [void]$existing.Add("$(ConvertTo-BuilderText $column.TableName).$(ConvertTo-BuilderText $column.ColumnName)")
            }
            $toAdd = New-Object System.Collections.Generic.List[object]
            foreach ($field in $available) {
                $identity = "$(ConvertTo-BuilderText $field.TableName).$(ConvertTo-BuilderText $field.FieldName)"
                if ($existing.Contains($identity)) { continue }
                $fieldFormat = New-ReportFieldFormat -Field $field
                [void]$toAdd.Add([pscustomobject]@{
                    ColumnID = ConvertTo-BuilderText $field.AppColumnID
                    TableName = ConvertTo-BuilderText $field.TableName
                    ColumnName = ConvertTo-BuilderText $field.FieldName
                    Label = Get-ReportFieldLabel -Field $field
                    FieldFormat = $fieldFormat
                    TallyFormat = New-ReportTallyFormat -FieldFormat $fieldFormat
                })
                [void]$existing.Add($identity)
            }
            if ($toAdd.Count -eq 0) {
                [System.Windows.Forms.MessageBox]::Show("No additional Active + ReportVisible $($spec.CustomTableName) fields were found. Review the AppColumns tab or the fields may already be present.", "No report fields to add", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
                return
            }

            $combined = New-Object System.Collections.Generic.List[object]
            $inserted = $false
            foreach ($column in @($layout.Columns)) {
                if (-not $inserted -and [string]::Equals((ConvertTo-BuilderText $column.ColumnName), (ConvertTo-BuilderText $spec.AnchorColumnName), [System.StringComparison]::OrdinalIgnoreCase)) {
                    foreach ($newColumn in $toAdd) { [void]$combined.Add($newColumn) }
                    $inserted = $true
                }
                [void]$combined.Add($column)
            }
            if (-not $inserted) { foreach ($newColumn in $toAdd) { [void]$combined.Add($newColumn) } }
            $layout.Columns = @($combined.ToArray())
            & $populateReportLayoutUi -Layout $layout
            $reportUiState.IsDirty = $true
            $reportLoadStatusLabel.Text = "Added $($toAdd.Count) ReportVisible field(s) before $($spec.AnchorColumnName). Adjust FieldFormat/TallyFormat and edit the exact header text."
        }
        catch {
            [System.Windows.Forms.MessageBox]::Show($_.Exception.Message, "Add report fields failed", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
        }
    }.GetNewClosure())

        # Run after the normal Add ReportVisible fields handler. This fills
    # blank new Code formats without changing loaded template rows.
