    function Refresh-GetOrderGridNumbers {
        param([System.Windows.Forms.DataGridView]$Grid)

        $index = 1
        foreach ($row in $Grid.Rows) {
            if ($row.IsNewRow) { continue }
            $row.Cells["OrderNumber"].Value = $index
            $index++
        }
    }

    function Move-GetOrderRow {
        param(
            [System.Windows.Forms.DataGridView]$Grid,
            [int]$Direction
        )

        if ($null -eq $Grid -or $null -eq $Grid.CurrentRow -or $Grid.CurrentRow.IsNewRow) { return }
        $oldIndex = $Grid.CurrentRow.Index
        $newIndex = $oldIndex + $Direction
        if ($newIndex -lt 0 -or $newIndex -ge $Grid.Rows.Count) { return }
        if ($Grid.Rows[$newIndex].IsNewRow) { return }

        foreach ($columnName in @("TableName", "FieldName", "OrderKey")) {
            $oldValue = $Grid.Rows[$oldIndex].Cells[$columnName].Value
            $Grid.Rows[$oldIndex].Cells[$columnName].Value = $Grid.Rows[$newIndex].Cells[$columnName].Value
            $Grid.Rows[$newIndex].Cells[$columnName].Value = $oldValue
        }
        Refresh-GetOrderGridNumbers -Grid $Grid
        $Grid.CurrentCell = $Grid.Rows[$newIndex].Cells["FieldName"]
    }

    function Add-GetOrderCandidate {
        param(
            [System.Windows.Forms.DataGridView]$Grid,
            [string]$TableName,
            [string]$FieldName
        )

        $table = ConvertTo-BuilderText $TableName
        $field = ConvertTo-BuilderText $FieldName
        if ([string]::IsNullOrWhiteSpace($table) -or [string]::IsNullOrWhiteSpace($field)) { return }
        if (Test-CfideerSampleRemoveField -FieldName $field) { return }
        if (-not (Test-GetOrderCandidateAllowed -TableName $table -FieldName $field)) { return }
        $key = "$table.$field"
        foreach ($row in $Grid.Rows) {
            if ($row.IsNewRow) { continue }
            if ([string]::Equals((ConvertTo-BuilderText $row.Cells["OrderKey"].Value), $key, [System.StringComparison]::OrdinalIgnoreCase)) { return }
        }
        $idx = $Grid.Rows.Add()
        $row = $Grid.Rows[$idx]
        $row.Cells["TableName"].Value = $table
        $row.Cells["FieldName"].Value = $field
        $row.Cells["OrderKey"].Value = $key
        Refresh-GetOrderGridNumbers -Grid $Grid
    }

    function New-GetOrderFieldKey {
        param(
            [string]$TableName,
            [string]$FieldName
        )

        $table = (ConvertTo-BuilderText $TableName) -replace "[\[\]\s]", ""
        $field = (ConvertTo-BuilderText $FieldName) -replace "[\[\]\s]", ""
        if ([string]::IsNullOrWhiteSpace($table) -or [string]::IsNullOrWhiteSpace($field)) { return "" }
        return "$table.$field"
    }

    function Test-GetOrderNameInList {
        param(
            [string]$Name,
            [string[]]$Names
        )

        $clean = ConvertTo-BuilderText $Name
        foreach ($item in @($Names)) {
            if ([string]::Equals((ConvertTo-BuilderText $item), $clean, [System.StringComparison]::OrdinalIgnoreCase)) { return $true }
        }
        return $false
    }

    function Test-GetOrderCandidateAllowed {
        param(
            [string]$TableName,
            [string]$FieldName
        )

        $table = ConvertTo-BuilderText $TableName
        $field = ConvertTo-BuilderText $FieldName
        if ([string]::IsNullOrWhiteSpace($table) -or [string]::IsNullOrWhiteSpace($field)) { return $false }
        if (Test-CfideerSampleRemoveField -FieldName $field) { return $false }

        switch ($table) {
            "PlotMeasurements" { return -not (Test-GetOrderNameInList -Name $field -Names @("PlotID", "ProjectPeriodID", "CalcSiteIndex", "GMP", "Created", "Updated", "UpdUser", "RetrievalID", "RetrevalID", "MeasurementID", "PlotMeasKey")) }
            "PlotCustomMeasurements" { return -not (Test-GetOrderNameInList -Name $field -Names @("MeasurementID", "PlotMeasKey")) }
            "TreeMeasurements" { return -not (Test-GetOrderNameInList -Name $field -Names @("TreeKey", "ProjectPeriodID", "Created", "Updated", "UpdUser", "RetrievalID", "RetrevalID", "MeasurementID", "TreeMeasKey")) }
            "TreeCustomMeasurements" { return -not (Test-GetOrderNameInList -Name $field -Names @("MeasurementID", "TreeMeasKey")) }
            "RegenMeasurements" { return -not (Test-GetOrderNameInList -Name $field -Names @("PlotNumber", "PlotID", "ProjectPeriodID", "MeasurementID", "IsDeleted", "Created", "Updated", "UpdUser", "RetrievalID", "RetrevalID", "RegenMeasKey")) }
            "RegenCustomMeasurements" { return -not (Test-GetOrderNameInList -Name $field -Names @("MeasurementID", "RegenMeasKey")) }
            default { return $false }
        }
    }

    function Get-GetOrderSelectItemsFromSql {
        param([string]$Sql)

        $sourceSql = ConvertTo-BuilderText $Sql
        $match = [regex]::Match($sourceSql, "(?is)\bSELECT\b(?<select>.*?)\bFROM\b")
        if (-not $match.Success) { return @() }
        return @($match.Groups["select"].Value -split "," | ForEach-Object { ConvertTo-BuilderText $_ } | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
    }

    function Get-GetOrderCandidateFromSelectItem {
        param(
            [string]$SelectItem,
            [string]$DefaultTableName,
            [string[]]$AllowedTables
        )

        $item = ConvertTo-BuilderText $SelectItem
        if ([string]::IsNullOrWhiteSpace($item)) { return $null }
        $expression = [regex]::Replace($item, "(?is)\s+AS\s+.+$", "").Trim()
        if ($expression -match "\*") { return $null }
        $plain = ($expression -replace "[\[\]]", "")

        foreach ($table in @($AllowedTables)) {
            $cleanTable = ConvertTo-BuilderText $table
            if ([string]::IsNullOrWhiteSpace($cleanTable)) { continue }
            $match = [regex]::Match($plain, "(?i)(^|[^A-Za-z0-9_])$([regex]::Escape($cleanTable))\s*\.\s*(?<field>[A-Za-z_][A-Za-z0-9_]*)")
            if ($match.Success) {
                $field = ConvertTo-BuilderText $match.Groups["field"].Value
                if (Test-GetOrderCandidateAllowed -TableName $cleanTable -FieldName $field) {
                    return [pscustomobject]@{ TableName = $cleanTable; FieldName = $field }
                }
                return $null
            }
        }

        $fieldMatch = [regex]::Match($plain, "(?i)(?<field>[A-Za-z_][A-Za-z0-9_]*)\s*$")
        if ($fieldMatch.Success) {
            $field = ConvertTo-BuilderText $fieldMatch.Groups["field"].Value
            if (Test-GetOrderCandidateAllowed -TableName $DefaultTableName -FieldName $field) {
                return [pscustomobject]@{ TableName = $DefaultTableName; FieldName = $field }
            }
        }
        return $null
    }

    function Get-GetOrderSetupMaps {
        Save-LoadedAppColumnGridState

        $current = New-Object "System.Collections.Generic.HashSet[string]" ([System.StringComparer]::OrdinalIgnoreCase)
        $original = New-Object "System.Collections.Generic.HashSet[string]" ([System.StringComparer]::OrdinalIgnoreCase)
        $hasLoadedSetup = $false

        foreach ($item in @($script:BuilderLoadedAppColumnItems)) {
            if ($null -eq $item) { continue }
            $hasLoadedSetup = $true
            $tableName = ConvertTo-BuilderText $item.TableName
            $fieldName = ConvertTo-BuilderText $item.FieldName
            if (-not (Test-GetOrderCandidateAllowed -TableName $tableName -FieldName $fieldName)) { continue }
            $key = New-GetOrderFieldKey -TableName $tableName -FieldName $fieldName
            if ([string]::IsNullOrWhiteSpace($key)) { continue }

            $active = ConvertTo-BuilderBool $item.Active
            $queryVisible = if ($item.PSObject.Properties["QueryVisible"]) { ConvertTo-BuilderBool $item.QueryVisible } else { $true }
            if ($active -and $queryVisible) { [void]$current.Add($key) }

            $originalActive = if ($item.PSObject.Properties["OriginalActive"]) { ConvertTo-BuilderBool $item.OriginalActive } else { $active }
            $originalQueryVisible = if ($item.PSObject.Properties["OriginalQueryVisible"]) { ConvertTo-BuilderBool $item.OriginalQueryVisible } else { $queryVisible }
            if ($originalActive -and $originalQueryVisible) { [void]$original.Add($key) }
        }

        foreach ($row in $customFieldGrid.Rows) {
            if ($row.IsNewRow) { continue }
            $tableName = ConvertTo-BuilderText $row.Cells["TableName"].Value
            $fieldName = ConvertTo-BuilderText $row.Cells["FieldName"].Value
            if (-not (Test-GetOrderCandidateAllowed -TableName $tableName -FieldName $fieldName)) { continue }
            $active = ConvertTo-BuilderBool $row.Cells["Active"].Value
            $queryVisible = ConvertTo-BuilderBool $row.Cells["QueryVisible"].Value
            if (-not ($active -and $queryVisible)) { continue }
            $key = New-GetOrderFieldKey -TableName $tableName -FieldName $fieldName
            if (-not [string]::IsNullOrWhiteSpace($key)) { [void]$current.Add($key) }
        }

        return [pscustomobject]@{
            Current = $current
            Original = $original
            UseLoadedFilter = $hasLoadedSetup
        }
    }

    function Test-GetOrderKeyAllowedBySetup {
        param(
            [object]$SetupMaps,
            [string]$TableName,
            [string]$FieldName,
            [switch]$RequireOriginal
        )

        if ($null -eq $SetupMaps -or -not (ConvertTo-BuilderBool $SetupMaps.UseLoadedFilter)) { return $true }
        $key = New-GetOrderFieldKey -TableName $TableName -FieldName $FieldName
        if ([string]::IsNullOrWhiteSpace($key)) { return $false }
        if (-not $SetupMaps.Current.Contains($key)) { return $false }
        if ($RequireOriginal -and -not $SetupMaps.Original.Contains($key)) { return $false }
        return $true
    }

    function Add-GetOrderCandidatesFromSavedQuery {
        param(
            [System.Windows.Forms.DataGridView]$Grid,
            [string]$DatabasePath,
            [string]$QueryName,
            [string]$DefaultTableName,
            [string[]]$AllowedTables,
            [object]$SetupMaps
        )

        if ([string]::IsNullOrWhiteSpace($DatabasePath) -or -not (Test-Path -LiteralPath $DatabasePath)) { return 0 }
        $beforeCount = $Grid.Rows.Count
        try {
            $sql = Get-AccessQueryDefinitionSql -DatabasePath $DatabasePath -QueryName $QueryName
            foreach ($item in (Get-GetOrderSelectItemsFromSql -Sql $sql)) {
                $candidate = Get-GetOrderCandidateFromSelectItem -SelectItem $item -DefaultTableName $DefaultTableName -AllowedTables $AllowedTables
                if ($null -eq $candidate) { continue }
                if (-not (Test-GetOrderKeyAllowedBySetup -SetupMaps $SetupMaps -TableName $candidate.TableName -FieldName $candidate.FieldName -RequireOriginal)) { continue }
                Add-GetOrderCandidate -Grid $Grid -TableName $candidate.TableName -FieldName $candidate.FieldName
            }
        }
        catch {
            return 0
        }
        return ($Grid.Rows.Count - $beforeCount)
    }

    function Add-GetOrderFieldSpecs {
        param(
            [System.Windows.Forms.DataGridView]$Grid,
            [string]$TableName,
            [object[]]$Fields,
            [string[]]$SkipFields = @(),
            [object]$SetupMaps = $null
        )

        foreach ($field in @($Fields)) {
            $fieldName = Get-CfideerFieldName $field
            if ([string]::IsNullOrWhiteSpace($fieldName)) { continue }
            if (@($SkipFields | Where-Object { [string]::Equals($_, $fieldName, [System.StringComparison]::OrdinalIgnoreCase) }).Count -gt 0) { continue }
            if (-not (Test-GetOrderKeyAllowedBySetup -SetupMaps $SetupMaps -TableName $TableName -FieldName $fieldName -RequireOriginal)) { continue }
            Add-GetOrderCandidate -Grid $Grid -TableName $TableName -FieldName $fieldName
        }
    }

    function Add-GetOrderCandidateFromAppColumnItem {
        param([object]$Item)

        if ($null -eq $Item) { return }
        if (-not (ConvertTo-BuilderBool $Item.Active)) { return }
        if ($Item.PSObject.Properties["QueryVisible"] -and -not (ConvertTo-BuilderBool $Item.QueryVisible)) { return }
        $tableName = ConvertTo-BuilderText $Item.TableName
        $fieldName = ConvertTo-BuilderText $Item.FieldName
        if ([string]::IsNullOrWhiteSpace($tableName) -or [string]::IsNullOrWhiteSpace($fieldName)) { return }

        $plotSkip = @("PlotID", "ProjectPeriodID", "CalcSiteIndex", "GMP", "Created", "Updated", "UpdUser", "RetrievalID", "RetrevalID", "RemarksPlot")
        $treeSkip = @("TreeKey", "ProjectPeriodID", "Created", "Updated", "UpdUser", "RetrievalID", "RetrevalID", "RemarksTree")
        $regenSkip = @("PlotNumber", "PlotID", "ProjectPeriodID", "MeasurementID", "IsDeleted", "Created", "Updated", "UpdUser", "RetrievalID", "RetrevalID", "RemarksRegen")

        switch ($tableName) {
            "PlotMeasurements" { if ($plotSkip -notcontains $fieldName) { Add-GetOrderCandidate -Grid $plotGetOrderGrid -TableName $tableName -FieldName $fieldName }; break }
            "PlotCustomMeasurements" { if ($fieldName -notin @("MeasurementID", "PlotMeasKey")) { Add-GetOrderCandidate -Grid $plotGetOrderGrid -TableName $tableName -FieldName $fieldName }; break }
            "TreeMeasurements" { if ($treeSkip -notcontains $fieldName) { Add-GetOrderCandidate -Grid $treeGetOrderGrid -TableName $tableName -FieldName $fieldName }; break }
            "TreeCustomMeasurements" { if ($fieldName -notin @("MeasurementID", "TreeMeasKey")) { Add-GetOrderCandidate -Grid $treeGetOrderGrid -TableName $tableName -FieldName $fieldName }; break }
            "RegenMeasurements" { if ($regenSkip -notcontains $fieldName) { Add-GetOrderCandidate -Grid $regenGetOrderGrid -TableName $tableName -FieldName $fieldName }; break }
            "RegenCustomMeasurements" { if ($fieldName -notin @("MeasurementID", "RegenMeasKey")) { Add-GetOrderCandidate -Grid $regenGetOrderGrid -TableName $tableName -FieldName $fieldName }; break }
        }
    }

    function Get-GetOrderDefaultFieldNames {
        param([string]$Domain)

        switch (ConvertTo-BuilderText $Domain) {
            "Plot" {
                return @(
                    "PlotStatus", "MeasurementDate", "Crew", "HabitatType", "CoverType",
                    "SizeClass", "DensityClass", "StandClass", "StandAge", "StockabilityPct",
                    "StockabilityFactor", "SISpecies", "SIDBH", "SITotalHeight", "SIAge",
                    "SIGrowth", "RemarksPlot"
                )
            }
            "Tree" {
                return @(
                    "TreeHistory", "MinorPlot", "IDBH", "RealDBH", "RadialIncrement",
                    "TotalHeight", "CrownRatio", "CrownClass", "TreeAge", "Problem1",
                    "Severity1", "Problem2", "Severity2", "DMR", "BDFTDefect",
                    "CUFTDefect", "SnagClass", "RemarksTree"
                )
            }
            "Regen" {
                return @(
                    "MinorPlot", "SpeciesCode", "IDBH", "StemCount", "RemarksRegen"
                )
            }
            default { return @() }
        }
    }

    function Add-GetOrderDefaultFields {
        foreach ($fieldName in @(Get-GetOrderDefaultFieldNames -Domain "Plot")) {
            Add-GetOrderCandidate -Grid $plotGetOrderGrid -TableName "PlotMeasurements" -FieldName $fieldName
        }
        foreach ($fieldName in @(Get-GetOrderDefaultFieldNames -Domain "Tree")) {
            Add-GetOrderCandidate -Grid $treeGetOrderGrid -TableName "TreeMeasurements" -FieldName $fieldName
        }
        foreach ($fieldName in @(Get-GetOrderDefaultFieldNames -Domain "Regen")) {
            Add-GetOrderCandidate -Grid $regenGetOrderGrid -TableName "RegenMeasurements" -FieldName $fieldName
        }
    }
    
    function Populate-GetQueryOrderGrids {
        foreach ($grid in @($plotGetOrderGrid, $treeGetOrderGrid, $regenGetOrderGrid)) {
            $grid.Rows.Clear()
        }

        $selectedMode = Get-WOOFComboText -Combo $modeBox
        if (-not (Test-WOOFTextEquals $selectedMode "Existing Project")) {
            Add-GetOrderDefaultFields
            foreach ($item in @($script:BuilderLoadedAppColumnItems)) {
                Add-GetOrderCandidateFromAppColumnItem -Item $item
            }
            foreach ($row in $customFieldGrid.Rows) {
                if ($row.IsNewRow) { continue }
                Add-GetOrderCandidateFromAppColumnItem -Item ([pscustomobject]@{
                    TableName = ConvertTo-BuilderText $row.Cells["TableName"].Value
                    FieldName = ConvertTo-BuilderText $row.Cells["FieldName"].Value
                    Active = ConvertTo-BuilderBool $row.Cells["Active"].Value
                    QueryVisible = ConvertTo-BuilderBool $row.Cells["QueryVisible"].Value
                })
            }

            foreach ($grid in @($plotGetOrderGrid, $treeGetOrderGrid, $regenGetOrderGrid)) {
                Refresh-GetOrderGridNumbers -Grid $grid
            }
            $statusLabel.Text = "Loaded Get field order from Active + QueryVisible AppColumns. Move rows here to set the exact CFIDEER Get query field order."
            return
        }

        $sourcePath = ConvertTo-BuilderText $sourceBox.Text
        $masterPath = ConvertTo-BuilderText $upgradeTemplateBox.Text
        $orderPaths = New-Object System.Collections.Generic.List[string]
        foreach ($candidatePath in @($sourcePath, $masterPath)) {
            if ([string]::IsNullOrWhiteSpace($candidatePath) -or -not (Test-Path -LiteralPath $candidatePath)) { continue }
            $alreadyAdded = $false
            foreach ($existingPath in @($orderPaths.ToArray())) {
                if ([string]::Equals($existingPath, $candidatePath, [System.StringComparison]::OrdinalIgnoreCase)) {
                    $alreadyAdded = $true
                    break
                }
            }
            if (-not $alreadyAdded) { [void]$orderPaths.Add($candidatePath) }
        }

        $setupMaps = Get-GetOrderSetupMaps
        $loadedFromSavedQuery = @{
            Plot = $false
            Tree = $false
            Regen = $false
        }

        foreach ($orderPath in @($orderPaths.ToArray())) {
            if (-not $loadedFromSavedQuery["Plot"]) {
                $added = Add-GetOrderCandidatesFromSavedQuery -Grid $plotGetOrderGrid -DatabasePath $orderPath -QueryName "_prjCFIDEER_GetPlotMeasurementsForPeriod" -DefaultTableName "PlotMeasurements" -AllowedTables @("PlotMeasurements", "PlotCustomMeasurements") -SetupMaps $setupMaps
                if ($added -gt 0) { $loadedFromSavedQuery["Plot"] = $true }
            }
            if (-not $loadedFromSavedQuery["Tree"]) {
                $added = Add-GetOrderCandidatesFromSavedQuery -Grid $treeGetOrderGrid -DatabasePath $orderPath -QueryName "_prjCFIDEER_GetTreeMeasurementsForPeriodByKey" -DefaultTableName "TreeMeasurements" -AllowedTables @("TreeMeasurements", "TreeCustomMeasurements") -SetupMaps $setupMaps
                if ($added -gt 0) { $loadedFromSavedQuery["Tree"] = $true }
            }
            if (-not $loadedFromSavedQuery["Regen"]) {
                $added = Add-GetOrderCandidatesFromSavedQuery -Grid $regenGetOrderGrid -DatabasePath $orderPath -QueryName "_prjCFIDEER_GetRegenMeasurements" -DefaultTableName "RegenMeasurements" -AllowedTables @("RegenMeasurements", "RegenCustomMeasurements") -SetupMaps $setupMaps
                if ($added -gt 0) { $loadedFromSavedQuery["Regen"] = $true }
            }
            if ($loadedFromSavedQuery["Plot"] -and $loadedFromSavedQuery["Tree"] -and $loadedFromSavedQuery["Regen"]) { break }
        }

        $tableOrderPath = ""
        foreach ($candidatePath in @($orderPaths.ToArray())) {
            if (-not [string]::IsNullOrWhiteSpace($candidatePath) -and (Test-Path -LiteralPath $candidatePath)) {
                $tableOrderPath = $candidatePath
                break
            }
        }
        if (-not [string]::IsNullOrWhiteSpace($tableOrderPath) -and (Test-Path -LiteralPath $tableOrderPath)) {
            $connection = $null
            try {
                $connection = Open-AccessConnection -ConnectionString (New-AccessConnectionString -Path $tableOrderPath)
                $plotFields = @(Get-ActiveFieldsForTable -Connection $connection -TableName "PlotMeasurements" -RequiredLast @("RemarksPlot", "PlotID", "ProjectPeriodID") -Exclude @("MeasurementID", "PlotMeasKey"))
                $plotCustomFields = @(Get-ActiveFieldsForTable -Connection $connection -TableName "PlotCustomMeasurements" -Exclude @("MeasurementID", "PlotMeasKey"))
                $treeFields = @(Get-ActiveFieldsForTable -Connection $connection -TableName "TreeMeasurements" -RequiredLast @("RemarksTree", "TreeKey", "ProjectPeriodID") -Exclude @("MeasurementID", "TreeMeasKey"))
                $treeCustomFields = @(Get-ActiveFieldsForTable -Connection $connection -TableName "TreeCustomMeasurements" -Exclude @("MeasurementID", "TreeMeasKey"))
                $regenFields = @(Get-ActiveFieldsForTable -Connection $connection -TableName "RegenMeasurements" -RequiredLast @("RemarksRegen", "MeasurementID") -Exclude @("RegenMeasKey"))
                $regenCustomFields = @(Get-ActiveFieldsForTable -Connection $connection -TableName "RegenCustomMeasurements" -Exclude @("MeasurementID", "RegenMeasKey"))

                if (-not $loadedFromSavedQuery["Plot"]) {
                    Add-GetOrderFieldSpecs -Grid $plotGetOrderGrid -TableName "PlotMeasurements" -Fields $plotFields -SkipFields @("PlotID", "ProjectPeriodID", "CalcSiteIndex", "GMP", "Created", "Updated", "UpdUser", "RetrievalID", "RetrevalID", "RemarksPlot") -SetupMaps $setupMaps
                    Add-GetOrderFieldSpecs -Grid $plotGetOrderGrid -TableName "PlotCustomMeasurements" -Fields $plotCustomFields -SetupMaps $setupMaps
                }
                if (-not $loadedFromSavedQuery["Tree"]) {
                    Add-GetOrderFieldSpecs -Grid $treeGetOrderGrid -TableName "TreeMeasurements" -Fields $treeFields -SkipFields @("TreeKey", "ProjectPeriodID", "Created", "Updated", "UpdUser", "RetrievalID", "RetrevalID", "RemarksTree") -SetupMaps $setupMaps
                    Add-GetOrderFieldSpecs -Grid $treeGetOrderGrid -TableName "TreeCustomMeasurements" -Fields $treeCustomFields -SetupMaps $setupMaps
                }
                if (-not $loadedFromSavedQuery["Regen"]) {
                    Add-GetOrderFieldSpecs -Grid $regenGetOrderGrid -TableName "RegenMeasurements" -Fields $regenFields -SkipFields @("PlotNumber", "PlotID", "ProjectPeriodID", "MeasurementID", "IsDeleted", "Created", "Updated", "UpdUser", "RetrievalID", "RetrevalID", "RemarksRegen") -SetupMaps $setupMaps
                    Add-GetOrderFieldSpecs -Grid $regenGetOrderGrid -TableName "RegenCustomMeasurements" -Fields $regenCustomFields -SetupMaps $setupMaps
                }
            }
            catch {
                [System.Windows.Forms.MessageBox]::Show("Project Pickle could not load query fields from the selected database. It will still add any fields currently listed in AppColumns.`r`n`r`n$($_.Exception.Message)", "Load Get query field order", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
            }
            finally {
                if ($connection) { if ($connection.State -eq "Open") { $connection.Close() }; $connection.Dispose() }
            }
        }

        foreach ($item in @($script:BuilderLoadedAppColumnItems)) {
            Add-GetOrderCandidateFromAppColumnItem -Item $item
        }
        foreach ($row in $customFieldGrid.Rows) {
            if ($row.IsNewRow) { continue }
            Add-GetOrderCandidateFromAppColumnItem -Item ([pscustomobject]@{
                TableName = ConvertTo-BuilderText $row.Cells["TableName"].Value
                FieldName = ConvertTo-BuilderText $row.Cells["FieldName"].Value
                Active = ConvertTo-BuilderBool $row.Cells["Active"].Value
                QueryVisible = ConvertTo-BuilderBool $row.Cells["QueryVisible"].Value
            })
        }

        Add-GetOrderDefaultFields
        
        foreach ($grid in @($plotGetOrderGrid, $treeGetOrderGrid, $regenGetOrderGrid)) {
            Refresh-GetOrderGridNumbers -Grid $grid
        }
        $statusLabel.Text = "Loaded Get field order. Existing Project kept database order where available and added new or newly activated AppColumns at the bottom."
    }

    function Get-GetQueryFieldOrderFromGrid {
        param([System.Windows.Forms.DataGridView]$Grid)

        $items = New-Object System.Collections.Generic.List[string]
        foreach ($row in $Grid.Rows) {
            if ($row.IsNewRow) { continue }
            $key = ConvertTo-BuilderText $row.Cells["OrderKey"].Value
            if ([string]::IsNullOrWhiteSpace($key)) {
                $tableName = ConvertTo-BuilderText $row.Cells["TableName"].Value
                $fieldName = ConvertTo-BuilderText $row.Cells["FieldName"].Value
                if (-not [string]::IsNullOrWhiteSpace($tableName) -and -not [string]::IsNullOrWhiteSpace($fieldName)) {
                    $key = "$tableName.$fieldName"
                }
            }
            if (-not [string]::IsNullOrWhiteSpace($key)) { [void]$items.Add($key) }
        }
        return @($items.ToArray())
    }

    function Get-GetQueryFieldOrderFromGrids {
        return [pscustomobject]@{
            Plot = @(Get-GetQueryFieldOrderFromGrid -Grid $plotGetOrderGrid)
            Tree = @(Get-GetQueryFieldOrderFromGrid -Grid $treeGetOrderGrid)
            Regen = @(Get-GetQueryFieldOrderFromGrid -Grid $regenGetOrderGrid)
        }
    }

