    $queryCheck = New-Object System.Windows.Forms.CheckBox
    $queryCheck.Text = "Build/refresh _prjCFIDEER_ get and update queries in the saved project database"
    $queryCheck.Location = New-Object System.Drawing.Point(36, 340)
