    $cfideerPage.Controls.Add($queryCheck)
    $toolTip.SetToolTip($queryCheck, "On by default in every mode. Leave checked so Project Pickle rebuilds _prjCFIDEER_ get/update queries in the output copy to match the current project setup and selected AppColumns. Uncheck only if existing saved queries should be left untouched.")

         $getOrderControlsDisabledByCFIDEERQueryCopy = @{}

    $setGetOrderControlsSkippedForCFIDEERQueryCopy = {
        param(
            [bool]$Skip
        )

        if ($Skip) {
            foreach ($control in @($getOrderPage.Controls)) {
                if ($control -ne $getOrderCopyPanel) {
                    if (-not $getOrderControlsDisabledByCFIDEERQueryCopy.ContainsKey($control)) {
                        $getOrderControlsDisabledByCFIDEERQueryCopy[$control] = [bool]$control.Enabled
                    }

                    $control.Enabled = $false
                }
            }
        }
        else {
            foreach ($control in @($getOrderControlsDisabledByCFIDEERQueryCopy.Keys)) {
                try {
                    $control.Enabled = [bool]$getOrderControlsDisabledByCFIDEERQueryCopy[$control]
                }
                catch {
                }
            }

            $getOrderControlsDisabledByCFIDEERQueryCopy.Clear()
        }

        $getOrderCopyPanel.Enabled = $true
        $copyExistingCFIDEERQueriesCheck.Enabled = Test-CFIDEERQueryCopyModeAllowed -Mode (Get-WOOFComboText -Combo $modeBox)
        $copyExistingCFIDEERQueriesNoteLabel.Enabled = $true
    }.GetNewClosure()

    $updateCFIDEERQueryCopyModeCue = {
        $upgradeMode = Test-CFIDEERQueryCopyModeAllowed -Mode (Get-WOOFComboText -Combo $modeBox)

        if (-not $upgradeMode) {
            if ([bool]$copyExistingCFIDEERQueriesCheck.Checked) {
                $copyExistingCFIDEERQueriesCheck.Checked = $false
            }

            $copyExistingCFIDEERQueriesCheck.Enabled = $false
            $copyExistingCFIDEERQueriesNoteLabel.Text = "Available only in Upgrade Project mode. Use the normal Get Field Order and CFIDEER query rebuild workflow in New Project and Existing Project mode."

            & $setGetOrderControlsSkippedForCFIDEERQueryCopy $false

            if ($null -ne $queryCheck) {
                $queryCheck.Enabled = $true
            }
        }
        else {
            $copyExistingCFIDEERQueriesCheck.Enabled = $true
            $copyExistingCFIDEERQueriesNoteLabel.Text = "Upgrade Project mode only. When checked, Get Field Order is skipped and existing _prjCFIDEER_ queries are copied from the old database."

            if ([bool]$copyExistingCFIDEERQueriesCheck.Checked) {
                & $setGetOrderControlsSkippedForCFIDEERQueryCopy $true

                if ($null -ne $queryCheck) {
                    $queryCheck.Checked = $false
                    $queryCheck.Enabled = $false
                }
            }
            else {
                & $setGetOrderControlsSkippedForCFIDEERQueryCopy $false

                if ($null -ne $queryCheck) {
                    $queryCheck.Enabled = $true
                }
            }
        }

        try {
            $tabs.Invalidate()
        }
        catch {
        }
    }.GetNewClosure()

    $copyExistingCFIDEERQueriesCheck.Add_CheckedChanged({
        & $updateCFIDEERQueryCopyModeCue

        if ([bool]$copyExistingCFIDEERQueriesCheck.Checked) {
            $statusLabel.Text = "Old _prjCFIDEER_ query copy selected. Get Field Order and CFIDEER query rebuild are disabled."
        }
        else {
            $statusLabel.Text = "Old _prjCFIDEER_ query copy turned off. Load Get Field Order before rebuilding CFIDEER queries."
        }
    }.GetNewClosure())

    $modeBox.Add_SelectedIndexChanged({
