    function script:Get-PeriodRowsFromGrid {
        $grid = $script:ProjectPicklePeriodGrid
        if ($null -eq $grid) {
            throw "Periods tab: the period grid is not ready yet. Reopen Project Pickle and try again."
        }
        $rows = New-Object System.Collections.Generic.List[object]
        $rowNumber = 1
        foreach ($row in $grid.Rows) {
            if ($row.IsNewRow) {
                $rowNumber++
                continue
            }
            $number = ConvertTo-BuilderText $row.Cells["PeriodNumber"].Value
            $hasAnyEntry = $false
            foreach ($name in @("PeriodNumber", "PeriodDescription", "PlannedStartDate", "PlannedEndDate", "ActualStartDate", "ActualEndDate", "ApplicablePeriod")) {
                if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $row.Cells[$name].Value))) {
                    $hasAnyEntry = $true
                    break
                }
            }
            if ([string]::IsNullOrWhiteSpace($number)) {
                if ($hasAnyEntry) { throw "Periods tab: row $rowNumber has period information but no PeriodNumber. Enter a number, such as 1, or clear the row." }
                $rowNumber++
                continue
            }
            $parsedNumber = 0
            if (-not [int]::TryParse($number, [ref]$parsedNumber) -or $parsedNumber -le 0) {
                throw "Periods tab: row $rowNumber PeriodNumber must be a positive whole number. Example: 1."
            }
            [void]$rows.Add([pscustomobject]@{
                ProjectPeriodID = ConvertTo-BuilderText $row.Cells["ProjectPeriodID"].Value
                PeriodNumber = $parsedNumber
                PeriodDescription = ConvertTo-BuilderText $row.Cells["PeriodDescription"].Value
                PlannedStartDate = ConvertTo-BuilderText $row.Cells["PlannedStartDate"].Value
                PlannedEndDate = ConvertTo-BuilderText $row.Cells["PlannedEndDate"].Value
                ActualStartDate = ConvertTo-BuilderText $row.Cells["ActualStartDate"].Value
                ActualEndDate = ConvertTo-BuilderText $row.Cells["ActualEndDate"].Value
                ApplicablePeriod = ConvertTo-BuilderText $row.Cells["ApplicablePeriod"].Value
                IsCurrent = [bool]$row.Cells["IsCurrent"].Value
            })
            $rowNumber++
        }
        return @($rows.ToArray())
    }

    function script:Get-CustomRowsFromGrid {
        $rows = New-Object System.Collections.Generic.List[object]
        Save-LoadedAppColumnGridState

        foreach ($item in @($script:BuilderLoadedAppColumnItems)) {
            $tableName = ConvertTo-BuilderText $item.TableName
            $fieldName = ConvertTo-BuilderText $item.FieldName
            if ([string]::IsNullOrWhiteSpace($tableName) -or [string]::IsNullOrWhiteSpace($fieldName)) { continue }
            $active = ConvertTo-BuilderBool $item.Active
            [void]$rows.Add([pscustomobject]@{
                Source = ConvertTo-BuilderText $item.Source
                AppColumnID = ConvertTo-BuilderText $item.AppColumnID
                LoadedFromAppColumns = ConvertTo-BuilderBool $item.LoadedFromAppColumns
                StandardCode = ConvertTo-BuilderBool $item.StandardCode
                TableName = $tableName
                FieldName = $fieldName
                DataType = if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $item.DataType))) { "Text" } else { ConvertTo-BuilderText $item.DataType }
                Category = if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $item.Category))) { "Range" } else { ConvertTo-BuilderText $item.Category }
                FriendlyName = ConvertTo-BuilderText $item.FriendlyName
                ShortName = ConvertTo-BuilderText $item.ShortName
                Description = ConvertTo-BuilderText $item.Description
                ValidationAbrv = ConvertTo-BuilderText $item.ValidationAbrv
                Codes = ConvertTo-AppColumnCodesCellText $item.Codes
                Active = $active
                Collected = $active
                ArchiveOnly = $false
                DisplayRule = ConvertTo-BuilderBool $item.DisplayRule
                ReportVisible = ConvertTo-BuilderBool $item.ReportVisible
                QueryVisible = ConvertTo-BuilderBool $item.QueryVisible
            })
        }

        $readRows = {
            param(
                [System.Windows.Forms.DataGridView]$Grid,
                [string]$BoxName
            )

            $rowNumber = 1
            foreach ($row in $Grid.Rows) {
                if ($row.IsNewRow) {
                    $rowNumber++
                    continue
                }
                $tableName = ConvertTo-BuilderText $row.Cells["TableName"].Value
                $fieldName = ConvertTo-BuilderText $row.Cells["FieldName"].Value
                $loadedFromAppColumns = ConvertTo-BuilderBool $row.Cells["LoadedFromAppColumns"].Value
                $hasTextEntry = $false
                $hasAnyEntry = $false
                foreach ($name in @("Source", "AppColumnID", "TableName", "FieldName", "DataType", "Category", "FriendlyName", "ShortName", "Description", "ValidationAbrv", "Codes")) {
                    if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $row.Cells[$name].Value))) {
                        $hasTextEntry = $true
                        $hasAnyEntry = $true
                        break
                    }
                }
                foreach ($name in @("LoadedFromAppColumns", "StandardCode", "Active", "Collected", "ArchiveOnly", "DisplayRule", "ReportVisible", "QueryVisible")) {
                    if (-not $Grid.Columns.Contains($name)) { continue }
                    if (ConvertTo-BuilderBool $row.Cells[$name].Value) {
                        $hasAnyEntry = $true
                        break
                    }
            }
                if ([string]::IsNullOrWhiteSpace($tableName) -or [string]::IsNullOrWhiteSpace($fieldName)) {
                    if ($hasAnyEntry -and $hasTextEntry) {
                        throw "AppColumns tab ($BoxName): row $rowNumber is incomplete. Choose an App table and enter a Field name, or clear the row."
                    }
                    $rowNumber++
                    continue
                }
                $category = if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $row.Cells["Category"].Value))) { "Range" } else { ConvertTo-BuilderText $row.Cells["Category"].Value }
                $codes = ConvertTo-AppColumnCodesCellText $row.Cells["Codes"].Value
                if ($category.Equals("Code", [System.StringComparison]::OrdinalIgnoreCase) -and -not $loadedFromAppColumns -and [string]::IsNullOrWhiteSpace($codes)) {
                    throw "AppColumns tab ($BoxName): row $rowNumber is Category=Code but the Codes cell is blank. Enter all allowed codes in the Codes cell, such as 1=Yes; 2=No; 9=Unknown or 1=Yes 2=No 9=Unknown, or change Category to Range."
                }
                [void]$rows.Add([pscustomobject]@{
                    Source = ConvertTo-BuilderText $row.Cells["Source"].Value
                    AppColumnID = ConvertTo-BuilderText $row.Cells["AppColumnID"].Value
                    LoadedFromAppColumns = $loadedFromAppColumns
                    StandardCode = if ($Grid.Columns.Contains("StandardCode")) { ConvertTo-BuilderBool $row.Cells["StandardCode"].Value } else { $false }
                    TableName = $tableName
                    FieldName = $fieldName
                    DataType = if ([string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $row.Cells["DataType"].Value))) { "Text" } else { ConvertTo-BuilderText $row.Cells["DataType"].Value }
                    Category = $category
                    FriendlyName = ConvertTo-BuilderText $row.Cells["FriendlyName"].Value
                    ShortName = ConvertTo-BuilderText $row.Cells["ShortName"].Value
                    Description = ConvertTo-BuilderText $row.Cells["Description"].Value
                    ValidationAbrv = ConvertTo-BuilderText $row.Cells["ValidationAbrv"].Value
                    Codes = $codes
                    Active = ConvertTo-BuilderBool $row.Cells["Active"].Value
                    Collected = ConvertTo-BuilderBool $row.Cells["Active"].Value
                    ArchiveOnly = $false
                    DisplayRule = ConvertTo-BuilderBool $row.Cells["DisplayRule"].Value
                    ReportVisible = ConvertTo-BuilderBool $row.Cells["ReportVisible"].Value
                    QueryVisible = ConvertTo-BuilderBool $row.Cells["QueryVisible"].Value
                })
                $rowNumber++
            }
        }

        & $readRows $customFieldGrid "new custom box"
        return @($rows.ToArray())
    }

    function Confirm-CfideerQueryVisibleFieldsBeforeBuild {
        param([object]$Config)

        if ($null -eq $Config) { return $true }
                if ($Config.PSObject.Properties["CopyAppColumnsFromExistingDatabase"] -and (ConvertTo-BuilderBool $Config.CopyAppColumnsFromExistingDatabase)) {
            return $true
        }
        if ($Config.PSObject.Properties["BuildCfideerQueries"] -and -not (ConvertTo-BuilderBool $Config.BuildCfideerQueries)) { return $true }

        $customTables = @("PlotCustomMeasurements", "TreeCustomMeasurements", "RegenCustomMeasurements")
        $included = New-Object System.Collections.Generic.List[string]
        $notIncludedCount = 0

        foreach ($field in @($Config.CustomFields)) {
            if ($null -eq $field) { continue }
            $tableName = ConvertTo-BuilderText $field.TableName
            $fieldName = ConvertTo-BuilderText $field.FieldName
            if ([string]::IsNullOrWhiteSpace($tableName) -or [string]::IsNullOrWhiteSpace($fieldName)) { continue }
            if ($customTables -notcontains $tableName) { continue }
            if (Test-CfideerSampleRemoveField -FieldName $fieldName) { continue }

            $active = ConvertTo-BuilderBool $field.Active
            $queryVisible = if ($field.PSObject.Properties["QueryVisible"]) { ConvertTo-BuilderBool $field.QueryVisible } else { $true }
            if ($active -and $queryVisible) {
                [void]$included.Add("$tableName.$fieldName")
            }
            else {
                $notIncludedCount++
            }
        }

        if ($included.Count -eq 0) { return $true }

        $maxToShow = 35
        $shown = @($included.ToArray() | Sort-Object | Select-Object -First $maxToShow)
        $message = "CFIDEER query reminder:`r`n`r`n"
        $message += "Only custom fields that are BOTH Active and QueryVisible will be added to the _prjCFIDEER Get/Update queries.`r`n`r`n"
        $message += "These custom fields are currently marked Active + QueryVisible and WILL be included:`r`n- "
        $message += ([string]::Join("`r`n- ", [string[]]$shown))
        if ($included.Count -gt $maxToShow) {
            $message += "`r`n- ...and $($included.Count - $maxToShow) more"
        }
        $message += "`r`n`r`nInactive or QueryVisible-off history fields are kept in the custom tables only and stay out of CFIDEER queries."
        if ($notIncludedCount -gt 0) {
            $message += "`r`n`r`nCustom/history fields staying out of queries: $notIncludedCount"
        }
        $message += "`r`n`r`nIf any older history field is listed above, click No and uncheck Active or QueryVisible on the AppColumns tab before building."
        $message += "`r`n`r`nContinue building?"

        $answer = [System.Windows.Forms.MessageBox]::Show($message, "Confirm CFIDEER query fields", [System.Windows.Forms.MessageBoxButtons]::YesNo, [System.Windows.Forms.MessageBoxIcon]::Warning)
        return ($answer -eq [System.Windows.Forms.DialogResult]::Yes)
    }

    function Open-OutputDatabase {
        param([string]$Path)
        if ([string]::IsNullOrWhiteSpace($Path) -or -not (Test-Path -LiteralPath $Path)) {
            [System.Windows.Forms.MessageBox]::Show("The saved project database could not be found.", "Open saved project database", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
            return
        }
        try {
            Start-Process -FilePath $Path
        }
        catch {
            [System.Windows.Forms.MessageBox]::Show("Could not open the saved project database:`r`n`r`n$($_.Exception.Message)", "Open saved project database", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
        }
    }

    function Get-CurrentWOOFRunConfigSnapshot {
        $modeText = Get-WOOFComboText -Combo $modeBox
        $sourceForMode = if (Test-NewProjectModeText -Mode $modeText) { "" } else { $sourceBox.Text }
        return [pscustomobject]@{
            Mode = $modeText
            SourceDatabase = $sourceForMode
            UpgradeTemplateDatabase = $upgradeTemplateBox.Text
            OutputDatabase = $outputBox.Text
            ProjectName = $projectBox.Text
        }
    }

    $runLogRows = New-Object System.Collections.Generic.List[object]
    $script:WOOFRunLogStartTime = $null
    $script:WOOFRunLogLastTime = $null

    $appendLog = {
        param([string]$Text)
        $logTime = Get-Date
        if ($null -eq $script:WOOFRunLogStartTime) { $script:WOOFRunLogStartTime = $logTime }
        $elapsedSeconds = [Math]::Round(($logTime - [datetime]$script:WOOFRunLogStartTime).TotalSeconds, 3)
        $stepDurationSeconds = if ($null -eq $script:WOOFRunLogLastTime) { 0.0 } else { [Math]::Round(($logTime - [datetime]$script:WOOFRunLogLastTime).TotalSeconds, 3) }
        $script:WOOFRunLogLastTime = $logTime
        $elapsedText = Format-WOOFDuration -Seconds $elapsedSeconds
        $stepDurationText = Format-WOOFDuration -Seconds $stepDurationSeconds
        $entry = [pscustomobject]@{
            LogTime = $logTime
            StepCategory = Get-WOOFRunLogStepCategory -Message $Text
            ElapsedSeconds = $elapsedSeconds
            StepDurationSeconds = $stepDurationSeconds
            ElapsedTime = $elapsedText
            StepDuration = $stepDurationText
            Message = $Text
        }
        [void]$runLogRows.Add($entry)
        $line = "$($logTime.ToString('HH:mm:ss'))  +$elapsedText  $Text`r`n"
        try {
            $logBox.AppendText($line)
            $logBox.SelectionStart = $logBox.TextLength
            $logBox.ScrollToCaret()
            $statusLabel.Text = $Text
            $logBox.Update()
            $statusStrip.Update()
            [System.Windows.Forms.Application]::DoEvents()
        }
        catch {
        }
        Test-WOOFCancelRequested
    }

       # >>> START: Upgrade-only old AppColumns archive checkbox
# ---------------------------------------------------------------------------
# Upgrade-only archive checkbox for the old database's AppColumns tables.
#
# This option is intentionally independent of the existing:
#     Copy AppColumns from existing database
#
# A user can archive the old tables while still manually setting up the
# current working AppColumns.
#
# IMPORTANT:
# This entire block belongs immediately above:
#
#     $buildButton.Add_Click({
# ---------------------------------------------------------------------------

$findProjectPickleAppColumnsCopyCheck = {
    param(
        [Parameter(Mandatory = $true)]
        [System.Windows.Forms.Control]$Root
    )

    $pendingControls =
        New-Object System.Collections.Queue

    $pendingControls.Enqueue(
        $Root
    )

    while (
        $pendingControls.Count -gt 0
    ) {
        $currentControl =
            $pendingControls.Dequeue()

        if (
            $currentControl -is
            [System.Windows.Forms.CheckBox]
        ) {
            $currentText =
                ConvertTo-BuilderText `
                    $currentControl.Text

            # Match the beginning of the text instead of requiring the
            # complete wording to be identical.
            if (
                $currentText.StartsWith(
                    "Copy AppColumns from",
                    [System.StringComparison]::OrdinalIgnoreCase
                )
            ) {
                return $currentControl
            }
        }

        foreach (
            $childControl in
            $currentControl.Controls
        ) {
            $pendingControls.Enqueue(
                $childControl
            )
        }
    }

    return $null
}.GetNewClosure()


$existingAppColumnsCopyCheck =
    & $findProjectPickleAppColumnsCopyCheck `
        -Root $tabs


if (
    $null -eq
    $existingAppColumnsCopyCheck
) {
    throw (
        "Project Pickle could not place the old AppColumns " +
        "archive option because the existing Copy AppColumns " +
        "checkbox was not found."
    )
}


$archiveOldAppColumnsHost =
    $existingAppColumnsCopyCheck.Parent


if (
    $null -eq
    $archiveOldAppColumnsHost
) {
    throw (
        "Project Pickle could not place the old AppColumns " +
        "archive option because the AppColumns checkbox does " +
        "not have a parent control."
    )
}


$archiveOldAppColumnsCheck =
    New-Object System.Windows.Forms.CheckBox


$archiveOldAppColumnsCheck.Name =
    "archiveOldAppColumnsCheck"


$archiveOldAppColumnsCheck.Text = (
    "Archive old AppColumns and AppColumnCodes as " +
    "zAppColumns and zAppColumnsCodes"
)


# The option defaults to selected whenever Project Pickle starts.
$archiveOldAppColumnsCheck.Checked =
    $true


$archiveOldAppColumnsCheck.AutoSize =
    $false


$archiveOldAppColumnsCheck.AutoEllipsis =
    $true


$archiveOldAppColumnsCheck.TextAlign =
    [System.Drawing.ContentAlignment]::MiddleLeft


# Always place the archive option on the same row as the existing
# Copy AppColumns option.
#
# The previous code measured the parent control before the form had
# completed layout. That sometimes made the available width appear too
# small and incorrectly placed this checkbox on the next row, where it
# overlapped the AppColumns information box.
$archiveOldAppColumnsCheck.Location =
    [System.Drawing.Point]::new(
        (
            [int]$existingAppColumnsCopyCheck.Right +
            12
        ),
        [int]$existingAppColumnsCopyCheck.Top
    )


# Match the original checkbox height so both controls align vertically.
$archiveOldAppColumnsCheck.Height =
    [int]$existingAppColumnsCopyCheck.Height


# Align the archive checkbox's right edge with the information box below.
# With the current layout this produces a width of approximately 598 pixels.
$archiveOldAppColumnsCheck.Width =
    [Math]::Max(
        340,
        (
            [int]$appColumnsCheckboxInfo.Right -
            [int]$archiveOldAppColumnsCheck.Left
        )
    )


# Keep the fixed left position. The information box beneath it already
# handles right-side resizing independently.
$archiveOldAppColumnsCheck.Anchor =
    "Top,Left"


$archiveOldAppColumnsCheck.TabIndex =
    $existingAppColumnsCopyCheck.TabIndex + 1


$archiveOldAppColumnsHost.Controls.Add(
    $archiveOldAppColumnsCheck
)


$archiveOldAppColumnsCheck.BringToFront()


$toolTip.SetToolTip(
    $archiveOldAppColumnsCheck,
    (
        "Upgrade Project mode only. When selected, Build copies " +
        "the Existing/old database's AppColumns table to " +
        "zAppColumns and its AppColumnCodes table to " +
        "zAppColumnsCodes in the new output database. " +
        "This does not replace or change the working AppColumns " +
        "and AppColumnCodes tables."
    )
)


$setOldAppColumnsArchiveModeUiState = {
    $upgradeModeSelected =
        Test-UpgradeModeText `
            -Mode (
                Get-WOOFComboText `
                    -Combo $modeBox
            )

    # The checkbox is shown only in Upgrade Project mode.
    $archiveOldAppColumnsCheck.Visible =
        [bool]$upgradeModeSelected

    $archiveOldAppColumnsCheck.Enabled =
        [bool]$upgradeModeSelected

    $archiveOldAppColumnsCheck.TabStop =
        [bool]$upgradeModeSelected
}.GetNewClosure()


# Reevaluate checkbox visibility whenever the user changes Project mode.
$modeBox.Add_SelectedIndexChanged({
    & $setOldAppColumnsArchiveModeUiState
}.GetNewClosure())


# Reapply the archive state when the separate AppColumns copy option
# changes. The two options remain independent.
$existingAppColumnsCopyCheck.Add_CheckedChanged({
    & $setOldAppColumnsArchiveModeUiState
}.GetNewClosure())


# Apply the correct visibility immediately when the form is created.
& $setOldAppColumnsArchiveModeUiState

# <<< END: Upgrade-only old AppColumns archive checkbox


    $buildButton.Add_Click({
        if ($script:WOOFIsProcessing) {
            [System.Windows.Forms.MessageBox]::Show("Project Pickle is already building a database. Please wait for the current build to finish.", "Project Pickle is still working", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
            return
        }

        $config = $null
        try {
            $modeText = Get-WOOFComboText -Combo $modeBox
            $sourceForMode = if (Test-NewProjectModeText -Mode $modeText) { "" } else { $sourceBox.Text }
            $projectNameForBuild = $projectBox.Text
            $cycleLengthForBuild = $cycleBox.Text
            $regionNameForBuild = $regionBox.Text
            $agencyNameForBuild = $agencyBox.Text
            $reservationNameForBuild = $reservationNameBox.Text
            if (Test-WOOFTextEquals $modeText "Existing Project") {
                $existingProjectInfoForBuild = Get-ExistingProjectReferenceSelection -DatabasePath $sourceForMode
                if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $existingProjectInfoForBuild.ProjectName))) {
                    $projectNameForBuild = ConvertTo-BuilderText $existingProjectInfoForBuild.ProjectName
                }
                if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $existingProjectInfoForBuild.CycleLength))) {
                    $cycleLengthForBuild = ConvertTo-BuilderText $existingProjectInfoForBuild.CycleLength
                }
                $regionNameForBuild = ConvertTo-BuilderText $existingProjectInfoForBuild.RegionName
                $agencyNameForBuild = ConvertTo-BuilderText $existingProjectInfoForBuild.AgencyName
                $reservationNameForBuild = ConvertTo-BuilderText $existingProjectInfoForBuild.ReservationName
            }
            $copyAppColumnsForBuild = [bool]$copyAppColumnsCheck.Checked
            $copyReportsForBuild = (Test-UpgradeModeText -Mode $modeText) -and [bool]$copyReportsCheck.Checked

            if ($copyAppColumnsForBuild) {
                $customFieldsForBuild = @()
            }
            else {
                $customFieldsForBuild = @(Get-CustomRowsFromGrid)
            }

            $reportLayoutsForBuild = @()
            if ([bool]$reportCheck.Checked -and -not $copyReportsForBuild) {
                [void](& $saveCurrentReportLayout -Validate $false)
                $reportLayoutItems = New-Object System.Collections.Generic.List[object]
                foreach ($reportSpec in $reportSpecs) {
                    $reportKey = ConvertTo-BuilderText $reportSpec.Key
                    if ($reportUiState.Layouts.ContainsKey($reportKey)) {
                        [void]$reportLayoutItems.Add((Copy-ManualReportLayout -Layout $reportUiState.Layouts[$reportKey]))
                    }
                }
                $reportLayoutsForBuild = @($reportLayoutItems.ToArray())
            }
            
            $config = [pscustomobject]@{
                Mode = $modeText
                SourceDatabase = $sourceForMode
                UpgradeTemplateDatabase = $upgradeTemplateBox.Text
                OutputDatabase = $outputBox.Text
                ProjectName = $projectNameForBuild
                ReservationCode = ""
                ReservationName = $reservationNameForBuild
                AgencyName = $agencyNameForBuild
                RegionName = $regionNameForBuild
                KeepExistingReferenceScope = [bool]$keepExistingReferenceCheck.Checked
                AllowBlankReferenceSelection = [bool]$keepExistingReferenceCheck.Checked
                CycleLength = $cycleLengthForBuild
                Periods = @(Get-PeriodRowsFromGrid)
                PruneReferences = $true
                CustomFields = $customFieldsForBuild
                CopyAppColumnsFromExistingDatabase = $copyAppColumnsForBuild
                ArchiveOldAppColumnsFromExistingDatabase =
    [bool](
        (
            Test-UpgradeModeText `
                -Mode (
                    Get-WOOFComboText `
                        -Combo $modeBox
                )
        ) -and
        $archiveOldAppColumnsCheck.Checked
    )
                CopyReportsFromExistingDatabase = $copyReportsForBuild
                CopyProcessingTablesFromExistingDatabase = ((Test-UpgradeModeText -Mode (Get-WOOFComboText -Combo $modeBox)) -and [bool]$processingImportCheck.Checked)
                CopyProcessingCalculatedTablesFromExistingDatabase = ((Test-UpgradeModeText -Mode (Get-WOOFComboText -Combo $modeBox)) -and [bool]$processingCalculatedTablesCheck.Checked)
                UpdateValidation = [bool]$validationCheck.Checked
                PlotImportPath = $plotImportBox.Text
                PlotImportMappings = @(Get-PlotImportMappingsFromGrid)
                ImportOldInventoryData = (Test-UpgradeModeText -Mode (Get-WOOFComboText -Combo $modeBox))
                UpgradeFieldMappings = @(Get-UpgradeFieldMappingsFromGrid)
                SetupAssignments = [bool]$assignCheck.Checked
                SetupTreeAssignments = ((Test-UpgradeModeText -Mode (Get-WOOFComboText -Combo $modeBox)) -and [bool]$treeAssignCheck.Checked)
                CrewNames = @($crewBox.Text -split "," | ForEach-Object { ConvertTo-BuilderText $_ } | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
                UpdateReports = [bool]$reportCheck.Checked
                ReportLayouts = $reportLayoutsForBuild
                BuildCfideerQueries = ((-not [bool]$copyExistingCFIDEERQueriesCheck.Checked) -and [bool]$queryCheck.Checked)
                CopyExistingCFIDEERQueriesFromExistingDatabase = ((Test-CFIDEERQueryCopyModeAllowed -Mode $modeText) -and [bool]$copyExistingCFIDEERQueriesCheck.Checked)
                GetQueryFieldOrder = Get-GetQueryFieldOrderFromGrids
                OpenOutputAfterBuild = [bool]$openOutputAfterBuildCheck.Checked
            }
        }
        catch {
            [System.Windows.Forms.MessageBox]::Show($_.Exception.Message, "Build setup needs attention", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
            return
        }

        if (-not (Confirm-CfideerQueryVisibleFieldsBeforeBuild -Config $config)) {
            $statusLabel.Text = "Build canceled so AppColumns query settings can be reviewed."
            return
        }

        $script:WOOFIsProcessing = $true
        $script:WOOFBackgroundBuildActive = $false
        $script:WOOFCancelRequested = $false
        $script:WOOFCloseAfterCancel = $false
        $script:WOOFAllowCloseAfterCancel = $false
        $buildButton.Enabled = $false
        $openFolderButton.Enabled = $false
        $logBox.Clear()
        $logBox.AppendText("Preparing build...`r`n")
        $statusLabel.Text = "Preparing build..."
        $progress.Value = 5
        try {
            $logBox.Update()
            $statusStrip.Update()
        }
        catch {
        }
        $runLogRows.Clear()
        $script:WOOFRunLogStartTime = Get-Date
        $script:WOOFRunLogLastTime = $null
        $script:WOOFLiveRunLogPath = ""
        $script:WOOFLiveRunLogConfig = $config
        $progress.Value = 10
        & $appendLog "Build started."
        & $appendLog "Running database work. Project Pickle will export the detailed run log at the end or if the build fails."

        $runLogTextPath = ""
        try {
            Invoke-InventoryBuild -Config $config -Log $appendLog
            if ($config.CopyAppColumnsFromExistingDatabase) {
                $copyAppColumnsCheck.Checked = $false
                & $setAppColumnsCopyModeUiState
            }
            if ($config.CopyReportsFromExistingDatabase) {
                $copyReportsCheck.Checked = $false
                & $setReportCopyModeUiState
            }
            if ($config.CopyProcessingTablesFromExistingDatabase) {
                $processingImportCheck.Checked = $false
            }

            if ($config.CopyProcessingCalculatedTablesFromExistingDatabase) {
                $processingCalculatedTablesCheck.Checked = $false
            }
            
            $totalRunSeconds = if ($null -eq $script:WOOFRunLogStartTime) { 0.0 } else { [Math]::Round(((Get-Date) - [datetime]$script:WOOFRunLogStartTime).TotalSeconds, 3) }
            & $appendLog ("Total run time: {0} ({1:N3} seconds)." -f (Format-WOOFDuration -Seconds $totalRunSeconds), $totalRunSeconds)
            try {
                & $appendLog "Writing detailed run log text export."
                $runLogTextPath = Write-WOOFRunLogTextExport -Entries @($runLogRows.ToArray()) -Config $config -RunStatus "Success"
                & $appendLog "Detailed run log text exported: $runLogTextPath"
                [void](Write-WOOFRunLogTextExport -Entries @($runLogRows.ToArray()) -Config $config -RunStatus "Success" -PreferredPath $runLogTextPath)
            }
            catch {
                & $appendLog "Detailed run log text export failed: $($_.Exception.Message)"
            }
            & $appendLog "Run log table export skipped by design. Use the detailed text run log instead."
            $progress.Value = 100
            $openFolderButton.Enabled = $true
            $completeMessage = "Database built:`r`n`r`n$($config.OutputDatabase)"
            if (-not [string]::IsNullOrWhiteSpace($runLogTextPath)) {
                $completeMessage += "`r`n`r`nDetailed run log:`r`n$runLogTextPath"
            }
            [System.Windows.Forms.MessageBox]::Show($completeMessage, "Build complete", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
            if ($config.OpenOutputAfterBuild) {
                Open-OutputDatabase -Path $config.OutputDatabase
            }
        }
        catch {
            $isUserCancel = [bool]$script:WOOFCancelRequested
            $script:WOOFSuppressCancelException = $true
            $buildErrorMessage = if ($isUserCancel) { "Build canceled by user. Project Pickle stopped at a safe checkpoint." } else { $_.Exception.Message }
            & $appendLog "Build failed: $buildErrorMessage"
            $totalRunSeconds = if ($null -eq $script:WOOFRunLogStartTime) { 0.0 } else { [Math]::Round(((Get-Date) - [datetime]$script:WOOFRunLogStartTime).TotalSeconds, 3) }
            & $appendLog ("Total run time before failure: {0} ({1:N3} seconds)." -f (Format-WOOFDuration -Seconds $totalRunSeconds), $totalRunSeconds)
            try {
                & $appendLog "Writing failed detailed run log text export."
                $runLogTextPath = Write-WOOFRunLogTextExport -Entries @($runLogRows.ToArray()) -Config $config -RunStatus "Failed"
                & $appendLog "Failed detailed run log text exported: $runLogTextPath"
                [void](Write-WOOFRunLogTextExport -Entries @($runLogRows.ToArray()) -Config $config -RunStatus "Failed" -PreferredPath $runLogTextPath)
            }
            catch {
                & $appendLog "Failed detailed run log text export failed: $($_.Exception.Message)"
            }
            & $appendLog "Failed run log table export skipped by design. Use the detailed text run log instead."
            $failureMessage = $buildErrorMessage
            if (-not [string]::IsNullOrWhiteSpace($runLogTextPath)) {
                $failureMessage += "`r`n`r`nDetailed run log:`r`n$runLogTextPath"
            }
            $progress.Value = 0
            if (-not ($isUserCancel -and $script:WOOFCloseAfterCancel)) {
                [System.Windows.Forms.MessageBox]::Show($failureMessage, "Build failed", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
            }
        }
        finally {
            $shouldCloseAfterCancel = [bool]$script:WOOFCloseAfterCancel
            $script:WOOFIsProcessing = $false
            $script:WOOFBackgroundBuildActive = $false
            $script:WOOFSuppressCancelException = $false
            $buildButton.Enabled = $true
            if ($shouldCloseAfterCancel -and $null -ne $form -and -not $form.IsDisposed) {
                $script:WOOFAllowCloseAfterCancel = $true
                $form.Close()
            }
        }
    })

    $openFolderButton.Add_Click({
        if (-not [string]::IsNullOrWhiteSpace($outputBox.Text)) {
            Open-OutputDatabase -Path $outputBox.Text
        }
    })

    $aiTestButton.Add_Click({
        if ($script:WOOFIsProcessing) {
            [System.Windows.Forms.MessageBox]::Show("Project Pickle is already working. Please wait for the current action to finish.", "Project Pickle is still working", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
            return
        }
        try {
            $script:WOOFIsProcessing = $true
            $aiTestButton.Enabled = $false
            $statusLabel.Text = "Testing AI connection..."
            $progress.Value = 5
            [System.Windows.Forms.Application]::DoEvents()
            $result = Invoke-WOOFAiConnectionTestRequest -Endpoint $aiEndpointBox.Text -Model $aiModelBox.Text -ApiKey $aiKeyBox.Text
            $progress.Value = 100
            $statusLabel.Text = "AI connection test complete"
            [System.Windows.Forms.MessageBox]::Show($result, "AI connection test", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
        }
        catch {
            $progress.Value = 0
            $statusLabel.Text = "AI connection test failed"
            [System.Windows.Forms.MessageBox]::Show($_.Exception.Message, "AI connection test failed", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
        }
        finally {
            $script:WOOFIsProcessing = $false
            $aiTestButton.Enabled = $true
        }
    })

    $aiAskButton.Add_Click({
        if ($script:WOOFIsProcessing) {
            [System.Windows.Forms.MessageBox]::Show("Project Pickle is already working. Please wait for the current action to finish.", "Project Pickle is still working", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
            return
        }
        try {
            $script:WOOFIsProcessing = $true
            $aiAskButton.Enabled = $false
            $aiTestButton.Enabled = $false
            $aiAnswerBox.Text = "Asking Project Pickle AI..."
            $statusLabel.Text = "Preparing AI help context..."
            $progress.Value = 15
            [System.Windows.Forms.Application]::DoEvents()
            $answer = Invoke-WOOFAiHelpRequest -Endpoint $aiEndpointBox.Text -Model $aiModelBox.Text -ApiKey $aiKeyBox.Text -Question $aiQuestionBox.Text -GuidePath $aiGuideBox.Text -IncludeCode ([bool]$aiIncludeCodeCheck.Checked)
            $aiAnswerBox.Text = $answer
            $progress.Value = 100
            $statusLabel.Text = "AI help response complete"
        }
        catch {
            $progress.Value = 0
            $statusLabel.Text = "AI help failed"
            $aiAnswerBox.Text = "AI help failed:`r`n`r`n$($_.Exception.Message)"
            [System.Windows.Forms.MessageBox]::Show($_.Exception.Message, "AI help failed", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Error) | Out-Null
        }
        finally {
            $script:WOOFIsProcessing = $false
            $aiAskButton.Enabled = $true
            $aiTestButton.Enabled = $true
        }
    })

    $aiClearButton.Add_Click({
        $aiAnswerBox.Clear()
        $statusLabel.Text = "Ready"
        $progress.Value = 0
    })

    $desiredTabOrder = @(
        $setupPage,
        $optionsPage,
        $fieldsPage,
        $upgradeMappingPage,
        $plotPage,
        $getOrderPage,
        $reportsPage,
        $cfideerPage,
        $plotAssignmentPage,
        $treeAssignmentPage,
        $processingPage,
        $finishPage,
        $aiPage
    )
    $selectedTabText = if ($tabs.SelectedTab) { ConvertTo-BuilderText $tabs.SelectedTab.Text } else { "" }
    foreach ($page in $desiredTabOrder) {
        if ($null -ne $page -and $tabs.TabPages.Contains($page)) {
            $tabs.TabPages.Remove($page)
        }
    }
    foreach ($page in $desiredTabOrder) {
        if ($null -ne $page) {
            [void]$tabs.TabPages.Add($page)
        }
    }
    if (-not [string]::IsNullOrWhiteSpace($selectedTabText)) {
        $matchingTab = @($tabs.TabPages | Where-Object { [string]::Equals((ConvertTo-BuilderText $_.Text), $selectedTabText, [System.StringComparison]::OrdinalIgnoreCase) } | Select-Object -First 1)
        if ($matchingTab.Count -gt 0) {
            $tabs.SelectedTab = $matchingTab[0]
        }
    }
    try { $tabs.Invalidate() } catch {}

    $updatePeriodsModeCue = {
        $enabled = -not (Test-WOOFTextEquals (Get-WOOFComboText -Combo $modeBox) "Existing Project")
        $optionsPage.Tag = if ($enabled) { "" } else { "Disabled" }
        $optionsPage.BackColor = if ($enabled) { $uiTheme.AppBack } else { $uiTheme.SoftSurface }
        foreach ($control in $optionsPage.Controls) {
            if ($control -eq $loadPeriodsButton) { continue }
            if ($control -eq $periodGrid -or $control -eq $periodIntroLabel) {
                $control.Enabled = $true
                continue
            }
            $control.Enabled = $enabled
        }
        $periodGrid.ReadOnly = -not $enabled
        $periodGrid.AllowUserToAddRows = $enabled
        $periodGrid.AllowUserToDeleteRows = $enabled
        $periodGrid.DefaultCellStyle.BackColor = if ($enabled) { $uiTheme.Surface } else { $uiTheme.SoftSurface }
        $periodGrid.DefaultCellStyle.ForeColor = if ($enabled) { $uiTheme.Text } else { $uiTheme.MutedText }
        if ($enabled) {
            & $updateLoadPeriodsButtonAvailability
        }
        else {
            $loadPeriodsButton.Enabled = $false
            $loadPeriodsButton.BackColor = $uiTheme.SoftSurface
            $loadPeriodsButton.ForeColor = $uiTheme.MutedText
            & $refreshReadOnlyExistingPeriods
            if ($tabs.SelectedTab -eq $optionsPage) {
                $statusLabel.Text = "Periods is read-only in Existing Project mode. Use Existing Project for AppColumns, plots, field order, queries, assignments, then Build."
            }
        }
        try { $tabs.Invalidate() } catch {}
    }.GetNewClosure()
    $modeBox.Add_SelectedIndexChanged({ & $updatePeriodsModeCue }.GetNewClosure())
    $modeBox.Add_SelectedIndexChanged({
        try { & $refreshReadOnlyExistingPeriods } catch {}
    }.GetNewClosure())
    $sourceBox.Add_TextChanged({
        try { & $refreshReadOnlyExistingPeriods } catch {}
    }.GetNewClosure())
    & $updatePeriodsModeCue
    $tabs.Add_Selecting({
        param($Sender, $EventArgs)
        if ($EventArgs.TabPage -eq $optionsPage -and (Test-WOOFTextEquals (Get-WOOFComboText -Combo $modeBox) "Existing Project")) {
            $statusLabel.Text = "Periods is read-only in Existing Project mode. Add new measurement periods only in New Project or Upgrade Project mode."
        }
    }.GetNewClosure())

    $getNextTabIssues = {
        $issues = New-Object System.Collections.Generic.List[string]
        $currentTabName = if ($tabs.SelectedTab) { ConvertTo-BuilderText $tabs.SelectedTab.Text } else { "" }

        if (Test-WOOFTextEquals $currentTabName "Project") {
            $modeText = Get-WOOFComboText -Combo $modeBox
            $sourcePath = ConvertTo-BuilderText $sourceBox.Text
            $savePath = ConvertTo-BuilderText $outputBox.Text
            $isNewProjectMode = Test-NewProjectModeText -Mode $modeText
            $usesCurrentMasterDatabase = Test-ModeUsesCurrentMasterDatabase -Mode $modeText

            if (-not $isNewProjectMode) {
                if ([string]::IsNullOrWhiteSpace($sourcePath)) {
                    [void]$issues.Add("Choose the Existing/old project database.")
                }
                elseif (-not (Test-Path -LiteralPath $sourcePath -ErrorAction SilentlyContinue)) {
                    [void]$issues.Add("The Existing/old project database path was not found. Choose the database again.")
                }
            }

            if ($usesCurrentMasterDatabase) {
                $currentMasterPath = ConvertTo-BuilderText $upgradeTemplateBox.Text
                if ([string]::IsNullOrWhiteSpace($currentMasterPath)) {
                    [void]$issues.Add("Choose the current master database version.")
                }
                elseif (-not (Test-Path -LiteralPath $currentMasterPath -ErrorAction SilentlyContinue)) {
                    [void]$issues.Add("The current master database version path was not found. Choose it again.")
                }
            }

            if ([string]::IsNullOrWhiteSpace($savePath)) {
                [void]$issues.Add("Choose the Save Project Location.")
            }
            else {
                $extension = [System.IO.Path]::GetExtension($savePath).ToLowerInvariant()
                if ($extension -notin @(".mdb", ".accdb")) {
                    [void]$issues.Add("The Save Project Location must end in .mdb or .accdb.")
                }
                if ([string]::IsNullOrWhiteSpace([System.IO.Path]::GetDirectoryName($savePath))) {
                    [void]$issues.Add("Choose a full Save Project Location path, not just a file name.")
                }
            }

            if (-not (Test-WOOFTextEquals $modeText "Existing Project") -and [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $projectBox.Text))) {
                [void]$issues.Add("Enter a Project name.")
            }
            if (-not [bool]$keepExistingReferenceCheck.Checked) {
                if ([string]::IsNullOrWhiteSpace((Get-WOOFComboText -Combo $regionBox))) {
                    [void]$issues.Add("Click Load lists, then choose a Region.")
                }
                if ([string]::IsNullOrWhiteSpace((Get-WOOFComboText -Combo $agencyBox))) {
                    [void]$issues.Add("Choose an Agency from the loaded agency list.")
                }
                if ([string]::IsNullOrWhiteSpace((Get-WOOFComboText -Combo $reservationNameBox))) {
                    [void]$issues.Add("Choose a Reservation name from the loaded reservation list.")
                }
            }
        }
        elseif (Test-WOOFTextEquals $currentTabName "Periods") {
            if (Test-WOOFTextEquals (Get-WOOFComboText -Combo $modeBox) "Existing Project") {
                return [string[]]$issues.ToArray()
            }
            try {
                $periods = @(Get-PeriodRowsFromGrid)
                if ($periods.Count -eq 0) {
                    [void]$issues.Add("Add at least one measurement period row. New projects normally use PeriodNumber 1.")
                }
                else {
                    $seenPeriods = @{}
                    foreach ($period in $periods) {
                        $periodNumber = [int]$period.PeriodNumber
                        if ($seenPeriods.ContainsKey($periodNumber)) {
                            [void]$issues.Add("PeriodNumber $periodNumber is listed more than once. Each period number must be unique.")
                        }
                        else {
                            $seenPeriods[$periodNumber] = $true
                        }

                        foreach ($dateField in @("PlannedStartDate", "PlannedEndDate", "ActualStartDate", "ActualEndDate")) {
                            $dateText = ConvertTo-BuilderText $period.$dateField
                            if ([string]::IsNullOrWhiteSpace($dateText)) { continue }
                            $parsedDate = [datetime]::MinValue
                            if (-not [datetime]::TryParse($dateText, [ref]$parsedDate)) {
                                [void]$issues.Add("$dateField for PeriodNumber $periodNumber is not a valid date. Use a normal date, such as 2026-01-01, or leave it blank.")
                            }
                        }
                    }
                    $currentPeriods = @($periods | Where-Object { ConvertTo-BuilderBool $_.IsCurrent })
                    if ($currentPeriods.Count -eq 0) {
                        [void]$issues.Add("Check IsCurrent for the active measurement period.")
                    }
                    elseif ($currentPeriods.Count -gt 1) {
                        [void]$issues.Add("Only one period can be checked as IsCurrent.")
                    }
                }
            }
            catch {
                [void]$issues.Add($_.Exception.Message)
            }
        }
        elseif (Test-WOOFTextEquals $currentTabName "Reports") {
            if ([bool]$copyReportsCheck.Checked) {
                if (-not (Test-UpgradeModeText -Mode (Get-WOOFComboText -Combo $modeBox))) {
                    [void]$issues.Add("Copy completed ReportHeaders and ReportColumns is available only in Upgrade Project mode.")
                }
            }
            else {
                try {
                    [void](& $saveCurrentReportLayout -Validate $false)
                    $manualLayouts = New-Object System.Collections.Generic.List[object]
                    foreach ($reportSpec in $reportSpecs) {
                        $reportKey = ConvertTo-BuilderText $reportSpec.Key
                        if ($reportUiState.Layouts.ContainsKey($reportKey)) {
                            [void]$manualLayouts.Add((Copy-ManualReportLayout -Layout $reportUiState.Layouts[$reportKey]))
                        }
                    }
                    foreach ($reportIssue in @(Get-ManualReportLayoutsIssues -Layouts @($manualLayouts.ToArray()))) {
                        [void]$issues.Add($reportIssue)
                    }
                }
                catch {
                    [void]$issues.Add($_.Exception.Message)
                }
            }
        }
        elseif (Test-WOOFTextEquals $currentTabName "Plots") {
            $plotImportPath = ConvertTo-BuilderText $plotImportBox.Text
            if (-not [string]::IsNullOrWhiteSpace($plotImportPath)) {
                if (-not (Test-Path -LiteralPath $plotImportPath -ErrorAction SilentlyContinue)) {
                    [void]$issues.Add("The selected Add New Plots file was not found. Choose it again or leave it blank.")
                }
                else {
                    $plotMappings = @(Get-PlotImportMappingsFromGrid)
                    $plotNumberMapping = @($plotMappings | Where-Object { [string]::Equals((ConvertTo-BuilderText $_.FieldName), "PlotNumber", [System.StringComparison]::OrdinalIgnoreCase) } | Select-Object -First 1)
                    if ($plotNumberMapping.Count -gt 0 -and [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $plotNumberMapping[0].SourceColumn))) {
                        [void]$issues.Add("Map Project Pickle field PlotNumber to the spreadsheet column that contains plot numbers, or leave Add New Plots blank for now. In Existing Project mode after an Upgrade, upload only the new plots you are adding.")
                    }
                }
            }
        }
        elseif (Test-WOOFTextEquals $currentTabName "AppColumns") {
            if ([bool]$copyAppColumnsCheck.Checked) {
                if (Test-NewProjectModeText -Mode (Get-WOOFComboText -Combo $modeBox)) {
                    [void]$issues.Add("Copy AppColumns from existing database can only be used in Upgrade Project or Existing Project mode because it needs an Existing/old project database.")
                }
            }
            else {
                try {
                    [void](Get-CustomRowsFromGrid)
                }
                catch {
                    [void]$issues.Add($_.Exception.Message)
                }
            }
        }

        return [string[]]$issues.ToArray()
    }.GetNewClosure()

    $isWorkflowTabUsable = {
        param([System.Windows.Forms.TabPage]$TabPage)

        if ($null -eq $TabPage) { return $false }
        if ($TabPage -eq $optionsPage -and (Test-WOOFTextEquals (Get-WOOFComboText -Combo $modeBox) "Existing Project")) {
            return $false
        }
        if ($TabPage -eq $upgradeMappingPage -and -not (Test-UpgradeModeText -Mode (Get-WOOFComboText -Combo $modeBox))) {
            return $false
        }
        if ($TabPage -eq $treeAssignmentPage -and -not (Test-UpgradeModeText -Mode (Get-WOOFComboText -Combo $modeBox))) {
            return $false
        }
        if ($TabPage -eq $processingPage -and -not (Test-UpgradeModeText -Mode (Get-WOOFComboText -Combo $modeBox))) {
            return $false
        }
        return $true
    }.GetNewClosure()

    $getNextWorkflowTabIndex = {
        param([int]$StartIndex)

        if ($StartIndex -ge 0 -and $StartIndex -lt $tabs.TabPages.Count -and $tabs.TabPages[$StartIndex] -eq $plotPage) {
            $getOrderIndex = $tabs.TabPages.IndexOf($getOrderPage)
            if ($getOrderIndex -ge 0 -and (& $isWorkflowTabUsable -TabPage $getOrderPage)) {
                return $getOrderIndex
            }
        }

        for ($i = $StartIndex + 1; $i -lt $tabs.TabPages.Count; $i++) {
            if (& $isWorkflowTabUsable -TabPage $tabs.TabPages[$i]) {
                return $i
            }
        }
        return -1
    }.GetNewClosure()

    $setNextTabButtonState = {
        param(
            [bool]$Ready,
            [bool]$HasNextTab
        )

        $nextTabButton.Enabled = $Ready
        $nextTabButton.UseVisualStyleBackColor = $false
        if ($Ready) {
            $nextTabButton.BackColor = $uiTheme.Accent
            $nextTabButton.ForeColor = [System.Drawing.Color]::White
            $nextTabButton.FlatAppearance.BorderColor = $uiTheme.AccentDark
            $nextTabButton.FlatAppearance.MouseOverBackColor = [System.Drawing.Color]::FromArgb(61, 132, 97)
            $nextTabButton.FlatAppearance.MouseDownBackColor = $uiTheme.AccentDark
            $nextTabButton.Cursor = [System.Windows.Forms.Cursors]::Hand
        }
        else {
            $nextTabButton.BackColor = if ($HasNextTab) { [System.Drawing.Color]::FromArgb(226, 232, 240) } else { [System.Drawing.Color]::FromArgb(241, 245, 249) }
            $nextTabButton.ForeColor = $uiTheme.MutedText
            $nextTabButton.FlatAppearance.BorderColor = $uiTheme.Border
            $nextTabButton.FlatAppearance.MouseOverBackColor = $nextTabButton.BackColor
            $nextTabButton.FlatAppearance.MouseDownBackColor = $nextTabButton.BackColor
            $nextTabButton.Cursor = [System.Windows.Forms.Cursors]::Default
        }
    }.GetNewClosure()

    $updateNextTabButton = {
        if ($tabs.TabPages.Count -eq 0) { return }
        $nextIndex = & $getNextWorkflowTabIndex -StartIndex $tabs.SelectedIndex
        $hasNextTab = ($nextIndex -ge 0)
        $issues = @()
        if ($hasNextTab -and -not $script:WOOFIsProcessing) {
            try {
                $issues = @(& $getNextTabIssues)
            }
            catch {
                $issues = @($_.Exception.Message)
            }
        }
        $ready = ($hasNextTab -and -not $script:WOOFIsProcessing -and $issues.Count -eq 0)
        & $setNextTabButtonState -Ready $ready -HasNextTab $hasNextTab
        $nextTabButton.Text = if ($hasNextTab) { "Next >" } else { "Last tab" }
        if (-not $hasNextTab) {
            $toolTip.SetToolTip($nextTabButton, "You are on the last available tab.")
            $statusLabel.ToolTipText = ""
        }
        elseif ($ready) {
            $toolTip.SetToolTip($nextTabButton, "Go to the next setup tab.")
            $statusLabel.ToolTipText = ""
        }
        else {
            $firstIssue = if ($issues.Count -gt 0) { ConvertTo-BuilderText $issues[0] } else { "" }
            if (-not [string]::IsNullOrWhiteSpace($firstIssue)) {
                $toolTip.SetToolTip($nextTabButton, "Before Next: $firstIssue")
                $statusLabel.Text = "Next needs attention. Hover over Next for details."
                $statusLabel.ToolTipText = $firstIssue
            }
            else {
                $toolTip.SetToolTip($nextTabButton, "Finish the required entries on this tab before moving next.")
            }
        }
    }.GetNewClosure()

    $tabs.Add_SelectedIndexChanged({ & $updateNextTabButton }.GetNewClosure())
    $modeBox.Add_SelectedIndexChanged({ & $updateNextTabButton }.GetNewClosure())
    $refreshNextTabButton = { try { & $updateNextTabButton } catch {} }.GetNewClosure()
    foreach ($textControl in @($sourceBox, $upgradeTemplateBox, $outputBox, $projectBox, $plotImportBox)) {
        if ($null -ne $textControl) { $textControl.Add_TextChanged($refreshNextTabButton) }
    }
    foreach ($comboControl in @($modeBox, $regionBox, $agencyBox, $reservationNameBox)) {
        if ($null -ne $comboControl) {
            $comboControl.Add_SelectedIndexChanged($refreshNextTabButton)
            $comboControl.Add_TextChanged($refreshNextTabButton)
        }
    }
    if ($null -ne $keepExistingReferenceCheck) {
    $keepExistingReferenceCheck.Add_CheckedChanged($refreshNextTabButton)
    }
    if ($null -ne $copyReportsCheck) {
    $copyReportsCheck.Add_CheckedChanged($refreshNextTabButton)
    }
    foreach ($gridControl in @($periodGrid, $plotMappingGrid, $fieldGrid, $customFieldGrid, $reportColumnsGrid, $plotGetOrderGrid, $treeGetOrderGrid, $regenGetOrderGrid)) {
        if ($null -ne $gridControl) {
            $gridControl.Add_CellValueChanged({ try { & $updateNextTabButton } catch {} }.GetNewClosure())
            $gridControl.Add_RowsAdded({ try { & $updateNextTabButton } catch {} }.GetNewClosure())
            $gridControl.Add_RowsRemoved({ try { & $updateNextTabButton } catch {} }.GetNewClosure())
            $gridControl.Add_CurrentCellDirtyStateChanged({
                param($Sender, $EventArgs)
                try {
                    if ($Sender.IsCurrentCellDirty) {
                        [void]$Sender.CommitEdit([System.Windows.Forms.DataGridViewDataErrorContexts]::Commit)
                    }
                    & $updateNextTabButton
                }
                catch {}
            }.GetNewClosure())
        }
    }
    & $updateNextTabButton

    $nextTabButton.Add_Click({
        if ($script:WOOFIsProcessing) {
            [System.Windows.Forms.MessageBox]::Show("Project Pickle is already working. Please wait for the current action to finish.", "Project Pickle is still working", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Warning) | Out-Null
            return
        }
        $issues = @(& $getNextTabIssues)
        if ($issues.Count -gt 0) {
            $message = "Before moving to the next tab, finish this tab:`r`n`r`n- " + ([string]::Join("`r`n- ", [string[]]$issues))
            $statusLabel.Text = "Finish the current tab before moving next."
            [System.Windows.Forms.MessageBox]::Show($message, "Project Pickle needs a little more info", [System.Windows.Forms.MessageBoxButtons]::OK, [System.Windows.Forms.MessageBoxIcon]::Information) | Out-Null
            return
        }
        $nextIndex = & $getNextWorkflowTabIndex -StartIndex $tabs.SelectedIndex
        if ($nextIndex -ge 0) {
            $tabs.SelectedIndex = $nextIndex
            $statusLabel.Text = "Moved to $($tabs.SelectedTab.Text)."
        }
    }.GetNewClosure())

    Set-PickleControlTreeStyle $form
    & $updateNextTabButton

    $uiSmokeTimer = $null
    $uiSmokeLoadListsTimer = $null
    if ($UiSmokeTest) {
        if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $sourceBox.Text)) -and (Test-Path -LiteralPath $sourceBox.Text)) {
            $uiSmokeLoadListsTimer = New-Object System.Windows.Forms.Timer
            $uiSmokeLoadListsTimer.Interval = 250
            $uiSmokeLoadListsTimer.Add_Tick({
                $uiSmokeLoadListsTimer.Stop()
                $modeBox.SelectedItem = "Existing Project"
                [void]$loadReferenceButton.PerformClick()
            }.GetNewClosure())
            $uiSmokeLoadListsTimer.Start()
        }
        $uiSmokeTimer = New-Object System.Windows.Forms.Timer
        $uiSmokeTimer.Interval = if ($uiSmokeLoadListsTimer) { 3000 } else { 250 }
        $uiSmokeTimer.Add_Tick({
            $uiSmokeTimer.Stop()
            if ($outputBrowseButton.Tag -is [scriptblock]) {
                $modeBox.SelectedItem = $script:UpgradeModeLabel
                $sourceBox.Text = "C:\Temp\Old Project CFI 20240101 v2.98.00.mdb"
                $upgradeTemplateBox.Text = "C:\Temp\[TribeName] CFI [Date 20260520] v3.06.00.mdb"
                $projectBox.Text = $script:DefaultProjectNamePlaceholder
                $outputBox.Text = "C:\Temp\Old Project CFI 20240101 v2.98.00.mdb"
                & ([scriptblock]$outputBrowseButton.Tag)
                if ((ConvertTo-BuilderText $outputBox.Tag) -ne "[TribeName] CFI [Date 20260520] vX.XX.XX.mdb") {
                    throw "UI smoke test expected upgrade output filename hint to use the current master database version, but got: $($outputBox.Tag)"
                }
            }
            $form.Close()
        }.GetNewClosure())
        $uiSmokeTimer.Start()
    }

  $splashReadyPathForShown =
    [string]$script:SplashReadyFilePath

    $form.Add_Shown({
    try {
        if (
            -not [string]::IsNullOrWhiteSpace(
                $splashReadyPathForShown
            )
        ) {
            [System.IO.File]::Delete(
                $splashReadyPathForShown
            )
        }
    }
    catch {
        # Do not interrupt the main form.
    }
}.GetNewClosure())

    try {
        # The ReportHeaders text and character ruler must use the same
    # true fixed-width font. Apply it now and again after the form is shown
    # so the normal application theme cannot replace it.
    Set-ProjectPickleReportHeaderFixedWidthView `
    -ReportHeadersContainer $reportHeadersGroup

        $form.Add_Shown({
        Set-ProjectPickleReportHeaderFixedWidthView `
            -ReportHeadersContainer $reportHeadersGroup
    }.GetNewClosure())

    [void]$form.ShowDialog()

    }
    finally {
        Set-ProjectPickleSplashReady

    [System.Windows.Forms.Application]::remove_ThreadException(
        $threadExceptionHandler
    )

    [System.AppDomain]::CurrentDomain.remove_UnhandledException(
        $unhandledHandler
    )

    if ($uiSmokeLoadListsTimer) {
        $uiSmokeLoadListsTimer.Dispose()
        }

        if ($uiSmokeTimer) {
            $uiSmokeTimer.Dispose()
            Write-Output "UI smoke test passed."
        }
    }
}

try {
    if (
    $SelfTest -or
    $ReferenceListTest -or
    $NoUi -or
    -not [string]::IsNullOrWhiteSpace($LoadAppColumnsPath)
    ) {
        Set-ProjectPickleSplashReady
    }
    if ($SelfTest) {
        Invoke-SelfTest
        exit 0
    }

    if ($ReferenceListTest) {
        Invoke-ReferenceListTest
        exit 0
    }

    if (-not [string]::IsNullOrWhiteSpace($LoadAppColumnsPath)) {
        $exitCode = Export-AppColumnsLoadResult -Path $LoadAppColumnsPath -OutputPath $LoadAppColumnsOutputPath -ErrorPath $LoadAppColumnsErrorPath
        exit $exitCode
    }

    if ($NoUi) {
        Write-Output "NoUi mode is reserved for scripted builds. Use the Windows app or -SelfTest."
        exit 0
    }

    Show-BuilderApp
}
catch {
    Set-ProjectPickleSplashReady
    
    $crashPath = Write-ProjectPickleCrashLog -ExceptionObject $_.Exception -Context "Top-level app failure"
    $message = $_.Exception.ToString()
    if (-not [string]::IsNullOrWhiteSpace((ConvertTo-BuilderText $crashPath))) {
        $message += "`r`n`r`nCrash log:`r`n$crashPath"
    }
    if (-not [string]::IsNullOrWhiteSpace($LoadAppColumnsErrorPath)) {
        [System.IO.File]::WriteAllText($LoadAppColumnsErrorPath, $message, [System.Text.Encoding]::UTF8)
    }
    else {
        Write-Error $message
    }
    exit 1
}




